INSERT INTO `movies` VALUES (111, 'Taxi Driver', 'Crime,Drama,Thriller', 1976, 'Martin Scorsese', 'A mentally unstable veteran works as a nighttime taxi driver in New York City, where the perceived decadence and sleaze fuels his urge for violent action.', 'https://m.media-amazon.com/images/M/MV5BZDNhMGYwM2UtMTdlZS00MGQ1LWI2YzAtODY5YWI1MjYyNzRmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Diahnne Abbott, Frank Adu, Victor Argo, Gino Ardito, Garth Avery, Peter Boyle', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (112, 'Rumble in the Bronx (Hont faan kui)', 'Action,Adventure,Comedy,Crime', 1995, 'Stanley Tong', 'A young man visiting and helping his uncle in New York City finds himself forced to fight a street gang and the mob with his martial art skills.', 'https://m.media-amazon.com/images/M/MV5BNWUxMDcyZTMtYzJjMi00Y2Q1LWE3NWMtNTRiNGQxZTljYjE2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jackie Chan, Anita Mui, Françoise Yip, Bill Tung, Marc Akerstream, Garvin Cross', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (123, 'Chungking Express (Chung Hing sam lam)', 'Drama,Mystery,Romance', 1994, 'Wong Kar-Wai', 'Two melancholic Hong Kong policemen fall in love: one with a mysterious female underworld figure, the other with a beautiful and ethereal waitress at a late-night restaurant he frequents.', 'https://m.media-amazon.com/images/M/MV5BNDQ4ZmYxODctZDVlZC00OTcxLWJjOGItZjRlMzk4MDA1Yjg1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brigitte Lin, Tony Leung Chiu-wai, Faye Wong, Takeshi Kaneshiro, Valerie Chow, Piggy Chan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (141, 'Birdcage, The', 'Comedy', 1996, 'Mike Nichols', 'A gay cabaret owner and his drag queen companion agree to put up a false straight front so that their son can introduce them to his fiancée\'s right-wing, conservative parents.', 'https://m.media-amazon.com/images/M/MV5BMTM2NjExODYyOF5BMl5BanBnXkFtZTcwNTc0NjgyNA@@._V1_FMjpg_UX1000_.jpg', 'Robin Williams, Gene Hackman, Nathan Lane, Dianne Wiest, Dan Futterman, Calista Flockhart', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (145, 'Bad Boys', 'Action,Comedy,Crime,Drama,Thriller', 1995, 'Michael Bay', 'Two hip detectives protect a witness to a murder while investigating a case of stolen heroin from the evidence storage room from their police precinct.', 'https://m.media-amazon.com/images/M/MV5BMWNjZWEwNDMtMWE1ZC00MTgwLTk2YzAtYmE0NTkwOWVhMDI0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Lisa Boyle, Michael Taliferro, Emmanuel Xuereb, Tchéky Karyo, Marc Macaulay, Ralph Gonzalez', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (150, 'Apollo 13', 'Adventure,Drama,IMAX', 1995, 'Ron Howard', 'NASA must devise a strategy to return Apollo 13 to Earth safely after the spacecraft undergoes massive internal damage putting the lives of the three astronauts on board in jeopardy.', 'https://m.media-amazon.com/images/M/MV5BMGZmNGY1OTAtNjFkYS00MjcyLWFlZjUtYzEyMDllZGZhMzM3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Bill Paxton, Kevin Bacon, Gary Sinise, Ed Harris, Kathleen Quinlan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (153, 'Batman Forever', 'Action,Adventure,Comedy,Crime', 1995, 'Joel Schumacher', 'Batman must battle former district attorney Harvey Dent, who is now Two-Face and Edward Nygma, The Riddler with help from an amorous psychologist and a young circus acrobat who becomes his sidekick, Robin.', 'https://m.media-amazon.com/images/M/MV5BMTUyNjJhZWItMTZkNS00NDc4LTllNjUtYTg3NjczMzA5ZTViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Val Kilmer, Tommy Lee Jones, Jim Carrey, Nicole Kidman, Chris O\'Donnell, Michael Gough', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (160, 'Congo', 'Action,Adventure,Mystery,Sci-Fi', 1995, 'Frank Marshall', 'When an expedition to the African Congo ends in disaster, a new team is assembled to find out what went wrong.', 'https://m.media-amazon.com/images/M/MV5BOTc0MmM1MmMtYTI0Yi00YzJlLTg4MjctNjBlOGQ4NGJjZTNmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Laura Linney, Dylan Walsh, Ernie Hudson, Tim Curry, Grant Heslov, Joe Don Baker', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (161, 'Crimson Tide', 'Drama,Thriller,War', 1995, 'Tony Scott', 'On a U.S. nuclear missile sub, a young First Officer stages a mutiny to prevent his trigger-happy Captain from launching his missiles before confirming his orders to do so.', 'https://m.media-amazon.com/images/M/MV5BNTNhZDk2NmQtNDc3ZC00Nzk3LWFmNTctYTc0OWMyNGM0ZWYyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Denzel Washington, Gene Hackman, Matt Craven, George Dzundza, Viggo Mortensen, James Gandolfini', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (163, 'Desperado', 'Action,Romance,Western', 1995, 'Robert Rodriguez', 'Former musician and gunslinger El Mariachi arrives at a small Mexican border town after being away for a long time. His past quickly catches up with him and he soon gets entangled with the local drug kingpin Bucho and his gang.', 'https://m.media-amazon.com/images/M/MV5BN2IzOThmNTMtODE4My00NTI1LThkOWMtNTA4MTc4NWI1NTNlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Antonio Banderas, Salma Hayek, Joaquim de Almeida, Cheech Marin, Steve Buscemi, Carlos Gómez', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (165, 'Die Hard: With a Vengeance', 'Action,Crime,Thriller', 1995, 'John McTiernan', 'John McClane is forced out of suspension to play a game of \"Simon Says\" by a terrorist who has planted bombs all around New York City and will detonate them if McClane doesn\'t do what he says.', 'https://m.media-amazon.com/images/M/MV5BYjkzNzdkMTctNzMwMS00M2Q0LWIyOTMtNmM2NDY5NWZjNTJlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bruce Willis, Jeremy Irons, Samuel L. Jackson, Graham Greene, Colleen Camp, Larry Bryggman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (170, 'Hackers', 'Action,Adventure,Crime,Thriller', 1995, 'Iain Softley', 'Teenage hackers discover a criminal conspiracy with plans to use a computer virus that will capsize five oil tankers.', 'https://m.media-amazon.com/images/M/MV5BOGZkZTc2ZjItNzIzMS00ODRlLTliNjgtZjRmNzM2NjkzZTU1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jonny Lee Miller, Angelina Jolie, Jesse Bradford, Matthew Lillard, Laurence Mason, Renoly Santiago', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (180, 'Mallrats', 'Comedy,Romance', 1995, 'Kevin Smith', 'Both dumped by their girlfriends, two best friends seek refuge in the local mall.', 'https://m.media-amazon.com/images/M/MV5BZDM2MWVkMWItNjhjMy00MDUzLWEyOTAtN2I0MzNlZjc4Mjk0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Shannen Doherty, Jeremy London, Jason Lee, Claire Forlani, Ben Affleck, Joey Lauren Adams', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (185, 'Net, The', 'Action,Crime,Thriller', 1995, 'Irwin Winkler', 'When Angela Bennett, a computer programmer, stumbles upon government secrets, she finds herself on the run from an unknown enemy hell-bent on destroying her completely.', 'https://m.media-amazon.com/images/M/MV5BMDNhMjgxODUtMWRjOS00N2JlLWEyYWEtOWJhNWQ1MTdmYTllXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sandra Bullock, Jeremy Northam, Dennis Miller, Diane Baker, Wendy Gazelle, Ken Howard', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (196, 'Species', 'Horror,Sci-Fi', 1995, 'Roger Donaldson', 'A group of scientists try to track down and trap a killer alien seductress before she successfully mates with a human.', 'https://m.media-amazon.com/images/M/MV5BMjEzOTkxNTcyM15BMl5BanBnXkFtZTcwOTk0MjI3NA@@._V1_FMjpg_UX1000_.jpg', 'Ben Kingsley, Michael Madsen, Alfred Molina, Forest Whitaker, Marg Helgenberger, Natasha Henstridge', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (208, 'Waterworld', 'Action,Adventure,Sci-Fi', 1995, 'Kevin Reynolds', 'In a future where the polar ice-caps have melted and Earth is almost entirely submerged, a mutated mariner fights starvation and outlaw \"smokers,\" and reluctantly helps a woman and a young girl try to find dry land.', 'https://m.media-amazon.com/images/M/MV5BMjI5ZmQ3NTAtNWVhMi00ZmI2LTg3YTMtN2Q1MmNjYzMwZGI1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kevin Costner, Chaim Jeraffi, Rick Aviles, R.D. Call, Zitto Kazann, Leonardo Cimino', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (215, 'Before Sunrise', 'Drama,Romance', 1995, 'Richard Linklater', 'A young man and woman meet on a train in Europe, and wind up spending one evening together in Vienna. Unfortunately, both know that this will probably be their only night together.', 'https://m.media-amazon.com/images/M/MV5BZDZhZmI1ZTUtYWI3NC00NTMwLTk3NWMtNDc0OGNjM2I0ZjlmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ethan Hawke, Julie Delpy, Andrea Eckert, Hanno Pöschl, Karl Bruckschwaiger, Tex Rubinowitz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (223, 'Clerks', 'Comedy', 1994, 'Kevin Smith', 'A day in the lives of two convenience clerks named Dante and Randal as they annoy customers, discuss movies, and play hockey on the store roof.', 'https://m.media-amazon.com/images/M/MV5BYzcwZTU5NzMtMGIxYi00NjRhLThkYTItNjhlYWQ0MjdhYWFmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brian O\'Halloran, Jeff Anderson, Marilyn Ghigliotti, Lisa Spoonauer, Jason Mewes, Kevin Smith', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (231, 'Dumb & Dumber (Dumb and Dumber)', 'Adventure,Comedy', 1994, 'Peter Farrelly', 'After a woman leaves a briefcase at the airport terminal, a dumb limo driver and his dumber friend set out on a hilarious cross-country road trip to Aspen to return it.', 'https://m.media-amazon.com/images/M/MV5BNGQxZDA1MmMtYWQ1Ni00NTJmLTljMjgtZWVmODllODVhMzgyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jim Carrey, Jeff Daniels, Lauren Holly, Mike Starr, Karen Duffy, Charles Rocket', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (235, 'Ed Wood', 'Comedy,Drama', 1994, 'Tim Burton', 'Ambitious but troubled movie director Edward D. Wood Jr. tries his best to fulfill his dreams despite his lack of talent.', 'https://m.media-amazon.com/images/M/MV5BOWU4NzlkZGEtODNmYi00YTVhLWJhYjAtZjBkN2Q1Y2U5NjE4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Martin Landau, Sarah Jessica Parker, Patricia Arquette, Jeffrey Jones, G.D. Spradlin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (236, 'French Kiss', 'Action,Comedy,Romance', 1995, 'Lawrence Kasdan', 'A woman flying to France to confront her straying fiance gets into trouble when the charming crook seated next to her uses her for smuggling.', 'https://m.media-amazon.com/images/M/MV5BMTkzMjg5MDQ3M15BMl5BanBnXkFtZTgwOTM5NTE0MDE@._V1_FMjpg_UX1000_.jpg', 'Meg Ryan, Kevin Kline, Timothy Hutton, Jean Reno, François Cluzet, Suzan Anbeh', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (252, 'I.Q.', 'Comedy,Romance', 1994, 'Fred Schepisi', 'A mechanic romances the mathematician niece of physicist Albert Einstein, with help from him and his friends.', 'https://m.media-amazon.com/images/M/MV5BMDkyZmFiNmQtNWY1YS00N2MxLWJkMDItNWI5ODIxNWY1M2FiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tim Robbins, Meg Ryan, Walter Matthau, Lou Jacobi, Gene Saks, Joseph Maher', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (253, 'Interview with the Vampire: The Vampire Chronicles', 'Drama,Horror', 1994, 'Neil Jordan', 'A vampire tells his epic life story: love, betrayal, loneliness, and hunger.', 'https://m.media-amazon.com/images/M/MV5BYzJlN2NiZDQtZmI4NC00ZWFiLWFmMTUtMWM4ODVlOGFlODY1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brad Pitt, Christian Slater, Virginia McCollam, John McConnell, Tom Cruise, Mike Seelig', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (260, 'Star Wars: Episode IV - A New Hope', 'Action,Adventure,Sci-Fi', 1977, 'George Lucas', 'Luke Skywalker joins forces with a Jedi Knight, a cocky pilot, a Wookiee and two droids to save the galaxy from the Empire\'s world-destroying battle station, while also attempting to rescue Princess Leia from the mysterious Darth Vader.', 'https://m.media-amazon.com/images/M/MV5BOGUwMDk0Y2MtNjBlNi00NmRiLTk2MWYtMGMyMDlhYmI4ZDBjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mark Hamill, Harrison Ford, Carrie Fisher, Peter Cushing, Alec Guinness, Anthony Daniels', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (282, 'Nell', 'Drama', 1994, 'Michael Apted', 'In a remote woodland cabin, a small-town doctor discovers Nell - a beautiful young hermit-woman with many secrets.', 'https://m.media-amazon.com/images/M/MV5BNTkxY2NkMmItOTNmNy00NGU0LTlhM2UtOGQwNDhmNTBmNzQ3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jodie Foster, Liam Neeson, Natasha Richardson, Richard Libertini, Nick Searcy, Robin Mullins', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (292, 'Outbreak', 'Action,Drama,Sci-Fi,Thriller', 1995, 'Wolfgang Petersen', 'A team of Army doctors struggle to find a cure for the deadly Motaba virus that was transported from Africa to North America by a white-headed Capuchin monkey and is now spreading quickly throughout a small California town.', 'https://m.media-amazon.com/images/M/MV5BNGYxY2Q0YzUtMmE3OS00ZmQ5LWFiOGUtZDZmNTJlM2YyZjJmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dustin Hoffman, Rene Russo, Morgan Freeman, Kevin Spacey, Cuba Gooding Jr., Donald Sutherland', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (293, 'Léon: The Professional (a.k.a. The Professional) (Léon)', 'Action,Crime,Drama,Thriller', 1994, 'Luc Besson', 'When her family is murdered by a group of corrupt officers led by the tyrannical Norman Stansfield, a young 12-year-old girl enlists the help of an Italian-American hitman to seek revenge.', 'https://m.media-amazon.com/images/M/MV5BNGRkYTNhOWQtYmI0Ni00MjZhLWJmMzAtMTA2Mjg4NGNiNDU0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jean Reno, Gary Oldman, Natalie Portman, Danny Aiello, Peter Appel, Willi One Blood', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (296, 'Pulp Fiction', 'Comedy,Crime,Drama,Thriller', 1994, 'Quentin Tarantino', 'The lives of two mob hitmen, a boxer, a gangster and his wife, and a pair of diner bandits intertwine in four tales of violence and redemption.', 'https://m.media-amazon.com/images/M/MV5BYTViYTE3ZGQtNDBlMC00ZTAyLTkyODMtZGRiZDg0MjA2YThkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tim Roth, Amanda Plummer, Laura Lovelace, John Travolta, Samuel L. Jackson, Phil LaMarr', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (316, 'Stargate', 'Action,Adventure,Sci-Fi', 1994, 'Roland Emmerich', 'An interstellar teleportation device, found in Egypt, leads to a planet with humans resembling ancient Egyptians who worship the god Ra.', 'https://m.media-amazon.com/images/M/MV5BNGRmZmNhMTctZTBiMy00ZmJhLWE3MmMtMDNmZWRkZjczMGVkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kurt Russell, James Spader, Jaye Davidson, Viveca Lindfors, Alexis Cruz, Mili Avital', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (317, 'Santa Clause, The', 'Comedy,Drama,Fantasy', 1994, 'John Pasquin', 'When a man inadvertently makes Santa fall off his roof on Christmas Eve, he finds himself magically recruited to take his place.', 'https://m.media-amazon.com/images/M/MV5BNTYwZWUxNmUtNzdmMS00MDBiLWFhN2EtNjBmYjM1ZWFiNDUzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tim Allen, Judge Reinhold, Wendy Crewson, Eric Lloyd, David Krumholtz, Larry Brandenburg', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (318, 'Shawshank Redemption, The', 'Crime,Drama', 1994, 'Frank Darabont', 'A banker convicted of uxoricide forms a friendship over a quarter century with a hardened convict, while maintaining his innocence and trying to remain hopeful through simple compassion.', 'https://m.media-amazon.com/images/M/MV5BMDAyY2FhYjctNDc5OS00MDNlLThiMGUtY2UxYWVkNGY2ZjljXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tim Robbins, Morgan Freeman, Bob Gunton, William Sadler, Clancy Brown, Gil Bellows', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (329, 'Star Trek: Generations', 'Adventure,Drama,Sci-Fi', 1994, 'David Carson', 'With the help of long presumed dead Captain Kirk, Captain Picard must stop a deranged scientist willing to murder on a planetary scale in order to enter a space matrix.', 'https://m.media-amazon.com/images/M/MV5BNDFjYmFmNmItODM5Ny00YzhlLWEzNjEtNTBlNjRiN2RlYTRhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Patrick Stewart, Jonathan Frakes, Brent Spiner, LeVar Burton, Michael Dorn, Gates McFadden', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (339, 'While You Were Sleeping', 'Comedy,Romance', 1995, 'Jon Turteltaub', 'A Subway clerk falls for a comatose man\'s brother.', 'https://m.media-amazon.com/images/M/MV5BZTJmOWIzY2YtYmE2ZC00NDRiLWIzYmMtNTkyNmNlMTA0N2NkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sandra Bullock, Bill Pullman, Peter Gallagher, Peter Boyle, Jack Warden, Glynis Johns', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (344, 'Ace Ventura: Pet Detective', 'Comedy', 1994, 'Tom Shadyac', 'A goofy detective specializing in animals goes in search of the missing mascot of the Miami Dolphins.', 'https://m.media-amazon.com/images/M/MV5BOWU1M2Q5MDgtOTkxZS00NjdmLWFlNWEtOGEyOTNlNGYyYTZlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jim Carrey, Courteney Cox, Sean Young, Tone Loc, Dan Marino, Noble Willingham', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (349, 'Clear and Present Danger', 'Action,Crime,Drama,Thriller', 1994, 'Phillip Noyce', 'CIA Analyst Jack Ryan is drawn into an illegal war fought by the US government against a Colombian drug cartel.', 'https://m.media-amazon.com/images/M/MV5BZmRhZWJhZTctZjE4OS00NzM0LWIyYzEtNTM2MDgyY2MwNTQzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Harrison Ford, Willem Dafoe, Anne Archer, Joaquim de Almeida, Henry Czerny, Harris Yulin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (353, 'Crow, The', 'Action,Crime,Fantasy,Thriller', 1994, 'Alex Proyas', 'The night before his wedding, musician Eric Draven and his fiancée are brutally murdered by members of a violent gang. On the anniversary of their death, Eric rises from the grave and assumes the mantle of the Crow, a supernatural avenger.', 'https://m.media-amazon.com/images/M/MV5BOTBiNzhkZTItZWUwZS00YTJkLTg0YTEtN2I0ZDI5ODI2MWFjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brandon Lee, Rochelle Davis, Ernie Hudson, Michael Wincott, Bai Ling, Sofia Shinas', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (355, 'Flintstones, The', 'Children,Comedy,Fantasy', 1994, 'Brian Levant', 'In a parallel modern-day Stone Age world, a working-class family, the Flintstones, are set up for an executive job. But they learn that money can\'t buy happiness.', 'https://m.media-amazon.com/images/M/MV5BZmQwYjljNjUtYjA0NC00MTEyLWE0YmItNGViNGU5ZDEzMWRiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Goodman, Elizabeth Perkins, Rick Moranis, Rosie O\'Donnell, Kyle MacLachlan, Halle Berry', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (356, 'Forrest Gump', 'Comedy,Drama,Romance,War', 1994, 'Robert Zemeckis', 'The history of the United States from the 1950s to the \'70s unfolds from the perspective of an Alabama man with an IQ of 75, who yearns to be reunited with his childhood sweetheart.', 'https://m.media-amazon.com/images/M/MV5BNDYwNzVjMTItZmU5YS00YjQ5LTljYjgtMjY2NDVmYWMyNWFmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Rebecca Williams, Sally Field, Michael Conner Humphreys, Harold G. Herthum, George Kelly', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (357, 'Four Weddings and a Funeral', 'Comedy,Romance', 1994, 'Mike Newell', 'Over the course of five social occasions, a committed bachelor must consider the notion that he may have discovered love.', 'https://m.media-amazon.com/images/M/MV5BMTMyNzg2NzgxNV5BMl5BanBnXkFtZTcwMTcxNzczNA@@._V1_FMjpg_UX1000_.jpg', 'Hugh Grant, James Fleet, Simon Callow, John Hannah, Kristin Scott Thomas, David Bower', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (364, 'Lion King, The', 'Adventure,Animation,Children,Drama,Musical,IMAX', 1994, 'Roger Allers', 'Lion prince Simba and his father are targeted by his bitter uncle, who wants to ascend the throne himself.', 'https://m.media-amazon.com/images/M/MV5BZGRiZDZhZjItM2M3ZC00Y2IyLTk3Y2MtMWY5YjliNDFkZTJlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Rowan Atkinson, Matthew Broderick, Niketa Calame-Harris, Jim Cummings, Whoopi Goldberg, Robert Guillaume', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (367, 'Mask, The', 'Action,Comedy,Crime,Fantasy', 1994, 'Chuck Russell', 'Bank clerk Stanley Ipkiss is transformed into a manic superhero when he wears a mysterious mask.', 'https://m.media-amazon.com/images/M/MV5BNGNmNjI0ZmMtMzI5MC00ZjUyLWFlZDEtYjUyMGZlN2E3N2E2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jim Carrey, Peter Riegert, Peter Greene, Amy Yasbeck, Richard Jeni, Orestes Matacena', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (370, 'Naked Gun 33 1/3: The Final Insult', 'Action,Comedy', 1994, 'Peter Segal', 'Frank Drebin comes out of retirement to help Police Squad infiltrate a gang of terrorists planning to detonate a bomb at the Academy Awards.', 'https://m.media-amazon.com/images/M/MV5BM2ViYTFhMTktMjU0OC00ZWY3LWEzZDItMTExNDc2NDNjN2I3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leslie Nielsen, Priscilla Presley, George Kennedy, O.J. Simpson, Fred Ward, Kathleen Freeman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (377, 'Speed', 'Action,Romance,Thriller', 1994, 'Jan de Bont', 'An extortionist bomber rigs a Los Angeles city bus to explode if its speed drops below 50 mph, forcing a young cop and a female passenger to keep it moving and save everyone on board.', 'https://m.media-amazon.com/images/M/MV5BMDc2ODI5YWQtMmM2ZS00MTdmLWEyNWEtNmRmOGE5NGZlYWMzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Keanu Reeves, Dennis Hopper, Sandra Bullock, Joe Morton, Jeff Daniels, Alan Ruck', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (380, 'True Lies', 'Action,Adventure,Comedy,Romance,Thriller', 1994, 'James Cameron', 'A fearless, globe-trotting, terrorist-battling secret agent has his life turned upside down when he discovers his wife might be having an affair with a used-car salesman while terrorists smuggle nuclear war heads into the United States.', 'https://m.media-amazon.com/images/M/MV5BYjU1ZjNhMjMtOTMxZS00MDc1LTlkNzQtZTdjNGQyYjQ4YTA4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Arnold Schwarzenegger, Jamie Lee Curtis, Tom Arnold, Bill Paxton, Tia Carrere, Art Malik', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (410, 'Addams Family Values', 'Children,Comedy,Fantasy', 1993, 'Barry Sonnenfeld', 'The Addams Family try to rescue their beloved Uncle Fester from his gold-digging new love, a black widow named Debbie.', 'https://m.media-amazon.com/images/M/MV5BYWY3Y2ZkYjktZWYxMC00ZmZmLTgxNjYtYmMwYmU5OWJjMThjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Anjelica Huston, Raul Julia, Christopher Lloyd, Joan Cusack, Christina Ricci, Carol Kane', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (434, 'Cliffhanger', 'Action,Adventure,Thriller', 1993, 'Renny Harlin', 'Two mountain rescuers are forced to guide a group of thieves to their missing loot.', 'https://m.media-amazon.com/images/M/MV5BNGJkZmZlYTYtODQ1ZC00N2JiLWIxMWYtZTE4ZDMxZjQyZTAzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sylvester Stallone, John Lithgow, Michael Rooker, Janine Turner, Rex Linn, Caroline Goodall', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (442, 'Demolition Man', 'Action,Adventure,Sci-Fi', 1993, 'Marco Brambilla', 'A police officer is brought out of suspended animation in prison to pursue an old ultra-violent nemesis who is loose in a non-violent future society.', 'https://m.media-amazon.com/images/M/MV5BNWY3ZThmN2QtMzVkNS00MjczLTllNDQtOGEwN2M0ZTFkMWMzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sylvester Stallone, Wesley Snipes, Sandra Bullock, Nigel Hawthorne, Benjamin Bratt, Bob Gunton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (454, 'The Firm', 'Drama,Thriller', 1993, 'Sydney Pollack', 'A young lawyer joins a prestigious law firm only to discover that it has a sinister dark side.', 'https://m.media-amazon.com/images/M/MV5BMjE3ZDZkMWMtY2RkMC00YzJjLWFhYTUtYmRjMzAyMzEwZDE5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Jeanne Tripplehorn, Gene Hackman, Hal Holbrook, Terry Kinney, Wilford Brimley', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (457, 'The Fugitive', 'Thriller', 1993, 'Andrew Davis', 'Dr. Richard Kimble, unjustly accused of murdering his wife, must find the real killer while being the target of a nationwide manhunt led by a seasoned U.S. Marshal.', 'https://m.media-amazon.com/images/M/MV5BM2RjMjEwODUtYTE4OC00MzhkLThjMjItZjYyZjk3YzA4YWUxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Harrison Ford, Tommy Lee Jones, Sela Ward, Julianne Moore, Joe Pantoliano, Andreas Katsulas', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (466, 'Hot Shots! Part Deux', 'Action,Comedy,War', 1993, 'Jim Abrahams', '\"Rambo\" parody in which Topper Harley leads a rescue team into Iraq to save Iraqi war prisoners and all of their previous rescue teams.', 'https://m.media-amazon.com/images/M/MV5BNGU5ZTUzMmQtZDI3Yy00Y2ZlLTg1MmMtYWZiNDYyYmI4YmE2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Charlie Sheen, Lloyd Bridges, Valeria Golino, Richard Crenna, Brenda Bakke, Miguel Ferrer', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (474, 'In the Line of Fire', 'Action,Thriller', 1993, 'Wolfgang Petersen', 'Secret Service agent Frank Horrigan couldn\'t save Kennedy, but he\'s determined not to let a clever assassin take out this president.', 'https://m.media-amazon.com/images/M/MV5BYmNiNjNjYmQtZTQzNC00M2I1LThiMDgtNWNmM2VjY2Y3NzQxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Clint Eastwood, John Malkovich, Rene Russo, Dylan McDermott, Gary Cole, Fred Thompson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (480, 'Jurassic Park', 'Action,Adventure,Sci-Fi,Thriller', 1993, 'Steven Spielberg', 'An industrialist invites some experts to visit his theme park of cloned dinosaurs. After a power failure, the creatures run loose, putting everyone\'s lives, including his grandchildren\'s, in danger.', 'https://m.media-amazon.com/images/M/MV5BMjM2MDgxMDg0Nl5BMl5BanBnXkFtZTgwNTM2OTM5NDE@._V1_FMjpg_UX1000_.jpg', 'Sam Neill, Laura Dern, Jeff Goldblum, Richard Attenborough, Bob Peck, Martin Ferrero', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (485, 'Last Action Hero', 'Action,Adventure,Comedy,Fantasy', 1993, 'John McTiernan', 'With the help of a magic ticket, a young movie fan is transported into the fictional world of his favorite action movie character.', 'https://m.media-amazon.com/images/M/MV5BZGU2NWQyY2ItY2JiZS00ZDJhLWI0NDQtNjMyNWU3MDA1NTgzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Arnold Schwarzenegger, F. Murray Abraham, Art Carney, Charles Dance, Frank McRae, Tom Noonan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (494, 'Executive Decision', 'Action,Adventure,Thriller', 1996, 'Stuart Baird', 'When terrorists seize control of an airliner, an intelligence analyst accompanies a commando unit for a midair boarding operation.', 'https://m.media-amazon.com/images/M/MV5BYTExYWQzMWMtZjdjYy00OWQ3LWJjY2ItYjU4YWQ4M2NmMTJlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kurt Russell, Steven Seagal, Halle Berry, John Leguizamo, Oliver Platt, Joe Morton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (500, 'Mrs. Doubtfire', 'Comedy,Drama', 1993, 'Chris Columbus', 'After a bitter divorce, an actor disguises himself as a female housekeeper to spend time with his children held in custody by his former wife.', 'https://m.media-amazon.com/images/M/MV5BY2E2MDc5ZGEtOTNlZS00Mjg4LThlNzUtMDY2Zjc4ZTViNWY0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robin Williams, Sally Field, Pierce Brosnan, Harvey Fierstein, Polly Holliday, Lisa Jakub', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (508, 'Philadelphia', 'Drama', 1993, 'Jonathan Demme', 'When a man with HIV is fired by his law firm because of his condition, he hires a homophobic small-time lawyer as the only willing advocate for a wrongful dismissal suit.', 'https://m.media-amazon.com/images/M/MV5BYzEzZmMwMmMtNDgxYi00YTAwLWFkMjQtOGQzNmUxMGU1YWYwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Denzel Washington, Roberta Maxwell, Buzz Kilman, Karen Finley, Daniel Chapman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (509, 'Piano, The', 'Drama,Romance', 1993, 'Jane Campion', 'In the mid-19th century a mute woman is sent to New Zealand along with her young daughter and prized piano for an arranged marriage to a farmer, but is soon lusted after by a farm worker.', 'https://m.media-amazon.com/images/M/MV5BZGZiYTQ0MmEtY2RmYy00ZjRkLWI3NTctYTRhMGJlMzA4ZDg0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Holly Hunter, Harvey Keitel, Sam Neill, Anna Paquin, Kerry Walker, Geneviève Lemon', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (520, 'Robin Hood: Men in Tights', 'Comedy', 1993, 'Mel Brooks', 'A spoof of Robin Hood in general, and Robin Hood: Prince of Thieves (1991) in particular.', 'https://m.media-amazon.com/images/M/MV5BY2ZkMGU1OGUtZTJlOS00MmE5LWIxZjQtYWRlZDljMGJkMTZmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cary Elwes, Richard Lewis, Roger Rees, Amy Yasbeck, Mark Blankfield, Dave Chappelle', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (524, 'Rudy', 'Drama', 1993, 'David Anspaugh', 'Rudy has always been told that he was too small to play college football. But he is determined to overcome the odds and fulfill his dream of playing for Notre Dame.', 'https://m.media-amazon.com/images/M/MV5BNjQ1MWQ4MWQtZWQzMy00NmU1LThmYzItNGU1OTc5MWJjNzQ1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sean Astin, Jon Favreau, Ned Beatty, Greta Lind, Scott Benjaminson, Mary Ann Thebus', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (527, 'Schindler\'s List', 'Drama,War', 1993, 'Steven Spielberg', 'In German-occupied Poland during World War II, industrialist Oskar Schindler gradually becomes concerned for his Jewish workforce after witnessing their persecution by the Nazis.', 'https://m.media-amazon.com/images/M/MV5BNjM1ZDQxYWUtMzQyZS00MTE1LWJmZGYtNGUyNTdlYjM3ZmVmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Liam Neeson, Ben Kingsley, Ralph Fiennes, Caroline Goodall, Jonathan Sagall, Embeth Davidtz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (539, 'Sleepless in Seattle', 'Comedy,Drama,Romance', 1993, 'Nora Ephron', 'A recently widowed man\'s son calls a radio talk-show in an attempt to find his father a partner.', 'https://m.media-amazon.com/images/M/MV5BMzYwNzNlYWEtY2NiMC00Y2ZkLWFmYzUtYWU4ZTQ5YTAyNTZmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Ross Malinger, Rita Wilson, Victor Garber, Tom Riis Farrell, Carey Lowell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (541, 'Blade Runner', 'Action,Sci-Fi,Thriller', 1982, 'Ridley Scott', 'A blade runner must pursue and terminate four replicants who stole a ship in space and have returned to Earth to find their creator.', 'https://m.media-amazon.com/images/M/MV5BOWQ4YTBmNTQtMDYxMC00NGFjLTkwOGQtNzdhNmY1Nzc1MzUxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Harrison Ford, Rutger Hauer, Sean Young, Edward James Olmos, M. Emmet Walsh, Daryl Hannah', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (551, 'Nightmare Before Christmas, The', 'Animation,Children,Fantasy,Musical', 1993, 'Henry Selick', 'Jack Skellington, king of Halloween Town, discovers Christmas Town, but his attempts to bring Christmas to his home causes confusion.', 'https://m.media-amazon.com/images/M/MV5BNmYxOTAzZWYtOGI3Yi00ODc3LTk5ZjYtZTY0MzVkZTg3YmRiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Danny Elfman, Chris Sarandon, Catherine O\'Hara, William Hickey, Glenn Shadix, Paul Reubens', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (555, 'True Romance', 'Crime,Thriller', 1993, 'Tony Scott', 'In Detroit, a pop-culture enthusiast steals cocaine from his new wife\'s pimp and tries to sell it in Hollywood, prompting the mobsters who own the drugs to pursue the couple.', 'https://m.media-amazon.com/images/M/MV5BYzQ5OGMwMDAtMzcyOS00YTA4LWEwM2MtOTA1MDZjZGEyYmI1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Christian Slater, Patricia Arquette, Dennis Hopper, Val Kilmer, Gary Oldman, Brad Pitt', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (588, 'Aladdin', 'Adventure,Animation,Children,Comedy,Musical', 1992, 'Ron Clements', 'A kind-hearted street urchin and a power-hungry Grand Vizier vie for a magic lamp that has the power to make their deepest wishes come true.', 'https://m.media-amazon.com/images/M/MV5BMmQwYWZjZGItYzc0OC00ZDllLTg3NjItOWIyOWYwMDljMjAyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Scott Weinger, Robin Williams, Linda Larkin, Jonathan Freeman, Frank Welker, Gilbert Gottfried', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (589, 'Terminator 2: Judgment Day', 'Action,Sci-Fi', 1991, 'James Cameron', 'A cyborg, identical to the one who failed to kill Sarah Connor, must now protect her ten year old son John from an even more advanced and powerful cyborg.', 'https://m.media-amazon.com/images/M/MV5BNGMyMGNkMDUtMjc2Ni00NWFlLTgyODEtZTY2MzBiZTg0OWZiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Arnold Schwarzenegger, Linda Hamilton, Edward Furlong, Robert Patrick, Earl Boen, Joe Morton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (590, 'Dances with Wolves', 'Adventure,Drama,Western', 1990, 'Kevin Costner', 'A lieutenant assigned to a remote Civil War outpost starts questioning his purpose after making contact with a neighboring Sioux settlement.', 'https://m.media-amazon.com/images/M/MV5BMTY3OTI5NDczN15BMl5BanBnXkFtZTcwNDA0NDY3Mw@@._V1_FMjpg_UX1000_.jpg', 'Kevin Costner, Mary McDonnell, Graham Greene, Rodney A. Grant, Floyd \'Red Crow\' Westerman, Tantoo Cardinal', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (592, 'Batman', 'Action,Crime,Thriller', 1989, 'Tim Burton', 'The Dark Knight of Gotham City begins his war on crime with his first major enemy being Jack Napier, a criminal who becomes the clownishly homicidal Joker.', 'https://m.media-amazon.com/images/M/MV5BYzZmZWViM2EtNzhlMi00NzBlLWE0MWEtZDFjMjk3YjIyNTBhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Keaton, Jack Nicholson, Kim Basinger, Robert Wuhl, Pat Hingle, Billy Dee Williams', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (593, 'Silence of the Lambs, The', 'Crime,Horror,Thriller', 1991, 'Jonathan Demme', 'A young F.B.I. cadet must receive the help of an incarcerated and manipulative cannibal killer to help catch another serial killer, a madman who skins his victims.', 'https://m.media-amazon.com/images/M/MV5BNDdhOGJhYzctYzYwZC00YmI2LWI0MjctYjg4ODdlMDExYjBlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jodie Foster, Anthony Hopkins, Scott Glenn, Ted Levine, Anthony Heald, Brooke Smith', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (594, 'Snow White and the Seven Dwarfs', 'Animation,Children,Drama,Fantasy,Musical', 1937, 'William Cottrell', 'Exiled into the dangerous forest by her wicked stepmother, a princess is rescued by seven dwarf miners who make her part of their household.', 'https://m.media-amazon.com/images/M/MV5BMTQwMzE2Mzc4M15BMl5BanBnXkFtZTcwMTE4NTc1Nw@@._V1_FMjpg_UX1000_.jpg', 'Roy Atwell, Stuart Buchanan, Adriana Caselotti, Eddie Collins, Pinto Colvig, Marion Darlington', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (595, 'Beauty and the Beast', 'Animation,Children,Fantasy,Musical,Romance,IMAX', 1991, 'Gary Trousdale', 'A prince cursed to spend his days as a hideous monster sets out to regain his humanity by earning a young woman\'s love.', 'https://m.media-amazon.com/images/M/MV5BYTY3NDg2YzktYWFjZC00MTExLTlmZDctMGY3MWYzZTlkYTNiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robby Benson, Jesse Corti, Rex Everhart, Angela Lansbury, Paige O\'Hara, Jerry Orbach', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (597, 'Pretty Woman', 'Comedy,Romance', 1990, 'Garry Marshall', 'A corporate raider hires a hooker to act as a business escort in Beverly Hills, California.', 'https://m.media-amazon.com/images/M/MV5BNjk2ODQzNDYxNV5BMl5BanBnXkFtZTgwMTcyNDg4NjE@._V1_FMjpg_UX1000_.jpg', 'Richard Gere, Julia Roberts, Ralph Bellamy, Jason Alexander, Laura San Giacomo, Alex Hyde-White', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (608, 'Fargo', 'Comedy,Crime,Drama,Thriller', 1996, 'Joel Coen', 'Minnesota car salesman Jerry Lundegaard\'s inept crime falls apart due to his and his henchmen\'s bungling and the persistent police work of the quite pregnant Marge Gunderson.', 'https://m.media-amazon.com/images/M/MV5BNjg4MWE0MjEtODFhNy00MjA5LTg5ODktMzgwNWFmZTAwNjBlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'William H. Macy, Steve Buscemi, Peter Stormare, Kristin Rudrüd, Harve Presnell, Tony Denman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (616, 'Aristocats, The', 'Animation,Children', 1970, 'Wolfgang Reitherman', 'With the help of a smooth talking tomcat, a family of Parisian felines set to inherit a fortune from their owner try to make it back home after a jealous butler kidnaps them and leaves them in the country.', 'https://m.media-amazon.com/images/M/MV5BMTU1MzM0MjcxMF5BMl5BanBnXkFtZTgwODQ0MzcxMTE@._V1_FMjpg_UX1000_.jpg', 'Phil Harris, Eva Gabor, Sterling Holloway, Scatman Crothers, Paul Winchell, Lord Tim Hudson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (648, 'Mission: Impossible', 'Action,Adventure,Mystery,Thriller', 1996, 'Brian De Palma', 'An American agent, under false suspicion of disloyalty, must discover and expose the real spy without the help of his organization.', 'https://m.media-amazon.com/images/M/MV5BOGZjNDlkMTYtMTJkZi00OTkzLWI4NDEtYTA2ODQyMjcwYTdlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Jon Voight, Emmanuelle Béart, Henry Czerny, Jean Reno, Ving Rhames', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (653, 'Dragonheart', 'Action,Adventure,Fantasy', 1996, 'Rob Cohen', 'The last dragon and a disillusioned dragon-slaying knight must unite to stop an evil king, who was granted partial immortality.', 'https://m.media-amazon.com/images/M/MV5BZDViYjIxNjgtMmEyNS00MmVlLTllOWMtMGU0NzEwZjU2ZTYzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dennis Quaid, David Thewlis, Pete Postlethwaite, Dina Meyer, Jason Isaacs, Brian Thompson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (673, 'Space Jam', 'Adventure,Animation,Children,Comedy,Fantasy,Sci-Fi', 1996, 'Joe Pytka', 'In a desperate attempt to win a basketball match and earn their freedom, the Looney Tunes seek the aid of retired basketball champion, Michael Jordan.', 'https://m.media-amazon.com/images/M/MV5BZGQ3ZDk0M2MtZDNmNi00OWE3LThiODUtMTU3NmVjMTA0ZGQyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Jordan, Wayne Knight, Theresa Randle, Manner Washington III, Eric Gordon, Penny Bae Bridges', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (733, 'Rock, The', 'Action,Adventure,Thriller', 1996, 'Michael Bay', 'An FBI chemical weapons expert, and a former SAS soldier turned political prisoner, must break into Alcatraz prison when a rogue military group, led by a renegade general, take it over and threaten a nerve gas attack on San Francisco.', 'https://m.media-amazon.com/images/M/MV5BMDhkYjRiZWEtZTE0Ny00ZjA1LThmNjgtM2UyYTQzODA4MjdhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sean Connery, Nicolas Cage, Ed Harris, John Spencer, David Morse, William Forsythe', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (736, 'Twister', 'Action,Adventure,Romance,Thriller', 1996, 'Jan de Bont', 'Two storm chasers on the brink of divorce must work together to create an advanced weather alert system by putting themselves in the cross-hairs of extremely violent tornadoes.', 'https://m.media-amazon.com/images/M/MV5BNGVhY2JjYzgtYjAyOC00ODg0LTliYWEtMzliZWYzMjA2NjYyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Helen Hunt, Bill Paxton, Jami Gertz, Cary Elwes, Lois Smith, Philip Seymour Hoffman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (741, 'Ghost in the Shell (Kôkaku kidôtai)', 'Animation,Sci-Fi', 1995, 'Mamoru Oshii', 'A cyborg policewoman and her partner hunt a mysterious and powerful hacker called the Puppet Master.', 'https://m.media-amazon.com/images/M/MV5BNzljMjA3MTQtMjM1OS00OGJjLWJiYzctZDRiMTk1NWI5YzQ5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Atsuko Tanaka, Akio Ôtsuka, Kôichi Yamadera, Yutaka Nakano, Tamio Ôki, Tesshô Genda', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (745, 'Wallace & Gromit: A Close Shave', 'Animation,Children,Comedy', 1995, 'Nick Park', 'Wallace\'s whirlwind romance with the owner of the local wool shop puts his head in a spin; Gromit is framed for sheep-rustling in a fiendish criminal plot.', 'https://m.media-amazon.com/images/M/MV5BM2M4ZmEzYzEtNjk0ZS00ODZkLTkxZjYtNTY4Njg2YjhhMWNkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Peter Sallis, Anne Reid, Justin Fletcher', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (750, 'Dr. Strangelove or: How I Learned to Stop Worrying and Love the Bomb', 'Comedy,War', 1964, 'Stanley Kubrick', 'A mentally unstable American general orders a hydrogen bomb attack on the Soviet Union, triggering a path to global nuclear holocaust that a war room full of politicians and generals frantically tries to stop.', 'https://m.media-amazon.com/images/M/MV5BMjFjYzBlOTktMTI2OS00ZWVhLTgxMDUtNzAwODY2NmI3YTAzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Peter Sellers, George C. Scott, Sterling Hayden, Keenan Wynn, Slim Pickens, Peter Bull', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (778, 'Trainspotting', 'Comedy,Crime,Drama', 1996, 'Danny Boyle', 'Renton, deeply immersed in the Edinburgh drug scene, tries to clean up and get out despite the allure of drugs and the influence of friends.', 'https://m.media-amazon.com/images/M/MV5BYmVkNGJkMzQtYWQwOS00OTZmLThjODQtZjNjNzllYzRiNTE0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ewan McGregor, Ewen Bremner, Jonny Lee Miller, Kevin McKidd, Robert Carlyle, Kelly Macdonald', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (780, 'Independence Day (a.k.a. ID4)', 'Action,Adventure,Sci-Fi,Thriller', 1996, 'Roland Emmerich', 'The aliens are coming and their goal is to invade and destroy Earth. Fighting superior technology, mankind\'s best weapon is the will to survive.', 'https://m.media-amazon.com/images/M/MV5BOGMwN2UwZjEtYjFjMi00ZDA1LWJlYTQtMjA1MTYxMzIyNTdiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Will Smith, Bill Pullman, Jeff Goldblum, Mary McDonnell, Judd Hirsch, Robert Loggia', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (783, 'Hunchback of Notre Dame, The', 'Animation,Children,Drama,Musical,Romance', 1996, 'Gary Trousdale', 'A deformed bell-ringer must assert his independence from a vicious government minister in order to help his friend, a gypsy dancer.', 'https://m.media-amazon.com/images/M/MV5BY2QzMGEzNGMtMDQyNC00YTlmLWEwYjMtOGI1NWYxMTM4NjA2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jason Alexander, Mary Kay Bergman, Corey Burton, Jim Cummings, Bill Fagerbakke, Tom Hulce', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (802, 'Phenomenon', 'Drama,Romance', 1996, 'Jon Turteltaub', 'A small-town Everyman becomes a telekinetic genius.', 'https://m.media-amazon.com/images/M/MV5BMjAwMDA2NzEyMl5BMl5BanBnXkFtZTgwNTA2MjgxMTE@._V1_FMjpg_UX1000_.jpg', 'John Travolta, Kyra Sedgwick, Forest Whitaker, Robert Duvall, Jeffrey DeMunn, Richard Kiley', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (805, 'Time to Kill, A', 'Drama,Thriller', 1996, 'Joel Schumacher', 'A young Mississippi lawyer defends a black man who killed the two white men that raped his preteen daughter.', 'https://m.media-amazon.com/images/M/MV5BYmNiYzY1N2ItZDZiNC00ZGMyLWJlZjktZDE1MDI3NDBlYjE5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matthew McConaughey, Sandra Bullock, Samuel L. Jackson, Kevin Spacey, Oliver Platt, Charles S. Dutton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (858, 'Godfather, The', 'Crime,Drama', 1972, 'Francis Ford Coppola', 'The aging patriarch of an organized crime dynasty transfers control of his clandestine empire to his reluctant son.', 'https://m.media-amazon.com/images/M/MV5BNGEwYjgwOGQtYjg5ZS00Njc1LTk2ZGEtM2QwZWQ2NjdhZTE5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Marlon Brando, Al Pacino, James Caan, Richard S. Castellano, Robert Duvall, Sterling Hayden', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (898, 'Philadelphia Story, The', 'Comedy,Drama,Romance', 1940, 'George Cukor', 'After a rich woman\'s ex-husband and a tabloid-type reporter turn up just before her planned remarriage, she begins to learn the truth about herself.', 'https://m.media-amazon.com/images/M/MV5BYmMwZTQ5OGUtMjQ4Ni00ZTIwLTk1ZWMtNzhlMGQxYjIxMTU1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cary Grant, Katharine Hepburn, James Stewart, Ruth Hussey, John Howard, Roland Young', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (902, 'Breakfast at Tiffany\'s', 'Drama,Romance', 1961, 'Blake Edwards', 'A young New York socialite becomes interested in a young man who has moved into her apartment building, but her past threatens to get in the way.', 'https://m.media-amazon.com/images/M/MV5BZmU1MzlmOTMtZTNmMC00ZTA3LTkzMWMtOTc1MWNlMjFiYjFlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Audrey Hepburn, George Peppard, Patricia Neal, Buddy Ebsen, Martin Balsam, José Luis de Vilallonga', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (904, 'Rear Window', 'Mystery,Thriller', 1954, 'Alfred Hitchcock', 'A bored photographer recovering from a broken leg passes the time by watching his neighbors and begins to suspect one of them of murder.', 'https://m.media-amazon.com/images/M/MV5BODZhOWI1ODgtMzdiOS00YjNkLTgwOGUtYmIyZDg5ZmQwMzQ1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'James Stewart, Grace Kelly, Wendell Corey, Thelma Ritter, Raymond Burr, Judith Evelyn', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (908, 'North by Northwest', 'Action,Adventure,Mystery,Romance,Thriller', 1959, 'Alfred Hitchcock', 'A New York City advertising executive goes on the run after being mistaken for a government agent by a group of foreign spies, and falls for a woman whose loyalties he begins to doubt.', 'https://m.media-amazon.com/images/M/MV5BZWIzODI2OGItMzM0Ny00OGRmLTlkNmItMDQxMTFmMTk3YmQwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cary Grant, Eva Marie Saint, James Mason, Jessie Royce Landis, Leo G. Carroll, Josephine Hutchinson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (909, 'Apartment, The', 'Comedy,Drama,Romance', 1960, 'Billy Wilder', 'A Manhattan insurance clerk tries to rise in his company by letting its executives use his apartment for trysts, but office politics and his own romantic hopes complicate matters.', 'https://m.media-amazon.com/images/M/MV5BNDdhMzVhOWQtNDU2Mi00ZmZmLWJiZDMtY2QxMjhjY2Y1ZTI5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jack Lemmon, Shirley MacLaine, Fred MacMurray, Ray Walston, Jack Kruschen, David Lewis', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (912, 'Casablanca', 'Drama,Romance', 1942, 'Michael Curtiz', 'A cynical expatriate American cafe owner struggles to decide whether or not to help his former lover and her fugitive husband escape the Nazis in French Morocco.', 'https://m.media-amazon.com/images/M/MV5BNWEzN2U1YTYtYTQyMS00NTVkLWE2NGQtZWFlMmM0MDNjMmRiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Humphrey Bogart, Ingrid Bergman, Paul Henreid, Claude Rains, Conrad Veidt, Sydney Greenstreet', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (919, 'Wizard of Oz, The', 'Adventure,Children,Fantasy,Musical', 1939, 'Victor Fleming', 'Young Dorothy Gale and her dog Toto are swept away by a tornado from their Kansas farm to the magical Land of Oz and embark on a quest with three new friends to see the Wizard, who can return her to her home and fulfill the others\' wishes.', 'https://m.media-amazon.com/images/M/MV5BYWRmY2I0MGItYTQ0OC00NWZmLWIwMDktYjJlNDc0MzVhMmViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Judy Garland, Frank Morgan, Ray Bolger, Bert Lahr, Jack Haley, Billie Burke', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (920, 'Gone with the Wind', 'Drama,Romance,War', 1939, 'Victor Fleming', 'A sheltered and manipulative Southern belle and a roguish profiteer face off in a turbulent romance as the society around them crumbles with the end of slavery and is rebuilt during the Civil War and Reconstruction periods.', 'https://m.media-amazon.com/images/M/MV5BYmYxZTE3YzMtYmE2Yy00NmFlLTkzYTAtYTAzN2IzNDFkN2E0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Thomas Mitchell, Barbara O\'Neil, Vivien Leigh, Evelyn Keyes, Ann Rutherford, George Reeves', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (923, 'Citizen Kane', 'Drama,Mystery', 1941, 'Orson Welles', 'Following the death of publishing tycoon Charles Foster Kane, reporters scramble to uncover the meaning of his final utterance: \'Rosebud.\'', 'https://m.media-amazon.com/images/M/MV5BYjk1ZDJlMmUtOWQ0Zi00MDM5LTk1OGYtODczNjFmMGYwZGVkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Joseph Cotten, Dorothy Comingore, Agnes Moorehead, Ruth Warrick, Ray Collins, Erskine Sanford', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (924, '2001: A Space Odyssey', 'Adventure,Drama,Sci-Fi', 1968, 'Stanley Kubrick', 'When a mysterious artifact is uncovered on the Moon, a spacecraft manned by two humans and one supercomputer is sent to Jupiter to find its origins.', 'https://m.media-amazon.com/images/M/MV5BNjU0NDFkMTQtZWY5OS00MmZhLTg3Y2QtZmJhMzMzMWYyYjc2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Keir Dullea, Gary Lockwood, William Sylvester, Daniel Richter, Leonard Rossiter, Margaret Tyzack', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (928, 'Rebecca', 'Drama,Mystery,Romance,Thriller', 1940, 'Alfred Hitchcock', 'A self-conscious woman juggles adjusting to her new role as an aristocrat\'s wife and avoiding being intimidated by his first wife\'s spectral presence.', 'https://m.media-amazon.com/images/M/MV5BYTI0MjUyODAtZTBkNC00MmIwLWFlNmYtMWE3ZmJlOWJjM2QyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Laurence Olivier, Joan Fontaine, George Sanders, Judith Anderson, Nigel Bruce, Reginald Denny', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (953, 'It\'s a Wonderful Life', 'Children,Drama,Fantasy,Romance', 1946, 'Frank Capra', 'An angel is sent from Heaven to help a desperately frustrated businessman see the value of his own life.', 'https://m.media-amazon.com/images/M/MV5BMDM4OWFhYjEtNTE5Yy00NjcyLTg5N2UtZDQwNDZlYjlmNDU5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'James Stewart, Donna Reed, Lionel Barrymore, Thomas Mitchell, Henry Travers, Beulah Bondi', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (969, 'African Queen, The', 'Adventure,Comedy,Romance,War', 1951, 'John Huston', 'In WWI East Africa, a gin-swilling Canadian riverboat captain is persuaded by a strait-laced English missionary to undertake a trip up a treacherous river and use his boat to attack a German gunship.', 'https://m.media-amazon.com/images/M/MV5BY2Y0OWQ4Y2QtNGE5NC00MDk4LWFlYmQtYWVmNzZlZWVhMTg4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Humphrey Bogart, Katharine Hepburn, Robert Morley, Peter Bull, Theodore Bikel, Walter Gotell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1022, 'Cinderella', 'Animation,Children,Fantasy,Musical,Romance', 1950, 'Clyde Geronimi', 'When Cinderella\'s cruel stepmother prevents her from attending the Royal Ball, she gets some unexpected help from the lovable mice Gus and Jaq and from her Fairy Godmother.', 'https://m.media-amazon.com/images/M/MV5BZWY3ZTM4YTUtZjg1OC00NjM2LTllMTItZjA4MGU0MzcwNjhkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ilene Woods, Eleanor Audley, Verna Felton, Claire Du Brey, Rhoda Williams, James MacDonald', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1025, 'Sword in the Stone, The', 'Animation,Children,Fantasy,Musical', 1963, 'Wolfgang Reitherman', 'A poor boy named Arthur learns the power of love, kindness, knowledge and bravery with the help of a wizard called Merlin in the path to become one of the most beloved kings in English history.', 'https://m.media-amazon.com/images/M/MV5BN2U1ZDI3OGMtOTU0Ni00MTAxLTgwYWEtN2QwZDI4ZTQ5MTQ0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sebastian Cabot, Karl Swenson, Rickie Sorensen, Junius Matthews, Ginny Tyler, Martha Wentworth', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1028, 'Mary Poppins', 'Children,Comedy,Fantasy,Musical', 1964, 'Robert Stevenson', 'In turn of the century London, a magical nanny employs music and adventure to help two neglected children become closer to their father.', 'https://m.media-amazon.com/images/M/MV5BNThiNjgzMTYtZjUzMC00YTVlLTg4MDItMmFjMDIwYjg4ZDAwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Julie Andrews, Dick Van Dyke, David Tomlinson, Glynis Johns, Hermione Baddeley, Reta Shaw', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1032, 'Alice in Wonderland', 'Adventure,Animation,Children,Fantasy,Musical', 1951, 'Clyde Geronimi', 'Alice stumbles into the world of Wonderland. Will she get home? Not if the Queen of Hearts has her way.', 'https://m.media-amazon.com/images/M/MV5BMTgyMjM2NTAxMF5BMl5BanBnXkFtZTgwNjU1NDc2MTE@._V1_FMjpg_UX1000_.jpg', 'Kathryn Beaumont, Ed Wynn, Richard Haydn, Sterling Holloway, Jerry Colonna, Verna Felton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1035, 'Sound of Music, The', 'Musical,Romance', 1965, 'Robert Wise', 'A young novice is sent by her convent in 1930s Austria to become a governess to the seven children of a widowed naval officer.', 'https://m.media-amazon.com/images/M/MV5BYWJhYmU4MjQtZDJhYi00ZGVjLTlkNTEtNzkzNGVjOWQ3MjcwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Julie Andrews, Christopher Plummer, Eleanor Parker, Richard Haydn, Peggy Wood, Charmian Carr', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1036, 'Die Hard', 'Action,Crime,Thriller', 1988, 'John McTiernan', 'A New York City cop, John McClane, tries to save his estranged wife and several others taken hostage by terrorists during a Christmas Eve party at the Nakatomi Plaza Skyscraper in Los Angeles, California.', 'https://m.media-amazon.com/images/M/MV5BMGNlYmM1NmQtYWExMS00NmRjLTg5ZmEtMmYyYzJkMzljYWMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bruce Willis, Bonnie Bedelia, Reginald VelJohnson, Paul Gleason, De\'voreaux White, William Atherton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1059, 'William Shakespeare\'s Romeo + Juliet', 'Drama,Romance', 1996, 'Baz Luhrmann', 'Shakespeare\'s famous play is updated to the hip modern suburb of Verona still retaining its original dialogue.', 'https://m.media-amazon.com/images/M/MV5BZjBhYjkxN2EtNDc1Yy00NTViLTkxMjQtMDYxMzM0MzA3NGQ4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Claire Danes, John Leguizamo, Harold Perrineau, Lupita Ochoa, Pete Postlethwaite', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1073, 'Willy Wonka & the Chocolate Factory', 'Children,Comedy,Fantasy,Musical', 1971, 'Mel Stuart', 'A poor but hopeful boy seeks one of the five coveted golden tickets that will send him on a tour of Willy Wonka\'s mysterious chocolate factory.', 'https://m.media-amazon.com/images/M/MV5BNzllNzlkNzYtZTEzZi00ODMwLWFlYTctZDE5Mzk0NTM1NmViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gene Wilder, Jack Albertson, Peter Ostrum, Roy Kinnear, Julie Dawn Cole, Leonard Stone', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1079, 'Fish Called Wanda, A', 'Comedy,Crime', 1988, 'Charles Crichton', 'In London, four very different people team up on a jewel heist, then try to double-cross one another for the loot, complicated by their efforts to fool the very proper barrister Archibald Leach.', 'https://m.media-amazon.com/images/M/MV5BNjFhZDg1ZmEtYmI0Ny00MjM3LWIxNzItMzU1MzczZTljMTkxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Cleese, Jamie Lee Curtis, Kevin Kline, Michael Palin, Maria Aitken, Tom Georgeson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1080, 'Monty Python\'s Life of Brian', 'Comedy', 1979, 'Terry Jones', 'Born on the original Christmas day in the stable next door to Jesus Christ, Brian of Nazareth spends his life being mistaken for the messiah.', 'https://m.media-amazon.com/images/M/MV5BNDMzY2E4NjEtMTJiZC00Y2UzLWFiM2MtZWVhNTg5OGQxNjk1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Graham Chapman, John Cleese, Terry Gilliam, Eric Idle, Terry Jones, Michael Palin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1088, 'Dirty Dancing', 'Drama,Musical,Romance', 1987, 'Emile Ardolino', 'Spending the summer at a Catskills resort with her family, Frances \"Baby\" Houseman falls in love with the camp\'s dance instructor, Johnny Castle.', 'https://m.media-amazon.com/images/M/MV5BZmIwZjA1NzUtNTA0OS00OWMyLWE5MzctM2RjOWYxZjQyZDdmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jennifer Grey, Patrick Swayze, Jerry Orbach, Cynthia Rhodes, Jack Weston, Jane Brucker', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1089, 'Reservoir Dogs', 'Crime,Mystery,Thriller', 1992, 'Quentin Tarantino', 'When a simple jewelry heist goes horribly wrong, the surviving criminals begin to suspect that one of them is a police informant.', 'https://m.media-amazon.com/images/M/MV5BMmMzYjg4NDctYWY0Mi00OGViLWIzMTMtYWNlZGY5ZDJmYjk3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Harvey Keitel, Tim Roth, Michael Madsen, Chris Penn, Steve Buscemi, Lawrence Tierney', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1090, 'Platoon', 'Drama,War', 1986, 'Oliver Stone', 'Chris Taylor, a neophyte recruit in Vietnam, finds himself caught in a battle of wills between two sergeants, one good and the other evil. A shrewd examination of the brutality of war and the duality of man in conflict.', 'https://m.media-amazon.com/images/M/MV5BZjE4YjllODAtZGMxZS00Mjg2LThkOWUtZjNkMjQ5YThiNDU4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Keith David, Forest Whitaker, Francesco Quinn, Kevin Dillon, John C. McGinley, Reggie Johnson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1094, 'Crying Game, The', 'Drama,Romance,Thriller', 1992, 'Neil Jordan', 'A British soldier kidnapped by the IRA soon befriends one of his captors, who then becomes drawn into the soldier\'s world.', 'https://m.media-amazon.com/images/M/MV5BY2NlZjJlODgtNDQ1ZC00YjcxLTgxMjAtODNmYmQ5MTRhOTNkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Forest Whitaker, Miranda Richardson, Stephen Rea, Adrian Dunbar, Breffni McKenna, Joe Savino', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1097, 'E.T. the Extra-Terrestrial', 'Children,Drama,Sci-Fi', 1982, 'Steven Spielberg', 'A troubled child summons the courage to help a friendly alien escape from Earth and return to his home planet.', 'https://m.media-amazon.com/images/M/MV5BYTNhNmY0YWMtMTczYi00MTA0LThhMmUtMTIxYzE0Y2QwMzRlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dee Wallace, Henry Thomas, Peter Coyote, Robert MacNaughton, Drew Barrymore, K.C. Martel', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1101, 'Top Gun', 'Action,Romance', 1986, 'Tony Scott', 'The Top Gun Naval Fighter Weapons School is where the best of the best train to refine their elite flying skills. When hotshot fighter pilot Maverick is sent to the school, his reckless attitude and cocky demeanor put him at odds with the other pilots, especially the cool and col...Read all', 'https://m.media-amazon.com/images/M/MV5BZmVjNzQ3MjYtYTZiNC00Y2YzLWExZTEtMTM2ZDllNDI0MzgyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Kelly McGillis, Val Kilmer, Anthony Edwards, Tom Skerritt, Michael Ironside', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1124, 'On Golden Pond', 'Drama', 1981, 'Mark Rydell', 'Curmudgeon Norman is estranged from his daughter Chelsea. Nevertheless, at Golden Pond he and his wife agree to look after Billy, the son of Chelsea\'s new boyfriend, and a most unexpected relationship blooms.', 'https://m.media-amazon.com/images/M/MV5BZmI3OGQ0YjQtZjNkYi00NmEzLWE5NjMtMTdkYjA4YTdiYzBiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Katharine Hepburn, Henry Fonda, Jane Fonda, Doug McKeon, Dabney Coleman, William Lanteau', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1127, 'Abyss, The', 'Action,Adventure,Sci-Fi,Thriller', 1989, 'James Cameron', 'A civilian diving team is enlisted to search for a lost nuclear submarine and faces danger while encountering an alien aquatic species.', 'https://m.media-amazon.com/images/M/MV5BMGRkNzJlNjgtZmUwYS00Y2U3LTljZDctMTQxYWIxOWVjMzNjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ed Harris, Mary Elizabeth Mastrantonio, Michael Biehn, Leo Burmester, Todd Graff, John Bedford Lloyd', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1136, 'Monty Python and the Holy Grail', 'Adventure,Comedy,Fantasy', 1975, 'Terry Gilliam', 'King Arthur and his Knights of the Round Table embark on a surreal, low-budget search for the Holy Grail, encountering many, very silly obstacles.', 'https://m.media-amazon.com/images/M/MV5BYWY4YmUzZmUtMzQ0ZS00N2Y2LWJlODQtN2IwMDc1MWQwMmU3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Graham Chapman, John Cleese, Eric Idle, Terry Gilliam, Terry Jones, Michael Palin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1148, 'Wallace & Gromit: The Wrong Trousers', 'Animation,Children,Comedy,Crime', 1993, 'Nick Park', 'Gromit butts heads with a mysterious penguin lodger, who hatches a sinister scheme involving the ex-NASA Techno Trousers that have been modified by Wallace for walkies.', 'https://m.media-amazon.com/images/M/MV5BZGI0ZjU1ZmUtZmRlZC00Yjg3LWI1MjktM2YwYmU1NGNiYzU0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Peter Sallis', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1172, 'Cinema Paradiso (Nuovo cinema Paradiso)', 'Drama', 1989, 'Giuseppe Tornatore', 'Salvatore, a famous film director, returns to his hometown for the funeral of the local theater\'s film projectionist, Alfredo. He reminisces about his life as a young boy falling in love with cinema.', 'https://m.media-amazon.com/images/M/MV5BMTljNzc4YWEtYTZlMS00ODMyLWIwMTAtNWQxY2VkMDEwYTk5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Antonella Attili, Enzo Cannavale, Isa Danieli, Leo Gullotta, Marco Leonardi, Pupella Maggio', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1178, 'Paths of Glory', 'Drama,War', 1957, 'Stanley Kubrick', 'A colonel defends three of his soldiers in a court-martial after they abandon a suicidal attack.', 'https://m.media-amazon.com/images/M/MV5BNmQ2NmI2ODYtMDQzNS00NzQyLTkzZjgtZmZlYTQ5MTc1OWU3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kirk Douglas, Ralph Meeker, Adolphe Menjou, George Macready, Wayne Morris, Richard Anderson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1183, 'English Patient, The', 'Drama,Romance,War', 1996, 'Anthony Minghella', 'At the close of World War II, a young nurse tends to a badly burned plane crash victim. His past is shown in flashbacks, revealing an involvement in a fateful love affair.', 'https://m.media-amazon.com/images/M/MV5BODg0NjdiN2UtZWY3MS00M2JmLTg1MDAtY2ZiNzNiMzAzYWFmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ralph Fiennes, Juliette Binoche, Willem Dafoe, Kristin Scott Thomas, Naveen Andrews, Colin Firth', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1186, 'Sex, Lies, and Videotape', 'Drama', 1989, 'Steven Soderbergh', 'A sexually repressed woman\'s husband is having an affair with her sister. The arrival of a visitor with a rather unusual fetish changes everything.', 'https://m.media-amazon.com/images/M/MV5BZmFjNjkyNmQtMDdkNy00YmQxLWFmZTYtZDQyYTY3ZGFjYmFiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'James Spader, Andie MacDowell, Peter Gallagher, Laura San Giacomo, Ron Vawter, Steven Brill', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1193, 'One Flew Over the Cuckoo\'s Nest', 'Drama', 1975, 'Milos Forman', 'A rebellious convict is sent to a psychiatric hospital for evaluation in 1963 Oregon, and encourages his docile companions to take more control of their lives and defy the tyrannical head nurse.', 'https://m.media-amazon.com/images/M/MV5BYjBkMjgzMzYtNzRiMS00NDc3LWE4YTUtZjYxYjZhNjNhYzhhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Berryman, Peter Brocco, Dean R. Brooks, Alonzo Brown, Scatman Crothers, Mwako Cumbuka', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1194, 'Cheech and Chong\'s Up in Smoke', 'Comedy', 1978, 'Lou Adler', 'Stoner musicians Pedro DePacas and Anthony \"Man\" Stoner unknowingly smuggle a van - made entirely of marijuana - from Mexico to Los Angeles with incompetent Police Sergeant Stedenko hot on their trail.', 'https://m.media-amazon.com/images/M/MV5BODhlMjE4YjEtMjYxMy00NmEyLTk0ZDMtZjU2ZWJjNTVkMzMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cheech Marin, Tommy Chong, Strother Martin, Edie Adams, Harold Fong, Richard Novo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1196, 'Star Wars: Episode V - The Empire Strikes Back', 'Action,Adventure,Sci-Fi', 1980, 'Irvin Kershner', 'After the Empire overpowers the Rebel Alliance, Luke Skywalker begins training with Jedi Master Yoda, while Darth Vader and bounty hunter Boba Fett pursue his friends across the galaxy.', 'https://m.media-amazon.com/images/M/MV5BMTkxNGFlNDktZmJkNC00MDdhLTg0MTEtZjZiYWI3MGE5NWIwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mark Hamill, Harrison Ford, Carrie Fisher, Billy Dee Williams, Anthony Daniels, David Prowse', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1197, 'Princess Bride, The', 'Action,Adventure,Comedy,Fantasy,Romance', 1987, 'Rob Reiner', 'A bedridden boy\'s grandfather reads him the story of a farmboy-turned-pirate who encounters numerous obstacles, enemies and allies in his quest to be reunited with his true love.', 'https://m.media-amazon.com/images/M/MV5BMjFiOTEyNGMtN2E4MC00ZjZlLTk3ZDQtNTU1ZGNiZTA1MzJlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cary Elwes, Mandy Patinkin, Chris Sarandon, Christopher Guest, Wallace Shawn, André René Roussimoff', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1198, 'Raiders of the Lost Ark (Indiana Jones and the Raiders of the Lost Ark)', 'Action,Adventure', 1981, 'Steven Spielberg', 'In 1936, archaeologist Indiana Jones is tasked by Army Intelligence to help locate a legendary ancient power, the Ark of Covenant, before the Nazis get it first.', 'https://m.media-amazon.com/images/M/MV5BOGNhMjg2ZjgtYzk4Ni00MTViLTg1MmUtYzM2MDZiYjZlMmU3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Harrison Ford, Karen Allen, Paul Freeman, Ronald Lacey, John Rhys-Davies, Denholm Elliott', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1199, 'Brazil', 'Fantasy,Sci-Fi', 1985, 'Terry Gilliam', 'A bureaucrat in a dystopic society becomes an enemy of the state as he pursues the woman of his dreams.', 'https://m.media-amazon.com/images/M/MV5BNjI1MTAzNmYtYzQ3Zi00ZWE0LWJiZmQtY2UwZWU3ZTE4OGQ3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jonathan Pryce, Robert De Niro, Katherine Helmond, Ian Holm, Bob Hoskins, Michael Palin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1200, 'Aliens', 'Action,Adventure,Horror,Sci-Fi', 1986, 'James Cameron', 'Decades after surviving the Nostromo incident, Ellen Ripley is sent out to re-establish contact with a terraforming colony but finds herself battling the Alien Queen and her offspring.', 'https://m.media-amazon.com/images/M/MV5BZjIyNGJhYzYtN2I1My00OTVhLWEyMzItZTVjNDMzOTVkYWViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sigourney Weaver, Carrie Henn, Michael Biehn, Paul Reiser, Lance Henriksen, Bill Paxton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1201, 'Good, the Bad and the Ugly, The (Buono, il brutto, il cattivo, Il)', 'Action,Adventure,Western', 1966, 'Sergio Leone', 'A bounty-hunting scam joins two men in an uneasy alliance against a third in a race to find a fortune in gold buried in a remote cemetery.', 'https://m.media-amazon.com/images/M/MV5BMWM5ZjQxM2YtNDlmYi00ZDNhLWI4MWUtN2VkYjBlMTY1ZTkwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Eli Wallach, Clint Eastwood, Lee Van Cleef, Aldo Giuffrè, Luigi Pistilli, Rada Rassimov', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1203, '12 Angry Men', 'Drama', 1957, 'Sidney Lumet', 'The jury in a New York City murder trial is frustrated by a single member whose skeptical caution forces them to more carefully consider the evidence before jumping to a hasty verdict.', 'https://m.media-amazon.com/images/M/MV5BYjE4NzdmOTYtYjc5Yi00YzBiLWEzNDEtNTgxZGQ2MWVkN2NiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Martin Balsam, John Fiedler, Lee J. Cobb, E.G. Marshall, Jack Klugman, Edward Binns', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1206, 'Clockwork Orange, A', 'Crime,Drama,Sci-Fi,Thriller', 1971, 'Stanley Kubrick', 'Alex DeLarge and his droogs barbarize a decaying near-future.', 'https://m.media-amazon.com/images/M/MV5BMTY3MjM1Mzc4N15BMl5BanBnXkFtZTgwODM0NzAxMDE@._V1_FMjpg_UX1000_.jpg', 'Malcolm McDowell, Patrick Magee, Michael Bates, Warren Clarke, John Clive, Adrienne Corri', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1207, 'To Kill a Mockingbird', 'Drama', 1962, 'Robert Mulligan', 'A widowed lawyer in Depression-era Alabama defends a black man against a false rape charge while teaching his young children about the sad reality of prejudice.', 'https://m.media-amazon.com/images/M/MV5BZTlkYWU4MGEtZmQyYi00OWEzLTgzY2EtYzVjOTEzYzAyNTk1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gregory Peck, John Megna, Frank Overton, Rosemary Murphy, Ruth White, Brock Peters', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1208, 'Apocalypse Now', 'Action,Drama,War', 1979, 'Francis Ford Coppola', 'A U.S. Army officer serving in Vietnam is tasked with assassinating a renegade Special Forces Colonel who sees himself as a god.', 'https://m.media-amazon.com/images/M/MV5BZDhiMTljYjYtODc1Yy00MmEwLTg2OTYtYmE1YTRmNDE4MmEwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Marlon Brando, Martin Sheen, Robert Duvall, Frederic Forrest, Sam Bottoms, Laurence Fishburne', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1209, 'Once Upon a Time in the West (C\'era una volta il West)', 'Action,Drama,Western', 1968, 'Sergio Leone', 'A mysterious stranger with a harmonica teams up with a notorious desperado to protect a beautiful widow and her land from a ruthless assassin in the employ of a railroad tycoon.', 'https://m.media-amazon.com/images/M/MV5BZjYyNGY1MDEtN2I1MC00MGVhLTljZTYtODQ1NzQ0ODc2NzZlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Claudia Cardinale, Henry Fonda, Jason Robards, Charles Bronson, Gabriele Ferzetti, Paolo Stoppa', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1210, 'Star Wars: Episode VI - Return of the Jedi', 'Action,Adventure,Sci-Fi', 1983, 'Richard Marquand', 'After rescuing Han Solo from Jabba the Hutt, the Rebel Alliance attempts to destroy the second Death Star while Luke struggles to help Darth Vader back from the dark side.', 'https://m.media-amazon.com/images/M/MV5BNWEwOTI0MmUtMGNmNy00ODViLTlkZDQtZTg1YmQ3MDgyNTUzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mark Hamill, Harrison Ford, Carrie Fisher, Billy Dee Williams, Anthony Daniels, Peter Mayhew', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1213, 'Goodfellas', 'Crime,Drama', 1990, 'Martin Scorsese', 'The story of Henry Hill and his life in the mafia, covering his relationship with his wife Karen and his mob partners Jimmy Conway and Tommy DeVito.', 'https://m.media-amazon.com/images/M/MV5BN2E5NzI2ZGMtY2VjNi00YTRjLWI1MDUtZGY5OWU1MWJjZjRjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert De Niro, Ray Liotta, Joe Pesci, Lorraine Bracco, Paul Sorvino, Frank Sivero', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1214, 'Alien', 'Horror,Sci-Fi', 1979, 'Ridley Scott', 'After investigating a mysterious transmission of unknown origin, the crew of a commercial spacecraft encounters a deadly lifeform.', 'https://m.media-amazon.com/images/M/MV5BN2NhMDk2MmEtZDQzOC00MmY5LThhYzAtMDdjZGFjOGZjMjdjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Skerritt, Sigourney Weaver, Veronica Cartwright, Harry Dean Stanton, John Hurt, Ian Holm', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1215, 'Army of Darkness', 'Action,Adventure,Comedy,Fantasy,Horror', 1993, 'Sam Raimi', 'When Ash Williams is accidentally transported to 1300 A.D., he must retrieve the Necronomicon and battle an army of the dead in order to return home.', 'https://m.media-amazon.com/images/M/MV5BYzU4ZDFmNzEtNmE2Ny00OTA1LWEyMmMtZjFiOWM0MGM3YTQ1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bruce Campbell, Embeth Davidtz, Marcus Gilbert, Ian Abercrombie, Richard Grove, Michael Earl Reid', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1220, 'Blues Brothers, The', 'Action,Comedy,Musical', 1980, 'John Landis', 'Jake Blues rejoins his brother Elwood after being released from prison, but the duo has just days to reunite their old R&B band and save the Catholic home where the two were raised, outrunning the police as they tear through Chicago.', 'https://m.media-amazon.com/images/M/MV5BNzI2ZDAyNjYtNzgwOS00MTRlLWE3MjUtMTI3M2VmYzQ1ZWJmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Erhart, Gerald Walling, John Belushi, Walter Levine, Frank Oz, Dan Aykroyd', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1221, 'Godfather: Part II, The', 'Crime,Drama', 1974, 'Francis Ford Coppola', 'The early life and career of Vito Corleone in 1920s New York City is portrayed, while his son, Michael, expands and tightens his grip on the family crime syndicate.', 'https://m.media-amazon.com/images/M/MV5BMDIxMzBlZDktZjMxNy00ZGI4LTgxNDEtYWRlNzRjMjJmOGQ1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Al Pacino, Robert Duvall, Diane Keaton, Robert De Niro, John Cazale, Talia Shire', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1222, 'Full Metal Jacket', 'Drama,War', 1987, 'Stanley Kubrick', 'A pragmatic U.S. Marine observes the dehumanizing effects the Vietnam War has on his fellow recruits from their brutal boot camp training to the bloody street fighting in Hue.', 'https://m.media-amazon.com/images/M/MV5BYWUzNzZkNzUtNDdiYy00Nzk5LTgxMmItNTk0MjRjNjdjNDA0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matthew Modine, Adam Baldwin, Vincent D\'Onofrio, R. Lee Ermey, Dorian Harewood, Kevyn Major Howard', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1223, 'Grand Day Out with Wallace and Gromit, A', 'Adventure,Animation,Children,Comedy,Sci-Fi', 1989, 'Nick Park', 'To replenish their depleted supply of cheese, inventor Wallace and his dog Gromit travel to the moon in a homemade rocket-ship.', 'https://m.media-amazon.com/images/M/MV5BNmY3MDYwMDAtMmYwZS00NzZlLWIyMDAtYWYyMGQxZTdkYmJhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Peter Sallis', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1225, 'Amadeus', 'Drama', 1984, 'Milos Forman', 'The life and work of Wolfgang Amadeus Mozart seen through the eyes of his contemporary and rival, Antonio Salieri.', 'https://m.media-amazon.com/images/M/MV5BMzc2MjM0NTMtOGY4NC00NzY1LWE2ODUtZjMzY2RhNGNkZDAyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'F. Murray Abraham, Tom Hulce, Elizabeth Berridge, Roy Dotrice, Simon Callow, Christine Ebersole', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1227, 'Once Upon a Time in America', 'Crime,Drama', 1984, 'Sergio Leone', 'A former Prohibition-era Jewish gangster returns to the Lower East Side of Manhattan 35 years later, where he must once again confront the ghosts and regrets of his old life.', 'https://m.media-amazon.com/images/M/MV5BMDQ0ZTg2OGUtZjMyOC00M2M5LThkMmItZmM2MmUzMmIxMWJhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert De Niro, James Woods, Elizabeth McGovern, Treat Williams, Tuesday Weld, Burt Young', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1232, 'Stalker', 'Drama,Mystery,Sci-Fi', 1979, 'Andrei Tarkovsky', 'A guide leads two men through an area known as the Zone to find a room that grants wishes.', 'https://m.media-amazon.com/images/M/MV5BMDIzMDRiYjgtM2U1Yy00MjlhLTliODMtM2E5NDI5Njc3YmZkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Alisa Freyndlikh, Aleksandr Kaydanovskiy, Anatoliy Solonitsyn, Nikolay Grinko, Natalya Abramova, Faime Jurno', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1233, 'Boot, Das (Boat, The)', 'Action,Drama,War', 1981, 'Wolfgang Petersen', 'A German U-boat stalks the frigid waters of the North Atlantic as its young crew experience the sheer terror and claustrophobic life of a submariner in World War II.', 'https://m.media-amazon.com/images/M/MV5BNGU0MWZlMTUtM2Y3Ny00NGNmLWE5NmEtN2YxOWQzMGM3ZWYzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jürgen Prochnow, Herbert Grönemeyer, Klaus Wennemann, Hubertus Bengsch, Martin Semmelrogge, Bernd Tauber', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1234, 'Sting, The', 'Comedy,Crime', 1973, 'George Roy Hill', 'Two grifters team up to pull off the ultimate con.', 'https://m.media-amazon.com/images/M/MV5BZGI4OTk4MDMtYmQ1Ni00YTUzLTkyYTktZGUwMjMyN2M4NjQ5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Paul Newman, Robert Redford, Robert Shaw, Charles Durning, Ray Walston, Eileen Brennan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1237, 'Seventh Seal, The (Sjunde inseglet, Det)', 'Drama', 1957, 'Ingmar Bergman', 'A knight returning to Sweden after the Crusades seeks answers about life, death, and the existence of God as he plays chess against the Grim Reaper during the Black Plague.', 'https://m.media-amazon.com/images/M/MV5BZDlmYTkzOWUtODQ0MS00MmM4LWE3ZjMtYTEwNGUwMmJkYzIxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gunnar Björnstrand, Bengt Ekerot, Nils Poppe, Max von Sydow, Bibi Andersson, Inga Gill', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1240, 'Terminator, The', 'Action,Sci-Fi,Thriller', 1984, 'James Cameron', 'A cyborg assassin from the future attempts to find and kill a young woman who is destined to give birth to a warrior that will lead a resistance to save humankind from extinction.', 'https://m.media-amazon.com/images/M/MV5BZmE0YzIxM2QtMGNlMi00MjRmLWE3MWMtOWQzMGVjMmU0YTFmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Arnold Schwarzenegger, Michael Biehn, Linda Hamilton, Paul Winfield, Lance Henriksen, Rick Rossovich', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1244, 'Manhattan', 'Comedy,Drama,Romance', 1979, 'Woody Allen', 'The life of a divorced television writer dating a teenage girl is further complicated when he falls in love with his best friend\'s mistress.', 'https://m.media-amazon.com/images/M/MV5BMzhjMjEyOWItMWU2Ni00ZTE5LWFhODEtZGU1MTQyZjU4ODkzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Woody Allen, Diane Keaton, Michael Murphy, Mariel Hemingway, Meryl Streep, Anne Byrne Hoffman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1246, 'Dead Poets Society', 'Drama', 1989, 'Peter Weir', 'Maverick teacher John Keating returns in 1959 to the prestigious New England boys\' boarding school where he was once a star student, using poetry to embolden his pupils to new heights of self-expression.', 'https://m.media-amazon.com/images/M/MV5BMDYwNGVlY2ItMWYxMS00YjZiLWE5MTAtYWM5NWQ2ZWJjY2Q3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robin Williams, Robert Sean Leonard, Ethan Hawke, Josh Charles, Gale Hansen, Dylan Kussman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1247, 'Graduate, The', 'Comedy,Drama,Romance', 1967, 'Mike Nichols', 'A disillusioned college graduate finds himself torn between his older lover and her daughter.', 'https://m.media-amazon.com/images/M/MV5BMTQ0ODc4MDk4Nl5BMl5BanBnXkFtZTcwMTEzNzgzNA@@._V1_FMjpg_UX1000_.jpg', 'Anne Bancroft, Dustin Hoffman, Katharine Ross, William Daniels, Murray Hamilton, Elizabeth Wilson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1252, 'Chinatown', 'Crime,Film-Noir,Mystery,Thriller', 1974, 'Roman Polanski', 'A private detective hired to expose an adulterer in 1930s Los Angeles finds himself caught up in a web of deceit, corruption, and murder.', 'https://m.media-amazon.com/images/M/MV5BNmRmZTE0NmUtZjhiZi00MzQ3LTk3ZjctN2Q3ODYzY2U3MDk3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jack Nicholson, Faye Dunaway, John Huston, Perry Lopez, John Hillerman, Darrell Zwerling', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1257, 'Better Off Dead...', 'Comedy,Romance', 1985, 'Savage Steve Holland', 'After his girlfriend dumps him for a boorish ski jock, a depressed high-school student begins to ineptly attempt suicide, which brings him nothing but embarrassment. A French exchange student starts to change his outlook on life.', 'https://m.media-amazon.com/images/M/MV5BZGQzNmQ3MmItZjQyOS00NmEyLTgwMTQtOTM3ZTE5NGY5N2M5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Cusack, David Ogden Stiers, Kim Darby, Demian Slade, Scooter Stevens, Diane Franklin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1258, 'Shining, The', 'Horror', 1980, 'Stanley Kubrick', 'A family heads to an isolated hotel for the winter, where a sinister presence influences the father into violence. At the same time, his psychic son sees horrifying forebodings from both the past and the future.', 'https://m.media-amazon.com/images/M/MV5BNmM5ZThhY2ItOGRjOS00NzZiLWEwYTItNDgyMjFkOTgxMmRiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jack Nicholson, Shelley Duvall, Danny Lloyd, Scatman Crothers, Barry Nelson, Philip Stone', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1259, 'Stand by Me', 'Adventure,Drama', 1986, 'Rob Reiner', 'A writer recounts a childhood journey with his friends to find the body of a missing boy.', 'https://m.media-amazon.com/images/M/MV5BNGJkNTUwM2MtZWE2MS00YjNkLWE3MjktNWQwZDQxMDIyZWVmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Wil Wheaton, River Phoenix, Corey Feldman, Jerry O\'Connell, Kiefer Sutherland, Casey Siemaszko', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1265, 'Groundhog Day', 'Comedy,Fantasy,Romance', 1993, 'Harold Ramis', 'A narcissistic, self-centered weatherman finds himself in a time loop on Groundhog Day.', 'https://m.media-amazon.com/images/M/MV5BOWE3MjQ3ZDAtNDQ2MC00YjBjLTk0ZWYtNjQ0YzQ4YWE3YTEyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bill Murray, Andie MacDowell, Chris Elliott, Stephen Tobolowsky, Brian Doyle-Murray, Marita Geraghty', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1269, 'Arsenic and Old Lace', 'Comedy,Mystery,Thriller', 1944, 'Frank Capra', 'Mortimer Brewster, a Brooklyn writer of books on the futility of marriage, risks his reputation after he decides to tie the knot. Things grow complicated when he learns that his beloved maiden aunts Abby and Martha are serial murderers.', 'https://m.media-amazon.com/images/M/MV5BZmRhYTJlOTktMjg2NC00MmZmLWE2YzAtZWUwNzU4ZWY1ODlhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cary Grant, Priscilla Lane, Raymond Massey, Jack Carson, Edward Everett Horton, Peter Lorre', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1270, 'Back to the Future', 'Adventure,Comedy,Sci-Fi', 1985, 'Robert Zemeckis', 'Marty McFly, a 17-year-old high school student, is accidentally sent 30 years into the past in a time-traveling DeLorean invented by his close friend, the maverick scientist Doc Brown.', 'https://m.media-amazon.com/images/M/MV5BZmM3ZjE0NzctNjBiOC00MDZmLTgzMTUtNGVlOWFlOTNiZDJiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael J. Fox, Christopher Lloyd, Lea Thompson, Crispin Glover, Tom Wilson, Claudia Wells', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1275, 'Highlander', 'Action,Adventure,Fantasy', 1986, 'Russell Mulcahy', 'An immortal Scottish swordsman must confront the last of his immortal opponents, a murderously brutal barbarian who lusts for the fabled \"Prize\".', 'https://m.media-amazon.com/images/M/MV5BMDUzODA3ZDctODM1MS00YzY0LWI1MzUtZTU0N2UzYjRhY2M3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Christopher Lambert, Roxanne Hart, Clancy Brown, Sean Connery, Beatie Edney, Alan North', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1282, 'Fantasia', 'Animation,Children,Fantasy,Musical', 1940, 'James Algar', 'A series of eight famous pieces of classical music, conducted by Leopold Stokowski and interpreted in animation by Walt Disney\'s team of artists.', 'https://m.media-amazon.com/images/M/MV5BMmM1NGNjZWUtZTk2Zi00ZjdmLTk3Y2QtMDQyNjJjMWI1ZDFlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Deems Taylor, Leopold Stokowski, The Philadelphia Orchestra, Corey Burton, Walt Disney, Hugh Douglas', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1287, 'Ben-Hur', 'Action,Adventure,Drama', 1959, 'William Wyler', 'A Jewish prince is betrayed and sent into slavery by a Roman friend in 1st-century Jerusalem, but it\'s not long before he regains his freedom and comes back for revenge.', 'https://m.media-amazon.com/images/M/MV5BNjg2M2E1YzYtOThmMC00NjAyLWI5MzgtMDEwOGFiODdlOGUzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Charlton Heston, Jack Hawkins, Haya Harareet, Stephen Boyd, Hugh Griffith, Martha Scott', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1291, 'Indiana Jones and the Last Crusade', 'Action,Adventure', 1989, 'Steven Spielberg', 'In 1938, after his father goes missing while pursuing the Holy Grail, Indiana Jones finds himself up against the Nazis again to stop them from obtaining its powers.', 'https://m.media-amazon.com/images/M/MV5BNGIxNzQ0YzYtMjNmYi00YjBlLWFjNzEtNGE3ZGFmYTczM2MwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Harrison Ford, Sean Connery, Denholm Elliott, Alison Doody, John Rhys-Davies, Julian Glover', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1302, 'Field of Dreams', 'Children,Drama,Fantasy', 1989, 'Phil Alden Robinson', 'Iowa farmer Ray Kinsella is inspired by a voice he can\'t ignore to pursue a dream he can hardly believe. Supported by his wife, Ray begins the quest by turning his ordinary cornfield into a place where dreams can come true.', 'https://m.media-amazon.com/images/M/MV5BZTEwMGYzNDktOWEyMi00NTJjLWE5MGQtNmNlNDkxOTYyZDA5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kevin Costner, Amy Madigan, Gaby Hoffmann, Ray Liotta, Timothy Busfield, James Earl Jones', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1307, 'When Harry Met Sally...', 'Comedy,Romance', 1989, 'Rob Reiner', 'Harry and Sally have known each other for years, and are very good friends, but they fear sex would ruin the friendship.', 'https://m.media-amazon.com/images/M/MV5BMjE0ODEwNjM2NF5BMl5BanBnXkFtZTcwMjU2Mzg3NA@@._V1_FMjpg_UX1000_.jpg', 'Billy Crystal, Meg Ryan, Carrie Fisher, Bruno Kirby, Steven Ford, Lisa Jane Persky', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1320, 'Alien³ (a.k.a. Alien 3)', 'Action,Horror,Sci-Fi,Thriller', 1992, 'David Fincher', 'Returning from LV-426, Ellen Ripley crash-lands on the maximum-security prison Fiorina 161, where she discovers that she has unwittingly brought along an unwelcome visitor.', 'https://m.media-amazon.com/images/M/MV5BOGZiNmVlZGEtM2VmMi00ZTFkLTliMzEtZDNhYzUzNTcxMGY3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sigourney Weaver, Charles S. Dutton, Charles Dance, Paul McGann, Brian Glover, Ralph Brown', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1339, 'Dracula (Bram Stoker\'s Dracula)', 'Fantasy,Horror,Romance,Thriller', 1992, 'Francis Ford Coppola', 'Centuries-old vampire Count Dracula comes to England to seduce his barrister Jonathan Harker\'s fiancée Mina Murray and wreak havoc in the foreign land.', 'https://m.media-amazon.com/images/M/MV5BMmVhNzhlMzMtYjJkNy00ODU4LWJmMjUtYzdlMGI3MTQ3YzBhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gary Oldman, Winona Ryder, Anthony Hopkins, Keanu Reeves, Richard E. Grant, Cary Elwes', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1342, 'Candyman', 'Horror,Thriller', 1992, 'Bernard Rose', 'The Candyman, a murderous soul with a hook for a hand, is accidentally summoned to reality by a skeptic grad student researching the monster\'s myth.', 'https://m.media-amazon.com/images/M/MV5BMmZhN2NhOTEtMmVhZC00NWM5LWE4ODgtZGUwMDQxOGViNjY4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Virginia Madsen, Tony Todd, Xander Berkeley, Kasi Lemmons, Vanessa Williams, DeJuan Guy', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1343, 'Cape Fear', 'Thriller', 1991, 'Martin Scorsese', 'A convicted rapist, released from prison after serving a fourteen-year sentence, stalks the family of the lawyer who originally defended him.', 'https://m.media-amazon.com/images/M/MV5BNTBkNTYwZTctOTgxYS00ZmIyLTgzNDAtODJhZjg2MDUwNmFlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert De Niro, Nick Nolte, Jessica Lange, Juliette Lewis, Joe Don Baker, Robert Mitchum', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1347, 'Nightmare on Elm Street, A', 'Horror,Thriller', 1984, 'Wes Craven', 'Teenager Nancy Thompson must uncover the dark truth concealed by her parents after she and her friends become targets of the spirit of a serial killer with a bladed glove in their dreams, in which if they die, it kills them in real life.', 'https://m.media-amazon.com/images/M/MV5BNTZmN2VlMWMtMTdlMi00NDBhLWIyODMtODEwMzM0ODMwMWYwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Saxon, Ronee Blakley, Heather Langenkamp, Amanda Wyss, Jsu Garcia, Johnny Depp', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1356, 'Star Trek: First Contact', 'Action,Adventure,Sci-Fi,Thriller', 1996, 'Jonathan Frakes', 'The Borg travel back in time intent on preventing Earth\'s first contact with an alien species. Captain Picard and his crew pursue them to ensure that Zefram Cochrane makes his maiden flight reaching warp speed.', 'https://m.media-amazon.com/images/M/MV5BZjc0OWE1NDMtNjRmMi00ZDc2LWI2ZmQtNzEwNWU4Nzg4NDA5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Patrick Stewart, Jonathan Frakes, Brent Spiner, LeVar Burton, Michael Dorn, Gates McFadden', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1370, 'Die Hard 2', 'Action,Adventure,Thriller', 1990, 'Renny Harlin', 'John McClane must race against time to save hundreds of lives (including his wife\'s) when a group of terrorists take control of Washington Dulles Airport\'s systems, and threaten to crash several planes if their demands are not met.', 'https://m.media-amazon.com/images/M/MV5BMTA1OGFlZWUtZjE4Yy00MzFmLTlhYjctOGY5ZmZjOWFlOWUwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bruce Willis, Bonnie Bedelia, William Atherton, Reginald VelJohnson, Franco Nero, William Sadler', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1387, 'Jaws', 'Action,Horror', 1975, 'Steven Spielberg', 'When a massive killer shark unleashes chaos on a beach community off Long Island, it\'s up to the local police chief, a marine biologist, and an old seafarer to hunt the beast down.', 'https://m.media-amazon.com/images/M/MV5BYjViNDQzNmUtYzkxZi00NTk5LTljMmItYjJlZmZkODIxNjU1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Roy Scheider, Robert Shaw, Richard Dreyfuss, Lorraine Gary, Murray Hamilton, Carl Gottlieb', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1391, 'Mars Attacks!', 'Action,Comedy,Sci-Fi', 1996, 'Tim Burton', 'Earth is invaded by Martians with unbeatable weapons and a cruel sense of humor.', 'https://m.media-amazon.com/images/M/MV5BZjJhNTIxZmQtZjQ3ZC00MTZkLWI2YTItY2Y0ZTdiMmNiNGIyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jack Nicholson, Glenn Close, Annette Bening, Pierce Brosnan, Danny DeVito, Martin Short', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1393, 'Jerry Maguire', 'Drama,Romance', 1996, 'Cameron Crowe', 'When a sports agent has a moral epiphany and is fired for expressing it, he decides to put his new philosophy to the test as an independent agent with the only athlete who stays with him and his former colleague.', 'https://m.media-amazon.com/images/M/MV5BM2E1ZjU1MjctZjU2Yi00MGE1LWI1MDEtYzBlMWJlNDc1NTQxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Cuba Gooding Jr., Renée Zellweger, Kelly Preston, Jerry O\'Connell, Jay Mohr', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1396, 'Sneakers', 'Action,Comedy,Crime,Drama,Sci-Fi', 1992, 'Phil Alden Robinson', 'A security pro finds his past returning to haunt him when he and his unique team are tasked with retrieving a particularly important item.', 'https://m.media-amazon.com/images/M/MV5BMGEwMmZlMjgtNDc0MS00NmY1LTljMzQtMzBmNmE0OWRkNjViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jo Marr, Gary Hershberger, Robert Redford, Sidney Poitier, David Strathairn, Dan Aykroyd', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1407, 'Scream', 'Comedy,Horror,Mystery,Thriller', 1996, 'Wes Craven', 'In the small town of Woodsboro, California, a masked killer known as Ghostface begins murdering high school students, and a group of friends must use their knowledge of horror movies to unmask the killer.', 'https://m.media-amazon.com/images/M/MV5BMjA2NjU5MTg5OF5BMl5BanBnXkFtZTgwOTkyMzQxMDE@._V1_FMjpg_UX1000_.jpg', 'Drew Barrymore, Roger Jackson, Kevin Patrick Walls, David Booth, Carla Hatley, Neve Campbell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1464, 'Lost Highway', 'Crime,Drama,Fantasy,Film-Noir,Mystery,Romance', 1997, 'David Lynch', 'Anonymous videotapes presage a musician\'s murder conviction, and a gangster\'s girlfriend leads a mechanic astray.', 'https://m.media-amazon.com/images/M/MV5BNjcyNmM2ODktYzk0Mi00Njk0LTljZGMtNGZhMzI4NmY1NzA1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bill Pullman, Patricia Arquette, John Roselius, Louis Eppolito, Jenna Maetlind, Michael Massee', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1466, 'Donnie Brasco', 'Crime,Drama', 1997, 'Mike Newell', 'An FBI undercover agent infiltrates the mob and finds himself identifying more with the Mafia life--at the expense of his regular one.', 'https://m.media-amazon.com/images/M/MV5BZWZkNDA2YTctZWJhZS00OTAzLThlODMtY2QyMzg1MTEwYjU2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Al Pacino, Johnny Depp, Michael Madsen, Bruno Kirby, James Russo, Anne Heche', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1479, 'Saint, The', 'Action,Romance,Sci-Fi,Thriller', 1997, 'Phillip Noyce', 'Simon \"The Saint\" Templar (Val Kilmer) is a thief for hire whose latest job to steal the secret process for cold fusion puts him at odds with a traitor bent on toppling the Russian government, as well as the woman who holds its secret.', 'https://m.media-amazon.com/images/M/MV5BNzFiY2VmYmMtZWM4Yi00OWJiLTgxNGUtZjJlYjc2NGU0YmQ4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Val Kilmer, Elisabeth Shue, Rade Serbedzija, Valeriy Nikolaev, Henry Goodman, Alun Armstrong', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1485, 'Liar Liar', 'Comedy', 1997, 'Tom Shadyac', 'A pathological liar-lawyer finds his career turned upside down when he inexplicably cannot physically lie for 24 whole hours.', 'https://m.media-amazon.com/images/M/MV5BMGQ4MTk5YjctNGE5NC00ODk4LWIzOWItNzNhODc0N2JmYzMzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jim Carrey, Maura Tierney, Justin Cooper, Cary Elwes, Anne Haney, Jennifer Tilly', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1500, 'Grosse Pointe Blank', 'Comedy,Crime,Romance', 1997, 'George Armitage', 'Professional assassin Martin Blank is sent on a mission to a small Detroit suburb, Grosse Pointe--where, by coincidence, his 10-year high-school reunion party is about to take place.', 'https://m.media-amazon.com/images/M/MV5BZDJkMWJkMTgtZjljZS00ZDNlLWE2MjEtNjQ2NzI5NDk4MTRkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Cusack, Minnie Driver, Alan Arkin, Dan Aykroyd, Joan Cusack, Hank Azaria', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1517, 'Austin Powers: International Man of Mystery', 'Action,Adventure,Comedy', 1997, 'Jay Roach', 'A world-class playboy and part-time secret agent from the 1960s emerges after thirty years in a cryogenic state to battle with his nemesis Dr. Evil.', 'https://m.media-amazon.com/images/M/MV5BODQzM2UwODQtMzg1ZC00MTk4LTlkOTEtYzU4NDFhYmM1MWJkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mike Myers, Elizabeth Hurley, Michael York, Mimi Rogers, Robert Wagner, Seth Green', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1527, 'Fifth Element, The', 'Action,Adventure,Comedy,Sci-Fi', 1997, 'Luc Besson', 'In the colorful future, cabdriver Korben Dallas unwittingly becomes the central figure in the search for a legendary cosmic weapon to keep the great evil and Jean-Baptiste Emmanuel Zorg at bay.', 'https://m.media-amazon.com/images/M/MV5BODU4ZTE5MWYtNmY2MC00NDkyLTk0NDgtNTk5YjgzMzc4NmQwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bruce Willis, Gary Oldman, Ian Holm, Milla Jovovich, Chris Tucker, Luke Perry', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1566, 'Hercules', 'Adventure,Animation,Children,Comedy,Musical', 1997, 'Ron Clements', 'The son of Zeus and Hera is stripped of his immortality as an infant and must become a true hero in order to reclaim it.', 'https://m.media-amazon.com/images/M/MV5BMmUyZGY1ZjItMWYwZS00MjJjLTg1YzAtY2Q5OTA4MmFhYzFjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Barbara Barrie, Roger Bart, Mary Kay Bergman, Corey Burton, Danny DeVito, Jim Cummings', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1573, 'Face/Off', 'Action,Crime,Drama,Thriller', 1997, 'John Woo', 'To foil a terrorist plot, an FBI agent assumes the identity of the criminal who murdered his son via facial transplant surgery, but the crook wakes up prematurely and vows revenge.', 'https://m.media-amazon.com/images/M/MV5BOGQyOWNmYTgtZWY0NS00NzhjLTg3NmMtMzcwYzQ2OTA2OTJkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Travolta, Nicolas Cage, Joan Allen, Alessandro Nivola, Gina Gershon, Dominique Swain', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1580, 'Men in Black (a.k.a. MIB)', 'Action,Comedy,Sci-Fi', 1997, 'Barry Sonnenfeld', 'James, an NYC cop, is hired by Agent K of a secret government agency that monitors extraterrestrial life on Earth. Together, they must recover an item that has been stolen by an intergalactic villain.', 'https://m.media-amazon.com/images/M/MV5BZmQ0YTdhYzEtMjIxZC00MGFiLTlmNjktZmFlOWE2M2QxOTRhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tommy Lee Jones, Will Smith, Linda Fiorentino, Vincent D\'Onofrio, Rip Torn, Tony Shalhoub', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1584, 'Contact', 'Drama,Sci-Fi', 1997, 'Robert Zemeckis', 'Dr. Ellie Arroway, after years of searching, finds conclusive radio proof of extraterrestrial intelligence, sending plans for a mysterious machine.', 'https://m.media-amazon.com/images/M/MV5BM2JiYmE1Y2UtNDQ3YS00YTZhLTk5MzAtYzEzMzIyNTM4OTRlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jena Malone, David Morse, Jodie Foster, Geoffrey Blake, William Fichtner, SaMi Chester', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1597, 'Conspiracy Theory', 'Drama,Mystery,Romance,Thriller', 1997, 'Richard Donner', 'A taxi driver with a penchant for conspiracy theories becomes a target after one of these theories turns out to be true. Unfortunately, to save himself, he has to figure out which theory it is.', 'https://m.media-amazon.com/images/M/MV5BMjQ1MTYxMzA4OF5BMl5BanBnXkFtZTgwNjg2NTM1MTI@._V1_FMjpg_UX1000_.jpg', 'Mel Gibson, Julia Roberts, Patrick Stewart, Cylk Cozart, Steve Kahan, Terry Alexander', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1608, 'Air Force One', 'Action,Thriller', 1997, 'Wolfgang Petersen', 'Communist radicals led by Ivan Korshunov hijack Air Force One with US President James Marshall and his family on board. Vice President Kathryn Bennett negotiates from Washington D.C., while Marshall fights to rescue the hostages on board.', 'https://m.media-amazon.com/images/M/MV5BOTVlYmFhZjktOTA2ZC00Y2YzLWFmNDMtZGU2YzBkNGZkODY4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Harrison Ford, Gary Oldman, Glenn Close, Wendy Crewson, Liesel Matthews, Paul Guilfoyle', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1610, 'Hunt for Red October, The', 'Action,Adventure,Thriller', 1990, 'John McTiernan', 'Moscow, Washington D.C. and a CIA Analyst track a rogue Soviet Captain and his new submarine.', 'https://m.media-amazon.com/images/M/MV5BMmNhYWJmN2EtZDYwNC00NzE0LWE5N2UtZTUyMDM4YjZmYWE3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sean Connery, Alec Baldwin, Scott Glenn, Sam Neill, James Earl Jones, Joss Ackland', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1617, 'L.A. Confidential', 'Crime,Film-Noir,Mystery,Thriller', 1997, 'Curtis Hanson', 'As corruption grows in 1950s Los Angeles, three policemen - one strait-laced, one brutal, and one sleazy - investigate a series of murders with their own brand of justice.', 'https://m.media-amazon.com/images/M/MV5BODdiMjY1OGYtNDk0NC00NGQ1LWI4MDItOTJhMTM0YjE1YTAzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kevin Spacey, Russell Crowe, Guy Pearce, James Cromwell, Kim Basinger, Danny DeVito', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1625, 'Game, The', 'Drama,Mystery,Thriller', 1997, 'David Fincher', 'A mysterious game invades a man\'s ordered existence.', 'https://m.media-amazon.com/images/M/MV5BNGUzNzQwNmMtNzI3Mi00ZDIwLWJlM2ItMTA5N2Q2ZDMxMjJiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Douglas, Sean Penn, Deborah Kara Unger, James Rebhorn, Peter Donat, Carroll Baker', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1639, 'Chasing Amy', 'Comedy,Drama,Romance', 1997, 'Kevin Smith', 'Holden and Banky are comic book artists. Everything\'s going good for them until they meet Alyssa, also a comic book artist. Holden falls for her, but his hopes are crushed when he finds out she\'s a lesbian.', 'https://m.media-amazon.com/images/M/MV5BZWQ5OWQ4NWEtZGJlYy00MzI3LTg5YzItZjVhYjJhYmNkZjM4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ethan Suplee, Ben Affleck, Scott Mosier, Jason Lee, Casey Affleck, Joey Lauren Adams', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1641, 'Full Monty, The', 'Comedy,Drama', 1997, 'Peter Cattaneo', 'Six unemployed steel workers form a male striptease act. The women cheer them on to go for \"the full monty\" - total nudity.', 'https://m.media-amazon.com/images/M/MV5BYjZjNjU4YjItM2NhNS00NzIwLWIzMjMtMGMzZjcyMjYwYzE2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert Carlyle, Mark Addy, Wim Snape, Steve Huison, Tom Wilkinson, Paul Barber', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1645, 'The Devil\'s Advocate', 'Drama,Mystery,Thriller', 1997, 'Taylor Hackford', 'An exceptionally adept Florida lawyer is offered a job at a high-end New York City law firm with a high-end boss - the biggest opportunity of his career to date.', 'https://m.media-amazon.com/images/M/MV5BNGIxZmU2ZjEtYjc3OC00Y2FiLWE2ZTQtZGI3NzE0YmRhOTMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Keanu Reeves, Al Pacino, Charlize Theron, Jeffrey Jones, Judith Ivey, Connie Nielsen', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1653, 'Gattaca', 'Drama,Sci-Fi,Thriller', 1997, 'Andrew Niccol', 'Vincent, an \"In-Valid,\" assumes the identity of a member of the genetic elite to pursue his goal of traveling into space with the Gattaca Aerospace Corporation. However, a week before his mission, a murder marks Vincent as a suspect.', 'https://m.media-amazon.com/images/M/MV5BZjQxNTc3YzQtZDA5ZC00MmM5LWE3NGYtMGE0Yjk3MDYwODVlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ethan Hawke, Uma Thurman, Gore Vidal, Xander Berkeley, Jayne Brook, Elias Koteas', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1663, 'Stripes', 'Comedy,War', 1981, 'Ivan Reitman', 'Two friends who are dissatisfied with their jobs decide to join the army for a bit of fun.', 'https://m.media-amazon.com/images/M/MV5BM2VjZDExMjctMGVjMS00MDQxLWI2NTQtODJjNjNkN2ExY2FkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bill Murray, Harold Ramis, Warren Oates, P.J. Soles, Sean Young, John Candy', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1673, 'Boogie Nights', 'Drama', 1997, 'Paul Thomas Anderson', 'An idealistic porn producer aspires to elevate his craft to an art when he discovers a hot young talent.', 'https://m.media-amazon.com/images/M/MV5BOTFmZmE4OTMtNDYxNi00MmZmLThlYjktMmExMzMwY2YzOTFiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Luis Guzmán, Burt Reynolds, Julianne Moore, Rico Bueno, John C. Reilly, Nicole Ari Parker', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1674, 'Witness', 'Drama,Romance,Thriller', 1985, 'Peter Weir', 'While protecting an Amish boy - the sole witness to a brutal murder - and his mother, a Philadelphia police detective is forced to seek refuge within their rural community when his own life is threatened.', 'https://m.media-amazon.com/images/M/MV5BNDcyNjU5MWMtNDZiYy00Yjc4LWE4YjItMTA5ODBlOGU1NzRhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Harrison Ford, Kelly McGillis, Josef Sommer, Lukas Haas, Jan Rubes, Alexander Godunov', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1676, 'Starship Troopers', 'Action,Sci-Fi', 1997, 'Paul Verhoeven', 'Humans, in a fascist militaristic future, wage war with giant alien bugs.', 'https://m.media-amazon.com/images/M/MV5BZTNiOGM1ZWUtZTZjZC00OWJmLWE2YzUtZjQ4ODZjZmVlMDU3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Casper Van Dien, Dina Meyer, Denise Richards, Jake Busey, Neil Patrick Harris, Clancy Brown', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1682, 'Truman Show, The', 'Comedy,Drama,Sci-Fi', 1998, 'Peter Weir', 'An insurance salesman begins to suspect that his whole life is actually some sort of reality TV show.', 'https://m.media-amazon.com/images/M/MV5BNzA3ZjZlNzYtMTdjMy00NjMzLTk5ZGYtMTkyYzNiOGM1YmM3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jim Carrey, Laura Linney, Noah Emmerich, Natascha McElhone, Holland Taylor, Brian Delate', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1688, 'Anastasia', 'Adventure,Animation,Children,Drama,Musical', 1997, 'Don Bluth', 'The last surviving child of the Russian Royal Family joins two con men to reunite with her grandmother, the Dowager Empress, while the undead Rasputin seeks her death.', 'https://m.media-amazon.com/images/M/MV5BMGY2YjdjNTItMGIzOC00MDNhLTkxNDMtNzgxN2U4YzA3YzRlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Meg Ryan, John Cusack, Kelsey Grammer, Christopher Lloyd, Hank Azaria, Bernadette Peters', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1690, 'Alien: Resurrection', 'Action,Horror,Sci-Fi', 1997, 'Jean-Pierre Jeunet', 'Two centuries after her death, a powerful human/alien hybrid clone of Ellen Ripley aids a crew of space pirates in stopping the aliens from reaching Earth.', 'https://m.media-amazon.com/images/M/MV5BNDMyNmU5ZGQtNzhiZi00NjRjLTk3NGUtMmQ5YWU4ODlkNTBhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sigourney Weaver, Winona Ryder, Dominique Pinon, Ron Perlman, Gary Dourdan, Michael Wincott', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1704, 'Good Will Hunting', 'Drama,Romance', 1997, 'Gus Van Sant', 'A therapist counsels Will Hunting, a janitor with a genius IQ.', 'https://m.media-amazon.com/images/M/MV5BNDdjZGQ5YzEtNTc2My00Mjc0LWFlMTctYzkwMzZlNzdiZWYzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matt Damon, Ben Affleck, Stellan Skarsgård, John Mighton, Rachel Majorowski, Colleen McCauley', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1721, 'Titanic', 'Drama,Romance', 1997, 'James Cameron', 'A seventeen-year-old aristocrat falls in love with a kind but poor artist aboard the luxurious, ill-fated R.M.S. Titanic.', 'https://m.media-amazon.com/images/M/MV5BYzYyN2FiZmUtYWYzMy00MzViLWJkZTMtOGY1ZjgzNWMwN2YxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Kate Winslet, Billy Zane, Kathy Bates, Frances Fisher, Gloria Stuart', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1722, 'Tomorrow Never Dies', 'Action,Adventure,Thriller', 1997, 'Roger Spottiswoode', 'James Bond is sent to disrupt a media mogul\'s plot to foment a war between China and the United Kingdom.', 'https://m.media-amazon.com/images/M/MV5BMTM1MTk2ODQxNV5BMl5BanBnXkFtZTcwOTY5MDg0NA@@._V1_FMjpg_UX1000_.jpg', 'Pierce Brosnan, Jonathan Pryce, Michelle Yeoh, Teri Hatcher, Ricky Jay, Götz Otto', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1729, 'Jackie Brown', 'Crime,Drama,Thriller', 1997, 'Quentin Tarantino', 'A flight attendant with a criminal past gets nabbed by the ATF for smuggling. Under pressure to become an informant against the illegal arms dealer she works for, she must find a way to secure her future without getting killed.', 'https://m.media-amazon.com/images/M/MV5BZmUxZjY3MDktNGI5NS00MTQ5LWE0YWItZWQzNmZhNjhkZDYyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Pam Grier, Samuel L. Jackson, Robert Forster, Bridget Fonda, Michael Keaton, Robert De Niro', '2025-11-24 12:30:37');
