INSERT INTO `movies` VALUES (1748, 'Dark City', 'Adventure,Film-Noir,Sci-Fi,Thriller', 1998, 'Alex Proyas', 'A man struggles with memories of his past, which include a wife he cannot remember and a nightmarish world no one else ever seems to wake up from.', 'https://m.media-amazon.com/images/M/MV5BMTFhMmE1YzgtNTFhYS00MTRlLWI3ZDMtMWJkMTBmOWMzOTk5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Rufus Sewell, William Hurt, Kiefer Sutherland, Jennifer Connelly, Richard O\'Brien, Ian Richardson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1777, 'Wedding Singer, The', 'Comedy,Romance', 1998, 'Frank Coraci', 'Robbie, a singer, and Julia, a waitress, are both engaged, but to the wrong people. Fortune intervenes to help them discover each other.', 'https://m.media-amazon.com/images/M/MV5BNjU5MGYxNGMtMWZjNC00ZGYxLWIzY2YtNWExNDFlNmQwYzU0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Adam Sandler, Drew Barrymore, Christine Taylor, Allen Covert, Matthew Glave, Ellen Albertini Dow', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1784, 'As Good as It Gets', 'Comedy,Drama,Romance', 1997, 'James L. Brooks', 'A single mother and waitress, a misanthropic author, and a gay artist form an unlikely friendship after the artist is assaulted in a robbery.', 'https://m.media-amazon.com/images/M/MV5BMzBiMWJhYmQtOWYzNS00NjgxLWE5NDItNzZlZDQwODBmODNjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jack Nicholson, Helen Hunt, Greg Kinnear, Cuba Gooding Jr., Skeet Ulrich, Shirley Knight', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1801, 'Man in the Iron Mask, The', 'Action,Adventure,Drama', 1998, 'Randall Wallace', 'The cruel King Louis XIV of France has a secret twin brother whom he keeps imprisoned. Can the twin be substituted for the real king?', 'https://m.media-amazon.com/images/M/MV5BNDc4YWYzNzEtNWMwMC00Y2ZlLWEzZWEtZDcwYjcwYTE3Y2ZlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Jeremy Irons, John Malkovich, Gérard Depardieu, Gabriel Byrne, Anne Parillaud', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1831, 'Lost in Space', 'Action,Adventure,Sci-Fi', 1998, 'Stephen Hopkins', 'The Robinson family was going into space to fight for a chance for humanity. Now they are fighting to live long enough to find a way home.', 'https://m.media-amazon.com/images/M/MV5BMzViNDBjNDMtMmYxOS00ZDcyLTk4NGQtZGQwMmIyODc2NGZmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'William Hurt, Mimi Rogers, Heather Graham, Lacey Chabert, Jack Johnson, Gary Oldman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1882, 'Godzilla', 'Action,Sci-Fi,Thriller', 1998, 'Roland Emmerich', 'French nuclear tests irradiate an iguana into a giant monster that heads off to New York City. The American military must chase the monster across the city to stop it before it reproduces.', 'https://m.media-amazon.com/images/M/MV5BMzdmYmUzYjAtMmJhNi00NGU3LWJiODYtM2I5MGFhZjBhM2NhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matthew Broderick, Jean Reno, Maria Pitillo, Hank Azaria, Kevin Dunn, Michael Lerner', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1884, 'Fear and Loathing in Las Vegas', 'Adventure,Comedy,Drama', 1998, 'Terry Gilliam', 'An oddball journalist and his psychopathic lawyer travel to Las Vegas for a series of psychedelic escapades.', 'https://m.media-amazon.com/images/M/MV5BNjFkNjdiZjUtNzUzNy00NWM5LWFlNDUtNTRiYmJiZWNiYjkwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Benicio Del Toro, Tobey Maguire, Michael Lee Gogin, Larry Cedar, Brian Le Baron', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1907, 'Mulan', 'Adventure,Animation,Children,Comedy,Drama,Musical,Romance', 1998, 'Tony Bancroft', 'To save her father from death in the army, a young maiden secretly goes in his place and becomes one of China\'s greatest heroines in the process.', 'https://m.media-amazon.com/images/M/MV5BYzU0ZTQxZDktOGY0Yy00NjdiLTllNDItMTMzMjI1YjMyYjRhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Miguel Ferrer, Harvey Fierstein, Freda Foh Shen, June Foray, James Hong, Miriam Margolyes', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1912, 'Out of Sight', 'Comedy,Crime,Drama,Romance,Thriller', 1998, 'Steven Soderbergh', 'A career bank robber breaks out of jail, and shares a moment of mutual attraction with a U.S. Marshal he has kidnapped.', 'https://m.media-amazon.com/images/M/MV5BM2U3OGQ0NTMtNmQxYS00MmRiLTg2OTctZDI3ZjNjZjM5N2NlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'George Clooney, Jim Robinson, Mike Malone, Donna Frenzel, Manny Suárez, Keith Hudson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1917, 'Armageddon', 'Action,Romance,Sci-Fi,Thriller', 1998, 'Michael Bay', 'After discovering that an asteroid the size of Texas will impact Earth in less than a month, NASA recruits a misfit team of deep-core drillers to save the planet.', 'https://m.media-amazon.com/images/M/MV5BYzQ3MzJmZjUtNTc0OC00ZWRiLWJkMTYtMTZkMDVhMDQ4OGU4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bruce Willis, Billy Bob Thornton, Ben Affleck, Liv Tyler, Will Patton, Steve Buscemi', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1921, 'Pi', 'Drama,Sci-Fi,Thriller', 1998, 'Darren Aronofsky', 'A paranoid mathematician searches for a key number that will unlock the universal patterns found in nature.', 'https://m.media-amazon.com/images/M/MV5BNWExNjZlZGQtYjIxMS00ZTAyLTkzMjktOWVlMDg0NTM2OTUxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sean Gullette, Mark Margolis, Ben Shenkman, Pamela Hart, Stephen Pearlman, Samia Shoaib', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1923, 'There\'s Something About Mary', 'Comedy,Romance', 1998, 'Bobby Farrelly', 'A man gets a chance to meet up with his dream girl from high school, even though his date with her back then was a complete disaster.', 'https://m.media-amazon.com/images/M/MV5BNWZjMDhkZGItOGE4OS00YjUyLTlmOTUtMjE0ZDVmM2I2YmU0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cameron Diaz, Matt Dillon, Ben Stiller, Lee Evans, Chris Elliott, Lin Shaye', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1953, 'French Connection, The', 'Action,Crime,Thriller', 1971, 'William Friedkin', 'A pair of NYPD detectives in the Narcotics Bureau stumble onto a heroin smuggling ring based in Marseilles, but stopping them and capturing their leaders proves an elusive goal.', 'https://m.media-amazon.com/images/M/MV5BZDAyZDU3OWUtNWQ3Zi00ZWRkLWI4MGEtNDFlZWIzZDk5ZTZkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gene Hackman, Fernando Rey, Roy Scheider, Tony Lo Bianco, Marcel Bozzuffi, Frédéric de Pasquale', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1954, 'Rocky', 'Drama', 1976, 'John G. Avildsen', 'A small-time Philadelphia boxer gets a supremely rare chance to fight the world heavyweight champion in a bout in which he strives to go the distance for his self-respect.', 'https://m.media-amazon.com/images/M/MV5BZDEyY2M2MGMtYjg5OC00ZWFjLWFkZDQtNmQzZTdiYmYzZTBkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sylvester Stallone, Talia Shire, Burt Young, Carl Weathers, Burgess Meredith, Thayer David', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1955, 'Kramer vs. Kramer', 'Drama', 1979, 'Robert Benton', 'After his wife leaves him, a work-obsessed Manhattan advertising executive is forced to learn long-neglected parenting skills, but a heated custody battle over the couple\'s young son deepens the wounds left by the separation.', 'https://m.media-amazon.com/images/M/MV5BNTJmYjYwZDMtYmU5MS00OWM0LWIxZTctZTcxODJkOTU4ZDMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dustin Hoffman, Meryl Streep, Jane Alexander, Justin Henry, Howard Duff, George Coe', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1956, 'Ordinary People', 'Drama', 1980, 'Robert Redford', 'The accidental death of the older son of an affluent family deeply strains the relationships among the bitter mother, the good-natured father and the guilt-ridden younger son.', 'https://m.media-amazon.com/images/M/MV5BODkyODllNDQtMTRjZS00ZGM5LWFmYmQtMzlhZjNhZjgwOGVhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Donald Sutherland, Mary Tyler Moore, Judd Hirsch, Timothy Hutton, M. Emmet Walsh, Elizabeth McGovern', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1961, 'Rain Man', 'Drama', 1988, 'Barry Levinson', 'After a selfish L.A. yuppie learns his estranged father left a fortune to an autistic-savant brother in Ohio that he didn\'t know existed, he absconds with his brother and sets out across the country, hoping to gain a larger inheritance.', 'https://m.media-amazon.com/images/M/MV5BZDUzODNkNGUtNzJjNi00ODFlLTkzMzktMGNkOTIwYWM2YTQzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dustin Hoffman, Tom Cruise, Valeria Golino, Gerald R. Molen, Jack Murdock, Michael D. Roberts', '2025-11-24 12:30:37');
