INSERT INTO `movies` VALUES (1968, 'Breakfast Club, The', 'Comedy,Drama', 1985, 'John Hughes', 'Five high school students meet in Saturday detention and discover how they have a great deal more in common than they thought.', 'https://m.media-amazon.com/images/M/MV5BZTZiMGU1MWMtNjk0Yi00ZjNjLTljMDEtMDhkNGE2OWY3YzZiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Emilio Estevez, Paul Gleason, Anthony Michael Hall, John Kapelos, Judd Nelson, Molly Ringwald', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1974, 'Friday the 13th', 'Horror,Mystery,Thriller', 1980, 'Sean S. Cunningham', 'A group of teenage camp counselors attempt to re-open an abandoned summer camp with a tragic past, but they are stalked by a mysterious, relentless killer.', 'https://m.media-amazon.com/images/M/MV5BZjEwOTY5MjMtMTkzMi00Zjk1LThkM2QtZGZhMzQ3MzI3NDNhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Betsy Palmer, Adrienne King, Jeannine Taylor, Robbi Morgan, Kevin Bacon, Harry Crosby', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1982, 'Halloween', 'Horror', 1978, 'John Carpenter', 'Fifteen years after murdering his sister on Halloween night 1963, Michael Myers escapes from a mental hospital and returns to the small town of Haddonfield, Illinois, to kill again.', 'https://m.media-amazon.com/images/M/MV5BMzZiNTdiYTgtYjNkMS00MmJmLWEwZGQtNmY0NGJkMGE0YmYzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Donald Pleasence, Jamie Lee Curtis, Nancy Kyes, P.J. Soles, Charles Cyphers, Kyle Richards', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1992, 'Child\'s Play 2', 'Horror,Thriller', 1990, 'John Lafia', 'While Andy\'s mother is admitted to a psychiatric hospital, the young boy is placed in foster care, and Chucky, determined to claim Andy\'s soul, is not far behind.', 'https://m.media-amazon.com/images/M/MV5BNmQ5ZWRhZmMtOWI0OC00OWMzLWIwNzgtMzYzNjNhZDEwNTE1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Alex Vincent, Jenny Agutter, Gerrit Graham, Christine Elise, Brad Dourif, Grace Zabriskie', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1993, 'Child\'s Play 3', 'Comedy,Horror,Thriller', 1991, 'Jack Bender', 'Chucky returns for revenge against Andy, the young boy who defeated him, and now a teenager living in a military academy.', 'https://m.media-amazon.com/images/M/MV5BNzc0NjExMTgtYTA4ZS00NWRiLWE3MzUtNTUyNDFkNGY3ODRkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Justin Whalin, Perrey Reeves, Jeremy Sylvers, Travis Fine, Dean Jacobson, Brad Dourif', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (1997, 'Exorcist, The', 'Horror,Mystery', 1973, 'William Friedkin', 'When a mysterious entity possesses a young girl, her mother seeks the help of two Catholic priests to save her life.', 'https://m.media-amazon.com/images/M/MV5BZjg3YjE4ZjAtYTdmYS00ZTBkLWE1ZjgtNzAzODUwNzRiYjlmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ellen Burstyn, Max von Sydow, Lee J. Cobb, Kitty Winn, Jack MacGowran, Jason Miller', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2000, 'Lethal Weapon', 'Action,Comedy,Crime,Drama', 1987, 'Richard Donner', 'Two newly paired cops who are complete opposites must put aside their differences in order to catch a gang of drug smugglers.', 'https://m.media-amazon.com/images/M/MV5BMWVlNWZlODktMzhhNS00YThhLWEzZWYtYzU0NDFmNzk0MGVlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mel Gibson, Danny Glover, Gary Busey, Mitchell Ryan, Tom Atkins, Darlene Love', '2025-11-24 12:30:37');
