INSERT INTO `movies` VALUES (2003, 'Gremlins', 'Comedy,Horror', 1984, 'Joe Dante', 'After receiving an exotic small animal as a Christmas gift, a young man inadvertently breaks three important rules concerning his new pet, which unleashes a horde of malevolently mischievous creatures on a small town.', 'https://m.media-amazon.com/images/M/MV5BYmMzMmIxNzYtYjk3OS00NjBiLTkxNDQtODU3ZDNjN2RiMTIxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Hoyt Axton, John Louie, Keye Luke, Don Steele, Susan Burgess, Scott Brady', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2006, 'Mask of Zorro, The', 'Action,Comedy,Romance', 1998, 'Martin Campbell', 'A young thief seeking revenge for his brother\'s death is trained by the once-great, aging Zorro, who is pursuing his own vengeance.', 'https://m.media-amazon.com/images/M/MV5BMzA2MDgyYzMtNjc4OC00YjU0LWEzMWEtOTRhMTViODY0Mjk0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'José María de Tavira, Diego Sieres, Emiliano Guerra, Yolanda Orizaga, Paco Morayta, William Marquez', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2011, 'Back to the Future Part II', 'Adventure,Comedy,Sci-Fi', 1989, 'Robert Zemeckis', 'After visiting 2015, Marty McFly must repeat his visit to 1955 to prevent disastrous changes to 1985, without interfering with his first trip.', 'https://m.media-amazon.com/images/M/MV5BMTNlOTRmOTEtMTAyMi00NjFiLTk3NDMtNWI0YzA3ZTZlYjZiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael J. Fox, Christopher Lloyd, Lea Thompson, Tom Wilson, Elisabeth Shue, James Tolkan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2012, 'Back to the Future Part III', 'Adventure,Comedy,Sci-Fi,Western', 1990, 'Robert Zemeckis', 'Stranded in 1955, Marty McFly learns about the death of Doc Brown in 1885 and must travel back in time to save him. With no fuel readily available for the DeLorean, the two must figure how to escape the Old West before Emmett is murdered.', 'https://m.media-amazon.com/images/M/MV5BNTNkNzJmY2MtOGNjYi00NDJmLWIyZTQtNmFmMGQ5M2VlOTI0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael J. Fox, Christopher Lloyd, Mary Steenburgen, Tom Wilson, Lea Thompson, Elisabeth Shue', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2018, 'Bambi', 'Animation,Children,Drama', 1942, 'James Algar', 'The story of a young deer growing up in the forest.', 'https://m.media-amazon.com/images/M/MV5BMTIyZDk5NDItZmU5Yy00N2Y5LWI2ZDItMzEyZDhiYjI3MDdmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Hardie Albright, Stan Alexander, Bobette Audrey, Peter Behn, Thelma Boardman, Dolyn Bramston-Cook', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2019, 'Seven Samurai (Shichinin no samurai)', 'Action,Adventure,Drama', 1954, 'Akira Kurosawa', 'Farmers from a village exploited by bandits hire a veteran samurai for protection, and he gathers six other samurai to join him.', 'https://m.media-amazon.com/images/M/MV5BZjliMWExOTMtZDQ3ZS00NWU3LWIyN2EtMjllNzk3ZTNlYzg4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Toshirô Mifune, Takashi Shimura, Keiko Tsushima, Yukiko Shimazaki, Kamatari Fujiwara, Daisuke Katô', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2023, 'Godfather: Part III, The', 'Crime,Drama,Mystery,Thriller', 1990, 'Francis Ford Coppola', 'Follows Michael Corleone, now in his 60s, as he seeks to free his family from crime and find a suitable successor to his empire.', 'https://m.media-amazon.com/images/M/MV5BMDVjODgzNTEtNjBiNS00ODBjLWEwZjUtMDljZTFhOTA4M2MxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Al Pacino, Diane Keaton, Talia Shire, Andy Garcia, Eli Wallach, Joe Mantegna', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2028, 'Saving Private Ryan', 'Action,Drama,War', 1998, 'Steven Spielberg', 'Following the Normandy Landings, a group of U.S. soldiers go behind enemy lines to retrieve a paratrooper whose comrades have been killed in action.', 'https://m.media-amazon.com/images/M/MV5BZGZhZGQ1ZWUtZTZjYS00MDJhLWFkYjctN2ZlYjE5NWYwZDM2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Tom Sizemore, Edward Burns, Barry Pepper, Adam Goldberg, Vin Diesel', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2058, 'Negotiator, The', 'Action,Crime,Drama,Mystery,Thriller', 1998, 'F. Gary Gray', 'A police negotiator confronts a framed counterpart.', 'https://m.media-amazon.com/images/M/MV5BNTBjZDM3NzctOGE2YS00NDZiLTk4ZWMtY2IwOWI5ZTE4ZDc0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Samuel L. Jackson, Kevin Spacey, David Morse, Ron Rifkin, John Spencer, J.T. Walsh', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2076, 'Blue Velvet', 'Drama,Mystery,Thriller', 1986, 'David Lynch', 'The discovery of a severed human ear found in a field leads a young man on an investigation related to a beautiful, mysterious nightclub singer and a group of psychopathic criminals who have kidnapped her child.', 'https://m.media-amazon.com/images/M/MV5BNzkwZGUyYjQtM2QyOC00MTBjLWE0NGYtMTZmOGM5MjI0Mzg0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Isabella Rossellini, Kyle MacLachlan, Dennis Hopper, Laura Dern, Hope Lange, Dean Stockwell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2078, 'Jungle Book, The', 'Animation,Children,Comedy,Musical', 1967, 'Wolfgang Reitherman', 'Bagheera the Panther and Baloo the Bear have a difficult time trying to convince a boy to leave the jungle for human civilization.', 'https://m.media-amazon.com/images/M/MV5BNGE4M2NiZDktY2E2MC00ZTY5LWIyMDktZWIxNzQ2OWU2NmQzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Phil Harris, Sebastian Cabot, Bruce Reitherman, George Sanders, Sterling Holloway, Louis Prima', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2080, 'Lady and the Tramp', 'Animation,Children,Comedy,Romance', 1955, 'Clyde Geronimi', 'The romantic tale of a sheltered uptown Cocker Spaniel dog and a streetwise downtown Mutt.', 'https://m.media-amazon.com/images/M/MV5BMjA1NmQ2MTYtNzU0NC00NzBiLWJmZmQtM2FlNDViODk4OWEwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Peggy Lee, Larry Roberts, Bill Baucom, Verna Felton, George Givot, Lee Millar', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2081, 'Little Mermaid, The', 'Animation,Children,Comedy,Musical,Romance', 1989, 'Ron Clements', 'A mermaid princess makes a Faustian bargain in an attempt to become human and win a prince\'s love.', 'https://m.media-amazon.com/images/M/MV5BNmQ3ODcyZGMtMjNlOS00YzhlLTg0YzAtZGVjNmQ0OTYyNDg0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Rene Auberjonois, Christopher Daniel Barnes, Jodi Benson, Pat Carroll, Paddi Edwards, Buddy Hackett', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2083, 'Muppet Christmas Carol, The', 'Children,Comedy,Musical', 1992, 'Brian Henson', 'The Muppets put their spin on the tale of an elder, Christmas-hating miser who is visited by spirits who foretell his future and share secrets from his past and present, which helps change his view on life.', 'https://m.media-amazon.com/images/M/MV5BNTIwOTAyMDgtNTY1Zi00ZWMyLWFjMjAtNjI5YWIyOTE2NDJhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Caine, Dave Goelz, Steve Whitmire, Jerry Nelson, Frank Oz, David Rudman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2085, '101 Dalmatians (One Hundred and One Dalmatians)', 'Adventure,Animation,Children', 1961, 'Clyde Geronimi', 'When a litter of Dalmatian puppies are abducted by the minions of Cruella De Vil, the owners must find them before she uses them for a diabolical fashion statement.', 'https://m.media-amazon.com/images/M/MV5BZTIyMzVmNmItYWFkNS00YWJkLTk3YTEtNTVhMmQ0ODFjYmY1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Rod Taylor, J. Pat O\'Malley, Betty Lou Gerson, Martha Wentworth, Ben Wright, Cate Bauer', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2087, 'Peter Pan', 'Animation,Children,Fantasy,Musical', 1953, 'Clyde Geronimi', 'Wendy and her brothers are whisked away to the magical world of Neverland with the hero of their stories, Peter Pan.', 'https://m.media-amazon.com/images/M/MV5BOGUwNjg5MWItNTc5OC00MTNkLWEwNzYtYzA1M2Y4MWU3NmQwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bobby Driscoll, Kathryn Beaumont, Hans Conried, Bill Thompson, Heather Angel, Paul Collins', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2096, 'Sleeping Beauty', 'Animation,Children,Musical', 1959, 'Les Clark', 'After being snubbed by the royal family, a malevolent fairy places a curse on a princess which only a prince can break, along with the help of three good fairies.', 'https://m.media-amazon.com/images/M/MV5BYjVjNjZkNTQtOTRhZi00NTVhLThkMzktYzY4YjIwZWRhZjA0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mary Costa, Bill Shirley, Eleanor Audley, Verna Felton, Barbara Luddy, Barbara Jo Allen', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2109, 'Jerk, The', 'Comedy', 1979, 'Carl Reiner', 'A simpleminded, sheltered country boy suddenly decides to leave his family home to experience life in the big city, where his naivete is both his best friend and his worst enemy.', 'https://m.media-amazon.com/images/M/MV5BNTNiNjEwZjktNTZjMi00NWMyLThkZWYtODVkMDVhNGVkZDcxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Steve Martin, Bernadette Peters, Catlin Adams, Mabel King, Richard Ward, Dick Anthony Williams', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2115, 'Indiana Jones and the Temple of Doom', 'Action,Adventure,Fantasy', 1984, 'Steven Spielberg', 'In 1935, Indiana Jones is tasked by Indian villagers with reclaiming a sacred stone stolen from them by a secret cult.', 'https://m.media-amazon.com/images/M/MV5BOGUwZjZiNWQtYzAzZi00NGI5LWE4YmUtN2Y4YWMwY2RlZDkyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Harrison Ford, Kate Capshaw, Ke Huy Quan, Amrish Puri, Roshan Seth, Philip Stone', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2132, 'Who\'s Afraid of Virginia Woolf?', 'Drama', 1966, 'Mike Nichols', 'A middle-aged New England associate professor and his wife, with the help of alcohol, use their young guests to fuel anguish and emotional pain towards each other over the course of a distressing night.', 'https://m.media-amazon.com/images/M/MV5BOGY5YWJlMjUtNWI4Zi00NTExLWIwMDUtNGJkOTM0MzliNjE4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Elizabeth Taylor, Richard Burton, George Segal, Sandy Dennis, Agnes Flanagan, Frank Flanagan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2144, 'Sixteen Candles', 'Comedy,Romance', 1984, 'John Hughes', 'A high school girl\'s sixteenth birthday is anything but special, her family forgets about it while preparing for her older sister\'s wedding, the boy she has a crush on has a girlfriend, and she suffers from multitude of embarrassments.', 'https://m.media-amazon.com/images/M/MV5BMTgzNTkxMTkxMl5BMl5BanBnXkFtZTgwMjE3NjkzMTE@._V1_FMjpg_UX1000_.jpg', 'Molly Ringwald, Justin Henry, Michael Schoeffling, Haviland Morris, Gedde Watanabe, Anthony Michael Hall', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2161, 'NeverEnding Story, The', 'Adventure,Children,Fantasy', 1984, 'Wolfgang Petersen', 'A troubled boy dives into a wondrous fantasy world through the pages of a mysterious book.', 'https://m.media-amazon.com/images/M/MV5BYzE0Y2E0NGYtYzRmMy00ZDRjLTk1NDItNjZjYTMyMmJjMGYxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Barret Oliver, Gerald McRaney, Chris Eastman, Darryl Cooksey, Nicholas Gilbert, Thomas Hill', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2167, 'Blade', 'Action,Horror,Thriller', 1998, 'Stephen Norrington', 'A half-vampire, half-mortal man becomes a protector of the mortal race, while slaying evil vampires.', 'https://m.media-amazon.com/images/M/MV5BNzAzMmY3OWMtNDgyMS00Y2U4LTlmM2UtY2YwMmM0MDI5ODJmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Wesley Snipes, Stephen Dorff, Kris Kristofferson, N\'Bushe Wright, Donal Logue, Udo Kier', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2174, 'Beetlejuice', 'Comedy,Fantasy', 1988, 'Tim Burton', 'The spirits of a deceased couple are harassed by an unbearable family that has moved into their home, and hire a malicious spirit to drive them out.', 'https://m.media-amazon.com/images/M/MV5BYjkwNzVlNDEtMTJlNy00OTdlLTljYWItM2RkZmZkYzY3YjM2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Alec Baldwin, Geena Davis, Annie McEnroe, Maurice Page, Hugo Stanger, Michael Keaton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2194, 'Untouchables, The', 'Action,Crime,Drama', 1987, 'Brian De Palma', 'During Prohibition, Treasury agent Eliot Ness sets out to stop ruthless Chicago gangster Al Capone, and assembles a small, incorruptible team to help him.', 'https://m.media-amazon.com/images/M/MV5BYjVlNTk3NGYtOWE0OC00MDI4LThlZWItZGMwMTdmYzcwM2Y5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kevin Costner, Sean Connery, Charles Martin Smith, Andy Garcia, Robert De Niro, Richard Bradford', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2232, 'Cube', 'Horror,Mystery,Sci-Fi,Thriller', 1997, 'Vincenzo Natali', 'A group of strangers awaken to find themselves placed in a giant cube. Each one of them is gifted with a special skill and they must work together to escape an endless maze of deadly traps.', 'https://m.media-amazon.com/images/M/MV5BMzcyOTE5YTItM2I4OC00MTc0LTkyNWUtMWZmYmY1MWVhNmZiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nicole de Boer, Nicky Guadagni, David Hewlett, Andrew Miller, Julian Richings, Wayne Robson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2245, 'Working Girl', 'Comedy,Drama,Romance', 1988, 'Mike Nichols', 'When a secretary\'s idea is stolen by her boss, she seizes an opportunity to steal it back by pretending she has her boss\' job.', 'https://m.media-amazon.com/images/M/MV5BYzZhNGFlNGYtMjgyMi00YmZiLWFjNjktZGIzYjkxM2YyZWJjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Harrison Ford, Sigourney Weaver, Melanie Griffith, Alec Baldwin, Joan Cusack, Philip Bosco', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2248, 'Say Anything...', 'Comedy,Drama,Romance', 1989, 'Cameron Crowe', 'A noble underachiever and a beautiful valedictorian fall in love the summer before she goes off to college.', 'https://m.media-amazon.com/images/M/MV5BNjY1N2QwZDItOWZjZC00MTg4LTg1YmUtZWMzMThhY2YxNmNiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Cusack, Ione Skye, John Mahoney, Lili Taylor, Amy Brooks, Pamela Adlon', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2268, 'Few Good Men, A', 'Crime,Drama,Thriller', 1992, 'Rob Reiner', 'A military lawyer intends to prove that two US Marines charged with murdering a fellow Marine were only following their base commander\'s orders.', 'https://m.media-amazon.com/images/M/MV5BOGVhMTUwYzEtZGQ1ZC00Nzg1LTk0OGUtMDk0NDM0ZmZlN2E0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Jack Nicholson, Demi Moore, Kevin Bacon, Kiefer Sutherland, Kevin Pollak', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2273, 'Rush Hour', 'Action,Comedy,Crime,Thriller', 1998, 'Brett Ratner', 'A loyal and dedicated Hong Kong Inspector teams up with a reckless and loudmouthed L.A.P.D. detective to rescue the Chinese Consul\'s kidnapped daughter, while trying to arrest a dangerous crime lord along the way.', 'https://m.media-amazon.com/images/M/MV5BMGZiMzViNmEtNTNlZi00MzFmLTk5NTEtNDE2OTUzNmNlMTY4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ken Leung, Jackie Chan, Tom Wilkinson, Tzi Ma, Robert Littman, Michael Chow', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2288, 'Thing, The', 'Action,Horror,Sci-Fi,Thriller', 1982, 'John Carpenter', 'A research team in Antarctica is hunted by a shape-shifting alien that assumes the appearance of its victims.', 'https://m.media-amazon.com/images/M/MV5BYTA3NDU5MWEtNTk4Yy00ZDNkLThmZTQtMjU3ZGVhYzAyMzU4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kurt Russell, Wilford Brimley, T.K. Carter, David Clennon, Keith David, Richard Dysart', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2291, 'Edward Scissorhands', 'Drama,Fantasy,Romance', 1990, 'Tim Burton', 'The solitary life of an artificial man with scissors for hands is upended when he is taken in by a suburban family.', 'https://m.media-amazon.com/images/M/MV5BODJhODczYjUtYzdkMy00Yjc4LTllNWMtZTQ3MDZlYWZjYWEzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Winona Ryder, Dianne Wiest, Anthony Michael Hall, Kathy Baker, Robert Oliveri', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2294, 'Antz', 'Adventure,Animation,Children,Comedy,Fantasy', 1998, 'Eric Darnell', 'A rather neurotic ant tries to break from his totalitarian society while trying to win the affection of the princess he loves.', 'https://m.media-amazon.com/images/M/MV5BYzdlMzZhZjctY2JjYy00OGRiLThjMTEtODRmZTg2ZjI5MjEzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Woody Allen, Dan Aykroyd, Anne Bancroft, Jane Curtin, Danny Glover, Gene Hackman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2297, 'What Dreams May Come', 'Adventure,Drama,Fantasy,Romance', 1998, 'Vincent Ward', 'Chris Nielsen dies in an accident, and enters Heaven. But when he discovers that his beloved wife Annie has killed herself out of grief over the loss, he embarks on an afterlife adventure to reunite with her.', 'https://m.media-amazon.com/images/M/MV5BOWVmNzA5NDQtYTNiYy00YjI0LWJjMWItZjEyNmI5YjRlZTI5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robin Williams, Cuba Gooding Jr., Annabella Sciorra, Max von Sydow, Jessica Brooks Grant, Josh Paddock', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2302, 'My Cousin Vinny', 'Comedy', 1992, 'Jonathan Lynn', 'Two New Yorkers accused of murder in rural Alabama while on their way back to college call in the help of one of their cousins, a loudmouth lawyer with no trial experience.', 'https://m.media-amazon.com/images/M/MV5BMTQxNDYzMTg1M15BMl5BanBnXkFtZTgwNzk4MDgxMTE@._V1_FMjpg_UX1000_.jpg', 'Joe Pesci, Ralph Macchio, Marisa Tomei, Mitchell Whitfield, Fred Gwynne, Lane Smith', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2312, 'Children of a Lesser God', 'Drama', 1986, 'Randa Haines', 'A new speech teacher at a school for the deaf falls in love with the janitor, a deaf woman speechless by choice.', 'https://m.media-amazon.com/images/M/MV5BMjY3YjQyMjAtOGI2ZC00NDljLWJlN2QtYjNiYTMxZjIxMzQ0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'William Hurt, Marlee Matlin, Piper Laurie, Philip Bosco, Allison Gompf, John F. Cleary', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2315, 'Bride of Chucky (Child\'s Play 4)', 'Comedy,Horror,Thriller', 1998, 'Ronny Yu', 'Chucky, the doll possessed by a serial killer, discovers the perfect mate to kill and revive into the body of another doll.', 'https://m.media-amazon.com/images/M/MV5BYTk2OGE5MjktYjcyYS00M2QxLWE4YTYtYmNjYmE0M2I3ZDMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jennifer Tilly, Brad Dourif, Katherine Heigl, Nick Stabile, Alexis Arquette, Gordon Michael Woolvett', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2321, 'Pleasantville', 'Comedy,Drama,Fantasy', 1998, 'Gary Ross', 'Two 1990s teenage siblings find themselves transported to a 1950s sitcom where their influence begins to profoundly change that colorless, complacent world.', 'https://m.media-amazon.com/images/M/MV5BYmM4ZThmNzAtYzRmNi00ZjZmLThhYjAtYjU2YTcwMmY3MzRmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'William H. Macy, Joan Allen, Natalie Ramsey, Kevin Connors, Jeff Daniels, Tobey Maguire', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2324, 'Life Is Beautiful (La Vita è bella)', 'Comedy,Drama,Romance,War', 1997, 'Roberto Benigni', 'When an open-minded Jewish waiter and his son become victims of the Holocaust, he uses a perfect mixture of will, humor and imagination to protect his son from the dangers around their camp.', 'https://m.media-amazon.com/images/M/MV5BZTBhOGYzZjQtYzE0Mi00MGIwLWE0MWYtNzMxNTM2OTFkM2NjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Roberto Benigni, Nicoletta Braschi, Giorgio Cantarini, Giustino Durano, Sergio Bini Bustric, Marisa Paredes', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2329, 'American History X', 'Crime,Drama', 1998, 'Tony Kaye', 'A white supremacist is released from prison a changed man and hopes to prevent his younger brother from following in his footsteps.', 'https://m.media-amazon.com/images/M/MV5BMzhiOTQ0NDItOTg0Zi00OGVmLWE0OGEtMTI4NDM0NWMxZWU4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Edward Norton, Edward Furlong, Beverly D\'Angelo, Jennifer Lien, Ethan Suplee, Fairuza Balk', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2340, 'Meet Joe Black', 'Romance', 1998, 'Martin Brest', 'Death, who takes the form of a young man killed in an accident, asks a media mogul to act as his guide to teach him about life on Earth and, in the process, he falls in love with the mogul\'s daughter.', 'https://m.media-amazon.com/images/M/MV5BMjVjNjAwYWItMDc0ZC00MTEwLWJiN2MtM2U4YThjNWE5YTZmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brad Pitt, Anthony Hopkins, Claire Forlani, Jake Weber, Marcia Gay Harden, Jeffrey Tambor', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2352, 'Big Chill, The', 'Comedy,Drama', 1983, 'Lawrence Kasdan', 'A group of seven former college friends gather for a weekend reunion at a South Carolina vacation home after the funeral of another of their college friends.', 'https://m.media-amazon.com/images/M/MV5BOTg3YWQ1MWItMTcxYy00NTczLWJiMDktYjkxMWExNDY3ZjI4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Berenger, Glenn Close, Jeff Goldblum, William Hurt, Kevin Kline, Mary Kay Place', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2353, 'Enemy of the State', 'Action,Thriller', 1998, 'Tony Scott', 'A lawyer becomes targeted by a corrupt politician and his N.S.A. goons when he accidentally receives key evidence to a politically motivated crime.', 'https://m.media-amazon.com/images/M/MV5BOWVhZmRiODktNzM0Zi00YmVlLWI3MGQtY2M0NmYzN2Q4Yzg4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Will Smith, Gene Hackman, Jon Voight, Lisa Bonet, Regina King, Stuart Wilson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2355, 'Bug\'s Life, A', 'Adventure,Animation,Children,Comedy', 1998, 'John Lasseter', 'A misfit ant, looking for \"warriors\" to save his colony from greedy grasshoppers, recruits a group of bugs that turn out to be an inept circus troupe.', 'https://m.media-amazon.com/images/M/MV5BNGI3Mjc1ZjUtYTJhYS00NjBiLTgyYjctODU5NTNlMWJiYjYzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dave Foley, Kevin Spacey, Julia Louis-Dreyfus, Hayden Panettiere, Phyllis Diller, Richard Kind', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2359, 'Waking Ned Devine (a.k.a. Waking Ned)', 'Comedy', 1998, 'Kirk Jones', 'When a lottery winner dies of shock, his fellow townsfolk attempt to claim the money.', 'https://m.media-amazon.com/images/M/MV5BZDhlOTA1NjItMTM2ZS00N2Q2LTg0ZTItYmNiZGFiNzQ2YTVmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ian Bannen, David Kelly, Fionnula Flanagan, Susan Lynch, James Nesbitt, Paul Vaughan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2360, 'Celebration, The (Festen)', 'Drama', 1998, 'Thomas Vinterberg', 'At Helge\'s 60th birthday party, some unpleasant family truths are revealed.', 'https://m.media-amazon.com/images/M/MV5BODNkY2VkOTktYTZlYy00OGJjLWEyZjMtZDAyZjljMTNlNmVmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ulrich Thomsen, Henning Moritzen, Thomas Bo Larsen, Paprika Steen, Birthe Neumann, Trine Dyrholm', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2371, 'Fletch', 'Comedy,Crime,Mystery', 1985, 'Michael Ritchie', 'While working undercover wisecracking newspaper reporter Irwin \"Fletch\" Fletcher is offered a large sum by a millionaire with a terminal disease to kill him. Intrigued, Fletch decides to unearth the full story behind the offer.', 'https://m.media-amazon.com/images/M/MV5BYmM2MDEyMjQtOGQwYS00M2NjLWIwODgtYzRmYjQ5ZDMxZDEyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chevy Chase, Joe Don Baker, Dana Wheeler-Nicholson, Richard Libertini, Tim Matheson, M. Emmet Walsh', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2375, 'Money Pit, The', 'Comedy', 1986, 'Richard Benjamin', 'A young couple struggles to repair a hopelessly dilapidated house.', 'https://m.media-amazon.com/images/M/MV5BNWMyMzliNDgtNDJiYy00ZDg2LTkwZGEtYjVmYmEyNTk2ZTFlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Shelley Long, Alexander Godunov, Maureen Stapleton, Joe Mantegna, Philip Bosco', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2396, 'Shakespeare in Love', 'Comedy,Drama,Romance', 1998, 'John Madden', 'History\'s greatest playwright is young, out of ideas and short of cash, but meets his ideal woman and is inspired to write one of his most famous plays.', 'https://m.media-amazon.com/images/M/MV5BYmM3MTllNzYtN2MzNS00NWQwLTk0NTEtNjY1MmMwYjNkNTE5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Geoffrey Rush, Tom Wilkinson, Steven O\'Donnell, Tim McMullan, Joseph Fiennes, Steven Beard', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2398, 'Miracle on 34th Street', 'Comedy,Drama', 1947, 'George Seaton', 'After a divorced New York mother hires a nice old man to play Santa Claus at Macy\'s, she is startled by his claim to be the genuine article. When his sanity is questioned, a lawyer defends him in court by arguing that he\'s not mistaken.', 'https://m.media-amazon.com/images/M/MV5BZThmOTU4MzktNzg4Yy00NGRhLThlZjQtYjA1MjY2Zjg0N2RiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Maureen O\'Hara, John Payne, Edmund Gwenn, Gene Lockhart, Natalie Wood, Porter Hall', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2403, 'First Blood (Rambo: First Blood)', 'Action,Adventure,Drama,Thriller', 1982, 'Ted Kotcheff', 'Green Beret veteran Rambo takes on a Pacific Northwest sheriff and the National Guard.', 'https://m.media-amazon.com/images/M/MV5BYzc4ZmQ5YzEtYTQzYy00ZDdiLWI2NmQtZTA3MzM1ZGIyYmUzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sylvester Stallone, Richard Crenna, Brian Dennehy, Bill McKinney, Jack Starrett, Michael Talbott', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2420, 'Karate Kid, The', 'Drama', 1984, 'John G. Avildsen', 'Recently relocated from NJ to LA, Daniel becomes the target of a gang of Cobra Kai dojo students. When Mr. Miyagi saves him with expert Karate skills, Daniel convinces him to teach him to defend himself, and put his bullies in their place.', 'https://m.media-amazon.com/images/M/MV5BM2I3ZmZhNzctMzBlNC00YTc2LWE1MmEtY2ZkMzg3Y2I1ZDJhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ralph Macchio, Pat Morita, Elisabeth Shue, Martin Kove, Randee Heller, William Zabka', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2424, 'You\'ve Got Mail', 'Comedy,Romance', 1998, 'Nora Ephron', 'Book superstore magnate Joe Fox and independent book shop owner Kathleen Kelly fall in love in the anonymity of the Internet, both blissfully unaware that he\'s trying to put her out of business.', 'https://m.media-amazon.com/images/M/MV5BN2FhMWRiODYtMTQwMy00OTE2LTlhZjMtNWRmYmIyZjYwYTk1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Meg Ryan, Greg Kinnear, Parker Posey, Jean Stapleton, Steve Zahn', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2455, 'Fly, The', 'Drama,Horror,Sci-Fi,Thriller', 1986, 'David Cronenberg', 'A botched experiment transmutes a man into a monstrous insect.', 'https://m.media-amazon.com/images/M/MV5BOTBlNTliNTItY2VhNS00MjA5LTllYzItMmQyNGRjYTAyZWQxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jeff Goldblum, Geena Davis, John Getz, Joy Boushel, Leslie Carlson, George Chuvalo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2467, 'Name of the Rose, The (Name der Rose, Der)', 'Crime,Drama,Mystery,Thriller', 1986, 'Jean-Jacques Annaud', 'An intellectually nonconformist friar investigates a series of mysterious deaths in an isolated abbey.', 'https://m.media-amazon.com/images/M/MV5BODcwODk2NmQtMjg0My00NzcxLWFhNTYtNjM4ODUxM2VjNTI2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sean Connery, Christian Slater, Helmut Qualtinger, Elya Baskin, Michael Lonsdale, Volker Prechtel', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2470, 'Crocodile Dundee', 'Adventure,Comedy', 1986, 'Peter Faiman', 'An American reporter travels to the Australian outback to meet eccentric poacher Mick \"Crocodile\" Dundee and invites him to New York City, where he comes face-to-face with the complexities of modern life.', 'https://m.media-amazon.com/images/M/MV5BMDFkMTYyNWUtOGNjMy00MTMyLWFkMTQtYzZiMmY1NzBhN2I3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Paul Hogan, Linda Kozlowski, John Meillon, David Gulpilil, Ritchie Singer, Maggie Blinco', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2490, 'Payback', 'Action,Thriller', 1999, 'Brian Helgeland', 'After a successful heist, Porter is left for dead. Once he recovers, he seeks vengeance and wants his share of the money.', 'https://m.media-amazon.com/images/M/MV5BZDVmM2YxNDUtMjE2Yy00M2I0LTk1MmEtYWUxZTI4NjMyMDJiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mel Gibson, Gregg Henry, Maria Bello, David Paymer, Bill Duke, Deborah Kara Unger', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2502, 'Office Space', 'Comedy,Crime', 1999, 'Mike Judge', 'Three company workers who hate their jobs decide to rebel against their greedy boss.', 'https://m.media-amazon.com/images/M/MV5BOTA5MzQ3MzI1NV5BMl5BanBnXkFtZTgwNTcxNTYxMTE@._V1_FMjpg_UX1000_.jpg', 'Ron Livingston, Jennifer Aniston, David Herman, Ajay Naidu, Diedrich Bader, Stephen Root', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2541, 'Cruel Intentions', 'Drama', 1999, 'Roger Kumble', 'Two vicious step-siblings of an elite Manhattan prep school make a wager: to deflower the new headmaster\'s daughter before the start of term.', 'https://m.media-amazon.com/images/M/MV5BMjgyYmVjNWYtZTNjOS00YjEyLWI0MjEtMDgwYWI2YzZiMTFkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sarah Michelle Gellar, Ryan Phillippe, Reese Witherspoon, Selma Blair, Louise Fletcher, Joshua Jackson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2542, 'Lock, Stock & Two Smoking Barrels', 'Comedy,Crime,Thriller', 1998, 'Guy Ritchie', 'When four small-time criminals lose a rigged poker game against a London kingpin, he gives them one week to settle their enormous debt.', 'https://m.media-amazon.com/images/M/MV5BMmY1M2M5ZmMtYzllZC00YzAxLTk4MjktZDJkNjA1MTUwMGQ4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jason Flemyng, Dexter Fletcher, Nick Moran, Jason Statham, Steven Mackintosh, Nicholas Rowe', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2571, 'Matrix, The', 'Action,Sci-Fi,Thriller', 1999, 'Lana Wachowski', 'When a beautiful stranger leads computer hacker Neo to a forbidding underworld, he discovers the shocking truth--the life he knows is the elaborate deception of an evil cyber-intelligence.', 'https://m.media-amazon.com/images/M/MV5BN2NmN2VhMTQtMDNiOS00NDlhLTliMjgtODE2ZTY0ODQyNDRhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Keanu Reeves, Laurence Fishburne, Carrie-Anne Moss, Hugo Weaving, Gloria Foster, Joe Pantoliano', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2572, '10 Things I Hate About You', 'Comedy,Romance', 1999, 'Gil Junger', 'A high-school boy, Cameron, cannot date Bianca until her anti-social older sister, Kat, has a boyfriend. So, Cameron pays a mysterious boy, Patrick, to charm Kat.', 'https://m.media-amazon.com/images/M/MV5BOTQwYmRhNGQtODI2Mi00ZTRlLTk0Y2QtY2NkNjE1MGNhNTgwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Heath Ledger, Julia Stiles, Joseph Gordon-Levitt, Larisa Oleynik, David Krumholtz, Andrew Keegan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2599, 'Election', 'Comedy', 1999, 'Alexander Payne', 'A high school teacher meets his match in an over-achieving student politician.', 'https://m.media-amazon.com/images/M/MV5BMTVmMWJiMTgtNmNmMS00NmI2LTgxZTAtNjdhODE2NTBlYTAyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matthew Broderick, Reese Witherspoon, Loren Nelson, Chris Klein, Phil Reeves, Emily Martin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2617, 'Mummy, The', 'Action,Adventure,Comedy,Fantasy,Horror,Thriller', 1999, 'Stephen Sommers', 'At an archaeological dig in the ancient city of Hamunaptra, an American serving in the French Foreign Legion accidentally awakens a mummy who begins to wreak havoc as he searches for the reincarnation of his long-lost love.', 'https://m.media-amazon.com/images/M/MV5BMTY4YWE0OGMtNjU0Yi00YzIwLTk3NTktM2ZiYWQwNjM4MmMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brendan Fraser, Rachel Weisz, John Hannah, Arnold Vosloo, Kevin J. O\'Connor, Jonathan Hyde', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2628, 'Star Wars: Episode I - The Phantom Menace', 'Action,Adventure,Sci-Fi', 1999, 'George Lucas', 'Two Jedi escape a hostile blockade to find allies and come across a young boy who may bring balance to the Force, but the long-dormant Sith resurface to claim their former glory.', 'https://m.media-amazon.com/images/M/MV5BODVhNGIxOGItYWNlMi00YTA0LWI3NTctZmQxZGUwZDEyZWI4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Liam Neeson, Ewan McGregor, Natalie Portman, Jake Lloyd, Ian McDiarmid, Pernilla August', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2640, 'Superman', 'Action,Adventure,Sci-Fi', 1978, 'Richard Donner', 'An alien orphan is sent from his dying planet to Earth, where he grows up to become his adoptive home\'s first and greatest superhero.', 'https://m.media-amazon.com/images/M/MV5BMzFlZDJjMDAtZDYxZS00NzZhLTk2ODMtZWRlODA3Njk3ZTdmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Marlon Brando, Gene Hackman, Christopher Reeve, Ned Beatty, Jackie Cooper, Glenn Ford', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2671, 'Notting Hill', 'Comedy,Romance', 1999, 'Roger Michell', 'A set of circumstances makes Anna Scott, a famous actress, fall in love with William Thacker, owner of a bookstore in Notting Hill. But the paparazzi\'s fascination with her complicates their bond.', 'https://m.media-amazon.com/images/M/MV5BZjY3YWI5OTMtYTdlNy00ZTZiLWEwYjItN2M1MGVkMDM4ZDExXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Julia Roberts, Hugh Grant, Richard McCabe, Rhys Ifans, James Dreyfus, Dylan Moran', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2683, 'Austin Powers: The Spy Who Shagged Me', 'Action,Adventure,Comedy', 1999, 'Jay Roach', 'Dr. Evil is back and has invented a new time machine that allows him to go back to the 1960s and steal Austin Powers\' mojo, inadvertently leaving him \"shagless\".', 'https://m.media-amazon.com/images/M/MV5BY2I3ZTBjOGQtYjQ3My00M2RlLTk3MjgtOTVmMWExNmU3ZjBkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mike Myers, Heather Graham, Michael York, Robert Wagner, Rob Lowe, Seth Green', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2687, 'Tarzan', 'Adventure,Animation,Children,Drama', 1999, 'Chris Buck', 'A man raised by gorillas must decide where he really belongs when he discovers he is a human.', 'https://m.media-amazon.com/images/M/MV5BZjM5OWM5NzktMTIzYy00OTk1LWIyYzAtYzBhNWY3NWQ2Y2Y0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brian Blessed, Glenn Close, Minnie Driver, Tony Goldwyn, Nigel Hawthorne, Lance Henriksen', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2692, 'Run Lola Run (Lola rennt)', 'Action,Crime', 1998, 'Tom Tykwer', 'After a botched money delivery, Lola has 20 minutes to come up with 100,000 Deutschmarks.', 'https://m.media-amazon.com/images/M/MV5BMzA0NDdiNDgtNjI4Ny00OTc0LTg3NGMtZDBlNmI1ZGUxYTg2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Franka Potente, Moritz Bleibtreu, Herbert Knaup, Nina Petri, Armin Rohde, Joachim Król', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2700, 'South Park: Bigger, Longer and Uncut', 'Animation,Comedy,Musical', 1999, 'Trey Parker', 'When Eric Cartman and his friends go see an R-rated movie, they start cursing and their parents think that Canada is to blame.', 'https://m.media-amazon.com/images/M/MV5BMDcyNDE4OWEtMjIzNi00OTdmLWIwMWEtNWU2ZjM4ZjA4YzNkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Trey Parker, Matt Stone, Mary Kay Bergman, Isaac Hayes, Jesse Brant Howell, Anthony Cross-Thomas', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2701, 'Wild Wild West', 'Action,Comedy,Sci-Fi,Western', 1999, 'Barry Sonnenfeld', 'The two best special agents in the Wild West must save President Grant from the clutches of a diabolical, wheelchair-bound, steampunk-savvy, Confederate scientist bent on revenge for losing the Civil War.', 'https://m.media-amazon.com/images/M/MV5BOGI1OWJjMWUtOTNiNC00N2RlLWE3OTYtM2FmOGUzNTQxNzk2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Will Smith, Kevin Kline, Kenneth Branagh, Salma Hayek, M. Emmet Walsh, Ted Levine', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2706, 'American Pie', 'Comedy,Romance', 1999, 'Paul Weitz', 'Four teenage boys enter a pact to lose their virginity by prom night.', 'https://m.media-amazon.com/images/M/MV5BMTg3ODY5ODI1NF5BMl5BanBnXkFtZTgwMTkxNTYxMTE@._V1_FMjpg_UX1000_.jpg', 'Jason Biggs, Jennifer Coolidge, Shannon Elizabeth, Alyson Hannigan, Chris Klein, Clyde Kusatsu', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2710, 'Blair Witch Project, The', 'Drama,Horror,Thriller', 1999, 'Daniel Myrick', 'Three film students vanish after traveling into a Maryland forest to film a documentary on the local Blair Witch legend, leaving only their footage behind.', 'https://m.media-amazon.com/images/M/MV5BNGFmYzA5NzktOTc1Ni00YTIxLWJiZTEtNmEyZjBjNDM2MjRlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Heather Donahue, Joshua Leonard, Michael C. Williams, Bob Griffin, Jim King, Sandra Sánchez', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2712, 'Eyes Wide Shut', 'Drama,Mystery,Thriller', 1999, 'Stanley Kubrick', 'A Manhattan doctor embarks on a bizarre, night-long odyssey after his wife\'s admission of unfulfilled longing.', 'https://m.media-amazon.com/images/M/MV5BZTQ0MmM5MDAtYmYyZS00MzlmLTlhZTAtZDJlZWY5ZTZkZjZmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Nicole Kidman, Madison Eginton, Jackie Sawiris, Sydney Pollack, Leslie Lowe', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2716, 'Ghostbusters (a.k.a. Ghost Busters)', 'Action,Comedy,Sci-Fi', 1984, 'Ivan Reitman', 'Three parapsychologists forced out of their university funding set up shop as a unique ghost removal service in New York City, attracting frightened yet skeptical customers.', 'https://m.media-amazon.com/images/M/MV5BMGI0Yjg2ODAtNDYzNi00Njc2LTlkMmMtMmRmYWI5MDE4ZGRkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bill Murray, Dan Aykroyd, Sigourney Weaver, Harold Ramis, Rick Moranis, Annie Potts', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2724, 'Runaway Bride', 'Comedy,Romance', 1999, 'Garry Marshall', 'For his latest column in USA Today, Ike Graham writes about Maggie, who always leaves all her fiances standing at the altar. He is fired as she complains to the newspaper for inaccuracies in her story.', 'https://m.media-amazon.com/images/M/MV5BNzBjNjBhN2YtYzQwNi00OTVkLWFkNTMtNjU0OWFkNTFmZGQ4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Julia Roberts, Richard Gere, Joan Cusack, Hector Elizondo, Rita Wilson, Paul Dooley', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2728, 'Spartacus', 'Action,Drama,Romance,War', 1960, 'Stanley Kubrick', 'The slave Spartacus survives brutal training as a gladiator and leads a violent revolt against the decadent Roman Republic, as the ambitious Crassus seeks to gain power by crushing the uprising.', 'https://m.media-amazon.com/images/M/MV5BMTcyOThhYzktMTYyMi00NDU5LWExZWMtOWUzNGJiZGFlMWQwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kirk Douglas, Laurence Olivier, Jean Simmons, Charles Laughton, Peter Ustinov, John Gavin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2746, 'Little Shop of Horrors', 'Comedy,Horror,Musical', 1986, 'Frank Oz', 'A nerdy florist finds his chance for success and romance with the help of a giant man-eating plant who demands to be fed.', 'https://m.media-amazon.com/images/M/MV5BNTJjM2VhMDctMTIxYi00MzY3LWI5ZDgtZjFiNzg0M2QxNzI5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Levi Stubbs, Rick Moranis, Ellen Greene, Vincent Gardenia, Steve Martin, Tichina Arnold', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2762, 'Sixth Sense, The', 'Drama,Horror,Mystery', 1999, 'M. Night Shyamalan', 'After being shot by a resentful former patient whom he failed to help, a Philadelphia child psychologist seeks redemption by treating a young boy with a disturbing secret.', 'https://m.media-amazon.com/images/M/MV5BZWQ2OTY0M2UtMTQxNC00MmIzLTllNDQtNDQ0MTQyYzI2M2ZiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bruce Willis, Haley Joel Osment, Toni Collette, Olivia Williams, Trevor Morgan, Donnie Wahlberg', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2763, 'Thomas Crown Affair, The', 'Action,Mystery', 1999, 'John McTiernan', 'A very rich and successful playboy amuses himself by stealing artwork, but may have met his match in a seductive detective.', 'https://m.media-amazon.com/images/M/MV5BOTEyMjkzYmYtMDJkNi00NjFiLTlmNDgtMWIzOTUyZDJkZmMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Pierce Brosnan, Rene Russo, Denis Leary, Ben Gazzara, Frankie Faison, Fritz Weaver', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2788, 'Monty Python\'s And Now for Something Completely Different', 'Comedy', 1971, 'Ian MacNaughton', 'An anthology of the best sketches from the first and second seasons of Monty Python\'s Flying Circus (1969).', 'https://m.media-amazon.com/images/M/MV5BZjEzYjIzMzYtODE3NC00ZjM5LWE0NWItM2Q4YTY2NWRlOWNjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Graham Chapman, John Cleese, Terry Gilliam, Eric Idle, Terry Jones, Michael Palin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2791, 'Airplane!', 'Comedy', 1980, 'Jim Abrahams', 'After the crew becomes sick with food poisoning, a neurotic ex-fighter pilot must safely land a commercial airplane full of passengers.', 'https://m.media-amazon.com/images/M/MV5BNGMxMDRhMjItMDNlZi00MDIzLWE5MDQtODljMDQ3MWM1Y2E4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kareem Abdul-Jabbar, Lloyd Bridges, Peter Graves, Julie Hagerty, Robert Hays, Leslie Nielsen', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2795, 'National Lampoon\'s Vacation', 'Comedy', 1983, 'Harold Ramis', 'The Griswold family\'s cross-country drive in their brand new Wagon Family Truckster to the Walley World theme park in California proves to be much more arduous than they ever anticipated.', 'https://m.media-amazon.com/images/M/MV5BOWQ3ZTg3MzYtOGU0Yi00NjgyLWFkNmMtMWFlZWE3MTkyOTdlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chevy Chase, Beverly D\'Angelo, Imogene Coca, Randy Quaid, Anthony Michael Hall, Dana Barron', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2797, 'Big', 'Comedy,Drama,Fantasy,Romance', 1988, 'Penny Marshall', 'After wishing to be made big, a teenage boy wakes the next morning to find himself mysteriously in the body of an adult.', 'https://m.media-amazon.com/images/M/MV5BNzE3ZTc2ZDgtMzQ4MS00NjEyLWJkMDYtZmMzZmY5ODJhMDdmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Elizabeth Perkins, Robert Loggia, John Heard, Jared Rushton, David Moscow', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2804, 'Christmas Story, A', 'Children,Comedy', 1983, 'Bob Clark', 'In the 1940s, a young boy named Ralphie Parker attempts to convince his parents, teacher, and Santa Claus that a Red Ryder Range 200 Shot BB gun really is the perfect Christmas gift.', 'https://m.media-amazon.com/images/M/MV5BZWZhYzI1YjktYzJjYy00NjIwLWE0MGItNWM4YWM2ZjFkNGM0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Melinda Dillon, Darren McGavin, Scott Schwartz, Jean Shepherd, Ian Petrella, Tedde Moore', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2805, 'Mickey Blue Eyes', 'Comedy,Romance', 1999, 'Kelly Makin', 'An English auctioneer proposes to the daughter of a Mafia kingpin, only to realize that certain \"favors\" would be asked of him.', 'https://m.media-amazon.com/images/M/MV5BNjIzNDQ4MDc5OV5BMl5BanBnXkFtZTYwNzI3MDM3._V1_FMjpg_UX1000_.jpg', 'Hugh Grant, James Caan, Jeanne Tripplehorn, Burt Young, James Fox, Joe Viterelli', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2810, 'Perfect Blue', 'Animation,Horror,Mystery,Thriller', 1997, 'Satoshi Kon', 'A pop singer gives up her career to become an actress, but she slowly goes insane when she starts being stalked by an obsessed fan and what seems to be a ghost of her past.', 'https://m.media-amazon.com/images/M/MV5BMzAwNDIzMzEtZDZkNC00ZDQ4LTk3ZDMtZjVhMTU2YzgzZTZiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Junko Iwao, Rica Matsumoto, Shinpachi Tsuji, Masaaki Ôkura, Yôsuke Akimoto, Yoku Shioya', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2819, 'Three Days of the Condor (3 Days of the Condor)', 'Drama,Mystery,Romance,Thriller', 1975, 'Sydney Pollack', 'A bookish CIA researcher in Manhattan finds all his co-workers dead, and must outwit those responsible until he figures out who he can really trust.', 'https://m.media-amazon.com/images/M/MV5BYjQ1NjlkZTMtNTkyZS00YmY3LWJmMzctMTgxNmE4NTFkNDViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert Redford, Faye Dunaway, Cliff Robertson, Max von Sydow, John Houseman, Addison Powell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2826, '13th Warrior, The', 'Action,Adventure,Fantasy', 1999, 'John McTiernan', 'A man, having fallen in love with the wrong woman, is sent by the sultan himself on a diplomatic mission to a distant land as an ambassador. Stopping at a Viking village port to restock on supplies, he finds himself unwittingly embroiled in a quest to banish a mysterious threat i...Read all', 'https://m.media-amazon.com/images/M/MV5BY2IwMTYyNjctYzhjZi00Y2Y3LWE3NjktMGVjMjFhNzk0NWFjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Antonio Banderas, Diane Venora, Dennis Storhøi, Vladimir Kulich, Omar Sharif, Anders T. Andersen', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2858, 'American Beauty', 'Drama,Romance', 1999, 'Sam Mendes', 'A sexually frustrated suburban father has a mid-life crisis after becoming infatuated with his daughter\'s best friend.', 'https://m.media-amazon.com/images/M/MV5BMDI1MDE0OTMtMmI2MS00Yjc2LTg2MTItMWExYTg5NzA1OGUzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kevin Spacey, Annette Bening, Thora Birch, Wes Bentley, Mena Suvari, Peter Gallagher', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2908, 'Boys Don\'t Cry', 'Drama', 1999, 'Kimberly Peirce', 'A young transgender man named Brandon navigates love, life, and trying to pass as a boy in rural Nebraska.', 'https://m.media-amazon.com/images/M/MV5BYTMwYWZkOWQtMDY4My00MzE5LThkODAtN2Q2Y2FmNzY3ZmE2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Hilary Swank, Chloë Sevigny, Peter Sarsgaard, Brendan Sexton III, Alicia Goranson, Alison Folland', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2916, 'Total Recall', 'Action,Adventure,Sci-Fi,Thriller', 1990, 'Paul Verhoeven', 'When a man goes in to have virtual vacation memories of the planet Mars implanted in his mind, an unexpected and harrowing series of events forces him to go to the planet for real - or is he?', 'https://m.media-amazon.com/images/M/MV5BZjRlMzBkOGMtMTA1Ny00ZWI4LTkzMDItOGVkNWJkN2E4ZTkwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Arnold Schwarzenegger, Rachel Ticotin, Sharon Stone, Ronny Cox, Michael Ironside, Marshall Bell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2918, 'Ferris Bueller\'s Day Off', 'Comedy', 1986, 'John Hughes', 'A brash, cocky high school senior, tired of skipping school to spend a boring day at home, is determined to enjoy an epic day roaring around his favorite Chicago sites, enlisting his best friend and girlfriend to join him on the adventure.', 'https://m.media-amazon.com/images/M/MV5BZWYwMjUxNjMtMzE0MC00NDM3LWIxMmQtYmEyNWVjNjdlZGZjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matthew Broderick, Alan Ruck, Mia Sara, Jeffrey Jones, Jennifer Grey, Cindy Pickett', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (2947, 'Goldfinger', 'Action,Adventure,Thriller', 1964, 'Guy Hamilton', 'While investigating a gold magnate\'s smuggling, James Bond uncovers a plot to contaminate the Fort Knox gold reserve.', 'https://m.media-amazon.com/images/M/MV5BMTQ2MzE0OTU3NV5BMl5BanBnXkFtZTcwNjQxNTgzNA@@._V1_FMjpg_UX1000_.jpg', 'Sean Connery, Honor Blackman, Gert Fröbe, Shirley Eaton, Tania Mallet, Harold Sakata', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (2948, 'From Russia with Love', 'Action,Adventure,Thriller', 1963, 'Terence Young', 'James Bond willingly inserts himself into an assassination plot involving a naive Russian beauty in order to retrieve a Soviet encryption device that was stolen by the evil SPECTRE organization.', 'https://m.media-amazon.com/images/M/MV5BMWY2MWY2ODAtMTY5Ny00MzA2LWFkMWYtODU2MjE0MmM4ZTQ4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sean Connery, Daniela Bianchi, Pedro Armendáriz, Lotte Lenya, Robert Shaw, Bernard Lee', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (2951, 'Fistful of Dollars, A (Per un pugno di dollari)', 'Action,Western', 1964, 'Sergio Leone', 'A wandering gunfighter plays two rival families against each other in a town torn apart by greed, pride, and revenge.', 'https://m.media-amazon.com/images/M/MV5BM2ZkYWU1MGQtMzM3MC00ODQ5LWE1ZGQtMDM5YjczZDZhMjg5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Clint Eastwood, Marianne Koch, Gian Maria Volontè, Wolfgang Lukschy, Sieghardt Rupp, Joseph Egger', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (2959, 'Fight Club', 'Action,Crime,Drama,Thriller', 1999, 'David Fincher', 'An insomniac office worker and a devil-may-care soap maker form an underground fight club that evolves into much more.', 'https://m.media-amazon.com/images/M/MV5BOTgyOGQ1NDItNGU3Ny00MjU3LTg2YWEtNmEyYjBiMjI1Y2M5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Edward Norton, Brad Pitt, Meat Loaf, Zach Grenier, Richmond Arquette, David Andrews', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (2978, 'Three to Tango', 'Comedy,Romance', 1999, 'Damon Santostefano', 'A rich businessman\'s assumption that his new colleague is gay leads him to ask the man to keep an eye on his mistress. However, the man is not gay--and he begins to fall for the woman himself.', 'https://m.media-amazon.com/images/M/MV5BMDUxNmFjMDYtZDQ4OC00ZTU5LTlhOGEtOTI0YThkZjEzNWI1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matthew Perry, Neve Campbell, Dylan McDermott, Oliver Platt, Cylk Cozart, John C. McGinley', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (2987, 'Who Framed Roger Rabbit?', 'Adventure,Animation,Children,Comedy,Crime,Fantasy,Mystery', 1988, 'Robert Zemeckis', 'When a cartoon rabbit is accused of murder, he enlists the help of a burnt out private investigator to prove his innocence.', 'https://m.media-amazon.com/images/M/MV5BMDc5ZGRiM2EtMWRmMC00YjViLWEwMjYtNGE5MWVlZGEzZGM0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bob Hoskins, Christopher Lloyd, Joanna Cassidy, Charles Fleischer, Stubby Kaye, Alan Tilvern', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (2997, 'Being John Malkovich', 'Comedy,Drama,Fantasy', 1999, 'Spike Jonze', 'A puppeteer discovers a portal that leads literally into the head of movie star John Malkovich.', 'https://m.media-amazon.com/images/M/MV5BNDExODk1MTktNzRiYS00MWEyLTgyOWItYTI1OWY4NzI1NDM2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Cusack, Cameron Diaz, Ned Bellamy, Eric Weinstein, Madison Lanc, Octavia Spencer', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3000, 'Princess Mononoke (Mononoke-hime)', 'Action,Adventure,Animation,Drama,Fantasy', 1997, 'Hayao Miyazaki', 'While seeking to cure himself of a curse, young warrior Ashitaka stumbles into a conflict between the people of Iron Town and Princess Mononoke, a girl raised by wolves, who will stop at nothing to prevent the destruction of her home.', 'https://m.media-amazon.com/images/M/MV5BZTcyN2Y0MDYtMGI1NC00MWQ1LWFhZGMtN2U4NTcxZGYyNjljXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Yôji Matsuda, Yuriko Ishida, Yûko Tanaka, Kaoru Kobayashi, Masahiko Nishimura, Tsunehiko Kamijô', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3005, 'Bone Collector, The', 'Thriller', 1999, 'Phillip Noyce', 'A quadriplegic ex-homicide detective and his partner try to track down a serial killer who is terrorizing New York City.', 'https://m.media-amazon.com/images/M/MV5BOWY0NjY0M2ItYmNjYy00YWZiLWE3ZjktM2Q3YmU2NWY0YmVmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Denzel Washington, Angelina Jolie, Queen Latifah, Michael Rooker, Michael McGlone, Luis Guzmán', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3006, 'Insider, The', 'Drama,Thriller', 1999, 'Michael Mann', 'A research chemist comes under personal and professional attack when he decides to appear in a 60 Minutes exposé on Big Tobacco.', 'https://m.media-amazon.com/images/M/MV5BZGY3ZjEyODAtNjAwMC00ZTEwLTg3NDctYzMzYTZkMjBmZDQwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Al Pacino, Russell Crowe, Christopher Plummer, Diane Venora, Philip Baker Hall, Lindsay Crouse', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3020, 'Falling Down', 'Action,Drama', 1993, 'Joel Schumacher', 'An ordinary man reaches his breaking point and starts lashing out against the various flaws he sees in society.', 'https://m.media-amazon.com/images/M/MV5BZmE2MGQ4OWEtMmUzYS00ZDBhLTg4ZDAtZGRhYWNkOTAzYWQyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Douglas, Robert Duvall, Barbara Hershey, Rachel Ticotin, Tuesday Weld, Frederic Forrest', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3030, 'Yojimbo', 'Action,Adventure', 1961, 'Akira Kurosawa', 'A crafty ronin comes to a town divided by two criminal gangs and decides to play them against each other to free the town.', 'https://m.media-amazon.com/images/M/MV5BYzFkODA1N2QtY2UyMC00NTMwLWEyNzctMmE3YjIzNzE1MzY4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Toshirô Mifune, Tatsuya Nakadai, Yôko Tsukasa, Isuzu Yamada, Daisuke Katô, Seizaburô Kawazu', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3033, 'Spaceballs', 'Comedy,Sci-Fi', 1987, 'Mel Brooks', 'A star-pilot for hire and his trusty sidekick must come to the rescue of a princess and save Planet Druidia from the clutches of the evil Spaceballs.', 'https://m.media-amazon.com/images/M/MV5BZWNhNWM3NWQtNTMwNy00NThiLWFkZDYtYzBlZTQyZGU2YzE1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mel Brooks, John Candy, Rick Moranis, Bill Pullman, Daphne Zuniga, Dick Van Patten', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3034, 'Robin Hood', 'Adventure,Animation,Children,Comedy,Musical', 1973, 'Wolfgang Reitherman', 'The story of the legendary British outlaw portrayed with the characters as anthropomorphic animals.', 'https://m.media-amazon.com/images/M/MV5BZDk2NTEzNjktZDg0MS00MWEwLTkzMWItNTU4ZjcxODM5ODdhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Roger Miller, Peter Ustinov, Terry-Thomas, Brian Bedford, Monica Evans, Phil Harris', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3037, 'Little Big Man', 'Western', 1970, 'Arthur Penn', 'Jack Crabb, looking back from extreme old age, tells of his life being raised by Native Americans and fighting with General Custer.', 'https://m.media-amazon.com/images/M/MV5BNWM3ODE1NTgtNDc5NS00OWFhLWIyNzgtMmNhMDU1MWI4N2I3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dustin Hoffman, Faye Dunaway, Chief Dan George, Martin Balsam, Richard Mulligan, Jeff Corey', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3039, 'Trading Places', 'Comedy', 1983, 'John Landis', 'A snobbish Wall Street commodities broker and a wily street hustler find their positions reversed as part of a bet by two callous millionaire brothers who run a brokerage house.', 'https://m.media-amazon.com/images/M/MV5BNzlkYjQ1MzUtNjgwZi00MmRhLTkwYzItMGRmN2Y3YmRjY2JmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Denholm Elliott, Dan Aykroyd, Maurice Woods, Richard D. Fisher Jr., Jim Gallagher, Anthony DiSabatino', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3052, 'Dogma', 'Adventure,Comedy,Fantasy', 1999, 'Kevin Smith', 'An abortion clinic worker with a special heritage is called upon to save the existence of humanity from being negated by two renegade angels trying to exploit a loop-hole and reenter Heaven.', 'https://m.media-amazon.com/images/M/MV5BNDE1Yjc3N2UtZmYwNi00YTA3LTllNGEtZTIwODg2MmMwNjBjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bud Cort, Barret Hackney, Jared Pfennigwerth, Kitao Sakurai, George Carlin, Brian O\'Halloran', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3072, 'Moonstruck', 'Comedy,Romance', 1987, 'Norman Jewison', 'Loretta Castorini, a bookkeeper from Brooklyn, New York, finds herself in a difficult situation when she falls for the brother of the man she has agreed to marry.', 'https://m.media-amazon.com/images/M/MV5BZjdiMjI1MTQtMWIzNC00OTg2LWI5NjItYTBiMTYzMmIxYmNjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cher, Nicolas Cage, Vincent Gardenia, Olympia Dukakis, Danny Aiello, Julie Bovasso', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3081, 'Sleepy Hollow', 'Fantasy,Horror,Mystery,Romance', 1999, 'Tim Burton', 'Ichabod Crane is sent to Sleepy Hollow to investigate the decapitations of three people; the culprit is legendary apparition The Headless Horseman.', 'https://m.media-amazon.com/images/M/MV5BYWIwMTIxZTQtNDZhNS00ZDZlLTg5MTEtOTNkMmNjOGUzMTA1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Christina Ricci, Miranda Richardson, Michael Gambon, Casper Van Dien, Jeffrey Jones', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3082, 'World Is Not Enough, The', 'Action,Adventure,Thriller', 1999, 'Michael Apted', 'James Bond uncovers a nuclear plot while protecting an oil heiress from her former kidnapper, an international terrorist who can\'t feel pain.', 'https://m.media-amazon.com/images/M/MV5BMDlmNTA0YmMtODJmMi00NTZhLTk4MzUtY2FiYjNhMmY4OTI1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Pierce Brosnan, Sophie Marceau, Robert Carlyle, Denise Richards, Robbie Coltrane, Judi Dench', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3088, 'Harvey', 'Comedy,Fantasy', 1950, 'Henry Koster', 'A whimsical man is thought to be insane due to his insistence that he is best friends with an invisible, humanoid rabbit, but he may be wiser than anyone knows.', 'https://m.media-amazon.com/images/M/MV5BZTNlNWRhZmEtYzgyOC00YTIxLTk1MjktMWQ1MjhlMmE0ZjljXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Wallace Ford, William H. Lynn, Victoria Horne, Jesse White, Cecil Kellaway, Charles Drake', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3097, 'Shop Around the Corner, The', 'Comedy,Drama,Romance', 1940, 'Ernst Lubitsch', 'Two employees at a gift shop can barely stand each other, without realizing that they are falling in love through the post as each other\'s anonymous pen pal.', 'https://m.media-amazon.com/images/M/MV5BMGU3Y2RmMTAtY2EzNC00MjUzLWIyMDUtZWJmYTE2MTU5ZDY5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Margaret Sullavan, James Stewart, Frank Morgan, Joseph Schildkraut, Sara Haden, Felix Bressart', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3105, 'Awakenings', 'Drama,Mystery', 1990, 'Penny Marshall', 'Dr. Sayer is a pioneering neurologist who wants to take a risk and give his patients who suffer from encephalitis a drug used for Parkinson\'s Disease. He tries it out on one man who miraculously wakes from his perpetual catatonic state.', 'https://m.media-amazon.com/images/M/MV5BZDUzOGQ4YTctNTY1OS00M2UzLWFjNzYtMGNlN2E5NDA2MGVkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert De Niro, Robin Williams, Julie Kavner, Ruth Nelson, John Heard, Penelope Ann Miller', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3107, 'Backdraft', 'Action,Drama', 1991, 'Ron Howard', 'Two feuding siblings carrying on a heroic family tradition as Chicago firefighters. But when a puzzling series of arson attacks is reported, they are forced to set aside their differences to solve the mystery surrounding these crimes.', 'https://m.media-amazon.com/images/M/MV5BYWM0Nzk2NzctYjkwMS00YWU4LWI5MTEtMGI4ZGRkNmYxOTk2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kurt Russell, William Baldwin, Robert De Niro, Donald Sutherland, Jennifer Jason Leigh, Scott Glenn', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3114, 'Toy Story 2', 'Adventure,Animation,Children,Comedy,Fantasy', 1999, 'Ash Brannon', 'When Woody is stolen by a toy collector, Buzz and his friends set out on a rescue mission to save Woody before he becomes a museum toy property with his roundup gang Jessie, Prospector, and Bullseye.', 'https://m.media-amazon.com/images/M/MV5BNzVmODlhMDEtY2YxZi00OTVjLTlkNTktN2Q2OTRlM2I4M2FhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Tim Allen, Joan Cusack, Kelsey Grammer, Don Rickles, Jim Varney', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3147, 'Green Mile, The', 'Crime,Drama', 1999, 'Frank Darabont', 'A death row guard learns that a gentle giant in his charge possesses a mysterious gift.', 'https://m.media-amazon.com/images/M/MV5BMTUxMzQyNjA5MF5BMl5BanBnXkFtZTYwOTU2NTY3._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, David Morse, Bonnie Hunt, Michael Clarke Duncan, James Cromwell, Michael Jeter', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3148, 'Cider House Rules, The', 'Drama', 1999, 'Lasse Hallström', 'During World War II, an orphan grows up under the tutelage of a doctor who runs an orphanage. However, he yearns for freedom and soon decides to leave in order to make a life for himself.', 'https://m.media-amazon.com/images/M/MV5BYWZlYzMyNzMtNjhlMy00ZTAzLWEwMTMtY2YwNzAxMDk1ZTViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tobey Maguire, Charlize Theron, Delroy Lindo, Paul Rudd, Michael Caine, Jane Alexander', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3160, 'Magnolia', 'Drama', 1999, 'Paul Thomas Anderson', 'An epic mosaic of interrelated characters in search of love, forgiveness and meaning in the San Fernando Valley.', 'https://m.media-amazon.com/images/M/MV5BOWY0Zjk1YTMtMGFlYi00OTFmLWEyOTAtNmRkYjE0ZDJiZWMwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Pat Healy, Genevieve Zweig, Mark Flanagan, Neil Flynn, Rod McLachlan, Allan Graf', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3168, 'Easy Rider', 'Adventure,Drama', 1969, 'Dennis Hopper', 'Two bikers head from L.A. to New Orleans through the open country and desert lands, and along the way they meet a man who bridges a counter-culture gap of which they had been unaware.', 'https://m.media-amazon.com/images/M/MV5BMTc2MjI2NDc4Ml5BMl5BanBnXkFtZTgwODI4NzU0MTI@._V1_FMjpg_UX1000_.jpg', 'Peter Fonda, Dennis Hopper, Antonio Mendoza, Phil Spector, Mac Mashourian, Warren Finnerty', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3174, 'Man on the Moon', 'Comedy,Drama', 1999, 'Milos Forman', 'The life and career of legendary comedian Andy Kaufman.', 'https://m.media-amazon.com/images/M/MV5BYjQ1NmQ3MjItNGNiZC00OWFiLWFiYjktN2E5MzAzZDYwNjdhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jim Carrey, Gerry Becker, Greyson Erik Pendry, Brittany Colonna, Leslie Lyles, Bobby Boriello', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3175, 'Galaxy Quest', 'Adventure,Comedy,Sci-Fi', 1999, 'Dean Parisot', 'The alumni cast of a space opera television series have to play their roles as the real thing when an alien race needs their help. However, they also have to defend both Earth and the alien race from a reptilian warlord.', 'https://m.media-amazon.com/images/M/MV5BZmJkYmNhMGMtMDYyNC00ZDEyLWE2ZjAtYTg5OWViODJlNDdmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tim Allen, Sigourney Weaver, Alan Rickman, Tony Shalhoub, Sam Rockwell, Daryl Mitchell', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3176, 'Talented Mr. Ripley, The', 'Drama,Mystery,Thriller', 1999, 'Anthony Minghella', 'In late 1950s New York, a young underachiever named Tom Ripley is sent to Italy to retrieve Dickie Greenleaf, a rich and spoiled millionaire playboy. But when the errand fails, Ripley takes extreme measures.', 'https://m.media-amazon.com/images/M/MV5BYzI2ZmU3MWMtZmRlMi00ZmVlLTkwMDMtZmI1YTg4YzcwMDE0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matt Damon, Gwyneth Paltrow, Jude Law, Cate Blanchett, Philip Seymour Hoffman, Jack Davenport', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3198, 'Papillon', 'Crime,Drama', 1973, 'Franklin J. Schaffner', 'A French convict in the 1930s befriends a fellow criminal as the two of them begin serving their sentence in the South American penal colony on Devil\'s Island, which inspires the man to plot his escape.', 'https://m.media-amazon.com/images/M/MV5BN2RkNTU2YmUtNGJmNy00YTAzLWE2MjMtOTVkYWU5NzY3M2ViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Steve McQueen, Dustin Hoffman, Victor Jory, Don Gordon, Anthony Zerbe, Robert Deman', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3210, 'Fast Times at Ridgemont High', 'Comedy,Drama,Romance', 1982, 'Amy Heckerling', 'A group of SoCal high school students would rather ignore their studies and instead indulge in their teenage distractions.', 'https://m.media-amazon.com/images/M/MV5BMWM4NTc3N2YtMjk2Ny00MTRmLWE4YzItNTVhMTRlODVkNmE5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sean Penn, Jennifer Jason Leigh, Judge Reinhold, Robert Romanus, Brian Backer, Phoebe Cates', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3252, 'Scent of a Woman', 'Drama', 1992, 'Martin Brest', 'A prep school student needing money agrees to \"babysit\" a blind man, but the job is not at all what he anticipated.', 'https://m.media-amazon.com/images/M/MV5BNzc5ODg2NzMtYTQ4MS00MWFiLWI5NWMtNWNkODNmZjE0ZGVjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Al Pacino, Chris O\'Donnell, James Rebhorn, Gabrielle Anwar, Philip Seymour Hoffman, Richard Venture', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3253, 'Wayne\'s World', 'Comedy', 1992, 'Penelope Spheeris', 'Two slacker friends try to promote their public-access cable show.', 'https://m.media-amazon.com/images/M/MV5BZGNlZDY1ZTEtZTMxOS00ZjQ5LThjODUtYTBmMWYyMjAxZDdiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mike Myers, Dana Carvey, Rob Lowe, Tia Carrere, Brian Doyle-Murray, Lara Flynn Boyle', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3255, 'League of Their Own, A', 'Comedy,Drama', 1992, 'Penny Marshall', 'During World War II, sisters Dottie and Kit join the first female professional baseball league and struggle to help it succeed amid their own growing rivalry.', 'https://m.media-amazon.com/images/M/MV5BMDgwZDJjNWQtMzBmNi00ZTNkLTk5NGQtMzE2ODJkZjUyYjRhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Geena Davis, Lori Petty, Madonna, Rosie O\'Donnell, Megan Cavanagh', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3256, 'Patriot Games', 'Action,Crime,Drama,Thriller', 1992, 'Phillip Noyce', 'When CIA analyst Jack Ryan interferes with an IRA assassination, a renegade faction targets him and his family for revenge.', 'https://m.media-amazon.com/images/M/MV5BZWQ3Y2NiOGEtNjdmMS00ODI1LTk0ODktM2U3NjllNzlmZTkxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Harrison Ford, Anne Archer, Patrick Bergin, Sean Bean, Thora Birch, James Fox', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3262, 'Twin Peaks: Fire Walk with Me', 'Crime,Drama,Mystery,Thriller', 1992, 'David Lynch', 'Laura Palmer\'s harrowing final days are chronicled one year after the murder of Teresa Banks, a resident of Twin Peaks\' neighboring town.', 'https://m.media-amazon.com/images/M/MV5BYzJmZGFiMzAtODNhOC00NzAwLWFlMzAtYTQzYmRmYjIwNDgyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sheryl Lee, Ray Wise, Mädchen Amick, Dana Ashbrook, Phoebe Augustine, David Bowie', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3264, 'Buffy the Vampire Slayer', 'Action,Comedy,Horror', 1992, 'Fran Rubel Kuzui', 'Flighty teenage girl Buffy Summers learns that she is her generation\'s destined battler of vampires.', 'https://m.media-amazon.com/images/M/MV5BZDQ4MzNlMzAtZDMxMy00YzcwLWJiMTMtNDBmMWMyMTAwODM5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kristy Swanson, Donald Sutherland, Paul Reubens, Rutger Hauer, Luke Perry, Michele Abrams', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3275, 'Boondock Saints, The', 'Action,Crime,Drama,Thriller', 2000, 'Troy Duffy', 'Two Irish Catholic brothers become vigilantes in order to try to wipe out Boston\'s criminal underworld in the name of God.', 'https://m.media-amazon.com/images/M/MV5BMzIzYjE3YmMtYjdjOC00NTk5LWI0N2MtZDliYjUxNGYyNGZhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Willem Dafoe, Sean Patrick Flanery, Norman Reedus, David Della Rocco, Billy Connolly, David Ferry', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3285, 'Beach, The', 'Adventure,Drama', 2000, 'Danny Boyle', 'On vacation in Thailand, Richard sets out for an island rumored to be a solitary beach paradise.', 'https://m.media-amazon.com/images/M/MV5BYTljNTg1YjktY2I3MS00MmQwLWJkYTAtYzcwZjRjM2ExNDJjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Tilda Swinton, Daniel York Loh, Patcharawan Patarakijjanon, Virginie Ledoyen, Guillaume Canet', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3300, 'Pitch Black', 'Horror,Sci-Fi,Thriller', 2000, 'David Twohy', 'A transport ship crashes and leaves its crew stranded on a desert planet inhabited by bloodthirsty creatures that come out during an eclipse.', 'https://m.media-amazon.com/images/M/MV5BNGJlYjllOTUtZGRiNS00YmI4LTkxYmItYjBmYTdmZWZlMTMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Vin Diesel, Radha Mitchell, Cole Hauser, Keith David, Lewis Fitz-Gerald, Claudia Black', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3360, 'Hoosiers (a.k.a. Best Shot)', 'Drama,Romance', 1986, 'David Anspaugh', 'A coach with a checkered past and a local drunk train a small-town high school basketball team to become a top contender for the state championship in 1950s Indiana.', 'https://m.media-amazon.com/images/M/MV5BOGFlMjJkNzYtMTMwYS00OWE0LWFkNzYtMGMzODIzOWM0ZDM2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gene Hackman, Barbara Hershey, Dennis Hopper, Sheb Wooley, Fern Persons, Chelcie Ross', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3408, 'Erin Brockovich', 'Drama', 2000, 'Steven Soderbergh', 'A flamboyant law firm secretary works tirelessly to gain justice for a small town wrecked by a utility company\'s pollution.', 'https://m.media-amazon.com/images/M/MV5BZTNkNzkzYTEtYTJkMC00MTNkLWE0YjMtOGYxNGI0ODNiMzIwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Julia Roberts, David Brisbin, Dawn Didawick, Albert Finney, Valente Rodriguez, Conchata Ferrell', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3409, 'Final Destination', 'Drama,Thriller', 2000, 'James Wong', 'After getting a premonition about a plane crash on his school trip, Alex, a student, saves a few of his classmates. However, their situation gets complicated when death starts chasing them.', 'https://m.media-amazon.com/images/M/MV5BMjE1MjlmOWYtYzdjMS00OTgwLThjMDctZWU4N2FkZjgyNTJiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Devon Sawa, Ali Larter, Kerr Smith, Kristen Cloke, Daniel Roebuck, Roger Guenveur Smith', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3418, 'Thelma & Louise', 'Adventure,Crime,Drama', 1991, 'Ridley Scott', 'Two best friends set out on an adventure, but it soon turns around to a terrifying escape from being hunted by the police, as these two women escape for the crimes they committed.', 'https://m.media-amazon.com/images/M/MV5BMjIxNDgzMDE2MF5BMl5BanBnXkFtZTcwNzY5NTk1NA@@._V1_FMjpg_UX1000_.jpg', 'Susan Sarandon, Geena Davis, Harvey Keitel, Michael Madsen, Christopher McDonald, Stephen Tobolowsky', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3421, 'Animal House', 'Comedy', 1978, 'John Landis', 'At a 1962 college, Dean Vernon Wormer is determined to expel the entire Delta Tau Chi Fraternity, but those troublemakers have other plans for him.', 'https://m.media-amazon.com/images/M/MV5BZjk2ODY5N2UtMzczOC00M2M1LWEzZDQtZTc2YTgzMGNhOWZiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hulce, Stephen Furst, Mark Metcalf, Mary Louise Weller, Martha Smith, James Daughton', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3448, 'Good Morning, Vietnam', 'Comedy,Drama,War', 1987, 'Barry Levinson', 'In 1965, an unorthodox and irreverent DJ named Adrian Cronauer begins to shake up things when he is assigned to the U.S. Armed Services radio station in Vietnam.', 'https://m.media-amazon.com/images/M/MV5BYThiZTU4N2UtYWU2Mi00ZGUyLWI2ZmEtM2U1ZmJmOGY1ZTc3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robin Williams, Forest Whitaker, Tom T. Tran, Chintara Sukapatana, Bruno Kirby, Robert Wuhl', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3461, 'Lord of the Flies', 'Adventure,Drama,Thriller', 1963, 'Peter Brook', 'Schoolboys marooned on a Pacific island create their own savage civilization.', 'https://m.media-amazon.com/images/M/MV5BY2RiOTM0ZDgtNDRlMi00MDMzLWI1NDYtY2NjZDM4YTkwNWVlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'James Aubrey, Tom Chapin, Hugh Edwards, Roger Elwin, Tom Gaman, Roger Allan', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3471, 'Close Encounters of the Third Kind', 'Adventure,Drama,Sci-Fi', 1977, 'Steven Spielberg', 'An Indiana electric lineman finds his quiet and ordinary daily life turned upside down after a close encounter with a UFO, spurring him to an obsessed cross-country quest for answers as a momentous event approaches.', 'https://m.media-amazon.com/images/M/MV5BMjM1NjE5NjQxN15BMl5BanBnXkFtZTgwMjYzMzQxMDE@._V1_FMjpg_UX1000_.jpg', 'Richard Dreyfuss, François Truffaut, Teri Garr, Melinda Dillon, Bob Balaban, J. Patrick McNamara', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3481, 'High Fidelity', 'Comedy,Drama,Romance', 2000, 'Stephen Frears', 'Rob, a record store owner and compulsive list maker, recounts his top five breakups, including the one in progress.', 'https://m.media-amazon.com/images/M/MV5BMTgxMTI1ODYyOV5BMl5BanBnXkFtZTYwNjQyOTI3._V1_FMjpg_UX1000_.jpg', 'John Cusack, Iben Hjejle, Todd Louiso, Jack Black, Lisa Bonet, Catherine Zeta-Jones', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3489, 'Hook', 'Adventure,Comedy,Fantasy', 1991, 'Steven Spielberg', 'When Captain James Hook kidnaps his children, an adult Peter Pan must return to Neverland and reclaim his youthful spirit in order to challenge his old enemy.', 'https://m.media-amazon.com/images/M/MV5BOTU0ZTU3MGUtOTQwNi00N2QzLWFmMDUtZDgxMGJlNGI5NDllXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dustin Hoffman, Robin Williams, Julia Roberts, Bob Hoskins, Maggie Smith, Caroline Goodall', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3499, 'Misery', 'Drama,Horror,Thriller', 1990, 'Rob Reiner', 'After a famous author is rescued from a car crash by a fan of his novels, he comes to realize that the care he is receiving is only the beginning of a nightmare of captivity and abuse.', 'https://m.media-amazon.com/images/M/MV5BNzY0ODQ3MTMxN15BMl5BanBnXkFtZTgwMDkwNTg4NjE@._V1_FMjpg_UX1000_.jpg', 'James Caan, Kathy Bates, Richard Farnsworth, Frances Sternhagen, Lauren Bacall, Graham Jarvis', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3503, 'Solaris (Solyaris)', 'Drama,Mystery,Sci-Fi', 1972, 'Andrei Tarkovsky', 'A psychologist is sent to a station orbiting a distant planet in order to discover what has caused the crew to go insane.', 'https://m.media-amazon.com/images/M/MV5BYTYyMjU4MjItYzZkNy00NmIyLTg1ZGEtYTY5ZTEyM2U2NDM2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Natalya Bondarchuk, Donatas Banionis, Jüri Järvet, Vladislav Dvorzhetskiy, Nikolay Grinko, Anatoliy Solonitsyn', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3510, 'Frequency', 'Drama,Thriller', 2000, 'Gregory Hoblit', 'An accidental cross-time radio link connects father and son across 30 years. The son tries to save his father\'s life, but then must fix the consequences.', 'https://m.media-amazon.com/images/M/MV5BNzJmODljY2UtMWFkMy00YzQ5LThiZjUtNDI3NjM5NjU0ZTRjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dennis Quaid, Jim Caviezel, Shawn Doyle, Elizabeth Mitchell, Andre Braugher, Noah Emmerich', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3524, 'Arthur', 'Comedy,Romance', 1981, 'Steve Gordon', 'Alcoholic billionaire playboy Arthur Bach must marry a woman he does not love, or he will be cut off from his $750,000,000 fortune. But when Arthur falls in love with a poor waitress, he must decide if he wants to choose love or money.', 'https://m.media-amazon.com/images/M/MV5BNWRhYzc3MDktOGY0My00NmE0LWE0OWEtNTFkMmVhMWFmNDE2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dudley Moore, Liza Minnelli, John Gielgud, Geraldine Fitzgerald, Jill Eikenberry, Stephen Elliott', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3526, 'Parenthood', 'Comedy,Drama', 1989, 'Ron Howard', 'Four Buckman siblings attempt to raise their children - each in their own different style - and deal with the joys and sorrows that the process brings.', 'https://m.media-amazon.com/images/M/MV5BYTEyOTQwOWQtNTA5Ny00N2ViLThkMzctY2Y3ZTkxNTQxZGRjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Steve Martin, Mary Steenburgen, Dianne Wiest, Jason Robards, Rick Moranis, Tom Hulce', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3527, 'Predator', 'Action,Sci-Fi,Thriller', 1987, 'John McTiernan', 'A team of commandos on a mission in a Central American jungle find themselves hunted by an extraterrestrial warrior.', 'https://m.media-amazon.com/images/M/MV5BOWEzMDI0MTUtMjQ0Yy00MGRhLWI4YjAtZTgzZTM3NTYxZGJkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Arnold Schwarzenegger, Carl Weathers, Elpidia Carrillo, Bill Duke, Jesse Ventura, Sonny Landham', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3535, 'American Psycho', 'Crime,Horror,Mystery,Thriller', 2000, 'Mary Harron', 'A wealthy New York City investment banking executive, Patrick Bateman, hides his alternate psychopathic ego from his co-workers and friends as he delves deeper into his violent, hedonistic fantasies.', 'https://m.media-amazon.com/images/M/MV5BNzBjM2I5ZjUtNmIzNy00OGNkLWIwZDMtOTAwYWUwMzA2YjdlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Christian Bale, Justin Theroux, Josh Lucas, Bill Sage, Chloë Sevigny, Reese Witherspoon', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3552, 'Caddyshack', 'Comedy', 1980, 'Harold Ramis', 'An exclusive golf course has to deal with a flatulent new member and a destructive dancing gopher.', 'https://m.media-amazon.com/images/M/MV5BZmUwZTBiMTYtODUxOS00NjcxLTkxZWQtODE2MTZlYTgwNDVlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chevy Chase, Rodney Dangerfield, Ted Knight, Michael O\'Keefe, Bill Murray, Sarah Holcomb', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3556, 'Virgin Suicides, The', 'Drama,Romance', 1999, 'Sofia Coppola', 'A group of male friends become obsessed with five mysterious sisters who are sheltered by their strict, religious parents in suburban Detroit in the mid 1970s.', 'https://m.media-amazon.com/images/M/MV5BMmNhYTE5MjQtMzI2Ny00MDRhLWE4ZjAtYTg0YjNhNjZmMTVlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'James Woods, Kathleen Turner, Kirsten Dunst, Josh Hartnett, Michael Paré, Scott Glenn', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3578, 'Gladiator', 'Action,Adventure,Drama', 2000, 'Ridley Scott', 'A former Roman General sets out to exact vengeance against the corrupt emperor who murdered his family and sent him into slavery.', 'https://m.media-amazon.com/images/M/MV5BYWQ4YmNjYjEtOWE1Zi00Y2U4LWI4NTAtMTU0MjkxNWQ1ZmJiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Russell Crowe, Joaquin Phoenix, Connie Nielsen, Oliver Reed, Richard Harris, Derek Jacobi', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3591, 'Mr. Mom', 'Comedy,Drama', 1983, 'Stan Dragoti', 'After he\'s suddenly laid off, a husband switches roles with his wife. She returns to the workforce, and he becomes a stay-at-home dad, and he has to take care of three young children, a job he has no clue how to do.', 'https://m.media-amazon.com/images/M/MV5BMTUyMzg0MTkwNV5BMl5BanBnXkFtZTgwOTA2NzEyMDE@._V1_FMjpg_UX1000_.jpg', 'Michael Keaton, Teri Garr, Frederick Koehler, Taliesin Jaffe, Courtney White, Brittany White', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3617, 'Road Trip', 'Comedy', 2000, 'Todd Phillips', 'Four college buddies embark on a road trip to retrieve an illicit tape mistakenly mailed to a female friend.', 'https://m.media-amazon.com/images/M/MV5BZmZhM2U0YTItYTdjOS00OTY5LTg5OTMtMjU2ZTcwMTU0MDdhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Breckin Meyer, Seann William Scott, Amy Smart, Paulo Costanzo, DJ Qualls, Rachel Blanchard', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3623, 'Mission: Impossible II', 'Action,Adventure,Thriller', 2000, 'John Woo', 'IMF agent Ethan Hunt is sent to Sydney to find and destroy a genetically modified disease called \"Chimera\".', 'https://m.media-amazon.com/images/M/MV5BYWFjM2NhMTAtNDU1My00ODUxLTkwMzYtODQzNzM0ODM0ZWQ0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Dougray Scott, Thandiwe Newton, Ving Rhames, Richard Roxburgh, John Polson', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3638, 'Moonraker', 'Action,Adventure,Sci-Fi,Thriller', 1979, 'Lewis Gilbert', 'James Bond investigates the mid-air theft of a space shuttle, and discovers a plot to commit global genocide.', 'https://m.media-amazon.com/images/M/MV5BZDM0YTZkNDQtYTU1ZC00MzUyLTlkMTYtYmM2ZjVlM2EyMjBhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Roger Moore, Lois Chiles, Michael Lonsdale, Richard Kiel, Corinne Cléry, Bernard Lee', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3671, 'Blazing Saddles', 'Comedy,Western', 1974, 'Mel Brooks', 'In order to ruin a western town and steal their land, a corrupt politician appoints a black sheriff, who promptly becomes his most formidable adversary.', 'https://m.media-amazon.com/images/M/MV5BNTI3Y2Y4NDgtY2I1NS00M2JmLWI5NzEtYTQwYTUwZGQxYzZlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cleavon Little, Gene Wilder, Slim Pickens, Harvey Korman, Madeline Kahn, Mel Brooks', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3676, 'Eraserhead', 'Drama,Horror', 1977, 'David Lynch', 'Henry Spencer tries to survive his industrial environment, his angry girlfriend, and the unbearable screams of his newborn mutant child.', 'https://m.media-amazon.com/images/M/MV5BNGYxNzZkYzAtMDExMS00MzE1LTg5ZGItMTgzMzJhZWMyNTBjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jack Nance, Charlotte Stewart, Allen Joseph, Jeanne Bates, Judith Roberts, Laurel Near', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3683, 'Blood Simple', 'Crime,Drama,Film-Noir', 1984, 'Joel Coen', 'The owner of a seedy small-town Texas bar discovers that one of his employees is having an affair with his wife. A chaotic chain of misunderstandings, lies, and mischief ensues after he devises a plot to have them murdered.', 'https://m.media-amazon.com/images/M/MV5BNTYxNWY5ODktYWRkOC00NDdkLWIwOGQtOWY5YWQ1N2Q3OWViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Getz, Frances McDormand, Dan Hedaya, M. Emmet Walsh, Samm-Art Williams, Deborah Neumann', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3698, 'Running Man, The', 'Action,Sci-Fi', 1987, 'Paul Michael Glaser', 'In a future dystopian America, a wrongfully accused and convicted policeman gets his shot at freedom when he\'s forced to participate in a TV game show where convicts called Runners must battle killers for their freedom.', 'https://m.media-amazon.com/images/M/MV5BMDQwYzMwMDItYzFhZC00YjkzLTlmODAtMzg3NDFlNDhhZjYzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Arnold Schwarzenegger, Maria Conchita Alonso, Yaphet Kotto, Jim Brown, Jesse Ventura, Erland van Lidth', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3702, 'Mad Max', 'Action,Adventure,Sci-Fi', 1979, 'George Miller', 'In a self-destructing world, a vengeful Australian policeman sets out to stop a violent motorcycle gang.', 'https://m.media-amazon.com/images/M/MV5BMTM4Mjg5ODEzMV5BMl5BanBnXkFtZTcwMDc3NDk0NA@@._V1_FMjpg_UX1000_.jpg', 'Mel Gibson, Joanne Samuel, Hugh Keays-Byrne, Steve Bisley, Tim Burns, Roger Ward', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3703, 'Road Warrior, The (Mad Max 2)', 'Action,Adventure,Sci-Fi,Thriller', 1981, 'George Miller', 'In the post-apocalyptic Australian wasteland, a cynical drifter agrees to help a small, gasoline-rich community get rid of a horde of bandits.', 'https://m.media-amazon.com/images/M/MV5BYTAyNzBiZWUtMGY4YS00YzkzLWJhNGUtNTU5OThlZjZhZTYyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mel Gibson, Bruce Spence, Michael Preston, Max Phipps, Vernon Wells, Kjell Nilsson', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3704, 'Mad Max Beyond Thunderdome', 'Action,Adventure,Sci-Fi', 1985, 'George Miller', 'After being exiled from the most advanced town in post-apocalyptic Australia, a drifter travels with a group of abandoned children to rebel against the town\'s queen.', 'https://m.media-amazon.com/images/M/MV5BMTNkOGZjMGMtNDI4Zi00ZDBjLWJhY2UtMzA2YWI1ZGI5OWVhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mel Gibson, Bruce Spence, Adam Cockburn, Tina Turner, Frank Thring, Angelo Rossitto', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3717, 'Gone in 60 Seconds', 'Action,Crime', 2000, 'Dominic Sena', 'To save his brother, ex-thief Memphis must steal 50 luxury cars in 3 days for a crime boss. He reunites his old crew, including his mentor Otto and ex-girlfriend Sway, while police track them.', 'https://m.media-amazon.com/images/M/MV5BMTIwMzExNDEwN15BMl5BanBnXkFtZTYwODMxMzg2._V1_FMjpg_UX1000_.jpg', 'Nicolas Cage, Giovanni Ribisi, Angelina Jolie, T.J. Cross, William Lee Scott, Scott Caan', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3751, 'Chicken Run', 'Animation,Children,Comedy', 2000, 'Peter Lord', 'When a cockerel apparently flies into a chicken farm, the chickens see him as an opportunity to escape their evil owners.', 'https://m.media-amazon.com/images/M/MV5BZGViZmJjMTQtNDk3NC00NjQ4LTg0ODItYWI3MjY3YmUwMjczXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Phil Daniels, Lynn Ferguson, Mel Gibson, Tony Haygarth, Jane Horrocks, Miranda Richardson', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3752, 'Me, Myself & Irene', 'Adventure,Comedy', 2000, 'Bobby Farrelly', 'A nice-guy cop with Dissociative Identity Disorder must protect a woman on the run from a corrupt ex-boyfriend and his associates.', 'https://m.media-amazon.com/images/M/MV5BZjEzYTdkMmUtN2Y3Mi00Mzc5LWJkYTUtYTY4NzUxZTU2NzExXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jim Carrey, Renée Zellweger, Anthony Anderson, Mongo Brownlee, Jerod Mixon, Chris Cooper', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3753, 'Patriot, The', 'Action,Drama,War', 2000, 'Roland Emmerich', 'Peaceful farmer Benjamin Martin is driven to lead the Colonial Militia during the American Revolution when a sadistic British officer murders his son.', 'https://m.media-amazon.com/images/M/MV5BYThjZWExNTItYmE5Yi00ZDE3LTk1ZDktMGJiMWUyYTc2YmFkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mel Gibson, Heath Ledger, Joely Richardson, Jason Isaacs, Chris Cooper, Tchéky Karyo', '2025-11-24 12:30:38');
