INSERT INTO `movies` VALUES (3785, 'Scary Movie', 'Comedy,Horror', 2000, 'Keenen Ivory Wayans', 'A year after disposing of the body of a man they accidentally killed, a group of dumb teenagers are stalked by a bumbling serial killer.', 'https://m.media-amazon.com/images/M/MV5BZGRmMGRhOWMtOTk3Ni00OTRjLTkyYTAtYzA1M2IzMGE3NGRkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Carmen Electra, Dave Sheridan, Frank B. Moore, Giacomo Baessato, Kyle Graham, Leanne Santos', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3791, 'Footloose', 'Drama', 1984, 'Herbert Ross', 'A big city teenager moves to a small town where Rock and Roll music and dancing have been banned by backward local parents and his rebellious spirit shakes up the populace.', 'https://m.media-amazon.com/images/M/MV5BMmRjMzdkZDUtMDRkYi00ZjVkLWJlMjItMmY1MjgwOTQzMzYwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kevin Bacon, Lori Singer, John Lithgow, Dianne Wiest, Chris Penn, Sarah Jessica Parker', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3793, 'X-Men', 'Action,Adventure,Sci-Fi', 2000, 'Bryan Singer', 'In a world where mutants (evolved super-powered humans) exist and are discriminated against, two groups form for an inevitable clash: the supremacist Brotherhood, and the pacifist X-Men.', 'https://m.media-amazon.com/images/M/MV5BNzNjZjQwOTAtNWQ3NC00MmJlLThlZDEtZmUyMWQ3NmE4Y2Y5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Hugh Jackman, Patrick Stewart, Ian McKellen, Famke Janssen, James Marsden, Halle Berry', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3809, 'What About Bob?', 'Comedy', 1991, 'Frank Oz', 'A successful psychotherapist loses his mind after one of his most dependent patients, an obsessive-compulsive neurotic, tracks him down during his family vacation.', 'https://m.media-amazon.com/images/M/MV5BOTM2MzhhZmQtMzg3Zi00OTJkLTlkNjYtY2NkMDMyZmE3NGFlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bill Murray, Richard Dreyfuss, Julie Hagerty, Charlie Korsmo, Kathryn Erbe, Tom Aldredge', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3868, 'Naked Gun: From the Files of Police Squad!, The', 'Action,Comedy,Crime,Romance', 1988, 'David Zucker', 'Incompetent police Detective Frank Drebin must foil an attempt to assassinate Queen Elizabeth II.', 'https://m.media-amazon.com/images/M/MV5BZTI5N2I1MjAtNTc0Yy00ZDIyLThkZTctMGQ5NTBhNjIwMWQ0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leslie Nielsen, Priscilla Presley, Ricardo Montalban, George Kennedy, O.J. Simpson, Susan Beaubian', '2025-11-24 12:30:38');
