INSERT INTO `movies` VALUES (3911, 'Best in Show', 'Comedy', 2000, 'Christopher Guest', 'A behind-the-scenes look into the highly competitive and cut-throat world of dog shows through the eyes of a group of ruthless dog owners.', 'https://m.media-amazon.com/images/M/MV5BMTQ5OTc0NDU1MF5BMl5BanBnXkFtZTYwNzk1OTI3._V1_FMjpg_UX1000_.jpg', 'Jay Brazeau, Parker Posey, Michael Hitchcock, Catherine O\'Hara, Eugene Levy, Carrie Aizley', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3916, 'Remember the Titans', 'Drama', 2000, 'Boaz Yakin', 'In 1971, Virginia high-school football was everything to the people of Alexandria, but when the school board was forced to integrate an all-Black school with an all-white one, the foundation of football\'s tradition was put to the test.', 'https://m.media-amazon.com/images/M/MV5BZWY0NzgxMWQtMjM4NC00MjRiLWE0YjctYTFiNjA2NTNkZGY1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Denzel Washington, Will Patton, Wood Harris, Ryan Hurst, Donald Faison, Craig Kirkwood', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3948, 'Meet the Parents', 'Comedy', 2000, 'Jay Roach', 'Chicago male nurse and chronic under-achiever Greg Focker meets his charming teacher girlfriend Pam Byrnes\' parents Jack and Dina before proposing, but suspicious Jack is an overprotective former CIA agent - every date\'s worst nightmare.', 'https://m.media-amazon.com/images/M/MV5BZmE0MGI0OTctOGRlMy00MDdjLTg4M2EtNzFmZWNiNDhjYTgzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert De Niro, Ben Stiller, Teri Polo, Blythe Danner, Nicole DeHuff, Jon Abrahams', '2025-11-24 12:30:38');
