INSERT INTO `movies` VALUES (3977, 'Charlie\'s Angels', 'Action,Comedy', 2000, 'McG', 'Three private investigators are assigned to track down a kidnapped software engineer, but the case isn\'t as straightforward as it seems.', 'https://m.media-amazon.com/images/M/MV5BYTkyYjRiZGMtYzA0Mi00N2IyLThhZDAtYWU1OWNhNjIxNzY5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cameron Diaz, Drew Barrymore, Lucy Liu, Bill Murray, Sam Rockwell, Kelly Lynch', '2025-11-24 12:30:38');
