INSERT INTO `movies` VALUES (3994, 'Unbreakable', 'Drama,Sci-Fi', 2000, 'M. Night Shyamalan', 'A man learns something extraordinary about himself after a devastating accident.', 'https://m.media-amazon.com/images/M/MV5BZWNmMGYwMDQtNGIxMS00MzMzLTlhNmItYzllN2M2M2EwMTZmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bruce Willis, Samuel L. Jackson, Robin Wright, Spencer Treat Clark, Charlayne Woodard, Eamonn Walker', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (3996, 'Crouching Tiger, Hidden Dragon (Wo hu cang long)', 'Action,Drama,Romance', 2000, 'Ang Lee', 'A young Chinese warrior steals a sword from a famed swordsman and then escapes into a world of romantic adventure with a mysterious man in the frontier of the nation.', 'https://m.media-amazon.com/images/M/MV5BMzRmMTU2OWEtZjI0Ni00MGRhLThjOTItZTJiNmM4MDk0ZWU2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chow Yun-Fat, Michelle Yeoh, Ziyi Zhang, Chang Chen, Sihung Lung, Pei-Pei Cheng', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (4002, 'Planes, Trains & Automobiles', 'Comedy', 1987, 'John Hughes', 'A Chicago advertising man must struggle to travel home from New York for Thanksgiving, with a lovable oaf of a shower-curtain-ring salesman as his only companion.', 'https://m.media-amazon.com/images/M/MV5BOWJhY2Y1Y2YtNjA0NC00ZjNkLTg2NWMtMjhhY2JiZDJhYTdmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Steve Martin, John Candy, Laila Robins, Michael McKean, Kevin Bacon, Dylan Baker', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (4007, 'Wall Street', 'Drama', 1987, 'Oliver Stone', 'An impatient young stockbroker is willing to do anything to get to the top, including trading on illegal inside information taken through a ruthless, greedy corporate raider who takes the youth under his wing.', 'https://m.media-amazon.com/images/M/MV5BMWQ4NDY4NTktYjE5NS00MWQ5LWFmZTUtNjk5NjA4Mzc3ODNhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Charlie Sheen, Tamara Tunie, Franklin Cover, Chuck Pfeiffer, John C. McGinley, Hal Holbrook', '2025-11-24 12:30:38');
