INSERT INTO `movies` VALUES (4226, 'Memento', 'Mystery,Thriller', 2000, 'Christopher Nolan', 'A former insurance investigator who now suffers from anterograde amnesia uses notes and tattoos to hunt down his wife\'s murderer.', 'https://m.media-amazon.com/images/M/MV5BMGQ3Y2Q4NjktN2E4Ny00Y2Q2LTliZDUtZTNiNjRhY2I0NGIyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Guy Pearce, Carrie-Anne Moss, Joe Pantoliano, Mark Boone Junior, Russ Fega, Jorja Fox', '2025-11-24 12:30:37');
