INSERT INTO `movies` VALUES (4239, 'Blow', 'Crime,Drama', 2001, 'Ted Demme', 'The story of how George Jung, along with the Medellín Cartel headed by Pablo Escobar, established the American cocaine market in the 1970s in the United States.', 'https://m.media-amazon.com/images/M/MV5BNTNkMzMwOWItM2FmYS00YmI2LWE4NjUtMmI5MDk0YTkwZjM2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Penélope Cruz, Franka Potente, Rachel Griffiths, Paul Reubens, Jordi Mollà', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4246, 'Bridget Jones\'s Diary', 'Comedy,Drama,Romance', 2001, 'Sharon Maguire', 'Bridget Jones is determined to improve herself while she looks for love in a year in which she keeps a personal diary.', 'https://m.media-amazon.com/images/M/MV5BNTM1MTFiNDEtMGYzZC00MjM5LWEwMWMtN2VhNjg1MTEzOTg3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Renée Zellweger, Gemma Jones, Celia Imrie, James Faulkner, Jim Broadbent, Colin Firth', '2025-11-24 12:30:37');
