INSERT INTO `movies` VALUES (4299, 'Knight\'s Tale, A', 'Action,Comedy,Romance', 2001, 'Brian Helgeland', 'After his master dies, a peasant squire, fueled by his desire for food and glory, creates a new identity for himself as a knight.', 'https://m.media-amazon.com/images/M/MV5BMTE5OTE4OTE2Nl5BMl5BanBnXkFtZTYwMDkzMTQ3._V1_FMjpg_UX1000_.jpg', 'Heath Ledger, Rufus Sewell, Shannyn Sossamon, Paul Bettany, Laura Fraser, Mark Addy', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4306, 'Shrek', 'Adventure,Animation,Children,Comedy,Fantasy,Romance', 2001, 'Andrew Adamson', 'A mean lord exiles fairytale creatures to the swamp of a grumpy ogre, who must go on a quest and rescue a princess for the lord in order to get his land back.', 'https://m.media-amazon.com/images/M/MV5BN2FkMTRkNTUtYTI0NC00ZjI4LWI5MzUtMDFmOGY0NmU2OGY1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mike Myers, Eddie Murphy, Cameron Diaz, John Lithgow, Vincent Cassel, Peter Dennis', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4308, 'Moulin Rouge', 'Drama,Musical,Romance', 2001, 'Baz Luhrmann', 'A poor Bohemian poet in 1890s Paris falls for a beautiful courtesan and nightclub star coveted by a jealous duke.', 'https://m.media-amazon.com/images/M/MV5BYTgyOGY4OTktZmZhMC00ZmIwLWI4YjUtNjYzNDg1Nzc3ZDg1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nicole Kidman, Ewan McGregor, John Leguizamo, Jim Broadbent, Richard Roxburgh, Garry McDonald', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4310, 'Pearl Harbor', 'Action,Drama,Romance,War', 2001, 'Michael Bay', 'A tale of war and romance mixed in with history. The story follows two lifelong friends and a beautiful nurse who are caught up in the horror of an infamous Sunday morning in 1941.', 'https://m.media-amazon.com/images/M/MV5BMTQ3MDc0MDc1NF5BMl5BanBnXkFtZTYwODI1ODY2._V1_FMjpg_UX1000_.jpg', 'Ben Affleck, Josh Hartnett, Kate Beckinsale, William Lee Scott, Greg Zola, Ewen Bremner', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4321, 'City Slickers', 'Comedy,Western', 1991, 'Ron Underwood', 'On the verge of turning 40, an unhappy Manhattan yuppie is roped into joining his two friends on a cattle drive in the southwest.', 'https://m.media-amazon.com/images/M/MV5BMTkwNjM2MTc5NF5BMl5BanBnXkFtZTcwMzQ2NjEzNA@@._V1_FMjpg_UX1000_.jpg', 'Billy Crystal, Daniel Stern, Bruno Kirby, Patricia Wettig, Helen Slater, Jack Palance', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4326, 'Mississippi Burning', 'Crime,Drama,Thriller', 1988, 'Alan Parker', 'Two FBI agents with wildly different styles arrive in Mississippi to investigate the disappearance of three civil rights activists.', 'https://m.media-amazon.com/images/M/MV5BZDgwNTljYmMtYmQyNi00MmEwLTk0NzMtZDJmZDIzZmQ4MzQ2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gene Hackman, Willem Dafoe, Frances McDormand, Brad Dourif, R. Lee Ermey, Gailard Sartain', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4343, 'Evolution', 'Comedy,Sci-Fi', 2001, 'Ivan Reitman', 'Two college professors team up with a fire-fighting cadet and a government scientist to combat an alien organism that has been rapidly evolving since its arrival on Earth inside a meteor.', 'https://m.media-amazon.com/images/M/MV5BZjMwZjJjYzItZjUwZS00MTU5LTlmOTItMmE5MGFhZTg2MWM2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'David Duchovny, Julianne Moore, Orlando Jones, Seann William Scott, Ted Levine, Ethan Suplee', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4344, 'Swordfish', 'Action,Crime,Drama', 2001, 'Dominic Sena', 'A covert counter-terrorist unit called Black Cell led by Gabriel Shear wants the money to help finance their war against international terrorism, but it\'s all locked away. Gabriel brings in convicted hacker Stanley Jobson to help him.', 'https://m.media-amazon.com/images/M/MV5BMmVlOGM1YjQtNzMzYS00ZmY5LTlkMDQtN2EyZTQ4NTExNjNjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Travolta, Hugh Jackman, Halle Berry, Don Cheadle, Sam Shepard, Vinnie Jones', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4361, 'Tootsie', 'Comedy,Romance', 1982, 'Sydney Pollack', 'Michael Dorsey, an unsuccessful actor, disguises himself as a woman in order to get a role on a trashy hospital soap.', 'https://m.media-amazon.com/images/M/MV5BNzc1YjU5NzEtMmZjYi00NzE2LThjMmEtMzY1ZTg5ZjgyM2EzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dustin Hoffman, Jessica Lange, Teri Garr, Dabney Coleman, Charles Durning, Bill Murray', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4367, 'Lara Croft: Tomb Raider', 'Action,Adventure', 2001, 'Simon West', 'Adventurer Lara Croft explores lost empires and discovers immeasurable treasures in her daily life, but a secret from the past of her father, a missing archaeologist, will lead her to one of her greatest challenges.', 'https://m.media-amazon.com/images/M/MV5BNjcxYzIyZWItZWRiOS00ODliLWI3ZTEtZTA4NTg4OGQwZDY1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Angelina Jolie, Jon Voight, Iain Glen, Noah Taylor, Daniel Craig, Richard Johnson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4369, 'Fast and the Furious, The', 'Action,Crime,Thriller', 2001, 'Rob Cohen', 'Los Angeles police officer Brian O\'Conner must decide where his loyalty really lies when he becomes enamored with the street racing world he has been sent undercover to end it.', 'https://m.media-amazon.com/images/M/MV5BZGRiMDE1NTMtMThmZS00YjE4LWI1ODQtNjRkZGZlOTg2MGE1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Paul Walker, Vin Diesel, Michelle Rodriguez, Jordana Brewster, Rick Yune, Chad Lindberg', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4370, 'A.I. Artificial Intelligence', 'Adventure,Drama,Sci-Fi', 2001, 'Steven Spielberg', 'A highly advanced robotic boy longs to become \"real\" so that he can regain the love of his human mother.', 'https://m.media-amazon.com/images/M/MV5BODA1YjhhZDctM2Y1ZS00ODkyLWFmMTAtZGY5YWEzNzRjYzA1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Haley Joel Osment, Frances O\'Connor, Sam Robards, Jake Thomas, Jude Law, William Hurt', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4446, 'Final Fantasy: The Spirits Within', 'Adventure,Animation,Fantasy,Sci-Fi', 2001, 'Hironobu Sakaguchi', 'A scientist makes a last stand on Earth with the help of a ragtag team of soldiers against an invasion of alien phantoms.', 'https://m.media-amazon.com/images/M/MV5BZWM1MDdjMjMtNjJmYy00ZjY5LTllYmItMTU5N2RmMGI5NTM1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ming-Na Wen, Alec Baldwin, Ving Rhames, Steve Buscemi, Peri Gilpin, Donald Sutherland', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4447, 'Legally Blonde', 'Comedy,Romance', 2001, 'Robert Luketic', 'Fashionable sorority queen Elle Woods follows her ex-boyfriend to law school, where she discovers that there is more to her than just looks.', 'https://m.media-amazon.com/images/M/MV5BNTEyNjUwMTkxMV5BMl5BanBnXkFtZTcwNjk0NDk0NA@@._V1_FMjpg_UX1000_.jpg', 'Reese Witherspoon, Luke Wilson, Selma Blair, Matthew Davis, Victor Garber, Jennifer Coolidge', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4499, 'Dirty Rotten Scoundrels', 'Comedy', 1988, 'Frank Oz', 'Two con men try to settle their rivalry by betting on who can swindle a young American heiress out of fifty thousand dollars first.', 'https://m.media-amazon.com/images/M/MV5BNzRmYjM2ZmEtYTczZC00YWJjLWJjZTMtYTFlYjljMTVmMTAwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Steve Martin, Michael Caine, Glenne Headly, Anton Rodgers, Barbara Harris, Ian McDiarmid', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4571, 'Bill & Ted\'s Excellent Adventure', 'Adventure,Comedy,Sci-Fi', 1989, 'Stephen Herek', 'Two rock-\'n-rolling teens, on the verge of failing their class, set out on a quest to make the ultimate school history report after being presented with a time machine.', 'https://m.media-amazon.com/images/M/MV5BMTk3Mjk5MzI3OF5BMl5BanBnXkFtZTcwMTY4MzcyNA@@._V1_FMjpg_UX1000_.jpg', 'Keanu Reeves, Alex Winter, George Carlin, Terry Camilleri, Dan Shor, Tony Steedman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4623, 'Major League', 'Comedy', 1989, 'David S. Ward', 'The new owner of the Cleveland Indians puts together a purposely horrible team so they\'ll lose and she can move the team. But when the plot is uncovered, they start winning just to spite her.', 'https://m.media-amazon.com/images/M/MV5BMmRiNjc2YWMtYzg4YS00Njg3LTg4YzgtNWVhM2RmMGIwNGFjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Berenger, Charlie Sheen, Corbin Bernsen, Margaret Whitton, James Gammon, Rene Russo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4638, 'Jurassic Park III', 'Action,Adventure,Sci-Fi,Thriller', 2001, 'Joe Johnston', 'A decidedly odd couple with ulterior motives convince Dr. Grant to go to Isla Sorna for a holiday, but their unexpected landing startles the island\'s new inhabitants.', 'https://m.media-amazon.com/images/M/MV5BN2FmMjhlZDYtNmYyMy00NTdjLTlhYzYtZWNlMDY2MmUzOGM2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sam Neill, William H. Macy, Téa Leoni, Alessandro Nivola, Trevor Morgan, Michael Jeter', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4643, 'Planet of the Apes', 'Action,Adventure,Drama,Sci-Fi', 2001, 'Tim Burton', 'In 2029, an Air Force astronaut crash-lands on a mysterious planet where evolved, talking apes dominate a race of primitive humans.', 'https://m.media-amazon.com/images/M/MV5BYjczODRhOTQtZjdkYi00MmM2LTg1ZmEtZDQ3YjA5MDJhODNhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mark Wahlberg, Tim Roth, Helena Bonham Carter, Michael Clarke Duncan, Paul Giamatti, Estella Warren', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4679, 'Uncle Buck', 'Comedy', 1989, 'John Hughes', 'Laid back commitment-phobe Buck babysits his brother\'s rebellious teenage daughter and her cute younger brother and sister.', 'https://m.media-amazon.com/images/M/MV5BYmRjMTIxZDgtMGI2ZC00ZGYwLWFlMjUtYmE5MzllYWZjNWJmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Candy, Jean Louisa Kelly, Gaby Hoffmann, Macaulay Culkin, Amy Madigan, Elaine Bromka', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4700, 'Princess Diaries, The', 'Children,Comedy,Romance', 2001, 'Garry Marshall', 'Mia Thermopolis has just found out that she is the heir apparent to the throne of Genovia. With her friends Lilly and Michael Moscovitz in tow, she tries to navigate through the rest of her fifteenth year.', 'https://m.media-amazon.com/images/M/MV5BMzNiYWQ4NjUtZjliMS00MTllLWIxNDItNGU1MjBkMTE3ODg1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Julie Andrews, Anne Hathaway, Hector Elizondo, Heather Matarazzo, Mandy Moore, Caroline Goodall', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4701, 'Rush Hour 2', 'Action,Comedy', 2001, 'Brett Ratner', 'Carter and Lee head to Hong Kong for a vacation, but become embroiled in a counterfeit money scam.', 'https://m.media-amazon.com/images/M/MV5BMGM0OTM4NGYtYzkzMC00OGZmLWEwZTItOTg4ZTdkYTIxOTc0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jackie Chan, Chris Tucker, John Lone, Ziyi Zhang, Roselyn Sanchez, Alan King', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4720, 'Others, The', 'Drama,Horror,Mystery,Thriller', 2001, 'Alejandro Amenábar', 'In 1945, immediately following the end of Second World War, a woman who lives with her two photosensitive children on her darkened old family estate in the Channel Islands becomes convinced that the home is haunted.', 'https://m.media-amazon.com/images/M/MV5BZTNhODBkODAtNDllYy00YTg1LWJmNDUtYjgzMzEzOWQ0YWNjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nicole Kidman, Fionnula Flanagan, Christopher Eccleston, Alakina Mann, James Bentley, Eric Sykes', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4734, 'Jay and Silent Bob Strike Back', 'Adventure,Comedy', 2001, 'Kevin Smith', 'The comic \"Bluntman and Chronic\" is based on real-life stoners Jay and Silent Bob, so when they get no profit from a big-screen adaptation, they set out to wreck the movie.', 'https://m.media-amazon.com/images/M/MV5BZjAxZDU1YjYtOGJjZC00NjQ2LWFhNjEtZGVhZDZhYTlhMzUyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Amy Noble, Harley Quinn Smith, Ever Carradine, Brian Andrew Saible, Gavin Brooks, John Willyung', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4776, 'Training Day', 'Crime,Drama,Thriller', 2001, 'Antoine Fuqua', 'A rookie cop spends his first day as a Los Angeles narcotics officer with a rogue detective who isn\'t what he appears to be.', 'https://m.media-amazon.com/images/M/MV5BMjRlNjUwOGYtNGQxZS00ZjhkLTg0NDgtYjcwNzZlNDU2YjBlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Denzel Washington, Ethan Hawke, Scott Glenn, Tom Berenger, Harris Yulin, Raymond J. Barry', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4816, 'Zoolander', 'Comedy', 2001, 'Ben Stiller', 'At the end of his career, a clueless fashion model is brainwashed to kill the Prime Minister of Malaysia.', 'https://m.media-amazon.com/images/M/MV5BODI4NDY2NDM5M15BMl5BanBnXkFtZTgwNzEwOTMxMDE@._V1_FMjpg_UX1000_.jpg', 'Ben Stiller, Owen Wilson, Christine Taylor, Will Ferrell, Milla Jovovich, Jerry Stiller', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4823, 'Serendipity', 'Comedy,Romance', 2001, 'Peter Chelsom', 'A couple search for each other years after the night they first met, fell in love, and separated, convinced that one day they\'d end up together.', 'https://m.media-amazon.com/images/M/MV5BYTQzMjE3YTAtYzc2MC00OTk4LTg0NTYtYzg3YzQ2ZTM3ODY1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Cusack, Kate Beckinsale, Jeremy Piven, Bridget Moynahan, Eugene Levy, Lilli Lavine', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4830, 'Brubaker', 'Crime,Drama', 1980, 'Stuart Rosenberg', 'The new warden of a small prison farm in Arkansas tries to clean it up of corruption after initially posing as an inmate.', 'https://m.media-amazon.com/images/M/MV5BMjI3OTY5OGYtZmI1Ny00MGU5LTg2MzgtZGY0YWVjODM1NDExXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert Redford, Yaphet Kotto, Jane Alexander, Murray Hamilton, David Keith, Morgan Freeman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4848, 'Mulholland Drive', 'Crime,Drama,Film-Noir,Mystery,Thriller', 2001, 'David Lynch', 'After a car wreck on Mulholland Drive renders a woman amnesiac, she and a Hollywood-hopeful search for clues and answers across Los Angeles in a twisting venture beyond dreams and reality.', 'https://m.media-amazon.com/images/M/MV5BNjliY2UwMjQtYjVlNi00NzExLTg1MDMtMjE2OTYwYjI0NTcxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Naomi Watts, Jeanne Bates, Dan Birnbaum, Laura Harring, Randall Wulff, Robert Forster', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4855, 'Dirty Harry', 'Action,Crime,Thriller', 1971, 'Don Siegel', 'When a killer calling himself \"Scorpio\" menaces San Francisco, tough-as-nails Police Inspector \"Dirty\" Harry Callahan is assigned to track down the crazed psychopath.', 'https://m.media-amazon.com/images/M/MV5BYzNmOWVjN2ItMTQzOS00MTI4LTgxZDItMmZjNTVlMjY5Mjc1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Clint Eastwood, Harry Guardino, Reni Santoni, John Vernon, Andrew Robinson, John Larch', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4865, 'From Hell', 'Crime,Horror,Mystery,Thriller', 2001, 'Albert Hughes', 'In 1888 London, a Scotland Yard investigator searches for Jack The Ripper.', 'https://m.media-amazon.com/images/M/MV5BNzA5N2RlZDItNzc5My00YjIwLWFiMzktYTI1NDg0MDc1YTY1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Heather Graham, Ian Holm, Robbie Coltrane, Ian Richardson, Jason Flemyng', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4874, 'K-PAX', 'Drama,Fantasy,Mystery,Sci-Fi', 2001, 'Iain Softley', 'PROT is a patient at a mental hospital who claims to be from a faraway planet named K-PAX. His psychiatrist tries to help him, only to begin to doubt his own explanations.', 'https://m.media-amazon.com/images/M/MV5BZWU5MTJiNDMtMmI0Yy00MWRjLTgwZjktODEyY2NmZThhM2EwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kevin Spacey, Jeff Bridges, Mary McCormack, Alfre Woodard, David Patrick Kelly, Saul Williams', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4878, 'Donnie Darko', 'Drama,Mystery,Sci-Fi,Thriller', 2001, 'Richard Kelly', 'After narrowly escaping a bizarre accident, a troubled teenager is plagued by visions of a man in a large rabbit suit who manipulates him to commit a series of crimes.', 'https://m.media-amazon.com/images/M/MV5BMWE3NTYzZmEtM2U5MS00MDZhLTk2ZTQtZTgzNjg0ZGQ5ZjM0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jake Gyllenhaal, Holmes Osborne, Maggie Gyllenhaal, Daveigh Chase, Mary McDonnell, James Duval', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4886, 'Monsters, Inc.', 'Adventure,Animation,Children,Comedy,Fantasy', 2001, 'Pete Docter', 'In order to power the city, monsters have to scare children so that they scream. However, the children are toxic to the monsters, and after a child gets through, two monsters realize things may not be what they think.', 'https://m.media-amazon.com/images/M/MV5BMTY1NTI0ODUyOF5BMl5BanBnXkFtZTgwNTEyNjQ0MDE@._V1_FMjpg_UX1000_.jpg', 'John Goodman, Billy Crystal, Mary Gibbs, Steve Buscemi, James Coburn, Jennifer Tilly', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4887, 'One, The', 'Action,Sci-Fi,Thriller', 2001, 'James Wong', 'A rogue Multiverse agent goes on a manhunt for alternate versions of himself, getting stronger with each kill. Only the last version of himself, an LASD cop, can stop his crusade before he becomes \"The One\".', 'https://m.media-amazon.com/images/M/MV5BMzE3Y2VjNzMtZGMyOS00ZjA5LWExZjYtYzNkMTQ3Mzk5YmY0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jet Li, Carla Gugino, Delroy Lindo, Jason Statham, James Morrison, Dylan Bruno', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4890, 'Shallow Hal', 'Comedy,Fantasy,Romance', 2001, 'Bobby Farrelly', 'A shallow man falls in love with a 300-pound woman because of her inner beauty.', 'https://m.media-amazon.com/images/M/MV5BMTcwMzY2NDE0NF5BMl5BanBnXkFtZTYwNjg2Njc2._V1_FMjpg_UX1000_.jpg', 'Gwyneth Paltrow, Jack Black, Jason Alexander, Joe Viterelli, Rene Kirby, Bruce McGill', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4896, 'Harry Potter and the Sorcerer\'s Stone (a.k.a. Harry Potter and the Philosopher\'s Stone)', 'Adventure,Children,Fantasy', 2001, 'Chris Columbus', 'An orphaned boy enrolls in a school of wizardry, where he learns the truth about himself, his family and the terrible evil that haunts the magical world.', 'https://m.media-amazon.com/images/M/MV5BNTU1MzgyMDMtMzBlZS00YzczLThmYWEtMjU3YmFlOWEyMjE1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Richard Harris, Maggie Smith, Robbie Coltrane, Saunders Triplets, Daniel Radcliffe, Fiona Shaw', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4901, 'Spy Game', 'Action,Crime,Drama,Thriller', 2001, 'Tony Scott', 'Retiring CIA agent Nathan Muir recalls his training of Tom Bishop while working against agency politics to free him from his Chinese captors.', 'https://m.media-amazon.com/images/M/MV5BYTljZmI1MjctMWJmMC00ZjJmLTkwNzUtNGQxNWJhZGRjMjM3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert Redford, Brad Pitt, Catherine McCormack, Stephen Dillane, Larry Bryggman, Marianne Jean-Baptiste', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4963, 'Ocean\'s Eleven', 'Crime,Thriller', 2001, 'Steven Soderbergh', 'Danny Ocean, a gangster, rounds up a gang of associates to stage a sophisticated and elaborate casino heist which involves robbing three Las Vegas casinos simultaneously during a popular boxing event.', 'https://m.media-amazon.com/images/M/MV5BMmNhZDkxYTgtMDM3ZC00NTQ3LWFjZTUtNzc1Y2QyNWZjNDRmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'George Clooney, Cecelia Ann Birt, Paul L. Nolan, Carol Florence, Lori Galinski, Bernie Mac', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4973, 'Amelie (Fabuleux destin d\'Amélie Poulain, Le)', 'Comedy,Romance', 2001, 'Jean-Pierre Jeunet', 'Despite being caught in her imaginative world, young waitress Amelie decides to help people find happiness. Her quest to spread joy leads her on a journey during which she finds true love.', 'https://m.media-amazon.com/images/M/MV5BOTNmYzY0MWQtZGZmNy00Y2Y4LWFmMDQtMTZjYTdiYzEwZGQ2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Audrey Tautou, Mathieu Kassovitz, Rufus, Lorella Cravotta, Serge Merlin, Jamel Debbouze', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4975, 'Vanilla Sky', 'Mystery,Romance,Sci-Fi,Thriller', 2001, 'Cameron Crowe', 'A self-indulgent and vain publishing magnate finds his privileged life upended after a vehicular accident with a resentful lover.', 'https://m.media-amazon.com/images/M/MV5BNTg5YmYyMzAtYmEzZi00MzA2LWIxMTMtZTc1N2ZjNTA3ZDU2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Penélope Cruz, Cameron Diaz, Kurt Russell, Jason Lee, Noah Taylor', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4979, 'Royal Tenenbaums, The', 'Comedy,Drama', 2001, 'Wes Anderson', 'The eccentric members of a dysfunctional family reluctantly gather under the same roof for various reasons.', 'https://m.media-amazon.com/images/M/MV5BZTc1MzFlMjEtMzkyNC00NDgyLThjMjMtMzQzZGI5YjUyNzU5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gene Hackman, Anjelica Huston, Ben Stiller, Gwyneth Paltrow, Luke Wilson, Owen Wilson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4993, 'Lord of the Rings: The Fellowship of the Ring, The', 'Adventure,Fantasy', 2001, 'Peter Jackson', 'A meek Hobbit from the Shire and eight companions set out on a journey to destroy the powerful One Ring and save Middle-earth from the Dark Lord Sauron.', 'https://m.media-amazon.com/images/M/MV5BNzIxMDQ2YTctNDY4MC00ZTRhLTk4ODQtMTVlOWY4NTdiYmMwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Alan Howard, Noel Appleby, Sean Astin, Sala Baker, Sean Bean, Billy Boyd', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (4995, 'Beautiful Mind, A', 'Drama,Romance', 2001, 'Ron Howard', 'A mathematical genius, John Nash made an astonishing discovery early in his career and stood on the brink of international acclaim. But the handsome and arrogant Nash soon found himself on a harrowing journey of self-discovery.', 'https://m.media-amazon.com/images/M/MV5BNzljZTk5ZDgtZTQ1Zi00NTM4LThlOGUtZDk2MGM4NDQ4NWQyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Russell Crowe, Ed Harris, Jennifer Connelly, Christopher Plummer, Paul Bettany, Adam Goldberg', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5010, 'Black Hawk Down', 'Action,Drama,War', 2001, 'Ridley Scott', 'The story of one hundred and sixty elite U.S. soldiers who dropped into Mogadishu in October 1993 to capture two top lieutenants of a renegade warlord, but found themselves in a desperate battle with a large force of heavily armed Somalis.', 'https://m.media-amazon.com/images/M/MV5BYTM3YTQ1M2MtNDEyNC00NzRlLWFmOTgtYjBhNDg2ODNjNTU0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Josh Hartnett, Ewan McGregor, Tom Sizemore, Eric Bana, William Fichtner, Ewen Bremner', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5015, 'Monster\'s Ball', 'Drama,Romance', 2001, 'Marc Forster', 'After a family tragedy, a racist prison guard re-examines his attitudes while falling in love with the African-American wife of the last prisoner he executed.', 'https://m.media-amazon.com/images/M/MV5BMjYxMTQxMzgtN2UyYS00Y2JkLTg1MmYtOTYwMGI4YWQxZDhmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Billy Bob Thornton, Taylor Simpson, Gabrielle Witcher, Heath Ledger, Amber Rules, Peter Boyle', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5021, 'Murder by Death', 'Comedy,Crime,Mystery,Thriller', 1976, 'Robert Moore', 'Five famous literary detective characters and their sidekicks are invited to a bizarre mansion to solve an even stranger mystery.', 'https://m.media-amazon.com/images/M/MV5BMDVkZjRjZjAtMmMyMy00ZDBmLWIwNWQtNDJiOWE4NjNjOGE0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Eileen Brennan, Truman Capote, James Coco, Peter Falk, Alec Guinness, Elsa Lanchester', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5051, 'Italian for Beginners (Italiensk for begyndere)', 'Comedy,Drama,Romance', 2000, 'Lone Scherfig', 'Several lonely hearts in a semi-provincial suburb of a town in Denmark use a beginner\'s course in Italian as the platform to meet the romance of their lives.', 'https://m.media-amazon.com/images/M/MV5BZjgwZjdmNjMtNmJhNS00ZGExLTkyNTctMDU1ZDY1MzY5MWNjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Anders W. Berthelsen, Anette Støvelbæk, Ann Eleonora Jørgensen, Peter Gantzler, Lars Kaalund, Sara Indrio Jensen', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5066, 'Walk to Remember, A', 'Drama,Romance', 2002, 'Adam Shankman', 'Two North Carolina teens, Landon Carter and Jamie Sullivan, are thrown together after Landon gets into trouble and is sentenced to perform community service.', 'https://m.media-amazon.com/images/M/MV5BYjkxZWE0YjMtYTk2OS00ZmFjLTk2YjEtY2M3MGY4MzE4MGNkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Shane West, Mandy Moore, Peter Coyote, Daryl Hannah, Lauren German, Clayne Crawford', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5171, 'Time Machine, The', 'Action,Adventure,Sci-Fi', 2002, 'Simon Wells', 'Hoping to alter the events of the past, a 19th century inventor instead travels 800,000 years into the future, where he finds humankind divided into two warring races.', 'https://m.media-amazon.com/images/M/MV5BZjRiMTdjNmEtOGJjNy00ZjA1LTlkNzktNzc0NzMxNTY0OGE5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Guy Pearce, Mark Addy, Phyllida Law, Sienna Guillory, Laura Kirk, Josh Stamberg', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5218, 'Ice Age', 'Adventure,Animation,Children,Comedy', 2002, 'Carlos Saldanha', 'Manny the mammoth, Sid the loquacious sloth, and Diego the sabre-toothed tiger go on a comical quest to return a human baby back to his father, across a world on the brink of an ice age.', 'https://m.media-amazon.com/images/M/MV5BMDBlYzU2OGMtOGJjNi00ZGZjLWIwNjMtYzdiZjkwYWNjZDljXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ray Romano, John Leguizamo, Denis Leary, Goran Visnjic, Jack Black, Cedric The Entertainer', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5266, 'Panic Room', 'Thriller', 2002, 'David Fincher', 'A divorced woman and her diabetic daughter take refuge in their newly-purchased house\'s safe room when three men break-in, searching for a missing fortune.', 'https://m.media-amazon.com/images/M/MV5BODU0ZGM0MjctM2YxYy00OWY1LTk2N2YtNWE4ZWQ2ODQwMTI5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jodie Foster, Kristen Stewart, Forest Whitaker, Dwight Yoakam, Jared Leto, Patrick Bauchau', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5299, 'My Big Fat Greek Wedding', 'Comedy,Romance', 2002, 'Joel Zwick', 'A young Greek woman falls in love with a non-Greek and struggles to get her family to accept him while she comes to terms with her heritage and cultural identity.', 'https://m.media-amazon.com/images/M/MV5BNWVmZmM3ZmUtNTU5ZS00ZmUxLTk0NDYtNWIxZjY4Zjk0MjQyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nia Vardalos, Michael Constantine, Christina Eleusiniotis, Kaylee Vieira, Johnny Kalangis, Lainie Kazan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5308, 'Three Men and a Baby', 'Comedy', 1987, 'Leonard Nimoy', 'Jack Holden and his friends, Peter and Michael, spend most of their time having flings with several women in their apartment. Their life changes when a mysterious baby appears at their doorstep.', 'https://m.media-amazon.com/images/M/MV5BNWZhZmJjMzEtOGE2Ni00ZTY3LWIwZDgtMTM1NTEzZDAxNmE4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Selleck, Steve Guttenberg, Ted Danson, Nancy Travis, Margaret Colin, Alexandra Amini', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5323, 'Jason X', 'Horror,Sci-Fi,Thriller', 2002, 'James Isaac', 'Jason Voorhees is cryogenically frozen at the beginning of the 21st century, and is discovered in the 25th century and taken to space. He gets thawed, and begins stalking and killing the crew of the spaceship that\'s transporting him.', 'https://m.media-amazon.com/images/M/MV5BMDY4NWZhZmMtNDQwZi00MmZiLTllNTItYTRjN2FkYTU1MDVmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kane Hodder, Jeff Geddis, Lexa Doig, David Cronenberg, Markus Parilo, Jonathan Potts', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5349, 'Spider-Man', 'Action,Adventure,Sci-Fi,Thriller', 2002, 'Sam Raimi', 'After being bitten by a genetically-modified spider, a shy teenager gains spider-like abilities that he uses to fight injustice as a masked superhero and face a vengeful enemy.', 'https://m.media-amazon.com/images/M/MV5BZWM0OWVmNTEtNWVkOS00MzgyLTkyMzgtMmE2ZTZiNjY4MmFiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tobey Maguire, Willem Dafoe, Kirsten Dunst, James Franco, Cliff Robertson, Rosemary Harris', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5378, 'Star Wars: Episode II - Attack of the Clones', 'Action,Adventure,Sci-Fi,IMAX', 2002, 'George Lucas', 'Ten years after initially meeting, Anakin Skywalker shares a forbidden romance with Padmé Amidala, while Obi-Wan Kenobi discovers a secret clone army crafted for the Jedi.', 'https://m.media-amazon.com/images/M/MV5BNTgxMjY2YzUtZmVmNC00YjAwLWJlODMtNDBhNzllNzIzMjgxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ewan McGregor, Natalie Portman, Hayden Christensen, Christopher Lee, Samuel L. Jackson, Frank Oz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5388, 'Insomnia', 'Action,Crime,Drama,Mystery,Thriller', 2002, 'Christopher Nolan', 'A Los Angeles detective chases a murder suspect in a remote Alaskan town.', 'https://m.media-amazon.com/images/M/MV5BOTE2NzQ0MzQtMDRmZi00ZWRiLWE4MDEtY2M1Mjc3OGY5N2JkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Al Pacino, Martin Donovan, Oliver \'Ole\' Zemen, Hilary Swank, Paul Dooley, Nicky Katt', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5418, 'Bourne Identity, The', 'Action,Mystery,Thriller', 2002, 'Doug Liman', 'A man is picked up by a fishing boat, bullet-riddled and suffering from amnesia, before racing to elude assassins and attempting to regain his memory.', 'https://m.media-amazon.com/images/M/MV5BYTk1ZTcyMWMtMWUxYS00MmEzLTlmODYtOTk1MGRjOTg1ZjlmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matt Damon, Franka Potente, Chris Cooper, Clive Owen, Brian Cox, Adewale Akinnuoye-Agbaje', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5419, 'Scooby-Doo', 'Adventure,Children,Comedy,Fantasy,Mystery', 2002, 'Raja Gosnell', 'After an acrimonious break up, the Mystery Inc. gang are individually brought to an island resort to investigate strange goings on.', 'https://m.media-amazon.com/images/M/MV5BMTg4MzMzMTY0OF5BMl5BanBnXkFtZTYwNzM3MTg2._V1_FMjpg_UX1000_.jpg', 'Freddie Prinze Jr., Sarah Michelle Gellar, Matthew Lillard, Linda Cardellini, Rowan Atkinson, Isla Fisher', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5444, 'Lilo & Stitch', 'Adventure,Animation,Children,Sci-Fi', 2002, 'Dean DeBlois', 'A young and parentless girl adopts a \'dog\' from the local pound, completely unaware that it\'s supposedly a dangerous scientific experiment that\'s taken refuge on Earth and is now hiding from its creator and those who see it as a menace.', 'https://m.media-amazon.com/images/M/MV5BYzRiYTA1YTEtMjYwMi00NGVhLThkOGYtZDBlYjNjZDk2NDEwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Daveigh Chase, Chris Sanders, Tia Carrere, David Ogden Stiers, Kevin McDonald, Ving Rhames', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5445, 'Minority Report', 'Action,Crime,Mystery,Sci-Fi,Thriller', 2002, 'Steven Spielberg', 'John works with the PreCrime police which stop crimes before they take place, with the help of three \'PreCogs\' who can foresee crimes. Events ensue when John finds himself framed for a future murder.', 'https://m.media-amazon.com/images/M/MV5BYTdmNzM3YzItZTRkYS00MTY5LTg4ZmItNjFmNTk2N2Q2NmNlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Max von Sydow, Steve Harris, Neal McDonough, Patrick Kilpatrick, Jessica Capshaw', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5459, 'Men in Black II (a.k.a. MIIB) (a.k.a. MIB 2)', 'Action,Comedy,Sci-Fi', 2002, 'Barry Sonnenfeld', 'Agent J is sent to find Agent K and restore his memory after the re-appearance of a case from K\'s past.', 'https://m.media-amazon.com/images/M/MV5BMTMxNDA0NTMxMV5BMl5BanBnXkFtZTYwMDE2NzY2._V1_FMjpg_UX1000_.jpg', 'Tommy Lee Jones, Will Smith, Rip Torn, Lara Flynn Boyle, Johnny Knoxville, Rosario Dawson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5464, 'Road to Perdition', 'Crime,Drama', 2002, 'Sam Mendes', 'A mob enforcer\'s son in 1930s Illinois witnesses a murder, forcing him and his father to take to the road, and his father down a path of redemption and revenge.', 'https://m.media-amazon.com/images/M/MV5BMjMyYjMyMzktMjlhZC00ZTZkLTkzMWQtZmEwMjdjNzJkM2RlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tyler Hoechlin, Rob Maxey, Liam Aiken, Jennifer Jason Leigh, Tom Hanks, Paul Newman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5481, 'Austin Powers in Goldmember', 'Comedy', 2002, 'Jay Roach', 'Upon learning that his father has been kidnapped, Austin Powers must travel to 1975 and defeat the aptly named villain Goldmember, who is working with Dr. Evil.', 'https://m.media-amazon.com/images/M/MV5BYTUwYjI0YzctMGI5Yy00NGU5LTgwMGUtMzE1OWZhYmRlMjMyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mike Myers, Beyoncé, Seth Green, Michael York, Robert Wagner, Mindy Sterling', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5502, 'Signs', 'Horror,Sci-Fi,Thriller', 2002, 'M. Night Shyamalan', 'A widowed former reverend living with his children and brother on a Pennsylvania farm finds mysterious crop circles in their fields, which suggests something more frightening to come.', 'https://m.media-amazon.com/images/M/MV5BNDUwMDUyMDAyNF5BMl5BanBnXkFtZTYwMDQ3NzM3._V1_FMjpg_UX1000_.jpg', 'Mel Gibson, Joaquin Phoenix, Rory Culkin, Abigail Breslin, Cherry Jones, M. Night Shyamalan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5528, 'One Hour Photo', 'Drama,Thriller', 2002, 'Mark Romanek', 'A mentally unstable photo developer targets an upper middle-class family after his obsession with them becomes more sick and disturbing than any of them could imagine.', 'https://m.media-amazon.com/images/M/MV5BNzZhYTZmMjYtNTg0Yy00NDhiLWIwMmItOTU1YmZhYWFiNWEzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robin Williams, Connie Nielsen, Michael Vartan, Dylan Smith, Erin Daniels, Paul Kim Jr.', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5574, 'Transporter, The', 'Action,Crime', 2002, 'Louis Leterrier', 'Frank Martin, who \"transports\" packages for unknown clients, is asked to move a package that soon begins moving, and complications arise.', 'https://m.media-amazon.com/images/M/MV5BMTk2NDc2MDAxN15BMl5BanBnXkFtZTYwNDc1NDY2._V1_FMjpg_UX1000_.jpg', 'Jason Statham, Shu Qi, François Berléand, Matt Schulze, Ric Young, Doug Rand', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5577, 'Igby Goes Down', 'Comedy,Drama', 2002, 'Burr Steers', 'A young man\'s peculiar upbringing renders him unable to competently cope with the struggle of growing up.', 'https://m.media-amazon.com/images/M/MV5BY2ExYWY0ZTEtYWNmZC00ZmYwLWE4MzQtYmNmYWU2OWI5MTY3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kieran Culkin, Claire Danes, Jeff Goldblum, Jared Harris, Amanda Peet, Ryan Phillippe', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5608, 'Das Experiment (Experiment, The)', 'Drama,Thriller', 2001, 'Oliver Hirschbiegel', 'For two weeks, 20 male participants are hired to play prisoners and guards in a prison. The \"prisoners\" have to follow seemingly mild rules, and the \"guards\" are told to retain order without using physical violence.', 'https://m.media-amazon.com/images/M/MV5BMGZlYzlkMjctN2U5Zi00OTQ1LTk2ZGMtYzMzYzYwMTY4MzFkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Moritz Bleibtreu, Christian Berkel, Oliver Stokowski, Wotan Wilke Möhring, Stephan Szasz, Polat Dal', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5618, 'Spirited Away (Sen to Chihiro no kamikakushi)', 'Adventure,Animation,Fantasy', 2001, 'Hayao Miyazaki', 'During her family\'s move to the suburbs, a sullen 10-year-old girl wanders into a world ruled by gods, witches and spirits, and where humans are changed into beasts.', 'https://m.media-amazon.com/images/M/MV5BNTEyNmEwOWUtYzkyOC00ZTQ4LTllZmUtMjk0Y2YwOGUzYjRiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Rumi Hiiragi, Miyu Irino, Mari Natsuki, Takashi Naitô, Yasuko Sawaguchi, Tatsuya Gashûin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5669, 'Bowling for Columbine', 'Documentary', 2002, 'Michael Moore', 'Filmmaker Michael Moore explores the roots of America\'s predilection for gun violence.', 'https://m.media-amazon.com/images/M/MV5BNTNlYzY3NDEtNDk4OC00MzJjLWJmNWUtZTJjMTAzMTA1NWI1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Moore, Salvador Allende, Jacobo Árbenz, Mike Bradley, Arthur A. Busch, George Bush', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5679, 'Ring, The', 'Horror,Mystery,Thriller', 2002, 'Gore Verbinski', 'A journalist must investigate a mysterious videotape which seems to cause the death of anyone one week to the day after they view it.', 'https://m.media-amazon.com/images/M/MV5BNDA2NTg2NjE4Ml5BMl5BanBnXkFtZTYwMjYxMDg5._V1_FMjpg_UX1000_.jpg', 'Naomi Watts, Martin Henderson, David Dorfman, Brian Cox, Jane Alexander, Lindsay Frost', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5784, 'Ghost Ship', 'Horror', 2002, 'Steve Beck', 'A salvage crew discovers a long-lost 1962 passenger ship floating lifeless in a remote region of the Bering Sea, and soon notices that its long-dead inhabitants may still be on board.', 'https://m.media-amazon.com/images/M/MV5BMTM3NTA4NDIwMF5BMl5BanBnXkFtZTYwNTc4NDE3._V1_FMjpg_UX1000_.jpg', 'Gabriel Byrne, Julianna Margulies, Ron Eldard, Desmond Harrington, Isaiah Washington, Alex Dimitriades', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5810, '8 Mile', 'Drama', 2002, 'Curtis Hanson', 'Follows a young rapper in the Detroit area, struggling with every aspect of his life; he wants to make it big but his friends and foes make this odyssey of rap harder than it may seem.', 'https://m.media-amazon.com/images/M/MV5BMzFhZDhjMDAtZWJlZS00ZWUyLWFlZGMtYTcwZjFlODcyMGE2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Eminem, Kim Basinger, Mekhi Phifer, Brittany Murphy, Evan Jones, Omar Benson Miller', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5816, 'Harry Potter and the Chamber of Secrets', 'Adventure,Fantasy', 2002, 'Chris Columbus', 'Harry Potter lives his second year at Hogwarts with Ron and Hermione when a message on the wall announces that the legendary Chamber of Secrets has been opened. The trio soon realize that, to save the school, it will take a lot of courage.', 'https://m.media-amazon.com/images/M/MV5BNGJhM2M2MWYtZjIzMC00MDZmLThkY2EtOWViMDhhYjRhMzk4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Daniel Radcliffe, Rupert Grint, Emma Watson, Richard Griffiths, Fiona Shaw, Harry Melling', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5902, 'Adaptation', 'Comedy,Drama,Romance', 2002, 'Spike Jonze', 'A lovelorn screenwriter becomes desperate as he tries and fails to adapt \'The Orchid Thief\' by Susan Orlean for the screen.', 'https://m.media-amazon.com/images/M/MV5BMmQ1MWMxZjEtNmNmYi00ZGFhLWExZDItODcwNzlmZjg0YzNlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nicolas Cage, Tilda Swinton, Meryl Streep, Chris Cooper, Jay Tavare, Litefoot', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5903, 'Equilibrium', 'Action,Sci-Fi,Thriller', 2002, 'Kurt Wimmer', 'In an oppressive future where all forms of feeling are illegal, a man in charge of enforcing the law rises to overthrow the system and state.', 'https://m.media-amazon.com/images/M/MV5BMTkzMzA1OTI3N15BMl5BanBnXkFtZTYwMzUyMDg5._V1_FMjpg_UX1000_.jpg', 'Dominic Purcell, Christian Bale, Sean Bean, Christian Kahrmann, John Keogh, Sean Pertwee', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5945, 'About Schmidt', 'Comedy,Drama', 2002, 'Alexander Payne', 'Newly retired from the insurance industry, Omaha native Warren Schmidt embarks on an RV journey to his estranged daughter Jeannie\'s wedding in Denver Colorado, only to discover more about himself and life than he ever expected.', 'https://m.media-amazon.com/images/M/MV5BMTg3ODY2ODM3OF5BMl5BanBnXkFtZTYwOTQ5NTM3._V1_FMjpg_UX1000_.jpg', 'Jack Nicholson, Kathy Bates, Hope Davis, Dermot Mulroney, June Squibb, Howard Hesseman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5952, 'Lord of the Rings: The Two Towers, The', 'Adventure,Fantasy', 2002, 'Peter Jackson', 'While Frodo and Sam edge closer to Mordor with the help of the shifty Gollum, the divided fellowship makes a stand against Sauron\'s new ally, Saruman, and his hordes of Isengard.', 'https://m.media-amazon.com/images/M/MV5BMGQxMDdiOWUtYjc1Ni00YzM1LWE2NjMtZTg3Y2JkMjEzMTJjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bruce Allpress, Sean Astin, John Bach, Sala Baker, Cate Blanchett, Orlando Bloom', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5954, '25th Hour', 'Crime,Drama', 2002, 'Spike Lee', 'Cornered by the DEA, convicted New York drug dealer Montgomery Brogan reevaluates his life in the 24 remaining hours before facing a seven-year jail term.', 'https://m.media-amazon.com/images/M/MV5BMjg0OWI0ZjktZTM0My00NmI3LTkzNDEtYzJiODE1ODM0MDk3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Edward Norton, Philip Seymour Hoffman, Barry Pepper, Rosario Dawson, Anna Paquin, Brian Cox', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5956, 'Gangs of New York', 'Crime,Drama', 2002, 'Martin Scorsese', 'In 1862, Amsterdam Vallon returns to the Five Points area of New York City seeking revenge against Bill the Butcher; his father\'s killer.', 'https://m.media-amazon.com/images/M/MV5BMTQ0MDA0MTUtYzkzMi00NDY3LThhZDEtNGM4MWUwYzMyZDk5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Daniel Day-Lewis, Cameron Diaz, Jim Broadbent, John C. Reilly, Henry Thomas', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5971, 'My Neighbor Totoro (Tonari no Totoro)', 'Animation,Children,Drama,Fantasy', 1988, 'Hayao Miyazaki', 'When two girls move to the country to be near their ailing mother, they have adventures with the wondrous forest spirits who live nearby.', 'https://m.media-amazon.com/images/M/MV5BYWM3MDE3YjEtMzIzZC00ODE5LTgxNTItNmUyMTBkM2M2NmNiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Noriko Hidaka, Chika Sakamoto, Shigesato Itoi, Sumi Shimamoto, Tanie Kitabayashi, Hitoshi Takagi', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5989, 'Catch Me If You Can', 'Crime,Drama', 2002, 'Steven Spielberg', 'Barely 17 yet, Frank is a skilled forger who has passed as a doctor, lawyer and pilot. FBI agent Carl becomes obsessed with tracking down the con man, who only revels in the pursuit.', 'https://m.media-amazon.com/images/M/MV5BMTY5MzYzNjc5NV5BMl5BanBnXkFtZTYwNTUyNTc2._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Tom Hanks, Christopher Walken, Martin Sheen, Nathalie Baye, Amy Adams', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5992, 'Hours, The', 'Drama,Romance', 2002, 'Stephen Daldry', 'The story of how the novel \"Mrs. Dalloway\" affects three generations of women, all of whom, in one way or another, have had to deal with suicide in their lives.', 'https://m.media-amazon.com/images/M/MV5BODA0ZWVkZTktZDk3Ny00MTcwLWJhZTYtMTA3N2U2OTBiYzQ3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nicole Kidman, Julianne Moore, Meryl Streep, Stephen Dillane, Miranda Richardson, George Loftus', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (5995, 'Pianist, The', 'Drama,War', 2002, 'Roman Polanski', 'During WWII, acclaimed Polish musician Wladyslaw faces various struggles as he loses contact with his family. As the situation worsens, he hides in the ruins of Warsaw in order to survive.', 'https://m.media-amazon.com/images/M/MV5BMjEwNmEwYjgtNTk3ZC00NjljLTg5ZDctZTY3ZGQwZjRkZmQxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Adrien Brody, Emilia Fox, Michal Zebrowski, Ed Stoppard, Maureen Lipman, Frank Finlay', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6016, 'City of God (Cidade de Deus)', 'Action,Adventure,Crime,Drama,Thriller', 2002, 'Kátia Lund', 'In the slums of Rio, two kids\' paths diverge as one struggles to become a photographer and the other a kingpin.', 'https://m.media-amazon.com/images/M/MV5BYjY4NGI5OTUtY2ZlZS00Zjk4LTk5N2MtN2JmYWVjNGNmMGRlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Alexandre Rodrigues, Leandro Firmino, Phellipe Haagensen, Douglas Silva, Jonathan Haagensen, Matheus Nachtergaele', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6058, 'Final Destination 2', 'Horror,Thriller', 2003, 'David R. Ellis', 'Death is stalking Kimberly Corman and multiple survivors of a deadly highway accident.', 'https://m.media-amazon.com/images/M/MV5BMjExMTMyODAzN15BMl5BanBnXkFtZTYwNjc5NDQ3._V1_FMjpg_UX1000_.jpg', 'Ali Larter, A.J. Cook, Michael Landes, David Paetkau, James Kirk, Lynda Boyd', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6059, 'Recruit, The', 'Action,Thriller', 2003, 'Roger Donaldson', 'A brilliant young CIA trainee is asked by his mentor to help find a mole in the Agency.', 'https://m.media-amazon.com/images/M/MV5BMjE5MDMzOTk3MV5BMl5BanBnXkFtZTYwNTE0NTg2._V1_FMjpg_UX1000_.jpg', 'Al Pacino, Colin Farrell, Bridget Moynahan, Gabriel Macht, Kenneth Mitchell, Mike Realba', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6187, 'Life of David Gale, The', 'Crime,Drama,Thriller', 2003, 'Alan Parker', 'A man against capital punishment is accused of murdering a fellow activist and is sent to death row.', 'https://m.media-amazon.com/images/M/MV5BMTAxMzU0NTgxNzZeQTJeQWpwZ15BbWU2MDQzNDkxNw@@._V1_FMjpg_UX1000_.jpg', 'Kate Winslet, Cleo King, Constance Jones, Kevin Spacey, Laura Linney, Lee Ritchey', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6218, 'Bend It Like Beckham', 'Comedy,Drama,Romance', 2002, 'Gurinder Chadha', 'Jess Bhamra dreams of playing professional football, but her Sikh parents have plans for her: a law degree and a marriage. Jules, a white female striker, spots Jess playing football and invites her to join the local women\'s team.', 'https://m.media-amazon.com/images/M/MV5BYjI3NGNmNjktOTBmYy00MDNlLWE2NTYtNzQ2ZDcwMDNlYzY5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Parminder Nagra, Keira Knightley, Jonathan Rhys Meyers, Anupam Kher, Archie Panjabi, Shaznay Lewis', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6281, 'Phone Booth', 'Drama,Thriller', 2002, 'Joel Schumacher', 'Publicist Stuart Shepard finds himself trapped in a phone booth, pinned down by an extortionist\'s sniper rifle. Unable to leave or receive outside help, Stuart\'s negotiation with the caller leads to a jaw-dropping climax.', 'https://m.media-amazon.com/images/M/MV5BYjJhYTNhYmEtODcyOS00ZGEwLWEwZTYtNzlkMmY0MjQ1OWQwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Colin Farrell, Kiefer Sutherland, Forest Whitaker, Radha Mitchell, Katie Holmes, Paula Jai Parker', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6286, 'Man Without a Past, The (Mies vailla menneisyyttä)', 'Comedy,Crime,Drama', 2002, 'Aki Kaurismäki', 'M arrives in Helsinki only to be viciously attacked by thugs and pronounced dead by medics. He revives but with no memory of his past or his identity. He rebuilds his life from scratch, but the past inevitably catches up with him.', 'https://m.media-amazon.com/images/M/MV5BYWRiNmQ5N2EtOWY2MC00Zjc2LTlmZGMtOTY0ZDE3ZTk2NWZmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Markku Peltola, Kati Outinen, Juhani Niemelä, Kaija Pakarinen, Sakari Kuosmanen, Annikki Tähti', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6297, 'Holes', 'Adventure,Children,Comedy,Mystery', 2003, 'Andrew Davis', 'A wrongfully convicted boy is sent to a brutal desert detention camp where he joins the job of digging holes for some mysterious reason.', 'https://m.media-amazon.com/images/M/MV5BMTg0MTU5ODkwM15BMl5BanBnXkFtZTYwMzgxNzY3._V1_FMjpg_UX1000_.jpg', 'Sigourney Weaver, Jon Voight, Tim Blake Nelson, Shia LaBeouf, Khleo Thomas, Jake M. Smith', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6323, 'Identity', 'Crime,Horror,Mystery,Thriller', 2003, 'James Mangold', 'Stranded at a desolate Nevada motel during a nasty rain storm, ten strangers become acquainted with each other when they realize that they\'re being killed off one by one.', 'https://m.media-amazon.com/images/M/MV5BZTg1YWUyODktMWY5MC00ZjliLTg3YmUtZDliMGZhZDZmMzU5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Cusack, Ray Liotta, Amanda Peet, John Hawkes, Alfred Molina, Clea DuVall', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6333, 'X2: X-Men United', 'Action,Adventure,Sci-Fi,Thriller', 2003, 'Bryan Singer', 'When anti-mutant Colonel William Stryker kidnaps Professor X and attacks his school, the X-Men must ally with their archenemy Magneto to stop him.', 'https://m.media-amazon.com/images/M/MV5BNDk0NjYxMzIzOF5BMl5BanBnXkFtZTYwMTc1MjU3._V1_FMjpg_UX1000_.jpg', 'Patrick Stewart, Hugh Jackman, Ian McKellen, Halle Berry, Famke Janssen, James Marsden', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6350, 'Laputa: Castle in the Sky (Tenkû no shiro Rapyuta)', 'Action,Adventure,Animation,Children,Fantasy,Sci-Fi', 1986, 'Hayao Miyazaki', 'Pazu\'s life changes when he meets Sheeta, a girl whom pirates are chasing for her crystal amulet, which has the potential to locate Laputa, a legendary castle floating in the sky.', 'https://m.media-amazon.com/images/M/MV5BZjcyMjg2MzktNjg4YS00MjQzLTg0YWQtMjUyZDk2Y2Y0YzZjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mayumi Tanaka, Keiko Yokozawa, Kotoe Hatsui, Minori Terada, Fujio Tokita, Ichirô Nagai', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6365, 'Matrix Reloaded, The', 'Action,Adventure,Sci-Fi,Thriller,IMAX', 2003, 'Lana Wachowski', 'Freedom fighters Neo, Trinity and Morpheus continue to lead the revolt against the Machine Army, unleashing their arsenal of extraordinary skills and weaponry against the systematic forces of repression and exploitation.', 'https://m.media-amazon.com/images/M/MV5BNjAxYjkxNjktYTU0YS00NjFhLWIyMDEtMzEzMTJjMzRkMzQ1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ray Anthony, Christine Anu, Andy Arness, Alima Ashton-Sheibu, Helmut Bakaitis, Steve Bastoni', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6373, 'Bruce Almighty', 'Comedy,Drama,Fantasy,Romance', 2003, 'Tom Shadyac', 'A whiny news reporter is given the chance to step into God\'s shoes.', 'https://m.media-amazon.com/images/M/MV5BZWM2ZjA2OTctZmRhMy00ZDIzLTkwZGQtYTRlNmQwZWZmMDBlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jim Carrey, Morgan Freeman, Jennifer Aniston, Philip Baker Hall, Catherine Bell, Lisa Ann Walter', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6377, 'Finding Nemo', 'Adventure,Animation,Children,Comedy', 2003, 'Andrew Stanton', 'After his son is captured in the Great Barrier Reef and taken to Sydney, a timid clownfish sets out on a journey to bring him home.', 'https://m.media-amazon.com/images/M/MV5BMTc5NjExNTA5OV5BMl5BanBnXkFtZTYwMTQ0ODY2._V1_FMjpg_UX1000_.jpg', 'Albert Brooks, Ellen DeGeneres, Alexander Gould, Willem Dafoe, Brad Garrett, Allison Janney', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6378, 'Italian Job, The', 'Action,Crime', 2003, 'F. Gary Gray', 'After being betrayed and left for dead in Italy, Charlie Croker and his team plan an elaborate gold heist against their former ally.', 'https://m.media-amazon.com/images/M/MV5BMjJjNzc5YjAtZjU2Ni00ZjVkLTkzYmItM2E2NDM0NWE1YmJhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mark Wahlberg, Charlize Theron, Donald Sutherland, Jason Statham, Seth Green, Yasiin Bey', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6383, '2 Fast 2 Furious (Fast and the Furious 2, The)', 'Action,Crime,Thriller', 2003, 'John Singleton', 'Former cop Brian O\'Conner is called upon to bust a dangerous criminal and he recruits the help of a former childhood friend and street racer who has a chance to redeem himself.', 'https://m.media-amazon.com/images/M/MV5BOTQzYzEwNWMtOTAwYy00YWYwLWE1NTEtZTkxOGQxZTM0M2VhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Paul Walker, Tyrese Gibson, Eva Mendes, Cole Hauser, Ludacris, Thom Barry', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6385, 'Whale Rider', 'Drama', 2002, 'Niki Caro', 'A contemporary story of love, rejection and triumph as a young Maori girl fights to fulfill a destiny her grandfather refuses to recognize.', 'https://m.media-amazon.com/images/M/MV5BMjM3MzE2OTEwNF5BMl5BanBnXkFtZTcwNTkyMTg4NA@@._V1_FMjpg_UX1000_.jpg', 'Keisha Castle-Hughes, Rawiri Paratene, Vicky Haughton, Cliff Curtis, Grant Roa, Mana Taumaunu', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6464, 'Good Burger', 'Children,Comedy', 1997, 'Brian Robbins', 'A dim-witted teenager and his new coworker try to save the old burger joint they work for from failing after the opening of a brand new burger restaurant across the street, which is planning to put them out of business.', 'https://m.media-amazon.com/images/M/MV5BYmZjMGM0OTktZDZhOC00MzJmLTllY2MtMjRmYTk2MGQ3ZmQ2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kel Mitchell, Kenan Thompson, Sinbad, Abe Vigoda, Shar Jackson, Dan Schneider', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6502, '28 Days Later', 'Action,Horror,Sci-Fi', 2002, 'Danny Boyle', 'Four weeks after a mysterious, incurable virus spreads throughout the United Kingdom, a handful of survivors try to find sanctuary.', 'https://m.media-amazon.com/images/M/MV5BM2I4NTI0ZGQtNGQ2ZC00ODIxLWI2N2QtMDBkNzI1NDhjYjE5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Alex Palmer, Bindu De Stoppani, Jukka Hiltunen, David Schneider, Cillian Murphy, Toby Sedgwick', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6539, 'Pirates of the Caribbean: The Curse of the Black Pearl', 'Action,Adventure,Comedy,Fantasy', 2003, 'Gore Verbinski', 'Blacksmith Will Turner teams up with eccentric pirate \"Captain\" Jack Sparrow to save Elizabeth Swann, the governor\'s daughter and his love, from Jack\'s former pirate allies, who are now undead.', 'https://m.media-amazon.com/images/M/MV5BNDhlMzEyNzItMTA5Mi00YWRhLThlNTktYTQyMTA0MDIyNDEyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Geoffrey Rush, Orlando Bloom, Keira Knightley, Jack Davenport, Jonathan Pryce', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6565, 'Seabiscuit', 'Drama', 2003, 'Gary Ross', 'True story of the undersized Depression-era racehorse whose victories lifted not only the spirits of the team behind it but also those of their nation.', 'https://m.media-amazon.com/images/M/MV5BMWExOWJjNmEtMjk3Ny00YjM5LWEwYTctY2ViMTgwMTZkNGM4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'David McCullough, Jeff Bridges, Paul Vincent O\'Connor, Chris Cooper, Michael Ensign, James Keane', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6593, 'Freaky Friday', 'Children,Comedy,Fantasy', 2003, 'Mark Waters', 'Dr. Tess Coleman and her daughter, Anna, do not get along with each other. However, things take a turn when, in a freak accident, they switch bodies and are forced to live each other\'s lives.', 'https://m.media-amazon.com/images/M/MV5BOGNhNDAyZWUtNmU3My00ZWRlLTkwYTgtMzZiYmNjNmM0MzVkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jamie Lee Curtis, Lindsay Lohan, Mark Harmon, Harold Gould, Chad Michael Murray, Stephen Tobolowsky', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6618, 'Shaolin Soccer (Siu lam juk kau)', 'Action,Comedy', 2001, 'Stephen Chow', 'A young Shaolin follower reunites with his discouraged brothers to form a soccer team using their martial art skills to their advantage.', 'https://m.media-amazon.com/images/M/MV5BM2JhYTkzYmUtYjY1Mi00OWNjLTk4N2ItNDRkZTIyMzgyMjMyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Stephen Chow, Man-Tat Ng, Wei Zhao, Yin Tse, Hui Li, Cecilia Cheung', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6711, 'Lost in Translation', 'Comedy,Drama,Romance', 2003, 'Sofia Coppola', 'A fading movie star falls for a lonely young woman in Tokyo.', 'https://m.media-amazon.com/images/M/MV5BMTUxMzk0NDg1MV5BMl5BanBnXkFtZTgwNDg0NjkxMDI@._V1_FMjpg_UX1000_.jpg', 'Scarlett Johansson, Bill Murray, Akiko Takeshita, Kazuyoshi Minamimagoe, Kazuko Shibata, Take', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6754, 'Underworld', 'Action,Fantasy,Horror', 2003, 'Len Wiseman', 'Selene, a vampire warrior, is entrenched in a conflict between vampires and werewolves, while falling in love with Michael, a human who is sought by werewolves for unknown reasons.', 'https://m.media-amazon.com/images/M/MV5BOWIwZjFkYjktZTI3My00YzhkLWI5NmUtZDYyMTg5ZWVmODZkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kate Beckinsale, Scott Speedman, Michael Sheen, Shane Brolly, Bill Nighy, Erwin Leder', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6773, 'Triplets of Belleville, The (Les triplettes de Belleville)', 'Animation,Comedy,Fantasy', 2003, 'Sylvain Chomet', 'When her grandson is kidnapped during the Tour de France, Madame Souza and her beloved pooch Bruno team up with the Belleville Sisters--an aged song-and-dance team from the days of Fred Astaire--to rescue him.', 'https://m.media-amazon.com/images/M/MV5BNGJhNjk2NjctZDdlOC00ZjUxLTljNGItMjI5MTBlZDc1NjViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jean-Claude Donda, Dirk Denoyelle, Monica Viegas, Graziellia de Villa, Michel Robin, Noël Baye', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6863, 'School of Rock', 'Comedy,Musical', 2003, 'Richard Linklater', 'After being kicked out of his rock band, Dewey Finn becomes a substitute teacher of an uptight elementary private school, only to try and turn his class into a rock band.', 'https://m.media-amazon.com/images/M/MV5BOTg2NDU4Mjg2NV5BMl5BanBnXkFtZTgwNjQ0MDIyMDI@._V1_FMjpg_UX1000_.jpg', 'Jack Black, Adam Pascal, Lucas Papaelias, Chris Stack, Sarah Silverman, Mike White', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6870, 'Mystic River', 'Crime,Drama,Mystery', 2003, 'Clint Eastwood', 'The tragic murder of a 19-year-old girl reunites three childhood friends still living in Boston--the victim\'s gangster father, a detective, and the disturbed man they both suspect of killing her.', 'https://m.media-amazon.com/images/M/MV5BMTIzNDUyMjA4MV5BMl5BanBnXkFtZTYwNDc4ODM3._V1_FMjpg_UX1000_.jpg', 'Sean Penn, Tim Robbins, Kevin Bacon, Laurence Fishburne, Marcia Gay Harden, Laura Linney', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6874, 'Kill Bill: Vol. 1', 'Action,Crime,Thriller', 2003, 'Quentin Tarantino', 'After waking from a four-year coma, a former assassin wreaks vengeance on the team of assassins who betrayed her.', 'https://m.media-amazon.com/images/M/MV5BZmMyYzJlZmYtY2I3NC00NjAyLTkyZWItZjdjZDI1YTYyYTEwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Uma Thurman, Lucy Liu, Vivica A. Fox, Daryl Hannah, David Carradine, Michael Madsen', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6887, 'Radio', 'Drama', 2003, 'Michael Tollin', 'The story of a high school coach and the developmentally challenged man who he took under his wing.', 'https://m.media-amazon.com/images/M/MV5BMzEyOTBiNWQtODQ0OS00MmZiLWJmNTEtMGIyMTNlZTcxOThkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cuba Gooding Jr., Ed Harris, Alfre Woodard, S. Epatha Merkerson, Brent Sexton, Chris Mulkey', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6890, 'Elephant', 'Drama', 2003, 'Gus Van Sant', 'Several ordinary high school students go through their daily routine as two others prepare for something more malevolent.', 'https://m.media-amazon.com/images/M/MV5BMTIwZjA2OGYtNmYyMS00MjJjLWIxYTEtOTEyMTZjMGYzMTM2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Alex Frost, Eric Deulen, John Robinson, Elias McConnell, Jordan Taylor, Carrie Finn', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6934, 'Matrix Revolutions, The', 'Action,Adventure,Sci-Fi,Thriller,IMAX', 2003, 'Lana Wachowski', 'The human city of Zion defends itself against the massive invasion of the machines as Neo fights to end the war at another front while also opposing the rogue Agent Smith.', 'https://m.media-amazon.com/images/M/MV5BMmNmMTEzODQtNmExMS00OGUxLWFkNTItMTM3NzBlNDk0YWU5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mary Alice, Tanveer K. Atwal, Helmut Bakaitis, Kate Beahan, Francine Bell, Monica Bellucci', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6936, 'Elf', 'Children,Comedy,Fantasy', 2003, 'Jon Favreau', 'Raised as an oversized elf, Buddy travels from the North Pole to New York City to meet his biological father, Walter Hobbs, who doesn\'t know he exists and is in desperate need of some Christmas spirit.', 'https://m.media-amazon.com/images/M/MV5BNDQ0ZWE2NzgtNGNhMC00MDIwLWI1MjUtYjYxZGRiM2UyYTQzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Will Ferrell, James Caan, Bob Newhart, Edward Asner, Mary Steenburgen, Zooey Deschanel', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6942, 'Love Actually', 'Comedy,Drama,Romance', 2003, 'Richard Curtis', 'Follows the lives of eight very different couples in dealing with their love lives in various loosely interrelated tales all set during a frantic month before Christmas in London, England.', 'https://m.media-amazon.com/images/M/MV5BYWRlZjcwYTgtYWJkOS00MGYwLTk3Y2ItNmU4NTg5Nzg2YTQ2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bill Nighy, Gregor Fisher, Rory MacGregor, Colin Firth, Sienna Guillory, Liam Neeson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6944, 'Father of the Bride', 'Comedy', 1991, 'Charles Shyer', 'With his oldest daughter\'s wedding approaching, a father finds himself reluctant to let go.', 'https://m.media-amazon.com/images/M/MV5BOGRiZjliMTktMzhjMi00MjUyLWE0OTQtYjUzYzZmNzg2NjQ3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Steve Martin, Diane Keaton, Kimberly Williams-Paisley, Kieran Culkin, George Newbern, Martin Short', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6947, 'Master and Commander: The Far Side of the World', 'Adventure,Drama,War', 2003, 'Peter Weir', 'During the Napoleonic Wars, a brash British captain pushes his ship and crew to their limits in pursuit of a formidable French war vessel around South America.', 'https://m.media-amazon.com/images/M/MV5BZDEzYmZmOTYtMzdlYS00MWNjLWE2YjEtMzkyZTMyOWZjMjkyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Russell Crowe, Paul Bettany, James D\'Arcy, Edward Woodall, Chris Larkin, Max Pirkis', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6953, '21 Grams', 'Crime,Drama,Mystery,Romance,Thriller', 2003, 'Alejandro G. Iñárritu', 'A freak accident brings together a critically ill mathematician, a grieving mother, and a born-again ex-con.', 'https://m.media-amazon.com/images/M/MV5BMjA4MjI2OTM5N15BMl5BanBnXkFtZTcwNDA1NjUzMw@@._V1_FMjpg_UX1000_.jpg', 'Sean Penn, Naomi Watts, Danny Huston, Carly Nahon, Claire Pakis, Benicio Del Toro', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (6979, 'WarGames', 'Drama,Sci-Fi,Thriller', 1983, 'John Badham', 'A young man finds a back door into a military central computer in which reality is confused with game-playing, possibly starting World War III.', 'https://m.media-amazon.com/images/M/MV5BMmM5MDlmZWUtYTE1Mi00M2JiLTk1NzYtMTg0NTdlMzM2N2RkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matthew Broderick, Dabney Coleman, John Wood, Ally Sheedy, Barry Corbin, Juanin Clay', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (7040, 'To Live and Die in L.A.', 'Action,Crime,Drama,Thriller', 1985, 'William Friedkin', 'A fearless Secret Service agent will stop at nothing to bring down the counterfeiter who killed his partner.', 'https://m.media-amazon.com/images/M/MV5BYjk1ODQ4NTgtNjAyZi00NjMyLTg4MzktOWQ3YTU3N2MxMTdlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'William Petersen, Willem Dafoe, John Pankow, Debra Feuer, John Turturro, Darlanne Fluegel', '2025-11-24 12:30:38');
