INSERT INTO `movies` VALUES (7137, 'Cooler, The', 'Comedy,Drama,Romance', 2003, 'Wayne Kramer', 'In an old school Las Vegas casino, its top gambling jinx breaks his curse when he falls in love, much to his boss\' consternation.', 'https://m.media-amazon.com/images/M/MV5BMjUwMTgyN2UtMGI2OS00NDFjLTk1MjQtYTJmMDQwNGYyYzU1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'William H. Macy, Alec Baldwin, Maria Bello, Shawn Hatosy, Ron Livingston, Paul Sorvino', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (7143, 'Last Samurai, The', 'Action,Adventure,Drama,War', 2003, 'Edward Zwick', 'In 19th century Japan, Nathan Algren, a US army captain, is hired by the Japanese emperor to train his army in the modern warfare techniques. Captain Algren finds himself trapped in a struggle between two eras and two worlds.', 'https://m.media-amazon.com/images/M/MV5BMzkyNzQ1Mzc0NV5BMl5BanBnXkFtZTcwODg3MzUzMw@@._V1_FMjpg_UX1000_.jpg', 'Ken Watanabe, Tom Cruise, William Atherton, Chad Lindberg, Ray Godshall Sr., Billy Connolly', '2025-11-24 12:30:38');
