INSERT INTO `movies` VALUES (7153, 'Lord of the Rings: The Return of the King, The', 'Action,Adventure,Drama,Fantasy', 2003, 'Peter Jackson', 'Gandalf and Aragorn lead the World of Men against Sauron\'s army to draw his gaze from Frodo and Sam as they approach Mount Doom with the One Ring.', 'https://m.media-amazon.com/images/M/MV5BMTZkMjBjNWMtZGI5OC00MGU0LTk4ZTItODg2NWM3NTVmNWQ4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Noel Appleby, Ali Astin, Sean Astin, David Aston, John Bach, Sean Bean', '2025-11-24 12:30:38');
