INSERT INTO `movies` VALUES (8798, 'Collateral', 'Action,Crime,Drama,Thriller', 2004, 'Michael Mann', 'A cab driver finds himself the hostage of an engaging contract killer as he makes his rounds from hit to hit during one night in Los Angeles.', 'https://m.media-amazon.com/images/M/MV5BMjE3NjM5OTMxMV5BMl5BanBnXkFtZTcwOTIzMTQyMw@@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Jamie Foxx, Jada Pinkett Smith, Mark Ruffalo, Peter Berg, Bruce McGill', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8800, 'Code 46', 'Romance,Sci-Fi', 2003, 'Michael Winterbottom', 'A futuristic Brief Encounter (1945), this is a love story in which the romance is doomed by genetic incompatibility.', 'https://m.media-amazon.com/images/M/MV5BOWVhMWEwMTMtYTgzZi00NjAyLWE3YTktNjhiYzU2ZmMzZDZkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tim Robbins, Togo Igawa, Nabil Elouahabi, Samantha Morton, Sarah Backhouse, Jonathan Ibbotson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8807, 'Harold and Kumar Go to White Castle', 'Adventure,Comedy', 2004, 'Danny Leiner', 'A Korean-American office worker and his Indian-American stoner friend embark on a quest to satisfy their desire for White Castle burgers.', 'https://m.media-amazon.com/images/M/MV5BNjk2MGI0M2YtZmIwOS00NGVjLWFlNDAtMDYzM2Y1MWM2OWNkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Cho, Ethan Embry, Rob Tinkler, Fred Willard, Kal Penn, Steve Braun', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8874, 'Shaun of the Dead', 'Comedy,Horror', 2004, 'Edgar Wright', 'The uneventful, aimless lives of a London electronics salesman and his layabout roommate are disrupted by the zombie apocalypse.', 'https://m.media-amazon.com/images/M/MV5BNzNjZGE4YTUtOWU3OC00Mzg2LThjNWItMzUwYzEwMDgxYmVjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Simon Pegg, Kate Ashfield, Nick Frost, Lucy Davis, Dylan Moran, Nicola Cunningham', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8898, 'Robinson Crusoe (Adventures of Robinson Crusoe, The)', 'Adventure,Drama', 1954, 'Luis Buñuel', 'The classic story of Robinson Crusoe, a man who is dragged to a desert island after a shipwreck.', 'https://m.media-amazon.com/images/M/MV5BZTY3ZThhMjItODJmMi00ZGZhLWI2NjQtNjkxMDY4OWJiMTY4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dan O\'Herlihy, Jaime Fernández, Felipe de Alba, Chel López, José Chávez, Emilio Garibay', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8907, 'Shark Tale', 'Animation,Children,Comedy', 2004, 'Bibo Bergeron', 'When a son of a gangster shark boss is accidentally killed while on the hunt, his would-be prey and his vegetarian brother decide to use the incident to their own advantage.', 'https://m.media-amazon.com/images/M/MV5BMTMxMjY0NzE2M15BMl5BanBnXkFtZTcwNTc3ODcyMw@@._V1_FMjpg_UX1000_.jpg', 'Will Smith, Robert De Niro, Renée Zellweger, Jack Black, Angelina Jolie, Martin Scorsese', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8910, 'I Heart Huckabees', 'Comedy', 2004, 'David O. Russell', 'A husband-and-wife team play detective, but not in the traditional sense. Instead, the happy duo helps others solve their existential issues, the kind that keep you up at night, wondering what it all means.', 'https://m.media-amazon.com/images/M/MV5BYzc2Nzk0ODktZTZiNy00NmE5LTliNDItNTRkYWU5YTdlYTBhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jason Schwartzman, Isabelle Huppert, Dustin Hoffman, Lily Tomlin, Jude Law, Mark Wahlberg', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8914, 'Primer', 'Drama,Sci-Fi', 2004, 'Shane Carruth', 'Four friends/fledgling entrepreneurs, knowing that there\'s something bigger and more innovative than the different error-checking devices they\'ve built, wrestle over their new invention.', 'https://m.media-amazon.com/images/M/MV5BZTRmZDlmNzUtNjM2NS00MjBjLWFmNjQtMTczMWNkZTdiOGZmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Shane Carruth, David Sullivan, Casey Gooden, Anand Upadhyaya, Carrie Crawford, Jay Butler', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8915, 'Stage Beauty', 'Drama', 2004, 'Richard Eyre', 'A female theatre dresser creates a stir and sparks a revolution in seventeenth century London theatre by playing Desdemona in Othello. But what will become of the male actor she once worked for and eventually replaced?', 'https://m.media-amazon.com/images/M/MV5BN2Q2YjllYzMtNjdkNS00ODU0LWE0YjAtY2M1NDIyYzAzMmEzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Derek Hutchinson, Mark Letheren, Claire Danes, Billy Crudup, Tom Wilkinson, Ben Chaplin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8917, 'Team America: World Police', 'Action,Adventure,Animation,Comedy', 2004, 'Trey Parker', 'Popular Broadway actor Gary Johnston is recruited by the elite counter-terrorism organization Team America: World Police. As the world begins to crumble around him, he must battle with terrorists, celebrities and falling in love.', 'https://m.media-amazon.com/images/M/MV5BMTM2Nzc4NjYxMV5BMl5BanBnXkFtZTcwNTM1MTcyMQ@@._V1_FMjpg_UX1000_.jpg', 'Trey Parker, Matt Stone, Kristen Miller, Masasa Moyo, Daran Norris, Phil Hendrie', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8949, 'Sideways', 'Comedy,Drama,Romance', 2004, 'Alexander Payne', 'Two men reaching middle age with not much to show but disappointment embark on a week-long road trip through California\'s wine country, just as one is about to take a trip down the aisle.', 'https://m.media-amazon.com/images/M/MV5BMTU0Mjg3MzkxOV5BMl5BanBnXkFtZTYwNDU1OTY3._V1_FMjpg_UX1000_.jpg', 'Paul Giamatti, Thomas Haden Church, Virginia Madsen, Sandra Oh, Marylouise Burke, Jessica Hecht', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8950, 'The Machinist', 'Drama,Mystery,Thriller', 2004, 'Brad Anderson', 'An industrial worker who hasn\'t slept in a year begins to doubt his own sanity.', 'https://m.media-amazon.com/images/M/MV5BY2I1MmUxYmMtZjk3OC00N2MwLWI2YjAtNGQxODA1Y2I3YTI4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Christian Bale, Jennifer Jason Leigh, Aitana Sánchez-Gijón, John Sharian, Michael Ironside, Lawrence Gilliard Jr.', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8957, 'Saw', 'Horror,Mystery,Thriller', 2004, 'James Wan', 'Two men awaken to find themselves on the opposite sides of a dead body, each with specific instructions to kill the other, escape or face the consequences. These two are the latest contestants in Jigsaw\'s games.', 'https://m.media-amazon.com/images/M/MV5BZTE5MzFlMTktMzBkOC00ZjMxLThmOTAtOGU3ZGEwZGRlNDdjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leigh Whannell, Cary Elwes, Danny Glover, Ken Leung, Dina Meyer, Mike Butters', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8958, 'Ray', 'Drama', 2004, 'Taylor Hackford', 'The story of the life and career of the legendary rhythm and blues musician Ray Charles, from his humble beginnings in the South, where he went blind at age seven, to his meteoric rise to stardom during the 1950s and 1960s.', 'https://m.media-amazon.com/images/M/MV5BMTQxNDQwNjQzOV5BMl5BanBnXkFtZTcwNTQxNDYyMQ@@._V1_FMjpg_UX1000_.jpg', 'Jamie Foxx, Kerry Washington, Regina King, Clifton Powell, Harry Lennix, Bokeem Woodbine', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8961, 'Incredibles, The', 'Action,Adventure,Animation,Children,Comedy', 2004, 'Brad Bird', 'While trying to lead a quiet suburban life, a family of undercover superheroes are forced into action to save the world.', 'https://m.media-amazon.com/images/M/MV5BMTY5OTU0OTc2NV5BMl5BanBnXkFtZTcwMzU4MDcyMQ@@._V1_FMjpg_UX1000_.jpg', 'Craig T. Nelson, Holly Hunter, Samuel L. Jackson, Jason Lee, Dominique Louis, Theodore Newton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8967, 'Seed of Chucky (Child\'s Play 5)', 'Comedy,Horror', 2004, 'Don Mancini', 'Chucky and Tiffany are resurrected by their innocent gender-confused child, Glen/Glenda, and hit Hollywood, where a movie depicting the killer dolls\' murder spree is underway.', 'https://m.media-amazon.com/images/M/MV5BMTIwMTczMjc3M15BMl5BanBnXkFtZTcwODcxMzcyMQ@@._V1_FMjpg_UX1000_.jpg', 'Jennifer Tilly, Brad Dourif, Billy Boyd, Redman, Hannah Spearritt, John Waters', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8969, 'Bridget Jones: The Edge of Reason', 'Comedy,Drama,Romance', 2004, 'Beeban Kidron', 'After finding love, Bridget Jones questions if she really has everything she\'d ever dreamed of having.', 'https://m.media-amazon.com/images/M/MV5BOTU1MTM1ZTUtMzcxNy00OTRiLTllNzItN2U3MGQ4YTQzYWE4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Renée Zellweger, Gemma Jones, Jim Broadbent, James Faulkner, Celia Imrie, Dominic McHale', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8970, 'Finding Neverland', 'Drama', 2004, 'Marc Forster', 'The story of Sir J.M. Barrie\'s friendship with a family who inspired him to create Peter Pan.', 'https://m.media-amazon.com/images/M/MV5BZWIyODcyYzYtNTNhMy00MThjLTkxZDgtMTBiOWY3ODkxNzQ1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Kate Winslet, Julie Christie, Radha Mitchell, Dustin Hoffman, Freddie Highmore', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8971, 'Veer Zaara', 'Drama,Musical,Romance', 2004, 'Yash Chopra', 'An Indian Air Force pilot rescues a Pakistani girl stranded in India. Years later, a lawyer seeks to unravel the truth behind the pilot\'s mysterious imprisonment in Pakistan for over two decades, during which he remained silent.', 'https://m.media-amazon.com/images/M/MV5BMmI0ODNhYmEtOWM4My00MmFlLTk4ZmEtYmQ2MmNjODcxNzU2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Shah Rukh Khan, Preity G Zinta, Rani Mukerji, Kirron Kher, Divya Dutta, Boman Irani', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8972, 'National Treasure', 'Action,Adventure,Drama,Mystery,Thriller', 2004, 'Jon Turteltaub', 'A historian races to find the legendary Templar Treasure before a team of mercenaries.', 'https://m.media-amazon.com/images/M/MV5BMTY3NTc4OTYxMF5BMl5BanBnXkFtZTcwMjk5NzUyMw@@._V1_FMjpg_UX1000_.jpg', 'Nicolas Cage, Diane Kruger, Justin Bartha, Sean Bean, Jon Voight, Harvey Keitel', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8983, 'House of Flying Daggers (Shi mian mai fu)', 'Action,Drama,Romance', 2004, 'Yimou Zhang', 'A romantic police captain breaks a beautiful member of a rebel group out of prison to help her rejoin her fellows, but things are not what they seem.', 'https://m.media-amazon.com/images/M/MV5BYWZlZjQwMjUtNGI5Ny00ODg4LTg0Y2UtODkxYmYxM2IxNjgzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Takeshi Kaneshiro, Andy Lau, Ziyi Zhang, Dandan Song, Hongfei Zhao, Jun Guo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (8984, 'Ocean\'s Twelve', 'Action,Comedy,Crime,Thriller', 2004, 'Steven Soderbergh', 'Daniel Ocean recruits one more team member so he can pull off three major European heists in this sequel to Ocean\'s Eleven (2001).', 'https://m.media-amazon.com/images/M/MV5BNjgxNjY3ODEtMTZhOC00NjgyLTg4YTAtZjA4ZDI2MDQ4OGJmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brad Pitt, Catherine Zeta-Jones, George Clooney, Ed Kross, Julia Roberts, Don Tiffany', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (26150, 'Andrei Rublev (Andrey Rublyov)', 'Drama,War', 1969, 'Andrei Tarkovsky', 'The life, times and afflictions of the fifteenth-century Russian iconographer St. Andrei Rublev.', 'https://m.media-amazon.com/images/M/MV5BY2I4YzZjZDgtNWQzNC00MDdhLWFiZTItZTAwODY2ZmQzMDQwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Anatoliy Solonitsyn, Ivan Lapikov, Nikolay Grinko, Nikolay Sergeev, Irma Tarkovskaya, Nikolay Burlyaev', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (26203, 'Colossus: The Forbin Project', 'Sci-Fi,Thriller', 1970, 'Joseph Sargent', 'Thinking this will prevent war, the US government gives an impenetrable supercomputer total control over launching nuclear missiles. But what the computer does with the power is unimaginable to its creators.', 'https://m.media-amazon.com/images/M/MV5BOWU0ZmM3N2QtYzgzOC00MDMyLTk4ZmUtNDdmYTI3ZGM4YjI5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Eric Braeden, Susan Clark, Gordon Pinsent, William Schallert, Leonid Rostoff, Georg Stanford Brown', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (26662, 'Kiki\'s Delivery Service (Majo no takkyûbin)', 'Adventure,Animation,Children,Drama,Fantasy', 1989, 'Hayao Miyazaki', 'Along with her black cat Jiji, Kiki settles in a seaside town and starts a high-flying delivery service. Here begins her magical encounter with independence and responsibility, making lifelong friends and finding her place in the world.', 'https://m.media-amazon.com/images/M/MV5BOTFhYWI1NGUtZWFhZS00MTdkLWIzZTItMDBhNWNiZDNlMjYyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Minami Takayama, Rei Sakuma, Mieko Nobusawa, Keiko Toda, Kappei Yamaguchi, Hiroko Seki', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (26776, 'Porco Rosso (Crimson Pig) (Kurenai no buta)', 'Adventure,Animation,Comedy,Fantasy,Romance', 1992, 'Hayao Miyazaki', 'In 1930s Italy, a veteran World War I pilot is cursed to look like an anthropomorphic pig.', 'https://m.media-amazon.com/images/M/MV5BOGNjMDM1NWEtMzI4OC00YzdlLWJmMjktNmJiYTlkNTNlODM0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Shûichirô Moriyama, Tokiko Katô, Bunshi Katsura VI, Tsunehiko Kamijô, Akemi Okamura, Akio Ôtsuka', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (26903, 'Whisper of the Heart (Mimi wo sumaseba)', 'Animation,Drama,Romance', 1995, 'Yoshifumi Kondô', 'A love story between a girl who loves reading books and a boy who has previously checked out all of the library books she chooses.', 'https://m.media-amazon.com/images/M/MV5BZWVlOGNlYjgtYWE4Yi00MjdiLWE1MTEtZTRmNzI1ODk5NzMzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Yoko Honna, Issei Takahashi, Takashi Tachibana, Shigeru Muroi, Shigeru Tsuyuguchi, Keiju Kobayashi', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (26939, 'Drifting Clouds (Kauas pilvet karkaavat)', 'Comedy,Drama', 1996, 'Aki Kaurismäki', 'The recession hits a couple in Helsinki.', 'https://m.media-amazon.com/images/M/MV5BOGEwYmRkZTUtOWM0Ni00NWFkLTk1NTMtNDRiMGUyNWU1OWZlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kati Outinen, Kari Väänänen, Elina Salo, Sakari Kuosmanen, Markku Peltola, Matti Onnismaa', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (27163, 'Something Is Happening (Kuch Kuch Hota Hai)', 'Comedy,Musical,Romance', 1998, 'Karan Johar', 'During their college years, Anjali was in love with her best-friend Rahul, but he had eyes only for Tina. Years later, Rahul and the now-deceased Tina\'s eight-year-old daughter attempts to reunite her father and Anjali.', 'https://m.media-amazon.com/images/M/MV5BMmQ0ZjliZTgtMjQ3NC00N2NiLTkxNjktY2VkOTQ2N2QyODNkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Shah Rukh Khan, Kajol, Rani Mukerji, Salman Khan, Sana Saeed, Farida Jalal', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (27266, '2046', 'Drama,Fantasy,Romance,Sci-Fi', 2004, 'Wong Kar-Wai', 'Several women enter a science fiction author\'s life over the course of a few years, after the author has lost the woman he considers his one true love.', 'https://m.media-amazon.com/images/M/MV5BNGM2NTQyM2MtODAzMi00NWVjLTgwNWMtYjNkMjMxZmUwOTU3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tony Leung Chiu-wai, Gong Li, Faye Wong, Takuya Kimura, Ziyi Zhang, Carina Lau', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (27434, 'Darkness', 'Horror,Mystery', 2002, 'Jaume Balagueró', 'There\'s something in this house - Something ancient and dark that remains still, hidden and silent. It can only wait, having been concealed in the shadows for years. In fact, its milieu is darkness.', 'https://m.media-amazon.com/images/M/MV5BODc3ODdlMWMtY2M4OS00YWY1LTg1M2ItZWZiYmQ4YjE5YmJmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Anna Paquin, Lena Olin, Iain Glen, Giancarlo Giannini, Fele Martínez, Stephan Enquist', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (27478, 'Ali G Indahouse', 'Comedy', 2002, 'Mark Mylod', 'Ali G unwittingly becomes a pawn in the Chancellor\'s plot to overthrow the Prime Minister of Great Britain. However, Ali is embraced by the nation as a voice of the youth, making the PM and his government more popular than ever.', 'https://m.media-amazon.com/images/M/MV5BYjg2NzAxMzYtNDRlZS00ZjQ3LWE4YWItMDBmZWUxYjdiZDQ5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sacha Baron Cohen, Emilio Rivera, Gina La Piana, Dana de Celis, Dominic Delesilva, Jacqueline Castro', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (27660, 'Animatrix, The', 'Action,Animation,Drama,Sci-Fi', 2003, 'Peter Chung', 'The crew of the hovercraft Osiris must get a message back to Zion, a message of vital importance. Easy to do, but for the armada of Sentinels between them and Zion.', 'https://m.media-amazon.com/images/M/MV5BNzU4NzE3ZDgtMTgyNi00NzgzLWE3OWUtMTI5Zjg0NzYyZjU1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kevin Michael Richardson, Pamela Adlon, John DiMaggio, Carrie-Anne Moss, Tom Kenny, Rick Gomez', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (27674, '11:14', 'Comedy,Crime,Drama,Mystery,Thriller', 2003, 'Greg Marcks', 'The events leading up to an 11:14 p.m. car crash, from five very different perspectives.', 'https://m.media-amazon.com/images/M/MV5BMTUwYWFhMzAtNmQ5MC00YWJmLTliMTMtMmI2OTNmZDg0NGI1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Henry Thomas, Blake Heron, Barbara Hershey, Clark Gregg, Hilary Swank, Shawn Hatosy', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (27706, 'Lemony Snicket\'s A Series of Unfortunate Events', 'Adventure,Children,Comedy,Fantasy', 2004, 'Brad Silberling', 'When a massive fire kills their parents, three children are delivered to the custody of cousin and stage actor Count Olaf, who is secretly plotting to steal their parents\' vast fortune.', 'https://m.media-amazon.com/images/M/MV5BMjE3MDM4NTg0NV5BMl5BanBnXkFtZTcwNjI4MTczMw@@._V1_FMjpg_UX1000_.jpg', 'Jim Carrey, Liam Aiken, Emily Browning, Kara Hoffman, Shelby Hoffman, Jude Law', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (27727, 'Head-On (Gegen die Wand)', 'Drama,Romance', 2004, 'Fatih Akin', 'With the intention to break free from the strict familial restrictions, a suicidal young woman sets up a marriage of convenience with a forty-year-old addict, an act that will lead to an outburst of envious love.', 'https://m.media-amazon.com/images/M/MV5BMTMyNDhjZmYtNjY0Yy00N2M4LTlmNmUtNWY1MThmYmRmNTMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Birol Ünel, Güven Kiraç, Zarah Jane McKenzie, Stefan Gebelhoff, Catrin Striebeck, Francesco Fiannaca', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (27729, 'Kal Ho Naa Ho', 'Comedy,Drama,Romance', 2003, 'Nikkhil Advani', 'Naina, an introverted, perpetually depressed girl\'s life changes when she meets Aman. But Aman has a secret of his own which changes their lives forever. Embroiled in all this is Rohit, Naina\'s best friend who conceals his love for her.', 'https://m.media-amazon.com/images/M/MV5BZTczMDQ0N2EtMTY4NS00ODJhLTk4MzQtOGJmZGRmY2M4MWQwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Shah Rukh Khan, Preity G Zinta, Saif Ali Khan, Jaya Bachchan, Sushma Seth, Reema Lagoo', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (27773, 'Old Boy', 'Mystery,Thriller', 2003, 'Park Chan-wook', 'After being kidnapped and imprisoned for fifteen years, Oh Dae-Su is released, only to find that he must track down his captor in five days.', 'https://m.media-amazon.com/images/M/MV5BMTAwNzNjYWItZmI0Ni00ZTcyLWIwNWMtZjlmNGMxZTEyYTJmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Choi Min-sik, Yoo Ji-tae, Kang Hye-jeong, Kim Byeong-Ok, Ji Dae-han, Oh Dal-su', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (27839, 'Ring Two, The', 'Drama,Horror,Mystery,Thriller', 2005, 'Hideo Nakata', 'Six months after the incidents involving the lethal videotape, new clues prove that there is a new evil lurking in the darkness.', 'https://m.media-amazon.com/images/M/MV5BMTY2ODc2NTQ2OF5BMl5BanBnXkFtZTYwNzA4OTU3._V1_FMjpg_UX1000_.jpg', 'Naomi Watts, Simon Baker, David Dorfman, Elizabeth Perkins, Gary Cole, Sissy Spacek', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (27857, 'As it is in Heaven (Så som i himmelen)', 'Drama,Musical,Romance', 2004, 'Kay Pollak', 'A famous international conductor returns to his small childhood town in Sweden for early retirement. He\'s asked to help with the church choir. He affects the lives of all in the choir.', 'https://m.media-amazon.com/images/M/MV5BYjE1ZWFhZTMtZDI3Ny00OTBmLWFkNzgtZDhlZDJiZDJjYjIyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Nyqvist, Frida Hallgren, Helen Sjöholm, Lennart Jähkel, Ingela Olsson, Niklas Falk', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (27891, 'Quiet as a Mouse (Muxmäuschenstill)', 'Drama', 2004, 'Marcus Mittermeier', 'A pseudo documentary study of an archetypal German who tries to model his world according to his ideas of law and (sexual) order.', 'https://m.media-amazon.com/images/M/MV5BOGJlYjI5NjQtYzMxMy00NjU3LWI2NGEtZjE0YzUyMDQ1YzcwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jan Henrik Stahlberg, Fritz Roth, Wanda Perdelwitz, Markus von Lingen, Joachim Kretzer, Oliver Urbanski', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (30707, 'Million Dollar Baby', 'Drama', 2004, 'Clint Eastwood', 'Frankie, an ill-tempered old coach, reluctantly agrees to train aspiring boxer Maggie. Impressed with her determination and talent, he helps her become the best and the two soon form a close bond.', 'https://m.media-amazon.com/images/M/MV5BMTkxNzA1NDQxOV5BMl5BanBnXkFtZTcwNTkyMTIzMw@@._V1_FMjpg_UX1000_.jpg', 'Clint Eastwood, Hilary Swank, Morgan Freeman, Jay Baruchel, Mike Colter, Lucia Rijker', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (30749, 'Hotel Rwanda', 'Drama,War', 2004, 'Terry George', 'Paul Rusesabagina, a hotel manager, houses over a thousand Tutsi refugees during their struggle against the Hutu militia in Rwanda, Africa.', 'https://m.media-amazon.com/images/M/MV5BY2FmMWRmZmQtN2IzMS00OGVmLWFmNjktMTM0YWQzODcwYTEwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Xolani Mali, Don Cheadle, Desmond Dube, Hakeem Kae-Kazim, Tony Kgoroge, Rosie Motene', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (30793, 'Charlie and the Chocolate Factory', 'Adventure,Children,Comedy,Fantasy,IMAX', 2005, 'Tim Burton', 'Charlie, a young boy from an impoverished family, and four other kids win a tour of an amazing chocolate factory run by an imaginative chocolatier, Willy Wonka, and his staff of Oompa-Loompas.', 'https://m.media-amazon.com/images/M/MV5BNjcxMjg1Njg2NF5BMl5BanBnXkFtZTcwMjQ4NzMzMw@@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Freddie Highmore, David Kelly, Helena Bonham Carter, Noah Taylor, Missi Pyle', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (30803, '3-Iron (Bin-jip)', 'Drama,Romance', 2004, 'Kim Ki-duk', 'A transient young man breaks into empty homes to partake of the vacationing residents\' lives for a few days.', 'https://m.media-amazon.com/images/M/MV5BMTM1ODIwNzM5OV5BMl5BanBnXkFtZTcwNjk5MDkyMQ@@._V1_FMjpg_UX1000_.jpg', 'Lee Seung-yun, Jae Hee, Hyuk-ho Kwon, Joo Jin-mo, Jeong-ho Choi, Joo-seok Lee', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (30810, 'Life Aquatic with Steve Zissou, The', 'Adventure,Comedy,Fantasy', 2004, 'Wes Anderson', 'With a plan to exact revenge on a legendary shark that killed his partner, oceanographer Steve Zissou (Bill Murray) rallies a crew that includes his estranged wife, a journalist, and a man who may or may not be his son.', 'https://m.media-amazon.com/images/M/MV5BMTYzODYzNzg2MF5BMl5BanBnXkFtZTcwMTkzOTQzMw@@._V1_FMjpg_UX1000_.jpg', 'Bill Murray, Owen Wilson, Cate Blanchett, Anjelica Huston, Willem Dafoe, Jeff Goldblum', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (30812, 'Aviator, The', 'Drama', 2004, 'Martin Scorsese', 'A biopic depicting the early years of legendary director and aviator Howard Hughes\' career from the late 1920s to the mid 1940s.', 'https://m.media-amazon.com/images/M/MV5BYTUyYWJlNDgtOTM5Ny00YTQ3LWFmYTgtZjJiNTNkYjJlMmY4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Cate Blanchett, Kate Beckinsale, John C. Reilly, Alec Baldwin, Alan Alda', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (30825, 'Meet the Fockers', 'Comedy', 2004, 'Jay Roach', 'All hell breaks loose when the Byrnes family meets the Focker family for the first time.', 'https://m.media-amazon.com/images/M/MV5BMGI0NDZhODctZWYwNC00ZGZhLTg2N2UtMzdiZjM0OTM4NTY0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert De Niro, Ben Stiller, Dustin Hoffman, Barbra Streisand, Blythe Danner, Teri Polo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (30848, 'Love Song for Bobby Long, A', 'Drama', 2004, 'Shainee Gabel', 'A headstrong young woman returns to New Orleans after the death of her estranged mother.', 'https://m.media-amazon.com/images/M/MV5BNmZjODdlN2QtMGJhYi00MzIwLThlMTAtMmJlNzkzZGU0YjA0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Travolta, Scarlett Johansson, Gabriel Macht, Deborah Kara Unger, Dane Rhodes, David Jensen', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (30898, 'Upside of Anger, The', 'Comedy,Drama,Romance', 2005, 'Mike Binder', 'When her husband unexpectedly disappears, a sharp-witted suburban wife and her daughters juggle their mom\'s romantic dilemmas and family dynamics.', 'https://m.media-amazon.com/images/M/MV5BMTIyODM2MzUzM15BMl5BanBnXkFtZTcwMDQ4MzgyMQ@@._V1_FMjpg_UX1000_.jpg', 'Joan Allen, Kevin Costner, Erika Christensen, Keri Russell, Alicia Witt, Evan Rachel Wood', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (31225, 'Coach Carter', 'Drama', 2005, 'Thomas Carter', 'Controversy surrounds high school basketball coach Ken Carter after he benches his entire team for breaking their academic contract with him.', 'https://m.media-amazon.com/images/M/MV5BNjk0M2Y4ZTUtNzA3MS00MWYwLThmYjktMmYzNzVkYzQ3NmFlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Samuel L. Jackson, Rob Brown, Robert Ri\'chard, Rick Gonzalez, Nana Gbewonyo, Antwon Tanner', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (31364, 'Memories of Murder (Salinui chueok)', 'Crime,Drama,Mystery,Thriller', 2003, 'Bong Joon Ho', 'In a small Korean province in 1986, two detectives struggle with the case of multiple young women being found raped and murdered by an unknown culprit.', 'https://m.media-amazon.com/images/M/MV5BYmRjOWE5NmMtYTdkYS00ODFlLWJiMTMtYzE2NDZlZjlkZDQ0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Song Kang-ho, Kim Sang-kyung, Kim Roe-ha, Song Jae-ho, Byun Hee-Bong, Ko Seo-hie', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (31410, 'Downfall (Untergang, Der)', 'Drama,War', 2004, 'Oliver Hirschbiegel', 'Traudl Junge, the final secretary for Adolf Hitler, tells of the Nazi dictator\'s final days in his Berlin bunker at the end of WWII.', 'https://m.media-amazon.com/images/M/MV5BMTU0NTU5NTAyMl5BMl5BanBnXkFtZTYwNzYwMDg2._V1_FMjpg_UX1000_.jpg', 'Bruno Ganz, Alexandra Maria Lara, Corinna Harfouch, Ulrich Matthes, Juliane Köhler, Heino Ferch', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (31658, 'Howl\'s Moving Castle (Hauru no ugoku shiro)', 'Adventure,Animation,Fantasy,Romance', 2004, 'Hayao Miyazaki', 'When an unconfident young woman is cursed with an old body by a spiteful witch, her only chance of breaking the spell lies with a self-indulgent yet insecure young wizard and his companions in his legged, walking castle.', 'https://m.media-amazon.com/images/M/MV5BMTY1OTg0MjE3MV5BMl5BanBnXkFtZTcwNTUxMTkyMQ@@._V1_FMjpg_UX1000_.jpg', 'Chieko Baishô, Takuya Kimura, Akihiro Miwa, Tatsuya Gashûin, Ryûnosuke Kamiki, Mitsunori Isaki', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (31685, 'Hitch', 'Comedy,Romance', 2005, 'Andy Tennant', 'A smooth-talking man falls for a hardened columnist while helping a shy accountant woo a beautiful heiress.', 'https://m.media-amazon.com/images/M/MV5BNzYyNzM2NzM2NF5BMl5BanBnXkFtZTcwNjg5NTQzMw@@._V1_FMjpg_UX1000_.jpg', 'Will Smith, Eva Mendes, Kevin James, Amber Valletta, Julie Ann Emery, Adam Arkin', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (31696, 'Constantine', 'Action,Fantasy,Horror,Thriller', 2005, 'Francis Lawrence', 'Detective Angela approaches Constantine, a demon hunter, to help her investigate her twin sister\'s mysterious death. As he digs deeper, he realizes that demons are trying to enter the human world.', 'https://m.media-amazon.com/images/M/MV5BMjNhNTlmYmYtYjcxZi00ZDU1LTkxMWYtYzFlMWMzY2RiODM1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Keanu Reeves, Rachel Weisz, Shia LaBeouf, Djimon Hounsou, Max Baker, Pruitt Taylor Vince', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (32460, 'Knockin\' on Heaven\'s Door', 'Action,Comedy,Crime,Drama', 1997, 'Thomas Jahn', 'Two terminally ill patients escape from a hospital, steal a car and rush towards the sea.', 'https://m.media-amazon.com/images/M/MV5BMDZlMDM2YjEtOWMxMC00OGMwLTgxNGEtZmM5ZTEwMTg1MDc0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Til Schweiger, Jan Josef Liefers, Thierry van Werveke, Moritz Bleibtreu, Huub Stapel, Leonard Lansink', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (32587, 'Sin City', 'Action,Crime,Film-Noir,Mystery,Thriller', 2005, 'Frank Miller', 'An exploration of the dark and miserable Basin City and three of its residents, all of whom are caught up in violent corruption.', 'https://m.media-amazon.com/images/M/MV5BNWE2YmYyYzQtNGMwMi00Yzk0LTk3ZTYtYTcxNmFjMDE1MGExXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jessica Alba, Devon Aoki, Alexis Bledel, Powers Boothe, Cara D. Briggs, Jude Ciccolella', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (33004, 'Hitchhiker\'s Guide to the Galaxy, The', 'Adventure,Comedy,Sci-Fi', 2005, 'Garth Jennings', 'Mere seconds before the Earth is to be demolished by an alien construction crew, journeyman Arthur Dent is swept off the planet by his friend Ford Prefect, a researcher penning a new edition of \"The Hitchhiker\'s Guide to the Galaxy.\"', 'https://m.media-amazon.com/images/M/MV5BMTg4OWYwZjgtZDU0ZS00NjU4LTkxNjItYmYyYmUwNDU5YmM3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bill Bailey, Anna Chancellor, Warwick Davis, Yasiin Bey, Zooey Deschanel, Su Elliot', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (33166, 'Crash', 'Crime,Drama', 2004, 'Paul Haggis', 'Racial tensions collide in a collection of intertwined stories involving residents of Los Angeles.', 'https://m.media-amazon.com/images/M/MV5BOTk1OTA1MjIyNV5BMl5BanBnXkFtZTcwODQxMTkyMQ@@._V1_FMjpg_UX1000_.jpg', 'Karina Arroyave, Dato Bakhtadze, Sandra Bullock, Don Cheadle, Art Chudabala, Sean Cory Cooper', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (33493, 'Star Wars: Episode III - Revenge of the Sith', 'Action,Adventure,Sci-Fi', 2005, 'George Lucas', 'As the Clone Wars nears its end, Obi-Wan Kenobi pursues a new threat, while Anakin Skywalker is lured by Chancellor Palpatine into a sinister plot for galactic domination.', 'https://m.media-amazon.com/images/M/MV5BNTc4MTc3NTQ5OF5BMl5BanBnXkFtZTcwOTg0NjI4NA@@._V1_FMjpg_UX1000_.jpg', 'Ewan McGregor, Natalie Portman, Hayden Christensen, Ian McDiarmid, Samuel L. Jackson, Jimmy Smits', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (33615, 'Madagascar', 'Adventure,Animation,Children,Comedy', 2005, 'Eric Darnell', 'A group of animals who have spent all their life in a New York zoo end up in the jungles of Madagascar, and must adjust to living in the wild.', 'https://m.media-amazon.com/images/M/MV5BYjk4OGFmZmYtYWE4NC00MzM4LTkwZTItODdhMjk3NTZjMmI5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ben Stiller, Chris Rock, David Schwimmer, Jada Pinkett Smith, Sacha Baron Cohen, Cedric The Entertainer', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (33660, 'Cinderella Man', 'Drama,Romance', 2005, 'Ron Howard', 'The true story of James J. Braddock, a supposedly washed-up boxer, who returned to the spotlight to win the heavyweight championship of the world.', 'https://m.media-amazon.com/images/M/MV5BYjQ3M2ZjMzYtNmQwNC00MjNkLTgzOTgtMjhjMDk0YzIzOWZkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Russell Crowe, Renée Zellweger, Paul Giamatti, Craig Bierko, Paddy Considine, Bruce McGill', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (33679, 'Mr. & Mrs. Smith', 'Action,Adventure,Comedy,Romance', 2005, 'Doug Liman', 'A husband and wife struggle to keep their marriage alive until they realize they are both secretly working as assassins. Now, their respective assignments require them to kill each other.', 'https://m.media-amazon.com/images/M/MV5BMTUxMzcxNzQzOF5BMl5BanBnXkFtZTcwMzQxNjUyMw@@._V1_FMjpg_UX1000_.jpg', 'Brad Pitt, Angelina Jolie, Vince Vaughn, Adam Brody, Kerry Washington, Keith David', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (33794, 'Batman Begins', 'Action,Crime,IMAX', 2005, 'Christopher Nolan', 'After witnessing his parents\' death, billionaire Bruce Wayne learns the art of fighting to confront injustice. When he returns to Gotham as Batman, he must stop a secret society that intends to destroy the city.', 'https://m.media-amazon.com/images/M/MV5BMzA2NDQzZDEtNDU5Ni00YTlkLTg2OWEtYmQwM2Y1YTBjMjFjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Christian Bale, Michael Caine, Liam Neeson, Katie Holmes, Gary Oldman, Cillian Murphy', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (33834, 'Land of the Dead', 'Action,Horror,Thriller', 2005, 'George A. Romero', 'The living dead have taken over the world, and the last humans live in a walled city to protect themselves as they come to grips with the situation.', 'https://m.media-amazon.com/images/M/MV5BNzU1MDI1NDM1NF5BMl5BanBnXkFtZTcwMzU5OTkyMQ@@._V1_FMjpg_UX1000_.jpg', 'Simon Baker, John Leguizamo, Dennis Hopper, Asia Argento, Robert Joy, Eugene Clark', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (33903, 'Edukators, The (Die Fetten Jahre sind vorbei)', 'Comedy,Crime,Drama,Romance', 2004, 'Hans Weingartner', 'Three activists cobble together a kidnapping plot after they encounter a businessman in his home.', 'https://m.media-amazon.com/images/M/MV5BY2Q2NDMzMjAtMTc4My00NTY4LTgxNDktYmVkNWY0ZTRjYTc5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Daniel Brühl, Julia Jentsch, Stipe Erceg, Burghart Klaußner, Peer Martiny, Petra Zieser', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (34048, 'War of the Worlds', 'Action,Adventure,Sci-Fi,Thriller', 2005, 'Steven Spielberg', 'An alien invasion threatens the future of humanity. The catastrophic nightmare is depicted through the eyes of one American family fighting for survival.', 'https://m.media-amazon.com/images/M/MV5BNDUyODAzNDI1Nl5BMl5BanBnXkFtZTcwMDA2NDAzMw@@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Dakota Fanning, Miranda Otto, Justin Chatwin, Tim Robbins, Rick Gonzalez', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (34150, 'Fantastic Four', 'Action,Adventure,Sci-Fi', 2005, 'Tim Story', 'A group of astronauts gain superpowers after a cosmic radiation exposure and must use them to oppose the plans of their enemy, Doctor Victor Von Doom.', 'https://m.media-amazon.com/images/M/MV5BNjY2YmZmMzUtZWY5Mi00MzI3LTljOTgtYTMwMWY1ODI5ZWY5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ioan Gruffudd, Jessica Alba, Chris Evans, Michael Chiklis, Julian McMahon, Hamish Linklater', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (34162, 'Wedding Crashers', 'Comedy,Romance', 2005, 'David Dobkin', 'John Beckwith and Jeremy Grey, a pair of committed womanizers who sneak into weddings to take advantage of the romantic tinge in the air, find themselves at odds with one another when John meets and falls for Claire Cleary.', 'https://m.media-amazon.com/images/M/MV5BYzQwNmU0NGEtZjlmYy00ZjQ5LTlmMWYtODY3YzI4NTdiYzA4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Owen Wilson, Vince Vaughn, Christopher Walken, Rachel McAdams, Isla Fisher, Jane Seymour', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (34319, 'Island, The', 'Action,Sci-Fi,Thriller', 2005, 'Michael Bay', 'In 2019, a mercenary pursues a man and woman who escaped a research facility after learning their true fate.', 'https://m.media-amazon.com/images/M/MV5BMTAwNjk0NjM1ODReQTJeQWpwZ15BbWU3MDc1NjIxMzM@._V1_FMjpg_UX1000_.jpg', 'Ewan McGregor, Scarlett Johansson, Djimon Hounsou, Sean Bean, Steve Buscemi, Michael Clarke Duncan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (34405, 'Serenity', 'Action,Adventure,Sci-Fi', 2005, 'Joss Whedon', 'The crew of the ship Serenity try to evade an assassin sent to recapture telepath River.', 'https://m.media-amazon.com/images/M/MV5BZWYwN2M1NWItMWI0YS00ZmJjLTk1Y2QtZjIxYmNhNGZkZDcwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nathan Fillion, Gina Torres, Alan Tudyk, Morena Baccarin, Adam Baldwin, Jewel Staite', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (34437, 'Broken Flowers', 'Comedy,Drama', 2005, 'Jim Jarmusch', 'As the extremely withdrawn Don Johnston is dumped by his latest woman, he receives an anonymous letter from a former lover informing him that he has a son who may be looking for him. A freelance sleuth neighbor moves Don to embark on a cross-country search for his old flames in s...Read all', 'https://m.media-amazon.com/images/M/MV5BNTRiMDMyZDktZDAzNS00NDZkLWJkN2MtMDM1ZTU3NWM5MDg3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bill Murray, Julie Delpy, Heather Alicia Simms, Brea Frazier, Jarry Fall, Korka Fall', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (34534, 'Four Brothers', 'Action,Crime,Drama', 2005, 'John Singleton', 'When their adoptive mother is gunned down in a store robbery, four brothers decide to investigate the murder and find the killers themselves, but not all is what it seems.', 'https://m.media-amazon.com/images/M/MV5BMTU4NzM3Njg2NV5BMl5BanBnXkFtZTcwNjU4NDczMw@@._V1_FMjpg_UX1000_.jpg', 'Mark Wahlberg, Tyrese Gibson, André 3000, Garrett Hedlund, Terrence Howard, Josh Charles', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (35836, '40-Year-Old Virgin, The', 'Comedy,Romance', 2005, 'Judd Apatow', 'Goaded by his buddies, a nerdy guy who\'s never \"done the deed\" only finds the pressure mounting when he meets a single mother.', 'https://m.media-amazon.com/images/M/MV5BMzFiNzU2NjQtZTcwZC00Nzc3LTk3NjEtMDZmMDhmYjQ4NTAwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Steve Carell, Catherine Keener, Paul Rudd, Romany Malco, Seth Rogen, Elizabeth Banks', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (36401, 'Brothers Grimm, The', 'Comedy,Fantasy,Horror,Thriller', 2005, 'Terry Gilliam', 'Will and Jake Grimm are traveling con-artists who encounter a genuine fairy-tale curse which requires true courage instead of their usual bogus exorcisms.', 'https://m.media-amazon.com/images/M/MV5BMjNmMWRlYTktNGQyMi00YTgzLThjYjgtYWFmNTc3NGEwNTVkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Petr Ratimec, Barbora Lukesová, Anna Rust, Jeremy Robson, Matt Damon, Heath Ledger', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (36517, 'Constant Gardener, The', 'Drama,Thriller', 2005, 'Fernando Meirelles', 'A widower\'s transcontinental quest to find answers about his wife\'s death leads him to explosive secrets.', 'https://m.media-amazon.com/images/M/MV5BOTU3OWMzMzgtMjYwMi00ZGIyLTk0YTctNDVkYzRmMTM5ZjlmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ralph Fiennes, Rachel Weisz, Hubert Koundé, Danny Huston, Daniele Harford, Packson Ngugi', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (36529, 'Lord of War', 'Action,Crime,Drama,Thriller,War', 2005, 'Andrew Niccol', 'An arms dealer confronts the morality of his work as he is being chased by an INTERPOL Agent.', 'https://m.media-amazon.com/images/M/MV5BNThlY2NkYmMtNTFhNi00MzBiLWJmNzEtZjk5MzYwYWU2MjllXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nicolas Cage, Bridget Moynahan, Jared Leto, Shake Tukhmanyan, Jean-Pierre Nshanian, Jared Burke', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (36535, 'Everything Is Illuminated', 'Comedy,Drama', 2005, 'Liev Schreiber', 'A young Jewish American man, with the help of an eccentric local, endeavors to find the woman who saved his grandfather during World War II in a Ukrainian village that was ultimately razed by the Nazis.', 'https://m.media-amazon.com/images/M/MV5BMjExNTU2MTczNl5BMl5BanBnXkFtZTYwODYxMjY3._V1_FMjpg_UX1000_.jpg', 'Eugene Hutz, Elijah Wood, Jonathan Safran Foer, Jana Hrabetova, Stephen Samudovsky, Ljubomir Dezera', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (36537, 'Thumbsucker', 'Comedy,Drama', 2005, 'Mike Mills', 'Justin throws himself and everyone around him into chaos when he attempts to break free from his addiction to his thumb.', 'https://m.media-amazon.com/images/M/MV5BZmIxYjc1MjUtYjliNC00MjQxLWEyYWQtN2JkYzVhNzI5NDQ5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ted Beckman, Benjamin Bratt, Vincent D\'Onofrio, Arvin V. Entena, Tyler Gannon, Kelli Garner', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (37729, 'Corpse Bride', 'Animation,Comedy,Fantasy,Musical,Romance', 2005, 'Tim Burton', 'When a shy groom practices his wedding vows in the inadvertent presence of a deceased young woman, she rises from the grave assuming he has married her.', 'https://m.media-amazon.com/images/M/MV5BMTk1MTY1NjU4MF5BMl5BanBnXkFtZTcwNjIzMTEzMw@@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Helena Bonham Carter, Emily Watson, Tracey Ullman, Paul Whitehouse, Joanna Lumley', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (37733, 'History of Violence, A', 'Action,Crime,Drama,Thriller', 2005, 'David Cronenberg', 'A mild-mannered man becomes a local hero through an act of violence, which sets off repercussions that will shake his family to its very core.', 'https://m.media-amazon.com/images/M/MV5BMTczMzIzMTQ1OV5BMl5BanBnXkFtZTYwMDQwNjk2._V1_FMjpg_UX1000_.jpg', 'Viggo Mortensen, Maria Bello, Ed Harris, William Hurt, Ashton Holmes, Peter MacNeill', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (37741, 'Capote', 'Crime,Drama', 2005, 'Bennett Miller', 'In 1959, Truman Capote learns of the murder of a Kansas family and decides to write a book about the case. While researching for his novel In Cold Blood, Capote forms a relationship with one of the killers, Perry Smith, who is on death row.', 'https://m.media-amazon.com/images/M/MV5BMTczMzU0MjM1MV5BMl5BanBnXkFtZTcwMjczNzgyNA@@._V1_FMjpg_UX1000_.jpg', 'Allie Mickelson, Kelci Stephenson, Philip Seymour Hoffman, Craig Archibald, Bronwen Coleman, Kate Shindle', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (38038, 'Wallace & Gromit in The Curse of the Were-Rabbit', 'Adventure,Animation,Children,Comedy', 2005, 'Steve Box', 'Wallace and his loyal dog, Gromit, set out to discover the mystery behind the garden sabotage that plagues their village and threatens the annual giant vegetable growing contest.', 'https://m.media-amazon.com/images/M/MV5BM2JkOTRkZTctN2ZiMy00ZGRmLWJkNzQtOGJkNmFiM2ZjNjYzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Peter Sallis, Ralph Fiennes, Helena Bonham Carter, Peter Kay, Nicholas Smith, Liz Smith', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (38061, 'Kiss Kiss Bang Bang', 'Comedy,Crime,Mystery,Thriller', 2005, 'Shane Black', 'After being mistaken for an actor, a New York thief is sent to Hollywood to train under a private eye for a potential movie role, but the duo are thrown together with a struggling actress into a murder mystery.', 'https://m.media-amazon.com/images/M/MV5BMTY5NDExMDA3M15BMl5BanBnXkFtZTYwNTc2MzA3._V1_FMjpg_UX1000_.jpg', 'Robert Downey Jr., Val Kilmer, Michelle Monaghan, Corbin Bernsen, Dash Mihok, Larry Miller', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (38886, 'Squid and the Whale, The', 'Comedy,Drama', 2005, 'Noah Baumbach', 'Follows two young boys dealing with their parents\' divorce in Brooklyn in the 1980s.', 'https://m.media-amazon.com/images/M/MV5BNmRkNmRiMDQtOWJmZS00OWQ0LThlZDQtNDRkYmEzMjQyZGZjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Owen Kline, Jeff Daniels, Laura Linney, Jesse Eisenberg, William Baldwin, David Benger', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (39183, 'Brokeback Mountain', 'Drama,Romance', 2005, 'Ang Lee', 'Two shepherds fall for each other, but their relationship becomes complicated when they both get married to their respective girlfriends.', 'https://m.media-amazon.com/images/M/MV5BMzM4OWFjMTMtZjNjOS00YmU3LTlhY2MtNjFiMTVkN2Y1OTZlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Heath Ledger, Jake Gyllenhaal, Randy Quaid, Valerie Planche, Dave Trimble, Victor Reyes', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (39231, 'Elizabethtown', 'Comedy,Drama,Romance', 2005, 'Cameron Crowe', 'During a hometown memorial for his Kentucky-born father, a young man begins an unexpected romance with a too-good-to-be-true stewardess.', 'https://m.media-amazon.com/images/M/MV5BNTEyZWU4YmMtNTQwNC00OWM4LThkNzktNmQ1YmJkY2NjZDE1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Orlando Bloom, Kirsten Dunst, Susan Sarandon, Alec Baldwin, Bruce McGill, Judy Greer', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (39292, 'Good Night, and Good Luck.', 'Crime,Drama', 2005, 'George Clooney', 'Broadcast journalist Edward R. Murrow looks to bring down Senator Joseph McCarthy.', 'https://m.media-amazon.com/images/M/MV5BOTJhMmY5OGMtNDZhNS00ZjAyLWFmODQtOTA0NWM5NjMyOTk5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jeff Daniels, David Strathairn, Alex Borstein, Rose Abdoo, Dianne Reeves, Peter Martin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (39427, 'Stay', 'Thriller', 2005, 'Marc Forster', 'A psychiatrist attempts to prevent one of his patients from committing suicide while trying to maintain his own grip on reality.', 'https://m.media-amazon.com/images/M/MV5BZTk3ZThjZjgtYjhlMi00YjFlLWFkMjQtOGM0MTQxMGNmMzhjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ewan McGregor, Ryan Gosling, Kate Burton, Naomi Watts, Elizabeth Reaser, Bob Hoskins', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (39444, 'Weather Man, The', 'Comedy,Drama', 2005, 'Gore Verbinski', 'A Chicago weatherman separated from his wife and children debates whether professional and personal success are mutually exclusive.', 'https://m.media-amazon.com/images/M/MV5BMTQ4NzAxMTE3Ml5BMl5BanBnXkFtZTYwMDAwMjY3._V1_FMjpg_UX1000_.jpg', 'Nicolas Cage, Michael Caine, Hope Davis, Gemmenne de la Peña, Nicholas Hoult, Michael Rispoli', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (39446, 'Saw II', 'Horror,Thriller', 2005, 'Darren Lynn Bousman', 'A detective and his team must rescue eight people trapped in a factory by a man known as Jigsaw.', 'https://m.media-amazon.com/images/M/MV5BZGVlNjk3MmItZmUzNy00MzcyLWIzOTktZjllYWU5MDAyMjM1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tobin Bell, Shawnee Smith, Donnie Wahlberg, Erik Knudsen, Franky G, Glenn Plummer', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (40148, 'Revolver', 'Crime,Drama,Thriller', 2005, 'Guy Ritchie', 'Gambler Jake Green enters into a game with potentially deadly consequences.', 'https://m.media-amazon.com/images/M/MV5BMTQ1OTA3MjM4MF5BMl5BanBnXkFtZTYwMTMxODc4._V1_FMjpg_UX1000_.jpg', 'Jason Statham, Ray Liotta, Vincent Pastore, André 3000, Terence Maynard, Andrew Howard', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (40278, 'Jarhead', 'Action,Drama,War', 2005, 'Sam Mendes', 'A psychological study of Marine\'s state of mind during the Gulf War. Told through the eyes of a U.S. Marine sniper who struggles to cope with boredom, a sense of isolation, and other issues back home.', 'https://m.media-amazon.com/images/M/MV5BNmQ1NmYzZDctZjA4ZS00MWNjLWJmNjUtMDI0ZjhmMGM4ZjAyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jake Gyllenhaal, Scott MacDonald, Peter Sarsgaard, Jamie Foxx, Ming Lo, Lucas Black', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (40629, 'Pride & Prejudice', 'Drama,Romance', 2005, 'Joe Wright', 'When Elizabeth Bennet meets the handsome Mr. Darcy, she believes he is the last man she could ever marry, but as their lives become intertwined, she finds herself captivated by the man she has sworn to hate forever.', 'https://m.media-amazon.com/images/M/MV5BMTA1NDQ3NTcyOTNeQTJeQWpwZ15BbWU3MDA0MzA4MzE@._V1_FMjpg_UX1000_.jpg', 'Keira Knightley, Talulah Riley, Rosamund Pike, Jena Malone, Carey Mulligan, Donald Sutherland', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (40732, 'Descent, The', 'Adventure,Drama,Horror,Thriller', 2005, 'Neil Marshall', 'A caving expedition goes horribly wrong when six explorers become trapped and ultimately pursued by a strange breed of predators.', 'https://m.media-amazon.com/images/M/MV5BMjA5NzQ1NTgwNV5BMl5BanBnXkFtZTcwNjUxMzUzMw@@._V1_FMjpg_UX1000_.jpg', 'Shauna Macdonald, Natalie Mendoza, Alex Reid, Saskia Mulder, MyAnna Buring, Nora-Jane Noone', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (40815, 'Harry Potter and the Goblet of Fire', 'Adventure,Fantasy,Thriller,IMAX', 2005, 'Mike Newell', 'Harry Potter finds himself competing in a hazardous tournament between rival schools of magic, but he is distracted by recurring nightmares.', 'https://m.media-amazon.com/images/M/MV5BMTI1NDMyMjExOF5BMl5BanBnXkFtZTcwOTc4MjQzMQ@@._V1_FMjpg_UX1000_.jpg', 'Eric Sykes, Timothy Spall, David Tennant, Daniel Radcliffe, Emma Watson, Rupert Grint', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (40819, 'Walk the Line', 'Drama,Musical,Romance', 2005, 'James Mangold', 'A chronicle of country music legend Johnny Cash\'s life, from his early days on an Arkansas cotton farm to his rise to fame with Sun Records in Memphis, where he recorded alongside Elvis Presley, Jerry Lee Lewis, and Carl Perkins.', 'https://m.media-amazon.com/images/M/MV5BMjIyOTU3MjUxOF5BMl5BanBnXkFtZTcwMTQ0NjYzMw@@._V1_FMjpg_UX1000_.jpg', 'Joaquin Phoenix, Reese Witherspoon, Ginnifer Goodwin, Robert Patrick, Dallas Roberts, Dan John Miller', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (41285, 'Match Point', 'Crime,Drama,Romance', 2005, 'Woody Allen', 'At a turning point in his life, a former tennis pro falls for an actress who happens to be dating his friend and soon-to-be brother-in-law.', 'https://m.media-amazon.com/images/M/MV5BMTQ1NzQ4OTM4MV5BMl5BanBnXkFtZTcwNzY2OTQzMw@@._V1_FMjpg_UX1000_.jpg', 'Jonathan Rhys Meyers, Alexander Armstrong, Paul Kaye, Matthew Goode, Brian Cox, Penelope Wilton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (41566, 'Chronicles of Narnia: The Lion, the Witch and the Wardrobe, The', 'Adventure,Children,Fantasy', 2005, 'Andrew Adamson', 'While playing, Lucy and her siblings find a wardrobe that lands them in a mystical place called Narnia. Here they realize that it was fated and they must now unite with Aslan to defeat an evil queen.', 'https://m.media-amazon.com/images/M/MV5BMTc0NTUwMTU5OV5BMl5BanBnXkFtZTcwNjAwNzQzMw@@._V1_FMjpg_UX1000_.jpg', 'Georgie Henley, Skandar Keynes, William Moseley, Anna Popplewell, Tilda Swinton, James McAvoy', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (41569, 'King Kong', 'Action,Adventure,Drama,Fantasy,Thriller', 2005, 'Peter Jackson', 'A greedy film producer assembles a team of moviemakers and sets out for the infamous Skull Island, where they find more than just cannibalistic natives.', 'https://m.media-amazon.com/images/M/MV5BMWY0NWE0ZjUtNjRlOS00ZDViLTgxNTQtMGMwN2FhNDY1YTg2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Naomi Watts, Jack Black, Adrien Brody, Thomas Kretschmann, Colin Hanks, Andy Serkis', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (41997, 'Munich', 'Action,Crime,Drama,Thriller', 2005, 'Steven Spielberg', 'After the Black September capture and massacre of Israeli athletes at the 1972 Olympics, five men are chosen to eliminate the people responsible for that fateful day.', 'https://m.media-amazon.com/images/M/MV5BMTcwNzYzMzMwMF5BMl5BanBnXkFtZTcwMzMzODczMQ@@._V1_FMjpg_UX1000_.jpg', 'Eric Bana, Daniel Craig, Ciarán Hinds, Mathieu Kassovitz, Hanns Zischler, Ayelet Zurer', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (42004, 'Transamerica', 'Adventure,Comedy,Drama', 2005, 'Duncan Tucker', 'A transgender woman takes an unexpected journey when she learns that she had a son, now a teenage runaway hustling on the streets of New York.', 'https://m.media-amazon.com/images/M/MV5BMzdmNmNjNGQtMTViMy00NDc5LTk1MmMtY2VjZWRlYmUwMWQyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Andrea James, Felicity Huffman, Danny Burstein, Maurice Orozco, Elizabeth Peña, Craig Bockhorn', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (43904, 'When a Stranger Calls', 'Horror,Thriller', 2006, 'Simon West', 'During a babysitting gig, a high-school student is harassed by an increasingly threatening prank caller.', 'https://m.media-amazon.com/images/M/MV5BZDIxMWUzOGMtMDBlZC00YzBjLTlkYjUtMTk0MjdmNDk3NTg4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Camilla Belle, Tommy Flanagan, Katie Cassidy, Tessa Thompson, Brian Geraghty, Clark Gregg', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (43914, 'Winter Passing', 'Drama', 2005, 'Adam Rapp', 'An editor offers actress/bartender Reese $100,000 for her late mom\'s letters from her novelist dad. She heads home from NYC to get them and finds her dad living in the garage while two strangers live in the house.', 'https://m.media-amazon.com/images/M/MV5BMTQzMzc2Njk1MV5BMl5BanBnXkFtZTcwODI3NDIzMQ@@._V1_FMjpg_UX1000_.jpg', 'Zooey Deschanel, Darrell Larson, John Bedford Lloyd, Deirdre O\'Connell, Mandy Siegfried, Amy Madigan', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (44022, 'Ice Age 2: The Meltdown', 'Adventure,Animation,Children,Comedy', 2006, 'Carlos Saldanha', 'Manny, Sid and Diego discover that the ice age is coming to an end, and join everybody for a journey to higher ground. On the trip, they discover that Manny is not in fact the last of the woolly mammoths.', 'https://m.media-amazon.com/images/M/MV5BMjAwODg3OTAxMl5BMl5BanBnXkFtZTcwMjg2NjYyMw@@._V1_FMjpg_UX1000_.jpg', 'Ray Romano, John Leguizamo, Denis Leary, Seann William Scott, Josh Peck, Queen Latifah', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (44191, 'V for Vendetta', 'Action,Sci-Fi,Thriller,IMAX', 2006, 'James McTeigue', 'In a future British dystopian society, a shadowy freedom fighter, known only by the alias of \"V\", plots to overthrow the tyrannical government - with the help of a young woman.', 'https://m.media-amazon.com/images/M/MV5BOTI5ODc3NzExNV5BMl5BanBnXkFtZTcwNzYxNzQzMw@@._V1_FMjpg_UX1000_.jpg', 'Natalie Portman, Hugo Weaving, Stephen Rea, Stephen Fry, John Hurt, Tim Pigott-Smith', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (44193, 'She\'s the Man', 'Comedy,Romance', 2006, 'Andy Fickman', 'When her brother decides to ditch for a couple weeks, Viola heads over to his elite boarding school, disguised as him, and proceeds to fall for his school\'s star soccer player, and soon learns she\'s not the only one with romantic troubles.', 'https://m.media-amazon.com/images/M/MV5BYjVkM2VmZDYtM2E2OS00NTIwLThlZjctM2NkM2QwYmIxMTFiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Amanda Bynes, Channing Tatum, Laura Ramsey, Vinnie Jones, David Cross, Julie Hagerty', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (44195, 'Thank You for Smoking', 'Comedy,Drama', 2006, 'Jason Reitman', 'The chief spokesman of a tobacco lobby wants to excel at his job while trying to remain a role model for his young son.', 'https://m.media-amazon.com/images/M/MV5BMTI2MDk5MjE4NV5BMl5BanBnXkFtZTYwMjkwNTU3._V1_FMjpg_UX1000_.jpg', 'Joan Lunden, Eric Haberman, Aaron Eckhart, Mary Jo Smith, Todd Louiso, Jeff Witzke', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (44199, 'Inside Man', 'Crime,Drama,Thriller', 2006, 'Spike Lee', 'A police detective, a bank robber and a high-power broker enter high-stakes negotiations after the criminal\'s brilliant heist spirals into a hostage situation.', 'https://m.media-amazon.com/images/M/MV5BZWFmMDZkYjktMjYyOS00MTM2LTg2MmQtOTUwMzJjMDlhZDY1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Denzel Washington, Clive Owen, Jodie Foster, Christopher Plummer, Willem Dafoe, Chiwetel Ejiofor', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (44204, 'Tsotsi', 'Crime,Drama', 2005, 'Gavin Hood', 'Six days in the violent life of a young Johannesburg gang leader.', 'https://m.media-amazon.com/images/M/MV5BNGVhMjgzZDktOTc5Yy00Y2M1LTk5NjctNWQwMmY5NmRjNTZiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Presley Chweneyagae, Terry Pheto, Kenneth Nkosi, Mothusi Magano, Zenzo Ngqobe, Zola', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (44555, 'Lives of Others, The (Das leben der Anderen)', 'Drama,Romance,Thriller', 2006, 'Florian Henckel von Donnersmarck', 'In 1984 East Berlin, an agent of the secret police conducting surveillance on a writer and his lover finds himself becoming increasingly absorbed by their lives.', 'https://m.media-amazon.com/images/M/MV5BYjM1N2Q0YWEtN2E5MC00NDM3LTk2NTEtMTc1NTk5OTA5ZGIzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Martina Gedeck, Ulrich Mühe, Sebastian Koch, Ulrich Tukur, Thomas Thieme, Hans-Uwe Bauer', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (44665, 'Lucky Number Slevin', 'Crime,Drama,Mystery', 2006, 'Paul McGuigan', 'A case of mistaken identity lands Slevin into the middle of a war being plotted by two of the city\'s rival crime bosses. Under constant surveillance by Detective Brikowski and assassin Goodkat, he must get them before they get him.', 'https://m.media-amazon.com/images/M/MV5BNzJkYjA4YjEtMTZlZi00NjFjLTgwNDMtN2VhYTY0MDU3ZjcwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Josh Hartnett, Bruce Willis, Lucy Liu, Morgan Freeman, Ben Kingsley, Michael Rubenfeld', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (45186, 'Mission: Impossible III', 'Action,Adventure,Thriller', 2006, 'J.J. Abrams', 'IMF agent Ethan Hunt comes into conflict with a dangerous and sadistic arms dealer who threatens his life and his fiancée in response.', 'https://m.media-amazon.com/images/M/MV5BNzY1MzdjMjYtNDJiZS00N2U4LWI0MWQtZTRiZWYxMzU3ZmI4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Philip Seymour Hoffman, Ving Rhames, Billy Crudup, Michelle Monaghan, Jonathan Rhys Meyers', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (45210, 'United 93', 'Crime,Drama', 2006, 'Paul Greengrass', 'A real-time account of the events on United Flight 93, one of the planes hijacked on September 11th, 2001 that crashed near Shanksville, Pennsylvania when passengers foiled the terrorist plot.', 'https://m.media-amazon.com/images/M/MV5BMTI1Nzc3NjAwOF5BMl5BanBnXkFtZTcwNzYzMjYzMQ@@._V1_FMjpg_UX1000_.jpg', 'J.J. Johnson, Gary Commock, Polly Adams, Opal Alladin, Starla Benford, Trish Gates', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (45447, 'Da Vinci Code, The', 'Drama,Mystery,Thriller', 2006, 'Ron Howard', 'A murder and clues in paintings lead to the discovery of a closely guarded religious mystery.', 'https://m.media-amazon.com/images/M/MV5BMjIxMjQyMTc3Nl5BMl5BanBnXkFtZTcwMTA1MDUzMw@@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Audrey Tautou, Ian McKellen, Jean Reno, Paul Bettany, Alfred Molina', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (45499, 'X-Men: The Last Stand', 'Action,Sci-Fi,Thriller', 2006, 'Brett Ratner', 'The human government develops a cure for mutations, and Jean Grey becomes a darker uncontrollable persona called the Phoenix who allies with Magneto, causing escalation into an all-out battle for the X-Men.', 'https://m.media-amazon.com/images/M/MV5BMThmOWE3OWEtODJmNC00ZDEzLTk4MWUtNzEzM2RiNmJiZmU3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Hugh Jackman, Halle Berry, Ian McKellen, Patrick Stewart, Famke Janssen, Anna Paquin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (45517, 'Cars', 'Animation,Children,Comedy', 2006, 'John Lasseter', 'On the way to the biggest race of his life, a hotshot rookie race car gets stranded in a rundown town and learns that winning isn\'t everything in life.', 'https://m.media-amazon.com/images/M/MV5BMTg5NzY0MzA2MV5BMl5BanBnXkFtZTYwNDc3NTc2._V1_FMjpg_UX1000_.jpg', 'Owen Wilson, Paul Newman, Bonnie Hunt, Larry the Cable Guy, Cheech Marin, Tony Shalhoub', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (45672, 'Click', 'Adventure,Comedy,Drama,Fantasy,Romance', 2006, 'Frank Coraci', 'A workaholic architect finds a universal remote that allows him to fast-forward and rewind to different parts of his life. Complications arise when the remote starts to overrule his choices.', 'https://m.media-amazon.com/images/M/MV5BMTA1MTUxNDY4NzReQTJeQWpwZ15BbWU2MDE3ODAxNw@@._V1_FMjpg_UX1000_.jpg', 'Adam Sandler, Kate Beckinsale, Christopher Walken, David Hasselhoff, Henry Winkler, Julie Kavner', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (45720, 'Devil Wears Prada, The', 'Comedy,Drama', 2006, 'David Frankel', 'With an aspiration to become a journalist, Andy, a smart but sensible young graduate, travels to New York. She starts working as an assistant to one of the city\'s biggest high fashion magazine editors, the cynical Miranda Priestly.', 'https://m.media-amazon.com/images/M/MV5BOWM3NTI3YWEtYjJmMy00M2U5LWI1NzEtZWM3ZDY2ZWNjOGRiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Meryl Streep, Anne Hathaway, Emily Blunt, Stanley Tucci, Simon Baker, Adrian Grenier', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (45722, 'Pirates of the Caribbean: Dead Man\'s Chest', 'Action,Adventure,Fantasy', 2006, 'Gore Verbinski', 'Jack Sparrow races to recover the heart of Davy Jones to avoid enslaving his soul to Jones\' service, as other friends and foes seek the heart for their own agenda as well.', 'https://m.media-amazon.com/images/M/MV5BMTcwODc1MTMxM15BMl5BanBnXkFtZTYwMDg1NzY3._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Orlando Bloom, Keira Knightley, Jack Davenport, Bill Nighy, Jonathan Pryce', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (46062, 'High School Musical', 'Children,Comedy,Drama,Musical,Romance', 2006, 'Kenny Ortega', 'A popular high school athlete and an academically gifted girl get roles in the school musical and develop a friendship that threatens East High\'s social order.', 'https://m.media-amazon.com/images/M/MV5BNzA2MmIxYWUtOGRiYi00ZTVkLWE4YTQtY2MyN2I5ZmRmOTBjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Zac Efron, Vanessa Hudgens, Ashley French, Lucas Grabeel, Corbin Bleu, Monique Coleman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (46335, 'Fast and the Furious: Tokyo Drift, The (Fast and the Furious 3, The)', 'Action,Crime,Drama,Thriller', 2006, 'Justin Lin', 'A teenager becomes a major competitor in the world of drift racing after moving in with his father in Tokyo to avoid a jail sentence in America.', 'https://m.media-amazon.com/images/M/MV5BMTQ2NTMxODEyNV5BMl5BanBnXkFtZTcwMDgxMjA0MQ@@._V1_FMjpg_UX1000_.jpg', 'Lucas Black, Damien Marzette, Trula M. Marcus, Zachery Ty Bryan, Brandon Brendel, Daniel Booko', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (46363, 'Summer in Berlin (Sommer vorm Balkon)', 'Drama', 2005, 'Andreas Dresen', 'Summer in Berlin: Nike and Katrin, neighbors in Prenzlauer Berg, discuss their desires on the balcony. Katrin seeks a father for her son; Nike wants a reliable man. Trucker Ronald arrives, but tensions soon arise between the friends.', 'https://m.media-amazon.com/images/M/MV5BMDc1ZmRiODItMGM4Mi00NTkzLTkyMDAtN2JmZDU4MjI0YjNhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Inka Friedrich, Nadja Uhl, Andreas Schmidt, Stephanie Schönfeld, Christel Peters, Kurt Radeke', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (46578, 'Little Miss Sunshine', 'Adventure,Comedy,Drama', 2006, 'Jonathan Dayton', 'A family determined to get their young daughter into the finals of a beauty pageant take a cross-country trip in their VW bus.', 'https://m.media-amazon.com/images/M/MV5BMTgzNTgzODU0NV5BMl5BanBnXkFtZTcwMjEyMjMzMQ@@._V1_FMjpg_UX1000_.jpg', 'Abigail Breslin, Greg Kinnear, Paul Dano, Alan Arkin, Toni Collette, Steve Carell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (46723, 'Babel', 'Drama,Thriller', 2006, 'Alejandro G. Iñárritu', 'Tragedy strikes a married couple on vacation in the Moroccan desert, which jump starts an interlocking story involving four different families.', 'https://m.media-amazon.com/images/M/MV5BNDY3YjliMzgtMTkxYi00MmRkLWI1YTktNGQ3NGJhNzVhNzg5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brad Pitt, Cate Blanchett, Mohamed Akhzam, Peter Wight, Harriet Walter, Trevor Martin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (46865, 'Little Man', 'Comedy', 2006, 'Keenen Ivory Wayans', 'A wannabe-dad mistakes a vertically-challenged criminal on the lam for his newly-adopted son.', 'https://m.media-amazon.com/images/M/MV5BMTI0NTA3MjI3NV5BMl5BanBnXkFtZTcwNTI1ODYzMQ@@._V1_FMjpg_UX1000_.jpg', 'Marlon Wayans, Shawn Wayans, Kerry Washington, John Witherspoon, Tracy Morgan, Lochlyn Munro', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (46948, 'Monster House', 'Animation,Children,Fantasy,Mystery', 2006, 'Gil Kenan', 'Three teens discover that their neighbor\'s house is really a living, breathing, scary monster.', 'https://m.media-amazon.com/images/M/MV5BMTIzNjE1NDg1N15BMl5BanBnXkFtZTcwOTg2NTMzMQ@@._V1_FMjpg_UX1000_.jpg', 'Ryan Whitney, Steve Buscemi, Mitchel Musso, Catherine O\'Hara, Fred Willard, Sam Lerner', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (46972, 'Night at the Museum', 'Action,Comedy,Fantasy,IMAX', 2006, 'Shawn Levy', 'A newly recruited night security guard at the Museum of Natural History discovers that an ancient curse causes the animals and exhibits on display to come to life and wreak havoc.', 'https://m.media-amazon.com/images/M/MV5BNGMyYjYyZDAtNzRiZC00ZjRkLTkwYjktODkxODQzNTFiMTVmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ben Stiller, Carla Gugino, Dick Van Dyke, Mickey Rooney, Bill Cobbs, Jake Cherry', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (46976, 'Stranger than Fiction', 'Comedy,Drama,Fantasy,Romance', 2006, 'Marc Forster', 'I.R.S. auditor Harold Crick suddenly finds his mundane Chicago life to be the subject of narration only he can hear: narration that begins to affect his entire existence, from his work to his love life to his death.', 'https://m.media-amazon.com/images/M/MV5BNzFmZjZhOTktYWIxZS00YzM1LWEzNmQtMDM2YjlhYmI2MDVlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Will Ferrell, William Dick, Guy Massey, Martha Espinoza, T.J. Jagodowski, Peter Grosz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (47099, 'Pursuit of Happyness, The', 'Drama', 2006, 'Gabriele Muccino', 'A struggling salesman takes custody of his son as he\'s poised to begin a life-changing professional career.', 'https://m.media-amazon.com/images/M/MV5BMTQ5NjQ0NDI3NF5BMl5BanBnXkFtZTcwNDI0MjEzMw@@._V1_FMjpg_UX1000_.jpg', 'Will Smith, Jaden Smith, Thandiwe Newton, Brian Howe, James Karen, Dan Castellaneta', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (47200, 'Crank', 'Action,Thriller', 2006, 'Mark Neveldine', 'Professional assassin Chev Chelios learns his rival has injected him with a poison that will kill him if his heart rate drops.', 'https://m.media-amazon.com/images/M/MV5BMjg0NjAxNDY4MV5BMl5BanBnXkFtZTcwODA5MjMzMw@@._V1_FMjpg_UX1000_.jpg', 'Jason Statham, Amy Smart, Jose Pablo Cantillo, Efren Ramirez, Dwight Yoakam, Carlos Sanz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (47610, 'Illusionist, The', 'Drama,Fantasy,Mystery,Romance', 2006, 'Neil Burger', 'In turn-of-the-century Vienna, a magician uses his abilities to secure the love of a woman far above his social standing.', 'https://m.media-amazon.com/images/M/MV5BNzNmYmI4YWMtMGFkOS00ODVkLTg3MTEtOTExNDg3ZjQ0MGM3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Edward Norton, Paul Giamatti, Jessica Biel, Rufus Sewell, Eddie Marsan, Jake Wood', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (47629, 'The Queen', 'Drama', 2006, 'Stephen Frears', 'After the death of Princess Diana, Queen Elizabeth II struggles with her reaction to a sequence of events nobody could have predicted.', 'https://m.media-amazon.com/images/M/MV5BMTQ3NTMxODg1Ml5BMl5BanBnXkFtZTcwMjEyMjczMQ@@._V1_FMjpg_UX1000_.jpg', 'Helen Mirren, James Cromwell, Alex Jennings, Roger Allam, Sylvia Syms, Tim McMullan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (48043, 'Fountain, The', 'Drama,Fantasy,Romance', 2006, 'Darren Aronofsky', 'As a modern-day scientist, Tommy is struggling with mortality, desperately searching for the medical breakthrough that will save the life of his cancer-stricken wife, Izzi.', 'https://m.media-amazon.com/images/M/MV5BMTU5OTczMTcxMV5BMl5BanBnXkFtZTcwNDg3MTEzMw@@._V1_FMjpg_UX1000_.jpg', 'Hugh Jackman, Rachel Weisz, Ellen Burstyn, Mark Margolis, Stephen McHattie, Fernando Hernandez', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (48082, 'Science of Sleep, The (La science des rêves)', 'Comedy,Drama,Fantasy,Romance', 2006, 'Michel Gondry', 'A man entranced by his dreams and imagination is love-struck with a French woman and feels he can show her his world.', 'https://m.media-amazon.com/images/M/MV5BMTg3NTcxNzY5NV5BMl5BanBnXkFtZTcwODk5NTQzMQ@@._V1_FMjpg_UX1000_.jpg', 'Gael García Bernal, Charlotte Gainsbourg, Alain Chabat, Miou-Miou, Pierre Vaneck, Emma de Caunes', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (48385, 'Borat: Cultural Learnings of America for Make Benefit Glorious Nation of Kazakhstan', 'Comedy', 2006, 'Larry Charles', 'Kazakh TV talking head Borat is dispatched to the United States to report on the greatest country in the world.', 'https://m.media-amazon.com/images/M/MV5BMTk0MTQ3NDQ4Ml5BMl5BanBnXkFtZTcwOTQ3OTQzMw@@._V1_FMjpg_UX1000_.jpg', 'Sacha Baron Cohen, Ken Davitian, Luenell, Chester, Charlie, Ilham Aliyev', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (48394, 'Pan\'s Labyrinth (Laberinto del fauno, El)', 'Drama,Fantasy,Thriller', 2006, 'Guillermo del Toro', 'In 1944 Spain, a girl is sent to live with her ruthless stepfather. During the night, she meets a fairy who takes her to an old faun. He tells her she\'s a princess, but must prove her royalty by surviving three gruesome tasks.', 'https://m.media-amazon.com/images/M/MV5BOTc1NTAxMWItMWFlNy00MmU2LTkwMTMtNzMwOTg5OTQ5YTFiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ivana Baquero, Sergi López, Maribel Verdú, Doug Jones, Ariadna Gil, Álex Angulo', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (48516, 'Departed, The', 'Crime,Drama,Thriller', 2006, 'Martin Scorsese', 'An undercover cop and a mole in the police attempt to identify each other while infiltrating an Irish gang in South Boston.', 'https://m.media-amazon.com/images/M/MV5BMTI1MTY2OTIxNV5BMl5BanBnXkFtZTYwNjQ4NjY3._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Matt Damon, Jack Nicholson, Mark Wahlberg, Martin Sheen, Ray Winstone', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (48696, 'Little Children', 'Drama,Romance', 2006, 'Todd Field', 'The lives of two lovelorn spouses from separate marriages, a registered sex offender, and a disgraced ex-police officer intersect as they struggle to resist their vulnerabilities and temptations in suburban Massachusetts.', 'https://m.media-amazon.com/images/M/MV5BMTYwNzEwNTI3MV5BMl5BanBnXkFtZTcwODUyODczMQ@@._V1_FMjpg_UX1000_.jpg', 'Kate Winslet, Jennifer Connelly, Patrick Wilson, Jackie Earle Haley, Noah Emmerich, Gregg Edelman', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (48738, 'Last King of Scotland, The', 'Drama,Thriller', 2006, 'Kevin Macdonald', 'Based on the events of the brutal Ugandan dictator Idi Amin\'s regime as seen by his personal physician during the 1970s.', 'https://m.media-amazon.com/images/M/MV5BZDg4NjA0YzctNWMzMi00NmY1LTkyMGYtZjI4ZjFmZjMzMGE0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Forest Whitaker, James McAvoy, Kerry Washington, Gillian Anderson, Simon McBurney, David Oyelowo', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (48774, 'Children of Men', 'Action,Adventure,Drama,Sci-Fi,Thriller', 2006, 'Alfonso Cuarón', 'In 2027, in a chaotic world in which women have somehow become infertile, a former activist agrees to help transport a miraculously pregnant woman to a sanctuary at sea.', 'https://m.media-amazon.com/images/M/MV5BMDNkNmNiYzYtYWY0YS00NWEwLTgwMWUtYjM0M2E4Nzk3MzhmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Juan Gabriel Yacuzzi, Mishal Husain, Rob Curling, Jon Chevalier, Rita Davies, Kim Fenton', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (48780, 'Prestige, The', 'Drama,Mystery,Sci-Fi,Thriller', 2006, 'Christopher Nolan', 'Rival 19th-century magicians engage in a bitter battle for trade secrets.', 'https://m.media-amazon.com/images/M/MV5BMTM3MzQ5MjQ5OF5BMl5BanBnXkFtZTcwMTQ3NzMzMw@@._V1_FMjpg_UX1000_.jpg', 'Hugh Jackman, Christian Bale, Michael Caine, Piper Perabo, Rebecca Hall, Scarlett Johansson', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (48877, 'Saw III', 'Crime,Horror,Thriller', 2006, 'Darren Lynn Bousman', 'Jigsaw abducts a doctor in order to keep himself alive while he watches his new apprentice put an unlucky citizen named Jeff through a brutal test.', 'https://m.media-amazon.com/images/M/MV5BODQ4YTAwZTItZGFjZi00YjNiLTllYzUtYWY3OWM2OTQzODVkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tobin Bell, Shawnee Smith, Angus Macfadyen, Bahar Soomekh, Donnie Wahlberg, Dina Meyer', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (48982, 'Flushed Away', 'Animation,Comedy', 2006, 'David Bowers', 'The story of an uptown rat that gets flushed down the toilet from his penthouse apartment, ending in the sewers of London, where he has to learn a whole new and different way of life.', 'https://m.media-amazon.com/images/M/MV5BMTI1MzE1MDk2N15BMl5BanBnXkFtZTYwMjEwMzI3._V1_FMjpg_UX1000_.jpg', 'Hugh Jackman, Kate Winslet, Ian McKellen, Jean Reno, Bill Nighy, Andy Serkis', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (49272, 'Casino Royale', 'Action,Adventure,Thriller', 2006, 'Martin Campbell', 'After earning a licence to kill, secret agent James Bond sets out on his first mission as 007. Bond must defeat a private banker funding terrorists in a high-stakes game of poker at Casino Royale, in Montenegro.', 'https://m.media-amazon.com/images/M/MV5BMWQ1ZDM4NDktMWY0NC00MjcxLWJlMDMtNmE2MGVhYzRjMWQ0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Daniel Craig, Eva Green, Mads Mikkelsen, Judi Dench, Jeffrey Wright, Giancarlo Giannini', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (49274, 'Happy Feet', 'Adventure,Animation,Children,Comedy,IMAX', 2006, 'Warren Coleman', 'Into the world of the Emperor Penguins, who find their soul mates through song, a penguin is born who cannot sing. But he can tap dance something fierce!', 'https://m.media-amazon.com/images/M/MV5BNjViZDZhNjctM2MwOS00MDdhLWIwMTYtNjNmNGY2OGMzZWZhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Carlos Alazraqui, Lombardo Boyar, Jeffrey Garcia, Johnny A. Sanchez, Robin Williams, Elijah Wood', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (49278, 'Déjà Vu (Deja Vu)', 'Action,Sci-Fi,Thriller', 2006, 'Tony Scott', 'After a ferry is bombed in New Orleans, an A.T.F. agent joins a unique investigation using experimental surveillance technology to find the bomber, but soon finds himself becoming obsessed with one of the victims.', 'https://m.media-amazon.com/images/M/MV5BMzEwNTAwNjEwMV5BMl5BanBnXkFtZTYwMzgzMjA3._V1_FMjpg_UX1000_.jpg', 'Denzel Washington, Paula Patton, Val Kilmer, Jim Caviezel, Adam Goldberg, Elden Henson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (49286, 'Holiday, The', 'Comedy,Romance', 2006, 'Nancy Meyers', 'Amanda lives in LA and is a movie trailer editor. Iris lives in Surrey and is a journalist. The two decide to swap houses for two weeks at Christmas - both trying to forget their troubled love lives, until love finds them anyways.', 'https://m.media-amazon.com/images/M/MV5BZmEwNDg0M2QtMDdiNy00YTliLTk4ZjctOThjZjczODVmMTdkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cameron Diaz, Kate Winslet, Jude Law, Jack Black, Eli Wallach, Edward Burns', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (49312, 'Snow Cake', 'Drama', 2006, 'Marc Evans', 'A drama focused on the friendship between a high-functioning autistic woman and a man who is traumatized after a fatal car accident.', 'https://m.media-amazon.com/images/M/MV5BMTU0MDk5OTQyM15BMl5BanBnXkFtZTYwMDY3ODc3._V1_FMjpg_UX1000_.jpg', 'Alan Rickman, Emily Hampshire, Jackie Brown, Callum Keith Rennie, Scott Wickware, Johnny Goltz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (49530, 'Blood Diamond', 'Action,Adventure,Crime,Drama,Thriller,War', 2006, 'Edward Zwick', 'A fisherman, a smuggler, and a syndicate of businessmen match wits over the possession of a priceless diamond.', 'https://m.media-amazon.com/images/M/MV5BOGYzOGI0YTUtNTAwYy00M2JhLTgyODEtMjlhZTk1Yzc5ZTBhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Djimon Hounsou, Jennifer Connelly, Kagiso Kuypers, Arnold Vosloo, Antony Coleman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (49910, 'Freedom Writers', 'Drama', 2007, 'Richard LaGravenese', 'Erin Gruwell, a young teacher in a racially divided Los Angeles school, inspires her class of at-risk students, deemed incapable of learning, to learn tolerance, apply themselves, and pursue education beyond high school.', 'https://m.media-amazon.com/images/M/MV5BZDFjNWQ5MzktOThjZS00NmY5LWEwNTMtNGFhZGNhYjc3NzBmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Hilary Swank, Patrick Dempsey, Scott Glenn, Imelda Staunton, April Hernandez Castillo, Mario', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (50872, 'Ratatouille', 'Animation,Children,Drama', 2007, 'Brad Bird', 'A rat who can cook makes an unusual alliance with a young kitchen worker at a famous Paris restaurant.', 'https://m.media-amazon.com/images/M/MV5BMTMzODU0NTkxMF5BMl5BanBnXkFtZTcwMjQ4MzMzMw@@._V1_FMjpg_UX1000_.jpg', 'Patton Oswalt, Ian Holm, Lou Romano, Brian Dennehy, Peter Sohn, Peter O\'Toole', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (51086, 'Number 23, The', 'Drama,Mystery,Thriller', 2007, 'Joel Schumacher', 'Walter Sparrow becomes obsessed with a novel that he believes was written about him, as more and more similarities between himself and his literary alter ego seem to arise.', 'https://m.media-amazon.com/images/M/MV5BYWYwNmZlZWEtZmVmYy00NTU2LTk5MjUtY2I3ZmY4OGQ0OGVkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jim Carrey, Virginia Madsen, Logan Lerman, Danny Huston, Lynn Collins, Rhona Mitra', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (51255, 'Hot Fuzz', 'Action,Comedy,Crime,Mystery', 2007, 'Edgar Wright', 'An overachieving London police sergeant is transferred to a village where the easygoing officers object to his fervor for regulations, all while a string of grisly murders strikes the town.', 'https://m.media-amazon.com/images/M/MV5BYjFkZTkzZTQtNjM1ZS00M2EyLWE3MTAtMmY5Yzk0NTc0NDc3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Simon Pegg, Martin Freeman, Bill Nighy, Robert Popper, Joe Cornish, Chris Waitt', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (51540, 'Zodiac', 'Crime,Drama,Thriller', 2007, 'David Fincher', 'Between 1968 and 1983, a San Francisco cartoonist becomes an amateur detective obsessed with tracking down the Zodiac Killer, an unidentified individual who terrorizes Northern California with a killing spree.', 'https://m.media-amazon.com/images/M/MV5BNDFkMTRkZmQtM2I0NC00NjJjLWJlMDctNTNiZWYxYzhjZDZiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jake Gyllenhaal, Mark Ruffalo, Anthony Edwards, Robert Downey Jr., Brian Cox, John Carroll Lynch', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (51662, '300', 'Action,Fantasy,War,IMAX', 2007, 'Zack Snyder', 'In the ancient battle of Thermopylae, King Leonidas and 300 Spartans fight against Xerxes and his massive Persian army.', 'https://m.media-amazon.com/images/M/MV5BMjc4OTc0ODgwNV5BMl5BanBnXkFtZTcwNjM1ODE0MQ@@._V1_FMjpg_UX1000_.jpg', 'Gerard Butler, Lena Headey, Dominic West, David Wenham, Vincent Regan, Michael Fassbender', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (51931, 'Reign Over Me', 'Drama', 2007, 'Mike Binder', 'A man who lost his family in the September 11 attack on New York City runs into his old college roommate. Rekindling the friendship is the one thing that appears able to help the man recover from his grief.', 'https://m.media-amazon.com/images/M/MV5BOTYyMTExNTgwNF5BMl5BanBnXkFtZTcwMDY4MTEzMw@@._V1_FMjpg_UX1000_.jpg', 'Adam Sandler, Don Cheadle, Jada Pinkett Smith, Liv Tyler, Saffron Burrows, Donald Sutherland', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (51935, 'Shooter', 'Action,Drama,Thriller', 2007, 'Antoine Fuqua', 'An expert marksman living in exile, is coaxed back into action after learning of a plot to kill the president. Now on the run after being double crossed for the assassination attempt he was trying to prevent, he sets out for the real killer, and the truth.', 'https://m.media-amazon.com/images/M/MV5BYmE0NWZiMjktY2U4MC00MDVmLTljMGMtMWZiMThiNjczNzViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mark Wahlberg, Michael Peña, Danny Glover, Kate Mara, Elias Koteas, Rhona Mitra', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (52241, 'Lookout, The', 'Crime,Drama,Thriller', 2007, 'Scott Frank', 'Chris is a once promising high school athlete whose life is turned upside down following a tragic accident. As he tries to maintain a normal life, he takes a job as a janitor at a bank, where he ultimately finds himself caught up in a planned heist.', 'https://m.media-amazon.com/images/M/MV5BMjkyMzE5Nzg0OV5BMl5BanBnXkFtZTcwNTM3MzU0MQ@@._V1_FMjpg_UX1000_.jpg', 'Joseph Gordon-Levitt, Jeff Daniels, Matthew Goode, Isla Fisher, Carla Gugino, Bruce McGill', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (52281, 'Grindhouse', 'Action,Crime,Horror,Sci-Fi,Thriller', 2007, 'Robert Rodriguez', 'Quentin Tarantino and Robert Rodriguez\'s homage to exploitation double features in the \'60s and \'70s with two back-to-back cult films that include previews of coming attractions between them.', 'https://m.media-amazon.com/images/M/MV5BMjA0MzExNzc3MV5BMl5BanBnXkFtZTcwODAxMzM0MQ@@._V1_FMjpg_UX1000_.jpg', 'Kurt Russell, Zoë Bell, Rosario Dawson, Vanessa Ferlito, Sydney Tamiia Poitier, Tracie Thoms', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (52328, 'Sunshine', 'Adventure,Drama,Sci-Fi,Thriller', 2007, 'Danny Boyle', 'A team of international astronauts is sent on a dangerous mission to reignite the dying Sun with a nuclear fission bomb in 2057.', 'https://m.media-amazon.com/images/M/MV5BNmExYTA4MGYtNWUwNC00YTZhLWE0YzUtMjI0OGYyMmQ4YTVkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cliff Curtis, Chipo Chung, Cillian Murphy, Michelle Yeoh, Hiroyuki Sanada, Rose Byrne', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (52604, 'Fracture', 'Crime,Drama,Mystery,Thriller', 2007, 'Gregory Hoblit', 'After shooting his wife, Ted confesses his crime and asks the court to move his case to trial. He represents himself against Willy, a successful lawyer. But there\'s more to the case than meets the eye.', 'https://m.media-amazon.com/images/M/MV5BMzIzNjQyMzkwM15BMl5BanBnXkFtZTcwOTg5ODQ0MQ@@._V1_FMjpg_UX1000_.jpg', 'Anthony Hopkins, Ryan Gosling, David Strathairn, Rosamund Pike, Embeth Davidtz, Billy Burke', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (52722, 'Spider-Man 3', 'Action,Adventure,Sci-Fi,Thriller,IMAX', 2007, 'Sam Raimi', 'A strange black entity from another world bonds with Peter Parker and causes inner turmoil as he contends with new villains, temptations, and revenge.', 'https://m.media-amazon.com/images/M/MV5BODE2NzNhMDctYjUzMC00Y2M5LWI2Y2EtODJkZTFjN2Y5ODlmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tobey Maguire, Kirsten Dunst, James Franco, Thomas Haden Church, Topher Grace, Bryce Dallas Howard', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (52885, 'Paprika (Papurika)', 'Animation,Mystery,Sci-Fi', 2006, 'Satoshi Kon', 'When a machine that allows therapists to enter their patients\' dreams is stolen, all hell breaks loose. Only a young female therapist, Paprika, can stop it.', 'https://m.media-amazon.com/images/M/MV5BZGJkYjkyMDUtM2U3ZC00NDM3LWI0MzItZjU5MmYwYjg2YmIwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Megumi Hayashibara, Tôru Furuya, Kôichi Yamadera, Katsunosuke Hori, Tôru Emori, Akio Ôtsuka', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (52973, 'Knocked Up', 'Comedy,Drama,Romance', 2007, 'Judd Apatow', 'For fun-loving party animal Ben Stone, the last thing he ever expected was for his one-night stand to show up on his doorstep eight weeks later to tell him she\'s pregnant with his child.', 'https://m.media-amazon.com/images/M/MV5BYmIyMDA5YzgtZmNhMC00YWNlLTgwYjItOTc0ZGNjNTcwNzAxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Seth Rogen, Katherine Heigl, Paul Rudd, Leslie Mann, Jason Segel, Jay Baruchel', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (53000, '28 Weeks Later', 'Horror,Sci-Fi,Thriller', 2007, 'Juan Carlos Fresnadillo', 'Six months after the rage virus was inflicted on the population of Great Britain, the US Army helps to secure a small area of London for the survivors to repopulate and start again. But not everything goes according to plan.', 'https://m.media-amazon.com/images/M/MV5BMTUxMjc2MTcxNV5BMl5BanBnXkFtZTcwMzgzOTY0MQ@@._V1_FMjpg_UX1000_.jpg', 'Robert Carlyle, Rose Byrne, Jeremy Renner, Harold Perrineau, Catherine McCormack, Idris Elba', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (53123, 'Once', 'Drama,Musical,Romance', 2006, 'John Carney', 'A modern-day musical about a busker and an immigrant and their eventful week in Dublin, as they write, rehearse and record songs that tell their love story.', 'https://m.media-amazon.com/images/M/MV5BYmFmZmRkNzYtMTcyNy00NjY3LTkyNTUtNGExZjViNGFhZDdkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Glen Hansard, Markéta Irglová, Hugh Walsh, Gerard Hendrick, Alaistair Foley, Geoff Minogue', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (53125, 'Pirates of the Caribbean: At World\'s End', 'Action,Adventure,Comedy,Fantasy', 2007, 'Gore Verbinski', 'Will Turner, Elizabeth Swann, Hector Barbossa, and the crew of the Black Pearl try and rescue Jack from davy jones locker and prepare to fight Lord Cutler Beckett, who controls Davy Jones and the Flying Dutchman.', 'https://m.media-amazon.com/images/M/MV5BMjIyNjkxNzEyMl5BMl5BanBnXkFtZTYwMjc3MDE3._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Geoffrey Rush, Orlando Bloom, Keira Knightley, Jack Davenport, Bill Nighy', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (53129, 'Mr. Brooks', 'Crime,Drama,Thriller', 2007, 'Bruce A. Evans', 'A well-respected businessman is sometimes controlled by his murder and mayhem-loving alter ego.', 'https://m.media-amazon.com/images/M/MV5BMTQyNTk5MTMxN15BMl5BanBnXkFtZTcwNTc0ODI1NA@@._V1_FMjpg_UX1000_.jpg', 'Kevin Costner, Demi Moore, Dane Cook, William Hurt, Marg Helgenberger, Ruben Santiago-Hudson', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (53161, 'I\'m a Cyborg, But That\'s OK (Saibogujiman kwenchana)', 'Comedy,Drama,Romance,Sci-Fi', 2006, 'Park Chan-wook', 'A girl who thinks she is a combat cyborg checks into a mental hospital, where she encounters other psychotics. Eventually, she falls for a man who thinks he can steal people\'s souls.', 'https://m.media-amazon.com/images/M/MV5BMTAwMjQ0NjQzMTReQTJeQWpwZ15BbWU4MDEyNjg3NTIx._V1_FMjpg_UX1000_.jpg', 'Lim Soo-jung, Rain, Park Byeong-eun, Kim Byeong-Ok, Seong-hun Cheon, Oh Dal-su', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (53189, 'Eagle vs Shark', 'Comedy', 2007, 'Taika Waititi', 'The tale of two socially-awkward misfits and the strange ways they try to find love: through revenge on high-school bullies, burgers, and video games.', 'https://m.media-amazon.com/images/M/MV5BOTUxMzY3MzI0NV5BMl5BanBnXkFtZTcwMDUwMDU0MQ@@._V1_FMjpg_UX1000_.jpg', 'Loren Taylor, Jemaine Clement, Joel Tobeck, Brian Sergent, Craig Hall, Rachel House', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (53322, 'Ocean\'s Thirteen', 'Crime,Thriller', 2007, 'Steven Soderbergh', 'Danny Ocean rounds up the boys for a third heist after casino owner Willy Bank double-crosses one of the original eleven, Reuben Tishkoff.', 'https://m.media-amazon.com/images/M/MV5BMTMyNTc1NzY5MV5BMl5BanBnXkFtZTcwNDM4NTQzMw@@._V1_FMjpg_UX1000_.jpg', 'George Clooney, Brad Pitt, Matt Damon, Michael Mantell, Elliott Gould, Ray Xifo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (53519, 'Death Proof', 'Action,Adventure,Crime,Horror,Thriller', 2007, 'Quentin Tarantino', 'Two separate sets of voluptuous women are stalked at different times by a scarred stuntman who uses his \"death proof\" cars to execute his murderous plans.', 'https://m.media-amazon.com/images/M/MV5BYjRlOTM0OTktZTBjNi00ZjZiLWJkMzktMmU2ZDBkMTQxN2FmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kurt Russell, Zoë Bell, Rosario Dawson, Vanessa Ferlito, Sydney Tamiia Poitier, Tracie Thoms', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (53953, '1408', 'Drama,Horror,Thriller', 2007, 'Mikael Håfström', 'Author Michael Enslin, who specializes in debunking paranormal occurrences, checks into the fabled room 1408 in the Dolphin Hotel in New York City, settles in, and soon confronts genuine terror.', 'https://m.media-amazon.com/images/M/MV5BMjQ2ODkxMjc4OV5BMl5BanBnXkFtZTgwMTgzNzQyMTI@._V1_FMjpg_UX1000_.jpg', 'John Cusack, Tony Shalhoub, Len Cariou, Isiah Whitlock Jr., Jasmine Jessica Anthony, Paul Birchard', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (54001, 'Harry Potter and the Order of the Phoenix', 'Adventure,Drama,Fantasy,IMAX', 2007, 'David Yates', 'With their warning about Lord Voldemort\'s return scoffed at, Harry and Dumbledore are targeted by the Wizard authorities as an authoritarian bureaucrat slowly seizes power at Hogwarts.', 'https://m.media-amazon.com/images/M/MV5BYWJmM2M1YzItMjY1Ni00YzRmLTg5YWYtNDFmNTJjNzQ0ODkyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Daniel Radcliffe, Harry Melling, Jason Boyd, Richard Macklin, Kathryn Hunter, Miles Jupp', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (54259, 'Stardust', 'Adventure,Comedy,Fantasy,Romance', 2007, 'Matthew Vaughn', 'In a countryside town bordering on a magical land, a young man makes a promise to his beloved that he\'ll retrieve a fallen star by venturing into the magical realm.', 'https://m.media-amazon.com/images/M/MV5BMjkyMTE1OTYwNF5BMl5BanBnXkFtZTcwMDIxODYzMw@@._V1_FMjpg_UX1000_.jpg', 'Ian McKellen, Bimbo Hart, Alastair MacIntosh, David Kelly, Ben Barnes, Kate Magowan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (54272, 'Simpsons Movie, The', 'Animation,Comedy', 2007, 'David Silverman', 'After Homer pollutes the town\'s water supply, Springfield is encased in a gigantic dome by the EPA and the Simpsons are declared fugitives.', 'https://m.media-amazon.com/images/M/MV5BMzIxN2IzOGItOTcyZi00MTkzLWE4ZjktZTdlOWFiYWE4NzlmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dan Castellaneta, Julie Kavner, Nancy Cartwright, Yeardley Smith, Hank Azaria, Harry Shearer', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (54286, 'Bourne Ultimatum, The', 'Action,Crime,Thriller', 2007, 'Paul Greengrass', 'Jason Bourne dodges a ruthless C.I.A. official and his Agents from a new assassination program while searching for the origins of his life as a trained killer.', 'https://m.media-amazon.com/images/M/MV5BYzE3ZGM4MzctZjU5MC00NWE2LTg5ZjYtMDFiM2ZlMWQ1MjkwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matt Damon, Julia Stiles, David Strathairn, Scott Glenn, Paddy Considine, Edgar Ramírez', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (54503, 'Superbad', 'Comedy', 2007, 'Greg Mottola', 'Two co-dependent high school seniors are forced to deal with separation anxiety after their plan to stage a booze-soaked party goes awry.', 'https://m.media-amazon.com/images/M/MV5BNjk0MzdlZGEtNTRkOC00ZDRiLWJkYjAtMzUzYTRiNzk1YTViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jonah Hill, Michael Cera, Christopher Mintz-Plasse, Bill Hader, Seth Rogen, Martha MacIsaac', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (54648, 'Rush Hour 3', 'Action,Comedy,Crime,Thriller', 2007, 'Brett Ratner', 'After an attempted assassination on Ambassador Han, Lee and Carter head to Paris to protect a French woman with knowledge of the Triads\' secret leaders.', 'https://m.media-amazon.com/images/M/MV5BMTA0Nzg5NjQ0MDBeQTJeQWpwZ15BbWU3MDE4Mzg5NDE@._V1_FMjpg_UX1000_.jpg', 'Chris Tucker, Jackie Chan, Max von Sydow, Hiroyuki Sanada, Yvan Attal, Yûki Kudô', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (54995, 'Planet Terror', 'Action,Horror,Sci-Fi', 2007, 'Robert Rodriguez', 'After an experimental bio-weapon is released, turning thousands into zombie-like creatures, it\'s up to a rag-tag group of survivors to stop the infected and those behind its release.', 'https://m.media-amazon.com/images/M/MV5BNmEzZTAxNDQtN2ZmMy00NGNlLWI3NDYtNGI3ZTlkNWU1NWZhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Rose McGowan, Freddy Rodríguez, Josh Brolin, Marley Shelton, Jeff Fahey, Michael Biehn', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (54997, '3:10 to Yuma', 'Action,Crime,Drama,Western', 2007, 'James Mangold', 'A small-time rancher agrees to hold a captured outlaw who\'s awaiting a train to go to court in Yuma. A battle of wills ensues as the outlaw tries to psych out the rancher.', 'https://m.media-amazon.com/images/M/MV5BODE0NTcxNTQzNF5BMl5BanBnXkFtZTcwMzczOTIzMw@@._V1_FMjpg_UX1000_.jpg', 'Russell Crowe, Christian Bale, Logan Lerman, Dallas Roberts, Ben Foster, Peter Fonda', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55063, 'My Winnipeg', 'Documentary,Fantasy', 2007, 'Guy Maddin', 'Fact, fantasy and memory are woven seamlessly together in this portrait of film-maker Guy Maddin\'s home town of Winnipeg, Manitoba.', 'https://m.media-amazon.com/images/M/MV5BMjE2Nzk1MjE4OV5BMl5BanBnXkFtZTcwNjk2ODA3MQ@@._V1_FMjpg_UX1000_.jpg', 'Ann Savage, Louis Negin, Amy Stewart, Darcy Fehr, Brendan Cade, Wesley Cade', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55094, 'In the Valley of Elah', 'Drama,Mystery', 2007, 'Paul Haggis', 'A retired military investigator works with a police detective to uncover the truth behind his son\'s disappearance following his return from a tour of duty in Iraq.', 'https://m.media-amazon.com/images/M/MV5BNzQwNzI3NzMtMGQ1Ny00NzU0LWIxMDUtMTNjMDc5M2I5NjQ0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tommy Lee Jones, Charlize Theron, Jason Patric, Susan Sarandon, James Franco, Barry Corbin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55118, 'Eastern Promises', 'Crime,Drama,Thriller', 2007, 'David Cronenberg', 'A teenager who dies during childbirth leaves clues in her journal that could tie her child to a rape involving a violent Russian mob family.', 'https://m.media-amazon.com/images/M/MV5BMTcwMzU0OTY3NF5BMl5BanBnXkFtZTYwNzkwNjg2._V1_FMjpg_UX1000_.jpg', 'Josef Altin, Mina E. Mina, Aleksandar Mikic, Sarah-Jeanne Labrosse, Lalita Ahmed, Badi Uzzaman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55247, 'Into the Wild', 'Action,Adventure,Drama', 2007, 'Sean Penn', 'After graduating from Emory University, top student and athlete Christopher McCandless abandons his possessions, gives his entire $24,000 savings account to charity and hitchhikes to Alaska to live in the wilderness.', 'https://m.media-amazon.com/images/M/MV5BNTgwZTJhNWMtNzVjMy00YzQzLWI4MTAtYmJhOGQ5ZmQ3MDM0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Emile Hirsch, Marcia Gay Harden, William Hurt, Jena Malone, Brian H. Dierker, Catherine Keener', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55269, 'Darjeeling Limited, The', 'Adventure,Comedy,Drama', 2007, 'Wes Anderson', 'A year after their father\'s funeral, three brothers travel across India by train in an attempt to bond with each other.', 'https://m.media-amazon.com/images/M/MV5BZDY4Mzc2YTQtZDg4ZS00OGIzLWJhOGMtOTQ2OThmNzg4NTc4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Owen Wilson, Adrien Brody, Jason Schwartzman, Amara Karan, Wallace Wolodarsky, Waris Ahluwalia', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55276, 'Michael Clayton', 'Drama,Thriller', 2007, 'Tony Gilroy', 'A law firm brings in its \"fixer\" to remedy the situation after a lawyer has a breakdown while representing a chemical company that he knows is guilty in a multibillion-dollar class action suit.', 'https://m.media-amazon.com/images/M/MV5BMTc0NTU5MjI2MV5BMl5BanBnXkFtZTcwMTg5NTQzMw@@._V1_FMjpg_UX1000_.jpg', 'Tom Wilkinson, Michael O\'Keefe, Sydney Pollack, Danielle Skraastad, Tilda Swinton, George Clooney', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55280, 'Lars and the Real Girl', 'Comedy,Drama', 2007, 'Craig Gillespie', 'A delusional young man strikes up an unconventional relationship with a doll he finds on the Internet.', 'https://m.media-amazon.com/images/M/MV5BZThiOTA4N2UtNzJiYS00MDI0LWI3OWItYzYxYzU3M2YwM2M4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ryan Gosling, Emily Mortimer, Paul Schneider, R.D. Reid, Kelli Garner, Nancy Beatty', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55282, '30 Days of Night', 'Horror,Thriller', 2007, 'David Slade', 'After an Alaskan town is plunged into darkness for a month, it is attacked by a bloodthirsty gang of vampires.', 'https://m.media-amazon.com/images/M/MV5BZWVjOTM3NmItZjU1Mi00YTVjLTlkM2YtNTJlYjI2YzUyNmUxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Josh Hartnett, Melissa George, Danny Huston, Ben Foster, Mark Boone Junior, Mark Rendall', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55290, 'Gone Baby Gone', 'Crime,Drama,Mystery', 2007, 'Ben Affleck', 'Two Boston area detectives investigate a little girl\'s kidnapping, which ultimately turns into a crisis both professionally and personally.', 'https://m.media-amazon.com/images/M/MV5BOTlmNmU2NDgtZDU1OS00OTFhLWJlNTgtMWE2OGQ1OTg1MGM4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Casey Affleck, Michelle Monaghan, Morgan Freeman, Ed Harris, John Ashton, Amy Ryan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55363, 'Assassination of Jesse James by the Coward Robert Ford, The', 'Crime,Drama,Western', 2007, 'Andrew Dominik', 'Robert Ford, who has idolized Jesse James since childhood, tries hard to join the resurgent gang of the Missouri outlaw, but gradually becomes resentful of the bandit leader.', 'https://m.media-amazon.com/images/M/MV5BMTY2NDI2MTc2NV5BMl5BanBnXkFtZTcwNjA2NTQzMw@@._V1_FMjpg_UX1000_.jpg', 'Brad Pitt, Mary-Louise Parker, Brooklynn Proulx, Dustin Bollinger, Casey Affleck, Sam Rockwell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55442, 'Persepolis', 'Animation,Drama', 2007, 'Vincent Paronnaud', 'A precocious and outspoken Iranian girl grows up during the Islamic Revolution.', 'https://m.media-amazon.com/images/M/MV5BNzk3NTI2NGUtNmM1Yy00YTRmLWE2YTItZTYyNGM0ZjdjOTliXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chiara Mastroianni, Catherine Deneuve, Danielle Darrieux, Simon Abkarian, Gabrielle Lopes Benites, François Jerosme', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55555, 'Edge of Heaven, The (Auf der anderen Seite)', 'Drama', 2007, 'Fatih Akin', 'A Turkish man travels to Istanbul to find the daughter of his father\'s former girlfriend.', 'https://m.media-amazon.com/images/M/MV5BNjgxMDQ5ZGUtZDk0MS00MDkzLWIxNDMtZmE0M2VhMjU3NTg2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Baki Davrak, Gürsoy Gemec, Cengiz Daner, Tuncel Kurtiz, Nursel Köse, Nurgül Yesilçay', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55577, 'Saw IV', 'Crime,Horror,Thriller', 2007, 'Darren Lynn Bousman', 'Despite Jigsaw\'s death, and in order to save the lives of two of his colleagues, Lieutenant Rigg is forced to take part in a new game, which promises to test him to the limit.', 'https://m.media-amazon.com/images/M/MV5BNjc0NjUyNzg3MF5BMl5BanBnXkFtZTYwODMxOTM3._V1_FMjpg_UX1000_.jpg', 'Tobin Bell, Costas Mandylor, Scott Patterson, Betsy Russell, Lyriq Bent, Athena Karkanis', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55765, 'American Gangster', 'Crime,Drama,Thriller', 2007, 'Ridley Scott', 'An outcast New York City cop is charged with bringing down Harlem drug lord Frank Lucas.', 'https://m.media-amazon.com/images/M/MV5BZGExM2MwNjUtNThkNi00ZjBmLWJhZDgtN2ZmOWJiZWEwNGMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Denzel Washington, Russell Crowe, Chiwetel Ejiofor, Josh Brolin, Lymari Nadal, Ted Levine', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55820, 'No Country for Old Men', 'Crime,Drama', 2007, 'Ethan Coen', 'Violence and mayhem ensue after a hunter stumbles upon the aftermath of a drug deal gone wrong and over two million dollars in cash near the Rio Grande.', 'https://m.media-amazon.com/images/M/MV5BMjA5Njk3MjM4OV5BMl5BanBnXkFtZTcwMTc5MTE1MQ@@._V1_FMjpg_UX1000_.jpg', 'Tommy Lee Jones, Javier Bardem, Josh Brolin, Woody Harrelson, Kelly Macdonald, Garret Dillahunt', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (55908, 'Man from Earth, The', 'Drama,Sci-Fi', 2007, 'Richard Schenkman', 'An impromptu goodbye party for Professor John Oldman becomes a mysterious interrogation after the retiring scholar reveals to his colleagues he has a longer and stranger past than they can imagine.', 'https://m.media-amazon.com/images/M/MV5BOTE1NGYxNjgtYmVlMS00ODEwLTg2NjAtMTdjODMzY2I1ZjZmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'David Lee Smith, Tony Todd, John Billingsley, Ellen Crawford, Annika Peterson, William Katt', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (56145, 'Mist, The', 'Horror,Sci-Fi', 2007, 'Frank Darabont', 'After a massive thunderstorm, an eerie, unwavering fog descends upon a Maine community. Locals seek refuge in a grocery store from the monstrous creatures now roaming the countryside killing everyone they encounter.', 'https://m.media-amazon.com/images/M/MV5BMTU2NjQyNDY1Ml5BMl5BanBnXkFtZTcwMTk1MDU1MQ@@._V1_FMjpg_UX1000_.jpg', 'Thomas Jane, Marcia Gay Harden, Laurie Holden, Andre Braugher, Toby Jones, William Sadler', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (56152, 'Enchanted', 'Adventure,Animation,Children,Comedy,Fantasy,Musical,Romance', 2007, 'Kevin Lima', 'A young maiden in a land called Andalasia, who is prepared to be wed, is sent away to New York City by an evil Queen, where she falls in love with a lawyer.', 'https://m.media-amazon.com/images/M/MV5BMjE4NDQ2Mjc0OF5BMl5BanBnXkFtZTcwNzQ2NDE1MQ@@._V1_FMjpg_UX1000_.jpg', 'Amy Adams, Patrick Dempsey, James Marsden, Timothy Spall, Idina Menzel, Rachel Covey', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (56174, 'I Am Legend', 'Action,Horror,Sci-Fi,Thriller,IMAX', 2007, 'Francis Lawrence', 'Years after a plague kills most of humanity and transforms the rest into monsters, the sole survivor in New York City struggles valiantly to find a cure.', 'https://m.media-amazon.com/images/M/MV5BMGE1OWZkZmItNmVhMC00YzAxLTgxOTctNjg3NWExM2RmOWJkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Will Smith, Alice Braga, Charlie Tahan, Salli Richardson-Whitfield, Willow Smith, Darrell Foster', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (56367, 'Juno', 'Comedy,Drama,Romance', 2007, 'Jason Reitman', 'Faced with an unplanned pregnancy, an offbeat young woman makes a selfless decision regarding the unborn child.', 'https://m.media-amazon.com/images/M/MV5BMTIwMDgwODc5Nl5BMl5BanBnXkFtZTYwMjQzMDM4._V1_FMjpg_UX1000_.jpg', 'Elliot Page, Michael Cera, Jennifer Garner, Jason Bateman, Allison Janney, J.K. Simmons', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (56587, 'Bucket List, The', 'Comedy,Drama', 2007, 'Rob Reiner', 'Two terminally ill men escape from a cancer ward and head off on a road trip with a wish list of to-dos before they die.', 'https://m.media-amazon.com/images/M/MV5BMTY2NTUyMjIyNF5BMl5BanBnXkFtZTYwNzYwMDM4._V1_FMjpg_UX1000_.jpg', 'Jack Nicholson, Morgan Freeman, Sean Hayes, Beverly Todd, Rob Morrow, Alfonso Freeman', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (56607, 'Kite Runner, The', 'Drama', 2007, 'Marc Forster', 'Amir lives in California with his wife Soraya. He receives a call from his uncle Rahim Khan who urges him to travel to Afghanistan and rescue the son of Amir\'s childhood servant and friend, Hassan.', 'https://m.media-amazon.com/images/M/MV5BMmRmZmU3YzgtN2ZhYi00ZmUxLWJhYzUtYjFlMmJlZDZmNTBiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Khalid Abdalla, Atossa Leoni, Shaun Toub, Sayed Jafar Masihullah Gharibzada, Zekeria Ebrahimi, Ahmad Khan Mahmoodzada', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (56757, 'Sweeney Todd: The Demon Barber of Fleet Street', 'Drama,Horror,Musical,Thriller', 2007, 'Tim Burton', 'The legendary tale of a barber who returns from wrongful imprisonment to 1840s London, bent on revenge for the rape and death of his wife, and resumes his trade while forming a sinister partnership with his fellow tenant, Mrs. Lovett.', 'https://m.media-amazon.com/images/M/MV5BMTg3NjUxMzM5NV5BMl5BanBnXkFtZTcwMzQ1NjQzMw@@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Helena Bonham Carter, Alan Rickman, Timothy Spall, Sacha Baron Cohen, Jamie Campbell Bower', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (56782, 'There Will Be Blood', 'Drama,Western', 2007, 'Paul Thomas Anderson', 'A story of family, religion, hatred, oil and madness, focusing on a turn-of-the-century prospector in the early days of the business.', 'https://m.media-amazon.com/images/M/MV5BMjAxODQ4MDU5NV5BMl5BanBnXkFtZTcwMDU4MjU1MQ@@._V1_FMjpg_UX1000_.jpg', 'Daniel Day-Lewis, Martin Stringer, Matthew Braden Stringer, Jacob Stringer, Joseph Mussey, Barry Del Sherman', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (56949, '27 Dresses', 'Comedy,Romance', 2008, 'Anne Fletcher', 'After serving as a bridesmaid 27 times, a young woman wrestles with the idea of standing by her sister\'s side as her sibling marries the man she\'s secretly in love with.', 'https://m.media-amazon.com/images/M/MV5BZWM3ZjRiNGUtNmZkMy00YWNkLWI5MGUtYWI1NTc5NGVkODJkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brian Kerwin, Charli Barcena, Peyton List, Jane Pfitsch, Katherine Heigl, Jennifer Lim', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (57274, '[REC]', 'Drama,Horror,Thriller', 2007, 'Jaume Balagueró', 'A television reporter and cameraman follow emergency workers into a dark apartment building and are quickly locked inside with something terrifying.', 'https://m.media-amazon.com/images/M/MV5BMDEzNDc5ODMtZTAyNi00MTNkLThkNGUtZGE2MDY0MjBiYjMzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Manuela Velasco, Ferran Terraza, Jorge-Yamam Serrano, Pablo Rosso, David Vert, Vicente Gil', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (57368, 'Cloverfield', 'Action,Mystery,Sci-Fi,Thriller', 2008, 'Matt Reeves', 'A group of friends venture deep into the streets of New York on a rescue mission during a rampaging monster attack.', 'https://m.media-amazon.com/images/M/MV5BOWM3NmYyMjAtMjU3YS00MDJjLThmNDItNWUzZmFmMzk5NTEyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Lizzy Caplan, Jessica Lucas, T.J. Miller, Michael Stahl-David, Mike Vogel, Odette Annable', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (57520, 'One Missed Call', 'Horror,Mystery,Thriller', 2008, 'Eric Valette', 'Several people start receiving voice-mails from their future selves - messages which include the date, time, and some of the details of their deaths.', 'https://m.media-amazon.com/images/M/MV5BMjA2NTk0OTcyMV5BMl5BanBnXkFtZTcwMzk1MDU1MQ@@._V1_FMjpg_UX1000_.jpg', 'Shannyn Sossamon, Edward Burns, Ana Claudia Talancón, Ray Wise, Azura Skye, Johnny Lewis', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (57669, 'In Bruges', 'Comedy,Crime,Drama,Thriller', 2008, 'Martin McDonagh', 'After a job gone wrong, hitman Ray and his partner await orders from their ruthless boss in Bruges, Belgium, the last place in the world Ray wants to be.', 'https://m.media-amazon.com/images/M/MV5BNjliZjBlNDItOWUyZC00ZTExLTg5NmUtNzE5ZmQyZWVmZmE5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Elizabeth Berrington, Rudy Blomme, Olivier Bonjour, Mark Donovan, Ann Elsley, Colin Farrell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (58559, 'Dark Knight, The', 'Action,Crime,Drama,IMAX', 2008, 'Christopher Nolan', 'When a menace known as the Joker wreaks havoc and chaos on the people of Gotham, Batman, James Gordon and Harvey Dent must work together to put an end to the madness.', 'https://m.media-amazon.com/images/M/MV5BMTMxNTMwODM0NF5BMl5BanBnXkFtZTcwODAyMTk2Mw@@._V1_FMjpg_UX1000_.jpg', 'Christian Bale, Heath Ledger, Aaron Eckhart, Michael Caine, Maggie Gyllenhaal, Gary Oldman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (58998, 'Forgetting Sarah Marshall', 'Comedy,Romance', 2008, 'Nicholas Stoller', 'Devastated Peter takes a Hawaiian vacation in order to deal with the recent break-up with his TV star girlfriend, Sarah. Little does he know, Sarah\'s traveling to the same resort as her ex - and she\'s bringing along her new boyfriend.', 'https://m.media-amazon.com/images/M/MV5BMTYzODgzMjAyM15BMl5BanBnXkFtZTcwMTI3NzI2MQ@@._V1_FMjpg_UX1000_.jpg', 'Jason Segel, Kristen Bell, Mila Kunis, Russell Brand, Bill Hader, Liz Cackowski', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (59315, 'Iron Man', 'Action,Adventure,Sci-Fi', 2008, 'Jon Favreau', 'After being held captive in an Afghan cave, billionaire engineer Tony Stark creates a unique weaponized suit of armor to fight evil.', 'https://m.media-amazon.com/images/M/MV5BMTczNTI2ODUwOF5BMl5BanBnXkFtZTcwMTU0NTIzMw@@._V1_FMjpg_UX1000_.jpg', 'Robert Downey Jr., Terrence Howard, Jeff Bridges, Gwyneth Paltrow, Leslie Bibb, Shaun Toub', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (59369, 'Taken', 'Action,Crime,Drama,Thriller', 2008, 'Pierre Morel', 'A retired CIA agent travels across Europe and relies on his old skills to save his estranged daughter, who has been kidnapped while on a trip to Paris.', 'https://m.media-amazon.com/images/M/MV5BYTAxNTY2NjMtYjk5Yy00Nzg4LTkyMmItYmMzMDM2OWQ1ZGQ3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Liam Neeson, Maggie Grace, Leland Orser, Jon Gries, David Warshofsky, Holly Valance', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (59387, 'Fall, The', 'Adventure,Drama,Fantasy', 2006, 'Tarsem Singh', 'In 1920s Los Angeles, a bedridden patient in a hospital captivates a young girl with a fantastic tale of heroes, myths, and villains on a desert island.', 'https://m.media-amazon.com/images/M/MV5BMjAzODUwMjM1M15BMl5BanBnXkFtZTcwNjU2MjU2MQ@@._V1_FMjpg_UX1000_.jpg', 'Catinca Untaru, Justine Waddell, Lee Pace, Kim Uylenbroek, Aiden Lithgow, Sean Gilder', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (59421, 'What Happens in Vegas...', 'Comedy,Romance', 2008, 'Tom Vaughan', 'A man and a woman are compelled, for legal reasons, to live life as a couple for a limited period of time. At stake is a large amount of money.', 'https://m.media-amazon.com/images/M/MV5BNmU3NDdkNDktYWJjNC00ZDAyLWI4ODItZjdhYjg2ZjZhNzM1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cameron Diaz, Ashton Kutcher, Rob Corddry, Lake Bell, Jason Sudeikis, Treat Williams', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (59615, 'Indiana Jones and the Kingdom of the Crystal Skull', 'Action,Adventure,Comedy,Sci-Fi', 2008, 'Steven Spielberg', 'In 1957, Indiana Jones is called back into action when he becomes entangled in a Soviet plot to uncover the secret behind mysterious artifacts known as the Crystal Skulls.', 'https://m.media-amazon.com/images/M/MV5BYTFiMDk2NzItZDU5Ni00ZjBjLTkzYWQtYzcwZDIwMWZjMmZiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Harrison Ford, Cate Blanchett, Karen Allen, Shia LaBeouf, Ray Winstone, John Hurt', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (59727, 'Strangers, The', 'Horror,Thriller', 2008, 'Bryan Bertino', 'James Hoyt and Kristen McKay visit an isolated vacation home to enjoy some time together. However, they are in for a rude surprise when three masked assailants make their stay a nightmare.', 'https://m.media-amazon.com/images/M/MV5BMTkxODAyODMwNV5BMl5BanBnXkFtZTcwNzk5Nzk2MQ@@._V1_FMjpg_UX1000_.jpg', 'Alex Fisher, Peter Clayton-Luce, Scott Speedman, Liv Tyler, Gemma Ward, Kip Weeks', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (59784, 'Kung Fu Panda', 'Action,Animation,Children,Comedy,IMAX', 2008, 'Mark Osborne', 'To everyone\'s surprise, including his own, Po, an overweight, clumsy panda, is chosen as protector of the Valley of Peace. His suitability will soon be tested as the valley\'s arch-enemy is on his way.', 'https://m.media-amazon.com/images/M/MV5BZDU5MDNiMGItYjVmZi00NDUxLTg2OTktNGE0NzNlNzM4NzgyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jack Black, Dustin Hoffman, Angelina Jolie, Ian McShane, Jackie Chan, Seth Rogen', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (60040, 'Incredible Hulk, The', 'Action,Sci-Fi', 2008, 'Louis Leterrier', 'Bruce Banner, a scientist on the run from the U.S. Government, must find a cure for the monster he turns into whenever he loses his temper.', 'https://m.media-amazon.com/images/M/MV5BMTUyNzk3MjA1OF5BMl5BanBnXkFtZTcwMTE1Njg2MQ@@._V1_FMjpg_UX1000_.jpg', 'Edward Norton, Liv Tyler, Tim Roth, William Hurt, Tim Blake Nelson, Ty Burrell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (60069, 'WALL·E', 'Adventure,Animation,Children,Romance,Sci-Fi', 2008, 'Andrew Stanton', 'A robot who is responsible for cleaning a waste-covered Earth meets another robot and falls in love with her. Together, they set out on a journey that will alter the fate of mankind.', 'https://m.media-amazon.com/images/M/MV5BMjExMTg5OTU0NF5BMl5BanBnXkFtZTcwMjMxMzMzMw@@._V1_FMjpg_UX1000_.jpg', 'Ben Burtt, Elissa Knight, Jeff Garlin, Fred Willard, MacInTalk, John Ratzenberger', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (60074, 'Hancock', 'Action,Adventure,Comedy,Crime,Fantasy', 2008, 'Peter Berg', 'Hancock is a superhero whose ill-considered behavior regularly causes damage in the millions. He changes when the person he saves helps him improve his public image.', 'https://m.media-amazon.com/images/M/MV5BMTgyMzc4ODU3NV5BMl5BanBnXkFtZTcwNjk5Mzc1MQ@@._V1_FMjpg_UX1000_.jpg', 'Will Smith, Charlize Theron, Jason Bateman, Jae Head, Eddie Marsan, David Mattey', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (60514, 'Journey to the Center of the Earth', 'Action,Adventure,Sci-Fi', 2008, 'Eric Brevig', 'On a quest to find out what happened to his missing brother, a scientist, his nephew and their mountain guide discover a fantastic and dangerous lost world in the center of the earth.', 'https://m.media-amazon.com/images/M/MV5BNTMyMGQ4MWYtZmMyYi00M2JhLWFhZmQtNWM5MTVjYjk1MTYxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brendan Fraser, Josh Hutcherson, Aníta Briem, Seth Meyers, Jean Michel Paré, Jane Wheeler', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (60684, 'Watchmen', 'Action,Drama,Mystery,Sci-Fi,Thriller,IMAX', 2009, 'Zack Snyder', 'In a version of 1985 where superheroes exist, the murder of a colleague sends active vigilante Rorschach on the trail of a conspiracy that will change the course of history.', 'https://m.media-amazon.com/images/M/MV5BYmJiNTUwYWUtZDllNi00ODdjLWFmNTEtOTVlNmYxYTZhNzYzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Malin Akerman, Billy Crudup, Matthew Goode, Jackie Earle Haley, Jeffrey Dean Morgan, Patrick Wilson', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (60756, 'Step Brothers', 'Comedy', 2008, 'Adam McKay', 'Two aimless middle-aged losers still living at home are forced against their will to become roommates when their parents marry.', 'https://m.media-amazon.com/images/M/MV5BYWNiOGZkOTgtNGMzMC00MDg5LTliM2UtN2VjMDI3N2ViOWE5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Will Ferrell, John C. Reilly, Mary Steenburgen, Richard Jenkins, Adam Scott, Kathryn Hahn', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (61024, 'Pineapple Express', 'Action,Comedy,Crime', 2008, 'David Gordon Green', 'A process server and his marijuana dealer wind up on the run from hitmen and a corrupt police officer after he witnesses his dealer\'s boss murder a competitor while trying to serve papers on him.', 'https://m.media-amazon.com/images/M/MV5BMTY1MTE4NzAwM15BMl5BanBnXkFtZTcwNzg3Mjg2MQ@@._V1_FMjpg_UX1000_.jpg', 'Seth Rogen, James Franco, Danny McBride, Kevin Corrigan, Craig Robinson, Gary Cole', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (61132, 'Tropic Thunder', 'Action,Adventure,Comedy,War', 2008, 'Ben Stiller', 'Through a series of freak occurrences, a group of actors shooting a big-budget war movie are forced to become the soldiers they are portraying.', 'https://m.media-amazon.com/images/M/MV5BNDE5NjQzMDkzOF5BMl5BanBnXkFtZTcwODI3ODI3MQ@@._V1_FMjpg_UX1000_.jpg', 'Jeff Kahn, Robert Downey Jr., Anthony Ruivivar, Jack Black, Jay Baruchel, Brandon T. Jackson', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (61240, 'Let the Right One In (Låt den rätte komma in)', 'Drama,Fantasy,Horror,Romance', 2008, 'Tomas Alfredson', 'A bullied boy forms a unique friendship with his new neighbor, a peculiar girl with a dark secret.', 'https://m.media-amazon.com/images/M/MV5BNjgxZGFlYjktNjE2NC00YTkzLTlhY2QtNDJmMDhmMGEzOTcwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kåre Hedebrant, Lina Leandersson, Per Ragnar, Henrik Dahl, Karin Bergquist, Peter Carlberg', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (61262, 'Mirrors', 'Horror,Mystery,Thriller', 2008, 'Alexandre Aja', 'Ben guards a partly-destroyed property by night but begins to see strange images in its impeccable mirrors. After his sister is killed, he is convinced that evil forces are out to get him.', 'https://m.media-amazon.com/images/M/MV5BMTI2NTA1ODEyOF5BMl5BanBnXkFtZTcwNjc3MjY3MQ@@._V1_FMjpg_UX1000_.jpg', 'Kiefer Sutherland, Paula Patton, Cameron Boyce, Arika Gluck, Amy Smart, Mary Beth Peil', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (61323, 'Burn After Reading', 'Comedy,Crime,Drama', 2008, 'Ethan Coen', 'A disk containing mysterious information from a CIA agent ends up in the hands of two unscrupulous and daft gym employees who attempt to sell it.', 'https://m.media-amazon.com/images/M/MV5BMjdmNjJjMzAtMmJkMy00MDJlLTgxYjctNDU3YjBkMmJhM2M5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'George Clooney, Frances McDormand, Brad Pitt, John Malkovich, Tilda Swinton, Richard Jenkins', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (62374, 'Body of Lies', 'Action,Drama,Thriller', 2008, 'Ridley Scott', 'A CIA agent on the ground in Jordan hunts down a powerful terrorist leader while being caught between the unclear intentions of his American supervisors and Jordan Intelligence.', 'https://m.media-amazon.com/images/M/MV5BMTgzOTY3MTM0OV5BMl5BanBnXkFtZTcwNjc5MTI5MQ@@._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Russell Crowe, Mark Strong, Golshifteh Farahani, Oscar Isaac, Ali Suliman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (62376, 'City of Ember', 'Adventure,Children,Sci-Fi', 2008, 'Gil Kenan', 'For generations, the people of the City of Ember have flourished in an amazing world of glittering lights. But Ember\'s once powerful generator is failing and the great lamps that illuminate the city are starting to flicker.', 'https://m.media-amazon.com/images/M/MV5BMTU3MDE4MDU1Nl5BMl5BanBnXkFtZTcwNDM2NDI5MQ@@._V1_FMjpg_UX1000_.jpg', 'Saoirse Ronan, David Ryall, Harry Treadaway, Bill Murray, Mary Kay Place, Tim Robbins', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (62644, 'Wave, The (Welle, Die)', 'Drama', 2008, 'Dennis Gansel', 'A high school teacher\'s experiment to demonstrate to his students what life is like under a dictatorship spins horribly out of control when he forms a social unit with a life of its own.', 'https://m.media-amazon.com/images/M/MV5BMjEwMmQwM2EtMzdjMS00Y2Q5LTkwYWQtMjdlNGUyYjBhNGNhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jürgen Vogel, Frederick Lau, Max Riemelt, Jennifer Ulrich, Christiane Paul, Jacob Matschenz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (62849, 'RocknRolla', 'Action,Crime', 2008, 'Guy Ritchie', 'When a Russian mobster orchestrates a crooked land deal, millions of dollars are up for grabs, drawing in the entire London underworld into a feeding frenzy at a time when the old criminal regime is losing turf to a wealthy foreign mob.', 'https://m.media-amazon.com/images/M/MV5BMTQ0NTk5Mzk2OV5BMl5BanBnXkFtZTcwMDE3NTE4MQ@@._V1_FMjpg_UX1000_.jpg', 'Gerard Butler, Tom Wilkinson, Thandiwe Newton, Mark Strong, Idris Elba, Tom Hardy', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (63062, 'Changeling', 'Crime,Drama,Mystery', 2008, 'Clint Eastwood', 'After Christine\'s son goes missing, she reaches out to the LAPD to find him, but when they try to pass off an impostor as her son to quiet public protests, she refuses to accept him or give up hope.', 'https://m.media-amazon.com/images/M/MV5BOTA1Mzg3NjIxNV5BMl5BanBnXkFtZTcwNzU2NTc5MQ@@._V1_FMjpg_UX1000_.jpg', 'Angelina Jolie, Gattlin Griffith, Michelle Gunn, Jan Devereaux, Erica Grant, Antonia Bennett', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (63072, 'Road, The', 'Adventure,Drama,Thriller', 2009, 'John Hillcoat', 'In a dangerous post-apocalyptic world, an ailing father defends his son as they slowly travel to the sea.', 'https://m.media-amazon.com/images/M/MV5BMTAwNzk4NTU3NDReQTJeQWpwZ15BbWU3MDg3OTEyODI@._V1_FMjpg_UX1000_.jpg', 'Viggo Mortensen, Kodi Smit-McPhee, Robert Duvall, Guy Pearce, Molly Parker, Michael Kenneth Williams', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (63082, 'Slumdog Millionaire', 'Crime,Drama,Romance', 2008, 'Danny Boyle', 'When a teenager from the slums of Mumbai is interrogated about his suspicious performance on a quiz show, he revisits various events from his past to explain how he knew all the answers.', 'https://m.media-amazon.com/images/M/MV5BMTE5ZTRkYWEtZmU5MC00NDJjLTk3NmUtZGJlYTM2MmQ3NTJkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dev Patel, Saurabh Shukla, Anil Kapoor, Raj Zutshi, Jeneva Talwar, Freida Pinto', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (63393, 'Camp Rock', 'Comedy,Musical,Romance', 2008, 'Matthew Diamond', 'At a music camp for gifted teens, a popular teen idol overhears a girl singing and sets out to find who the talented voice belongs to. What he doesn\'t know is that the girl is actually a camp kitchen worker with a fear of being heard.', 'https://m.media-amazon.com/images/M/MV5BNDllOWY0MDgtYzdlNS00MzYwLWFhZWEtZWZmZmNmMDZhYTlhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Demi Lovato, Joe Jonas, Meaghan Martin, Maria Canals-Barrera, Alyson Stoner, Julie Brown', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (63436, 'Saw V', 'Crime,Horror,Thriller', 2008, 'David Hackl', 'Following Jigsaw\'s grisly demise, Mark Hoffman is commended as a hero, but Agent Strahm is suspicious, and delves into Hoffman\'s past. Meanwhile, another group of people are put through a series of gruesome tests.', 'https://m.media-amazon.com/images/M/MV5BNWViYzg3YzItYzQxNS00MTE1LWJkNTMtMTM3OGI4ODAxOTMwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tobin Bell, Costas Mandylor, Scott Patterson, Betsy Russell, Julie Benz, Meagan Good', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (63876, 'Milk', 'Drama', 2008, 'Gus Van Sant', 'The story of American gay activist Harvey Milk, who fought for gay rights and was elected as California\'s first openly gay official.', 'https://m.media-amazon.com/images/M/MV5BOWVmZWYzMDEtN2NkMi00NWM4LThjYzYtNzBjNzIzN2FmM2NlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sean Penn, Emile Hirsch, Josh Brolin, Diego Luna, James Franco, Alison Pill', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (63992, 'Twilight', 'Drama,Fantasy,Romance,Thriller', 2008, 'Catherine Hardwicke', 'When Bella Swan moves to a small town in the Pacific Northwest, she falls in love with Edward Cullen, a mysterious classmate who reveals himself to be a 108-year-old vampire.', 'https://m.media-amazon.com/images/M/MV5BMTQ2NzUxMTAxN15BMl5BanBnXkFtZTcwMzEyMTIwMg@@._V1_FMjpg_UX1000_.jpg', 'Kristen Stewart, Sarah Clarke, Matt Bushell, Billy Burke, Gil Birmingham, Taylor Lautner', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (64034, 'Boy in the Striped Pajamas, The (Boy in the Striped Pyjamas, The)', 'Drama,War', 2008, 'Mark Herman', 'Through the innocent eyes of Bruno, the eight-year-old son of the commandant at a German concentration camp, a forbidden friendship with a Jewish boy on the other side of the camp fence has startling and unexpected consequences.', 'https://m.media-amazon.com/images/M/MV5BMTMzMTc3MjA5NF5BMl5BanBnXkFtZTcwOTk3MDE5MQ@@._V1_FMjpg_UX1000_.jpg', 'Asa Butterfield, Zac Mattoon O\'Brien, Domonkos Németh, Henry Kingsmill, Vera Farmiga, Cara Horgan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (64197, 'Hunger', 'Drama', 2008, 'Steve McQueen', 'Irish republican Bobby Sands leads the inmates of a Northern Irish prison in a hunger strike.', 'https://m.media-amazon.com/images/M/MV5BMDMwMWZmZjMtZmZkMS00MzNmLTlmNTUtY2MyYTdkYzRiZDg0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Stuart Graham, Laine Megaw, Brian Milligan, Liam McMahon, Karen Hassan, Michael Fassbender', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (64321, 'Friend of Mine, A (Ein Freund von mir)', 'Comedy,Drama', 2006, 'Sebastian Schipper', 'An introverted insurance executive at a car rental service is annoyed by his hyperactive, garrulous coworker, but the two end up becoming friends.', 'https://m.media-amazon.com/images/M/MV5BZjMzOWY4ZjYtOGI4ZS00NjNkLTlmZDItY2IwZjA0N2RlYjUxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Daniel Brühl, Jürgen Vogel, Sabine Timoteo, Peter Kurth, Michael Wittenborn, Oktay Özdemir', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (64614, 'Gran Torino', 'Crime,Drama', 2008, 'Clint Eastwood', 'After a Hmong teenager tries to steal his prized 1972 Gran Torino, a disgruntled, prejudiced Korean War veteran seeks to redeem both the boy and himself.', 'https://m.media-amazon.com/images/M/MV5BMTc5NTk2OTU1Nl5BMl5BanBnXkFtZTcwMDc3NjAwMg@@._V1_FMjpg_UX1000_.jpg', 'Clint Eastwood, Christopher Carley, Bee Vang, Ahney Her, Brian Haley, Geraldine Hughes', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (64622, 'Reader, The', 'Drama,Romance', 2008, 'Stephen Daldry', 'Post-WWII Germany: Nearly a decade after his affair with an older woman came to a mysterious end, law student Michael Berg re-encounters his former lover as she defends herself in a war-crime trial.', 'https://m.media-amazon.com/images/M/MV5BMTM0NDQxNjA0N15BMl5BanBnXkFtZTcwNDUwMzcwMg@@._V1_FMjpg_UX1000_.jpg', 'Ralph Fiennes, Jeanette Hain, David Kross, Kate Winslet, Susanne Lothar, Alissa Wilms', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (64716, 'Seven Pounds', 'Drama', 2008, 'Gabriele Muccino', 'A man with a fateful secret embarks on an extraordinary journey of redemption by forever changing the lives of seven strangers.', 'https://m.media-amazon.com/images/M/MV5BMTU0NzY0MTY5OF5BMl5BanBnXkFtZTcwODY3MDEwMg@@._V1_FMjpg_UX1000_.jpg', 'Will Smith, Rosario Dawson, Woody Harrelson, Michael Ealy, Barry Pepper, Elpidia Carrillo', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (64839, 'Wrestler, The', 'Drama', 2008, 'Darren Aronofsky', 'A faded professional wrestler must retire, but finds his quest for a new life outside the ring a dispiriting struggle.', 'https://m.media-amazon.com/images/M/MV5BMTc5MjYyOTg4MF5BMl5BanBnXkFtZTcwNDc2MzQwMg@@._V1_FMjpg_UX1000_.jpg', 'Mickey Rourke, Marisa Tomei, Evan Rachel Wood, Mark Margolis, Todd Barry, Wass Stevens', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (64957, 'Curious Case of Benjamin Button, The', 'Drama,Fantasy,Mystery,Romance', 2008, 'David Fincher', 'Benjamin Button, born in 1918 with the physical state of an elderly man, ages in reverse. He experiences love and break-ups, ecstasy and sorrow, and timelessness by the time he dies in 2003 as a baby.', 'https://m.media-amazon.com/images/M/MV5BYjIyNDExOWItM2Y4ZC00NmY3LWFlN2ItYTJlZDQ1NTJlZTUwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cate Blanchett, Brad Pitt, Julia Ormond, Faune Chambers Watkins, Elias Koteas, Donna Duplantier', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (65088, 'Bedtime Stories', 'Adventure,Children,Comedy', 2008, 'Adam Shankman', 'A hotel handyman\'s life changes when the lavish bedtime stories he tells his niece and nephew start to magically come true.', 'https://m.media-amazon.com/images/M/MV5BMjA5Njk5MTUxNF5BMl5BanBnXkFtZTcwMDI3MTg5MQ@@._V1_FMjpg_UX1000_.jpg', 'Adam Sandler, Keri Russell, Guy Pearce, Russell Brand, Richard Griffiths, Teresa Palmer', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (65216, 'Defiance', 'Drama,Thriller,War', 2008, 'Edward Zwick', 'Jewish brothers in German-occupied Eastern Europe escape into a Belorussian forest, where they join Russian resistance fighters, and endeavor to build a village, in order to protect themselves and about one thousand Jewish non-combatants.', 'https://m.media-amazon.com/images/M/MV5BM2YzY2UzMDUtODM1NS00MmNlLTg0Y2EtYjhiODczMmExMGFlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Daniel Craig, Liev Schreiber, Jamie Bell, Alexa Davalos, Allan Corduner, Mark Feuerstein', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (65230, 'Marley & Me', 'Comedy,Drama', 2008, 'David Frankel', 'A family learns important life lessons from their adorable, but naughty and neurotic dog.', 'https://m.media-amazon.com/images/M/MV5BYjAzOGQ1NjYtNWZmMi00ZDcwLThiMGEtZTdkZjkzMDU5ZjE2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Owen Wilson, Jennifer Aniston, Eric Dane, Kathleen Turner, Alan Arkin, Nathan Gamble', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (65261, 'Ponyo (Gake no ue no Ponyo)', 'Adventure,Animation,Children,Fantasy', 2008, 'Hayao Miyazaki', 'A five-year-old boy develops a relationship with Ponyo, a young goldfish princess who longs to become a human after falling in love with him.', 'https://m.media-amazon.com/images/M/MV5BZDkzMzQ5ZmQtOTA3MC00MjhiLTk5M2UtNzk0MjEzZmVjN2UxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tomoko Yamaguchi, Kazushige Nagashima, Yûki Amami, George Tokoro, Yuria Nara, Hiroki Doi', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (65642, 'Timecrimes (Cronocrímenes, Los)', 'Sci-Fi,Thriller', 2007, 'Nacho Vigalondo', 'A man accidentally gets into a time machine and travels back in time nearly an hour. Finding himself will be the first of a series of disasters of unforeseeable consequences.', 'https://m.media-amazon.com/images/M/MV5BZTc3NGZkZmItMmZkZS00Yzc4LWIzZDItODRkYTI0MjlhNjA0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Karra Elejalde, Candela Fernández, Bárbara Goenaga, Nacho Vigalondo, Juan Inciarte', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (65813, 'Unborn, The', 'Horror,Mystery,Thriller', 2009, 'David S. Goyer', 'When Casey Beldon witnesses a series of paranormal activities around her, she takes the help of a spiritual adviser and soon finds out a frightful family secret solely responsible for her condition.', 'https://m.media-amazon.com/images/M/MV5BOTM5NDY1MTk2Nl5BMl5BanBnXkFtZTcwNTMyNjkxMg@@._V1_FMjpg_UX1000_.jpg', 'Odette Annable, Gary Oldman, Cam Gigandet, Meagan Good, Idris Elba, Jane Alexander', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (65882, 'Uninvited, The', 'Drama,Horror,Mystery,Thriller', 2009, 'Charles Guard', 'Anna returns home after a stint in a mental hospital, but her recovery is jeopardized by her father\'s new girlfriend and ghastly visions of her dead mother.', 'https://m.media-amazon.com/images/M/MV5BOTY0OTc3OTkyNV5BMl5BanBnXkFtZTcwMTg4Nzc5MQ@@._V1_FMjpg_UX1000_.jpg', 'Emily Browning, Arielle Kebbel, David Strathairn, Elizabeth Banks, Maya Massar, Kevin McNulty', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (66097, 'Coraline', 'Animation,Fantasy,Thriller', 2009, 'Henry Selick', 'Wandering her rambling old house in her boring new town, a young girl discovers a hidden door to a strangely idealized version of her life that seems too good to be true.', 'https://m.media-amazon.com/images/M/MV5BMzQxNjM5NzkxNV5BMl5BanBnXkFtZTcwMzg5NDMwMg@@._V1_FMjpg_UX1000_.jpg', 'Dakota Fanning, Teri Hatcher, Jennifer Saunders, Dawn French, Keith David, John Hodgman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (66665, 'Away We Go', 'Comedy,Drama,Romance', 2009, 'Sam Mendes', 'A couple expecting their first child travels the U.S. seeking the perfect \"family home.\" They have misadventures and find fresh connections with relatives and old friends who help them discover \"home\" on their own terms for the first time.', 'https://m.media-amazon.com/images/M/MV5BMTYxNzE3NjAwMl5BMl5BanBnXkFtZTcwODkxOTI0Mg@@._V1_FMjpg_UX1000_.jpg', 'John Krasinski, Maya Rudolph, Carmen Ejogo, Catherine O\'Hara, Jeff Daniels, Allison Janney', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (66934, 'Dr. Horrible\'s Sing-Along Blog', 'Comedy,Drama,Musical,Sci-Fi', 2008, 'Neil Patrick Harris', 'An aspiring supervillain must balance his career and his pursuit of a beautiful do-gooder.', 'https://m.media-amazon.com/images/M/MV5BOWZiNjY1YjQtMWE1Yy00YmNjLThiYWUtZjUwNmM0ZGRlM2QzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Neil Patrick Harris, Nathan Fillion, Felicia Day, Simon Helberg, Nick Towne, Jed Whedon', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (67255, 'Girl with the Dragon Tattoo, The (Män som hatar kvinnor)', 'Crime,Drama,Mystery,Thriller', 2009, 'Niels Arden Oplev', 'Influential industrialist Vanger\'s niece Harriet disappeared under mysterious circumstances 40 years ago. As a last attempt at solving the case, he hires investigative journalist Mikael Blomkvist.', 'https://m.media-amazon.com/images/M/MV5BMTc2Mjc0MDg3MV5BMl5BanBnXkFtZTcwMjUzMDkxMw@@._V1_FMjpg_UX1000_.jpg', 'Michael Nyqvist, Noomi Rapace, Lena Endre, Sven-Bertil Taube, Peter Haber, Peter Andersson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (68073, 'Pirate Radio', 'Comedy,Drama', 2009, 'Richard Curtis', 'A band of rogue DJs that captivated Britain, playing the music that defined a generation and standing up to a government that wanted classical music, and nothing else, on the airwaves.', 'https://m.media-amazon.com/images/M/MV5BMTMzMjYzMTMyM15BMl5BanBnXkFtZTcwOTk5NDA5Mg@@._V1_FMjpg_UX1000_.jpg', 'Michael Hadley, Charlie Rowe, Lucy Fleming, Philip Seymour Hoffman, Tom Sturridge, Ian Mercer', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (68157, 'Inglourious Basterds', 'Action,Drama,War', 2009, 'Quentin Tarantino', 'In Nazi-occupied France during World War II, a plan to assassinate Nazi leaders by a group of Jewish U.S. soldiers coincides with a theatre owner\'s vengeful plans for the same.', 'https://m.media-amazon.com/images/M/MV5BODZhMWJlNjYtNDExNC00MTIzLTllM2ItOGQ2NGVjNDQ3MzkzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brad Pitt, Mélanie Laurent, Christoph Waltz, Eli Roth, Michael Fassbender, Diane Kruger', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (68205, 'Crank: High Voltage', 'Action,Comedy,Crime', 2009, 'Mark Neveldine', 'Chelios faces a Chinese mobster who has stolen his nearly indestructible heart and replaced it with a battery-powered ticker which requires regular jolts of electricity to keep working.', 'https://m.media-amazon.com/images/M/MV5BMTQzNTU1ODkxNl5BMl5BanBnXkFtZTcwMDgyODEzMg@@._V1_FMjpg_UX1000_.jpg', 'Jason Statham, Amy Smart, Dwight Yoakam, Efren Ramirez, Julanne Chidi Hill, Jose Pablo Cantillo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (68237, 'Moon', 'Drama,Mystery,Sci-Fi,Thriller', 2009, 'Duncan Jones', 'Astronaut Sam Bell has a quintessentially personal encounter toward the end of his three-year stint on the Moon, where he, working alongside his computer, GERTY, sends back to Earth, parcels of a resource that has helped diminish our plane', 'https://m.media-amazon.com/images/M/MV5BMTgzODgyNTQwOV5BMl5BanBnXkFtZTcwNzc0NTc0Mg@@._V1_FMjpg_UX1000_.jpg', 'Sam Rockwell, Kevin Spacey, Dominique McElligott, Rosie Shaw, Adrienne Shaw, Kaya Scodelario', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (68358, 'Star Trek', 'Action,Adventure,Sci-Fi,IMAX', 2009, 'J.J. Abrams', 'The brash James T. Kirk tries to live up to his father\'s legacy with Mr. Spock keeping him in check as a vengeful Romulan from the future creates black holes to destroy the Federation one planet at a time.', 'https://m.media-amazon.com/images/M/MV5BMjE5NDQ5OTE4Ml5BMl5BanBnXkFtZTcwOTE3NDIzMw@@._V1_FMjpg_UX1000_.jpg', 'Chris Pine, Zachary Quinto, Leonard Nimoy, Eric Bana, Bruce Greenwood, Karl Urban', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (68522, 'Earth', 'Documentary', 2007, 'Alastair Fothergill', 'Feature-length version of the documentary TV series Planet Earth (2006), following the migration paths of four animal families.', 'https://m.media-amazon.com/images/M/MV5BZDlkODRjYmItM2Y4Mi00NGY1LTgyODUtZmMxOWI5NWQ1NmFmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Anggun, James Earl Jones, Patrick Stewart, Ulrich Tukur, Ken Watanabe', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (68554, 'Angels & Demons', 'Crime,Drama,Mystery,Thriller', 2009, 'Ron Howard', 'Harvard symbologist Robert Langdon works with a nuclear physicist to solve a murder and prevent a terrorist act against the Vatican during one of the significant events within the church.', 'https://m.media-amazon.com/images/M/MV5BMjEzNzM2MjgxMF5BMl5BanBnXkFtZTcwNTQ1MTM0Mg@@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Ewan McGregor, Ayelet Zurer, Stellan Skarsgård, Pierfrancesco Favino, Nikolaj Lie Kaas', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (68690, 'Love Songs (Les chansons d\'amour)', 'Drama,Musical', 2007, 'Christophe Honoré', 'Ismael and Julie enter a playful yet emotionally laced threesome with Alice. When tragedy strikes, these young Parisians are forced to deal with the fragility of life and love.', 'https://m.media-amazon.com/images/M/MV5BNjZiMjQ5Y2MtZjY4YS00YmE2LWFkZWItZWZiYzRlZWFkZjQ1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Louis Garrel, Ludivine Sagnier, Chiara Mastroianni, Clotilde Hesme, Grégoire Leprince-Ringuet, Brigitte Roüan', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (68954, 'Up', 'Adventure,Animation,Children,Drama', 2009, 'Pete Docter', '78-year-old Carl Fredricksen travels to South America in his house equipped with balloons, inadvertently taking a young stowaway.', 'https://m.media-amazon.com/images/M/MV5BNmI1ZTc5MWMtMDYyOS00ZDc2LTkzOTAtNjQ4NWIxNjYyNDgzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Edward Asner, Christopher Plummer, Jordan Nagai, Bob Peterson, Delroy Lindo, Jerome Ranft', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (69122, 'Hangover, The', 'Comedy,Crime', 2009, 'Todd Phillips', 'Three buddies wake up from a bachelor party in Las Vegas with no memory of the previous night and the bachelor missing. They must make their way around the city in order to find their friend in time for his wedding.', 'https://m.media-amazon.com/images/M/MV5BNDI2MzBhNzgtOWYyOS00NDM2LWE0OGYtOGQ0M2FjMTI2NTllXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bradley Cooper, Ed Helms, Zach Galifianakis, Justin Bartha, Heather Graham, Sasha Barrese', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (69481, 'Hurt Locker, The', 'Action,Drama,Thriller,War', 2008, 'Kathryn Bigelow', 'During the Iraq War, a Sergeant recently assigned to an army bomb squad is put at odds with his squad mates due to his maverick way of handling his work.', 'https://m.media-amazon.com/images/M/MV5BNzgyMGM2YTItYzY2Yi00NDQ0LWE0M2EtMGUzYjFlMDgyY2M3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jeremy Renner, Anthony Mackie, Brian Geraghty, Guy Pearce, Ralph Fiennes, David Morse', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (69644, 'Ice Age: Dawn of the Dinosaurs', 'Action,Adventure,Animation,Children,Comedy,Romance', 2009, 'Carlos Saldanha', 'When Sid\'s attempt to adopt three dinosaur eggs gets him abducted by their real mother to an underground lost world, his friends attempt to rescue him.', 'https://m.media-amazon.com/images/M/MV5BZWJjZDYwMjgtZDZiMy00YzcyLThjN2YtYjI1ZDQ2ZDJkOTVmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Eunice Cho, Karen Disher, Harrison Fahn, Maile Flanagan, Jason Fricchione, Bill Hader', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (69757, '(500) Days of Summer', 'Comedy,Drama,Romance', 2009, 'Marc Webb', 'After being dumped by the girl he believes to be his soulmate, hopeless romantic Tom Hansen reflects on their relationship to try and figure out where things went wrong and how he can win her back.', 'https://m.media-amazon.com/images/M/MV5BMTk5MjM4OTU1OV5BMl5BanBnXkFtZTcwODkzNDIzMw@@._V1_FMjpg_UX1000_.jpg', 'Joseph Gordon-Levitt, Zooey Deschanel, Geoffrey Arend, Chloë Grace Moretz, Matthew Gray Gubler, Clark Gregg', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (69844, 'Harry Potter and the Half-Blood Prince', 'Adventure,Fantasy,Mystery,Romance,IMAX', 2009, 'David Yates', 'As Harry Potter begins his sixth year at Hogwarts, he discovers an old book marked as \"the property of the Half-Blood Prince\" and begins to learn more about Lord Voldemort\'s dark past.', 'https://m.media-amazon.com/images/M/MV5BNzU3NDg4NTAyNV5BMl5BanBnXkFtZTcwOTg2ODg1Mg@@._V1_FMjpg_UX1000_.jpg', 'Daniel Radcliffe, Michael Gambon, Dave Legeno, Elarica Johnson, Jim Broadbent, Geraldine Somerville', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (70159, 'Orphan', 'Drama,Horror,Mystery,Thriller', 2009, 'Jaume Collet-Serra', 'A husband and wife who recently lost their baby adopt a 9-year-old girl who is not nearly as innocent as she appears.', 'https://m.media-amazon.com/images/M/MV5BYjc1Y2M4ZmQtMTA2NC00OTUwLTgxZDMtZDJmNTk1OTU4Njk4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Vera Farmiga, Peter Sarsgaard, Isabelle Fuhrman, CCH Pounder, Jimmy Bennett, Margo Martindale', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (70183, 'Ugly Truth, The', 'Comedy,Drama,Romance', 2009, 'Robert Luketic', 'An uptight television producer takes control of a morning show segment on modern relationships hosted by a misogynistic man.', 'https://m.media-amazon.com/images/M/MV5BMTM2MTM2OTUwNl5BMl5BanBnXkFtZTcwNTgwNTE0Mg@@._V1_FMjpg_UX1000_.jpg', 'Katherine Heigl, Gerard Butler, Bree Turner, Eric Winter, Nick Searcy, Jesse D. Goins', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (70286, 'District 9', 'Mystery,Sci-Fi,Thriller', 2009, 'Neill Blomkamp', 'In a future Earth in which aliens are isolated in a remote ghetto, a government agent finds himself banished there.', 'https://m.media-amazon.com/images/M/MV5BMTM4OTI1OTM5NF5BMl5BanBnXkFtZTcwMzk5MTU1Mg@@._V1_FMjpg_UX1000_.jpg', 'Sharlto Copley, Jason Cope, David James, Vanessa Haywood, Mandla Gaduka, Kenneth Nkosi', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (70336, 'G.I. Joe: The Rise of Cobra', 'Action,Adventure,Sci-Fi,Thriller', 2009, 'Stephen Sommers', 'An elite military unit comprised of special operatives known as G.I. Joe, operating out of The Pit, takes on an evil organization led by a notorious arms dealer.', 'https://m.media-amazon.com/images/M/MV5BMTQzMTU1NzQwNl5BMl5BanBnXkFtZTcwNDg4NzMzMw@@._V1_FMjpg_UX1000_.jpg', 'Adewale Akinnuoye-Agbaje, Christopher Eccleston, Grégory Fitoussi, Joseph Gordon-Levitt, Leo Howard, Karolina Kurkova', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (70599, 'Time Traveler\'s Wife, The', 'Drama,Romance,Sci-Fi', 2009, 'Robert Schwentke', 'Henry DeTamble, a librarian, possesses a unique gene that lets him involuntarily travel through time. His wife, Claire Abshire, finds it difficult to cope with it.', 'https://m.media-amazon.com/images/M/MV5BOGU4M2JjNmEtYTVkOS00ZWY5LTllODQtNWExN2U1NzQwZGEwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michelle Nolden, Alex Ferris, Arliss Howard, Eric Bana, Katherine Trowell, Bart Bedford', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (70728, 'Bronson', 'Action,Comedy,Drama,Thriller', 2009, 'Nicolas Winding Refn', 'A young man who was sentenced to seven years in prison for robbing a post office ends up spending three decades in solitary confinement. During this time, his own personality is supplanted by his alter-ego, Charles Bronson.', 'https://m.media-amazon.com/images/M/MV5BYTkyNTRkNWUtN2Q3MC00Mzg4LThlZTUtYzEyZjlkYjc1NDA3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hardy, Kelly Adams, Luing Andrews, Katy Barker, Gordon Brown, Amanda Burton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (71057, '9', 'Adventure,Animation,Sci-Fi', 2009, 'Shane Acker', 'A rag doll that awakens in a postapocalyptic future holds the key to humanity\'s salvation.', 'https://m.media-amazon.com/images/M/MV5BMTY2ODE1MTgxMV5BMl5BanBnXkFtZTcwNTM1NTM2Mg@@._V1_FMjpg_UX1000_.jpg', 'Christopher Plummer, Martin Landau, John C. Reilly, Crispin Glover, Jennifer Connelly, Fred Tatasciore', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (71205, 'Jennifer\'s Body', 'Comedy,Horror,Sci-Fi,Thriller', 2009, 'Karyn Kusama', 'A newly-possessed high-school cheerleader turns into a succubus who specializes in killing her male classmates. Can her best friend put an end to the horror?', 'https://m.media-amazon.com/images/M/MV5BMTMxNzYwMjc1Ml5BMl5BanBnXkFtZTcwNDI3MDE3Mg@@._V1_FMjpg_UX1000_.jpg', 'Megan Fox, Amanda Seyfried, Johnny Simmons, Adam Brody, Sal Cortez, Ryan Levine', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (71264, 'Cloudy with a Chance of Meatballs', 'Animation,Children,Fantasy,IMAX', 2009, 'Phil Lord', 'A local scientist is often regarded as a failure until he invents a machine that can make food fall from the sky. But little does he know that things are about to take a turn for the worst.', 'https://m.media-amazon.com/images/M/MV5BMTg0MjAwNDI5MV5BMl5BanBnXkFtZTcwODkyMzg2Mg@@._V1_FMjpg_UX1000_.jpg', 'Bill Hader, Anna Faris, James Caan, Andy Samberg, Bruce Campbell, Mr. T', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (71464, 'Serious Man, A', 'Comedy,Drama', 2009, 'Ethan Coen', 'Larry Gopnik, a Midwestern physics teacher, watches his life unravel over multiple sudden incidents. Despite seeking meaning and answers amidst his turmoils, he seems to keep sinking.', 'https://m.media-amazon.com/images/M/MV5BYTQ0MWU5ODItMmY0Yy00NTM1LWJjMmItMjg4MDgwMTE5YmY5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Stuhlbarg, Richard Kind, Fred Melamed, Sari Lennick, Aaron Wolff, Jessica McManus', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (71535, 'Zombieland', 'Action,Comedy,Horror', 2009, 'Ruben Fleischer', 'A shy student trying to reach his family in Ohio, a gun-toting bruiser in search of the last Twinkie and a pair of sisters striving to get to an amusement park join forces in a trek across a zombie-filled America.', 'https://m.media-amazon.com/images/M/MV5BMTU5MDg0NTQ1N15BMl5BanBnXkFtZTcwMjA4Mjg3Mg@@._V1_FMjpg_UX1000_.jpg', 'Jesse Eisenberg, Woody Harrelson, Emma Stone, Abigail Breslin, Amber Heard, Bill Murray', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (71838, 'Law Abiding Citizen', 'Drama,Thriller', 2009, 'F. Gary Gray', 'A frustrated man decides to take justice into his own hands after a plea bargain sets one of his family\'s killers free.', 'https://m.media-amazon.com/images/M/MV5BNDFjNzM2NzMtNTkxZi00ZGFmLTkyZGMtZWQ3ZjMwZDc5NDExXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jamie Foxx, Gerard Butler, Colm Meaney, Bruce McGill, Leslie Bibb, Michael Irby', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (72011, 'Up in the Air', 'Drama,Romance', 2009, 'Jason Reitman', 'Ryan\'s job is to travel around the country, firing people. When his boss hires Natalie, who proposes firing people via video conference, he tries to convince her that her method is a mistake.', 'https://m.media-amazon.com/images/M/MV5BMTI3MzYxMTA4NF5BMl5BanBnXkFtZTcwMDE4ODg3Mg@@._V1_FMjpg_UX1000_.jpg', 'George Clooney, Vera Farmiga, Anna Kendrick, Jason Bateman, Amy Morton, Melanie Lynskey', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (72104, 'Balance', 'Animation,Drama,Mystery,Sci-Fi,Thriller', 1989, 'Christoph Lauenstein', 'A group of fishermen on a precariously balanced platform fight over a trunk.', 'https://m.media-amazon.com/images/M/MV5BZWU2OTI4NTAtZDdkMC00OGQxLTkxZGEtNTczOTEyMTNkNGQxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', NULL, '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (72129, 'Saw VI', 'Crime,Horror,Mystery,Thriller', 2009, 'Kevin Greutert', 'Agent Strahm is dead, and FBI agent Erickson draws nearer to Hoffman. Meanwhile, a pair of insurance executives find themselves in another game set by Jigsaw.', 'https://m.media-amazon.com/images/M/MV5BMTU0NDA3MTM4M15BMl5BanBnXkFtZTcwOTY4Njg3Mg@@._V1_FMjpg_UX1000_.jpg', 'Costas Mandylor, Mark Rolston, Betsy Russell, Shawnee Smith, Peter Outerbridge, Athena Karkanis', '2025-11-24 12:30:37');
