INSERT INTO `movies` VALUES (72380, 'Box, The', 'Drama,Horror,Mystery,Sci-Fi,Thriller', 2009, 'Richard Kelly', 'With the press of a button, a wooden box bestows riches and death.', 'https://m.media-amazon.com/images/M/MV5BMTI4MDA5NjIwM15BMl5BanBnXkFtZTcwNTA2MjY0Mg@@._V1_FMjpg_UX1000_.jpg', 'Cameron Diaz, James Marsden, Frank Langella, James Rebhorn, Holmes Osborne, Sam Oz Stone', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (72407, 'Twilight Saga: New Moon, The', 'Drama,Fantasy,Horror,Romance,Thriller', 2009, 'Chris Weitz', 'After Edward leaves because of an incident involving Bella, Jacob Black becomes her best friend, but what Bella doesn\'t realize is that Jacob also has a secret that will suddenly change their lives.', 'https://m.media-amazon.com/images/M/MV5BMTI3MjE3NDIxNF5BMl5BanBnXkFtZTcwODM3NTY5Mg@@._V1_FMjpg_UX1000_.jpg', 'Kristen Stewart, Christina Jastrzembska, Robert Pattinson, Billy Burke, Anna Kendrick, Michael Welch', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (72641, 'Blind Side, The', 'Drama', 2009, 'John Lee Hancock', 'The story of Michael Oher, a homeless and traumatized boy who became an All-American football player and first-round NFL draft pick with the help of a caring woman and her family.', 'https://m.media-amazon.com/images/M/MV5BMjEzOTE3ODM3OF5BMl5BanBnXkFtZTcwMzYyODI4Mg@@._V1_FMjpg_UX1000_.jpg', 'Sandra Bullock, Tim McGraw, Quinton Aaron, Jae Head, Lily Collins, Ray McKinnon', '2025-11-24 12:30:38');
