INSERT INTO `movies` VALUES (73017, 'Sherlock Holmes', 'Action,Crime,Mystery,Thriller', 2009, 'Guy Ritchie', 'Detective Sherlock Holmes and his stalwart partner Watson engage in a battle of wits and brawn with a nemesis whose plot is a threat to all of England.', 'https://m.media-amazon.com/images/M/MV5BMTg0NjEwNjUxM15BMl5BanBnXkFtZTcwMzk0MjQ5Mg@@._V1_FMjpg_UX1000_.jpg', 'Robert Downey Jr., Jude Law, Rachel McAdams, Mark Strong, Eddie Marsan, Robert Maillet', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (73321, 'Book of Eli, The', 'Action,Adventure,Drama', 2010, 'Albert Hughes', 'A drifter fights his way across a ravaged, post-apocalyptic America while protecting a sacred book that holds the secrets to humanity\'s salvation.', 'https://m.media-amazon.com/images/M/MV5BZjk4N2U2YTAtNWEzZC00N2VmLTlkNDctMjg5YjI4OTExZTFhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Denzel Washington, Gary Oldman, Mila Kunis, Ray Stevenson, Jennifer Beals, Evan Jones', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (73344, 'Prophet, A (Un Prophète)', 'Crime,Drama', 2009, 'Jacques Audiard', 'A delinquent Muslim man struggles to get by in prison until he is taken under the wing of a powerful mob boss, but his gradual rise through the organization\'s ranks brings him in conflict with his mentor.', 'https://m.media-amazon.com/images/M/MV5BMTUyMjQ1MTY5OV5BMl5BanBnXkFtZTcwNzY5NjExMw@@._V1_FMjpg_UX1000_.jpg', 'Tahar Rahim, Niels Arestrup, Adel Bencherif, Reda Kateb, Hichem Yacoubi, Jean-Philippe Ricci', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (73929, 'Legion', 'Action,Fantasy,Horror,Thriller', 2010, 'Scott Stewart', 'When a group of strangers at a dusty roadside diner come under attack by demonic forces, their only chance for survival lies with an archangel named Michael, who informs a pregnant waitress that her unborn child is humanity\'s last hope.', 'https://m.media-amazon.com/images/M/MV5BMTMzNDg4NjYxOV5BMl5BanBnXkFtZTcwODQyNDg3Mg@@._V1_FMjpg_UX1000_.jpg', 'Paul Bettany, Lucas Black, Tyrese Gibson, Adrianne Palicki, Charles S. Dutton, Jon Tenney', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (74426, 'Mohabbatein', 'Drama,Musical,Romance', 2000, 'Aditya Chopra', 'A film about the battle between love and fear, between two stubborn men and their opposing beliefs and the outcome of the love stories of 3 couples.', 'https://m.media-amazon.com/images/M/MV5BMzY5M2RkYjMtYmFhNC00NzdmLTgxNTUtYTE3Yjc2NDhkYTcyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Amitabh Bachchan, Shah Rukh Khan, Aishwarya Rai Bachchan, Jimmy Shergill, Uday Chopra, Jugal Hansraj', '2025-11-24 12:30:37');
