INSERT INTO `movies` VALUES (80463, 'Social Network, The', 'Drama', 2010, 'David Fincher', 'As Harvard student Mark Zuckerberg creates the social networking site that would become known as Facebook, he is sued by the twins who claimed he stole their idea and by the co-founder who was later squeezed out of the business.', 'https://m.media-amazon.com/images/M/MV5BMjlkNTE5ZTUtNGEwNy00MGVhLThmZjMtZjU1NDE5Zjk1NDZkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jesse Eisenberg, Rooney Mara, Bryan Barter, Dustin Fitzsimons, Joseph Mazzello, Patrick Mapel', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (80489, 'Town, The', 'Crime,Drama,Thriller', 2010, 'Ben Affleck', 'A proficient group of thieves rob a bank and hold the manager hostage. Things begin to get complicated when one of the crew members falls in love with her.', 'https://m.media-amazon.com/images/M/MV5BMTcyNzcxODg3Nl5BMl5BanBnXkFtZTcwMTUyNjQ3Mw@@._V1_FMjpg_UX1000_.jpg', 'Ben Affleck, Rebecca Hall, Jon Hamm, Jeremy Renner, Blake Lively, George Carroll', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (80549, 'Easy A', 'Comedy,Romance', 2010, 'Will Gluck', 'When Olive lies to her best friend about losing her virginity to one of the college boys, a girl overhears their conversation. Soon, her story spreads across the entire school like wildfire.', 'https://m.media-amazon.com/images/M/MV5BMjE1MzU1Mjg1OF5BMl5BanBnXkFtZTcwNDc3NDQ2Mw@@._V1_FMjpg_UX1000_.jpg', 'Emma Stone, Penn Badgley, Amanda Bynes, Dan Byrd, Thomas Haden Church, Patricia Clarkson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (80693, 'It\'s Kind of a Funny Story', 'Comedy,Drama', 2010, 'Anna Boden', 'A clinically-depressed teenager gets a new start after he checks himself into an adult psychiatric ward.', 'https://m.media-amazon.com/images/M/MV5BMTk0MTAyNjQ2N15BMl5BanBnXkFtZTcwNjYwOTU3Mw@@._V1_FMjpg_UX1000_.jpg', 'Keir Gilchrist, Dana DeVestern, Lauren Graham, Jim Gaffigan, Karen Chilton, Zach Galifianakis', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (80846, 'Devil', 'Horror,Mystery,Thriller', 2010, 'John Erick Dowdle', 'A group of people are trapped in an elevator and the Devil is mysteriously amongst them.', 'https://m.media-amazon.com/images/M/MV5BZDRmYWMzYjYtODkyMS00YWU4LWJkYzMtMWM1Y2M5YjFlZGZhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chris Messina, Logan Marshall-Green, Jenny O\'Hara, Bojana Novakovic, Bokeem Woodbine, Geoffrey Arend', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (81020, 'Hedgehog, The (Le hérisson)', 'Comedy,Drama', 2009, 'Mona Achache', 'The life of a determined young girl is changed when she befriends her building\'s concierge, a solitary woman who is more than what she seems.', 'https://m.media-amazon.com/images/M/MV5BMTc0Mzg3OTQyN15BMl5BanBnXkFtZTcwODA2OTc4NQ@@._V1_FMjpg_UX1000_.jpg', 'Josiane Balasko, Garance Le Guillermic, Togo Igawa, Anne Brochet, Ariane Ascaride, Wladimir Yordanoff', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (81229, 'Red', 'Action,Comedy', 2010, 'Robert Schwentke', 'When his peaceful life is threatened by a high-tech assassin, former black-ops agent Frank Moses reassembles his old team in a last-ditch effort to survive and uncover the assailants.', 'https://m.media-amazon.com/images/M/MV5BMzg2Mjg1OTk0NF5BMl5BanBnXkFtZTcwMjQ4MTA3Mw@@._V1_FMjpg_UX1000_.jpg', 'Bruce Willis, Mary-Louise Parker, Heidi von Palleske, Jefferson Brown, Karl Urban, Chris Owens', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (81535, 'Saw VII 3D - The Final Chapter', 'Horror,Mystery,Thriller', 2010, 'Kevin Greutert', 'As a deadly battle rages over Jigsaw\'s brutal legacy, a group of Jigsaw survivors gathers to seek the support of self-help guru and fellow survivor Bobby Dagen, a man whose own dark secrets unleash a new wave of terror.', 'https://m.media-amazon.com/images/M/MV5BMjI0NTEwNTgwNF5BMl5BanBnXkFtZTcwMDM5MTU5Mw@@._V1_FMjpg_UX1000_.jpg', 'Tobin Bell, Costas Mandylor, Betsy Russell, Cary Elwes, Sean Patrick Flanery, Chad Donella', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (81537, 'Due Date', 'Comedy', 2010, 'Todd Phillips', 'High-strung father-to-be Peter Highman is forced to hitch a ride with aspiring actor Ethan Tremblay on a road trip in order to make it to his child\'s birth on time.', 'https://m.media-amazon.com/images/M/MV5BMTU5MTgxODM3Nl5BMl5BanBnXkFtZTcwMjMxNDEwNA@@._V1_FMjpg_UX1000_.jpg', 'Robert Downey Jr., Zach Galifianakis, Michelle Monaghan, Jamie Foxx, Juliette Lewis, Danny McBride', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (81562, '127 Hours', 'Adventure,Drama,Thriller', 2010, 'Danny Boyle', 'A mountain climber becomes trapped under a boulder while canyoneering alone near Moab, Utah and resorts to desperate measures in order to survive.', 'https://m.media-amazon.com/images/M/MV5BMTc2NjMzOTE3Ml5BMl5BanBnXkFtZTcwMDE0OTc5Mw@@._V1_FMjpg_UX1000_.jpg', 'James Franco, Kate Mara, Amber Tamblyn, Sean Bott, Koleman Stinger, Treat Williams', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (81564, 'Megamind', 'Action,Animation,Children,Comedy,Sci-Fi,IMAX', 2010, 'Tom McGrath', 'Evil genius Megamind finally defeats his do-gooder nemesis, Metro Man, but is left without a purpose in a superhero-free world.', 'https://m.media-amazon.com/images/M/MV5BMTAzMzI0NTMzNDBeQTJeQWpwZ15BbWU3MDM3NTAyOTM@._V1_FMjpg_UX1000_.jpg', 'Will Ferrell, Brad Pitt, Tina Fey, Jonah Hill, David Cross, Ben Stiller', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (81591, 'Black Swan', 'Drama,Thriller', 2010, 'Darren Aronofsky', 'Nina is a talented but unstable ballerina on the verge of stardom. Pushed to the breaking point by her artistic director and a seductive rival, Nina\'s grip on reality slips, plunging her into a waking nightmare.', 'https://m.media-amazon.com/images/M/MV5BNzY2NzI4OTE5MF5BMl5BanBnXkFtZTcwMjMyNDY4Mw@@._V1_FMjpg_UX1000_.jpg', 'Natalie Portman, Mila Kunis, Vincent Cassel, Barbara Hershey, Winona Ryder, Benjamin Millepied', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (81782, 'Unstoppable', 'Action,Drama,Thriller', 2010, 'Tony Scott', 'With an unmanned, half-mile-long freight train barreling toward a city, a veteran engineer and a young conductor race against the clock to prevent a catastrophe.', 'https://m.media-amazon.com/images/M/MV5BMjI4NDQwMDM0N15BMl5BanBnXkFtZTcwMzY1ODMwNA@@._V1_FMjpg_UX1000_.jpg', 'Denzel Washington, Chris Pine, Rosario Dawson, Ethan Suplee, Kevin Dunn, Kevin Corrigan', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (81804, 'Wild Target', 'Comedy,Drama,Romance,Thriller', 2010, 'Jonathan Lynn', 'A hit-man tries to retire but a beautiful thief may change his plans.', 'https://m.media-amazon.com/images/M/MV5BMjMwN2RmZDEtZWU3OS00NGU5LWI5YzYtZjY3Y2I5MzIwYzQ1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bill Nighy, Emily Blunt, Rupert Grint, Rupert Everett, Eileen Atkins, Martin Freeman', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (81834, 'Harry Potter and the Deathly Hallows: Part 1', 'Action,Adventure,Fantasy,IMAX', 2010, 'David Yates', 'Harry Potter is tasked with the dangerous and seemingly impossible task of locating and destroying Voldemort\'s remaining Horcruxes. Harry must rely on Ron and Hermione more than ever, but dark forces threaten to tear them apart.', 'https://m.media-amazon.com/images/M/MV5BMTQ2OTE1Mjk0N15BMl5BanBnXkFtZTcwODE3MDAwNA@@._V1_FMjpg_UX1000_.jpg', 'Bill Nighy, Emma Watson, Richard Griffiths, Harry Melling, Daniel Radcliffe, Julie Walters', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (81845, 'King\'s Speech, The', 'Drama', 2010, 'Tom Hooper', 'The story of King George VI, his unexpected ascension to the throne of the British Empire in 1936, and the speech therapist who helped the unsure monarch overcome his stammer.', 'https://m.media-amazon.com/images/M/MV5BMzU5MjEwMTg2Nl5BMl5BanBnXkFtZTcwNzM3MTYxNA@@._V1_FMjpg_UX1000_.jpg', 'Colin Firth, Helena Bonham Carter, Derek Jacobi, Robert Portal, Richard Dixon, Paul Trussell', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (81847, 'Tangled', 'Animation,Children,Comedy,Fantasy,Musical,Romance,IMAX', 2010, 'Nathan Greno', 'The magically long-haired Rapunzel has spent her entire life in a tower, but now that a runaway thief has stumbled upon her, she is about to discover the world for the first time, and who she really is.', 'https://m.media-amazon.com/images/M/MV5BMTAxNDYxMjg0MjNeQTJeQWpwZ15BbWU3MDcyNTk2OTM@._V1_FMjpg_UX1000_.jpg', 'Mandy Moore, Zachary Levi, Donna Murphy, Ron Perlman, M.C. Gainey, Jeffrey Tambor', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (81932, 'Fighter, The', 'Drama', 2010, 'David O. Russell', 'Based on the story of Micky Ward, a fledgling boxer who tries to escape the shadow of his more famous but troubled older boxing brother and get his own shot at greatness.', 'https://m.media-amazon.com/images/M/MV5BMTM0ODk3MjM1MV5BMl5BanBnXkFtZTcwNzc1MDIwNA@@._V1_FMjpg_UX1000_.jpg', 'Mark Wahlberg, Christian Bale, Amy Adams, Melissa Leo, Mickey O\'Keefe, Jack McGee', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (82093, 'London Boulevard', 'Crime,Romance', 2010, 'William Monahan', 'An ex-con with a reputation tries to go straight by working as a handy man for a reclusive actress but this is unfortunately not the wish of London\'s underground crime lord.', 'https://m.media-amazon.com/images/M/MV5BMjA1OTk2NTI4NF5BMl5BanBnXkFtZTcwOTA5NTE5Ng@@._V1_FMjpg_UX1000_.jpg', 'Colin Farrell, Keira Knightley, David Thewlis, Anna Friel, Ben Chaplin, Ray Winstone', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (82150, 'Bunny and the Bull', 'Adventure,Comedy,Drama', 2009, 'Paul King', 'A young shut-in takes an imaginary road trip inside his apartment, based on mementos and memories of a European trek from years before.', 'https://m.media-amazon.com/images/M/MV5BNzQyMzk2NGEtNmRhZC00N2JjLTg1NTEtNGIzMzUyMjM1NTM2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Edward Hogg, Simon Farnaby, Verónica Echegui, Richard Ayoade, Julian Barratt, Noel Fielding', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (82459, 'True Grit', 'Western', 2010, 'Ethan Coen', 'A stubborn teenager enlists the help of a tough U.S. Marshal to track down her father\'s murderer.', 'https://m.media-amazon.com/images/M/MV5BMTU5MjU3MTI4OF5BMl5BanBnXkFtZTcwMTQxOTAxNA@@._V1_FMjpg_UX1000_.jpg', 'Jeff Bridges, Hailee Steinfeld, Matt Damon, Josh Brolin, Barry Pepper, Dakin Matthews', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (82461, 'Tron: Legacy', 'Action,Adventure,Sci-Fi,IMAX', 2010, 'Joseph Kosinski', 'The son of a computer programmer goes looking for his father and ends up inside the digital world that his father designed. He meets his father\'s corrupted creation and a unique ally who was born inside the digital world.', 'https://m.media-amazon.com/images/M/MV5BMTk4NTk4MTk1OF5BMl5BanBnXkFtZTcwNTE2MDIwNA@@._V1_FMjpg_UX1000_.jpg', 'Jeff Bridges, Garrett Hedlund, Olivia Wilde, Bruce Boxleitner, James Frain, Beau Garrett', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (82527, 'Barney\'s Version', 'Drama', 2010, 'Richard J. Lewis', 'The picaresque and touching story of the politically incorrect, fully lived life of the impulsive, irascible and fearlessly blunt Barney Panofsky.', 'https://m.media-amazon.com/images/M/MV5BMTM4MTUwNDg0OF5BMl5BanBnXkFtZTcwMjUyODYxNA@@._V1_FMjpg_UX1000_.jpg', 'Paul Giamatti, Macha Grenon, Paul Gross, Atom Egoyan, Mark Camacho, David Pryde', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (82534, 'Company Men, The', 'Drama', 2010, 'John Wells', 'The story centers on a year in the life of three men trying to survive a round of corporate downsizing at a major company - and how that affects them, their families, and their communities.', 'https://m.media-amazon.com/images/M/MV5BMTQxMTgyNDc5M15BMl5BanBnXkFtZTcwMzk4OTM5Mw@@._V1_FMjpg_UX1000_.jpg', 'Ben Affleck, Tommy Lee Jones, Chris Cooper, Suzanne Rico, Kent Shocknek, Adrianne Krstansky', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (82667, 'I Saw the Devil (Akmareul boatda)', 'Crime,Thriller', 2010, 'Kim Jee-woon', 'A secret agent exacts revenge on a serial killer through a series of captures and releases.', 'https://m.media-amazon.com/images/M/MV5BM2Q1ZGZiNTYtMWNjOC00NmU2LTg1MDQtZGZkNmY0Y2RlOTBmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Lee Byung-hun, Choi Min-sik, Jeon Gook-hwan, Chun Ho-jin, San-ha Oh, Kim Yun-Seo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (82906, 'Baghban', 'Drama,Romance', 2003, 'Ravi Chopra', 'An elderly couple wish their children to care for them in their old age. But their children see and treat them as a burden, and they must struggle to regain their worth and dignity to themselves and others.', 'https://m.media-amazon.com/images/M/MV5BMjA2NTEyODY4Ml5BMl5BanBnXkFtZTcwOTk2ODgzMQ@@._V1_FMjpg_UX1000_.jpg', 'Amitabh Bachchan, Hema Malini, Salman Khan, Mahima Chaudhry, Aman Verma, Samir Soni', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (83134, 'Tucker & Dale vs Evil', 'Comedy,Horror', 2010, 'Eli Craig', 'Affable hillbillies Tucker and Dale are on vacation at their dilapidated mountain cabin when they are mistaken for murderers by a group of preppy college students.', 'https://m.media-amazon.com/images/M/MV5BODQ5NDQ0MjkwMF5BMl5BanBnXkFtZTcwNDg1OTU4NQ@@._V1_FMjpg_UX1000_.jpg', 'Tyler Labine, Alan Tudyk, Katrina Bowden, Jesse Moss, Philip Granger, Brandon Jay McLaren', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (83349, 'Green Hornet, The', 'Action,Comedy,Crime,Fantasy,Thriller,IMAX', 2011, 'Michel Gondry', 'Following the death of his father, Britt Reid, heir to his father\'s large company, teams up with his late dad\'s assistant Kato to become a masked crime fighting team.', 'https://m.media-amazon.com/images/M/MV5BMTcwOTMwMDYyMl5BMl5BanBnXkFtZTcwMzAxMjMyNA@@._V1_FMjpg_UX1000_.jpg', 'Seth Rogen, Jay Chou, Cameron Diaz, Tom Wilkinson, Christoph Waltz, David Harbour', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (83652, 'Emma\'s Bliss (Emmas Glück)', 'Drama,Romance', 2006, 'Sven Taddicken', 'Max is very ill. He decides to steal in his own company. But when he tries to run away with the money, he has a car accident that takes him to Emma\'s pigs farm.', 'https://m.media-amazon.com/images/M/MV5BNjllYzYzYTMtM2RiMy00NjZmLWI5NDQtOTFlODJmNmJkZDI1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jördis Triebel, Jürgen Vogel, Maik Solbach, Martin Feifel, Anja Leppehof, Nina Petri', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (84152, 'Limitless', 'Sci-Fi,Thriller', 2011, 'Neil Burger', 'A mysterious pill that enables the user to access 100% of his brain\'s abilities transforms a struggling writer into a financial wizard, but it also puts him in a new world with many dangers.', 'https://m.media-amazon.com/images/M/MV5BMWQ4OTQ4YzYtODlmMi00ZjA0LTg5M2QtZWUzNjA5N2NmODE5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bradley Cooper, Robert De Niro, Abbie Cornish, Andrew Howard, Anna Friel, Johnny Whitworth', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (84392, 'Lincoln Lawyer, The', 'Crime,Drama,Thriller', 2011, 'Brad Furman', 'Defence lawyer Mick Haller lands a case defending a wealthy realtor\'s son who is accused of raping a prostitute. Believing his client to be innocent, Haller soon finds evidence that proves otherwise.', 'https://m.media-amazon.com/images/M/MV5BMTQ4NDE4NTY5MV5BMl5BanBnXkFtZTcwODQyMTkxNA@@._V1_FMjpg_UX1000_.jpg', 'Matthew McConaughey, Marisa Tomei, Ryan Phillippe, William H. Macy, Josh Lucas, John Leguizamo', '2025-11-24 12:30:37');
