INSERT INTO `movies` VALUES (85007, 'Happythankyoumoreplease', 'Comedy,Drama', 2010, 'Josh Radnor', 'Captures a generational moment - young people on the cusp of truly growing up, tiring of their reflexive cynicism, each in their own ways struggling to connect and define what it means to love and be loved.', 'https://m.media-amazon.com/images/M/MV5BNTk3NDgwODQ5NF5BMl5BanBnXkFtZTcwMTY5MjMzNA@@._V1_FMjpg_UX1000_.jpg', 'Malin Akerman, Michael Algieri, Bram Barouh, Dana Barron, Sunah Bilsted, Jimmy Gary Jr.', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (85179, 'Summer Wars (Samâ wôzu)', 'Adventure,Animation,Comedy,Sci-Fi', 2009, 'Mamoru Hosoda', 'A student tries to fix a problem he accidentally caused in OZ, a digital world, while pretending to be the fiancé of his friend at her grandmother\'s 90th birthday.', 'https://m.media-amazon.com/images/M/MV5BZGQ4MWE3Y2ItYjllYi00ZTVlLTljMTUtNTUwOWMwZWIyYmM1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ryûnosuke Kamiki, Nanami Sakuraba, Mitsuki Tanimura, Takahiro Yokokawa, Mieko Nobusawa, Mutsumi Sasaki', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (85211, 'Norwegian Wood (Noruwei no mori)', 'Drama,Romance', 2010, 'Anh Hung Tran', 'Toru recalls his life in the 1960s, when his friend Kizuki killed himself and he grew close to Naoko, Kizuki\'s girlfriend, and another woman, the outgoing, lively Midori.', 'https://m.media-amazon.com/images/M/MV5BODQ3NTM0Nzg3OV5BMl5BanBnXkFtZTcwMTE3MDMxNw@@._V1_FMjpg_UX1000_.jpg', 'Ken\'ichi Matsuyama, Rinko Kikuchi, Kiko Mizuhara, Kengo Kôra, Reika Kirishima, Eriko Hatsune', '2025-11-24 12:30:38');
