INSERT INTO `movies` VALUES (85414, 'Source Code', 'Action,Drama,Mystery,Sci-Fi,Thriller', 2011, 'Duncan Jones', 'A soldier wakes up in someone else\'s body and discovers he\'s part of an experimental government program to find the bomber of a commuter train within 8 minutes.', 'https://m.media-amazon.com/images/M/MV5BMTY0MTc3MzMzNV5BMl5BanBnXkFtZTcwNDE4MjE0NA@@._V1_FMjpg_UX1000_.jpg', 'Jake Gyllenhaal, Michelle Monaghan, Vera Farmiga, Jeffrey Wright, Michael Arden, Cas Anvar', '2025-11-24 12:30:38');
