INSERT INTO `movies` VALUES (85881, 'Win Win', 'Comedy,Drama', 2011, 'Tom McCarthy', 'A struggling lawyer and volunteer wrestling coach\'s chicanery comes back to haunt him when the teenage grandson of the client he has double-crossed comes into his life.', 'https://m.media-amazon.com/images/M/MV5BMTczNTgzNjY4OF5BMl5BanBnXkFtZTcwMTcwMjI0NA@@._V1_FMjpg_UX1000_.jpg', 'Paul Giamatti, Amy Ryan, Bobby Cannavale, Jeffrey Tambor, Burt Young, Melanie Lynskey', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (86320, 'Melancholia', 'Drama,Sci-Fi', 2011, 'Lars von Trier', 'Two sisters find their already strained relationship challenged as a mysterious new planet threatens to collide with Earth.', 'https://m.media-amazon.com/images/M/MV5BMTk4NjM0MjI3MV5BMl5BanBnXkFtZTcwNjcxMDYzNg@@._V1_FMjpg_UX1000_.jpg', 'Kirsten Dunst, Charlotte Gainsbourg, Alexander Skarsgård, Brady Corbet, Cameron Spurr, Charlotte Rampling', '2025-11-24 12:30:37');
