INSERT INTO `movies` VALUES (86781, 'Incendies', 'Drama,Mystery,War', 2010, 'Denis Villeneuve', 'Twins journey to the Middle East to discover their family history and fulfill their mother\'s last wishes.', 'https://m.media-amazon.com/images/M/MV5BYWFmMjdmNjctNzhhOC00ZmMzLTkwOGItMmVmZDU4MjE2MTYwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mustafa Kamel, Hussein Sami, Rémy Girard, Mélissa Désormeaux-Poulin, Maxim Gaudette, Dominique Briand', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (86833, 'Bridesmaids', 'Comedy', 2011, 'Paul Feig', 'Competition between the maid of honor and a bridesmaid, over who is the bride\'s best friend, threatens to upend the life of an out-of-work pastry chef.', 'https://m.media-amazon.com/images/M/MV5BMjAyOTMyMzUxNl5BMl5BanBnXkFtZTcwODI4MzE0NA@@._V1_FMjpg_UX1000_.jpg', 'Kristen Wiig, Terry Crews, Maya Rudolph, Tom Yi, Elaine Kao, Michael Hitchcock', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (86852, 'Beaver, The', 'Drama', 2011, 'Jodie Foster', 'A troubled husband and executive adopts a beaver hand-puppet as his sole means of communication.', 'https://m.media-amazon.com/images/M/MV5BMzc0Nzc0MjA4OF5BMl5BanBnXkFtZTcwNTEyOTYxNA@@._V1_FMjpg_UX1000_.jpg', 'Mel Gibson, Cherry Jones, Jodie Foster, Anton Yelchin, Riley Thomas Stewart, Zachary Booth', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (86882, 'Midnight in Paris', 'Comedy,Fantasy,Romance', 2011, 'Woody Allen', 'While on a trip to Paris with his fiancée\'s family, a nostalgic screenwriter finds himself mysteriously going back to the 1920s every day at midnight.', 'https://m.media-amazon.com/images/M/MV5BMTM4NjY1MDQwMl5BMl5BanBnXkFtZTcwNTI3Njg3NA@@._V1_FMjpg_UX1000_.jpg', 'Owen Wilson, Rachel McAdams, Kurt Fuller, Mimi Kennedy, Michael Sheen, Nina Arianda', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (86898, 'Tree of Life, The', 'Drama', 2011, 'Terrence Malick', 'The story of a family in Waco, Texas in 1956. The eldest son witnesses the loss of innocence and struggles with his parents\' conflicting teachings.', 'https://m.media-amazon.com/images/M/MV5BMTMwNjQ0NjMzN15BMl5BanBnXkFtZTcwNjMxMTkyNA@@._V1_FMjpg_UX1000_.jpg', 'Brad Pitt, Sean Penn, Jessica Chastain, Hunter McCracken, Laramie Eppler, Tye Sheridan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (86911, 'Hangover Part II, The', 'Comedy', 2011, 'Todd Phillips', 'Two years after the bachelor party in Las Vegas, Phil, Stu, Alan, and Doug jet to Thailand for Stu\'s wedding, but Stu\'s plan for subdued pre-wedding brunch goes seriously awry.', 'https://m.media-amazon.com/images/M/MV5BMTM2MTM4MzY2OV5BMl5BanBnXkFtZTcwNjQ3NzI4NA@@._V1_FMjpg_UX1000_.jpg', 'Bradley Cooper, Ed Helms, Zach Galifianakis, Justin Bartha, Ken Jeong, Paul Giamatti', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (87192, 'Attack the Block', 'Action,Comedy,Sci-Fi', 2011, 'Joe Cornish', 'A teen gang in South London defend their block from an alien invasion.', 'https://m.media-amazon.com/images/M/MV5BMjAzNjc1MjgzOF5BMl5BanBnXkFtZTcwMzE3Njk5NQ@@._V1_FMjpg_UX1000_.jpg', 'Jodie Whittaker, John Boyega, Alex Esmail, Leeon Jones, Franz Drameh, Simon Howard', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (87194, 'The Way', 'Adventure,Comedy,Drama', 2010, 'Emilio Estevez', 'A father heads overseas to recover the body of his estranged son who died while traveling the \"El camino de Santiago,\" and decides to take the pilgrimage himself.', 'https://m.media-amazon.com/images/M/MV5BMTU4MzM4NzkyOF5BMl5BanBnXkFtZTcwMjQwNjMzNg@@._V1_FMjpg_UX1000_.jpg', 'Martin Sheen, Emilio Estevez, Deborah Kara Unger, Yorick van Wageningen, James Nesbitt, Romy Baskerville', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (87232, 'X-Men: First Class', 'Action,Adventure,Sci-Fi,Thriller,War', 2011, 'Matthew Vaughn', 'In the 1960s, superpowered humans Charles Xavier and Erik Lensherr work together to find others like them, but Erik\'s vengeful pursuit of an ambitious mutant who ruined his life causes a schism to divide them.', 'https://m.media-amazon.com/images/M/MV5BMTg5OTMxNzk4Nl5BMl5BanBnXkFtZTcwOTk1MjAwNQ@@._V1_FMjpg_UX1000_.jpg', 'James McAvoy, Laurence Belcher, Michael Fassbender, Bill Milner, Kevin Bacon, Rose Byrne', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (87304, 'Beginners', 'Drama', 2010, 'Mike Mills', 'Oliver, a graphic designer, is attracted to a free-spirited and unpredictable Anna. Memories of his father encourage him to open himself up to the potential of a true and long-lasting relationship.', 'https://m.media-amazon.com/images/M/MV5BOTI0ZTYwYjItZTA0ZC00YTMwLTljMmYtODZlZjJiNGY3YmExXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ewan McGregor, Christopher Plummer, Mélanie Laurent, Goran Visnjic, Kai Lennox, Mary Page Keller', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (87306, 'Super 8', 'Mystery,Sci-Fi,Thriller,IMAX', 2011, 'J.J. Abrams', 'During the summer of 1979, a group of friends witness a train crash and investigate subsequent unexplained events in their small town.', 'https://m.media-amazon.com/images/M/MV5BMjIzNjEyMzcwOF5BMl5BanBnXkFtZTcwMTkyMjE0NQ@@._V1_FMjpg_UX1000_.jpg', 'Joel Courtney, Jessica Tuck, Joel McKinnon Miller, Ryan Lee, Zach Mills, Riley Griffiths', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (87697, 'Shoppen', 'Comedy,Romance', 2006, 'Ralf Westhoff', 'By attending speed dating, 9 single women and 9 single men are \'shopping\' for a life partner.', 'https://m.media-amazon.com/images/M/MV5BNDhkMDY3ZjQtNzNlMS00ZTNhLWI0NGEtZTBlNDg1YjFiNDNkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sebastian Weber, Anna Böger, Felix Hellmann, Katharina Marie Schubert, David Baalcke, Julia Koschitz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (87869, 'Horrible Bosses', 'Comedy,Crime', 2011, 'Seth Gordon', 'Three friends conspire to murder their awful bosses when they realize they are standing in the way of their happiness.', 'https://m.media-amazon.com/images/M/MV5BNzYxNDI5Njc5NF5BMl5BanBnXkFtZTcwMDUxODE1NQ@@._V1_FMjpg_UX1000_.jpg', 'Jason Bateman, Steve Wiebe, Kevin Spacey, Charlie Day, Lindsay Sloane, Michael Albala', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (87876, 'Cars 2', 'Adventure,Animation,Children,Comedy,IMAX', 2011, 'John Lasseter', 'Star race car Lightning McQueen and his pal Mater head overseas to compete in the World Grand Prix race. But the road to the championship becomes rocky as Mater gets caught up in an intriguing adventure of his own: international espionage.', 'https://m.media-amazon.com/images/M/MV5BMTUzNTc3MTU3M15BMl5BanBnXkFtZTcwMzIxNTc3NA@@._V1_FMjpg_UX1000_.jpg', 'Larry the Cable Guy, Owen Wilson, Michael Caine, Emily Mortimer, Eddie Izzard, John Turturro', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (88125, 'Harry Potter and the Deathly Hallows: Part 2', 'Action,Adventure,Drama,Fantasy,Mystery,IMAX', 2011, 'David Yates', 'Harry, Ron and Hermione set out on a quest to eliminate the remaining horcruxes. On the other hand, the students and teachers must unite to defend Hogwarts against Lord Voldemort and his minions.', 'https://m.media-amazon.com/images/M/MV5BOTA1Mzc2N2ItZWRiNS00MjQzLTlmZDQtMjU0NmY1YWRkMGQ4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ralph Fiennes, Michael Gambon, Alan Rickman, Daniel Radcliffe, Rupert Grint, Emma Watson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (88129, 'Drive', 'Crime,Drama,Film-Noir,Thriller', 2011, 'Nicolas Winding Refn', 'A mysterious Hollywood action film stuntman gets in trouble with gangsters when he tries to help his neighbor\'s husband rob a pawn shop while serving as his getaway driver.', 'https://m.media-amazon.com/images/M/MV5BYTFmNTFlOTAtNzEyNi00MWU2LTg3MGEtYjA2NWY3MDliNjlkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ryan Gosling, Carey Mulligan, Bryan Cranston, Albert Brooks, Oscar Isaac, Christina Hendricks', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (88140, 'Captain America: The First Avenger', 'Action,Adventure,Sci-Fi,Thriller,War', 2011, 'Joe Johnston', 'Steve Rogers, a rejected military soldier, transforms into Captain America after taking a dose of a \"Super-Soldier serum\". But being Captain America comes at a price as he attempts to take down a warmonger and a terrorist organization.', 'https://m.media-amazon.com/images/M/MV5BNzUyM2YyY2MtNzNlMS00MWU5LTgxNjAtNzZlNmI2NjU2NDZlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chris Evans, Hayley Atwell, Sebastian Stan, Tommy Lee Jones, Hugo Weaving, Dominic Cooper', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (88163, 'Crazy, Stupid, Love.', 'Comedy,Drama,Romance', 2011, 'Glenn Ficarra', 'A middle-aged husband\'s life changes dramatically when his wife asks him for a divorce. He seeks to rediscover his manhood with the help of a newfound friend, Jacob, learning to pick up girls at bars.', 'https://m.media-amazon.com/images/M/MV5BMTg2MjkwMTM0NF5BMl5BanBnXkFtZTcwMzc4NDg2NQ@@._V1_FMjpg_UX1000_.jpg', 'Steve Carell, Ryan Gosling, Julianne Moore, Emma Stone, Lio Tipton, Jonah Bobo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (88179, 'One Day', 'Drama,Romance', 2011, 'Lone Scherfig', 'After spending the night together on the eve of their college graduation, Dexter and Emma are shown each year on the same date to see where they are in their lives. They are sometimes together, and sometimes not.', 'https://m.media-amazon.com/images/M/MV5BMTQ3NTg2MDI3NF5BMl5BanBnXkFtZTcwMjc5MTA1NA@@._V1_FMjpg_UX1000_.jpg', 'Anne Hathaway, Jim Sturgess, Tom Mison, Jodie Whittaker, Tim Key, Rafe Spall', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (88405, 'Friends with Benefits', 'Comedy,Romance', 2011, 'Will Gluck', 'A young man and woman decide to take their friendship to the next level without becoming a couple, but soon discover that adding sex only leads to complications.', 'https://m.media-amazon.com/images/M/MV5BMTQ2MzQ0NTk4N15BMl5BanBnXkFtZTcwMDc2NDYzNQ@@._V1_FMjpg_UX1000_.jpg', 'Justin Timberlake, Mila Kunis, Patricia Clarkson, Jenna Elfman, Bryan Greenberg, Richard Jenkins', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (88744, 'Rise of the Planet of the Apes', 'Action,Drama,Sci-Fi,Thriller', 2011, 'Rupert Wyatt', 'A substance designed to help the brain repair itself gives advanced intelligence to a chimpanzee who leads an ape uprising.', 'https://m.media-amazon.com/images/M/MV5BMjllODU1NDItODU1Ni00N2Y2LTg4Y2ItOTJjMTczZDliN2FhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Andy Serkis, Karin Konoval, Terry Notary, Richard Ridings, Christopher Gordon, Devyn Dalton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (88810, 'Help, The', 'Drama', 2011, 'Tate Taylor', 'An aspiring author during the civil rights movement of the 1960s decides to write a book detailing the African American maids\' point of view on the white families for which they work, and the hardships they go through on a daily basis.', 'https://m.media-amazon.com/images/M/MV5BMTM5OTMyMjIxOV5BMl5BanBnXkFtZTcwNzU4MjIwNQ@@._V1_FMjpg_UX1000_.jpg', 'Emma Stone, Viola Davis, Bryce Dallas Howard, Octavia Spencer, Jessica Chastain, Ahna O\'Reilly', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (88812, '30 Minutes or Less', 'Action,Comedy,Crime', 2011, 'Ruben Fleischer', 'Two fledgling criminals kidnap a pizza delivery guy, strap a bomb to his chest, and inform him that he has mere hours to rob a bank or else...', 'https://m.media-amazon.com/images/M/MV5BMTM5NjM0ODY1NF5BMl5BanBnXkFtZTcwMjk5NjI0Ng@@._V1_FMjpg_UX1000_.jpg', 'Jesse Eisenberg, Danny McBride, Aziz Ansari, Nick Swardson, Dilshad Vadsaria, Michael Peña', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (89039, 'Another Earth', 'Drama,Romance,Sci-Fi', 2011, 'Mike Cahill', 'Tragedy connects a young woman and a shattered music professor as an exact replica of Earth is discovered.', 'https://m.media-amazon.com/images/M/MV5BMTAzNTIzMjkxNjJeQTJeQWpwZ15BbWU3MDEwNDQ2OTU@._V1_FMjpg_UX1000_.jpg', 'Brit Marling, Matthew-Lee Erlbach, DJ Flava, William Mapother, Meggan Lennon, AJ Diana', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (89118, 'Skin I Live In, The (La piel que habito)', 'Drama', 2011, 'Pedro Almodóvar', 'A brilliant plastic surgeon, haunted by past tragedies, creates a type of synthetic skin that withstands any kind of damage. His guinea pig: a mysterious and volatile woman who holds the key to his obsession.', 'https://m.media-amazon.com/images/M/MV5BYjgzMDNlOTgtMDM1Ny00MjdmLWIwNjItN2IzYzRiZGY4MWY3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Antonio Banderas, Elena Anaya, Marisa Paredes, Jan Cornet, Roberto Álamo, Eduard Fernández', '2025-11-24 12:30:38');
