INSERT INTO `movies` VALUES (89492, 'Moneyball', 'Drama', 2011, 'Bennett Miller', 'Oakland A\'s general manager Billy Beane\'s successful attempt to assemble a baseball team on a lean budget by employing computer-generated analysis to acquire new players.', 'https://m.media-amazon.com/images/M/MV5BMjAxOTU3Mzc1M15BMl5BanBnXkFtZTcwMzk1ODUzNg@@._V1_FMjpg_UX1000_.jpg', 'Brad Pitt, Jonah Hill, Philip Seymour Hoffman, Robin Wright, Chris Pratt, Stephen Bishop', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (89745, 'Avengers, The', 'Action,Adventure,Sci-Fi,IMAX', 2012, 'Joss Whedon', 'Earth\'s mightiest heroes must come together and learn to fight as a team if they are going to stop the mischievous Loki and his alien army from enslaving humanity.', 'https://m.media-amazon.com/images/M/MV5BNGE0YTVjNzUtNzJjOS00NGNlLTgxMzctZTY4YTE1Y2Y1ZTU4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert Downey Jr., Chris Evans, Mark Ruffalo, Chris Hemsworth, Scarlett Johansson, Jeremy Renner', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (89753, 'Tinker Tailor Soldier Spy', 'Drama,Film-Noir,Thriller', 2011, 'Tomas Alfredson', 'In the bleak days of the Cold War, espionage veteran George Smiley is forced from semi-retirement to uncover a Soviet Agent within MI6.', 'https://m.media-amazon.com/images/M/MV5BMTU2OTkwNzMyM15BMl5BanBnXkFtZTcwOTI4ODg2Ng@@._V1_FMjpg_UX1000_.jpg', 'Mark Strong, John Hurt, Zoltán Mucsi, Péter Kálloy Molnár, Ilona Kassai, Imre Csuja', '2025-11-24 12:30:38');
