INSERT INTO `movies` VALUES (89864, '50/50', 'Comedy,Drama', 2011, 'Jonathan Levine', 'Inspired by a true story, a comedy centered on a 27-year-old guy who learns of his cancer diagnosis and his subsequent struggle to beat the disease.', 'https://m.media-amazon.com/images/M/MV5BNjg3ODQyNTIyN15BMl5BanBnXkFtZTcwMjUzNzM5NQ@@._V1_FMjpg_UX1000_.jpg', 'Joseph Gordon-Levitt, Seth Rogen, Anna Kendrick, Bryce Dallas Howard, Anjelica Huston, Serge Houde', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (89904, 'The Artist', 'Comedy,Drama,Romance', 2011, 'Michel Hazanavicius', 'When George, a silent movie superstar, meets Peppy Miller, a dancer, sparks fly between the two. However, after the introduction of talking pictures, their fortunes change, affecting their dynamic.', 'https://m.media-amazon.com/images/M/MV5BYjEwOGZmM2QtNjY4Mi00NjI0LTkyZjItZDEzZGI1YTEzMDg1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jean Dujardin, Bérénice Bejo, John Goodman, James Cromwell, Penelope Ann Miller, Missi Pyle', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (90057, 'Take Shelter', 'Drama', 2011, 'Jeff Nichols', 'Frightening visions convince an Ohio man that disaster looms on the horizon.', 'https://m.media-amazon.com/images/M/MV5BNzgzODA5MTU3MF5BMl5BanBnXkFtZTcwODY4MDEwNg@@._V1_FMjpg_UX1000_.jpg', 'Michael Shannon, Jessica Chastain, Tova Stewart, Shea Whigham, Katy Mixon Greer, Natasha Randall', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (90071, 'Music Never Stopped, The', 'Drama', 2011, 'Jim Kohlberg', 'Tale of a father who struggles to bond with his estranged son Gabriel, after Gabriel suffers from a brain tumor that prevents him from forming new memories. With Gabriel unable to shed the beliefs and interests that caused their physical and emotional distance, Henry must learn t...Read all', 'https://m.media-amazon.com/images/M/MV5BMTU5NzU5NzIzNV5BMl5BanBnXkFtZTcwNjE0MTU0NA@@._V1_FMjpg_UX1000_.jpg', 'J.K. Simmons, Cara Seymour, Lou Taylor Pucci, Scott Adsit, James Urbaniak, Max Antisell', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (90374, 'Martha Marcy May Marlene', 'Drama,Thriller', 2011, 'Sean Durkin', 'Haunted by painful memories and increasing paranoia, a damaged woman struggles to re-assimilate with her family after fleeing an abusive cult.', 'https://m.media-amazon.com/images/M/MV5BMTc1MTYwMzg1N15BMl5BanBnXkFtZTcwNzM0MDY4Ng@@._V1_FMjpg_UX1000_.jpg', 'Elizabeth Olsen, Christopher Abbott, Brady Corbet, Hugh Dancy, Maria Dizzia, Julia Garner', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (90376, 'We Need to Talk About Kevin', 'Drama,Thriller', 2011, 'Lynne Ramsay', 'Kevin\'s mother struggles to love her strange child despite the increasingly dangerous things he says and does as he grows up. But Kevin is just getting started, and his final act will be beyond anything anyone imagined.', 'https://m.media-amazon.com/images/M/MV5BMjE0NDE0MjYxNF5BMl5BanBnXkFtZTcwNjM2NTY5Ng@@._V1_FMjpg_UX1000_.jpg', 'Tilda Swinton, John C. Reilly, Ezra Miller, Jasper Newell, Rocky Duer, Ashley Gerasimovich', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (90405, 'In Time', 'Crime,Sci-Fi,Thriller', 2011, 'Andrew Niccol', 'In a future where people stop aging at 25, but are engineered to live only one more year, having the means to buy your way out of the situation is a shot at immortal youth. Will Salas is accused of murder and on the run with a hostage.', 'https://m.media-amazon.com/images/M/MV5BMjA3NzI1ODc1MV5BMl5BanBnXkFtZTcwMzI5NjQwNg@@._V1_FMjpg_UX1000_.jpg', 'Justin Timberlake, Olivia Wilde, Shyloh Oostwald, Johnny Galecki, Colin McGurk, Will Harris', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (90430, 'Carnage', 'Comedy,Drama', 2011, 'Roman Polanski', 'Two pairs of parents hold a cordial meeting after their sons are involved in a fight, though as their time together progresses, increasingly childish behavior throws the discussion into chaos.', 'https://m.media-amazon.com/images/M/MV5BMTc4MjAyMDUwNl5BMl5BanBnXkFtZTcwOTQwMDMwNw@@._V1_FMjpg_UX1000_.jpg', 'Jodie Foster, Kate Winslet, Christoph Waltz, John C. Reilly, Elvis Polanski, Eliot Berger', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (90528, 'This Must Be the Place', 'Crime,Drama,Thriller', 2011, 'Paolo Sorrentino', 'Cheyenne, a retired rock star living off his royalties in Dublin, returns to New York City to find the man responsible for a humiliation suffered by his recently deceased father during W.W.II.', 'https://m.media-amazon.com/images/M/MV5BYjc2YzZmNjEtZmVlOS00YWYzLTk4YTItNWUzN2ZmM2MzYjJkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sean Penn, Olwen Fouéré, Eve Hewson, Johnny Ward, Sam Keeley, Danielle O\'Brien', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (90531, 'Shame', 'Drama', 2011, 'Steve McQueen', 'A nymphomaniac\'s carefully cultivated private life falls apart after his sister arrives for an indefinite stay.', 'https://m.media-amazon.com/images/M/MV5BM2I4YjYzYmQtNGM4Yy00NmYwLWEzYjUtMDBmNjYzZmViZWE3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Fassbender, Lucy Walters, Mari-Ange Ramirez, James Badge Dale, Nicole Beharie, Alex Manette', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (90933, 'Deep Blue Sea, The', 'Drama,Romance', 2011, 'Terence Davies', 'The wife of a British Judge is caught in a self-destructive love affair with a Royal Air Force pilot.', 'https://m.media-amazon.com/images/M/MV5BMTM5NjI1MTQ0N15BMl5BanBnXkFtZTcwNDM5OTc0Nw@@._V1_FMjpg_UX1000_.jpg', 'Ann Mitchell, Jolyon Coy, Karl Johnson, Rachel Weisz, Simon Russell Beale, Tom Hiddleston', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (91077, 'Descendants, The', 'Comedy,Drama', 2011, 'Alexander Payne', 'A land baron tries to reconnect with his two daughters after his wife is seriously injured in a boating accident.', 'https://m.media-amazon.com/images/M/MV5BMjAyNTA1MTcyN15BMl5BanBnXkFtZTcwNjEyODczNQ@@._V1_FMjpg_UX1000_.jpg', 'George Clooney, Shailene Woodley, Amara Miller, Nick Krause, Patricia Hastie, Grace A. Cruz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (91325, 'Extremely Loud and Incredibly Close', 'Drama', 2011, 'Stephen Daldry', 'A nine-year-old amateur inventor, Francophile, and pacifist searches New York City for the lock that matches a mysterious key left behind by his father, who died in the World Trade Center on September 11, 2001.', 'https://m.media-amazon.com/images/M/MV5BMTUxNzYwMTE3NV5BMl5BanBnXkFtZTcwMDY2NzU4Ng@@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Thomas Horn, Sandra Bullock, Zoe Caldwell, Dennis Hearn, Paul Klementowicz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (91485, 'Expendables 2, The', 'Action,Adventure', 2012, 'Simon West', 'Mr. Church reunites the Expendables for what should be an easy paycheck, but when one of their men is murdered on the job, their quest for revenge puts them deep in enemy territory and up against an unexpected threat.', 'https://m.media-amazon.com/images/M/MV5BMTkwZGYyYzktNmEzMS00ZDkzLTlkMjEtYTdiOWExM2Y2ZjE4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sylvester Stallone, Jason Statham, Jet Li, Dolph Lundgren, Chuck Norris, Jean-Claude Van Damme', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (91500, 'The Hunger Games', 'Action,Adventure,Drama,Sci-Fi,Thriller', 2012, 'Gary Ross', 'Katniss Everdeen voluntarily takes her younger sister\'s place in the Hunger Games: a televised competition in which two teenagers from each of the twelve Districts of Panem are chosen at random to fight to the death.', 'https://m.media-amazon.com/images/M/MV5BMWI1OGM4YjQtNmIxNi00YmE2LWJkNTAtY2Q0YjU4NTI5NWQyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Stanley Tucci, Wes Bentley, Jennifer Lawrence, Willow Shields, Liam Hemsworth, Elizabeth Banks', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (91529, 'Dark Knight Rises, The', 'Action,Adventure,Crime,IMAX', 2012, 'Christopher Nolan', 'Bane, an imposing terrorist, attacks Gotham City and disrupts its eight-year-long period of peace. This forces Bruce Wayne to come out of hiding and don the cape and cowl of Batman again.', 'https://m.media-amazon.com/images/M/MV5BMTk4ODQzNDY3Ml5BMl5BanBnXkFtZTcwODA0NTM4Nw@@._V1_FMjpg_UX1000_.jpg', 'Christian Bale, Gary Oldman, Tom Hardy, Joseph Gordon-Levitt, Anne Hathaway, Marion Cotillard', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (91535, 'Bourne Legacy, The', 'Action,Adventure,Drama,Thriller,IMAX', 2012, 'Tony Gilroy', 'An expansion of the universe from Robert Ludlum\'s novels, centered on a new hero whose stakes have been triggered by the events of the previous three films.', 'https://m.media-amazon.com/images/M/MV5BMTc4Njk3MDM1Nl5BMl5BanBnXkFtZTcwODgyOTMxOA@@._V1_FMjpg_UX1000_.jpg', 'Jeremy Renner, Scott Glenn, Stacy Keach, Edward Norton, Donna Murphy, Michael Chernus', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (91542, 'Sherlock Holmes: A Game of Shadows', 'Action,Adventure,Comedy,Crime,Mystery,Thriller', 2011, 'Guy Ritchie', 'Detective Sherlock Holmes is on the trail of criminal mastermind Professor Moriarty, who is carrying out a string of random crimes across Europe.', 'https://m.media-amazon.com/images/M/MV5BMTQwMzQ5Njk1MF5BMl5BanBnXkFtZTcwNjIxNzIxNw@@._V1_FMjpg_UX1000_.jpg', 'Robert Downey Jr., Jude Law, Noomi Rapace, Rachel McAdams, Jared Harris, Stephen Fry', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (91630, 'Mission: Impossible - Ghost Protocol', 'Action,Adventure,Thriller,IMAX', 2011, 'Brad Bird', 'The IMF is shut down when it\'s implicated in the bombing of the Kremlin, causing Ethan Hunt and his new team to go rogue to clear their organization\'s name.', 'https://m.media-amazon.com/images/M/MV5BMTY4MTUxMjQ5OV5BMl5BanBnXkFtZTcwNTUyMzg5Ng@@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Paula Patton, Simon Pegg, Jeremy Renner, Michael Nyqvist, Vladimir Mashkov', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (91658, 'Girl with the Dragon Tattoo, The', 'Drama,Thriller', 2011, 'David Fincher', 'Journalist Mikael Blomkvist is aided in his search for a woman who has been missing for 40 years by hacker Lisbeth Salander.', 'https://m.media-amazon.com/images/M/MV5BMTczNDk4NTQ0OV5BMl5BanBnXkFtZTcwNDAxMDgxNw@@._V1_FMjpg_UX1000_.jpg', 'Daniel Craig, Rooney Mara, Christopher Plummer, Stellan Skarsgård, Steven Berkoff, Robin Wright', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (91978, 'Man on a Ledge', 'Crime,Thriller', 2012, 'Asger Leth', 'As a police psychologist works to talk down an ex-con who is threatening to jump from a Manhattan hotel rooftop, the biggest diamond heist ever committed is in motion.', 'https://m.media-amazon.com/images/M/MV5BMTc5MTE4MzY2N15BMl5BanBnXkFtZTcwNjMwNDc3Ng@@._V1_FMjpg_UX1000_.jpg', 'Sam Worthington, Mandy Gonzalez, William Sadler, Barbara Marineau, J. Smith-Cameron, Anthony Mackie', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (92259, 'Intouchables', 'Comedy,Drama', 2011, 'Olivier Nakache', 'After he becomes a quadriplegic from a paragliding accident, an aristocrat hires a young man from the projects to be his caregiver.', 'https://m.media-amazon.com/images/M/MV5BMTYxNDA3MDQwNl5BMl5BanBnXkFtZTcwNTU4Mzc1Nw@@._V1_FMjpg_UX1000_.jpg', 'François Cluzet, Omar Sy, Anne Le Ny, Audrey Fleurot, Joséphine de Meaux, Clotilde Mollet', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (92262, 'Declaration of War (La Guerre est Déclarée)', 'Drama', 2011, 'Valérie Donzelli', 'When their young son is diagnosed with a brain tumor, young parents Roméo and Juliette unite in the fight for his survival.', 'https://m.media-amazon.com/images/M/MV5BMTU1NjI1Mjg3Ml5BMl5BanBnXkFtZTcwMDk0ODAxNw@@._V1_FMjpg_UX1000_.jpg', 'Valérie Donzelli, Jérémie Elkaïm, César Desseix, Gabriel Elkaïm, Brigitte Sy, Elina Löwensohn', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (93510, '21 Jump Street', 'Action,Comedy,Crime', 2012, 'Phil Lord', 'A pair of underachieving cops are sent back to a local high school to blend in and bring down a synthetic drug ring.', 'https://m.media-amazon.com/images/M/MV5BMTg2NjJiODctM2IyMS00MmQ5LWI1YmQtNTBjMTI4M2U2YzA5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jonah Hill, Channing Tatum, Brie Larson, Dave Franco, Rob Riggle, DeRay Davis', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (93563, 'Lockout', 'Action,Sci-Fi,Thriller', 2012, 'James Mather', 'A man wrongfully accused and convicted of conspiring to commit espionage against the US government is offered his freedom if he can rescue the president\'s daughter from an outer-space prison that\'s been taken over by violent inmates.', 'https://m.media-amazon.com/images/M/MV5BMTg1OTQ3MzM0NV5BMl5BanBnXkFtZTcwNDU1MDI0Nw@@._V1_FMjpg_UX1000_.jpg', 'Guy Pearce, Maggie Grace, Vincent Regan, Joe Gilgun, Lennie James, Peter Stormare', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (93721, 'Jiro Dreams of Sushi', 'Documentary', 2011, 'David Gelb', 'A documentary on 85-year-old sushi master Jiro Ono, his renowned Tokyo restaurant, and his relationship with his son and eventual heir, Yoshikazu.', 'https://m.media-amazon.com/images/M/MV5BMTA5NzQzODUxOTheQTJeQWpwZ15BbWU3MDIwODg1MDc@._V1_FMjpg_UX1000_.jpg', 'Jiro Ono, Yoshikazu Ono, Masuhiro Yamamoto, Daisuke Nakazama, Hachiro Mizutani, Harutaki Takahashi', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (93740, 'Salmon Fishing in the Yemen', 'Comedy,Drama,Romance', 2011, 'Lasse Hallström', 'A fisheries expert is approached by a consultant to help realize a sheik\'s vision of bringing the sport of fly-fishing to the desert and embarks on an upstream journey of faith and fish to prove the impossible possible.', 'https://m.media-amazon.com/images/M/MV5BMGQ4YzRhMzAtZGQ5ZS00NmE5LWFjYzQtNTExZWRmMTI5OWUyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Amr Waked, Emily Blunt, Catherine Steadman, Tom Mison, Ewan McGregor, Rachael Stirling', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (93840, 'Cabin in the Woods, The', 'Comedy,Horror,Sci-Fi,Thriller', 2012, 'Drew Goddard', 'Five teens visit a remote cabin and explore its cellar, finding strange items. When Dana reads from a book there, she unleashes zombie killers. But the situation is more complex than it appears.', 'https://m.media-amazon.com/images/M/MV5BNTUxNzYyMjg2N15BMl5BanBnXkFtZTcwMTExNzExNw@@._V1_FMjpg_UX1000_.jpg', 'Kristen Connolly, Chris Hemsworth, Anna Hutchison, Fran Kranz, Jesse Williams, Richard Jenkins', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (94070, 'Best Exotic Marigold Hotel, The', 'Comedy,Drama', 2011, 'John Madden', 'British retirees travel to India to take up residence in what they believe is a newly restored hotel. Less luxurious than advertised, the Marigold Hotel nevertheless slowly begins to charm in unexpected ways.', 'https://m.media-amazon.com/images/M/MV5BMjIwNjkwMDI2NV5BMl5BanBnXkFtZTcwNDc1ODIyNw@@._V1_FMjpg_UX1000_.jpg', 'Judi Dench, Tom Wilkinson, Patrick Pearson, Hugh Dickson, James Rawlings, Bill Nighy', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (94266, 'Five-Year Engagement, The', 'Comedy,Romance', 2012, 'Nicholas Stoller', 'One year after meeting, Tom proposes to his girlfriend, Violet, but unexpected events keep tripping them up as they look to walk down the aisle together.', 'https://m.media-amazon.com/images/M/MV5BMTk3MDE1NTA3M15BMl5BanBnXkFtZTcwNDcwNTMxNw@@._V1_FMjpg_UX1000_.jpg', 'Jason Segel, Emily Blunt, Chris Pratt, Alison Brie, Lauren Weedman, Mimi Kennedy', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (94478, 'Dark Shadows', 'Comedy,Horror,IMAX', 2012, 'Tim Burton', 'An imprisoned vampire, Barnabas Collins, is set free and returns to his ancestral home, where his dysfunctional descendants are in need of his protection.', 'https://m.media-amazon.com/images/M/MV5BMjNiYWMxZjctMzEyZS00NDZmLTgxYmYtM2NmOGI0MmY3ZTJiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Michelle Pfeiffer, Helena Bonham Carter, Eva Green, Jackie Earle Haley, Jonny Lee Miller', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (94864, 'Prometheus', 'Action,Horror,Sci-Fi,IMAX', 2012, 'Ridley Scott', 'Following clues to the origin of mankind, a team finds a structure on a distant moon, but they soon realize they are not alone.', 'https://m.media-amazon.com/images/M/MV5BMTY3NzIyNTA2NV5BMl5BanBnXkFtZTcwNzE2NjI4Nw@@._V1_FMjpg_UX1000_.jpg', 'Noomi Rapace, Michael Fassbender, Charlize Theron, Idris Elba, Guy Pearce, Logan Marshall-Green', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (94931, 'Take This Waltz', 'Drama,Romance', 2011, 'Sarah Polley', 'A happily married woman falls for the artist who lives across the street.', 'https://m.media-amazon.com/images/M/MV5BMjIzOTc1NTExNV5BMl5BanBnXkFtZTcwOTg5MTY2Nw@@._V1_FMjpg_UX1000_.jpg', 'Michelle Williams, Seth Rogen, Luke Kirby, Sarah Silverman, Jennifer Podemski, Diane D\'Aquila', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (94959, 'Moonrise Kingdom', 'Comedy,Drama,Romance', 2012, 'Wes Anderson', 'Two 12-year-olds, who live on an island, fall in love with each other and elope into the wilderness. While people set out on a search mission, a violent storm approaching them catches their attention.', 'https://m.media-amazon.com/images/M/MV5BMTEwMTc3NDkzOTJeQTJeQWpwZ15BbWU3MDI4NTAwNzc@._V1_FMjpg_UX1000_.jpg', 'Bruce Willis, Edward Norton, Bill Murray, Frances McDormand, Tilda Swinton, Jared Gilman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (94985, 'Get the Gringo', 'Action,Crime,Drama,Thriller', 2012, 'Adrian Grunberg', 'A career criminal nabbed by Mexican authorities is placed in a tough prison where he learns to survive with the help of a young boy.', 'https://m.media-amazon.com/images/M/MV5BYTljNDRmZmMtNTY2MS00MTA4LTg4YmEtMGUzZTVlZjcwYjA5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mel Gibson, Kevin Balmore, Daniel Giménez Cacho, Jesús Ochoa, Dolores Heredia, Peter Gerety', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (95058, 'Cosmopolis', 'Drama', 2012, 'David Cronenberg', 'A 28-year-old billionaire senses his empire collapsing around him.', 'https://m.media-amazon.com/images/M/MV5BMTY1NjI0MDYyNV5BMl5BanBnXkFtZTcwNDIzMDEyOA@@._V1_FMjpg_UX1000_.jpg', 'Robert Pattinson, Sarah Gadon, Paul Giamatti, Kevin Durand, Abdul Ayoola, Juliette Binoche', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (95088, 'Safety Not Guaranteed', 'Comedy,Drama', 2012, 'Colin Trevorrow', 'Three magazine employees head out on an assignment to interview a guy who placed a classified advertisement seeking a companion for time travel.', 'https://m.media-amazon.com/images/M/MV5BZDAzYTlhZjktNmFkNi00YzZjLWI4NmMtYWI1MWJiYzYwNTlkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Aubrey Plaza, Lauren Carlos, Basil Harris, Mary Lynn Rajskub, Jake Johnson, Karan Soni', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (95167, 'Brave', 'Action,Adventure,Animation,Children', 2012, 'Mark Andrews', 'Determined to make her own path in life, Princess Merida defies a custom that brings chaos to her kingdom. Granted one wish, Merida must rely on her bravery and her archery skills to undo a beastly curse.', 'https://m.media-amazon.com/images/M/MV5BMzgwODk3ODA1NF5BMl5BanBnXkFtZTcwNjU3NjQ0Nw@@._V1_FMjpg_UX1000_.jpg', 'Kelly Macdonald, Billy Connolly, Emma Thompson, Julie Walters, Robbie Coltrane, Kevin McKidd', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (95201, 'To Rome with Love', 'Comedy', 2012, 'Woody Allen', 'The lives of some visitors and residents of Rome and the romances, adventures and predicaments they get into.', 'https://m.media-amazon.com/images/M/MV5BMTcwNTg4MDMxM15BMl5BanBnXkFtZTcwNjAzMzY3Nw@@._V1_FMjpg_UX1000_.jpg', 'Pierluigi Marchionne, Flavio Parenti, Alison Pill, Alessandro Tiberi, Alessandra Mastronardi, Alec Baldwin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (95309, 'Seeking a Friend for the End of the World', 'Comedy,Drama,Romance', 2012, 'Lorene Scafaria', 'As an asteroid nears Earth, a man finds himself alone after his wife leaves in a panic. He decides to take a road trip to reunite with his high school sweetheart. Accompanying him is a neighbor who inadvertently puts a wrench in his plan.', 'https://m.media-amazon.com/images/M/MV5BNDgxYzQ5ZGYtZDAyMS00MWNiLWIwMWMtZmIwODUwODFhYjdlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Steve Carell, Keira Knightley, Adam Brody, Connie Britton, Roger Aaron Brown, Rob Huebel', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (95441, 'Ted', 'Comedy,Fantasy', 2012, 'Seth MacFarlane', 'John Bennett, a man whose childhood wish of bringing his teddy bear to life came true, now must decide between keeping the relationship with the bear, Ted or his girlfriend, Lori.', 'https://m.media-amazon.com/images/M/MV5BMTQ1OTU0ODcxMV5BMl5BanBnXkFtZTcwOTMxNTUwOA@@._V1_FMjpg_UX1000_.jpg', 'Mark Wahlberg, Mila Kunis, Seth MacFarlane, Joel McHale, Giovanni Ribisi, Patrick Warburton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (95510, 'Amazing Spider-Man, The', 'Action,Adventure,Sci-Fi,IMAX', 2012, 'Marc Webb', 'After Peter Parker is bitten by a genetically altered spider, he gains newfound, spider-like powers and ventures out to save the city from the machinations of a mysterious reptilian foe.', 'https://m.media-amazon.com/images/M/MV5BMjMyOTM4MDMxNV5BMl5BanBnXkFtZTcwNjIyNzExOA@@._V1_FMjpg_UX1000_.jpg', 'Andrew Garfield, Emma Stone, Rhys Ifans, Denis Leary, Martin Sheen, Sally Field', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (95558, 'Beasts of the Southern Wild', 'Drama,Fantasy', 2012, 'Benh Zeitlin', 'Faced with both her hot-tempered father\'s fading health and melting ice-caps that flood her ramshackle bayou community and unleash ancient aurochs, six-year-old Hushpuppy must learn the ways of courage and love.', 'https://m.media-amazon.com/images/M/MV5BMTgxNDM5MDM1Ml5BMl5BanBnXkFtZTcwOTYwNzQ3Nw@@._V1_FMjpg_UX1000_.jpg', 'Quvenzhané Wallis, Dwight Henry, Levy Easterly, Lowell Landes, Pamela Harper, Gina Montana', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (95583, 'Savages', 'Crime,Drama,Thriller', 2012, 'Oliver Stone', 'Pot growers Ben and Chon face off against the Mexican drug cartel who kidnapped their shared girlfriend.', 'https://m.media-amazon.com/images/M/MV5BMTk0ODIyNDAyMF5BMl5BanBnXkFtZTcwMTQ5Nzg3Nw@@._V1_FMjpg_UX1000_.jpg', 'Blake Lively, Taylor Kitsch, Aaron Taylor-Johnson, Jana Banker, Candra Docherty, Nana Ghana', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (95875, 'Total Recall', 'Action,Sci-Fi,Thriller', 2012, 'Len Wiseman', 'A factory worker, Douglas Quaid, begins to suspect that he is a spy after visiting Rekall - a company that provides its clients with implanted fake memories of a life they would like to have led - goes wrong and he finds himself on the run.', 'https://m.media-amazon.com/images/M/MV5BOWYzNDNiYzUtNWMwOS00YmFkLTkzN2UtYmVmOGJlNDdjZWUyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Colin Farrell, Kate Beckinsale, Jessica Biel, Bryan Cranston, Bokeem Woodbine, Bill Nighy', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (96079, 'Skyfall', 'Action,Adventure,Thriller,IMAX', 2012, 'Sam Mendes', 'James Bond\'s loyalty to M is tested when her past comes back to haunt her. When MI6 comes under attack, 007 must track down and destroy the threat, no matter how personal the cost.', 'https://m.media-amazon.com/images/M/MV5BNjAzMWNkODUtM2FlMi00NzgyLWJhMGUtMWEyNDYyZGFiN2RlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Daniel Craig, Judi Dench, Javier Bardem, Ralph Fiennes, Naomie Harris, Bérénice Marlohe', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (96488, 'Searching for Sugar Man', 'Documentary', 2012, 'Malik Bendjelloul', 'Two South Africans set out to discover what happened to their unlikely musical hero, the mysterious 1970s rock n roller, Rodriguez.', 'https://m.media-amazon.com/images/M/MV5BMjA5Nzc2NDUyN15BMl5BanBnXkFtZTcwNjQwMjc5Nw@@._V1_FMjpg_UX1000_.jpg', 'Stephen \'Sugar\' Segerman, Dennis Coffey, Mike Theodore, Dan DiMaggio, Jerome Ferretti, Steve Rowland', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (96501, 'Little White Lies (Les petits mouchoirs)', 'Comedy,Drama', 2010, 'Guillaume Canet', 'A near-fatal accident leaves one friend in the hospital while the rest go on their annual vacation. But their secrets and personal grief threaten to drive them apart.', 'https://m.media-amazon.com/images/M/MV5BMWU5YTkxNDktZDMyYy00YmM1LTk0OTAtNDQyM2FkYTM4ZGFkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'François Cluzet, Marion Cotillard, Benoît Magimel, Gilles Lellouche, Jean Dujardin, Laurent Lafitte', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (96588, 'Pitch Perfect', 'Comedy,Musical', 2012, 'Jason Moore', 'Beca, a freshman at Barden University, is cajoled into joining The Bellas, her school\'s all-girls singing group. Injecting some much needed energy into their repertoire, The Bellas take on their male rivals in a campus competition.', 'https://m.media-amazon.com/images/M/MV5BMTcyMTMzNzE5N15BMl5BanBnXkFtZTcwNzg5NjM5Nw@@._V1_FMjpg_UX1000_.jpg', 'Anna Kendrick, Skylar Astin, Ben Platt, Brittany Snow, Anna Camp, Rebel Wilson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (96610, 'Looper', 'Action,Crime,Sci-Fi', 2012, 'Rian Johnson', 'In 2074, when the mob wants to get rid of someone, the target is sent into the past, where a hired gun awaits - someone like Joe - who one day learns the mob wants to \'close the loop\' by sending back Joe\'s future self for assassination.', 'https://m.media-amazon.com/images/M/MV5BMTg5NTA3NTg4NF5BMl5BanBnXkFtZTcwNTA0NDYzOA@@._V1_FMjpg_UX1000_.jpg', 'Joseph Gordon-Levitt, Bruce Willis, Emily Blunt, Paul Dano, Noah Segan, Piper Perabo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (96655, 'Robot & Frank', 'Comedy,Drama,Sci-Fi', 2012, 'Jake Schreier', 'In the near future, an ex-jewel thief receives a gift from his son: a robot butler programmed to look after him. But soon the two companions try their luck as a heist team.', 'https://m.media-amazon.com/images/M/MV5BMTUzMTE0NTk4Ml5BMl5BanBnXkFtZTcwNjQ1OTMwOA@@._V1_FMjpg_UX1000_.jpg', 'Frank Langella, James Marsden, Liv Tyler, Peter Sarsgaard, Susan Sarandon, Jeremy Strong', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (96693, 'Trouble with the Curve', 'Drama', 2012, 'Robert Lorenz', 'A daughter tries to remedy her dysfunctional relationship with her ailing father, a decorated baseball scout, by helping him in a recruiting trip which could be his last.', 'https://m.media-amazon.com/images/M/MV5BMTUwNjMyMzQ3M15BMl5BanBnXkFtZTcwMjcwNDMyOA@@._V1_FMjpg_UX1000_.jpg', 'Clint Eastwood, Chelcie Ross, Raymond Anthony Thomas, Ed Lauter, Amy Adams, Clifton Guterman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (96728, 'Master, The', 'Drama', 2012, 'Paul Thomas Anderson', 'A Naval veteran arrives home from war unsettled and uncertain of his future - until he is tantalized by a cult and its charismatic leader.', 'https://m.media-amazon.com/images/M/MV5BMTQ2NjQ5MzMwMF5BMl5BanBnXkFtZTcwMjczNTAzOA@@._V1_FMjpg_UX1000_.jpg', 'Joaquin Phoenix, Price Carson, Mike Howard, Sarah Shoshana David, Bruce Goodchild, Matt Hering', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (96737, 'Dredd', 'Action,Sci-Fi', 2012, 'Pete Travis', 'In a violent, futuristic metropolis, a law enforcement and his rookie trainee become caught up in a high-stakes drug war.', 'https://m.media-amazon.com/images/M/MV5BODkyNDQzMzUzOF5BMl5BanBnXkFtZTcwODYyMDEyOA@@._V1_FMjpg_UX1000_.jpg', 'Karl Urban, Rachel Wood, Andile Mngadi, Porteus Xandau, Jason Cope, Emma Breschi', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (96811, 'End of Watch', 'Crime,Drama,Thriller', 2012, 'David Ayer', 'Shot documentary-style, this film follows the daily grind of two young police officers in LA who are partners and close friends.', 'https://m.media-amazon.com/images/M/MV5BMjMxNjU0ODU5Ml5BMl5BanBnXkFtZTcwNjI4MzAyOA@@._V1_FMjpg_UX1000_.jpg', 'Jake Gyllenhaal, Michael Peña, Natalie Martinez, Anna Kendrick, David Harbour, Frank Grillo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (96821, 'Perks of Being a Wallflower, The', 'Drama,Romance', 2012, 'Stephen Chbosky', 'Charlie, a 15-year-old introvert, enters high school and is nervous about his new life. When he befriends two seniors, he learns to cope with his friend\'s suicide and his tumultuous past.', 'https://m.media-amazon.com/images/M/MV5BNTY0ZTI2NzQtYWI1YS00ZWM3LWFmMjMtZWYxNmNmOTI0MGJjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Logan Lerman, Dylan McDermott, Kate Walsh, Patrick de Ledebur, Johnny Simmons, Brian Balzerini', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (96829, 'Hunt, The (Jagten)', 'Drama', 2012, 'Thomas Vinterberg', 'A teacher lives a lonely life, all the while struggling over his son\'s custody. His life slowly gets better as he finds love and receives good news from his son, but his new luck is about to be brutally shattered by an innocent little lie.', 'https://m.media-amazon.com/images/M/MV5BMTg2NDg3ODg4NF5BMl5BanBnXkFtZTcwNzk3NTc3Nw@@._V1_FMjpg_UX1000_.jpg', 'Mads Mikkelsen, Thomas Bo Larsen, Annika Wedderkopp, Lasse Fogelstrøm, Susse Wold, Anne Louise Hassing', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (97304, 'Argo', 'Drama,Thriller', 2012, 'Ben Affleck', 'Acting under the cover of a Hollywood producer scouting a location for a science fiction film, a CIA agent launches a dangerous operation to rescue six Americans in Tehran during the U.S. hostage crisis in Iran in 1979.', 'https://m.media-amazon.com/images/M/MV5BM2QyMGUyZTEtMjE4Yi00M2RiLTgwN2QtZDMxZDNiMTFkMTFjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ben Affleck, Bryan Cranston, Alan Arkin, John Goodman, Victor Garber, Tate Donovan', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (97306, 'Seven Psychopaths', 'Comedy,Crime', 2012, 'Martin McDonagh', 'A struggling screenwriter inadvertently becomes entangled in the Los Angeles criminal underworld after his oddball friends kidnap a gangster\'s beloved Shih Tzu.', 'https://m.media-amazon.com/images/M/MV5BMTgwMzUxMjc0M15BMl5BanBnXkFtZTcwMzQ2MjYyOA@@._V1_FMjpg_UX1000_.jpg', 'Michael Pitt, Michael Stuhlbarg, Sam Rockwell, Colin Farrell, Abbie Cornish, Christopher Walken', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (97752, 'Cloud Atlas', 'Drama,Sci-Fi,IMAX', 2012, 'Tom Tykwer', 'As souls are born and reborn, they renew their connections to one another throughout the ages.', 'https://m.media-amazon.com/images/M/MV5BMTczMTgxMjc4NF5BMl5BanBnXkFtZTcwNjM5MTA2OA@@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Halle Berry, Jim Broadbent, Hugo Weaving, Jim Sturgess, Bae Doona', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (97866, 'Imposter, The', 'Documentary', 2012, 'Bart Layton', 'A documentary centered on a young man in Spain who claims to a grieving Texas family that he is their 16-year-old son who has been missing for 3 years.', 'https://m.media-amazon.com/images/M/MV5BMmJjNTI4N2YtNTM0Yi00MGIwLTliYWYtYmEzZTAwYjllNDZmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nicholas Barclay, Carey Gibson, Bryan Gibson, Beverly Dollarhide, Frédéric Bourdin, Nancy Fisher', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (97870, 'Sessions, The (Surrogate, The)', 'Drama', 2012, 'Ben Lewin', 'A man in an iron lung who wishes to lose his virginity contacts a professional sex surrogate with the help of his therapist and priest.', 'https://m.media-amazon.com/images/M/MV5BMTQzNTU4NjMzNV5BMl5BanBnXkFtZTcwNDQzMTY1OA@@._V1_FMjpg_UX1000_.jpg', 'John Hawkes, Helen Hunt, William H. Macy, Moon Bloodgood, Annika Marks, Adam Arkin', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (97913, 'Wreck-It Ralph', 'Animation,Comedy', 2012, 'Rich Moore', 'Ralph is tired of playing the role of a bad guy and embarks on a journey to become a video game hero. But he accidentally lets loose a deadly enemy that threatens the entire arcade.', 'https://m.media-amazon.com/images/M/MV5BNzMxNTExOTkyMF5BMl5BanBnXkFtZTcwMzEyNDc0OA@@._V1_FMjpg_UX1000_.jpg', 'John C. Reilly, Sarah Silverman, Jack McBrayer, Jane Lynch, Alan Tudyk, Mindy Kaling', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (97921, 'Silver Linings Playbook', 'Comedy,Drama', 2012, 'David O. Russell', 'After a stint in a mental institution, former teacher Pat Solitano moves back in with his parents and tries to reconcile with his ex-wife. Things get more challenging when Pat meets Tiffany, a mysterious girl with problems of her own.', 'https://m.media-amazon.com/images/M/MV5BMTM2MTI5NzA3MF5BMl5BanBnXkFtZTcwODExNTc0OA@@._V1_FMjpg_UX1000_.jpg', 'Bradley Cooper, Jennifer Lawrence, Robert De Niro, Jacki Weaver, Chris Tucker, Anupam Kher', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (97923, 'Flight', 'Drama', 2012, 'Robert Zemeckis', 'Troubling questions arise after airline pilot Whip Whitaker makes a miracle landing after a mid-air catastrophe.', 'https://m.media-amazon.com/images/M/MV5BMTUxMjI1OTMxNl5BMl5BanBnXkFtZTcwNjc3NTY1OA@@._V1_FMjpg_UX1000_.jpg', 'Nadine Velazquez, Denzel Washington, Carter Cabassa, Adam C. Edwards, Tamara Tunie, Brian Geraghty', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (97938, 'Life of Pi', 'Adventure,Drama,IMAX', 2012, 'Ang Lee', 'A young man who survives a disaster at sea is hurtled into an epic journey of adventure and discovery. While cast away, he forms an unexpected connection with another survivor: a fearsome Bengal tiger.', 'https://m.media-amazon.com/images/M/MV5BNTg2OTY2ODg5OF5BMl5BanBnXkFtZTcwODM5MTYxOA@@._V1_FMjpg_UX1000_.jpg', 'Suraj Sharma, Irrfan Khan, Ayush Tandon, Gautam Belur, Adil Hussain, Tabu', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (98243, 'Rise of the Guardians', 'Adventure,Animation,Children,Fantasy,IMAX', 2012, 'Peter Ramsey', 'When the evil spirit Pitch launches an assault on Earth, the Immortal Guardians team up to protect the innocence of children all around the world.', 'https://m.media-amazon.com/images/M/MV5BMTkzMjgwMDg1M15BMl5BanBnXkFtZTcwMTgzNTI1OA@@._V1_FMjpg_UX1000_.jpg', 'Chris Pine, Alec Baldwin, Jude Law, Isla Fisher, Hugh Jackman, Dakota Goyo', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (98585, 'Hitchcock', 'Drama', 2012, 'Sacha Gervasi', 'The relationship between Alfred Hitchcock and his wife Alma Reville during the filming of Psycho (1960) in 1959 is explored.', 'https://m.media-amazon.com/images/M/MV5BODAwNDI5NjIwN15BMl5BanBnXkFtZTcwNjc4ODc2OA@@._V1_FMjpg_UX1000_.jpg', 'Anthony Hopkins, Helen Mirren, Scarlett Johansson, Danny Huston, Toni Collette, Michael Stuhlbarg', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (98809, 'Hobbit: An Unexpected Journey, The', 'Adventure,Fantasy,IMAX', 2012, 'Peter Jackson', 'A reluctant Hobbit, Bilbo Baggins, sets out to the Lonely Mountain with a spirited group of dwarves to reclaim their mountain home and the gold within it from the dragon Smaug.', 'https://m.media-amazon.com/images/M/MV5BMTcwNTE4MTUxMl5BMl5BanBnXkFtZTcwMDIyODM4OA@@._V1_FMjpg_UX1000_.jpg', 'Ian McKellen, Martin Freeman, Richard Armitage, Ken Stott, Graham McTavish, William Kircher', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (98836, 'Hyde Park on Hudson', 'Comedy,Drama', 2012, 'Roger Michell', 'The story of the love affair between FDR and his distant cousin Margaret \"Daisy\" Suckley, centered around the weekend in 1939 when the King and Queen of the United Kingdom visited upstate New York.', 'https://m.media-amazon.com/images/M/MV5BNjU1MzU3Nzc4OF5BMl5BanBnXkFtZTcwOTk5NDI4Nw@@._V1_FMjpg_UX1000_.jpg', 'Bill Murray, Laura Linney, Samuel West, Olivia Colman, Elizabeth Marvel, Olivia Williams', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (98961, 'Zero Dark Thirty', 'Action,Drama,Thriller', 2012, 'Kathryn Bigelow', 'A chronicle of the decade-long hunt for al-Qaeda terrorist leader Osama bin Laden after the September 2001 attacks, and his death at the hands of the Navy S.E.A.L.s Team 6 in May 2011.', 'https://m.media-amazon.com/images/M/MV5BMTQ4OTUyNzcwN15BMl5BanBnXkFtZTcwMTQ1NDE3OA@@._V1_FMjpg_UX1000_.jpg', 'Jason Clarke, Reda Kateb, Jessica Chastain, Kyle Chandler, Jennifer Ehle, Harold Perrineau', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (99007, 'Warm Bodies', 'Comedy,Horror,Romance', 2013, 'Jonathan Levine', 'After a highly unusual zombie saves a still-living girl from an attack, the two form a relationship that sets in motion events that might transform the entire lifeless world.', 'https://m.media-amazon.com/images/M/MV5BNTM2YWZhMDUtMzEzMi00YzUzLWI0ZjYtNzgzNTA4YWEzOTdkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nicholas Hoult, Teresa Palmer, Lio Tipton, Rob Corddry, Dave Franco, John Malkovich', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (99114, 'Django Unchained', 'Action,Drama,Western', 2012, 'Quentin Tarantino', 'With the help of a German bounty-hunter, a freed slave sets out to rescue his wife from a brutal plantation owner in Mississippi.', 'https://m.media-amazon.com/images/M/MV5BMjIyNTQ5NjQ1OV5BMl5BanBnXkFtZTcwODg1MDU4OA@@._V1_FMjpg_UX1000_.jpg', 'Jamie Foxx, Christoph Waltz, Leonardo DiCaprio, Kerry Washington, Samuel L. Jackson, Walton Goggins', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (99149, 'Misérables, Les', 'Drama,Musical,Romance,IMAX', 2012, 'Tom Hooper', 'In 19th-century France, Jean Valjean, who, for decades, has been hunted by the ruthless policeman Javert after breaking parole, agrees to care for a factory worker\'s daughter. The decision changes their lives forever.', 'https://m.media-amazon.com/images/M/MV5BY2Q1YjIxZTAtZTU0YS00ZmE5LWEwODEtY2IyYWM2ZTJlOWE1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Hugh Jackman, Russell Crowe, Anne Hathaway, Amanda Seyfried, Sacha Baron Cohen, Helena Bonham Carter', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (99294, 'Willow Tree, The (Beed-e majnoon)', 'Drama', 2005, 'Majid Majidi', 'Youssef, a blind university professor, is suddenly diagnosed with a fatal disease and must undergo treatment in France. Back home, will he find the life he had before?', 'https://m.media-amazon.com/images/M/MV5BN2Q5NjA5MWQtNmEyOS00ZDQ4LWE1NjAtYjgwOTM3Mzg4NWUzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Parviz Parastui, Roya Teymourian, Soghra Obeisi, Melika Eslafi, Mahmoud Behraznia, Dawlat Asadi', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (99636, 'English Vinglish', 'Comedy,Drama', 2012, 'Gauri Shinde', 'A quiet, sweet tempered housewife endures small slights from her well-educated husband and daughter every day because of her inability to speak and understand English.', 'https://m.media-amazon.com/images/M/MV5BMmMwYzZhNTgtMzhhZC00N2FmLTlmY2MtZWJmZWE2MjJhMGE4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sridevi, Adil Hussain, Mehdi Nebbou, Priya Anand, Sujata Kumar, Sulabha Deshpande', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (99728, 'Gangster Squad', 'Action,Crime,Drama', 2013, 'Ruben Fleischer', 'It\'s 1949 Los Angeles, the city is run by gangsters and a malicious mobster, Mickey Cohen. Determined to end the corruption, John O\'Mara assembles a team of cops, ready to take down the ruthless leader and restore peace to the city.', 'https://m.media-amazon.com/images/M/MV5BMTcwMjAyMTUzMl5BMl5BanBnXkFtZTcwODgxNzk1OA@@._V1_FMjpg_UX1000_.jpg', 'Sean Penn, Holt McCallany, Wade Williams, James Landry Hébert, Ambyr Childers, Josh Brolin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (99741, 'Company You Keep, The', 'Thriller', 2012, 'Robert Redford', 'After a journalist discovers his identity, a former Weather Underground activist goes on the run.', 'https://m.media-amazon.com/images/M/MV5BMTQ0NDQxOTY3M15BMl5BanBnXkFtZTcwNTE0MTExOQ@@._V1_FMjpg_UX1000_.jpg', 'Robert Redford, Shia LaBeouf, Julie Christie, Susan Sarandon, Nick Nolte, Chris Cooper', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (99912, 'Mama', 'Horror', 2013, 'Andy Muschietti', 'Two little girls disappear into the woods the day that their parents were killed. When they are found 5 years later and begin a new life, they find that someone or something still wants to tuck them in at night.', 'https://m.media-amazon.com/images/M/MV5BMTM5MjIwNDAwMl5BMl5BanBnXkFtZTcwNzQyOTY0OA@@._V1_FMjpg_UX1000_.jpg', 'Jessica Chastain, Nikolaj Coster-Waldau, Megan Charpentier, Isabelle Nélisse, Daniel Kash, Javier Botet', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (100383, 'Side Effects', 'Crime,Drama,Mystery,Thriller', 2013, 'Steven Soderbergh', 'A young woman\'s world unravels when a drug prescribed by her psychiatrist has unexpected side effects.', 'https://m.media-amazon.com/images/M/MV5BMTc2MzY0NDAwOF5BMl5BanBnXkFtZTcwMTE1Mzc4OA@@._V1_FMjpg_UX1000_.jpg', 'Rooney Mara, Jude Law, Channing Tatum, Catherine Zeta-Jones, Polly Draper, Vinessa Shaw', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (100556, 'Act of Killing, The', 'Documentary', 2012, 'Anonymous', 'A documentary which challenges former Indonesian death-squad leaders to reenact their mass-killings in whichever cinematic genres they wish, including classic Hollywood crime scenarios and lavish musical numbers.', 'https://m.media-amazon.com/images/M/MV5BZDg1NDMwMGQtMmFkZS00NTQwLTkxYjktMTlhNjI2NzNlYTQ1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Anwar Congo, Herman Koto, Syamsul Arifin, Ibrahim Sinik, Yapto Soerjosoemarno, Safit Pardede', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (100714, 'Before Midnight', 'Drama,Romance', 2013, 'Richard Linklater', 'We meet Jesse and Celine nine years on in Greece. Almost two decades have passed since their first meeting on that train bound for Vienna.', 'https://m.media-amazon.com/images/M/MV5BMjA5NzgxODE2NF5BMl5BanBnXkFtZTcwNTI1NTI0OQ@@._V1_FMjpg_UX1000_.jpg', 'Ethan Hawke, Julie Delpy, Seamus Davey-Fitzpatrick, Jennifer Prior, Charlotte Prior, Xenia Kalogeropoulou', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (101112, 'Oz the Great and Powerful', 'Action,Adventure,Fantasy,IMAX', 2013, 'Sam Raimi', 'A small-time magician is swept away to an enchanted land and is forced into a power struggle among three witches.', 'https://m.media-amazon.com/images/M/MV5BNDRlOTNlMWMtM2FlMi00MzNiLTk1NzEtNjc3Njg1M2NkNmY5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'James Franco, Mila Kunis, Rachel Weisz, Michelle Williams, Zach Braff, Bill Cobbs', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (101260, 'StarStruck', 'Comedy,Musical', 2010, 'Michael Grossman', 'Jessica Olsen was expecting a normal trip to California with her family to visit her grandma. However, she agrees to join her older sister to find famous pop star Christopher Wilde.', 'https://m.media-amazon.com/images/M/MV5BMjU4MjZjZGMtMmMxMC00NGE1LWIzNDQtMWE1NmM1YjYzOTk4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sterling Knight, Danielle Campbell, Maggie Castle, Brandon Mychal Smith, Chelsea Kane, Matt Winston', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (101281, 'I Give It a Year', 'Comedy,Romance', 2013, 'Dan Mazer', 'Newlywed couple Nat and Josh are deliriously happy despite their differences, though friends and family aren\'t convinced that they can last. With their first anniversary approaching and attractive alternatives in the mix, can they last?', 'https://m.media-amazon.com/images/M/MV5BMTg5NDk4MTUwNl5BMl5BanBnXkFtZTcwMDU5MTc4OQ@@._V1_FMjpg_UX1000_.jpg', 'Rose Byrne, Rafe Spall, Minnie Driver, Alex Macqueen, Stephen Merchant, Jane Asher', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (101362, 'Olympus Has Fallen', 'Action,Thriller', 2013, 'Antoine Fuqua', 'Secret Service agent Mike Banning finds himself trapped inside the White House in the wake of a terrorist attack and works with national security to rescue the President from his kidnappers.', 'https://m.media-amazon.com/images/M/MV5BNzg3Mjc0YzItZWQyOS00ODY4LTgwZjUtYWRmYzM1MDg1ZDA5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gerard Butler, Aaron Eckhart, Finley Jacobsen, Dylan McDermott, Rick Yune, Morgan Freeman', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (101525, 'Place Beyond the Pines, The', 'Crime,Drama', 2012, 'Derek Cianfrance', 'A stunt rider turns into a robber in order to lead a happy life with his child and lover and grabs the attention of a police officer. They both get on a collision course that affects their families.', 'https://m.media-amazon.com/images/M/MV5BMjc1OTEwNjU4N15BMl5BanBnXkFtZTcwNzUzNDIwOQ@@._V1_FMjpg_UX1000_.jpg', 'Ryan Gosling, Craig Van Hook, Eva Mendes, Olga Merediz, Angelo Anthony Pizza, Mahershala Ali', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (101739, 'Evil Dead', 'Horror', 2013, 'Fede Alvarez', 'Five friends head to a remote cabin, where the discovery of a Book of the Dead leads them to unwittingly summon up demons living in the nearby woods.', 'https://m.media-amazon.com/images/M/MV5BYjkwODM5ZWUtMjI2Ni00Y2RiLWJkNDYtZWQ2ZTRhMjI1N2FmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jane Levy, Shiloh Fernandez, Lou Taylor Pucci, Jessica Lucas, Elizabeth Blackmore, Phoenix Connolly', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (101741, 'Trance', 'Crime,Thriller', 2013, 'Danny Boyle', 'An art auctioneer mixed up with a group of criminals partners with a hypnotherapist in order to recover a lost painting.', 'https://m.media-amazon.com/images/M/MV5BMjMzNjU1MTg5NF5BMl5BanBnXkFtZTcwMTExMTcwOQ@@._V1_FMjpg_UX1000_.jpg', 'James McAvoy, Vincent Cassel, Rosario Dawson, Danny Sapani, Matt Cross, Wahab Sheikh', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (101864, 'Oblivion', 'Action,Adventure,Sci-Fi,IMAX', 2013, 'Joseph Kosinski', 'A stranger\'s arrival triggers one man\'s battle to save mankind.', 'https://m.media-amazon.com/images/M/MV5BMTQwMDY0MTA4MF5BMl5BanBnXkFtZTcwNzI3MDgxOQ@@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Morgan Freeman, Olga Kurylenko, Andrea Riseborough, Nikolaj Coster-Waldau, Melissa Leo', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (101895, '42', 'Drama', 2013, 'Brian Helgeland', 'In 1947, Jackie Robinson becomes the first African-American to play in Major League Baseball in the modern era when he was signed by the Brooklyn Dodgers and faces considerable racism in the process.', 'https://m.media-amazon.com/images/M/MV5BMTQwMDU4MDI3MV5BMl5BanBnXkFtZTcwMjU1NDgyOQ@@._V1_FMjpg_UX1000_.jpg', 'Chadwick Boseman, Harrison Ford, Nicole Beharie, Christopher Meloni, Ryan Merriman, Lucas Black', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (102125, 'Iron Man 3', 'Action,Sci-Fi,Thriller,IMAX', 2013, 'Shane Black', 'When Tony Stark\'s world is torn apart by a formidable terrorist called the Mandarin, he starts an odyssey of rebuilding and retribution.', 'https://m.media-amazon.com/images/M/MV5BMjIzMzAzMjQyM15BMl5BanBnXkFtZTcwNzM2NjcyOQ@@._V1_FMjpg_UX1000_.jpg', 'Robert Downey Jr., Gwyneth Paltrow, Don Cheadle, Guy Pearce, Rebecca Hall, Jon Favreau', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (102407, 'Great Gatsby, The', 'Drama', 2013, 'Baz Luhrmann', 'A writer and wall street trader, Nick Carraway, finds himself drawn to the past and lifestyle of his mysterious millionaire neighbor, Jay Gatsby, amid the riotous parties of the Jazz Age.', 'https://m.media-amazon.com/images/M/MV5BMTkxNTk1ODcxNl5BMl5BanBnXkFtZTcwMDI1OTMzOQ@@._V1_FMjpg_UX1000_.jpg', 'Lisa Adam, Frank Aldridge, Amitabh Bachchan, Steve Bisley, Richard Carter, Jason Clarke', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (102445, 'Star Trek Into Darkness', 'Action,Adventure,Sci-Fi,IMAX', 2013, 'J.J. Abrams', 'After the crew of the Enterprise find an unstoppable force of terror from within their own organization, Captain Kirk leads a manhunt to a war-zone world to capture a one-man weapon of mass destruction.', 'https://m.media-amazon.com/images/M/MV5BMTk2NzczOTgxNF5BMl5BanBnXkFtZTcwODQ5ODczOQ@@._V1_FMjpg_UX1000_.jpg', 'Leonard Nimoy, Chris Pine, Zachary Quinto, Zoe Saldaña, Karl Urban, Simon Pegg', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (102686, 'Hangover Part III, The', 'Comedy', 2013, 'Todd Phillips', 'When one of their own is kidnapped by an angry gangster, the Wolf Pack must track down Mr. Chow, who has escaped from prison and is on the run.', 'https://m.media-amazon.com/images/M/MV5BMTA0NjE1MzMzODheQTJeQWpwZ15BbWU3MDY4MTQ3Mzk@._V1_FMjpg_UX1000_.jpg', 'Bradley Cooper, Ed Helms, Zach Galifianakis, Justin Bartha, Ken Jeong, John Goodman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (102753, 'Past, The (Le passé)', 'Drama,Mystery,Romance', 2013, 'Asghar Farhadi', 'An Iranian man deserts his French wife and her two children to return to his homeland. Meanwhile, his wife starts up a new relationship, a reality her husband confronts upon his wife\'s request for a divorce.', 'https://m.media-amazon.com/images/M/MV5BMTcxNTgzNDg1N15BMl5BanBnXkFtZTgwNjg4MzI1MDE@._V1_FMjpg_UX1000_.jpg', 'Bérénice Bejo, Ali Mosaffa, Tahar Rahim, Pauline Burlet, Elyes Aguis, Jeanne Jestin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (102903, 'Now You See Me', 'Crime,Mystery,Thriller', 2013, 'Louis Leterrier', 'An FBI agent and an Interpol detective track a team of illusionists who pull off bank heists during their performances, and reward their audiences with the money.', 'https://m.media-amazon.com/images/M/MV5BMTY0NDY3MDMxN15BMl5BanBnXkFtZTcwOTM5NzMzOQ@@._V1_FMjpg_UX1000_.jpg', 'Jesse Eisenberg, Mark Ruffalo, Woody Harrelson, Isla Fisher, Dave Franco, Mélanie Laurent', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103107, '20 Feet from Stardom (Twenty Feet from Stardom)', 'Documentary', 2013, 'Morgan Neville', 'Backup singers live in a world that lies just beyond the spotlight. Their voices bring harmony to the biggest bands in popular music, but we\'ve had no idea who these singers are or what lives they lead, until now.', 'https://m.media-amazon.com/images/M/MV5BMTQxNDY2NjMwNF5BMl5BanBnXkFtZTcwNzExMDg0OQ@@._V1_FMjpg_UX1000_.jpg', 'Lou Adler, Stephanie \'Stevvi\' Alexander, Patti Austin, Chris Botti, Todd Boyd, Carole Childs', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103137, 'Bling Ring, The', 'Crime,Drama', 2013, 'Sofia Coppola', 'Inspired by actual events, a group of fame-obsessed teenagers use the internet to track celebrities\' whereabouts in order to rob their homes.', 'https://m.media-amazon.com/images/M/MV5BMTQzMTgwMzQxN15BMl5BanBnXkFtZTcwOTcwNTY0OQ@@._V1_FMjpg_UX1000_.jpg', 'Katie Chang, Israel Broussard, Emma Watson, Claire Julien, Taissa Farmiga, Georgia Rock', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103141, 'Monsters University', 'Adventure,Animation,Comedy', 2013, 'Dan Scanlon', 'A look at the relationship between Mike Wazowski and James P. \"Sully\" Sullivan during their days at Monsters University, when they weren\'t necessarily the best of friends.', 'https://m.media-amazon.com/images/M/MV5BMTUyODgwMDU3M15BMl5BanBnXkFtZTcwOTM4MjcxOQ@@._V1_FMjpg_UX1000_.jpg', 'Billy Crystal, John Goodman, Steve Buscemi, Helen Mirren, Peter Sohn, Joel Murray', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103228, 'Pacific Rim', 'Action,Adventure,Sci-Fi,IMAX', 2013, 'Guillermo del Toro', 'As a war between humankind and monstrous sea creatures wages on, a former pilot and a trainee are paired up to drive a seemingly obsolete special weapon in a desperate effort to save the world from the apocalypse.', 'https://m.media-amazon.com/images/M/MV5BMTY3MTI5NjQ4Nl5BMl5BanBnXkFtZTcwOTU1OTU0OQ@@._V1_FMjpg_UX1000_.jpg', 'Charlie Hunnam, Diego Klattenhoff, Idris Elba, Rinko Kikuchi, Charlie Day, Burn Gorman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103249, 'World War Z', 'Action,Drama,Horror,IMAX', 2013, 'Marc Forster', 'Former United Nations employee Gerry Lane traverses the world in a race against time to stop a zombie pandemic that is toppling armies and governments and threatens to destroy humanity itself.', 'https://m.media-amazon.com/images/M/MV5BODg3ZTM2YWQtZDE5Ny00NGNiLTkzYjgtYWVlYjNkOTg5NDI1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brad Pitt, Mireille Enos, Daniella Kertesz, James Badge Dale, Ludi Boeken, Matthew Fox', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103253, 'Elysium', 'Action,Drama,Sci-Fi,IMAX', 2013, 'Neill Blomkamp', 'In the year 2154, the very wealthy live on a man-made space station while the rest of the population resides on a ruined Earth. A man takes on a mission that could bring equality to the polarized worlds.', 'https://m.media-amazon.com/images/M/MV5BNDc2NjU0MTcwNV5BMl5BanBnXkFtZTcwMjg4MDg2OQ@@._V1_FMjpg_UX1000_.jpg', 'Matt Damon, Jodie Foster, Sharlto Copley, Alice Braga, Diego Luna, Wagner Moura', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103335, 'Despicable Me 2', 'Animation,Children,Comedy,IMAX', 2013, 'Pierre Coffin', 'When a new criminal comes to town, the Anti-Villain League decides to hire Gru in order to fight him off. While Gru initially refuses, he eventually agrees after his aide goes back to his evil ways.', 'https://m.media-amazon.com/images/M/MV5BMTQxNzY1MjI5NF5BMl5BanBnXkFtZTcwNTI0MDY1OQ@@._V1_FMjpg_UX1000_.jpg', 'Steve Carell, Kristen Wiig, Benjamin Bratt, Miranda Cosgrove, Russell Brand, Ken Jeong', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103339, 'White House Down', 'Action,Drama,Thriller,IMAX', 2013, 'Roland Emmerich', 'While on a tour of the White House with his young daughter, a Capitol policeman springs into action to save his child and protect the president from a heavily armed group of dangerous terrorists.', 'https://m.media-amazon.com/images/M/MV5BNTZkMmRiY2EtOTljZS00MjJjLWFiNDQtNjEwYWE0NWNkYjI4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Channing Tatum, Jamie Foxx, Maggie Gyllenhaal, Jason Clarke, Richard Jenkins, Joey King', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103341, 'World\'s End, The', 'Action,Comedy,Sci-Fi', 2013, 'Edgar Wright', 'Five friends who reunite in an attempt to top their epic pub crawl from twenty years earlier unwittingly become humanity\'s only hope for survival.', 'https://m.media-amazon.com/images/M/MV5BNzA1MTk1MzY0OV5BMl5BanBnXkFtZTgwNjkzNTUwMDE@._V1_FMjpg_UX1000_.jpg', 'Thomas Law, Zachary Bailess, Jasper Levine, James Tarpey, Luke Bromley, Sophie Evans', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103372, 'Heat, The', 'Action,Comedy,Crime', 2013, 'Paul Feig', 'An uptight FBI Special Agent is paired with a foul-mouthed Boston cop to take down a ruthless drug lord.', 'https://m.media-amazon.com/images/M/MV5BMjA2MDQ2ODM3MV5BMl5BanBnXkFtZTcwNDUzMTQ3OQ@@._V1_FMjpg_UX1000_.jpg', 'Sandra Bullock, Melissa McCarthy, Demián Bichir, Marlon Wayans, Michael Rapaport, Jane Curtin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103539, 'The Spectacular Now', 'Comedy,Drama,Romance', 2013, 'James Ponsoldt', 'A hard-partying high school senior\'s philosophy on life changes when he meets the not-so-typical \"nice girl.\"', 'https://m.media-amazon.com/images/M/MV5BMjA5MTc0NTkzM15BMl5BanBnXkFtZTcwODEwNjE3OQ@@._V1_FMjpg_UX1000_.jpg', 'Miles Teller, Shailene Woodley, Brie Larson, Masam Holden, Dayo Okeniyi, Kyle Chandler', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103541, 'Thanks for Sharing', 'Comedy,Drama', 2012, 'Stuart Blumberg', 'A romantic comedy that brings together three disparate characters who are learning to face a challenging and often confusing world as they struggle together against a common demon: sex addiction.', 'https://m.media-amazon.com/images/M/MV5BMjA5MzI3ODcxMF5BMl5BanBnXkFtZTcwODY5MTc4OQ@@._V1_FMjpg_UX1000_.jpg', 'Mark Ruffalo, Tim Robbins, Gwyneth Paltrow, Josh Gad, Joely Richardson, Patrick Fugit', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103624, 'Fruitvale Station', 'Drama', 2013, 'Ryan Coogler', 'The story of Oscar Grant III, a 22-year-old Bay Area resident, who crosses paths with friends, enemies, family, and strangers on the last day of 2008.', 'https://m.media-amazon.com/images/M/MV5BMTQ0OTU1MDkxMF5BMl5BanBnXkFtZTcwNjI5OTA3OQ@@._V1_FMjpg_UX1000_.jpg', 'Michael B. Jordan, Melonie Diaz, Octavia Spencer, Kevin Durand, Chad Michael Murray, Ahna O\'Reilly', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103685, 'Field in England, A', 'Drama,Fantasy,Thriller,War', 2013, 'Ben Wheatley', 'Amid the Civil War in 17th-century England, a group of deserters flee from battle through an overgrown field. Captured by an alchemist, the men are forced to help him search to find a hidden treasure that he believes is buried in the field.', 'https://m.media-amazon.com/images/M/MV5BMjcyNzQyMjI0NF5BMl5BanBnXkFtZTgwNjU2MDc5MDE@._V1_FMjpg_UX1000_.jpg', 'Julian Barratt, Peter Ferdinando, Richard Glover, Ryan Pope, Reece Shearsmith, Michael Smiley', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103688, 'Conjuring, The', 'Horror,Thriller', 2013, 'James Wan', 'Paranormal investigators Ed and Lorraine Warren work to help a family terrorized by a dark presence in their farmhouse.', 'https://m.media-amazon.com/images/M/MV5BMTM3NjA1NDMyMV5BMl5BanBnXkFtZTcwMDQzNDMzOQ@@._V1_FMjpg_UX1000_.jpg', 'Vera Farmiga, Patrick Wilson, Lili Taylor, Ron Livingston, Shanley Caswell, Hayley McFarland', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103819, 'Coffee Town', 'Comedy', 2013, 'Brad Copeland', 'A website manager enlists the help of his two friends in order to convince the owners of his favorite coffee shop -- which doubles as his office -- not to turn their business into a bar.', 'https://m.media-amazon.com/images/M/MV5BMTg4NTE3Njg2OF5BMl5BanBnXkFtZTcwMDU0MjQ2OQ@@._V1_FMjpg_UX1000_.jpg', 'Glenn Howerton, Steve Little, Ben Schwartz, Josh Groban, Adrianne Palicki, Josh Perry', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (103980, 'Blue Jasmine', 'Drama', 2013, 'Woody Allen', 'A New York socialite, deeply troubled and in denial, arrives in San Francisco to impose upon her sister. She looks like a million dollars but isn\'t bringing money, peace or love.', 'https://m.media-amazon.com/images/M/MV5BMTc0ODk5MzEyMV5BMl5BanBnXkFtZTcwMzI0MDY1OQ@@._V1_FMjpg_UX1000_.jpg', 'Cate Blanchett, Joy Carlin, Richard Conti, Glen Caspillo, Alec Baldwin, Charlie Tahan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (104211, 'We\'re the Millers', 'Comedy,Crime', 2013, 'Rawson Marshall Thurber', 'A veteran pot dealer creates a fake family as part of his plan to move a huge shipment of weed into the U.S. from Mexico.', 'https://m.media-amazon.com/images/M/MV5BNDQ0NWI1ZGEtY2NlMy00MWYyLTk4NGEtMTY5MmQ4YTcyY2E0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jennifer Aniston, Jason Sudeikis, Emma Roberts, Will Poulter, Ed Helms, Nick Offerman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (104283, 'Wind Rises, The (Kaze tachinu)', 'Animation,Drama,Romance', 2013, 'Hayao Miyazaki', 'Jiro Horikoshi studies assiduously to fulfill his aim of becoming an aeronautical engineer. As WWII begins, fighter aircraft designed by him end up getting used by the Japanese Empire against its foes.', 'https://m.media-amazon.com/images/M/MV5BMTU4NDg0MzkzNV5BMl5BanBnXkFtZTgwODA3Mzc1MDE@._V1_FMjpg_UX1000_.jpg', 'Hideaki Anno, Hidetoshi Nishijima, Miori Takimoto, Masahiko Nishimura, Mansai Nomura, Jun Kunimura', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (104337, 'Lee Daniels\' The Butler', 'Drama', 2013, 'Lee Daniels', 'As Cecil Gaines serves eight presidents during his tenure as a butler at the White House, the civil rights movement, Vietnam, and other major events affect this man\'s life, family, and American society.', 'https://m.media-amazon.com/images/M/MV5BMjM2NDY3MjkyMF5BMl5BanBnXkFtZTcwMDM5Nzg5OQ@@._V1_FMjpg_UX1000_.jpg', 'Forest Whitaker, David Banner, Michael Rainey Jr., LaJessie Smith, Mariah Carey, Alex Pettyfer', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (104374, 'About Time', 'Drama,Fantasy,Romance', 2013, 'Richard Curtis', 'At the age of 21, Tim discovers he can travel in time and change what happens and has happened in his own life. His decision to make his world a better place by getting a girlfriend turns out not to be as easy as you might think.', 'https://m.media-amazon.com/images/M/MV5BMTA1ODUzMDA3NzFeQTJeQWpwZ15BbWU3MDgxMTYxNTk@._V1_FMjpg_UX1000_.jpg', 'Domhnall Gleeson, Rachel McAdams, Bill Nighy, Lydia Wilson, Lindsay Duncan, Richard Cordery', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (104457, 'You\'re Next', 'Horror,Thriller', 2011, 'Adam Wingard', 'When the Davison family comes under attack during their wedding anniversary getaway, the gang of mysterious killers soon learns that one of the victims harbors a secret talent for fighting back.', 'https://m.media-amazon.com/images/M/MV5BMTQwODAxMTE1NF5BMl5BanBnXkFtZTcwNTQ0MjY3OQ@@._V1_FMjpg_UX1000_.jpg', 'Sharni Vinson, Nicholas Tucci, Wendy Glenn, AJ Bowen, Joe Swanberg, Margaret Laney', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (104841, 'Gravity', 'Action,Sci-Fi,IMAX', 2013, 'Alfonso Cuarón', 'Dr Ryan Stone, an engineer on her first space mission, and Matt Kowalski, an astronaut on his final expedition, have to survive in space after they are hit by debris while spacewalking.', 'https://m.media-amazon.com/images/M/MV5BNjE5MzYwMzYxMF5BMl5BanBnXkFtZTcwOTk4MTk0OQ@@._V1_FMjpg_UX1000_.jpg', 'Sandra Bullock, George Clooney, Ed Harris, Orto Ignatiussen, Phaldut Sharma, Amy Warren', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (104879, 'Prisoners', 'Drama,Mystery,Thriller', 2013, 'Denis Villeneuve', 'A desperate father takes the law into his own hands after police fail to find two kidnapped girls.', 'https://m.media-amazon.com/images/M/MV5BMTg0NTIzMjQ1NV5BMl5BanBnXkFtZTcwNDc3MzM5OQ@@._V1_FMjpg_UX1000_.jpg', 'Hugh Jackman, Jake Gyllenhaal, Viola Davis, Maria Bello, Terrence Howard, Melissa Leo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (104913, 'Rush', 'Action,Drama', 2013, 'Ron Howard', 'James Hunt and Niki Lauda, two extremely skilled Formula One racers, have an intense rivalry with each other. However, it is their enmity that pushes them to their limits.', 'https://m.media-amazon.com/images/M/MV5BMTZhOGQxM2ItNGQyYy00YzE5LWI5MjMtNmMzNGQzNDE1OTUzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chris Hemsworth, Daniel Brühl, Olivia Wilde, Alexandra Maria Lara, Pierfrancesco Favino, David Calder', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (104944, 'Short Term 12', 'Drama', 2013, 'Destin Daniel Cretton', 'A 20-something supervising staff member of a residential treatment facility navigates the troubled waters of that world alongside her co-worker and longtime boyfriend.', 'https://m.media-amazon.com/images/M/MV5BNzQ1MjQzMzM3OF5BMl5BanBnXkFtZTcwMzg3NzQ3OQ@@._V1_FMjpg_UX1000_.jpg', 'Brie Larson, John Gallagher Jr., Stephanie Beatriz, Rami Malek, Alex Calloway, Kevin Balmore', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (105053, 'Factory, The', 'Mystery,Thriller', 2012, 'Morgan O\'Neill', 'An obsessed cop is on the trail of a serial killer prowling the streets of Buffalo, N.Y. but when his teenage daughter disappears, he drops any professional restraint to get the killer.', 'https://m.media-amazon.com/images/M/MV5BYzlkY2QyOGMtMzc0YS00Mjg1LThlMWItZWY5NmE0ZTM5MmZiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Cusack, Jennifer Carpenter, Dallas Roberts, Mae Whitman, Sonya Walger, Mageina Tovah', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (105197, 'Nebraska', 'Adventure,Drama', 2013, 'Alexander Payne', 'An aging, booze-addled father makes the trip from Montana to Nebraska with his estranged son in order to claim a million-dollar Mega Sweepstakes Marketing prize.', 'https://m.media-amazon.com/images/M/MV5BYTgyNzRhMTQtZWUxZi00YzFmLTlhYTItNzY5ZDY2ZjdlYjM1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bruce Dern, Will Forte, June Squibb, Bob Odenkirk, Stacy Keach, Mary Louise Wilson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (105211, 'Enough Said', 'Comedy,Drama,Romance', 2013, 'Nicole Holofcener', 'A divorced woman who decides to pursue the man she\'s interested in learns he\'s her new friend\'s ex-husband.', 'https://m.media-amazon.com/images/M/MV5BMjI2MjIwMDk2Ml5BMl5BanBnXkFtZTcwNTQ1MzQ5OQ@@._V1_FMjpg_UX1000_.jpg', 'Julia Louis-Dreyfus, Lennie Loftin, Jessica St. Clair, Christopher Nicholas Smith, Tracey Fairaway, Toni Collette', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (105246, 'Mood Indigo (L\'écume des jours)', 'Drama,Fantasy', 2013, 'Michel Gondry', 'Wealthy, inventive bachelor Colin endeavors to find a cure for his lover Chloe after she\'s diagnosed with an unusual illness caused by a flower growing in her lungs.', 'https://m.media-amazon.com/images/M/MV5BYTExYzhiZDgtMGI3Yi00ZjdkLWIwZTgtMTEzOGZiNDAxOGZhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Romain Duris, Audrey Tautou, Gad Elmaleh, Omar Sy, Aïssa Maïga, Charlotte Le Bon', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (105355, 'Blue Is the Warmest Color (La vie d\'Adèle)', 'Drama,Romance', 2013, 'Abdellatif Kechiche', 'Adèle\'s life is changed when she meets Emma, a young woman with blue hair, who will allow her to discover desire and to assert herself as a woman and as an adult. In front of others, Adèle grows, seeks herself, loses herself, and ultimately finds herself through love and loss.', 'https://m.media-amazon.com/images/M/MV5BMTQ5NTg5ODk4OV5BMl5BanBnXkFtZTgwODc4MTMzMDE@._V1_FMjpg_UX1000_.jpg', 'Léa Seydoux, Adèle Exarchopoulos, Salim Kechiouche, Aurélien Recoing, Catherine Salée, Benjamin Siksou', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (105504, 'Captain Phillips', 'Adventure,Drama,Thriller,IMAX', 2013, 'Paul Greengrass', 'The true story of Captain Richard Phillips and the 2009 hijacking by Somali pirates of the U.S.-flagged MV Maersk Alabama, the first American cargo ship to be hijacked in two hundred years.', 'https://m.media-amazon.com/images/M/MV5BMWYyNjI3ZjEtNGE5ZS00MDgxLWIzNGEtZTgzNDVlZjZjYWU5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Catherine Keener, Barkhad Abdi, Barkhad Abdirahman, Faysal Ahmed, Mahat M. Ali', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (105844, '12 Years a Slave', 'Drama', 2013, 'Steve McQueen', 'In the antebellum United States, Solomon Northup, a free black man from upstate New York, is abducted and sold into slavery.', 'https://m.media-amazon.com/images/M/MV5BMjExMTEzODkyN15BMl5BanBnXkFtZTcwNTU4NTc4OQ@@._V1_FMjpg_UX1000_.jpg', 'Chiwetel Ejiofor, Dwight Henry, Dickie Gravois, Bryan Batt, Ashley Dyke, Kelsey Scott', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (105954, 'All Is Lost', 'Action,Adventure,Drama', 2013, 'J.C. Chandor', 'After a collision with a shipping container at sea, a resourceful sailor finds himself, despite all efforts to the contrary, staring his mortality in the face.', 'https://m.media-amazon.com/images/M/MV5BMjI0MzIyMjU1N15BMl5BanBnXkFtZTgwOTk1MjQxMDE@._V1_FMjpg_UX1000_.jpg', 'Robert Redford', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (106072, 'Thor: The Dark World', 'Action,Adventure,Fantasy,IMAX', 2013, 'Alan Taylor', 'When the Dark Elves attempt to plunge the universe into darkness, Thor must embark on a perilous and personal journey that will reunite him with doctor Jane Foster.', 'https://m.media-amazon.com/images/M/MV5BMTQyNzAwOTUxOF5BMl5BanBnXkFtZTcwMTE0OTc5OQ@@._V1_FMjpg_UX1000_.jpg', 'Chris Hemsworth, Natalie Portman, Tom Hiddleston, Anthony Hopkins, Christopher Eccleston, Jaimie Alexander', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (106100, 'Dallas Buyers Club', 'Drama', 2013, 'Jean-Marc Vallée', 'In 1985 Dallas, electrician and hustler Ron Woodroof works around the system to help AIDS patients get the medication they need after he is diagnosed with the disease.', 'https://m.media-amazon.com/images/M/MV5BMTYwMTA4MzgyNF5BMl5BanBnXkFtZTgwMjEyMjE0MDE@._V1_FMjpg_UX1000_.jpg', 'Matthew McConaughey, Jennifer Garner, Jared Leto, Denis O\'Hare, Steve Zahn, Michael O\'Neill', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (106438, 'Philomena', 'Comedy,Drama', 2013, 'Stephen Frears', 'A world-weary political journalist picks up the story of a woman\'s search for her son, who was taken away from her decades ago after she became pregnant and was forced to live in a convent.', 'https://m.media-amazon.com/images/M/MV5BMjA5ODgyNzcxMV5BMl5BanBnXkFtZTgwMzkzOTYzMDE@._V1_FMjpg_UX1000_.jpg', 'Judi Dench, Steve Coogan, Sophie Kennedy Clark, Mare Winningham, Barbara Jefford, Ruth McCabe', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (106487, 'The Hunger Games: Catching Fire', 'Action,Adventure,Sci-Fi,IMAX', 2013, 'Francis Lawrence', 'Katniss Everdeen and Peeta Mellark become targets of the Capitol after their victory in the 74th Hunger Games sparks a rebellion in the Districts of Panem.', 'https://m.media-amazon.com/images/M/MV5BMTAyMjQ3OTAxMzNeQTJeQWpwZ15BbWU4MDU0NzA1MzAx._V1_FMjpg_UX1000_.jpg', 'Jennifer Lawrence, Liam Hemsworth, Jack Quaid, Taylor St. Clair, Sandra Ellis Lafferty, Woody Harrelson', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (106696, 'Frozen', 'Adventure,Animation,Comedy,Fantasy,Musical,Romance', 2013, 'Chris Buck', 'Fearless optimist Anna teams up with rugged mountain man Kristoff and his loyal reindeer Sven in an epic journey to find Anna\'s sister Elsa, whose icy powers have trapped the kingdom of Arendelle in eternal winter.', 'https://m.media-amazon.com/images/M/MV5BMTQ1MjQwMTE5OF5BMl5BanBnXkFtZTgwNjk3MTcyMDE@._V1_FMjpg_UX1000_.jpg', 'Kristen Bell, Idina Menzel, Jonathan Groff, Josh Gad, Santino Fontana, Alan Tudyk', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (106766, 'Inside Llewyn Davis', 'Drama', 2013, 'Ethan Coen', 'A week in the life of a young singer as he navigates the Greenwich Village folk scene of 1961.', 'https://m.media-amazon.com/images/M/MV5BMjAxNjcyNDQxM15BMl5BanBnXkFtZTgwNzU2NDA0MDE@._V1_FMjpg_UX1000_.jpg', 'Oscar Isaac, Carey Mulligan, Justin Timberlake, Ethan Phillips, Robin Bartlett, Max Casella', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (106782, 'Wolf of Wall Street, The', 'Comedy,Crime,Drama', 2013, 'Martin Scorsese', 'Based on the true story of Jordan Belfort, from his rise to a wealthy stock-broker living the high life to his fall involving crime, corruption and the federal government.', 'https://m.media-amazon.com/images/M/MV5BMjIxMjgxNTk0MF5BMl5BanBnXkFtZTgwNjIyOTg2MDE@._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Jonah Hill, Margot Robbie, Matthew McConaughey, Kyle Chandler, Rob Reiner', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (106839, 'Mandela: Long Walk to Freedom', 'Drama', 2013, 'Justin Chadwick', 'A chronicle of Nelson Mandela\'s life journey from his childhood in a rural village through to his inauguration as the first democratically elected president of South Africa.', 'https://m.media-amazon.com/images/M/MV5BMTg1NTQ1NDczNV5BMl5BanBnXkFtZTcwNDQyMDU1OQ@@._V1_FMjpg_UX1000_.jpg', 'Idris Elba, Naomie Harris, Tony Kgoroge, Riaad Moosa, Zolani Mkiva, Simo Magwaza', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (106841, 'August: Osage County', 'Comedy,Drama', 2013, 'John Wells', 'A look at the lives of the strong-willed women of the Weston family, whose paths have diverged until a family crisis brings them back to the Oklahoma house they grew up in, and to the dysfunctional woman who raised them.', 'https://m.media-amazon.com/images/M/MV5BNzQ5ODE4NTcxNV5BMl5BanBnXkFtZTgwNjkyNDQ0MDE@._V1_FMjpg_UX1000_.jpg', 'Meryl Streep, Julia Roberts, Chris Cooper, Ewan McGregor, Margo Martindale, Sam Shepard', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (106916, 'American Hustle', 'Crime,Drama', 2013, 'David O. Russell', 'A con man, Irving Rosenfeld, along with his seductive partner Sydney Prosser, is forced to work for a wild F.B.I. Agent, Richie DiMaso, who pushes them into a world of Jersey powerbrokers and the Mafia.', 'https://m.media-amazon.com/images/M/MV5BMGQ2NzEwZGEtYjk1MC00NWFmLTgyYTgtZmRhMTRmOTBlN2U5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Christian Bale, Bradley Cooper, Amy Adams, Jeremy Renner, Jennifer Lawrence, Louis C.K.', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (106918, 'Secret Life of Walter Mitty, The', 'Adventure,Comedy,Drama', 2013, 'Ben Stiller', 'When both he and a colleague are about to lose their job, Walter takes action by embarking on an adventure more extraordinary than anything he ever imagined.', 'https://m.media-amazon.com/images/M/MV5BODYwNDYxNDk1Nl5BMl5BanBnXkFtZTgwOTAwMTk2MDE@._V1_FMjpg_UX1000_.jpg', 'Ben Stiller, Kristen Wiig, Jon Daly, Kathryn Hahn, Terence Bernie Hines, Adam Scott', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (106920, 'Her', 'Drama,Romance,Sci-Fi', 2013, 'Spike Jonze', 'In the near future, a lonely writer develops an unlikely relationship with an operating system designed to meet his every need.', 'https://m.media-amazon.com/images/M/MV5BMjA1Nzk0OTM2OF5BMl5BanBnXkFtZTgwNjU2NjEwMDE@._V1_FMjpg_UX1000_.jpg', 'Joaquin Phoenix, Lynn Adrianna Freedman, Lisa Renee Pitts, Gabe Gomez, Chris Pratt, Artt Butler', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (107069, 'Lone Survivor', 'Action,Drama,Thriller,War', 2013, 'Peter Berg', 'Marcus Luttrell and his team set out on a mission to capture or kill notorious Taliban leader Ahmad Shah, in late June 2005. Marcus and his team are left to fight for their lives in one of the most valiant efforts of modern warfare.', 'https://m.media-amazon.com/images/M/MV5BMjA0NTgwOTk5Ml5BMl5BanBnXkFtZTcwMjE3NDc5OQ@@._V1_FMjpg_UX1000_.jpg', 'Mark Wahlberg, Taylor Kitsch, Emile Hirsch, Ben Foster, Yousuf Azami, Ali Suliman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (107141, 'Saving Mr. Banks', 'Comedy,Drama', 2013, 'John Lee Hancock', 'P. L. Travers, a London author who is financially broke, visits Los Angeles to meet Walt Disney, who is keen to adapt her Mary Poppins books for the cinema. However, his methods do not meet her approval.', 'https://m.media-amazon.com/images/M/MV5BMTc0MTQ3NzE4Nl5BMl5BanBnXkFtZTcwMzA4NDM5OQ@@._V1_FMjpg_UX1000_.jpg', 'Emma Thompson, Tom Hanks, Annie Rose Buckley, Colin Farrell, Ruth Wilson, Paul Giamatti', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (107348, 'Anchorman 2: The Legend Continues', 'Comedy', 2013, 'Adam McKay', 'With the 1970s behind him, Ron Burgundy, San Diego\'s former top-rated newsreader, returns to take New York City\'s first twenty-four-hour news channel by storm.', 'https://m.media-amazon.com/images/M/MV5BMjE5ODk0NjQzNV5BMl5BanBnXkFtZTgwODk4MDA1MDE@._V1_FMjpg_UX1000_.jpg', 'Will Ferrell, Steve Carell, Paul Rudd, David Koechner, Christina Applegate, Dylan Baker', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (107406, 'Snowpiercer', 'Action,Drama,Sci-Fi', 2013, 'Bong Joon Ho', 'In a future where a failed climate change experiment has killed all life except for the survivors who boarded the Snowpiercer (a train that travels around the globe), a new class system emerges.', 'https://m.media-amazon.com/images/M/MV5BMTQ3NzA1MTY3MV5BMl5BanBnXkFtZTgwNzE2Mzg5MTE@._V1_FMjpg_UX1000_.jpg', 'Chris Evans, Song Kang-ho, Ed Harris, John Hurt, Tilda Swinton, Jamie Bell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (107565, 'Fuck You, Goethe (Fack Ju Göhte)', 'Comedy', 2013, 'Bora Dagtekin', 'A comedy that follows an ex-convict who lands a position at a school that sits over the spot where money from one of his earlier robberies was stashed.', 'https://m.media-amazon.com/images/M/MV5BMTkxMzc1MjMxM15BMl5BanBnXkFtZTgwNzQxNzI5MDE@._V1_FMjpg_UX1000_.jpg', 'Elyas M\'Barek, Karoline Herfurth, Katja Riemann, Jana Pallaske, Alwara Höfels, Jella Haase', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (107771, 'Only Lovers Left Alive', 'Drama,Horror,Romance', 2013, 'Jim Jarmusch', 'A depressed musician reunites with his lover. However, their romance, which has already endured several centuries, is disrupted by the arrival of her uncontrollable younger sister.', 'https://m.media-amazon.com/images/M/MV5BMTY0NTQ1NjA0OV5BMl5BanBnXkFtZTgwMDg5NjkzMTE@._V1_FMjpg_UX1000_.jpg', 'Tilda Swinton, Tom Hiddleston, Anton Yelchin, Mia Wasikowska, Jeffrey Wright, Slimane Dazi', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (107883, 'The Lunchbox', 'Drama,Romance', 2013, 'Ritesh Batra', 'A mistaken delivery in Mumbai\'s famously efficient lunchbox delivery system connects a young housewife to an older man in the dusk of his life as they build a fantasy world together through notes in the lunchbox.', 'https://m.media-amazon.com/images/M/MV5BMTUwMzc1NjIzMV5BMl5BanBnXkFtZTgwODUyMTIxMTE@._V1_FMjpg_UX1000_.jpg', 'Irrfan Khan, Nimrat Kaur, Nawazuddin Siddiqui, Lillete Dubey, Nakul Vaid, Bharti Achrekar', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (108188, 'Jack Ryan: Shadow Recruit', 'Action,Drama,Thriller,IMAX', 2014, 'Kenneth Branagh', 'Jack Ryan, as a young covert C.I.A. analyst, uncovers a Russian plot to crash the U.S. economy with a terrorist attack.', 'https://m.media-amazon.com/images/M/MV5BMTY2MDkxNzYwNl5BMl5BanBnXkFtZTgwOTM2MjE5MDE@._V1_FMjpg_UX1000_.jpg', 'Chris Pine, Keira Knightley, Kevin Costner, Kenneth Branagh, Lenn Kudrjawizki, Alec Utgoff', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (108190, 'Divergent', 'Adventure,Romance,Sci-Fi,IMAX', 2014, 'Neil Burger', 'In a world divided by factions based on virtues, Tris learns she\'s Divergent and won\'t fit in. When she discovers a plot to destroy Divergents, Tris and the mysterious Four must find out what makes Divergents dangerous before it\'s too late.', 'https://m.media-amazon.com/images/M/MV5BMTYxMzYwODE4OV5BMl5BanBnXkFtZTgwNDE5MzE2MDE@._V1_FMjpg_UX1000_.jpg', 'Shailene Woodley, Theo James, Ashley Judd, Jai Courtney, Ray Stevenson, Zoë Kravitz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (108729, 'Enemy', 'Mystery,Thriller', 2013, 'Denis Villeneuve', 'A mild-mannered college professor investigates the life of an actor who looks exactly like him.', 'https://m.media-amazon.com/images/M/MV5BMTQ2NzA5NjE4N15BMl5BanBnXkFtZTgwMjQ4NzMxMTE@._V1_FMjpg_UX1000_.jpg', 'Jake Gyllenhaal, Mélanie Laurent, Sarah Gadon, Isabella Rossellini, Joshua Peace, Tim Post', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (108928, 'Monuments Men, The', 'Action,Drama,War', 2014, 'George Clooney', 'An unlikely World War II platoon is tasked to rescue art masterpieces from German thieves and return them to their owners.', 'https://m.media-amazon.com/images/M/MV5BMjMxMjk4NTM1M15BMl5BanBnXkFtZTgwNjg0MjQ3MDE@._V1_FMjpg_UX1000_.jpg', 'George Clooney, Matt Damon, Bill Murray, Cate Blanchett, John Goodman, Jean Dujardin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (108932, 'The Lego Movie', 'Action,Adventure,Animation,Children,Comedy,Fantasy', 2014, 'Phil Lord', 'An ordinary LEGO construction worker, thought to be the prophesied as \"special\", is recruited to join a quest to stop an evil tyrant from gluing the LEGO universe into eternal stasis.', 'https://m.media-amazon.com/images/M/MV5BMTg4MDk1ODExN15BMl5BanBnXkFtZTgwNzIyNjg3MDE@._V1_FMjpg_UX1000_.jpg', 'Will Arnett, Elizabeth Banks, Craig Berry, Alison Brie, David Burrows, Anthony Daniels', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (109187, 'Zero Theorem, The', 'Drama,Fantasy,Sci-Fi', 2013, 'Terry Gilliam', 'A hugely talented but socially isolated computer operator is tasked by Management to prove the Zero Theorem: that the universe ends as nothing, rendering life meaningless. But meaning is what he already craves.', 'https://m.media-amazon.com/images/M/MV5BMTc4NTIxMTE0OF5BMl5BanBnXkFtZTgwNTQ5NTYxMjE@._V1_FMjpg_UX1000_.jpg', 'Christoph Waltz, Gwendoline Christie, Rupert Friend, Ray Cooper, Lily Cole, David Thewlis', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (109374, 'Grand Budapest Hotel, The', 'Comedy,Drama', 2014, 'Wes Anderson', 'A writer encounters the owner of an aging high-class hotel, who tells him of his early years serving as a lobby boy in the hotel\'s glorious years under an exceptional concierge.', 'https://m.media-amazon.com/images/M/MV5BMzM5NjUxOTEyMl5BMl5BanBnXkFtZTgwNjEyMDM0MDE@._V1_FMjpg_UX1000_.jpg', 'Ralph Fiennes, F. Murray Abraham, Mathieu Amalric, Adrien Brody, Willem Dafoe, Jeff Goldblum', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (109390, 'Black Coal, Thin Ice (Bai ri yan huo)', 'Crime,Drama,Mystery,Thriller', 2014, 'Yi\'nan Diao', 'An ex cop and his ex partner decide to follow up on investigation of a series of murders that ended their careers and shamed them, when identical murders begin again.', 'https://m.media-amazon.com/images/M/MV5BZWUyYTMwZGQtNmJlMy00NThhLTlmYWUtNjJmMWQ2Y2M2OTMwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Fan Liao, Lun-Mei Gwei, Xuebing Wang, Jingchun Wang, Ailei Yu, Jingyang Ni', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (109487, 'Interstellar', 'Sci-Fi,IMAX', 2014, 'Christopher Nolan', 'When Earth becomes uninhabitable in the future, a farmer and ex-NASA pilot, Joseph Cooper, is tasked to pilot a spacecraft, along with a team of researchers, to find a new planet for humans.', 'https://m.media-amazon.com/images/M/MV5BYzdjMDAxZGItMjI2My00ODA1LTlkNzItOWFjMDU5ZDJlYWY3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ellen Burstyn, Matthew McConaughey, Mackenzie Foy, John Lithgow, Timothée Chalamet, David Oyelowo', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (109578, 'Non-Stop', 'Action,Mystery,Thriller', 2014, 'Jaume Collet-Serra', 'An air marshal springs into action during a transatlantic flight after receiving a series of text messages demanding $150 million into an off-shore account, or someone will die every 20 minutes.', 'https://m.media-amazon.com/images/M/MV5BOTI3NzcxMjkzMl5BMl5BanBnXkFtZTgwMDY0NTQ0MDE@._V1_FMjpg_UX1000_.jpg', 'Liam Neeson, Julianne Moore, Scoot McNairy, Michelle Dockery, Nate Parker, Corey Stoll', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (109864, 'Veronica Mars', 'Comedy,Crime,Drama', 2014, 'Rob Thomas', 'Years after walking away from her past as a young private eye, Veronica Mars gets pulled back to her hometown, just in time for her high school reunion, in order to help her old flame Logan Echolls, who\'s embroiled in a murder mystery.', 'https://m.media-amazon.com/images/M/MV5BMTQ4MDc0Mjg4OV5BMl5BanBnXkFtZTgwODk3NjYyMTE@._V1_FMjpg_UX1000_.jpg', 'Kristen Bell, Jason Dohring, Enrico Colantoni, Christopher Lowell, Percy Daggs III, Tina Majorino', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (110102, 'Captain America: The Winter Soldier', 'Action,Adventure,Sci-Fi,IMAX', 2014, 'Anthony Russo', 'As Steve Rogers struggles to embrace his role in the modern world, he teams up with a fellow Avenger and S.H.I.E.L.D agent, Black Widow, to battle a new threat from history: an assassin known as the Winter Soldier.', 'https://m.media-amazon.com/images/M/MV5BNWY1NjFmNDItZDhmOC00NjI1LWE0ZDItMTM0MjBjZThiOTQ2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chris Evans, Samuel L. Jackson, Scarlett Johansson, Robert Redford, Sebastian Stan, Anthony Mackie', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (110127, 'Noah', 'Adventure,Drama,IMAX', 2014, 'Darren Aronofsky', 'Noah is chosen by God to undertake a momentous mission before an apocalyptic flood cleanses the world.', 'https://m.media-amazon.com/images/M/MV5BMjI2OTgyNTc0Ml5BMl5BanBnXkFtZTgwNDM1NTQxMTE@._V1_FMjpg_UX1000_.jpg', 'Russell Crowe, Jennifer Connelly, Ray Winstone, Anthony Hopkins, Emma Watson, Logan Lerman', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (110273, 'Diplomacy (Diplomatie)', 'Drama,War', 2014, 'Volker Schlöndorff', 'A historical drama that depicts the relationship between Dietrich von Choltitz, the German military governor of occupied Paris, and Swedish consul-general Raoul Nordling.', 'https://m.media-amazon.com/images/M/MV5BMTg1NDIzNTQ5N15BMl5BanBnXkFtZTgwMjY2MTU2MjE@._V1_FMjpg_UX1000_.jpg', 'André Dussollier, Niels Arestrup, Burghart Klaußner, Robert Stadlober, Charlie Nelson, Jean-Marc Roulot', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (110730, 'Transcendence', 'Drama,Sci-Fi,IMAX', 2014, 'Wally Pfister', 'A scientist\'s drive for artificial intelligence takes on dangerous implications when his own consciousness is uploaded into one such program.', 'https://m.media-amazon.com/images/M/MV5BMTc1MjQ3ODAyOV5BMl5BanBnXkFtZTgwNjI1NDQ0MTE@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Rebecca Hall, Paul Bettany, Cillian Murphy, Kate Mara, Cole Hauser', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (110792, 'Ghost Adventures', 'Documentary', 2004, 'Zak Bagans', 'Zak Bagans, Nick Groff and Aaron Goodwin visit two of the most notoriously haunted sites in the United States, collecting undeniable evidence to prove the existence of ghosts.', 'https://m.media-amazon.com/images/M/MV5BMTgwNzUyNjg5MV5BMl5BanBnXkFtZTgwMzA2MDk4MDE@._V1_FMjpg_UX1000_.jpg', 'Zak Bagans, Brian Clune, Debby Constantino, Aaron Goodwin, Nick Groff, Mike Hardy', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (111113, 'Neighbors', 'Comedy', 2014, 'Nicholas Stoller', 'After they are forced to live next to a fraternity house, a couple with a newborn baby do whatever they can to take them down.', 'https://m.media-amazon.com/images/M/MV5BOTQ0OTkzODgyNF5BMl5BanBnXkFtZTgwOTA3OTE4MDE@._V1_FMjpg_UX1000_.jpg', 'Seth Rogen, Rose Byrne, Elise Vargas, Zoey Vargas, Brian Huskey, Ike Barinholtz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (111362, 'X-Men: Days of Future Past', 'Action,Adventure,Sci-Fi', 2014, 'Bryan Singer', 'The X-Men send Wolverine to the past in a desperate effort to change history and prevent an event that results in doom for both humans and mutants.', 'https://m.media-amazon.com/images/M/MV5BNzNiYWE4NjMtMTU4OS00NmM4LWE4ZjAtYmE5OTA5NjkzODExXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Hugh Jackman, James McAvoy, Michael Fassbender, Jennifer Lawrence, Halle Berry, Nicholas Hoult', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (111384, 'Blue Ruin', 'Thriller', 2013, 'Jeremy Saulnier', 'A mysterious outsider\'s quiet life is turned upside down when he returns to his childhood home to carry out an act of vengeance. Proving himself an amateur assassin, he winds up in a brutal fight to protect his estranged family.', 'https://m.media-amazon.com/images/M/MV5BMTY4NTM2MDg5OV5BMl5BanBnXkFtZTgwMDA3OTAwMTE@._V1_FMjpg_UX1000_.jpg', 'Macon Blair, Ydaiber Orozco, Ronald Sarcos, Dani Santiago, Adrian Santiago, George Fredericks', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (111622, 'Begin Again', 'Comedy,Romance', 2013, 'John Carney', 'A chance encounter between a down-and-out music business executive, and a young singer songwriter new to Manhattan, turns into a promising collaboration between the two talents.', 'https://m.media-amazon.com/images/M/MV5BNjAxMTI4MTgzMV5BMl5BanBnXkFtZTgwOTAwODEwMjE@._V1_FMjpg_UX1000_.jpg', 'James Corden, Keira Knightley, Mark Ruffalo, Hailee Steinfeld, Yasiin Bey, Karen Pittman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (111759, 'Edge of Tomorrow', 'Action,Sci-Fi,IMAX', 2014, 'Doug Liman', 'A man fighting in a war against aliens must relive the same day every time he dies until he can find a way to stop their power source with the help of an elite soldier.', 'https://m.media-amazon.com/images/M/MV5BMTc5OTk4MTM3M15BMl5BanBnXkFtZTgwODcxNjg3MDE@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Emily Blunt, Brendan Gleeson, Bill Paxton, Jonas Armstrong, Tony Way', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (111781, 'Mission: Impossible - Rogue Nation', 'Action,Adventure,Thriller', 2015, 'Christopher McQuarrie', 'Ethan and his team take on their most impossible mission yet when they have to eradicate an international rogue organization as highly skilled as they are and committed to destroying the IMF.', 'https://m.media-amazon.com/images/M/MV5BZjUwZjg2ZjAtY2RhZi00YmZjLTlhNGQtOWQwNDk1MjhhM2NhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Jeremy Renner, Simon Pegg, Rebecca Ferguson, Ving Rhames, Sean Harris', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (111921, 'The Fault in Our Stars', 'Drama,Romance', 2014, 'Josh Boone', 'Hazel and Gus are teenagers who meet at a cancer support group and fall in love. They both share the same acerbic wit and a love of books, especially \"An Imperial Affliction\", so they embark on a journey to visit an author in Amsterdam.', 'https://m.media-amazon.com/images/M/MV5BYTA4ODg5YWUtYmZiYy00Y2M4LWE0NjEtODE5MzhkYmJmZGEwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Shailene Woodley, Ansel Elgort, Nat Wolff, Laura Dern, Sam Trammell, Willem Dafoe', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (112171, 'Equalizer, The', 'Action,Crime,Thriller', 2014, 'Antoine Fuqua', 'A man who believes he has put his mysterious past behind him cannot stand idly by when he meets a young girl under the control of ultra-violent Russian gangsters.', 'https://m.media-amazon.com/images/M/MV5BMTQ2MzE2NTk0NF5BMl5BanBnXkFtZTgwOTM3NTk1MjE@._V1_FMjpg_UX1000_.jpg', 'Denzel Washington, Marton Csokas, Chloë Grace Moretz, David Harbour, Haley Bennett, Bill Pullman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (112175, 'How to Train Your Dragon 2', 'Action,Adventure,Animation', 2014, 'Dean DeBlois', 'When Hiccup and Toothless discover an ice cave that is home to hundreds of new wild dragons and the mysterious Dragon Rider, the two friends find themselves at the center of a battle to protect the peace.', 'https://m.media-amazon.com/images/M/MV5BMzMwMTAwODczN15BMl5BanBnXkFtZTgwMDk2NDA4MTE@._V1_FMjpg_UX1000_.jpg', 'Jay Baruchel, Cate Blanchett, Gerard Butler, Craig Ferguson, America Ferrera, Jonah Hill', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (112183, 'Birdman: Or (The Unexpected Virtue of Ignorance)', 'Comedy,Drama', 2014, 'Alejandro G. Iñárritu', 'A washed-up superhero actor attempts to revive his fading career by writing, directing, and starring in a Broadway production.', 'https://m.media-amazon.com/images/M/MV5BODAzNDMxMzAxOV5BMl5BanBnXkFtZTgwMDMxMjA4MjE@._V1_FMjpg_UX1000_.jpg', 'Michael Keaton, Emma Stone, Kenny Chin, Jamahl Garrison-Lowe, Zach Galifianakis, Naomi Watts', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (112290, 'Boyhood', 'Drama', 2014, 'Richard Linklater', 'The life of Mason, from early childhood to his arrival at college.', 'https://m.media-amazon.com/images/M/MV5BMTYzNDc2MDc0N15BMl5BanBnXkFtZTgwOTcwMDQ5MTE@._V1_FMjpg_UX1000_.jpg', 'Ellar Coltrane, Patricia Arquette, Elijah Smith, Lorelei Linklater, Steven Chester Prince, Bonnie Cross', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (112552, 'Whiplash', 'Drama', 2014, 'Damien Chazelle', 'A promising young drummer enrolls at a cut-throat music conservatory where his dreams of greatness are mentored by an instructor who will stop at nothing to realize a student\'s potential.', 'https://m.media-amazon.com/images/M/MV5BMDFjOWFkYzktYzhhMC00NmYyLTkwY2EtYjViMDhmNzg0OGFkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Miles Teller, J.K. Simmons, Paul Reiser, Melissa Benoist, Austin Stowell, Nate Lang', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (112556, 'Gone Girl', 'Drama,Thriller', 2014, 'David Fincher', 'The husband of a missing woman becomes the main suspect in her disappearance.', 'https://m.media-amazon.com/images/M/MV5BMTk0MDQ3MzAzOV5BMl5BanBnXkFtZTgwNzU1NzE3MjE@._V1_FMjpg_UX1000_.jpg', 'Ben Affleck, Rosamund Pike, Neil Patrick Harris, Tyler Perry, Carrie Coon, Kim Dickens', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (112623, 'Dawn of the Planet of the Apes', 'Sci-Fi', 2014, 'Matt Reeves', 'The fragile peace between apes and humans is threatened as mistrust and betrayal threaten to plunge both tribes into a war for dominance over the Earth.', 'https://m.media-amazon.com/images/M/MV5BNWNjYzQ4ZGItZTg1My00NTM2LTg1NDUtYThjOTQwMTYyNjU1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Andy Serkis, Jason Clarke, Gary Oldman, Keri Russell, Toby Kebbell, Kodi Smit-McPhee', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (112852, 'Guardians of the Galaxy', 'Action,Adventure,Sci-Fi', 2014, 'James Gunn', 'A group of intergalactic criminals must pull together to stop a fanatical warrior with plans to purge the universe.', 'https://m.media-amazon.com/images/M/MV5BM2ZmNjQ2MzAtNDlhNi00MmQyLWJhZDMtNmJiMjFlOWY4MzcxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chris Pratt, Zoe Saldaña, Dave Bautista, Vin Diesel, Bradley Cooper, Lee Pace', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (112946, 'Wish I Was Here', 'Comedy,Drama', 2014, 'Zach Braff', 'A struggling actor, father and husband finds himself at a major crossroads, which forces him to examine his life, his family and his career.', 'https://m.media-amazon.com/images/M/MV5BMjI1MTM5NTY2Nl5BMl5BanBnXkFtZTgwODE4OTk4MTE@._V1_FMjpg_UX1000_.jpg', 'Zach Braff, Pierce Gagnon, Kate Hudson, Joey King, Alexander Chaplin, Leslie David Baker', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (113225, 'Magic in the Moonlight', 'Comedy,Drama,Romance', 2014, 'Woody Allen', 'A romantic comedy about an Englishman brought in to help unmask a possible swindle. Personal and professional complications ensue.', 'https://m.media-amazon.com/images/M/MV5BMTQ3NDY5NjIwN15BMl5BanBnXkFtZTgwNjQ2ODkxMjE@._V1_FMjpg_UX1000_.jpg', 'Colin Firth, Antonia Clarke, Natasha Andrews, Valérie Beaulieu, Peter Wollasch, Jürgen Zwingel', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (113275, 'The Hundred-Foot Journey', 'Comedy,Drama', 2014, 'Lasse Hallström', 'The Kadam family leaves India for France where they open a restaurant directly across the road from Madame Mallory\'s Michelin-starred eatery.', 'https://m.media-amazon.com/images/M/MV5BMTQ3Mjg2MTE4M15BMl5BanBnXkFtZTgwMzcyNDMwMjE@._V1_FMjpg_UX1000_.jpg', 'Helen Mirren, Om Puri, Manish Dayal, Charlotte Le Bon, Amit Shah, Farzana Dua Elahe', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (113370, 'Nayak: The Hero', 'Drama', 1966, 'Satyajit Ray', 'En route to Delhi to receive an award, a Bengali film star reevaluates his success through his fellow passengers, dreams, and past experiences.', 'https://m.media-amazon.com/images/M/MV5BMjNkOWMwMWYtMGExNS00ZGE5LWI0M2UtZjZmMDg2NTk5OTI2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Uttam Kumar, Sharmila Tagore, Bireswar Sen, Somen Bose, Nirmal Ghosh, Premangshu Bose', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (113378, 'Giver, The', 'Drama,Sci-Fi', 2014, 'Phillip Noyce', 'In a seemingly perfect community without war, pain, suffering, differences, or choices, a young boy is chosen to learn from an elderly man, the true pain and pleasure of the real world.', 'https://m.media-amazon.com/images/M/MV5BMTY1MTIxMjg2Ml5BMl5BanBnXkFtZTgwMjUyNzgwMjE@._V1_FMjpg_UX1000_.jpg', 'Jeff Bridges, Meryl Streep, Brenton Thwaites, Alexander Skarsgård, Katie Holmes, Odeya Rush', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (113741, 'Coherence', 'Drama,Mystery,Sci-Fi,Thriller', 2013, 'James Ward Byrkit', 'Strange things begin to happen when a group of friends gather for a dinner party on an evening when a comet is passing overhead.', 'https://m.media-amazon.com/images/M/MV5BNzQ3ODUzNDY2M15BMl5BanBnXkFtZTgwNzg0ODY2MTE@._V1_FMjpg_UX1000_.jpg', 'Emily Baldoni, Maury Sterling, Nicholas Brendon, Lorene Scafaria, Elizabeth Gracen, Hugo Armstrong', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (114028, 'Pride', 'Comedy,Drama', 2014, 'Matthew Warchus', 'U.K. gay activists work to help miners during their lengthy strike of the National Union of Mineworkers in the summer of 1984.', 'https://m.media-amazon.com/images/M/MV5BMTU2OTcyOTE3MF5BMl5BanBnXkFtZTgwNTg5Mjc1MjE@._V1_FMjpg_UX1000_.jpg', 'Ben Schnetzer, Abram Rooney, Jim McManus, George MacKay, Monica Dolan, Matthew Flynn', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (114060, 'The Drop', 'Crime,Drama,Thriller', 2014, 'Michaël R. Roskam', 'Bob Saginowski finds himself at the center of a robbery gone awry and entwined in an investigation that digs deeply into the neighborhood\'s past where friends, families, and foes all work together to make a living--no matter the cost.', 'https://m.media-amazon.com/images/M/MV5BNGNlMDM4ODUtZjYxMy00MjkxLThjNGQtYmM3MDZiMWRkMmNjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hardy, Noomi Rapace, James Gandolfini, Matthias Schoenaerts, John Ortiz, Elizabeth Rodriguez', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (114494, 'Who Am I (Kein System Ist Sicher)', 'Thriller', 2014, 'Baran bo Odar', 'Benjamin, a computer genius, is invited to join FRI3NDS, a fame-seeking hacker group. However, when his associates are murdered by Russian gangsters, he is interrogated by Europol.', 'https://m.media-amazon.com/images/M/MV5BZDFmNDY0NWUtMzZhYS00ZDk4LTg0MWItMTg5MDliZWExNmI4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Schilling, Elyas M\'Barek, Wotan Wilke Möhring, Antoine Monot, Hannah Herzsprung, Stephan Kampwirth', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (114601, 'This Is Where I Leave You', 'Comedy,Drama', 2014, 'Shawn Levy', 'After their father passes away, four grown siblings are forced to return to their childhood home and live under the same roof for a week, along with their over-sharing mother and an assortment of spouses, exes, and might-have-beens.', 'https://m.media-amazon.com/images/M/MV5BMjkzNzQ2NDMyNl5BMl5BanBnXkFtZTgwMTY3MTcxMjE@._V1_FMjpg_UX1000_.jpg', 'Jason Bateman, Tina Fey, Jane Fonda, Adam Driver, Rose Byrne, Corey Stoll', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (114662, 'American Sniper', 'Action,War', 2014, 'Clint Eastwood', 'Navy S.E.A.L. sniper Chris Kyle\'s pinpoint accuracy saves countless lives on the battlefield and turns him into a legend. Back home with his family after four tours of duty, however, Chris finds that it is the war he can\'t leave behind.', 'https://m.media-amazon.com/images/M/MV5BMTkxNzI3ODI4Nl5BMl5BanBnXkFtZTgwMjkwMjY4MjE@._V1_FMjpg_UX1000_.jpg', 'Bradley Cooper, Kyle Gallner, Cole Konis, Ben Reed, Elise Robertson, Luke Sunshine', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (114935, 'Predestination', 'Action,Mystery,Sci-Fi,Thriller', 2014, 'Michael Spierig', 'As his last assignment, a temporal agent is tasked to travel back in time and prevent a bomb attack in New York in 1975. The hunt, however, turns out to be beyond the bounds of possibility.', 'https://m.media-amazon.com/images/M/MV5BY2VhODM5OTUtZDJhMi00MTc5LThjNjYtZWY1M2NlNWU0N2NjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ethan Hawke, Sarah Snook, Christopher Kirby, Christopher Sommers, Kuni Hashimoto, Sara El-Yafi', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (115122, 'What We Do in the Shadows', 'Comedy,Horror', 2014, 'Jemaine Clement', 'Viago, Deacon, and Vladislav are vampires who are struggling with the mundane aspects of modern life, like paying rent, keeping up with the chore wheel, trying to get into nightclubs, and overcoming flatmate conflicts.', 'https://m.media-amazon.com/images/M/MV5BNGFhNjkyZDYtOTc4Yi00OWM4LTg4ZTktNjIzNDA5NGE5YTYwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jemaine Clement, Taika Waititi, Jonny Brugh, Cori Gonzalez-Macuer, Stu Rutherford, Ben Fransham', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (115149, 'John Wick', 'Action,Thriller', 2014, 'Chad Stahelski', 'John Wick is a former hitman grieving the loss of his true love. When his home is broken into, robbed, and his dog killed, he is forced to return to action to exact revenge.', 'https://m.media-amazon.com/images/M/MV5BMTU2NjA1ODgzMF5BMl5BanBnXkFtZTgwMTM2MTI4MjE@._V1_FMjpg_UX1000_.jpg', 'Keanu Reeves, Michael Nyqvist, Alfie Allen, Willem Dafoe, Dean Winters, Adrianne Palicki', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (115170, 'Judge, The', 'Drama', 2014, 'David Dobkin', 'Big-city lawyer Hank Palmer returns to his childhood home where his father, the town\'s judge, is suspected of murder. Hank sets out to discover the truth; along the way he reconnects with his estranged family.', 'https://m.media-amazon.com/images/M/MV5BMTcyNzIxOTIwMV5BMl5BanBnXkFtZTgwMzE0NjQwMjE@._V1_FMjpg_UX1000_.jpg', 'Robert Downey Jr., Robert Duvall, Vera Farmiga, Billy Bob Thornton, Vincent D\'Onofrio, Jeremy Strong', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (115210, 'Fury', 'Action,Drama,War', 2014, 'David Ayer', 'A grizzled tank commander makes tough decisions as he and his crew fight their way across Germany in April, 1945.', 'https://m.media-amazon.com/images/M/MV5BMjA4MDU0NTUyN15BMl5BanBnXkFtZTgwMzQxMzY4MjE@._V1_FMjpg_UX1000_.jpg', 'Brad Pitt, Shia LaBeouf, Logan Lerman, Michael Peña, Jon Bernthal, Jim Parrack', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (115231, 'St. Vincent', 'Comedy', 2014, 'Theodore Melfi', 'A young boy whose parents have just divorced finds an unlikely friend and mentor in the misanthropic, bawdy, hedonistic war veteran who lives next door.', 'https://m.media-amazon.com/images/M/MV5BMTk5NzI5OTA4MF5BMl5BanBnXkFtZTgwNjc4NTM3MjE@._V1_FMjpg_UX1000_.jpg', 'Bill Murray, Melissa McCarthy, Naomi Watts, Chris O\'Dowd, Terrence Howard, Jaeden Martell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (115569, 'Nightcrawler', 'Crime,Drama,Thriller', 2014, 'Dan Gilroy', 'A petty thief desperate for work muscles into the world of crime journalism and becomes the star of his own story as he blurs the line between observer and participant.', 'https://m.media-amazon.com/images/M/MV5BYjMwMmI5MWQtOTU4OS00OTAyLTg0OTYtNmQ5YzExZTQ3ZWJhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jake Gyllenhaal, Michael Papajohn, Marco Rodríguez, Bill Paxton, James Huang, Kent Shocknek', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (115617, 'Big Hero 6', 'Action,Animation,Comedy', 2014, 'Don Hall', 'A special bond develops between plus-sized inflatable robot Baymax and prodigy Hiro Hamada, who together team up with a group of friends to form a band of high-tech heroes.', 'https://m.media-amazon.com/images/M/MV5BYjQ3YzUyOGQtNjdlYS00YmRhLWIyOWYtMGQ3YjkwMjJiYzRjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Scott Adsit, Ryan Potter, Daniel Henney, T.J. Miller, Jamie Chung, Damon Wayans Jr.', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (115713, 'Ex Machina', 'Drama,Sci-Fi,Thriller', 2015, 'Alex Garland', 'A young programmer is selected to participate in a ground-breaking experiment in synthetic intelligence by evaluating the human qualities of a highly advanced humanoid A.I.', 'https://m.media-amazon.com/images/M/MV5BMTUxNzc0OTIxMV5BMl5BanBnXkFtZTgwNDI3NzU2NDE@._V1_FMjpg_UX1000_.jpg', 'Domhnall Gleeson, Alicia Vikander, Oscar Isaac, Sonoya Mizuno, Corey Johnson, Claire Selby', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (115881, '9', 'Animation,Fantasy', 2005, 'Shane Acker', 'A rag doll fights a monster that has been stealing the souls of his people.', 'https://m.media-amazon.com/images/M/MV5BOTMzZjlhZTctOTRmOC00NmZmLTk3YjMtOTlhYTc1MTY5NGZkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', NULL, '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (116161, 'Foxcatcher', 'Drama', 2014, 'Bennett Miller', 'U.S. Olympic wrestling champions and brothers Mark Schultz and Dave Schultz join \"Team Foxcatcher\", led by eccentric multi-millionaire John du Pont, as they train for the 1988 Olympic Games in Seoul, South Korea, but John\'s self-destructive behavior threatens to consume them all.', 'https://m.media-amazon.com/images/M/MV5BMTQ2MjQxNjYxOV5BMl5BanBnXkFtZTgwMzIwODUxMzE@._V1_FMjpg_UX1000_.jpg', 'Steve Carell, Channing Tatum, Mark Ruffalo, Sienna Miller, Vanessa Redgrave, Anthony Michael Hall', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (116660, 'Free Fall', 'Drama', 2013, 'Stephan Lacant', 'A soon-to-be-father policeman falls for a gay fellow officer and his life starts falling apart.', 'https://m.media-amazon.com/images/M/MV5BMTc3MjgwNTEzNV5BMl5BanBnXkFtZTcwNTM5MzY5OQ@@._V1_FMjpg_UX1000_.jpg', 'Hanno Koffler, Max Riemelt, Attila Borlan, Katharina Schüttler, Stephanie Schönfeld, Oliver Bröcker', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (116797, 'The Imitation Game', 'Drama,Thriller,War', 2014, 'Morten Tyldum', 'During World War II, the English mathematical genius Alan Turing tries to crack the German Enigma code with help from fellow mathematicians while attempting to come to terms with his troubled private life.', 'https://m.media-amazon.com/images/M/MV5BNjI3NjY1Mjg3MV5BMl5BanBnXkFtZTgwMzk5MDQ3MjE@._V1_FMjpg_UX1000_.jpg', 'Benedict Cumberbatch, Keira Knightley, Matthew Goode, Rory Kinnear, Allen Leech, Matthew Beard', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (116823, 'The Hunger Games: Mockingjay - Part 1', 'Adventure,Sci-Fi,Thriller', 2014, 'Francis Lawrence', 'Katniss Everdeen is in District 13 after she shatters the games forever. Under the leadership of President Coin and the advice of her trusted friends, Katniss spreads her wings as she fights to save Peeta and a nation moved by her courage.', 'https://m.media-amazon.com/images/M/MV5BMTcxNDI2NDAzNl5BMl5BanBnXkFtZTgwODM3MTc2MjE@._V1_FMjpg_UX1000_.jpg', 'Jennifer Lawrence, Josh Hutcherson, Liam Hemsworth, Woody Harrelson, Donald Sutherland, Philip Seymour Hoffman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (117176, 'The Theory of Everything', 'Drama,Romance', 2014, 'James Marsh', 'Stephen Hawking gets unprecedented success in the field of physics despite being diagnosed with motor neuron disease at the age of 21. He defeats awful odds as his first wife Jane aids him loyally.', 'https://m.media-amazon.com/images/M/MV5BMTAwMTU4MDA3NDNeQTJeQWpwZ15BbWU4MDk4NTMxNTIx._V1_FMjpg_UX1000_.jpg', 'Eddie Redmayne, Felicity Jones, Tom Prior, Sophie Perry, Finlay Wright-Stephens, Harry Lloyd', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (117438, 'When Marnie Was There', 'Animation,Drama', 2014, 'Hiromasa Yonebayashi', 'Anna, a shy 12-year-old girl, is sent to spend time with her aunt and uncle who live in the countryside, where she meets Marnie. The two become best friends. But Anna gradually discovers that Marnie is not quite who she appears to be.', 'https://m.media-amazon.com/images/M/MV5BYjM3MGUyY2YtYjMwNC00ODI5LWIyMTctM2JiZDE0ODBjNDcxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sara Takatsuki, Kasumi Arimura, Nanako Matsushima, Susumu Terajima, Toshie Negishi, Ryôko Moriyama', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (117529, 'Jurassic World', 'Action,Adventure,Drama,Sci-Fi,Thriller', 2015, 'Colin Trevorrow', 'A new theme park, built on the original site of Jurassic Park, creates a genetically modified hybrid dinosaur, the Indominus Rex, which escapes containment and goes on a killing spree.', 'https://m.media-amazon.com/images/M/MV5BNzBhNzlkM2UtZTQyOC00NjUyLTkzMmMtNDQ1YTM5N2NmMGE5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chris Pratt, Bryce Dallas Howard, Irrfan Khan, Vincent D\'Onofrio, Ty Simpkins, Nick Robinson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (117533, 'Citizenfour', 'Documentary', 2014, 'Laura Poitras', 'A documentarian and a reporter travel to Hong Kong for the first of many meetings with Edward Snowden.', 'https://m.media-amazon.com/images/M/MV5BMTc0MTM0MTA5MF5BMl5BanBnXkFtZTgwNzEwODEwMzE@._V1_FMjpg_UX1000_.jpg', 'Edward Snowden, Glenn Greenwald, William Binney, Jacob Appelbaum, Ewen MacAskill, Jeremy Scahill', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (117879, 'Altman', 'Documentary', 2014, 'Ron Mann', 'A look at the life and work of American film-maker Robert Altman.', 'https://m.media-amazon.com/images/M/MV5BMTkzNDQyNzczOF5BMl5BanBnXkFtZTgwOTkwOTc5MTE@._V1_FMjpg_UX1000_.jpg', 'Michael Murphy, Robert Altman, Kathryn Reed, Sally Kellerman, James Caan, Donald Sutherland', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (117881, 'Still Alice', 'Drama', 2014, 'Richard Glatzer', 'A linguistics professor and her family find their bonds tested when she is diagnosed with Alzheimer\'s Disease.', 'https://m.media-amazon.com/images/M/MV5BMjIzNzAxNjY1Nl5BMl5BanBnXkFtZTgwMDg4ODQxMzE@._V1_FMjpg_UX1000_.jpg', 'Julianne Moore, Kate Bosworth, Shane McRae, Hunter Parrish, Alec Baldwin, Seth Gilliam', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (118696, 'The Hobbit: The Battle of the Five Armies', 'Adventure,Fantasy', 2014, 'Peter Jackson', 'Bilbo Baggins and company are forced to engage in a war against an array of combatants and keep the Lonely Mountain from falling into the hands of a rising darkness.', 'https://m.media-amazon.com/images/M/MV5BMTYzNDE3OTQ3MF5BMl5BanBnXkFtZTgwODczMTg4MjE@._V1_FMjpg_UX1000_.jpg', 'Ian McKellen, Martin Freeman, Richard Armitage, Ken Stott, Graham McTavish, William Kircher', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (118702, 'Unbroken', 'Drama,War', 2014, 'Angelina Jolie', 'After a near-fatal plane crash in WWII, Olympian Louis Zamperini spends a harrowing 47 days in a raft with two fellow crewmen before he\'s caught by the Japanese navy and sent to a prisoner-of-war camp.', 'https://m.media-amazon.com/images/M/MV5BMTY3ODg2OTgyOF5BMl5BanBnXkFtZTgwODk1OTAwMzE@._V1_FMjpg_UX1000_.jpg', 'Jack O\'Connell, Domhnall Gleeson, Garrett Hedlund, Miyavi, Finn Wittrock, Jai Courtney', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (118854, 'The Dust Bowl', 'Documentary', 2012, 'Dorothy Christenson Wiliamson', 'A documentary about the 1930s drought of North American prairie farm land, and its consequences during the great depression.', 'https://m.media-amazon.com/images/M/MV5BMTJiMDc1ODctOTNmYy00ZjRhLTljMzQtYTYzZTg3ZmU5NWE1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dorothy Christenson Wiliamson, Donald Worster, Timothy Egan, Pamela Riney-Kehrberg, Calvin Crabill, Imogene Glover', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (119068, 'Men, Women & Children', 'Comedy,Drama', 2014, 'Jason Reitman', 'A group of high school teenagers and their parents attempt to navigate the many ways the Internet has changed their relationships, their communications, their self-images, and their love lives.', 'https://m.media-amazon.com/images/M/MV5BMTAwMzc2OTgwOTZeQTJeQWpwZ15BbWU4MDg2ODA4NjIx._V1_FMjpg_UX1000_.jpg', 'Adam Sandler, Jennifer Garner, Rosemarie DeWitt, Judy Greer, Dean Norris, Emma Thompson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (119145, 'Kingsman: The Secret Service', 'Action,Adventure,Comedy,Crime', 2015, 'Matthew Vaughn', 'A spy organisation recruits a promising street kid into the agency\'s training program, while a global threat emerges from a twisted tech genius.', 'https://m.media-amazon.com/images/M/MV5BODk1MTYwNTAtYmI5Zi00OWYyLWE0MzQtOWE4NDIxZmU2MjMwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Adrian Quinton, Colin Firth, Mark Strong, Jonno Davies, Jack Davenport, Alex Nikolov', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (120138, 'PK', 'Comedy,Drama,Fantasy,Mystery,Romance', 2014, 'Rajkumar Hirani', 'An alien on Earth loses the only device he can use to communicate with his spaceship. His innocent nature and child-like questions force the country to evaluate the impact of religious views on people.', 'https://m.media-amazon.com/images/M/MV5BMTYzOTE2NjkxN15BMl5BanBnXkFtZTgwMDgzMTg0MzE@._V1_FMjpg_UX1000_.jpg', 'Aamir Khan, Anushka Sharma, Saurabh Shukla, Sushant Singh Rajput, Boman Irani, Sanjay Dutt', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (120466, 'Chappie', 'Action,Thriller', 2015, 'Neill Blomkamp', 'In the near future, crime is patrolled by a mechanized police force. When one police droid, Chappie, is stolen and given new programming, he becomes the first robot with the ability to think and feel for himself.', 'https://m.media-amazon.com/images/M/MV5BMTUyNTI4NTIwNl5BMl5BanBnXkFtZTgwMjQ4MTI0NDE@._V1_FMjpg_UX1000_.jpg', 'Sharlto Copley, Dev Patel, Ninja, Yo-Landi Visser, Jose Pablo Cantillo, Hugh Jackman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (121231, 'It Follows', 'Horror', 2014, 'David Robert Mitchell', 'A young woman is followed by an unknown supernatural force after a sexual encounter.', 'https://m.media-amazon.com/images/M/MV5BNGZiYWRiYjAtODU0NS00YzAzLTk2MzQtZGVlMzVjM2M3MGQ3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bailey Spry, Carollette Phillips, Loren Bass, Keir Gilchrist, Maika Monroe, Lili Sepe', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122882, 'Mad Max: Fury Road', 'Action,Adventure,Sci-Fi,Thriller', 2015, 'George Miller', 'In a post-apocalyptic wasteland, a woman rebels against a tyrannical ruler in search for her homeland with the aid of a group of female prisoners, a psychotic worshipper and a drifter named Max.', 'https://m.media-amazon.com/images/M/MV5BZDRkODJhOTgtOTc1OC00NTgzLTk4NjItNDgxZDY4YjlmNDY2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hardy, Charlize Theron, Nicholas Hoult, Hugh Keays-Byrne, Josh Helman, Nathan Jones', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122886, 'Star Wars: Episode VII - The Force Awakens', 'Action,Adventure,Fantasy,Sci-Fi,IMAX', 2015, 'J.J. Abrams', 'As a new threat to the galaxy rises, Rey, a desert scavenger, and Finn, an ex-stormtrooper, must join Han Solo and Chewbacca to search for the one hope of restoring peace.', 'https://m.media-amazon.com/images/M/MV5BOTAzODEzNDAzMl5BMl5BanBnXkFtZTgwMDU1MTgzNzE@._V1_FMjpg_UX1000_.jpg', 'Harrison Ford, Mark Hamill, Carrie Fisher, Adam Driver, Daisy Ridley, John Boyega', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122892, 'Avengers: Age of Ultron', 'Action,Adventure,Sci-Fi', 2015, 'Joss Whedon', 'When Tony Stark and Bruce Banner try to jump-start a dormant peacekeeping program called Ultron, things go horribly wrong and it\'s up to Earth\'s mightiest heroes to stop the villainous Ultron from enacting his terrible plan.', 'https://m.media-amazon.com/images/M/MV5BODBhYTg1NGQtNGVmNS00ZTdiLThjYTYtZDFkNzRiNTZmNDZjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert Downey Jr., Chris Hemsworth, Mark Ruffalo, Chris Evans, Scarlett Johansson, Jeremy Renner', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122898, 'Justice League', 'Action,Adventure,Sci-Fi', 2017, 'Zack Snyder', 'Steppenwolf and his Parademons return after eons to capture Earth. However, Batman seeks the help of Wonder Woman to recruit and assemble Flash, Cyborg and Aquaman to fight the powerful new enemy.', 'https://m.media-amazon.com/images/M/MV5BMjM5YmQxM2YtZjI2Yy00YjhhLTg5N2MtMTEyMzdlZDU3OTVhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ben Affleck, Henry Cavill, Amy Adams, Gal Gadot, Ezra Miller, Jason Momoa', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122900, 'Ant-Man', 'Action,Adventure,Sci-Fi', 2015, 'Peyton Reed', 'Armed with a super-suit with the astonishing ability to shrink in scale but increase in strength, cat burglar Scott Lang must embrace his inner hero and help his mentor, Dr. Hank Pym, pull off a plan that will save the world.', 'https://m.media-amazon.com/images/M/MV5BMjM2NTQ5Mzc2M15BMl5BanBnXkFtZTgwNTcxMDI2NTE@._V1_FMjpg_UX1000_.jpg', 'Paul Rudd, Michael Douglas, Evangeline Lilly, Corey Stoll, Bobby Cannavale, Anthony Mackie', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122904, 'Deadpool', 'Action,Adventure,Comedy,Sci-Fi', 2016, 'Tim Miller', 'A wisecracking mercenary gets experimented on and becomes immortal yet hideously scarred, and sets out to track down the man who ruined his looks.', 'https://m.media-amazon.com/images/M/MV5BNzY3ZWU5NGQtOTViNC00ZWVmLTliNjAtNzViNzlkZWQ4YzQ4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ryan Reynolds, Karan Soni, Ed Skrein, Michael Benyaer, Stefan Kapicic, Brianna Hildebrand', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122906, 'Black Panther', 'Action,Adventure,Sci-Fi', 2017, 'Ryan Coogler', 'T\'Challa, heir to the hidden but advanced kingdom of Wakanda, must step forward to lead his people into a new future and must confront a challenger from his country\'s past.', 'https://m.media-amazon.com/images/M/MV5BMTg1MTY2MjYzNV5BMl5BanBnXkFtZTgwMTc4NTMwNDI@._V1_FMjpg_UX1000_.jpg', 'Chadwick Boseman, Michael B. Jordan, Lupita Nyong\'o, Danai Gurira, Martin Freeman, Daniel Kaluuya', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122910, 'Captain Marvel', 'Action,Adventure,Sci-Fi', 2018, 'Anna Boden', 'Carol Danvers becomes one of the universe\'s most powerful heroes when Earth is caught in the middle of a galactic war between two alien races.', 'https://m.media-amazon.com/images/M/MV5BZDI1NGU2ODAtNzBiNy00MWY5LWIyMGEtZjUxZjUwZmZiNjBlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brie Larson, Samuel L. Jackson, Ben Mendelsohn, Jude Law, Annette Bening, Djimon Hounsou', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122912, 'Avengers: Infinity War - Part I', 'Action,Adventure,Sci-Fi', 2018, 'Anthony Russo', 'The Avengers and their allies must be willing to sacrifice all in an attempt to defeat the powerful Thanos before his blitz of devastation and ruin puts an end to the universe.', 'https://m.media-amazon.com/images/M/MV5BMjMxNjY2MDU1OV5BMl5BanBnXkFtZTgwNzY1MTUwNTM@._V1_FMjpg_UX1000_.jpg', 'Robert Downey Jr., Chris Hemsworth, Mark Ruffalo, Chris Evans, Scarlett Johansson, Don Cheadle', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122914, 'Avengers: Infinity War - Part II', 'Action,Adventure,Sci-Fi', 2019, 'Anthony Russo', 'After the devastating events of Avengers: Infinity War (2018), the universe is in ruins. With the help of remaining allies, the Avengers assemble once more in order to reverse Thanos\' actions and restore balance to the universe.', 'https://m.media-amazon.com/images/M/MV5BMTc5MDE2ODcwNV5BMl5BanBnXkFtZTgwMzI2NzQ2NzM@._V1_FMjpg_UX1000_.jpg', 'Robert Downey Jr., Chris Evans, Mark Ruffalo, Chris Hemsworth, Scarlett Johansson, Jeremy Renner', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122916, 'Thor: Ragnarok', 'Action,Adventure,Sci-Fi', 2017, 'Taika Waititi', 'Imprisoned on the planet Sakaar, Thor must race against time to return to Asgard and stop Ragnarök, the destruction of his world, at the hands of the powerful and ruthless villain Hela.', 'https://m.media-amazon.com/images/M/MV5BMjMyNDkzMzI1OF5BMl5BanBnXkFtZTgwODcxODg5MjI@._V1_FMjpg_UX1000_.jpg', 'Chris Hemsworth, Tom Hiddleston, Cate Blanchett, Idris Elba, Jeff Goldblum, Tessa Thompson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122918, 'Guardians of the Galaxy 2', 'Action,Adventure,Sci-Fi', 2017, 'James Gunn', 'The Guardians struggle to keep together as a team while dealing with their personal family issues, notably Star-Lord\'s encounter with his father, the ambitious celestial being Ego.', 'https://m.media-amazon.com/images/M/MV5BNWE5MGI3MDctMmU5Ni00YzI2LWEzMTQtZGIyZDA5MzQzNDBhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chris Pratt, Zoe Saldaña, Dave Bautista, Vin Diesel, Bradley Cooper, Michael Rooker', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122920, 'Captain America: Civil War', 'Action,Sci-Fi,Thriller', 2016, 'Anthony Russo', 'Political involvement in the Avengers\' affairs causes a rift between Captain America and Iron Man.', 'https://m.media-amazon.com/images/M/MV5BMjQ0MTgyNjAxMV5BMl5BanBnXkFtZTgwNjUzMDkyODE@._V1_FMjpg_UX1000_.jpg', 'Chris Evans, Robert Downey Jr., Scarlett Johansson, Sebastian Stan, Anthony Mackie, Don Cheadle', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122922, 'Doctor Strange', 'Action,Adventure,Sci-Fi', 2016, 'Scott Derrickson', 'While on a journey of physical and spiritual healing, a brilliant neurosurgeon is drawn into the world of the mystic arts.', 'https://m.media-amazon.com/images/M/MV5BNjgwNzAzNjk1Nl5BMl5BanBnXkFtZTgwMzQ2NjI1OTE@._V1_FMjpg_UX1000_.jpg', 'Benedict Cumberbatch, Chiwetel Ejiofor, Rachel McAdams, Benedict Wong, Mads Mikkelsen, Tilda Swinton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (122926, 'Untitled Spider-Man Reboot', 'Action,Adventure,Fantasy', 2017, 'Jon Watts', 'Peter Parker tries to stop Adrian \'The Vulture\' Toomes from selling weapons made with advanced Chitauri technology while trying to balance his life as an ordinary high school student.', 'https://m.media-amazon.com/images/M/MV5BODY2MTAzOTQ4M15BMl5BanBnXkFtZTgwNzg5MTE0MjI@._V1_FMjpg_UX1000_.jpg', 'Tom Holland, Michael Keaton, Robert Downey Jr., Marisa Tomei, Jon Favreau, Gwyneth Paltrow', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (126430, 'The Pacific', 'Action,Adventure,Drama,War', 2010, 'James Badge Dale', 'The Pacific Theatre of World War II, as seen through the eyes of several young Marines.', 'https://m.media-amazon.com/images/M/MV5BNGFjYTZmYjEtZDI3MS00MGVhLWI5NDQtY2QwZTcwNjUwMTA2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'James Badge Dale, Joseph Mazzello, Jon Seda, Ashton Holmes, Josh Helman, Rami Malek', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (127114, 'The End of the Tour', 'Drama', 2015, 'James Ponsoldt', 'The story of the five-day interview between Rolling Stone reporter David Lipsky and acclaimed novelist David Foster Wallace, which took place right after the 1996 publication of Wallace\'s groundbreaking epic novel, \'Infinite Jest.\'', 'https://m.media-amazon.com/images/M/MV5BMTUwODU3NjQxNF5BMl5BanBnXkFtZTgwODE2NTE4NTE@._V1_FMjpg_UX1000_.jpg', 'Jesse Eisenberg, Jason Segel, Anna Chlumsky, Mamie Gummer, Mickey Sumner, Joan Cusack', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (127202, 'Me and Earl and the Dying Girl', 'Drama', 2015, 'Alfonso Gomez-Rejon', 'High schooler Greg, who spends most of his time making parodies of classic movies with his co-worker Earl, finds his outlook forever altered after befriending a classmate who has just been diagnosed with cancer.', 'https://m.media-amazon.com/images/M/MV5BNTA1NzUzNjY4MV5BMl5BanBnXkFtZTgwNDU0MDI0NTE@._V1_FMjpg_UX1000_.jpg', 'Thomas Mann, RJ Cyler, Olivia Cooke, Nick Offerman, Connie Britton, Molly Shannon', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (127311, 'The Forbidden Room', 'Comedy,Drama,Mystery,Romance', 2015, 'Evan Johnson', 'In this non-linear amalgamation, submarine crewmen and a woodsman wend their way through a voyage of odd experiences.', 'https://m.media-amazon.com/images/M/MV5BMTYzMTkyNjE4OF5BMl5BanBnXkFtZTgwMzU3MTQwNzE@._V1_FMjpg_UX1000_.jpg', 'Roy Dupuis, Clara Furey, Louis Negin, Udo Kier, Gregory Hlady, Mathieu Amalric', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (127323, 'Vice', 'Action,Adventure,Sci-Fi,Thriller', 2015, 'Brian A. Miller', 'Bruce Willis stars in this Sci-Fi thriller about ultimate resort: VICE, where customers can play out their wildest fantasies with artificial inhabitants who look like humans.', 'https://m.media-amazon.com/images/M/MV5BMjE4OTg3Mjg5OV5BMl5BanBnXkFtZTgwMzYxMTg0MzE@._V1_FMjpg_UX1000_.jpg', 'Ambyr Childers, Thomas Jane, Bryan Greenberg, Bruce Willis, Johnathon Schaech, Charlotte Kirk', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (127390, 'Family Guy Presents: Blue Harvest', 'Animation,Comedy', 2007, 'Dominic Polcino', 'With the Griffins stuck at home during a blackout, Peter tells the story of Star Wars Episode IV: A New Hope.', 'https://m.media-amazon.com/images/M/MV5BZWQ3OGQ4N2QtY2Y3MC00ZmVhLTllNjktMTcxN2UxNTkzNzZlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Seth MacFarlane, Alex Borstein, Seth Green, Mila Kunis, Mike Henry, Lori Alan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (127652, 'We Are Young. We Are Strong.', 'Drama', 2014, 'Burhan Qurbani', 'People from different walks of life in the German city of Rostock intersect when a rampaging mob besieges a residential building occupied by Vietnamese immigrants.', 'https://m.media-amazon.com/images/M/MV5BMTc3MzUzNTAyNF5BMl5BanBnXkFtZTgwMDE3NzA4NjE@._V1_FMjpg_UX1000_.jpg', 'Jonas Nay, Trang Le Hong, Devid Striesow, Joel Basman, Saskia Rosendahl, Paul Gäbler', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (128093, 'Bo Burnham: Words, Words, Words', 'Comedy', 2010, 'Shannon Hartman', 'The internet (and soon to be movie, TV, radio, etc.) phenomenon, Bo Burnham, brings you his first one-hour stand-up special \"Bo Burnham: Words, Words, Words\" from the House of Blues in Boston.', 'https://m.media-amazon.com/images/M/MV5BZmYyMDFlNTUtM2EyOS00YTAwLWJhMGEtYTgzN2NlODM1YjViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bo Burnham', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (128360, 'The Hateful Eight', 'Western', 2015, 'Quentin Tarantino', 'In the dead of a Wyoming winter, a bounty hunter and his prisoner find shelter in a cabin currently inhabited by a collection of nefarious characters.', 'https://m.media-amazon.com/images/M/MV5BMjA1MTc1NTg5NV5BMl5BanBnXkFtZTgwOTM2MDEzNzE@._V1_FMjpg_UX1000_.jpg', 'Samuel L. Jackson, Kurt Russell, Jennifer Jason Leigh, Walton Goggins, Demián Bichir, Tim Roth', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (128512, 'Paper Towns', 'Drama,Mystery,Romance', 2015, 'Jake Schreier', 'After an all-night adventure, Quentin\'s lifelong crush, Margo, disappears, leaving behind clues that Quentin and his friends follow on the journey of a lifetime.', 'https://m.media-amazon.com/images/M/MV5BMjE2ODQxODMwOF5BMl5BanBnXkFtZTgwNDY5NjY3NDE@._V1_FMjpg_UX1000_.jpg', 'Nat Wolff, Cara Delevingne, Austin Abrams, Justice Smith, Halston Sage, Jaz Sinclair', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (128838, 'Crimson Peak', 'Horror', 2015, 'Guillermo del Toro', 'A new bride investigates ghostly visions at a remote gothic mansion that holds dark secrets.', 'https://m.media-amazon.com/images/M/MV5BNjg2NzcxYzAtZDdjYS00ZTZiLTg5ZmMtZmQ1ZjBhNGQxMDI0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mia Wasikowska, Jessica Chastain, Tom Hiddleston, Charlie Hunnam, Jim Beaver, Burn Gorman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (131724, 'The Jinx: The Life and Deaths of Robert Durst', 'Documentary', 2015, 'Robert Durst', 'Filmmaker Andrew Jarecki examines the complicated life of reclusive real estate icon Robert Durst, the key suspect in a series of unsolved crimes.', 'https://m.media-amazon.com/images/M/MV5BYTVhZGNkNDMtNWEwMi00ODgxLTg2NTItN2UxOWFjYzNlZjUwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert Durst, Andrew Jarecki, Charles Bagli, Dick DeGuerin, Kathie Durst, Paul Blumenthal', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (132660, 'Man Up', 'Comedy,Romance', 2015, 'Ben Palmer', 'A single woman takes the place of a stranger\'s blind date and finds the perfect man for her.', 'https://m.media-amazon.com/images/M/MV5BMTUzODcxNDcxMl5BMl5BanBnXkFtZTgwODE1NjM4NTE@._V1_FMjpg_UX1000_.jpg', 'Lake Bell, Rory Kinnear, Ken Stott, Harriet Walter, Olivia Williams, Sharon Horgan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (133195, 'Hitman: Agent 47', 'Action,Crime,Thriller', 2015, 'Aleksander Bach', 'An assassin teams up with a woman to help her find her father and uncover the mysteries of her ancestry.', 'https://m.media-amazon.com/images/M/MV5BNTBiYjg1ZGYtZjQxZS00NDBkLTgyZjEtZGIzYWNmNjhiOGRjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Angelababy, Dan Bakkedahl, Charlene Beck, Michael Bornhütter, Melissa Broughton, Nils Brunkhorst', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (133771, 'The Lobster', 'Comedy,Romance,Sci-Fi', 2015, 'Yorgos Lanthimos', 'In a dystopian near future, according to the laws of The City, single people are taken to The Hotel, where they are obliged to find a romantic partner in 45 days or they\'re transformed into beasts and sent off into The Woods.', 'https://m.media-amazon.com/images/M/MV5BNDQ1NDE5NzQ1NF5BMl5BanBnXkFtZTgwNzA5OTM2NTE@._V1_FMjpg_UX1000_.jpg', 'Jacqueline Abrahams, Roger Ashton-Griffiths, Jessica Barden, Olivia Colman, Anthony Dougall, Seán Duggan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (134130, 'The Martian', 'Adventure,Drama,Sci-Fi', 2015, 'Ridley Scott', 'An astronaut becomes stranded on Mars after his team assumes him dead, and must rely on his ingenuity to find a way to signal to Earth that he is alive and can survive until a potential rescue.', 'https://m.media-amazon.com/images/M/MV5BMTc2MTQ3MDA1Nl5BMl5BanBnXkFtZTgwODA3OTI4NjE@._V1_FMjpg_UX1000_.jpg', 'Matt Damon, Jessica Chastain, Kristen Wiig, Jeff Daniels, Michael Peña, Sean Bean', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (134170, 'Kung Fury', 'Action,Comedy,Fantasy,Sci-Fi', 2015, 'David Sandberg', 'In 1985, Kung Fury, the toughest martial artist cop in Miami, goes back in time to kill the worst criminal of all time - Kung Führer, a.k.a. Adolf Hitler.', 'https://m.media-amazon.com/images/M/MV5BMjQwMjU2ODU5NF5BMl5BanBnXkFtZTgwNTU1NjM4NTE@._V1_FMjpg_UX1000_.jpg', 'David Sandberg, Jorma Taccone, Steven Chew, Leopold Nilsson, Andreas Cahling, Per-Henrik Arvidius', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (134214, 'Youth', 'Drama', 2015, 'Paolo Sorrentino', 'Retired orchestra conductor Fred Ballinger is on vacation with his daughter Lena and his film director best friend Mick Boyle in the Alps when he receives an invitation from Queen Elizabeth II to perform for Prince Philip\'s birthday.', 'https://m.media-amazon.com/images/M/MV5BMjI2OTk5MzYyMl5BMl5BanBnXkFtZTgwMzY1MjE3NjE@._V1_FMjpg_UX1000_.jpg', 'The Retrosettes, Gabriella Belisario, Laura De Marchi, Rachel Weisz, Paul Dano, Harvey Keitel', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (134248, 'Hot Girls Wanted', 'Documentary', 2015, 'Jill Bauer', 'A documentary about young women who have been drawn into the sex trade - and how easy it is for a web-savvy generation to end up making porn.', 'https://m.media-amazon.com/images/M/MV5BZDYxZmZhMmUtNTY3YS00YmQyLWI3ODctMWI2ZTEwMWRmYTJlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Stella May, Riley Reynolds, Rachel Bernard, John Anthony, Kelly Silguero, Emeterio Silguero', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (134368, 'Spy', 'Action,Comedy,Crime', 2015, 'Paul Feig', 'A desk-bound CIA analyst volunteers to go undercover to infiltrate the world of a deadly arms dealer and prevent diabolical global disaster.', 'https://m.media-amazon.com/images/M/MV5BNjI5OTQ0MDQxM15BMl5BanBnXkFtZTgwMzcwNjMyNTE@._V1_FMjpg_UX1000_.jpg', 'Jude Law, Raad Rawi, Melissa McCarthy, Jessica Chaffin, Miranda Hart, Sam Richardson', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (134853, 'Inside Out', 'Adventure,Animation,Children,Comedy,Drama,Fantasy', 2015, 'Ronnie Del Carmen', 'After young Riley is uprooted from her Midwest life and moved to San Francisco, her emotions, Joy, Fear, Anger, Disgust, and Sadness, conflict on how best to navigate a new city, house, and school.', 'https://m.media-amazon.com/images/M/MV5BOTgxMDQwMDk0OF5BMl5BanBnXkFtZTgwNjU5OTg2NDE@._V1_FMjpg_UX1000_.jpg', 'Amy Poehler, Phyllis Smith, Richard Kind, Bill Hader, Lewis Black, Mindy Kaling', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (135141, 'Allegiant: Part 1', 'Adventure,Sci-Fi', 2016, 'Robert Schwentke', 'After the earth-shattering revelations of Insurgent, Tris must escape with Four beyond the wall that encircles Chicago to finally discover the shocking truth of the world outside.', 'https://m.media-amazon.com/images/M/MV5BMzZlYzZlNDktMDAxMS00OGZiLThkYzAtNWEzNDliYjAyZmM5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Shailene Woodley, Theo James, Naomi Watts, Octavia Spencer, Jeff Daniels, Zoë Kravitz', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (135143, 'Fantastic Beasts and Where to Find Them', 'Fantasy', 2016, 'David Yates', 'In 1926, magizoologist Newt Scamander arrives in New York during his worldwide tour to research and rescue magical creatures as something mysterious leaves trails of destruction in the city, threatening to expose the wizarding world.', 'https://m.media-amazon.com/images/M/MV5BMjMxOTM1OTI4MV5BMl5BanBnXkFtZTgwODE5OTYxMDI@._V1_FMjpg_UX1000_.jpg', 'Eddie Redmayne, Sam Redford, Scott Goldman, Tim Bentinck, Tristan Tait, Colin Farrell', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (135278, 'Wendy Wu: Homecoming Warrior', 'Action,Adventure,Children', 2006, 'John Laing', 'A Californian teenager learns that she is the reincarnation of a legendary female warrior destined to protect the world.', 'https://m.media-amazon.com/images/M/MV5BZTY2YmU3MmEtNTExMi00YzljLWE2ZWUtYTY0MzUyOTMyODk4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brenda Song, Shin Koyamada, Susan Chuang, Justin Chon, Michael David Cheng, Andy Fischer-Price', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (135518, 'Self/less', 'Action,Mystery,Sci-Fi,Thriller', 2015, 'Tarsem Singh', 'A dying real estate mogul transfers his consciousness into a healthy young body, but soon finds that neither the procedure nor the company that performed it are quite what they seem.', 'https://m.media-amazon.com/images/M/MV5BMTU0MTQzNzAxMl5BMl5BanBnXkFtZTgwNjg4MjcxNjE@._V1_FMjpg_UX1000_.jpg', 'Ryan Reynolds, Natalie Martinez, Matthew Goode, Ben Kingsley, Victor Garber, Derek Luke', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (135536, 'Suicide Squad', 'Action,Crime,Sci-Fi', 2016, 'David Ayer', 'A secret government agency recruits some of the most dangerous incarcerated super-villains to form a defensive task force. Their first mission: save the world from the apocalypse.', 'https://m.media-amazon.com/images/M/MV5BMjM1OTMxNzUyM15BMl5BanBnXkFtZTgwNjYzMTIzOTE@._V1_FMjpg_UX1000_.jpg', 'Will Smith, Jaime FitzSimons, Ike Barinholtz, Margot Robbie, Christopher Dyson, Bambadjan Bamba', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (135569, 'Star Trek Beyond', 'Action,Adventure,Sci-Fi', 2016, 'Justin Lin', 'The crew of the USS Enterprise explores the furthest reaches of uncharted space, where they encounter a new ruthless enemy, who puts them, and everything the Federation stands for, to the test.', 'https://m.media-amazon.com/images/M/MV5BN2FhNDI1YTYtNWI0OC00ZjYxLWJlYWEtN2ZiZjRmZDY1MWJjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chris Pine, Zachary Quinto, Karl Urban, Zoe Saldaña, Simon Pegg, John Cho', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (135887, 'Minions', 'Adventure,Animation,Children,Comedy', 2015, 'Kyle Balda', 'Minions Stuart, Kevin, and Bob are recruited by Scarlet Overkill, a supervillain who, alongside her inventor husband Herb, hatches a plot to take over the world.', 'https://m.media-amazon.com/images/M/MV5BODI4NzMyNjE0MF5BMl5BanBnXkFtZTgwMTcwNzI0MzE@._V1_FMjpg_UX1000_.jpg', 'Sandra Bullock, Jon Hamm, Michael Keaton, Allison Janney, Steve Coogan, Jennifer Saunders', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (136018, 'Black Mass', 'Crime,Drama', 2015, 'Scott Cooper', 'The true story of Whitey Bulger, the brother of a state senator and the most infamous violent criminal in the history of South Boston, who became an FBI informant to take down a Mafia family invading his turf.', 'https://m.media-amazon.com/images/M/MV5BNzg0ODI3NDQxNF5BMl5BanBnXkFtZTgwMzgzNDA0NjE@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Joel Edgerton, Benedict Cumberbatch, Dakota Johnson, Kevin Bacon, Peter Sarsgaard', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (136020, 'Spectre', 'Action,Adventure,Crime', 2015, 'Sam Mendes', 'A cryptic message from James Bond\'s past sends him on a trail to uncover the existence of a sinister organisation named SPECTRE. With a new threat dawning, Bond learns the terrible truth about the author of all his pain in his most recent missions.', 'https://m.media-amazon.com/images/M/MV5BMzA5MzFiNDAtYTI0NC00MDE5LTljYTctYTNkODk1OTZlODI5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Daniel Craig, Christoph Waltz, Léa Seydoux, Ralph Fiennes, Monica Bellucci, Ben Whishaw', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (136562, 'Steve Jobs', 'Drama', 2015, 'Danny Boyle', 'Steve Jobs takes us behind the scenes of the digital revolution, to paint a portrait of the man at its epicenter. The story unfolds backstage at three iconic product launches, ending in 1998 with the unveiling of the iMac.', 'https://m.media-amazon.com/images/M/MV5BMjE0NTA2MTEwOV5BMl5BanBnXkFtZTgwNzg4NzU2NjE@._V1_FMjpg_UX1000_.jpg', 'Michael Fassbender, Kate Winslet, Seth Rogen, Jeff Daniels, Michael Stuhlbarg, Katherine Waterston', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (136602, 'Creep', 'Horror,Thriller', 2014, 'Patrick Brice', 'A young videographer answers an online ad for a one-day job in a remote town to record the last messages of a dying man. When he notices the man\'s odd behavior, he starts to question his intentions.', 'https://m.media-amazon.com/images/M/MV5BMTY0NTU2ODM5Ml5BMl5BanBnXkFtZTgwMTAwOTA5NTE@._V1_FMjpg_UX1000_.jpg', 'Mark Duplass, Patrick Brice, Katie Aselton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (136864, 'Batman v Superman: Dawn of Justice', 'Action,Adventure,Fantasy,Sci-Fi', 2016, 'Zack Snyder', 'Batman is manipulated by Lex Luthor to fear Superman. Superman´s existence is meanwhile dividing the world and he is framed for murder during an international crisis. The heroes clash and force the neutral Wonder Woman to reemerge.', 'https://m.media-amazon.com/images/M/MV5BZTJkYjdmYjYtOGMyNC00ZGU1LThkY2ItYTc1OTVlMmE2YWY1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ben Affleck, Henry Cavill, Amy Adams, Jesse Eisenberg, Diane Lane, Laurence Fishburne', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (137737, 'Darkness Falls', 'Drama,Horror,Romance,Thriller', 1999, 'Gerry Lively', 'An intruder invades the home of Mark and Sally Driscoll, a heavily indebted businessman, and his rich, neglected wife. Determined to learn the truth, the man takes them hostage. As he tells his story, secrets are revealed.', 'https://m.media-amazon.com/images/M/MV5BOTUzMzYyMjE0NF5BMl5BanBnXkFtZTcwODM5ODAwMQ@@._V1_FMjpg_UX1000_.jpg', 'Sherilyn Fenn, Ray Winstone, Tim Dutton, Anita Dobson, Bryan Pringle, Robin McCaffrey', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (137857, 'The Jungle Book', 'Adventure,Drama,Fantasy', 2016, 'Jon Favreau', 'After a threat from the tiger Shere Khan forces him to flee the jungle, a man-cub named Mowgli embarks on a journey of self discovery with the help of panther Bagheera and free-spirited bear Baloo.', 'https://m.media-amazon.com/images/M/MV5BMTc3NTUzNTI4MV5BMl5BanBnXkFtZTgwNjU0NjU5NzE@._V1_FMjpg_UX1000_.jpg', 'Neel Sethi, Bill Murray, Ben Kingsley, Idris Elba, Lupita Nyong\'o, Scarlett Johansson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (138036, 'The Man from U.N.C.L.E.', 'Action,Adventure,Comedy', 2015, 'Guy Ritchie', 'In the early 1960s, CIA agent Napoleon Solo and KGB operative Illya Kuryakin participate in a joint mission against a mysterious criminal organization, which is working to proliferate nuclear weapons.', 'https://m.media-amazon.com/images/M/MV5BMDFjN2NlOGItYjZiZi00OThhLTlhYWUtYjgyNWFjMWJlNGU4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Henry Cavill, Armie Hammer, Alicia Vikander, Elizabeth Debicki, Luca Calvani, Sylvester Groth', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (138210, '13 Hours', 'Drama', 2016, 'Michael Bay', 'During an attack on a U.S. compound in Libya, a security team struggles to make sense out of the chaos.', 'https://m.media-amazon.com/images/M/MV5BOGM1MWUzZjktMWY0MS00N2ZhLWJmZjQtNjIxOGVlNzA1OGI0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Krasinski, James Badge Dale, Pablo Schreiber, David Denman, Dominic Fumusa, Max Martini', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (139385, 'The Revenant', 'Adventure,Drama', 2015, 'Alejandro G. Iñárritu', 'A frontiersman on a fur trading expedition in the 1820s fights for survival after being mauled by a bear and left for dead by members of his own hunting team.', 'https://m.media-amazon.com/images/M/MV5BYTgwNmQzZDctMjNmOS00OTExLTkwM2UtNzJmOTJhODFjOTdlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Tom Hardy, Domhnall Gleeson, Will Poulter, Forrest Goodluck, Paul Anderson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (139642, 'Southpaw', 'Action,Drama', 2015, 'Antoine Fuqua', 'After a fatal incident sends him on a rampant path of destruction, a champion boxer fights to get custody of his daughter and revive his professional career.', 'https://m.media-amazon.com/images/M/MV5BMjI1MTcwODk0MV5BMl5BanBnXkFtZTgwMTgwMDM5NTE@._V1_FMjpg_UX1000_.jpg', 'Jake Gyllenhaal, Rachel McAdams, Forest Whitaker, Oona Laurence, 50 Cent, Skylan Brooks', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (139644, 'Sicario', 'Crime,Drama,Mystery', 2015, 'Denis Villeneuve', 'An idealistic FBI agent is enlisted by a government task force to aid in the escalating war against drugs at the border area between the U.S. and Mexico.', 'https://m.media-amazon.com/images/M/MV5BMjA5NjM3NTk1M15BMl5BanBnXkFtZTgwMzg1MzU2NjE@._V1_FMjpg_UX1000_.jpg', 'Emily Blunt, Benicio Del Toro, Josh Brolin, Victor Garber, Jon Bernthal, Daniel Kaluuya', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (139747, 'Before We Go', 'Romance', 2014, 'Chris Evans', 'Two strangers stuck in Manhattan for the night grow into each other\'s most trusted confidants when an evening of unexpected adventure forces them to confront their fears and take control of their lives.', 'https://m.media-amazon.com/images/M/MV5BOTMxNzE0NjY4NV5BMl5BanBnXkFtZTgwMjIxNjIzNjE@._V1_FMjpg_UX1000_.jpg', 'Chris Evans, Alice Eve, Emma Fitzpatrick, John Cullum, Mark Kassen, Elijah Moreland', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (140110, 'The Intern', 'Comedy', 2015, 'Nancy Meyers', 'Seventy-year-old widower Ben Whittaker has discovered that retirement isn\'t all it\'s cracked up to be. Seizing an opportunity to get back in the game, he becomes a senior intern at an online fashion site, founded and run by Jules Ostin.', 'https://m.media-amazon.com/images/M/MV5BMTUyNjE5NjI5OF5BMl5BanBnXkFtZTgwNzYzMzU3NjE@._V1_FMjpg_UX1000_.jpg', 'Robert De Niro, Anne Hathaway, Rene Russo, Anders Holm, JoJo Kushner, Andrew Rannells', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (140174, 'Room', 'Drama', 2015, 'Lenny Abrahamson', 'A little boy is held captive in a room with his mother since his birth, so he has never known the world outside.', 'https://m.media-amazon.com/images/M/MV5BMjE4NzgzNzEwMl5BMl5BanBnXkFtZTgwMTMzMDE0NjE@._V1_FMjpg_UX1000_.jpg', 'Brie Larson, Jacob Tremblay, Sean Bridgers, Wendy Crewson, Sandy McMaster, Matt Gordon', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (140247, 'The Gift', 'Drama,Horror', 2015, 'Joel Edgerton', 'A married couple, Simon and Robyn, run into Gordo, an old classmate. Things take a turn when Gordo begins to drop in unannounced at their house and inundates them with mysterious gifts.', 'https://m.media-amazon.com/images/M/MV5BOTNlZmJiNGUtZGEwNC00MzE1LTkzNTItNGQ0NGRkYjhiYTNmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jason Bateman, Rebecca Hall, Joel Edgerton, Allison Tolman, Tim Griffin, Busy Philipps', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (140267, 'The Witch', 'Horror', 2015, 'Robert Eggers', 'An isolated Puritan family in 1630s New England comes unraveled by the forces of witchcraft and possession.', 'https://m.media-amazon.com/images/M/MV5BMTUyNzkwMzAxOF5BMl5BanBnXkFtZTgwMzc1OTk1NjE@._V1_FMjpg_UX1000_.jpg', 'Anya Taylor-Joy, Ralph Ineson, Kate Dickie, Harvey Scrimshaw, Ellie Grainger, Lucas Dawson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (140301, 'The Escort', 'Comedy,Romance', 2015, 'Will Slocombe', 'Desperate for a good story, a sex-addicted journalist throws himself into the world of high-class escorts when he starts following a Stanford-educated prostitute.', 'https://m.media-amazon.com/images/M/MV5BNTgzNDgzNDAyMF5BMl5BanBnXkFtZTgwMTgxOTkzNjE@._V1_FMjpg_UX1000_.jpg', 'Lyndsy Fonseca, Michael Doneger, Tommy Dewey, Bruce Campbell, Rachel Resheff, Rumer Willis', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (140481, 'Family Guy Presents: Something, Something, Something, Dark Side', 'Animation,Comedy,Sci-Fi', 2009, 'Dominic Polcino', 'Peter makes good on another power outage at home by retelling Star Wars Episode V: The Empire Strikes Back.', 'https://m.media-amazon.com/images/M/MV5BMTg0MDMzMTQ2MV5BMl5BanBnXkFtZTcwNjgwOTU0Mw@@._V1_FMjpg_UX1000_.jpg', 'Seth MacFarlane, Alex Borstein, Seth Green, Mila Kunis, Mike Henry, H. Jon Benjamin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (140715, 'Straight Outta Compton', 'Drama', 2015, 'F. Gary Gray', 'The rap group NWA emerges from the mean streets of Compton in the mid-1980s and revolutionizes hip-hop culture with their music and tales about life in the hood.', 'https://m.media-amazon.com/images/M/MV5BMTA5MzkyMzIxNjJeQTJeQWpwZ15BbWU4MDU0MDk0OTUx._V1_FMjpg_UX1000_.jpg', 'O\'Shea Jackson Jr., Corey Hawkins, Jason Mitchell, Neil Brown Jr., Aldis Hodge, Marlon Yates Jr.', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (140928, 'Joy', 'Comedy,Drama', 2015, 'David O. Russell', 'Joy is the story of the title character, who rose to become founder and matriarch of a powerful family business dynasty.', 'https://m.media-amazon.com/images/M/MV5BMzc2MTI5Mzk0MV5BMl5BanBnXkFtZTgwMDIxMDg1NjE@._V1_FMjpg_UX1000_.jpg', 'Jennifer Lawrence, Robert De Niro, Bradley Cooper, Edgar Ramírez, Diane Ladd, Virginia Madsen', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (140956, 'Ready Player One', 'Action,Sci-Fi,Thriller', NULL, 'Steven Spielberg', 'When the creator of a virtual reality called the OASIS dies, he makes a posthumous challenge to all OASIS users to find his Easter Egg, which will give the finder his fortune and control of his world.', 'https://m.media-amazon.com/images/M/MV5BNzVkMTgzODQtMWIwZC00NzE4LTgzZjYtMzAwM2I5OGZhNjE4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tye Sheridan, Olivia Cooke, Ben Mendelsohn, Lena Waithe, T.J. Miller, Simon Pegg', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (141038, 'Get a Clue', 'Children,Comedy,Mystery', 2002, 'Maggie Greenwald', 'A wealthy student with too much fashion sense, her equally rich friends, and her rival/superior from the school paper work together to solve the case when their teacher goes missing.', 'https://m.media-amazon.com/images/M/MV5BZmExMzI4YWEtNDEyNC00MDY4LWIxMjQtOTAzNGIxYmIyNGNkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Lindsay Lohan, Bug Hall, Ian Gomez, Brenda Song, Al Mukadam, Dan Lett', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (141098, 'Being Evel', 'Documentary', 2015, 'Daniel Junge', 'The real story behind the myth of American icon Robert \'Evel\' Knievel and his legacy.', 'https://m.media-amazon.com/images/M/MV5BMTg2NzQ1MjUwNl5BMl5BanBnXkFtZTgwNDQwMjc5NTE@._V1_FMjpg_UX1000_.jpg', 'Ken Berg, Seth Enslow, Ray Gunn, George Hamilton, Mat Hoffman, Evel Knievel', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (141544, 'Turbo Kid', 'Action,Adventure,Sci-Fi', 2015, 'François Simard', 'In a post-apocalyptic wasteland in 1997, a comic book fan adopts the persona of his favourite hero to save his enthusiastic friend and fight a tyrannical overlord.', 'https://m.media-amazon.com/images/M/MV5BMTY1NjkwNDQ0NF5BMl5BanBnXkFtZTgwMTkyOTE2NjE@._V1_FMjpg_UX1000_.jpg', 'Munro Chambers, Laurence Leboeuf, Michael Ironside, Edwin Wright, Aaron Jeffery, Romano Orzari', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (141688, 'Legend', 'Crime,Thriller', 2015, 'Brian Helgeland', 'Identical twin gangsters Ronald and Reginald Kray terrorize London during the 1960s.', 'https://m.media-amazon.com/images/M/MV5BMjE0MjkyODQ3NF5BMl5BanBnXkFtZTgwNDM1OTk1NjE@._V1_FMjpg_UX1000_.jpg', 'Paul Anderson, Tom Hardy, Christopher Eccleston, Joshua Hill, Emily Browning, Colin Morgan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (141749, 'The Danish Girl', 'Drama', 2015, 'Tom Hooper', 'A love story loosely inspired by the lives of Danish artists Lili Elbe and Gerda Wegener. Lili and Gerda\'s marriage and work evolve as they navigate Lili\'s groundbreaking journey as a transgender pioneer.', 'https://m.media-amazon.com/images/M/MV5BMjA0NjA4NjE2Nl5BMl5BanBnXkFtZTgwNzIxNTY2NjE@._V1_FMjpg_UX1000_.jpg', 'Alicia Vikander, Eddie Redmayne, Tusse Silberg, Adrian Schiller, Amber Heard, Emerald Fennell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (141866, 'Green Room', '(no genres listed)', 2015, 'Jeremy Saulnier', 'A punk rock band is forced to fight for survival after witnessing a murder at a neo-Nazi skinhead bar.', 'https://m.media-amazon.com/images/M/MV5BMjU1ODQ5NzA0N15BMl5BanBnXkFtZTgwMDg5MTA5NzE@._V1_FMjpg_UX1000_.jpg', 'Anton Yelchin, Joe Cole, Alia Shawkat, Callum Turner, David Thompson, Mark Webber', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (141890, 'Beasts of No Nation', 'Drama,War', 2015, 'Cary Joji Fukunaga', 'A drama based on the experiences of Agu, a child soldier fighting in the civil war of an unnamed African country.', 'https://m.media-amazon.com/images/M/MV5BMTYwMzMzMDI0NF5BMl5BanBnXkFtZTgwNDQ3NjI3NjE@._V1_FMjpg_UX1000_.jpg', 'Abraham Attah, Emmanuel Affadzi, Ricky Adelayitar, Andrew Adote, Vera Nyarkoah Antwi, Ama K. Abebrese', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (142448, 'Everest', 'Adventure,Drama,Thriller', 2015, 'Baltasar Kormákur', 'On May 10, 1996, mountain guides Rob Hall and Scott Fischer combine their expedition teams for a final ascent to the summit of Mount Everest. With little warning, a storm strikes the mountain and the climbers must now battle to survive.', 'https://m.media-amazon.com/images/M/MV5BNDAzOTYxMTctY2ViNi00NDI3LTgwMGItY2FhN2JjZWE5MjRkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jason Clarke, Ang Phula Sherpa, Thomas M. Wright, Martin Henderson, Tom Goodman-Hill, Charlotte Bøving', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (142488, 'Spotlight', 'Thriller', 2015, 'Tom McCarthy', 'The true story of how the Boston Globe uncovered the massive scandal of child molestation and cover-up within the local Catholic Archdiocese, shaking the entire Catholic Church to its core.', 'https://m.media-amazon.com/images/M/MV5BMjIyOTM5OTIzNV5BMl5BanBnXkFtZTgwMDkzODE2NjE@._V1_FMjpg_UX1000_.jpg', 'Mark Ruffalo, Michael Keaton, Rachel McAdams, Liev Schreiber, John Slattery, Brian d\'Arcy James', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (142509, 'Hardcore Henry', 'Action,Adventure,Sci-Fi', 2015, 'Ilya Naishuller', 'Henry is resurrected from death with no memory, and he must save his wife from a telekinetic warlord with a plan to bio-engineer soldiers.', 'https://m.media-amazon.com/images/M/MV5BNjIzNTcwMDc3Nl5BMl5BanBnXkFtZTgwNzU5NTY5NzE@._V1_FMjpg_UX1000_.jpg', 'Sharlto Copley, Danila Kozlovsky, Haley Bennett, Tim Roth, Andrei Dementiev, Svetlana Ustinova', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (143345, 'Shazam!', 'Action,Adventure,Fantasy,Sci-Fi', 2019, 'David F. Sandberg', 'A newly fostered young boy in search of his mother instead finds unexpected super powers and soon gains a powerful enemy.', 'https://m.media-amazon.com/images/M/MV5BZWM1YjdmOGQtNGYyMC00NjMwLTk1OWUtMGYzM2NjYjliYzYyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Zachary Levi, Mark Strong, Asher Angel, Jack Dylan Grazer, Adam Brody, Djimon Hounsou', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (143355, 'Wonder Woman', 'Action,Adventure,Fantasy', 2017, 'Patty Jenkins', 'When a pilot crashes and tells of conflict in the outside world, Diana, an Amazonian warrior in training, leaves home to fight a war, discovering her full powers and true destiny.', 'https://m.media-amazon.com/images/M/MV5BMjEzYmZkNjktODBmYi00NzNkLWIzMjItMjhkMWZiZTZlN2MwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gal Gadot, Chris Pine, Connie Nielsen, Robin Wright, Danny Huston, David Thewlis', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (143365, 'The Circle', 'Drama,Sci-Fi,Thriller', 2016, 'James Ponsoldt', 'A woman lands a dream job at a powerful tech company called the Circle, only to uncover an agenda that will affect the lives of all of humanity.', 'https://m.media-amazon.com/images/M/MV5BMjY2OTM2Njc3Ml5BMl5BanBnXkFtZTgwNDgzODU3MTI@._V1_FMjpg_UX1000_.jpg', 'Emma Watson, Ellar Coltrane, Glenne Headly, Bill Paxton, Karen Gillan, Tom Hanks', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (143367, 'Silence', 'Drama,Thriller', 2016, 'Martin Scorsese', 'In the 17th century, two Portuguese Jesuit priests travel to Japan in an attempt to locate their mentor, who is rumored to have committed apostasy, and to propagate Catholicism.', 'https://m.media-amazon.com/images/M/MV5BMjY3OTk0NjA2NV5BMl5BanBnXkFtZTgwNTg3Mjc2MDI@._V1_FMjpg_UX1000_.jpg', 'Andrew Garfield, Adam Driver, Liam Neeson, Tadanobu Asano, Ciarán Hinds, Issei Ogata', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (143385, 'Bridge of Spies', 'Drama,Thriller', 2015, 'Steven Spielberg', 'During the Cold War, an American lawyer is recruited to defend an arrested Soviet spy in court, and then help the CIA facilitate an exchange of the spy for the Soviet captured American U2 spy plane pilot, Francis Gary Powers.', 'https://m.media-amazon.com/images/M/MV5BMjIxOTI0MjU5NV5BMl5BanBnXkFtZTgwNzM4OTk4NTE@._V1_FMjpg_UX1000_.jpg', 'Mark Rylance, Domenick Lombardozzi, Victor Verhaeghe, Mark Fichera, Brian Hutchison, Tom Hanks', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (143657, 'The Invitation', 'Horror,Thriller', 2015, 'Karyn Kusama', 'When a man accepts an invitation to a dinner party hosted by his ex-wife, the unsettling past reopens old wounds and creates new tensions.', 'https://m.media-amazon.com/images/M/MV5BMTkzODMwNDkzOF5BMl5BanBnXkFtZTgwNDA4NzA1ODE@._V1_FMjpg_UX1000_.jpg', 'Logan Marshall-Green, Tammy Blanchard, Emayatzy Corinealdi, Aiden Lovekamp, Michelle Krusiec, Mike Doyle', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (143859, 'Hail, Caesar!', 'Comedy', 2016, 'Ethan Coen', 'A Hollywood fixer in the 1950s works to keep the studio\'s stars in line.', 'https://m.media-amazon.com/images/M/MV5BYmE1NDE2ODUtZmVmNi00OTM3LWFkOTItZDE2NGUwMTM0YjIyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Josh Brolin, George Clooney, Alden Ehrenreich, Ralph Fiennes, Scarlett Johansson, Tilda Swinton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (144482, 'Circle', 'Drama,Horror,Sci-Fi', 2015, 'Aaron Hann', 'Held captive and faced with their imminent executions, fifty strangers are forced to choose the one person among them who deserves to live.', 'https://m.media-amazon.com/images/M/MV5BMTg0Mjg0MjUwOF5BMl5BanBnXkFtZTgwNjk0NzQ4NzE@._V1_FMjpg_UX1000_.jpg', 'Allegra Masters, Aimee McKay, Ashley Key, Autumn Federici, Bill Lewis, Brent Stiefel', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (146279, 'Do I Sound Gay?', 'Documentary', 2015, 'David Thorpe', 'A documentary about the stereotype of the gay voice.', 'https://m.media-amazon.com/images/M/MV5BNDQ2MzAzNzYzMV5BMl5BanBnXkFtZTgwODc3OTU5NTE@._V1_FMjpg_UX1000_.jpg', 'Michael Airington, Richard Barrios, Margaret Cho, Becky Collins, Bob Corff, Tim Gunn', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (146656, 'Creed', 'Drama', 2015, 'Ryan Coogler', 'The former World Heavyweight Champion Rocky Balboa serves as a trainer and mentor to Adonis Johnson, the son of his late friend and former rival Apollo Creed.', 'https://m.media-amazon.com/images/M/MV5BNWM3NjY2ZDctMGZiYy00OGFlLThkMTktOTY2MDM2YjE2OTliXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael B. Jordan, Sylvester Stallone, Tessa Thompson, Phylicia Rashad, Andre Ward, Tony Bellew', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (147726, 'Criminal Activities', 'Crime,Drama,Thriller', 2015, 'Jackie Earle Haley', 'Four young men make a risky investment together that puts them in trouble with the mob.', 'https://m.media-amazon.com/images/M/MV5BMzkyNjk4MDY0MV5BMl5BanBnXkFtZTgwNDI5MTQxNzE@._V1_FMjpg_UX1000_.jpg', 'Michael Pitt, Dan Stevens, Christopher Abbott, Rob Brown, Edi Gathegi, Jackie Earle Haley', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (148626, 'Big Short, The', 'Drama', 2015, 'Adam McKay', 'In 2006-2007 a group of investors bet against the United States mortgage market. In their research, they discover how flawed and corrupt the market is.', 'https://m.media-amazon.com/images/M/MV5BZDZkNDQ3YjktYjBlZC00YTY1LTgxOGYtY2RhMWFhZmNkZGY3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ryan Gosling, Rudy Eisenzopf, Casey Groves, Charlie Talbert, Harold Gervais, Maria Frangos', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (148667, 'John Mulaney: The Comeback Kid', 'Comedy', 2015, 'Rhys Thomas', 'Armed with boyish charm and a sharp wit, the former SNL writer offers sly takes on marriage, his beef with babies and the time he met Bill Clinton.', 'https://m.media-amazon.com/images/M/MV5BMzA3NjgyNDMtMTFkMS00Zjg4LWI0N2UtZGU2ODE4OTA0M2YyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Petunia, John Mulaney, Amanda Walsh', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (148671, 'Saw', 'Crime,Horror', 2003, 'James Wan', 'David, an orderly at a hospital, tells his horrific story of being kidnapped and forced to play a vile game of survival.', 'https://m.media-amazon.com/images/M/MV5BMzA5MDQwYWEtYjIxYy00YTYzLWI0NzAtNzRjNGU2OTg5MzgwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leigh Whannell, Paul Moder, Katrina Mathers, Dean Francis', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (149334, 'Nocturnal Animals', 'Drama,Thriller', NULL, 'Tom Ford', 'A wealthy art gallery owner is haunted by her ex-husband\'s novel, her memories of their relationship, and her regrets about her life.', 'https://m.media-amazon.com/images/M/MV5BMTYwMzMwMzgxNl5BMl5BanBnXkFtZTgwMTA0MTUzMDI@._V1_FMjpg_UX1000_.jpg', 'Amy Adams, Jake Gyllenhaal, Michael Shannon, Aaron Taylor-Johnson, Isla Fisher, Ellie Bamber', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (149352, 'Daddy\'s Home', 'Comedy', 2015, 'Sean Anders', 'Brad Whitaker is a radio host trying to get his stepchildren to love him and call him Dad. But his plans turn upside down when their biological father, Dusty Mayron, returns.', 'https://m.media-amazon.com/images/M/MV5BMTQ0OTE1MTk4N15BMl5BanBnXkFtZTgwMDM5OTk5NjE@._V1_FMjpg_UX1000_.jpg', 'Will Ferrell, Mark Wahlberg, Linda Cardellini, Thomas Haden Church, Scarlett Estevez, Owen Vaccaro', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (150324, 'The Cheetah Girls: One World', 'Children,Comedy,Drama', 2008, 'Paul Hoen', 'The girl group travel to India to star in a Bollywood movie - but end up competing for the same part.', 'https://m.media-amazon.com/images/M/MV5BZDM4YzliOTYtYWMzYy00Y2FjLTk3MDEtZDU0ODFlZjg4MjBjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Adrienne Houghton, Sabrina Bryan, Kiely Williams, Roshan Seth, Michael Steger, Kunal Sharma', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (151639, 'The Boy', 'Horror,Thriller', 2016, 'William Brent Bell', 'An American nanny is shocked that her new English family\'s boy is actually a life-sized doll. After she violates a list of strict rules, disturbing events make her believe that the doll is really alive.', 'https://m.media-amazon.com/images/M/MV5BMTc1MjcxNzcwMV5BMl5BanBnXkFtZTgwMTE0NTE2NzE@._V1_FMjpg_UX1000_.jpg', 'Lauren Cohan, Rupert Evans, James Russell, Jim Norton, Diana Hardcastle, Ben Robson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (152077, '10 Cloverfield Lane', 'Thriller', 2016, 'Dan Trachtenberg', 'A young woman is held in an underground bunker by a man who insists that a hostile event has left the surface of the Earth uninhabitable.', 'https://m.media-amazon.com/images/M/MV5BMjEzMjczOTIxMV5BMl5BanBnXkFtZTgwOTUwMjI3NzE@._V1_FMjpg_UX1000_.jpg', 'John Goodman, Mary Elizabeth Winstead, John Gallagher Jr., Douglas M. Griffin, Suzanne Cryer, Bradley Cooper', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (152079, 'London Has Fallen', 'Action,Crime,Thriller', 2016, 'Babak Najafi', 'Whilst in London, England for the British Prime Minister\'s funeral, Mike Banning is caught up in a terrorist plot to assassinate all the attending world leaders in one strike.', 'https://m.media-amazon.com/images/M/MV5BMTY1ODY2MTgwM15BMl5BanBnXkFtZTgwOTY3Nzc3NzE@._V1_FMjpg_UX1000_.jpg', 'Alon Aboutboul, Waleed Zuaiter, Adel Bencherif, Mehdi Dehbi, Shivaani Ghai, Martin Petrushev', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (152081, 'Zootopia', 'Action,Adventure,Animation,Children,Comedy', 2016, 'Jared Bush', 'In a city of anthropomorphic animals, a rookie bunny cop and a cynical con artist fox must work together to uncover a conspiracy.', 'https://m.media-amazon.com/images/M/MV5BOTMyMjEyNzIzMV5BMl5BanBnXkFtZTgwNzIyNjU0NzE@._V1_FMjpg_UX1000_.jpg', 'Ginnifer Goodwin, Jason Bateman, Idris Elba, Jenny Slate, Nate Torrence, Bonnie Hunt', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (152362, 'Saathiya', 'Drama,Romance', 2002, 'Shaad Ali', 'A couple elopes to get married and set up home hoping that just love will do the trick - but that\'s just the beginning of their story.', 'https://m.media-amazon.com/images/M/MV5BMGZlOTQwMDAtMWFiMS00MDYzLTg0YTYtOGY2Y2I3ZDc4OTE3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Vivek Oberoi, Rani Mukerji, Shah Rukh Khan, Tabu, Sandhya Mridul, Tanuja Samarth', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (155968, 'The Night Manager', 'Crime,Drama,Mystery,Thriller', 2016, 'David Farr', 'The night manager of a Cairo hotel is recruited to infiltrate an arms dealer\'s inner circle.', 'https://m.media-amazon.com/images/M/MV5BMTk1NzkyMTUyN15BMl5BanBnXkFtZTgwNTM0NzM2ODE@._V1_FMjpg_UX1000_.jpg', 'Tom Hiddleston, Olivia Colman, Alistair Petrie, Michael Nardone, Hugh Laurie, Elizabeth Debicki', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (156387, 'Sing Street', 'Drama', 2016, 'John Carney', 'A young lad notices a beautiful girl who begins to occupy his thoughts. While struggling with poverty, personal relationships and life\'s woes, he starts a band, hoping to catch her attention.', 'https://m.media-amazon.com/images/M/MV5BMjEzODA3MDcxMl5BMl5BanBnXkFtZTgwODgxNDk3NzE@._V1_FMjpg_UX1000_.jpg', 'Ferdia Walsh-Peelo, Kelly Thornton, Maria Doyle Kennedy, Jack Reynor, Aidan Gillen, Ian Kenny', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (156605, 'Paterson', '(no genres listed)', NULL, 'Jim Jarmusch', 'A quiet observation of the triumphs and defeats of daily life, along with the poetry evident in its smallest details.', 'https://m.media-amazon.com/images/M/MV5BMTUzODA4Nzk0OF5BMl5BanBnXkFtZTgwNzE1MDIwMDI@._V1_FMjpg_UX1000_.jpg', 'Adam Driver, Golshifteh Farahani, Nellie, Rizwan Manji, Dominic Liriano, Jaden Michael', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (156726, 'Hush', 'Thriller', 2016, 'Mike Flanagan', 'A deaf and mute writer who retreated into the woods to live a solitary life must fight for her life in silence when a masked killer appears at her window.', 'https://m.media-amazon.com/images/M/MV5BZjQ0YTU4OTQtMTU3Zi00OTdlLTkzN2EtZjlmOTZhNjIwN2VkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Gallagher Jr., Kate Siegel, Michael Trucco, Samantha Sloyan, Emma Graves', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (157276, 'Our Kind of Traitor', 'Drama,Thriller', 2016, 'Susanna White', 'A couple finds themselves lured into a Russian oligarch\'s plans to defect, and are soon positioned between the Russian Mafia and the British Secret Service, neither of whom they can trust.', 'https://m.media-amazon.com/images/M/MV5BMjM2MjY2ODgxMF5BMl5BanBnXkFtZTgwNzYxNjc2ODE@._V1_FMjpg_UX1000_.jpg', 'Carlos Acosta, Radivoje Bukvic, Stellan Skarsgård, Mariya Fomina, Dolya Gavanski, Grigory Dobrygin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (157296, 'Finding Dory', 'Adventure,Animation,Comedy', 2016, 'Angus MacLane', 'Friendly but forgetful blue tang Dory begins a search for her long-lost parents and everyone learns a few things about the real meaning of family along the way.', 'https://m.media-amazon.com/images/M/MV5BY2VlYWJjMGMtYjcwZC00MDE2LThmMDItYjVlMzNhYzBhYTk5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ellen DeGeneres, Albert Brooks, Ed O\'Neill, Kaitlin Olson, Hayden Rolence, Ty Burrell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (157699, 'Snowden', 'Drama,Thriller', 2016, 'Oliver Stone', 'The NSA\'s illegal surveillance techniques are leaked to the public by one of the agency\'s employees, Edward Snowden, in the form of thousands of classified documents distributed to the press.', 'https://m.media-amazon.com/images/M/MV5BMTg2MzYzNzgzOF5BMl5BanBnXkFtZTgwOTg4NzQ4OTE@._V1_FMjpg_UX1000_.jpg', 'Melissa Leo, Zachary Quinto, Joseph Gordon-Levitt, Jaymes Butler, Robert Firth, Rachel Handshaw', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (158238, 'The Nice Guys', 'Crime,Mystery,Thriller', 2016, 'Shane Black', 'In 1970s Los Angeles, a mismatched pair of private eyes investigate a missing girl and the mysterious death of a porn star.', 'https://m.media-amazon.com/images/M/MV5BM2YwNWZlZGEtYTEyZi00NjdjLWEwM2ItM2Q2MDMwZjkzMjk0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Russell Crowe, Ryan Gosling, Angourie Rice, Matt Bomer, Margaret Qualley, Yaya DaCosta', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (158414, 'East Side Sushi', 'Drama', 2014, 'Anthony Lucero', 'An immigrant single mother discontented by her regular life decides to take a chance working at a Japanese restaurant and realize her dream to become a sushi chef and provide a better future to her family.', 'https://m.media-amazon.com/images/M/MV5BMjM1Nzc1MTM4MV5BMl5BanBnXkFtZTgwMjU0MTc2NjE@._V1_FMjpg_UX1000_.jpg', 'Diana Elizabeth Torres, Yutaka Takeuchi, Rodrigo Duarte Clark, Kaya Jade Aguirre, Roji Oyama, Miyoko Sakatani', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (158813, 'Alice Through the Looking Glass', 'Adventure,Children,Fantasy', 2016, 'James Bobin', 'Alice is appointed to save her beloved Mad Hatter from deadly grief by travelling back to the past, but this means fatally harming Time himself, the noble clockwork man with the device needed to save the Hatter\'s family from the Red Queen.', 'https://m.media-amazon.com/images/M/MV5BMTc2NjExMTIyN15BMl5BanBnXkFtZTgwMjg0OTIwODE@._V1_FMjpg_UX1000_.jpg', 'Johnny Depp, Mia Wasikowska, Helena Bonham Carter, Anne Hathaway, Sacha Baron Cohen, Rhys Ifans', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (158972, 'Toni Erdmann', 'Drama', 2016, 'Maren Ade', 'A practical joking father tries to reconnect with his hard working daughter by creating an outrageous alter ego and posing as her CEO\'s life coach.', 'https://m.media-amazon.com/images/M/MV5BODNiNmE5OWMtNDAxMy00YTQzLThjMGItMTAwOTNlNGM2ZDlhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sandra Hüller, Peter Simonischek, Michael Wittenborn, Thomas Loibl, Trystan Pütter, Ingrid Bisu', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (159721, 'Brexit: The Movie', 'Documentary', 2016, 'Martin Durkin', 'A documentary exploring Britain\'s relationship with the EU and possibility of Britain\'s exit from the European Union', 'https://m.media-amazon.com/images/M/MV5BMTU4M2E5MmMtNDU1Mi00NGFjLWI5YTktMDYxMDk5NmEzMTg4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Martin Durkin, James Delingpole, Simon Heffer, Mark Littlewood, Matt Ridley, Kelvin Mackenzie', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (159817, 'Planet Earth', 'Documentary', 2006, 'Sigourney Weaver', 'A documentary series on the wildlife found on Earth. Each episode covers a different habitat: deserts, mountains, deep oceans, shallow seas, forests, caves, polar regions, fresh water, plains and jungles. Narrated by David Attenborough.', 'https://m.media-amazon.com/images/M/MV5BY2NjNDUzOTgtMDFmNC00ZGQ4LWE5MDctMzczNGVlOGU1N2MyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sigourney Weaver, David Attenborough, Nikolay Drozdov, Thomas Anguti Johnston, Sanae Ueda, Huw Cordey', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (160438, 'Jason Bourne', 'Action', 2016, 'Paul Greengrass', 'The CIA\'s most dangerous former operative is drawn out of hiding to uncover more explosive truths about his past.', 'https://m.media-amazon.com/images/M/MV5BMzY3Y2Q3MmUtZmU3MC00OWMxLWIwNDMtNDA4MmViMTUxYjYxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matt Damon, Tommy Lee Jones, Alicia Vikander, Vincent Cassel, Julia Stiles, Riz Ahmed', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (160718, 'Piper', 'Animation', 2016, 'Alan Barillaro', 'A hungry sandpiper hatchling ventures from her nest for the first time to dig for food by the shoreline. The problem is, the food is buried in the sand where scary waves roll up.', 'https://m.media-amazon.com/images/M/MV5BNDU1ZTYwNmYtNjM1Zi00NTlkLWI5ZmQtNjM2OWM0ZTMxYTFlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', NULL, '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (160726, 'Fastball', 'Documentary', 2016, 'Jonathan Hock', 'With Kevin Costner narrating, lead a cast of baseball legends and scientists who explore the magic within the 396 milliseconds it takes a fastball to reach home plate, and decipher who threw the fastest pitch ever.', 'https://m.media-amazon.com/images/M/MV5BNzcyMzUzODk2M15BMl5BanBnXkFtZTgwNzAxNzYwODE@._V1_FMjpg_UX1000_.jpg', 'Kevin Costner, Derek Jeter, Denard Span, Craig Kimbrel, Nolan Ryan, Justin Verlander', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (160980, 'Sully', 'Drama', 2016, 'Clint Eastwood', 'When pilot Chesley \"Sully\" Sullenberger lands his damaged plane on the Hudson River in order to save the flight\'s passengers and crew, some consider him a hero while others think he was reckless.', 'https://m.media-amazon.com/images/M/MV5BYzM5ODA5MDItZGM4MS00YmQ3LTkxMDUtMDY2NjcyM2RmYzlkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Aaron Eckhart, Valerie Mahaffey, Delphi Harrington, Mike O\'Malley, Jamey Sheridan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (161127, 'The Infiltrator', 'Crime,Drama', 2016, 'Brad Furman', 'A U.S. Customs official uncovers a money laundering scheme involving Colombian drug lord Pablo Escobar.', 'https://m.media-amazon.com/images/M/MV5BMTEwNzM2NjY2MTNeQTJeQWpwZ15BbWU4MDQ3MDI3Njgx._V1_FMjpg_UX1000_.jpg', 'Bryan Cranston, Leanne Best, Daniel Mays, Tom Vaughan-Lawlor, Niall Hayes, Lara Decaro', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (161131, 'War Dogs', 'Comedy', 2016, 'Todd Phillips', 'Loosely based on the true story of two young men, David Packouz and Efraim Diveroli, who won a three hundred million dollar contract from the Pentagon to arm America\'s allies in Afghanistan.', 'https://m.media-amazon.com/images/M/MV5BMjEyNzQ0NzM4MV5BMl5BanBnXkFtZTgwMDI0ODM2OTE@._V1_FMjpg_UX1000_.jpg', 'Miles Teller, Steve Lantz, Gregg Weiner, David Packouz, Eddie Jemison, Julian Sergi', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (161582, 'Hell or High Water', 'Crime,Drama', 2016, 'David Mackenzie', 'Toby is a divorced father who\'s trying to make a better life. His brother is an ex-con with a short temper and a loose trigger finger. Together, they plan a series of heists against the bank that\'s about to foreclose on their family ranch.', 'https://m.media-amazon.com/images/M/MV5BMTg4NDA1OTA5NF5BMl5BanBnXkFtZTgwMDQ2MDM5ODE@._V1_FMjpg_UX1000_.jpg', 'Dale Dickey, Ben Foster, Chris Pine, William Sterchi, Buck Taylor, Kristin K. Berg', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (161634, 'Don\'t Breathe', 'Thriller', 2016, 'Fede Alvarez', 'Three delinquents break into the house of a war veteran who is blind to steal his money. However, they discover that the man is not as defenseless as he seems.', 'https://m.media-amazon.com/images/M/MV5BNjAxOTJkMmEtNjg4MC00ODk3LTkwYmUtNjM3YzE5YTk1YTFjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Stephen Lang, Jane Levy, Dylan Minnette, Daniel Zovatto, Emma Bercovici, Franciska Töröcsik', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (162082, 'Train to Busan', 'Action,Thriller', 2016, 'Yeon Sang-ho', 'While a zombie virus breaks out in South Korea, passengers struggle to survive on the train from Seoul to Busan.', 'https://m.media-amazon.com/images/M/MV5BMTkwOTQ4OTg0OV5BMl5BanBnXkFtZTgwMzQyOTM0OTE@._V1_FMjpg_UX1000_.jpg', 'Gong Yoo, Jung Yu-mi, Ma Dong-seok, Kim Su-an, Kim Eui-sung, Choi Woo-sik', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (162414, 'Moonlight', 'Drama', NULL, 'Barry Jenkins', 'A young African-American man grapples with his identity and sexuality while experiencing the everyday struggles of childhood, adolescence, and burgeoning adulthood.', 'https://m.media-amazon.com/images/M/MV5BNzQxNTIyODAxMV5BMl5BanBnXkFtZTgwNzQyMDA3OTE@._V1_FMjpg_UX1000_.jpg', 'Mahershala Ali, Shariff Earp, Duan Sanderson, Alex R. Hibbert, Janelle Monáe, Naomie Harris', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (162578, 'Kubo and the Two Strings', 'Adventure,Animation,Children,Fantasy', 2016, 'Travis Knight', 'A young boy named Kubo must locate a magical suit of armour worn by his late father in order to defeat a vengeful spirit from the past.', 'https://m.media-amazon.com/images/M/MV5BMjA2Mzg2NDMzNl5BMl5BanBnXkFtZTgwMjcwODUzOTE@._V1_FMjpg_UX1000_.jpg', 'Art Parkinson, Charlize Theron, Brenda Vaccaro, Cary-Hiroyuki Tagawa, Meyrick Murphy, George Takei', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (162590, 'Bridget Jones\'s Baby', 'Comedy,Romance', 2016, 'Sharon Maguire', 'Bridget Jones\' focus on her single and professional life is interrupted when she discovers she is pregnant, but is unsure of the identity of the father.', 'https://m.media-amazon.com/images/M/MV5BMWViMmNmNmEtYTg5Mi00Y2IwLTg4NzgtNzg2ZjNjY2RmYWZlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Renée Zellweger, Gemma Jones, Jim Broadbent, Sally Phillips, Julian Rhind-Tutt, Shirley Henderson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (162598, 'Deepwater Horizon', 'Drama', 2016, 'Peter Berg', 'A dramatization of the disaster in April 2010, when the offshore drilling rig called the Deepwater Horizon exploded, resulting in the worst oil spill in history.', 'https://m.media-amazon.com/images/M/MV5BOTEzNDU0OTgxM15BMl5BanBnXkFtZTgwNjA0ODM2OTE@._V1_FMjpg_UX1000_.jpg', 'Mark Wahlberg, Kurt Russell, Douglas M. Griffin, James DuMont, Joe Chrest, Gina Rodriguez', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (162600, 'Miss Peregrine\'s Home for Peculiar Children', 'Fantasy', 2016, 'Tim Burton', 'When Jacob discovers clues to a mystery that stretches across time, he finds Miss Peregrine\'s Home for Peculiar Children. But the danger deepens after he gets to know the residents and learns about their special powers.', 'https://m.media-amazon.com/images/M/MV5BMTU0Nzc5NzI5NV5BMl5BanBnXkFtZTgwNTk1MDE4MDI@._V1_FMjpg_UX1000_.jpg', 'Eva Green, Asa Butterfield, Samuel L. Jackson, Judi Dench, Rupert Everett, Allison Janney', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (162602, 'The Girl on the Train', 'Thriller', 2016, 'Tate Taylor', 'A divorcee becomes entangled in a missing persons investigation that promises to send shockwaves throughout her life.', 'https://m.media-amazon.com/images/M/MV5BZTg4MGViYTMtYTFkMC00YzVlLWExZDItOTM4NTUwMjc2NTE2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Emily Blunt, Haley Bennett, Rebecca Ferguson, Justin Theroux, Luke Evans, Edgar Ramírez', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (162606, 'The Accountant', 'Crime,Drama,Thriller', 2016, 'Gavin O\'Connor', 'As a math savant uncooks the books for a new client, the treasury department closes in on his activities and the body count starts to rise.', 'https://m.media-amazon.com/images/M/MV5BNDc5Mzg2NTYxNV5BMl5BanBnXkFtZTgwMjQ2ODAwOTE@._V1_FMjpg_UX1000_.jpg', 'Ben Affleck, Anna Kendrick, J.K. Simmons, Jon Bernthal, Jeffrey Tambor, Cynthia Addai-Robinson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (162990, 'PSYCHO-PASS: The Movie', 'Action,Animation,Sci-Fi', 2016, 'Katsuyuki Motohiro', 'In this sequel to Psycho-Pass TV show, Inspector Tsunemori is sent to a neighboring war-torn nation, where the Sibyl System is being introduced as an experiment, to find Shinya Kogami, her former enforcer who went rogue three years ago.', 'https://m.media-amazon.com/images/M/MV5BYTFiNzY3MDktYjkyMi00Y2U4LWIyNzgtM2Y3OWI1OGVlYzQwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bryn Apprill, Major Attaway, Z. Charles Bolton, Cole Brown, Bob Carter, Leah Clark', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (163134, 'Your Name.', 'Animation,Drama,Fantasy,Romance', 2016, 'Makoto Shinkai', 'Two teenagers share a profound, magical connection upon discovering they are swapping bodies. Things manage to become even more complicated when the boy and girl decide to meet in person.', 'https://m.media-amazon.com/images/M/MV5BMjI1ODZkYTgtYTY3Yy00ZTJkLWFkOTgtZDUyYWM4MzQwNjk0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ryûnosuke Kamiki, Mone Kamishiraishi, Ryo Narita, Aoi Yûki, Nobunaga Shimazaki, Kaito Ishikawa', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (163645, 'Hacksaw Ridge', 'Drama,War', 2016, 'Mel Gibson', 'World War II American Army Medic Desmond T. Doss, serving during the Battle of Okinawa, refuses to kill people and becomes the first man in American history to receive the Medal of Honor without firing a shot.', 'https://m.media-amazon.com/images/M/MV5BMjQ1NjM3MTUxNV5BMl5BanBnXkFtZTgwMDc5MTY5OTE@._V1_FMjpg_UX1000_.jpg', 'Andrew Garfield, Richard Pyros, Jacob Warner, Milo Gibson, Darcy Bryce, Roman Guerriero', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (164141, 'I.T.', 'Drama', 2016, 'John Moore', 'A millionaire has his life turned upside down after firing his I.T. consultant.', 'https://m.media-amazon.com/images/M/MV5BMTkzMzY3MzYzNF5BMl5BanBnXkFtZTgwNzgzMTA3OTE@._V1_FMjpg_UX1000_.jpg', 'Pierce Brosnan, Jason Barry, Karen Moskow, Kai Ryssdal, Brian F. Mulvey, Martin \'Mako\' Hindy', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (164175, 'A Monster Calls', 'Drama,Fantasy', 2016, 'J.A. Bayona', 'Conor, a twelve-year-old boy, encounters an ancient tree monster who proceeds to help him cope with his mother\'s terminal illness and being bullied in school.', 'https://m.media-amazon.com/images/M/MV5BMTg1OTA5OTkyNV5BMl5BanBnXkFtZTgwODMwNDU5OTE@._V1_FMjpg_UX1000_.jpg', 'Lewis MacDougall, Sigourney Weaver, Felicity Jones, Toby Kebbell, Ben Moor, James Melville', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (164179, 'Arrival', 'Sci-Fi', 2016, 'Denis Villeneuve', 'Linguist Louise Banks leads a team of investigators when gigantic spaceships touch down around the world. As nations teeter on the verge of global war, Banks and her crew must find a way to communicate with the extraterrestrial visitors.', 'https://m.media-amazon.com/images/M/MV5BMTExMzU0ODcxNDheQTJeQWpwZ15BbWU4MDE1OTI4MzAy._V1_FMjpg_UX1000_.jpg', 'Amy Adams, Jeremy Renner, Forest Whitaker, Michael Stuhlbarg, Mark O\'Brien, Tzi Ma', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (164411, 'My Life as a Courgette', 'Animation,Children,Drama', 2016, 'Claude Barras', 'After losing his mother, a young boy is sent to an orphanage with other orphans his age where he begins to learn the meaning of trust and true love.', 'https://m.media-amazon.com/images/M/MV5BZmMyMTBmZmMtZjNiNS00OTBiLThjZjUtNDQwZTE4MGVjYTFiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gaspard Schlatter, Sixtine Murat, Paulin Jaccoud, Michel Vuillermoz, Raul Ribera, Estelle Hennard', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (164909, 'La La Land', 'Comedy,Drama,Romance', 2016, 'Damien Chazelle', 'When Sebastian, a pianist, and Mia, an actress, follow their passion and achieve success in their respective fields, they find themselves torn between their love for each other and their careers.', 'https://m.media-amazon.com/images/M/MV5BMzUzNDM2NzM2MV5BMl5BanBnXkFtZTgwNTM3NTg4OTE@._V1_FMjpg_UX1000_.jpg', 'Ryan Gosling, Emma Stone, Amiee Conn, Terry Walters, Thom Shelton, Cinda Adams', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (164949, 'The Salesman', 'Drama', 2016, 'Asghar Farhadi', 'While Ranaa and Emad, a married couple, are participating in a production of \"Death of a Salesman,\" she is assaulted in their new home, which leaves him determined to find the perpetrator over his wife\'s traumatized objections.', 'https://m.media-amazon.com/images/M/MV5BMTg2MTc0ODEwOV5BMl5BanBnXkFtZTgwNDAyOTY1MDI@._V1_FMjpg_UX1000_.jpg', 'Shahab Hosseini, Taraneh Alidoosti, Babak Karimi, Farid Sajjadi Hosseini, Mina Sadati, Maral Baniadam', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (165549, 'Manchester by the Sea', 'Drama', 2016, 'Kenneth Lonergan', 'A depressed uncle is asked to take care of his teenage nephew after the boy\'s father dies.', 'https://m.media-amazon.com/images/M/MV5BMTYxMjk0NDg4Ml5BMl5BanBnXkFtZTgwODcyNjA5OTE@._V1_FMjpg_UX1000_.jpg', 'Casey Affleck, Ivy O\'Brien, Kyle Chandler, Richard Donelly, Virginia Loring Cooke, Quincy Tyler Bernstine', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (165551, 'Lion', 'Drama', 2016, 'Garth Davis', 'A five-year-old Indian boy is adopted by an Australian couple after getting lost hundreds of kilometers from home. 25 years later, he sets out to find his lost family.', 'https://m.media-amazon.com/images/M/MV5BMjA3NjkzNjg2MF5BMl5BanBnXkFtZTgwMDkyMzgzMDI@._V1_FMjpg_UX1000_.jpg', 'Sunny Pawar, Abhishek Bharate, Priyanka Bose, Khushi Solanki, Shankar Nisode, Tannishtha Chatterjee', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (165603, 'The Autopsy of Jane Doe', 'Horror', 2016, 'André Øvredal', 'Father and son coroners investigate the death of a beautiful Jane Doe.', 'https://m.media-amazon.com/images/M/MV5BMjA2MTEzMzkzM15BMl5BanBnXkFtZTgwMjM2MTM5MDI@._V1_FMjpg_UX1000_.jpg', 'Brian Cox, Emile Hirsch, Ophelia Lovibond, Michael McElhatton, Olwen Catherine Kelly, Jane Perry', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (165639, 'While You Were Fighting: A Thor Mockumentary', 'Comedy,Fantasy,Sci-Fi', 2016, 'Taika Waititi', 'The story of what the hammer-wielding Nordic god Thor was up to while the rest of the Avengers were battling each other in \"Captain America: Civil War\". He moves into a flat with office worker Darryl Jacobson in Australia.', 'https://m.media-amazon.com/images/M/MV5BNDZiNWVjZDMtOTNkOS00NzdiLTljMTEtOGM0NWExNGJjZjYzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chris Hemsworth, Mark Ruffalo, Daley Pearson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (165699, 'Angel Has Fallen', 'Action,Thriller', NULL, 'Ric Roman Waugh', 'Mike Banning is framed for the attempted assassination of the President, and now must evade his own agency, and the FBI, as he tries to uncover the real threat.', 'https://m.media-amazon.com/images/M/MV5BZmY4YTJlZjktNmVkYi00MzBjLTg3MTAtMGZiNWUwY2NiMmM5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gerard Butler, Frederick Schmidt, Danny Huston, Rocci Boy Williams, Piper Perabo, Harry Ditson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (166024, 'Whiplash', '(no genres listed)', 2013, 'Damien Chazelle', 'A ferocious, bullying music teacher teaches a dedicated student.', 'https://m.media-amazon.com/images/M/MV5BZjVkZDJjM2EtNjgzOC00ODRiLTllZWEtYWYyZjE5MTJlY2NiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Johnny Simmons, Nate Lang, J.K. Simmons, C.J. Vana, Honora Javier, Omari Grayson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (166461, 'Moana', 'Adventure,Animation,Children,Comedy,Fantasy', 2016, 'Ron Clements', 'In ancient Polynesia, when a terrible curse incurred by the demigod Maui reaches Moana\'s island, she answers the Ocean\'s call to seek out Maui to set things right.', 'https://m.media-amazon.com/images/M/MV5BMjI4MzU5NTExNF5BMl5BanBnXkFtZTgwNzY1MTEwMDI@._V1_FMjpg_UX1000_.jpg', 'Auli\'i Cravalho, Dwayne Johnson, Rachel House, Temuera Morrison, Jemaine Clement, Nicole Scherzinger', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (166528, 'Rogue One: A Star Wars Story', 'Action,Adventure,Fantasy,Sci-Fi', 2016, 'Gareth Edwards', 'In a time of conflict, a group of unlikely heroes band together on a mission to steal the plans to the Death Star, the Empire\'s ultimate weapon of destruction.', 'https://m.media-amazon.com/images/M/MV5BMjEwMzMxODIzOV5BMl5BanBnXkFtZTgwNzg3OTAzMDI@._V1_FMjpg_UX1000_.jpg', 'Felicity Jones, Diego Luna, Alan Tudyk, Donnie Yen, Wen Jiang, Ben Mendelsohn', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (166534, 'Split', 'Drama,Horror,Thriller', 2017, 'M. Night Shyamalan', 'Three girls are kidnapped by a man with a diagnosed 23 distinct personalities. They must try to escape before the apparent emergence of a frightful new 24th.', 'https://m.media-amazon.com/images/M/MV5BNTZjNmVjMzAtZjg2Mi00MWNmLTk5NTItOTExZDYwNTE2YmExXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'James McAvoy, Anya Taylor-Joy, Betty Buckley, Haley Lu Richardson, Jessica Sula, Izzie Coffey', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (166635, 'Passengers', 'Adventure,Drama,Romance,Sci-Fi', 2016, 'Morten Tyldum', 'A malfunction in a sleeping pod on a spacecraft traveling to a distant colony planet wakes one passenger 90 years early.', 'https://m.media-amazon.com/images/M/MV5BYzRjNTFmMzQtM2JhZi00ZTI0LTlhMjMtNzQ4YWRhZGVmZWRmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jennifer Lawrence, Chris Pratt, Michael Sheen, Laurence Fishburne, Andy Garcia, Vince Foster', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (166643, 'Hidden Figures', 'Drama', 2016, 'Theodore Melfi', 'Three female African-American mathematicians play a pivotal role in astronaut John Glenn\'s launch into orbit while dealing with racial and gender discrimination.', 'https://m.media-amazon.com/images/M/MV5BY2RhNDRhNzctZTllMy00NTc2LWJjZmUtMzg3MTNiNjhhODMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Taraji P. Henson, Octavia Spencer, Janelle Monáe, Kevin Costner, Kirsten Dunst, Jim Parsons', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (166721, 'Bleed for This', 'Drama', 2016, 'Ben Younger', 'The inspirational story of World Champion Boxer Vinny Pazienza who, after a near fatal car crash which left him not knowing if he\'d ever walk again, made one of sports\' most incredible comebacks.', 'https://m.media-amazon.com/images/M/MV5BMjAwNzgyNTUxMF5BMl5BanBnXkFtZTgwNzc0ODc1OTE@._V1_FMjpg_UX1000_.jpg', 'Miles Teller, Aaron Eckhart, Katey Sagal, Ciarán Hinds, Ted Levine, Jordan Gelber', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (166775, 'Uno: The Movie', 'Comedy', NULL, 'Geoff Ramsey', 'This is simply a YouTube video of kids playing an online game of YouTube. The entire movie is a screen recording of an online UNO match.', 'https://m.media-amazon.com/images/M/MV5BMTkxNzMxNTMtZjE4My00NmUyLWEwYmUtNTk3NjcxZTZhNTUxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Geoff Ramsey, Gavin Free, Ryan Haywood, Jeremy Dooley, Jack Pattillo, Jean-Luc Troesch', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (166788, '20th Century Women', 'Drama', 2016, 'Mike Mills', 'In 1979 Santa Barbara, Dorothea is a determined single mother who is raising her son, Jamie. Dorothea enlists the help of two women -- Abbie, a free-spirited punk artist and Julie, a savvy teenager -- to help with Jamie\'s upbringing.', 'https://m.media-amazon.com/images/M/MV5BMTkwNDE4NzQwM15BMl5BanBnXkFtZTgwNzQ5Nzg0MDI@._V1_FMjpg_UX1000_.jpg', 'Annette Bening, Elle Fanning, Greta Gerwig, Billy Crudup, Lucas Jade Zumann, Alison Elliott', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (166946, 'The Founder', 'Drama', 2016, 'John Lee Hancock', 'The story of Ray Kroc, a salesman who turned two brothers\' innovative fast food eatery, McDonald\'s, into the biggest restaurant business in the world, with a combination of ambition, persistence, and ruthlessness.', 'https://m.media-amazon.com/images/M/MV5BMzExNDg0MDk1M15BMl5BanBnXkFtZTgwNzE1Mjg0MDI@._V1_FMjpg_UX1000_.jpg', 'Michael Keaton, Nick Offerman, John Carroll Lynch, Linda Cardellini, B.J. Novak, Laura Dern', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (167038, 'Dear Zindagi', 'Drama,Romance', 2016, 'Gauri Shinde', 'Kaira is a budding cinematographer in search of a perfect life. Her encounter with Jug, an unconventional thinker, helps her gain a new perspective on life. She discovers that happiness is all about finding comfort in life\'s imperfections.', 'https://m.media-amazon.com/images/M/MV5BMGVhMjczOWYtNWYyOS00MTYwLTg3OWYtNmVjYWQ0OThlOThiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Alia Bhatt, Shah Rukh Khan, Kunal Kapoor, Ali Zafar, Bobby Duggal, Angad Bedi', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (167544, 'Patriots Day', 'Drama,Thriller', 2016, 'Peter Berg', 'The story of the 2013 Boston Marathon bombing and the aftermath, which includes the city-wide manhunt to find the terrorists responsible.', 'https://m.media-amazon.com/images/M/MV5BODYxMDc0NTg2Nl5BMl5BanBnXkFtZTgwNjY0NDYzOTE@._V1_FMjpg_UX1000_.jpg', 'Mark Wahlberg, Dicky Eklund Jr., Michael Marchand, Rhet Kidd, John Goodman, Frank Czarnowski', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (167570, 'The OA', '(no genres listed)', NULL, 'Brit Marling', 'Having gone missing seven years ago, the previously blind Prairie returns home, now in her twenties with her sight restored. While many believe she is a miracle, others worry that she could be dangerous.', 'https://m.media-amazon.com/images/M/MV5BMTY5OTkwNDkzOF5BMl5BanBnXkFtZTgwMDEyNzI1NzM@._V1_FMjpg_UX1000_.jpg', 'Brit Marling, Emory Cohen, Patrick Gibson, Jason Isaacs, Ian Alexander, Phyllis Smith', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (167746, 'The Lego Batman Movie', 'Action,Animation,Comedy', 2017, 'Chris McKay', 'A cooler-than-ever Bruce Wayne must deal with the usual suspects as they plan to rule Gotham City, while discovering that he has accidentally adopted a teenage orphan who wishes to become his sidekick.', 'https://m.media-amazon.com/images/M/MV5BMTcyNTEyOTY0M15BMl5BanBnXkFtZTgwOTAyNzU3MDI@._V1_FMjpg_UX1000_.jpg', 'Will Arnett, Michael Cera, Rosario Dawson, Ralph Fiennes, Siri, Zach Galifianakis', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (168248, 'John Wick: Chapter Two', 'Action,Crime,Thriller', 2017, 'Chad Stahelski', 'After returning to the criminal underworld to repay a debt, John Wick discovers that a large bounty has been put on his life.', 'https://m.media-amazon.com/images/M/MV5BMjE2NDkxNTY2M15BMl5BanBnXkFtZTgwMDc2NzE0MTI@._V1_FMjpg_UX1000_.jpg', 'Keanu Reeves, Riccardo Scamarcio, Ian McShane, Ruby Rose, Common, Claudia Gerini', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (168250, 'Get Out', 'Horror', 2017, 'Jordan Peele', 'A young African-American visits his white girlfriend\'s parents for the weekend, where his simmering uneasiness about their reception of him eventually reaches a boiling point.', 'https://m.media-amazon.com/images/M/MV5BMjUxMDQwNjcyNl5BMl5BanBnXkFtZTgwNzcwMzc0MTI@._V1_FMjpg_UX1000_.jpg', 'Daniel Kaluuya, Allison Williams, Catherine Keener, Bradley Whitford, Caleb Landry Jones, Marcus Henderson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (168252, 'Logan', 'Action,Sci-Fi', 2017, 'James Mangold', 'In a future where mutants are nearly extinct, an elderly and weary Logan leads a quiet life. But when Laura, a mutant child pursued by scientists, comes to him for help, he must get her to safety.', 'https://m.media-amazon.com/images/M/MV5BM2JjODdkMGMtNmY2YS00OGM2LThiY2YtZGYyNzE4Nzc2ODA0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Hugh Jackman, Patrick Stewart, Dafne Keen, Boyd Holbrook, Stephen Merchant, Elizabeth Rodriguez', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (168266, 'T2: Trainspotting', 'Crime,Drama', 2017, 'Danny Boyle', 'After 20 years abroad, Mark Renton returns to Scotland and reunites with his old friends Sick Boy, Spud, and Begbie.', 'https://m.media-amazon.com/images/M/MV5BMjI0MTE1ODkzMl5BMl5BanBnXkFtZTgwMTQ1MTg5MDI@._V1_FMjpg_UX1000_.jpg', 'Ewan McGregor, Logan Gillies, Ben Skelton, Aiden Haggarty, Daniel Smith, Elijah Wolf', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (168344, 'King Arthur: Legend of the Sword', 'Action,Adventure,Drama,Fantasy', 2017, 'Guy Ritchie', 'Robbed of his birthright, Arthur comes up the hard way in the back alleys of the city. But once he pulls the sword from the stone, he is forced to acknowledge his true legacy - whether he likes it or not.', 'https://m.media-amazon.com/images/M/MV5BMjM3ODY3Njc5Ml5BMl5BanBnXkFtZTgwMjQ5NjM5MTI@._V1_FMjpg_UX1000_.jpg', 'Charlie Hunnam, Astrid Bergès-Frisbey, Jude Law, Djimon Hounsou, Eric Bana, Aidan Gillen', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (168366, 'Beauty and the Beast', 'Fantasy,Romance', 2017, 'Bill Condon', 'A brave, beautiful, and brilliant young woman is imprisoned by a beast in his castle. Despite her fears, she learns to see beyond the beast\'s hideous exterior and realize the gentle heart of the true prince within him.', 'https://m.media-amazon.com/images/M/MV5BMTUwNjUxMTM4NV5BMl5BanBnXkFtZTgwODExMDQzMTI@._V1_FMjpg_UX1000_.jpg', 'Emma Watson, Dan Stevens, Luke Evans, Josh Gad, Kevin Kline, Hattie Morahan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (168492, 'Call Me by Your Name', 'Drama,Romance', 2017, 'Luca Guadagnino', 'In the summer of 1983, 17-year-old Elio is spending the days with his family at their villa in Lombardy, Italy. He soon meets 24-year-old Oliver, an intern working for Elio\'s father. They discover the heady beauty of awakening desire.', 'https://m.media-amazon.com/images/M/MV5BNDk3NTEwNjc0MV5BMl5BanBnXkFtZTgwNzYxNTMwMzI@._V1_FMjpg_UX1000_.jpg', 'Armie Hammer, Timothée Chalamet, Michael Stuhlbarg, Amira Casar, Esther Garrel, Victoire Du Bois', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (168612, 'Ghost in the Shell', 'Action,Drama,Sci-Fi', 2017, 'Rupert Sanders', 'In the near future, Major Mira Killian is the first of her kind: A human saved from a terrible crash, who is cyber-enhanced to be a perfect soldier devoted to stopping the world\'s most dangerous criminals.', 'https://m.media-amazon.com/images/M/MV5BNzBkNjdjZTctNjdhOS00NmIyLTlkNjQtY2EwNGMwYmZjNTIxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Scarlett Johansson, Pilou Asbæk, Takeshi Kitano, Juliette Binoche, Michael Pitt, Chin Han', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (169864, 'Life', 'Horror,Sci-Fi,Thriller', 2017, 'Daniel Espinosa', 'A team of scientists aboard the ISS discover a rapidly evolving Martian predator that needs to be kept away from Earth at all costs.', 'https://m.media-amazon.com/images/M/MV5BNWNkYWYzNGUtOWVjNS00MGY0LWIyY2YtODllNGIxOGRlOTgyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Hiroyuki Sanada, Ryan Reynolds, Rebecca Ferguson, Jake Gyllenhaal, Olga Dykhovichnaya, Ariyon Bakare', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (169906, 'The Night Of', 'Crime,Drama', 2016, 'Steven Zaillian', 'After a night of partying with a woman he picked up, a man wakes up to find her stabbed to death and is charged with her murder.', 'https://m.media-amazon.com/images/M/MV5BMjQyOTgxMDI0Nl5BMl5BanBnXkFtZTgwOTE4MzczOTE@._V1_FMjpg_UX1000_.jpg', 'John Turturro, Riz Ahmed, Bill Camp, Payman Maadi, Jeannie Berlin, Poorna Jagannathan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (170153, 'The Dinner', 'Drama,Mystery,Thriller', 2017, 'Oren Moverman', 'Two sets of wealthy parents meet for dinner to decide what to do about a crime their sons have committed.', 'https://m.media-amazon.com/images/M/MV5BMjM0ODg1NTMzMV5BMl5BanBnXkFtZTgwMjczMzA2MTI@._V1_FMjpg_UX1000_.jpg', 'Michael Chernus, Taylor Rae Almonte-Roman, Steve Coogan, Charlie Plummer, Seamus Davey-Fitzpatrick, Miles J. Harvey', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (170481, 'The Most Hated Woman in America', 'Crime,Drama', 2017, 'Tommy O\'Haver', 'The life of Madelyn Murray O\'Hair, the outspoken activist and founder of American Atheists.', 'https://m.media-amazon.com/images/M/MV5BMTI2MzIyY2MtZjQ5Mi00ZWQzLWI3ZWYtNzFkMzNiZjZiZmZhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Melissa Leo, Brandon Mychal Smith, Juno Temple, Michael Chernus, Rory Cochrane, Alex Frost', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (170697, 'Gifted', 'Drama', 2017, 'Marc Webb', 'Frank, a single man raising his child prodigy niece Mary, is drawn into a custody battle with his mother.', 'https://m.media-amazon.com/images/M/MV5BMjQ2NDU3NDE0M15BMl5BanBnXkFtZTgwMjA3OTg0MDI@._V1_FMjpg_UX1000_.jpg', 'Chris Evans, Mckenna Grace, Lindsay Duncan, Octavia Spencer, Jenny Slate, Michael Kendall Kaplan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (170705, 'Band of Brothers', 'Action,Drama,War', 2001, 'Scott Grimes', 'The story of Easy Company of the U.S. Army 101st Airborne Division and their mission in World War II Europe, from Operation Overlord to V-J Day.', 'https://m.media-amazon.com/images/M/MV5BMTQ3NTdmOTEtZTRmMi00NTg5LWI5NmUtYTNiOTc0ZmNkODU0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Scott Grimes, Damian Lewis, Ron Livingston, Shane Taylor, Donnie Wahlberg, Peter Youngblood Hills', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (170947, 'Megan Leavey', 'Adventure,Drama,War', 2017, 'Gabriela Cowperthwaite', 'Based on the true life story of a young Marine corporal whose unique discipline and bond with her military combat dog saved many lives during their deployment in Iraq.', 'https://m.media-amazon.com/images/M/MV5BMTUxOTk2NTkxNF5BMl5BanBnXkFtZTgwOTUyOTM3MTI@._V1_FMjpg_UX1000_.jpg', 'Kate Mara, Edie Falco, Alisa Harris, Nick Madrick, Jason Turner, Sasha Morfaw', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (171263, 'Tramps', 'Comedy,Romance', 2016, 'Adam Leon', 'A young man and woman find love in an unlikely place while carrying out a shady deal.', 'https://m.media-amazon.com/images/M/MV5BODhmZmU1NmEtOGNlZi00ZmYzLWE1YmItNmE4ZDQ5Zjc3NGZmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Callum Turner, Grace Van Patten, Michal Vondel, Mike Birbiglia, Margaret Colin, Louis Cancelmi', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (171315, 'Sand Castle', 'Drama,War', 2017, 'Fernando Coimbra', 'The story follows a young soldier, and his introduction into the 2003 invasion of Iraq. Based on true events, it bears witness to the destruction and horrors of war.', 'https://m.media-amazon.com/images/M/MV5BMDFmNGUwYTMtNDMyMC00YWM2LWEwOTktNTM1YWI0NDRiMDY3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nicholas Hoult, Logan Marshall-Green, Henry Cavill, Glen Powell, Neil Brown Jr., Beau Knapp', '2025-11-24 12:30:38');
