INSERT INTO `movies` VALUES (183339, 'Earth: One Amazing Day', 'Documentary', 2017, 'Richard Dale', 'From BBC Earth Films, the studio that brought you Earth, comes the sequel - Earth: One Amazing Day, an astonishing journey revealing the awesome power of the natural world. Over the course of one single day, we track the sun from the highest mountains to the remotest islands to e...Read all', 'https://m.media-amazon.com/images/M/MV5BZDAyODk4ZjYtZjZiZi00ZWE0LWE4NDgtZGQ4ODg2YjllY2U1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert Redford, Jackie Chan', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (183379, 'Renegades', 'Action,Thriller', 2017, 'Steven Quale', 'A team of Navy SEALs discover an underwater treasure of Nazi stolen gold in a Bosnian lake. An updated Kelly\'s Heroes.', 'https://m.media-amazon.com/images/M/MV5BOWU4MWNiMzItNDdiNC00ZmNjLWJhYTEtNDY5YTgzZTI5MzY2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sullivan Stapleton, Charlie Bewley, Sylvia Hoeks, Joshua Henry, Diarmaid Murtagh, Dimitri Leonidas', '2025-11-24 12:30:38');
