INSERT INTO `movies` VALUES (183701, '12 Strong', 'Drama,War', 2018, 'Nicolai Fuglsig', '12 Strong tells the story of the first Special Forces team deployed to Afghanistan after 9/11; under the leadership of a new captain, the team must work with an Afghan warlord to take down the Taliban.', 'https://m.media-amazon.com/images/M/MV5BNTEzMjk3NzkxMV5BMl5BanBnXkFtZTgwNjY2NDczNDM@._V1_FMjpg_UX1000_.jpg', 'Chris Hemsworth, Michael Shannon, Michael Peña, Navid Negahban, Trevante Rhodes, Geoff Stults', '2025-11-24 12:30:38');
