INSERT INTO `movies` VALUES (186341, 'Minnie the Moocher', 'Animation,Comedy', 1932, 'Dave Fleischer', 'Betty Boop and Bimbo run away from home, but that night they are scared by a chorus of ghosts singing the title song.', 'https://m.media-amazon.com/images/M/MV5BYTRhMzE5ZmQtOTRiMS00ZjVlLThlNmEtYmRhZjU0MWExYTIyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cab Calloway and His Cotton Club Orchestra, Cab Calloway, Billy Murray, William Pennell, Mae Questel', '2025-11-24 12:30:37');
