INSERT INTO `movies` VALUES (187541, 'Incredibles 2', 'Action,Adventure,Animation,Children', 2018, 'Brad Bird', 'The Incredibles family takes on a new mission which involves a change in family roles: Bob Parr (Mr. Incredible) must manage the house while his wife Helen (Elastigirl) goes out to save the world.', 'https://m.media-amazon.com/images/M/MV5BMTEzNzY0OTg0NTdeQTJeQWpwZ15BbWU4MDU3OTg3MjUz._V1_FMjpg_UX1000_.jpg', 'Craig T. Nelson, Holly Hunter, Sarah Vowell, Huck Milner, Catherine Keener, Eli Fucile', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (187577, 'The Death & Life of John F. Donovan', 'Drama', NULL, 'Xavier Dolan', 'A decade after the death of an American television star, a young actor reminisces about the written correspondence he shared with him, as well as the impact those letters had on both their lives.', 'https://m.media-amazon.com/images/M/MV5BNjVhNDY4ZjItZDdiMy00ZjE3LThhZTgtN2M2ZTMzZWIxMjFiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kit Harington, Natalie Portman, Jacob Tremblay, Susan Sarandon, Kathy Bates, Ben Schnetzer', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (187593, 'Deadpool 2', 'Action,Comedy,Sci-Fi', 2018, 'David Leitch', 'Foul-mouthed mutant mercenary Wade Wilson (a.k.a. Deadpool) assembles a team of fellow mutant rogues to protect a young boy with abilities from the brutal, time-traveling cyborg Cable.', 'https://m.media-amazon.com/images/M/MV5BNGY3N2ZhYmMtYTlmYi00ZWIzLWJiZWMtMjgxMjljYTk3MDAwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ryan Reynolds, Josh Brolin, Morena Baccarin, Julian Dennison, Zazie Beetz, T.J. Miller', '2025-11-24 12:30:38');
