INSERT INTO `movies` VALUES (188189, 'Sorry to Bother You', 'Comedy,Fantasy,Sci-Fi', 2018, 'Boots Riley', 'In an alternate present-day version of Oakland, telemarketer Cassius Green discovers a magical key to professional success, propelling him into a universe of greed.', 'https://m.media-amazon.com/images/M/MV5BYjA3ZTYwMzctZTM2ZS00MTllLWE5YzYtOTBjZGRlOTNkODVlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'LaKeith Stanfield, Tessa Thompson, Jermaine Fowler, Omari Hardwick, Terry Crews, Kate Berlant', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (188749, 'The Equalizer 2', 'Action,Crime,Thriller', 2018, 'Antoine Fuqua', 'Robert McCall serves an unflinching justice for the exploited and oppressed, but how far will he go when that is someone he loves?', 'https://m.media-amazon.com/images/M/MV5BMTU2OTYzODQyMF5BMl5BanBnXkFtZTgwNjU3Njk5NTM@._V1_FMjpg_UX1000_.jpg', 'Denzel Washington, Pedro Pascal, Ashton Sanders, Orson Bean, Bill Pullman, Melissa Leo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (189041, 'Sicario: Day of the Soldado', 'Action,Crime,Drama,Thriller', 2018, 'Stefano Sollima', 'The drug war on the U.S.-Mexico border has escalated as the cartels have begun trafficking terrorists across the US border. To fight the war, federal agent Matt Graver re-teams with the mercurial Alejandro.', 'https://m.media-amazon.com/images/M/MV5BMTEzNjM2NTYxMjReQTJeQWpwZ15BbWU4MDU2NzAxNTUz._V1_FMjpg_UX1000_.jpg', 'Benicio Del Toro, Josh Brolin, Isabela Merced, Jeffrey Donovan, Catherine Keener, Manuel Garcia-Rulfo', '2025-11-24 12:30:37');
