INSERT INTO `movies` VALUES (189333, 'Mission: Impossible - Fallout', 'Action,Adventure,Thriller', 2018, 'Christopher McQuarrie', 'A group of terrorists plans to detonate three plutonium cores for a simultaneous nuclear attack on different cities. Ethan Hunt, along with his IMF team, sets out to stop the carnage.', 'https://m.media-amazon.com/images/M/MV5BZmUwZTg2YmMtMmZjOS00ZDYwLWI2ZDgtZDcyY2ZmMWMwZDdlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Henry Cavill, Ving Rhames, Simon Pegg, Rebecca Ferguson, Sean Harris', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (189713, 'BlacKkKlansman', 'Comedy,Crime,Drama', 2018, 'Spike Lee', 'In this story inspired by true events, Ron Stallworth, an African-American Colorado police officer, successfully infiltrates the local branch of the Ku Klux Klan with the help of a white Jewish colleague.', 'https://m.media-amazon.com/images/M/MV5BMjUyOTE1NjI0OF5BMl5BanBnXkFtZTgwMTM4ODQ5NTM@._V1_FMjpg_UX1000_.jpg', 'Alec Baldwin, John David Washington, Isiah Whitlock Jr., Robert John Burke, Brian Tarantina, Arthur J. Nascarella', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (189805, 'Papillon', 'Drama', 2018, 'Michael Noer', 'Wrongfully convicted for murder, Henri Charriere forms an unlikely relationship with fellow inmate and quirky convicted counterfeiter, Louis Dega, in an attempt to escape from the notorious penal colony on Devil\'s Island.', 'https://m.media-amazon.com/images/M/MV5BMjIxMTMyOTE2NF5BMl5BanBnXkFtZTgwMDYyNzY1NTM@._V1_FMjpg_UX1000_.jpg', 'Charlie Hunnam, Damijan Oklopdzic, Christopher Fairbank, Jason Ryan, Eve Hewson, Sladjana Biljman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (189863, 'The Silent Revolution', 'Drama', 2018, 'Lars Kraume', 'A group of twelfth-grade pupils in East Germany decide to show their solidarity with the victims of the 1956 Hungarian uprising by staging a moment of silence during lessons.', 'https://m.media-amazon.com/images/M/MV5BOTAwZTczZTQtZjM3Zi00ZGYzLWJiYmMtZmVlZjg4MDI3MDc4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leonard Scheicher, Tom Gramenz, Lena Klenke, Isaiah Michalski, Jonas Dassler, Nora Labisch', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (190939, 'A Simple Favor', 'Crime,Mystery,Thriller', 2018, 'Paul Feig', 'Stephanie is a single mother with a parenting vlog who befriends Emily, a secretive upper-class woman who has a child at the same elementary school. When Emily goes missing, Stephanie takes it upon herself to investigate.', 'https://m.media-amazon.com/images/M/MV5BZmM4MGFkMTItNzI1ZS00ODZlLThjYjktMTQyYmQzM2M2M2Y3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Anna Kendrick, Ian Ho, Joshua Satine, Glenda Braganza, Andrew Rannells, Kelly McCormack', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (191489, 'Peppermint', 'Action,Crime,Thriller', 2018, 'Pierre Morel', 'Five years after her husband and daughter are killed in a senseless act of violence, a woman comes back from self-imposed exile to seek revenge against those responsible and the system that let them go free.', 'https://m.media-amazon.com/images/M/MV5BN2ZmZGZmMzgtMWMwYS00ODEzLThhODgtYmM4YTViNTRlMWVlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jennifer Garner, John Gallagher Jr., John Ortiz, Juan Pablo Raba, Annie Ngosi Ilonzeh, Jeff Hephner', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (192159, 'Mi obra maestra', 'Comedy', 2018, 'Gastón Duprat', 'Arturo is an unscrupulous art dealer and Renzo his socially-awkward painter and longtime friend. Willing to risk it all, they develop an extreme and ludicrous plan to save themselves.', 'https://m.media-amazon.com/images/M/MV5BZTU1ZTU1MzItYWI2Yy00OTI5LTk5NDEtZjdlN2JhYTVlNzJiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Guillermo Francella, Luis Brandoni, Raúl Arévalo, Andrea Frigerio, Andrea Acatto, Ana María Aldaburu', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (192245, 'Bad Times at the El Royale', 'Horror,Thriller', 2018, 'Drew Goddard', '1969. Four strangers check in at the El Royale Hotel. The hotel is deserted, staffed by a single desk clerk. Some of the new guests\' reasons for being there are less than innocent and some are not who they appear to be.', 'https://m.media-amazon.com/images/M/MV5BOTk1Nzk1MDc1MF5BMl5BanBnXkFtZTgwNjU2NDExNjM@._V1_FMjpg_UX1000_.jpg', 'Jeff Bridges, Cynthia Erivo, Dakota Johnson, Jon Hamm, Chris Hemsworth, Cailee Spaeny', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (192285, 'Birds of Passage', 'Crime,Drama', 2018, 'Cristina Gallego', 'During the marijuana bonanza, a violent decade that saw the origins of drug trafficking in Colombia, Rapayet and his indigenous family get involved in a war to control the business that ends up destroying their lives and their culture.', 'https://m.media-amazon.com/images/M/MV5BMjUxODM5ODUyM15BMl5BanBnXkFtZTgwNzA3Nzg3NjM@._V1_FMjpg_UX1000_.jpg', 'Carmiña Martínez, José Acosta, Natalia Reyes, Jhon Narváez, Greider Meza, José Vicente', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (192379, 'First Man', 'Drama', 2018, 'Damien Chazelle', 'A look back at the life of astronaut Neil Armstrong and the legendary space mission that led him to become the first man to walk on the Moon on July 20, 1969.', 'https://m.media-amazon.com/images/M/MV5BYmIzYmViN2UtMDRhYy00OTMwLWI5YzctMTQxYzg2ODMwMTIwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ryan Gosling, Claire Foy, Jason Clarke, Kyle Chandler, Corey Stoll, Patrick Fugit', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (192385, 'A Star Is Born', 'Drama,Romance', 2018, 'Bradley Cooper', 'A hard-drinking country music star falls in love with a singer whose career quickly takes off.', 'https://m.media-amazon.com/images/M/MV5BNGUxZTc0NTAtNzQwMy00MmM2LTgzMGYtZWIyY2E1MGFjYmM5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Lady Gaga, Bradley Cooper, Sam Elliott, Andrew Dice Clay, Rafi Gavron, Anthony Ramos', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (192389, 'Venom', 'Action,Horror,Sci-Fi,Thriller', 2018, 'Ruben Fleischer', 'A failed reporter is bonded to an alien entity, one of many symbiotes who have invaded Earth. But the being takes a liking to Earth and decides to protect it.', 'https://m.media-amazon.com/images/M/MV5BNTYwMDg5MDItNjhmZi00NmVmLThjNWItMmNkMjVkMWRhNzI2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hardy, Michelle Williams, Riz Ahmed, Scott Haze, Reid Scott, Jenny Slate', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (192803, 'Bohemian Rhapsody', 'Drama', 2018, 'Bryan Singer', 'With his impeccable vocal abilities, Freddie Mercury and his rock band, Queen, achieve superstardom. However, amidst his skyrocketing success, he grapples with his ego, sexuality and a fatal illness.', 'https://m.media-amazon.com/images/M/MV5BMTA2NDc3Njg5NDVeQTJeQWpwZ15BbWU4MDc1NDcxNTUz._V1_FMjpg_UX1000_.jpg', 'Rami Malek, Lucy Boynton, Gwilym Lee, Ben Hardy, Joseph Mazzello, Aidan Gillen', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (193259, 'Gundermann', 'Drama', 2018, 'Andreas Dresen', 'The movie deals with the real life story of East German singer and writer Gerhard Gundermann and his struggles with music, life as a coal miner and his dealings with the secret police (STASI) of the GDR.', 'https://m.media-amazon.com/images/M/MV5BMzg2MjFhYTEtMjk4OC00ODFmLThhZmUtMzBlYTIxMjFlYTk1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Alexander Scheer, Anna Unterberger, Axel Prahl, Thorsten Merten, Eva Weißenborn, Benjamin Kramme', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (193866, 'Tales from the Hood 2', 'Horror', 2018, 'Rusty Cundieff', 'Sequel to the cult classic reunites executive producer Spike Lee and writers/directors/producers Rusty Cundieff and Darin Scott for this horror-comedy starring Keith David.', 'https://m.media-amazon.com/images/M/MV5BZjFiYzUwYjgtOWE1NC00Njg5LWEyZTUtNjYwNTI5MTQxNWJlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Keith David, Bryan Batt, Lou Beatty Jr., Alexandria DeBerry, Bill Martin Williams, Martin Bats Bradford', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (193944, 'The Ballad of Buster Scruggs', 'Comedy,Drama,Western', 2018, 'Ethan Coen', 'Six tales of life and violence in the Old West, following a singing gunslinger, a bank robber, a traveling impresario, an elderly prospector, a wagon train and a perverse pair of bounty hunters.', 'https://m.media-amazon.com/images/M/MV5BOTc0MzZjYTktYzBlZC00MmViLTgyNDYtNjljNTcxMzdjODRkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tim Blake Nelson, Willie Watson, Clancy Brown, Danny McCarthy, David Krumholtz, Thomas Wingate', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (193958, 'Creed II', 'Drama', 2018, 'Steven Caple Jr.', 'Under the tutelage of Rocky Balboa, newly crowned heavyweight champion Adonis Creed faces off against Viktor Drago, the son of Ivan Drago.', 'https://m.media-amazon.com/images/M/MV5BMTBmYTg3YTItZjUzYi00MGU2LThiNDUtMDA3NjNmMTFiYzZkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael B. Jordan, Sylvester Stallone, Tessa Thompson, Phylicia Rashad, Dolph Lundgren, Florian Munteanu', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (194004, 'Halloween', 'Horror', 2018, 'David Gordon Green', 'Laurie Strode confronts her long-time foe, Michael Myers, the masked figure who has haunted her since she narrowly escaped his killing spree on Halloween night four decades ago.', 'https://m.media-amazon.com/images/M/MV5BY2FlMzdkZTMtN2MwOS00NjQzLTlkMGYtMTRiYWUxZjM2M2ZiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jamie Lee Curtis, Judy Greer, Andi Matichak, James Jude Courtney, Nick Castle, Haluk Bilginer', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (194016, 'Ralph Breaks the Internet', 'Animation,Children', 2018, 'Phil Johnston', 'On a quest to save the video game \'Sugar Rush\' and to find a replacement, Ralph and his best friend Vanellope travel to the World Wide Web through a Wi-Fi router they find at the arcade.', 'https://m.media-amazon.com/images/M/MV5BMTYyNzEyNDAzOV5BMl5BanBnXkFtZTgwNTk3NDczNjM@._V1_FMjpg_UX1000_.jpg', 'John C. Reilly, Sarah Silverman, Gal Gadot, Taraji P. Henson, Jack McBrayer, Jane Lynch', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (194026, 'The Man Who Killed Hitler and Then the Bigfoot', 'Drama', 2018, 'Robert D. Krzykowski', 'A legendary American war veteran is recruited to hunt a mythical creature.', 'https://m.media-amazon.com/images/M/MV5BMTg2NzI4NjY1Nl5BMl5BanBnXkFtZTgwNjUxOTc3NTM@._V1_FMjpg_UX1000_.jpg', 'Sam Elliott, Rocco Gioffre, Aidan Turner, Melissa Jalali, Joe Lucas, Alton Fitzgerald White', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (194396, 'Overlord', 'Action,Horror,Sci-Fi,Thriller,War', 2018, 'Julius Avery', 'A small group of American soldiers find horror behind enemy lines on the eve of D-Day.', 'https://m.media-amazon.com/images/M/MV5BMzVmZWZjZjEtNDk2OC00ZDUxLTg5NzktYWJhZTJiYTlkMzhmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jovan Adepo, Wyatt Russell, Mathilde Ollivier, Pilou Asbæk, John Magaro, Iain De Caestecker', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (194448, 'Green Book', 'Comedy,Drama', 2018, 'Peter Farrelly', 'A working-class Italian-American bouncer becomes the driver for an African-American classical pianist on a tour of venues through the 1960s American South.', 'https://m.media-amazon.com/images/M/MV5BNDU5YTNmMmItN2QxNy00OGQ0LTg5MTctNzFmYjEzZjcwN2UwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Viggo Mortensen, Mahershala Ali, Linda Cardellini, Sebastian Maniscalco, Dimiter D. Marinov, Mike Hatton', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (194628, 'Der Junge muss an die frische Luft', 'Drama', 2018, 'Caroline Link', 'Dramatised origin story of one of Germany\'s most beloved contemporary comedians.', 'https://m.media-amazon.com/images/M/MV5BMjUyZWM2M2QtNTg4OC00NTU1LTg2ODAtYzNiZjY0Mjc1MDlkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Julius Weckauf, Luise Heyer, Sönke Möhring, Hedi Kriegeskotte, Joachim Król, Ursula Werner', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (194664, 'They Shall Not Grow Old', 'Documentary,War', 2018, 'Peter Jackson', 'A documentary about World War I with never-before-seen footage to commemorate the centennial of the end of the war.', 'https://m.media-amazon.com/images/M/MV5BOGMwNzc3NTQtY2QzZS00YzJmLTgyM2UtYjlkMjBjZTAwM2Y5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Thomas Adlam, William Argent, John Ashby, Attwood, Walter Aust, Donald Bain', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (194762, 'The Clovehitch Killer', 'Horror,Thriller', 2018, 'Duncan Skiles', 'A picture-perfect family is shattered when the work of a serial killer hits too close to home.', 'https://m.media-amazon.com/images/M/MV5BNDI3OWExYzItYzY2Mi00N2IyLWE3ZjAtNWJkMDE2ZDhhZjhjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dylan McDermott, Charlie Plummer, Samantha Mathis, Madisen Beaty, Brenna Sherman, Lance Chantiles-Wertz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (194951, 'Bird Box', 'Drama,Sci-Fi,Thriller', 2018, 'Susanne Bier', 'Five years after an ominous unseen presence drives most of society to suicide, a mother and her two children make a desperate bid to reach safety.', 'https://m.media-amazon.com/images/M/MV5BMjAzMTI1MjMyN15BMl5BanBnXkFtZTgwNzU5MTE2NjM@._V1_FMjpg_UX1000_.jpg', 'Sandra Bullock, Trevante Rhodes, John Malkovich, Sarah Paulson, Jacki Weaver, Rosa Salazar', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (195159, 'Spider-Man: Into the Spider-Verse', 'Action,Adventure,Animation,Sci-Fi', 2018, 'Bob Persichetti', 'Teen Miles Morales becomes the Spider-Man of his universe and must join with five spider-powered individuals from other dimensions to stop a threat for all realities.', 'https://m.media-amazon.com/images/M/MV5BMjMwNDkxMTgzOF5BMl5BanBnXkFtZTgwNTkwNTQ3NjM@._V1_FMjpg_UX1000_.jpg', 'Shameik Moore, Jake Johnson, Hailee Steinfeld, Mahershala Ali, Brian Tyree Henry, Lily Tomlin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (195485, 'Time Freak', 'Comedy,Drama,Sci-Fi', 2018, 'Andrew Bowler', 'A genius teenage boy is in love with a girl who breaks up with him after a year. He invents a time machine and tries to fix the breakup repeatedly. He finally goes a year back with his friend to fix the bad days.', 'https://m.media-amazon.com/images/M/MV5BMmEzODVhYTAtYWE2Ni00MWI5LTk0NjUtNDkxY2ZmYzM5YzIyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Asa Butterfield, Sophie Turner, Skyler Gisondo, Will Peltz, Aubrey Reynolds, Jillian Joy', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (195497, 'Vice', 'Comedy,Drama', 2018, 'Adam McKay', 'The story of Dick Cheney, an unassuming bureaucratic Washington insider, who quietly wielded immense power as Vice President to George W. Bush, reshaping the country and the globe in ways that are still felt today.', 'https://m.media-amazon.com/images/M/MV5BMTY1NjM0MzgxMV5BMl5BanBnXkFtZTgwNDc4NTY0NjM@._V1_FMjpg_UX1000_.jpg', 'Christian Bale, Amy Adams, Steve Carell, Sam Rockwell, Alison Pill, Eddie Marsan', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (195561, 'The Hummingbird Project', '(no genres listed)', 2018, 'Kim Nguyen', 'A pair of high-frequency traders go up against their old boss in an effort to make millions in a fiber-optic cable deal.', 'https://m.media-amazon.com/images/M/MV5BMTA2MDM2OTMzODNeQTJeQWpwZ15BbWU4MDgxNjExMjcz._V1_FMjpg_UX1000_.jpg', 'Jesse Eisenberg, Alexander Skarsgård, Salma Hayek, Michael Mando, Johan Heldenbergh, Ayisha Issa', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (196417, 'How to Train Your Dragon: The Hidden World', 'Adventure,Animation,Children', 2019, 'Dean DeBlois', 'When Hiccup discovers Toothless isn\'t the only Night Fury, he must seek the Hidden World, a secret Dragon Utopia before a hired tyrant named Grimmel finds it first.', 'https://m.media-amazon.com/images/M/MV5BMjIwMDIwNjAyOF5BMl5BanBnXkFtZTgwNDE1MDc2NTM@._V1_FMjpg_UX1000_.jpg', 'Jay Baruchel, America Ferrera, F. Murray Abraham, Cate Blanchett, Gerard Butler, Craig Ferguson', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (196889, 'Glass', 'Drama,Horror,Mystery,Sci-Fi,Thriller', 2019, 'M. Night Shyamalan', 'Security guard David Dunn uses his supernatural abilities to track Kevin Wendell Crumb, a disturbed man who has twenty-four personalities.', 'https://m.media-amazon.com/images/M/MV5BMTY1OTA2MjI5OV5BMl5BanBnXkFtZTgwNzkxMjU4NjM@._V1_FMjpg_UX1000_.jpg', 'James McAvoy, Bruce Willis, Samuel L. Jackson, Anya Taylor-Joy, Sarah Paulson, Spencer Treat Clark', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (197175, 'Alita: Battle Angel', 'Action,Romance,Sci-Fi,Thriller', 2019, 'Robert Rodriguez', 'A deactivated cyborg\'s revived, but can\'t remember anything of her past and goes on a quest to find out who she is.', 'https://m.media-amazon.com/images/M/MV5BYmZhZGQzM2MtMWEyZC00YTU1LTk4YTQtMTg3ZjEzM2U1NTkxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Rosa Salazar, Christoph Waltz, Jennifer Connelly, Mahershala Ali, Ed Skrein, Jackie Earle Haley', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (197197, 'The Report', 'Drama', 2019, 'Scott Z. Burns', 'Idealistic Senate staffer Daniel J. Jones, tasked by his boss to lead an investigation into the CIA\'s post 9/11 Detention and Interrogation Program, uncovers shocking secrets.', 'https://m.media-amazon.com/images/M/MV5BNTA3MDQwMDktNTNmYS00ZTkzLWE4ZDAtMzg2NGYyM2UzYWQ3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Adam Driver, Corey Stoll, Evander Duck Jr., Jon Hamm, Linda Powell, Annette Bening', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (197651, 'The King', 'Drama', NULL, 'David Michôd', 'Young Henry V encounters deceit, war and treachery after becoming King of England in the 15th century, in the aftermath of his brother\'s death.', 'https://m.media-amazon.com/images/M/MV5BOTFhZTY4YWUtMmJjMy00OTE0LTlmZjctMDg5MTk4N2ZjZWNjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Glynn-Carney, Gábor Czap, Tom Fisher, Edward Ashley, Steven Elder, Stephen Fewell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (197689, 'Polar', 'Action', 2019, 'Jonas Åkerlund', 'A retiring assassin suddenly finds himself on the receiving end of a hit, contracted by none other than his own employer seeking to cash in on the pensions of aging employees.', 'https://m.media-amazon.com/images/M/MV5BZmEzNzU2MDUtZmJiNi00ZGI0LWFiNjItYWQzNGIxY2I2MGZjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mads Mikkelsen, Vanessa Hudgens, Katheryn Winnick, Fei Ren, Ruby O. Fee, Matt Lucas', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (197711, 'Us', 'Horror,Thriller', 2019, 'Jordan Peele', 'In order to get away from their busy lives, the Wilson family takes a vacation to Santa Cruz, California. At night, four strangers break into Adelaide\'s childhood home. The family is shocked to find out that the intruders look like them.', 'https://m.media-amazon.com/images/M/MV5BMzhkMjFkN2YtODU2Ni00YWYwLWExN2MtOWNjZmQxM2U4YTM5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Lupita Nyong\'o, Winston Duke, Elisabeth Moss, Tim Heidecker, Shahadi Wright Joseph, Evan Alex', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (198153, 'The Beach Bum', 'Comedy', 2019, 'Harmony Korine', 'A rebellious stoner named Moondog lives life by his own rules.', 'https://m.media-amazon.com/images/M/MV5BZGU5MzRkY2MtYWIyMS00NzU5LWE0NmQtMjMwYmE4NTkyMjA2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matthew McConaughey, Snoop Dogg, Isla Fisher, Stefania LaVie Owen, Martin Lawrence, Zac Efron', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (199065, 'Synonyms', 'Drama', 2019, 'Nadav Lapid', 'A young Israeli man absconds to Paris to flee his nationality, aided by his trusty Franco-Israeli dictionary.', 'https://m.media-amazon.com/images/M/MV5BMjA5ZGZlODUtYjgxMS00NTJmLWI2ZmEtMDkxOGViNjRjZWVmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Mercier, Quentin Dolmaire, Louise Chevillotte, Uria Hayik, Olivier Loustau, Yehuda Almagor', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (199223, 'Pet Sematary', 'Horror,Thriller', 2019, 'Kevin Kölsch', 'Dr. Louis Creed and his wife, Rachel, relocate from Boston to rural Maine with their two young children. The couple soon discover a mysterious burial ground hidden deep in the woods near their new home.', 'https://m.media-amazon.com/images/M/MV5BNWQ0ZTQ2NTQtNGQ3MS00YTdlLThlOTAtZDBiZDkzNDk1MDk2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jason Clarke, Amy Seimetz, John Lithgow, Jeté Laurence, Hugo Lavoie, Lucas Lavoie', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (199910, 'The Professor and the Madman', 'Drama', 2019, 'Farhad Safinia', 'Professor James Murray begins work compiling words for the first edition of the Oxford English Dictionary in the 19th century, and receives over 10,000 entries from a patient at Broadmoor Criminal Lunatic Asylum, Dr. William Chester Minor.', 'https://m.media-amazon.com/images/M/MV5BN2JlYzRmNjYtYTg4Mi00MjMyLTlhYTYtMmNiY2Y0ODg5M2I1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mel Gibson, Sean Penn, Eddie Marsan, Natalie Dormer, Jennifer Ehle, Steve Coogan', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (200306, 'Booksmart', 'Comedy', 2019, 'Olivia Wilde', 'On the eve of their high-school graduation, two academic superstars and best friends realize they should have worked less and played more. Determined not to fall short of their peers, the girls try to cram four years of fun into one night.', 'https://m.media-amazon.com/images/M/MV5BMjEzMjcxNjA2Nl5BMl5BanBnXkFtZTgwMjAxMDM2NzM@._V1_FMjpg_UX1000_.jpg', 'Kaitlyn Dever, Beanie Feldstein, Jessica Williams, Jason Sudeikis, Lisa Kudrow, Will Forte', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (200638, 'Tolkien', 'Drama', 2019, 'Dome Karukoski', 'Tolkien\'s novels were inspired by his mom\'s storytelling, falling in love with another orphan, Edith, forming a brotherhood with 3 other misfits at school, the trench war of WWI and later telling stories to his own kids.', 'https://m.media-amazon.com/images/M/MV5BMjUzNzA1MDczOF5BMl5BanBnXkFtZTgwODY5OTI2NzM@._V1_FMjpg_UX1000_.jpg', 'Nicholas Hoult, Al Bollands, Kallum Tolkien, Craig Roberts, Harry Gilby, Colm Meaney', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (200678, 'A Vigilante', 'Drama,Thriller', 2019, 'Sarah Daggar-Nickson', 'After escaping her violent husband, Sadie makes it her life\'s mission to help free others in danger. After months of rigorous training in survival skills, boxing, and lethal martial arts, she is back with a vengeance.', 'https://m.media-amazon.com/images/M/MV5BOGJmNzA5ODktM2NlOS00YjcxLWJiNTMtODc2OGUzM2ExNmYyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Olivia Wilde, Morgan Spector, Kyle Catlett, Estefania Tejeda, Tonye Patano, Betsy Aidem', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (200818, 'John Wick: Chapter 3 – Parabellum', 'Action,Crime,Thriller', 2019, 'Chad Stahelski', 'John Wick is on the run after killing a member of the international assassins\' guild, and with a $14 million price tag on his head, he is the target of hit men and women everywhere.', 'https://m.media-amazon.com/images/M/MV5BYjdlNWFlZjEtM2U0NS00ZWU5LTk1M2EtZmQxNWFiZjk0MGM5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Keanu Reeves, Halle Berry, Ian McShane, Laurence Fishburne, Mark Dacascos, Asia Kate Dillon', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (201340, 'The Lighthouse', 'Drama,Fantasy,Horror', 2019, 'Robert Eggers', 'Two lighthouse keepers try to maintain their sanity while living on a remote and mysterious New England island in the 1890s.', 'https://m.media-amazon.com/images/M/MV5BMTI4MjFhMjAtNmQxYi00N2IxLWJjMGEtYWY1YmU3OTQ0Zjk3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert Pattinson, Willem Dafoe, Valeriia Karaman, Logan Hawkes, Kyla Nicolle, Shaun Clarke', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (201588, 'Toy Story 4', 'Adventure,Animation,Children,Comedy', 2019, 'Josh Cooley', 'When a new toy called \"Forky\" joins Woody and the gang, a road trip alongside old and new friends reveals how big the world can be for a toy.', 'https://m.media-amazon.com/images/M/MV5BMTYzMDM4NzkxOV5BMl5BanBnXkFtZTgwNzM1Mzg2NzM@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Tim Allen, Annie Potts, Tony Hale, Keegan-Michael Key, Madeleine McGraw', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (201646, 'Midsommar', 'Drama,Horror,Mystery', 2019, 'Ari Aster', 'A couple travels to Northern Europe to visit a rural hometown\'s fabled Swedish mid-summer festival. What begins as an idyllic retreat quickly devolves into an increasingly violent and bizarre competition at the hands of a pagan cult.', 'https://m.media-amazon.com/images/M/MV5BMzQxNzQzOTQwM15BMl5BanBnXkFtZTgwMDQ2NTcwODM@._V1_FMjpg_UX1000_.jpg', 'Florence Pugh, Jack Reynor, Vilhelm Blomgren, William Jackson Harper, Will Poulter, Ellora Torchia', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (201725, 'Bloodline', 'Horror', 2018, 'Henry Jacobson', 'Evan values family above all else, and anyone who gets between him, his wife, and newborn son learns that the hard way. But when it comes to violent tendencies, it seems the apple doesn\'t fall far from the tree.', 'https://m.media-amazon.com/images/M/MV5BZmIzMjA0MzktNGU4Yi00OWQyLWJkZmUtMmE5YTBkMDE0MTRjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Seann William Scott, Mariela Garriga, Dale Dickey, Christie Herring, Raymond Cham Jr., Nick Boraine', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (201773, 'Spider-Man: Far from Home', 'Action,Adventure,Sci-Fi', 2019, 'Jon Watts', 'Peter Parker, the beloved superhero Spider-Man, faces four destructive elemental monsters while on holiday in Europe. Soon, he receives help from Mysterio, a fellow hero with mysterious origins.', 'https://m.media-amazon.com/images/M/MV5BMzNhNTE0NWQtN2E1Ny00NjcwLTg1YTctMGY1NmMwODJmY2NmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Holland, Samuel L. Jackson, Jake Gyllenhaal, Marisa Tomei, Jon Favreau, Zendaya', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (202429, 'Once Upon a Time in Hollywood', 'Comedy,Drama', 2019, 'Quentin Tarantino', 'As Hollywood\'s Golden Age is winding down during the summer of 1969, television actor Rick Dalton and his stunt double Cliff Booth endeavor to achieve lasting success in Hollywood while meeting several colorful characters along the way.', 'https://m.media-amazon.com/images/M/MV5BMzMzNmViNjYtN2ViNi00NDM3LWFlMmItNDYyMGIzY2EzZjE2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Brad Pitt, Margot Robbie, Emile Hirsch, Margaret Qualley, Timothy Olyphant', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (202439, 'Parasite', 'Comedy,Drama', 2019, 'Bong Joon Ho', 'Greed and class discrimination threaten the newly formed symbiotic relationship between the wealthy Park family and the destitute Kim clan.', 'https://m.media-amazon.com/images/M/MV5BYjk1Y2U4MjQtY2ZiNS00OWQyLWI3MmYtZWUwNmRjYWRiNWNhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Song Kang-ho, Lee Sun-kyun, Cho Yeo-jeong, Choi Woo-sik, Park So-dam, Lee Jeong-eun', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (202497, 'Les Misérables', 'Crime,Drama', 2019, 'Ladj Ly', 'A cop from the provinces moves to Paris to join the Anti-Crime Brigade of Montfermeil, discovering an underworld where the tensions between the different groups mark the rhythm.', 'https://m.media-amazon.com/images/M/MV5BMzE2Y2Y0NjUtNWI3Yy00NGUyLTk0MmEtODE1YzAxNDhkMTgzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Damien Bonnard, Alexis Manenti, Djebril Zonga, Issa Perica, Al-Hassan Ly, Steve Tientcheu', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (202519, 'Child\'s Play', 'Comedy,Horror', 2019, 'Lars Klevberg', 'A mother gives her 13-year-old son a toy doll for his birthday, unaware of its more sinister nature.', 'https://m.media-amazon.com/images/M/MV5BNzMwZTNkYzktM2EwYS00ZGZlLWJhNmQtZWNhMTBlMDUzOWRkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tim Matheson, Ben Daon, Zahra Anderson, Serge Jaswal, Ariana Nica, Phoenix Ly', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (202749, 'Portrait of a Lady on Fire', 'Drama,Romance', 2019, 'Céline Sciamma', 'On an isolated island in Brittany at the end of the eighteenth century, a female painter is obliged to paint a wedding portrait of a young woman.', 'https://m.media-amazon.com/images/M/MV5BZjJlYWJlYmMtNjMyMS00ZDgxLTlmNjAtOTJhMzBiZWM5N2VmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Noémie Merlant, Adèle Haenel, Luàna Bajrami, Valeria Golino, Christel Baras, Armande Boulanger', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (203222, 'The Lion King', 'Adventure,Animation,Children,Drama', 2019, 'Jon Favreau', 'After the murder of his father, a young lion prince flees his kingdom only to learn the true meaning of responsibility and bravery.', 'https://m.media-amazon.com/images/M/MV5BMjIwMjE1Nzc4NV5BMl5BanBnXkFtZTgwNDg4OTA1NzM@._V1_FMjpg_UX1000_.jpg', 'Chiwetel Ejiofor, John Oliver, James Earl Jones, John Kani, Alfre Woodard, JD McCrary', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (203322, 'The Peanut Butter Falcon', 'Adventure', 2019, 'Tyler Nilson', 'Zak, a man with Down syndrome, runs away from a residential nursing home to pursue his dream of becoming a wrestler. Later, he meets with an outlaw who becomes his friend and coach.', 'https://m.media-amazon.com/images/M/MV5BYjgxZTE4NDctZTM1MC00YjIwLTk0MmMtNWFkZGUwMGE2ZjNhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Zack Gottsagen, Ann Pierce, Dakota Johnson, Bruce Dern, Shia LaBeouf, Thomas Haden Church', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (203375, 'Ford v. Ferrari', 'Action,Drama', 2019, 'James Mangold', 'American car designer Carroll Shelby and driver Ken Miles battle corporate interference and the laws of physics to build a revolutionary race car for Ford in order to defeat Ferrari at the 24 Hours of Le Mans in 1966.', 'https://m.media-amazon.com/images/M/MV5BOTBjNTEyNjYtYjdkNi00YzE5LTljYzUtZjVlYmYwZmJmZWYxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matt Damon, Christian Bale, Jon Bernthal, Caitríona Balfe, Josh Lucas, Noah Jupe', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (203934, 'Freaks', 'Sci-Fi,Thriller', 2019, 'Zach Lipovsky', 'A bold girl discovers a bizarre, threatening, and mysterious new world beyond her front door after she escapes her father\'s protective and paranoid control.', 'https://m.media-amazon.com/images/M/MV5BNjcxZjdkNmYtYWM1Yi00YWQ0LWFkZDEtMmIzNDVlMzVmZjY0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Emile Hirsch, Bruce Dern, Grace Park, Amanda Crew, Lexy Kolker, Ava Telek', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (204152, 'Vivarium', 'Sci-Fi,Thriller', 2019, 'Lorcan Finnegan', 'A young couple looking for the perfect home find themselves trapped in a mysterious labyrinth-like neighborhood of identical houses.', 'https://m.media-amazon.com/images/M/MV5BZjdlZmRmOTUtN2IxZi00ZmY2LWE5MWMtOTYxNTkyNzA3ZGFjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Imogen Poots, Danielle Ryan, Molly McCann, Jesse Eisenberg, Jonathan Aris, Côme Thiry', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (204352, 'Ad Astra', 'Adventure,Drama,Mystery,Sci-Fi,Thriller', 2019, 'James Gray', 'Astronaut Roy McBride undertakes a mission across an unforgiving solar system to uncover the truth about his missing father and his doomed expedition that now, 30 years later, threatens the universe.', 'https://m.media-amazon.com/images/M/MV5BOGRhOGNjZjEtNTU2Ni00MDlmLWI3MWEtNzc1OGE2ZmEwZGNhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brad Pitt, Tommy Lee Jones, Ruth Negga, Donald Sutherland, Kimberly Elise, Loren Dean', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (204542, 'It: Chapter Two', 'Horror', 2019, 'Andy Muschietti', 'Twenty-seven years after their first encounter with the terrifying Pennywise, the Losers Club have grown up and moved away, until a devastating phone call brings them back.', 'https://m.media-amazon.com/images/M/MV5BYzUxM2VhOGItZTY2My00OTA4LWI4NjUtMDA5YWJjM2M2NDJjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jessica Chastain, James McAvoy, Bill Hader, Isaiah Mustafa, Jay Ryan, James Ransone', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (204698, 'Joker', 'Crime,Drama,Thriller', 2019, 'Todd Phillips', 'Arthur Fleck, a party clown and a failed stand-up comedian, leads an impoverished life with his ailing mother. However, when society shuns him and brands him as a freak, he decides to embrace the life of chaos in Gotham City.', 'https://m.media-amazon.com/images/M/MV5BNzY3OWQ5NDktNWQ2OC00ZjdlLThkMmItMDhhNDk3NTFiZGU4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Joaquin Phoenix, Robert De Niro, Zazie Beetz, Frances Conroy, Brett Cullen, Shea Whigham', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (204704, 'Ready or Not', 'Comedy,Horror,Thriller', 2019, 'Matt Bettinelli-Olpin', 'A bride\'s wedding night takes a sinister turn when her eccentric new in-laws force her to take part in a terrifying game.', 'https://m.media-amazon.com/images/M/MV5BMTViMDA4YjgtZDQ4NC00ZDk2LTg0MWItOTc4MTkwMmVkZWRmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Samara Weaving, Adam Brody, Mark O\'Brien, Henry Czerny, Andie MacDowell, Melanie Scrofano', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (204878, 'Dolemite Is My Name', 'Comedy,Drama', 2019, 'Craig Brewer', 'Eddie Murphy portrays real-life legend Rudy Ray Moore, a comedy and rap pioneer who proved naysayers wrong when his hilarious, obscene, kung-fu fighting alter ego, Dolemite, became a 1970s Blaxploitation phenomenon.', 'https://m.media-amazon.com/images/M/MV5BOTYyNGU3MDctZWU1NS00N2Y5LWE2MDUtOWFlMmVmM2IzNDQ5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Eddie Murphy, Keegan-Michael Key, Mike Epps, Craig Robinson, Tituss Burgess, Da\'Vine Joy Randolph', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (205048, '21 Bridges', 'Action,Crime,Thriller', 2019, 'Brian Kirk', 'An embattled NYPD detective is thrust into a citywide manhunt for a pair of cop killers after uncovering a massive and unexpected conspiracy.', 'https://m.media-amazon.com/images/M/MV5BMmZjYjI0YjUtOTc4OC00MmEyLWE4MDItN2M5NGZmNWY1YzYxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chadwick Boseman, Sienna Miller, J.K. Simmons, Stephan James, Taylor Kitsch, Keith David', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (205072, 'Zombieland: Double Tap', 'Action,Comedy,Horror', 2019, 'Ruben Fleischer', 'Columbus, Tallahassee, Wichita, and Little Rock move to the American heartland as they face off against evolved zombies, fellow survivors, and the growing pains of the snarky makeshift family.', 'https://m.media-amazon.com/images/M/MV5BOTViNDc4NTgtYzVlNi00YmY3LWFiNDgtODJlNGU1YzI1MGExXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Woody Harrelson, Jesse Eisenberg, Emma Stone, Abigail Breslin, Zoey Deutch, Avan Jogia', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (205156, 'Jojo Rabbit', 'Comedy,War', 2019, 'Taika Waititi', 'A young German boy in the Hitler Youth, whose hero and imaginary friend is the country\'s dictator, is shocked to discover that his mother is hiding a Jewish girl in their home.', 'https://m.media-amazon.com/images/M/MV5BYmFmNmUyMjYtZTFjNS00OWQyLThhZmMtMGZkYTQ3YjY0ZDQ1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Roman Griffin Davis, Thomasin McKenzie, Scarlett Johansson, Taika Waititi, Sam Rockwell, Rebel Wilson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (205160, 'Woodstock: Three Days that Defined a Generation', 'Documentary', 2019, 'Jamila Ephron', 'The iconic 3-day music festival that symbolized the counterculture era, exploring its organization, performances, and societal impact in a factual, unbiased manner.', 'https://m.media-amazon.com/images/M/MV5BYmU3MGZmMjUtNzY2NC00MDZhLWJhMTItMmYxYjJhY2Q3NzQwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'John Roberts, Joel Rosenman, Joel Makower, Bob Spitz, Michael Lang, Buffalo Springfield', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (205190, 'Mike Wallace Is Here', 'Documentary', 2019, 'Avi Belkin', 'A look at the career of 60 Minutes (1968) newsman, Mike Wallace.', 'https://m.media-amazon.com/images/M/MV5BODZlYjMzZjUtZjczZC00YWU2LWFjZjQtZTI0MGZmMjkwYjliXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mike Wallace, Spiro Agnew, Jonathan Alter, Yasser Arafat, Menachem Begin, Jack Benny', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (205291, 'Badla', 'Crime,Drama,Mystery,Thriller', 2019, 'Sujoy Ghosh', 'A dynamic young entrepreneur finds herself locked in a hotel room with the corpse of her dead lover. She hires a prestigious lawyer to defend her and they work together to figure out what actually happened.', 'https://m.media-amazon.com/images/M/MV5BMDEyNjI2NTktZmJlMy00Njk5LTk2OGQtMjI5NTAwNWRiZmFlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Amitabh Bachchan, Taapsee Pannu, Amrita Singh, Antonio Aakeel, Tony Luke, Tanveer Ghani', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (205327, 'Motherless Brooklyn', 'Crime,Drama', 2019, 'Edward Norton', 'In 1950s New York, Lionel, a private detective with Tourette syndrome, sets out to uncover the mystery behind his mentor and only friend Frank\'s murder. Scouring the jazz clubs and slums of Brooklyn, he soon uncovers a web of secrets.', 'https://m.media-amazon.com/images/M/MV5BMTU3ZWViNGUtZWFkNC00NWQzLTg4MzgtNGYwZThhOWU0YzFkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Edward Norton, Gugu Mbatha-Raw, Alec Baldwin, Willem Dafoe, Bruce Willis, Ethan Suplee', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (205383, 'El Camino: A Breaking Bad Movie', 'Crime,Drama,Thriller', 2019, 'Vince Gilligan', 'Fugitive Jesse Pinkman runs from his captors, the law, and his past.', 'https://m.media-amazon.com/images/M/MV5BYTYxMjI2YzUtODQ5Mi00M2JmLTlmNzItOTlkM2MyM2ExM2RlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Aaron Paul, Jonathan Banks, Matt Jones, Charles Baker, Todd Terry, Julie Pearl', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (205441, 'Marriage Story', 'Comedy,Drama', 2019, 'Noah Baumbach', 'A stage director and his actor wife struggle through a grueling divorce that pushes them to their personal and creative extremes. Noah Baumbach\'s incisive and compassionate look at a marriage breaking up and a family staying together.', 'https://m.media-amazon.com/images/M/MV5BNmE0OWJlM2MtNzhmMi00YmQyLTlmY2EtZmUzNzBiNGRlN2JkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Adam Driver, Scarlett Johansson, Julia Greer, Azhy Robertson, Wallace Shawn, Matthew Maher', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (205545, 'Official Secrets', 'Drama,Romance,Thriller,War', 2019, 'Gavin Hood', 'The true story of a British whistleblower who leaked information to the press about an illegal NSA spy operation designed to push the UN Security Council into sanctioning the 2003 invasion of Iraq.', 'https://m.media-amazon.com/images/M/MV5BNGM2NzcwZjItOTE4Mi00Yzc5LWI3ZmItYTdkZWQ0NDYxN2YzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Keira Knightley, Matt Smith, Matthew Goode, Rhys Ifans, Adam Bakri, Ralph Fiennes', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (205661, 'Maleficent: Mistress of Evil', 'Fantasy', 2019, 'Joachim Rønning', 'Maleficent and her goddaughter Aurora begin to question the complex family ties that bind them as they are pulled in different directions by impending nuptials, unexpected allies, and dark new forces at play.', 'https://m.media-amazon.com/images/M/MV5BNTY4YjYwYzMtYTg1NC00ZmJiLTk0OTYtMWMzM2Y4Yzc5MDc2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Angelina Jolie, Elle Fanning, Harris Dickinson, Michelle Pfeiffer, Sam Riley, Chiwetel Ejiofor', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (206246, 'The Platform', 'Drama,Horror,Sci-Fi', 2019, 'Galder Gaztelu-Urrutia', 'In a prison where inmates are fed on a descending platform, those on the upper levels take more than their fair share while those below are left to starve on scraps and one man decides to change the system.', 'https://m.media-amazon.com/images/M/MV5BYjUyZjNmYmMtNjA1My00ZWMyLTliZGQtODgzZjIxM2Y4NGI1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ivan Massagué, Zorion Eguileor, Antonia San Juan, Emilio Buale, Alexandra Masangkay, Zihara Llana', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (206415, 'The Corrupted', 'Crime,Thriller', 2019, 'Ron Scalpello', 'Liam is an ex-con trying to win back the love and trust of his family. Liam\'s drive for redemption will see him caught up in a web of conspiracy, crime, and corruption.', 'https://m.media-amazon.com/images/M/MV5BM2QxMTc4OTEtMGY3Mi00MDMwLTlhYWItYzM4Yzc1ODNjZWM1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sam Claflin, Timothy Spall, Hugh Bonneville, Noel Clarke, Charlie Murphy, Joe Claflin', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (206419, 'The Two Popes', 'Drama', 2019, 'Fernando Meirelles', 'Behind Vatican walls, the conservative Pope Benedict XVI and the liberal future Pope Francis must find common ground to forge a new path for the Catholic Church.', 'https://m.media-amazon.com/images/M/MV5BN2NlYjdkOGEtMGYyOC00MzM5LWE5MzYtYzUyZjE3NTM5NGIyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Anthony Hopkins, Jonathan Pryce, Juan Minujín, Luis Gnecco, Cristina Banegas, María Ucedo', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (206451, 'Bad Education', 'Comedy,Drama', 2019, 'Cory Finley', 'The beloved superintendent of New York\'s Roslyn school district and his staff, friends and relatives become the prime suspects in the unfolding of the single largest public school embezzlement scandal in American history.', 'https://m.media-amazon.com/images/M/MV5BMTc4NzU0ZWMtZDBhNC00MWE3LTk5ZmQtMWFlYjE1ODQwZTU2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Hugh Jackman, Ray Romano, Welker White, Allison Janney, Annaleigh Ashford, Stephanie Kurtzuba', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (206499, 'Between Two Ferns: The Movie', 'Comedy', 2019, 'Scott Aukerman', 'Zach Galifianakis and his oddball crew take a road trip to complete a series of high-profile celebrity interviews.', 'https://m.media-amazon.com/images/M/MV5BMGRhMmFmODItYzkwZS00MzAyLTk3NjEtYjNiNzg0ZTdhOTZmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Zach Galifianakis, Matthew McConaughey, Rekha Shankar, Olivia Mekdara, Mo Zelof, Gabriel Gundacker', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (206857, 'The Irishman', 'Crime,Drama', 2019, 'Martin Scorsese', 'An illustration of Frank Sheeran\'s life, from W.W.II veteran to hit-man for the Bufalino crime family and his alleged assassination of his close friend Jimmy Hoffa.', 'https://m.media-amazon.com/images/M/MV5BMTY2YThkNmQtOWJhYy00ZDc3LWEzOGEtMmQwNzM0YjFmZWIyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert De Niro, Al Pacino, Joe Pesci, Harvey Keitel, Ray Romano, Bobby Cannavale', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (207233, 'Jumanji: The Next Level', 'Action,Adventure,Comedy,Fantasy', 2019, 'Jake Kasdan', 'In Jumanji: The Next Level, the gang is back but the game has changed. As they return to rescue one of their own, the players will have to brave parts unknown from arid deserts to snowy mountains, to escape the world\'s most dangerous game.', 'https://m.media-amazon.com/images/M/MV5BYWFjODExZWEtYzIwYS00M2YwLTk4YTktNDQ5ZmVmOThiNmI1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dwayne Johnson, Kevin Hart, Jack Black, Karen Gillan, Awkwafina, Nick Jonas', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (207309, 'Fractured', 'Thriller', 2019, 'Brad Anderson', 'A couple stops at a gas station, where their 6 y.o. daughter\'s arm is fractured. They hurry to a hospital. Something strange is going on there. The wife and daughter go missing.', 'https://m.media-amazon.com/images/M/MV5BMDViOTQwZDMtNjBiMS00YzU4LTllNGUtM2YwNjk4NGMwOTk3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sam Worthington, Lily Rabe, Lucy Capri, Adjoa Andoh, Stephen Tobolowsky, Lauren Cochrane', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (207313, 'Knives Out', 'Comedy,Crime,Drama,Mystery,Thriller', 2019, 'Rian Johnson', 'When renowned crime novelist Harlan Thrombey is found dead at his estate just after his 85th birthday, the inquisitive and debonair Detective Benoit Blanc is mysteriously enlisted to investigate.', 'https://m.media-amazon.com/images/M/MV5BZDU5ZTRkYmItZjg0Mi00ZTQwLThjMWItNWM3MTMxMzVjZmVjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Daniel Craig, Chris Evans, Ana de Armas, Jamie Lee Curtis, Michael Shannon, Don Johnson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (207405, 'Doctor Sleep', 'Horror', 2019, 'Mike Flanagan', 'Years following the events of The Shining (1980), a now-adult Dan Torrance must protect a young girl with similar powers from a cult known as The True Knot, who prey on children with powers to remain immortal.', 'https://m.media-amazon.com/images/M/MV5BNGUyNTg0NWItODdkZS00YWY0LTljNjItMDYwMTI1ZmZkMjExXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ewan McGregor, Rebecca Ferguson, Kyliegh Curran, Cliff Curtis, Zahn McClarnon, Emily Alyn Lind', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (208108, 'Dark Waters', 'Drama', 2019, 'Todd Haynes', 'A corporate defense attorney takes on an environmental lawsuit against a chemical company that exposes a lengthy history of pollution.', 'https://m.media-amazon.com/images/M/MV5BNmQzM2M4MTEtZjM3Yy00Njk1LWJmNjQtYzg4YjVmZmZkZDA0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mark Ruffalo, Anne Hathaway, Tim Robbins, Bill Pullman, Bill Camp, Victor Garber', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (208205, 'Star Wars: The Rise of Skywalker', 'Action,Adventure,Sci-Fi', 2019, 'J.J. Abrams', 'The surviving Resistance faces the First Order once again.', 'https://m.media-amazon.com/images/M/MV5BODg5ZTNmMTUtYThlNy00NjljLWE0MGUtYmQ1NDg4NWU5MjQ1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Carrie Fisher, Mark Hamill, Adam Driver, Daisy Ridley, John Boyega, Oscar Isaac', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (208289, 'Richard Jewell', 'Drama', 2019, 'Clint Eastwood', 'Security guard Richard Jewell is an instant hero after foiling a bomb attack at the 1996 Atlanta Olympics, but his life becomes a nightmare when the FBI leaks to the media that he is a suspect in the case.', 'https://m.media-amazon.com/images/M/MV5BMjI3ZThhNTYtM2ZlMy00OWMwLTk3M2MtM2IyYzYzN2IwMDA2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Paul Walter Hauser, Sam Rockwell, Brandon Stanley, Ryan Boz, Charles Green, Olivia Wilde', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (208429, 'The Banker', 'Drama', 2019, 'George Nolfi', 'In the 1960s, two African-American entrepreneurs hire a working-class white man to pretend to be the head of their business empire while they pose as a janitor and chauffeur.', 'https://m.media-amazon.com/images/M/MV5BZTRiY2YyNmYtY2M4My00MDBkLWE4ZDctZDlmMWQ4ZjMzZjQ2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Anthony Mackie, Samuel L. Jackson, Nicholas Hoult, Nia Long, Scott Daniel Johnson, Jessie T. Usher', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (208469, 'Just Mercy', 'Drama', 2019, 'Destin Daniel Cretton', 'World-renowned civil rights defense attorney Bryan Stevenson works to free a wrongly condemned death row prisoner.', 'https://m.media-amazon.com/images/M/MV5BNmJmYmUyODctZDU2Mi00NDhlLWFmYWYtZDcxZmZhMzUxZTFhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jamie Foxx, Charlie Pye Jr., Michael Harding, Christopher Wolfe, Michael B. Jordan, J. Alphonse Nicholson', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (208621, 'Color Out of Space', 'Horror,Sci-Fi', 2019, 'Richard Stanley', 'A secluded farm is struck by a strange meteorite which has apocalyptic consequences for the family living there and possibly the world.', 'https://m.media-amazon.com/images/M/MV5BNmNlNDMwNzUtYzJlOC00MjRkLTkyNjYtZjY3NTk1NjZlZGMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nicolas Cage, Joely Richardson, Madeleine Arthur, Elliot Knight, Tommy Chong, Brendan Meyer', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (208703, '1917', 'Drama,War', 2019, 'Sam Mendes', 'April 6th, 1917. As an infantry battalion assembles to wage war deep in enemy territory, two soldiers are assigned to race against time and deliver a message that will stop 1,600 men from walking straight into a deadly trap.', 'https://m.media-amazon.com/images/M/MV5BYzkxZjg2NDQtMGVjMy00NWZkLTk0ZDEtZWE3NDYwYjAyMTg1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dean-Charles Chapman, George MacKay, Daniel Mays, Colin Firth, Pip Carter, Andy Apollo', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (209173, 'A Beautiful Day in the Neighborhood', 'Drama', 2019, 'Marielle Heller', 'Lloyd Vogel, a cynical journalist, gets acquainted with a kind-hearted television host Fred Rogers while writing an article on him. With time, they strike an unlikely friendship.', 'https://m.media-amazon.com/images/M/MV5BMzE5MjVhNDMtMDJhYi00NDJhLWFmZjQtNzc2MWFkYmIzYzU4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Matthew Rhys, Chris Cooper, Susan Kelechi Watson, Maryann Plunkett, Enrico Colantoni', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (209315, 'Little Women', 'Drama,Romance', 2019, 'Greta Gerwig', 'In 19th century Massachusetts, the March sisters--Meg, Jo, Beth, and Amy--on the threshold of womanhood, go through many ups and downs in life and endeavor to make important decisions about their futures.', 'https://m.media-amazon.com/images/M/MV5BMWMzYjNiZWMtMDg4NS00MDgyLTk5MWItOTFmNjg4NzRhZmExXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Saoirse Ronan, Emma Watson, Florence Pugh, Eliza Scanlen, Laura Dern, Timothée Chalamet', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (209497, 'The Vast of Night', 'Fantasy,Mystery,Sci-Fi', 2019, 'Andrew Patterson', 'One night in New Mexico, in the late 1950s, a switchboard operator and radio DJ start hearing a strange signal over a radio frequency.', 'https://m.media-amazon.com/images/M/MV5BNGI1OGQ0Y2YtY2RmNi00MmJmLThhYzktNWU2NWRkMGNkNzRiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sierra McCormick, Jake Horowitz, Gail Cronauer, Bruce Davis, Cheyenne Barton, Mark Banik', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (209917, 'Bombshell', 'Drama', 2019, 'Jay Roach', 'A group of women take on Fox News head Roger Ailes and the toxic atmosphere he presided over at the network.', 'https://m.media-amazon.com/images/M/MV5BODY3ODVkYTAtZDFmNS00ZDYyLTlkOTEtNTY3NTFhNDE4ZjFjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Charlize Theron, Nicole Kidman, Margot Robbie, John Lithgow, Allison Janney, Malcolm McDowell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (209965, 'Uncut Gems', 'Comedy,Crime,Drama,Thriller', 2019, 'Benny Safdie', 'With his debts mounting and angry collectors closing in, a fast-talking New York City jeweler risks everything in hope of staying afloat and alive.', 'https://m.media-amazon.com/images/M/MV5BNmI0YjA5NjItYzExYi00NzkxLTkxNDctNGJjYTZhM2M0NDQ0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mesfin Lamengo, Sun Zhi Hua-Hilton, Liang Wei-Hui-Duncan, Sunny Wu Jin Zahao, Deneke Muhugeta, Habtunu Africho', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (210271, '6 Underground', 'Action,Adventure,Thriller', 2019, 'Michael Bay', 'It follows a group of people who fake their deaths and decide to form a vigilante team in order to stage a coup d\'état against a ruthless dictator.', 'https://m.media-amazon.com/images/M/MV5BNTNmZDgzMmMtMzJhMy00NGI3LWI5YTktYjg5MTllZmYyYTMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ryan Reynolds, Mélanie Laurent, Manuel Garcia-Rulfo, Ben Hardy, Adria Arjona, Dave Franco', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (210571, 'Fantasy Island', 'Fantasy,Horror,Sci-Fi', 2020, 'Jeff Wadlow', 'When the owner and operator of a luxurious island invites a collection of guests to live out their most elaborate fantasies in relative seclusion, chaos quickly descends.', 'https://m.media-amazon.com/images/M/MV5BMjhiNGM2NGQtNDlkNi00NTg4LWFlNTctMTE0ODNlOWY3NWI5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Peña, Maggie Q, Lucy Hale, Austin Stowell, Jimmy O. Yang, Portia Doubleday', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (210859, 'Run', 'Thriller', 2020, 'Aneesh Chaganty', 'Chloe, a teenager who is confined to a wheelchair, is homeschooled by her mother, Diane. Chloe soon becomes suspicious of her mother and begins to suspect that she may be harboring a dark secret.', 'https://m.media-amazon.com/images/M/MV5BOTViNDViNDgtNDc0Ny00NWZkLTljMzctYjgzNzI5MTYwZjJlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sarah Paulson, Kiera Allen, Sara Sohn, Pat Healy, Erik Athavale, BJ Harrison', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (210861, 'The Gentlemen', 'Action,Crime', 2020, 'Guy Ritchie', 'An American expat tries to sell off his highly profitable marijuana empire in London, triggering plots, schemes, bribery and blackmail in an attempt to steal his domain out from under him.', 'https://m.media-amazon.com/images/M/MV5BMjE2ZjQ4ZGMtZjFhMi00NmI5LTliNjEtODczMWMxNjliZjgxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matthew McConaughey, Charlie Hunnam, Michelle Dockery, Jeremy Strong, Lyne Renée, Colin Farrell', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (210865, 'Bad Boys for Life', 'Action,Crime,Thriller', 2020, 'Adil El Arbi', 'Miami detectives Mike Lowrey and Marcus Burnett must face off against a mother-and-son pair of drug lords who wreak vengeful havoc on their city.', 'https://m.media-amazon.com/images/M/MV5BYzM3ZTFmMTUtODAxNy00N2IxLWI2MGMtYTdmMDFhNmZkMDI3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Will Smith, Martin Lawrence, Vanessa Hudgens, Alexander Ludwig, Charles Melton, Paola Núñez', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (212281, 'Mulan', 'Adventure,Drama,Fantasy', 2020, 'Niki Caro', 'To keep her ailing father from serving in the Imperial Army, a fearless young woman disguises herself as a man and battles northern invaders in China.', 'https://m.media-amazon.com/images/M/MV5BYWJiZDg3ZWEtYWZkMC00Zjc1LTkzYTctZWFkODk2MDlmOGNiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Yifei Liu, Donnie Yen, Gong Li, Jet Li, Jason Scott Lee, Yoson An', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (212371, 'The New Mutants', 'Action,Horror,Sci-Fi', 2020, 'Josh Boone', 'Five young mutants, just discovering their abilities while held in a secret facility against their will, fight to escape their past sins and save themselves.', 'https://m.media-amazon.com/images/M/MV5BZGVlMjBkYmMtZDhmYS00N2QyLWI2YTgtMDU2N2UwOWYzM2MxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Maisie Williams, Anya Taylor-Joy, Charlie Heaton, Alice Braga, Blu Hunt, Henrique Zaga', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (212373, 'I\'m Thinking of Ending Things', 'Drama,Horror,Thriller', NULL, 'Charlie Kaufman', 'Full of misgivings, a young woman travels with her new boyfriend to his parents\' secluded farm. Upon arriving, she comes to question everything she thought she knew about him, and herself.', 'https://m.media-amazon.com/images/M/MV5BYTgxNWU0MGMtMDI1Ny00NDIwLTllYzYtZDkyOTVmYmFhZGM0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jesse Plemons, Jessie Buckley, Toni Collette, David Thewlis, Guy Boyd, Hadley Robinson', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (212461, 'The Invisible Man', 'Horror,Sci-Fi,Thriller', 2020, 'Leigh Whannell', 'When Cecilia\'s abusive ex takes his own life and leaves her his fortune, she suspects his death was a hoax. As a series of coincidences turn lethal, Cecilia works to prove that she is being hunted by someone nobody can see.', 'https://m.media-amazon.com/images/M/MV5BYTM3NDJhZWUtZWM1Yy00ODk4LThjNmMtNDg3OGYzMGM2OGYzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Elisabeth Moss, Oliver Jackson-Cohen, Harriet Dyer, Aldis Hodge, Storm Reid, Michael Dorman', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (212587, 'Spenser Confidential', 'Crime,Drama,Mystery,Thriller', 2020, 'Peter Berg', 'When two Boston police officers are murdered, ex-cop Spenser teams up with his no-nonsense roommate Hawk to take down criminals.', 'https://m.media-amazon.com/images/M/MV5BMDFiNmViNGUtMWI2NC00OTI0LTg5NjMtZGYwOTlkM2JlZGRmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mark Wahlberg, Winston Duke, Alan Arkin, Iliza Shlesinger, Michael Gaston, Bokeem Woodbine', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (213347, 'A Quiet Place Part II', 'Drama,Sci-Fi,Thriller', 2020, 'John Krasinski', 'Following the events at home, the Abbott family now face the terrors of the outside world. Forced to venture into the unknown, they realize the creatures that hunt by sound are not the only threats lurking beyond the sand path.', 'https://m.media-amazon.com/images/M/MV5BNjRiYjk4ZmItNGQ5NS00MmRhLTk4Y2EtMGQ1MTYxZWJhYjU0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Emily Blunt, John Krasinski, Millicent Simmonds, Noah Jupe, Cillian Murphy, Djimon Hounsou', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (213551, 'ZZ Top: That Little Ol\' Band From Texas', 'Documentary', 2019, 'Sam Dunn', 'The story of how three oddball teenage bluesmen became one of the biggest, most beloved bands on the planet.', 'https://m.media-amazon.com/images/M/MV5BZGJmMmMwMmYtN2EzYy00NGNkLTgzMTEtZWE3YjEwOTI2Zjk5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Billy Gibbons, Dusty Hill, Frank Beard, ZZ Top, Robin Hood Brians, Josh Homme', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (213892, 'The Hunt', 'Action,Horror,Thriller', 2020, 'Craig Zobel', 'Twelve strangers wake up in a clearing. They don\'t know where they are, or how they got there. They don\'t know they\'ve been chosen - for a very specific purpose - The Hunt.', 'https://m.media-amazon.com/images/M/MV5BMjVmMDY4NGMtZTk3Yi00Zjg1LTkxOWYtNGFmNTdjNzYzNDkwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Betty Gilpin, Hilary Swank, Ike Barinholtz, Wayne Duvall, Ethan Suplee, Emma Roberts', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (213898, 'Never Rarely Sometimes Always', 'Drama', 2020, 'Eliza Hittman', 'A pair of teenage girls in rural Pennsylvania travel to New York City to seek out medical help after an unintended pregnancy.', 'https://m.media-amazon.com/images/M/MV5BMjI4ZDA4NDgtNDlkNS00MDEzLWEzNTMtZDJjMGRkNzg3MjE4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Eliazar Jimenez, David Buneta, Christian Clements, Sam Dugger, Talia Ryder, Sharon Van Etten', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (213914, 'Greyhound', 'War', 2020, 'Aaron Schneider', 'Several months after the U.S. entry into World War II, an inexperienced U.S. Navy commander must lead an Allied convoy being stalked by a German submarine wolf pack.', 'https://m.media-amazon.com/images/M/MV5BZTU3YzY0NjktMmRhMC00MzYyLWI0YmUtZGJkMzJjMWYwZDZkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hanks, Elisabeth Shue, Stephen Graham, Matt Helm, Craig Tate, Rob Morgan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (214776, 'Extraction', 'Action,Thriller', 2020, 'Sam Hargrave', 'Tyler Rake, a fearless black market mercenary, embarks on the most deadly extraction of his career when he\'s enlisted to rescue the kidnapped son of an imprisoned international crime lord.', 'https://m.media-amazon.com/images/M/MV5BNDBhMmI3OWYtZTA2Ny00Y2RjLTliMWQtYWY5MGIwN2RlZGFjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chris Hemsworth, Bryon Lerum, Ryder Lerum, Rudhraksh Jaiswal, Shivam Vichare, Piyush Khati', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (214951, 'Only', 'Drama,Romance,Sci-Fi', 2020, 'Takashi Doscher', 'After a comet releases a mysterious virus that begins to kill all the women in the world, a young couple hides out in their over-sterilized apartment trying to fight for their lives.', 'https://m.media-amazon.com/images/M/MV5BNmQ1M2FiODItMmMzZC00NTY4LTlhNTMtMmI1YjkzMzIzZWYwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Freida Pinto, Leslie Odom Jr., Chandler Riggs, Jayson Warner Smith, Joshua Mikel, Mark Ashworth', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (215353, 'Minari', 'Drama', 2020, 'Lee Isaac Chung', 'A Korean American family moves to an Arkansas farm in search of its own American dream. Amidst the challenges of new life in the strange and rugged Ozarks, they discover the undeniable resilience of family and what really makes a home.', 'https://m.media-amazon.com/images/M/MV5BNWVmNDE3YzMtZWQ3Ny00YjhkLWEzN2QtZjNhYWNlMGI2N2NkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Alan Kim, Han Ye-ri, Noel Cho, Steven Yeun, Darryl Cox, Esther Moon', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (215525, 'Artemis Fowl', 'Adventure,Children,Fantasy,Sci-Fi', 2020, 'Kenneth Branagh', 'Artemis Fowl, a young criminal prodigy, hunts down a secret society of fairies to find his missing father.', 'https://m.media-amazon.com/images/M/MV5BMzhmMGViNTctMjE1Ny00N2JlLWFiNmEtMDBiYjRmMzU2NTMyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Rouse, Racheal Ofori, Josh Gad, Ferdia Shaw, Simone Kirby, Joe O\'Grady', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (215707, 'Circus of Books', 'Documentary', 2019, 'Rachel Mason', 'In 1976, Karen and Barry Mason had fallen on hard times and were looking for a way to support their young family when they answered an ad in the Los Angeles Times. Larry Flynt was seeking distributors for Hustler Magazine. What was expected to be a brief sideline led to their bec...Read all', 'https://m.media-amazon.com/images/M/MV5BNjQ4MTZhNjMtZjE2My00ZjA5LTg5NjctYWQ1YjA4N2UxMTkwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Karen Mason, Barry Mason, Micah Mason, Rachel Mason, Josh Mason, Fernando Aguilar', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (215711, 'The Sputnik', 'Drama,Sci-Fi,Thriller', 2020, 'Egor Abramenko', 'The lone survivor of an enigmatic spaceship incident hasn\'t returned home alone - hiding inside his body is a dangerous creature.', 'https://m.media-amazon.com/images/M/MV5BZGZlMjYwYTctOWVmZS00MzczLWI0MWEtZDZmZWFjNmY0ODljXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Oksana Akinshina, Fedor Bondarchuk, Pyotr Fyodorov, Anton Vasilev, Aleksey Demidov, Anna Nazarova', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (216107, 'A Secret Love', 'Documentary', 2020, 'Chris Bolan', 'Falling in love in 1947, two women -- Pat Henschel and pro baseball player Terry Donahue -- begin a 65-year journey of love and overcoming prejudice.', 'https://m.media-amazon.com/images/M/MV5BY2Q3ZWU2N2YtMThkZi00YWJmLTg5MzUtN2IxZDg0OGU5MDI3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Terry Donahue, Pat Henschel, Diana Bolan, Kim Donahue, Tammy Donahue, Jack Xagas', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (216402, 'The King of Staten Island', 'Comedy,Drama', 2020, 'Judd Apatow', 'Scott has been a case of arrested development since his firefighter dad died. He spends his days smoking weed and dreaming of being a tattoo artist until events force him to grapple with his grief and take his first steps forward in life.', 'https://m.media-amazon.com/images/M/MV5BMGNiYzcwNDItMjc2OS00OWE5LWJkMGUtNjhhNDgwZjBhZjBiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Pete Davidson, Bel Powley, Ricky Velez, Lou Wilson, Moises Arias, Carly Aquilino', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (216745, 'The Wrong Missy', 'Comedy,Romance', 2020, 'Tyler Spindel', 'Tim thinks he\'s invited the woman of his dreams on a work retreat to Hawaii, realizing too late he mistakenly texted someone from a nightmare blind date.', 'https://m.media-amazon.com/images/M/MV5BYzlhOGQ0YzEtNTgzOS00NGZjLWFkMmEtOGU1MWU0ZWEzOTZhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'David Spade, Lauren Lapkus, Nick Swardson, Geoff Pierson, Jackie Sandler, Molly Sims', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (216817, 'Scoob!', 'Adventure,Animation,Children,Comedy,Mystery', 2020, 'Tony Cervone', 'Scooby and the gang face their most challenging mystery ever: a plot to unleash the ghost dog Cerberus upon the world. As they race to stop this dogpocalypse, the gang discovers that Scooby has an epic destiny greater than anyone imagined.', 'https://m.media-amazon.com/images/M/MV5BNzUzMDk2ZDQtNWQ2ZC00NmQ0LTg2ODItZDc0MjA3YzVhNTE5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Will Forte, Mark Wahlberg, Jason Isaacs, Gina Rodriguez, Zac Efron, Amanda Seyfried', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (216937, 'Da 5 Bloods', 'Drama,War', 2020, 'Spike Lee', 'Four black veterans battle the forces of man and nature when they return to Vietnam seeking the remains of their fallen squad leader and the gold fortune he helped them hide.', 'https://m.media-amazon.com/images/M/MV5BNjIwN2IxODEtNDhhMi00NDEwLWIwODEtYjIzZDVhZjg0Y2MyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Delroy Lindo, Jonathan Majors, Clarke Peters, Norm Lewis, Isiah Whitlock Jr., Mélanie Thierry', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (217079, 'Patton Oswalt: I Love Everything', 'Comedy', 2020, 'Marcus Raboy', 'Turning 50. Finding love again. Buying a house. Experiencing existential dread at Denny\'s. Life comes at Patton Oswalt fast in this stand-up special.', 'https://m.media-amazon.com/images/M/MV5BODIyNzIxY2UtNmRjYS00NmIxLWJmOWUtMDM1MjEwMjM1ZWRmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Patton Oswalt, Bob Rubin', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (217465, 'Tenet', 'Action,Thriller', 2020, 'Christopher Nolan', 'Armed with only the word \"Tenet,\" and fighting for the survival of the entire world, CIA operative, The Protagonist, journeys through a twilight world of international espionage on a global mission that unfolds beyond real time.', 'https://m.media-amazon.com/images/M/MV5BNTIzNDIxMzktMzlkMi00MmUyLWFmMjQtZDgwMjBmOGJmNTI3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Juhan Ulfsak, Jefferson Hall, Ivo Uukkivi, Andrew Howard, John David Washington, Rich Ceraulo Ko', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (218537, 'Palm Springs', 'Comedy', 2020, 'Max Barbakow', 'Nyles and Sarah find themselves stuck in a time loop and living the same day over and over again. They are drawn to each other, but certain revelations threaten their budding romance.', 'https://m.media-amazon.com/images/M/MV5BY2VkNGY0MTMtMjEzZi00OThkLWJiOTMtNGU4ZGNjZDE5ZGIyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Andy Samberg, Cristin Milioti, J.K. Simmons, Peter Gallagher, Meredith Hagner, Camila Mendes', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (218867, 'Ava', 'Action,Crime,Drama,Mystery,Thriller', NULL, 'Tate Taylor', 'Ava is a deadly assassin who works for a black ops organization, traveling the globe specializing in high profile hits. When a job goes dangerously wrong she is forced to fight for her own survival.', 'https://m.media-amazon.com/images/M/MV5BMjgxYjI0NzUtYTUzOC00ZDQwLThhMzItZThjMjU1YTBjM2MxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jessica Chastain, John Malkovich, Common, Geena Davis, Jess Weixler, Ioan Gruffudd', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (219726, 'The Old Guard', 'Action,Fantasy', 2020, 'Gina Prince-Bythewood', 'A covert group of tight-knit mercenaries with an inability to die have fought to protect the world for centuries. But when their abilities are suddenly exposed, they need to eliminate the threat of those who seek to replicate their power.', 'https://m.media-amazon.com/images/M/MV5BYzMwNjVjNTEtZDVhOC00NzQzLTg0MGYtMGI1Yzc0Nzg2MjNmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Charlize Theron, KiKi Layne, Matthias Schoenaerts, Marwan Kenzari, Luca Marinelli, Chiwetel Ejiofor', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (220528, 'Twelve Angry Men', 'Drama', 1954, 'Franklin J. Schaffner', 'The jurors in a murder trial take their seats in a small, drab room to decide the defendant\'s fate. At first, all the men vote guilty bar one, who still has many questions not answered in court. Through theories and re-enactments, others change their minds, but one man is adamant...Read all', 'https://m.media-amazon.com/images/M/MV5BMjAxOTJhYWItNDNjZi00ZGM5LTk5ODEtZGU2NDdhM2E5N2UwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert Cummings, Franchot Tone, Edward Arnold, Paul Hartman, John Beal, Walter Abel', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (220792, 'Project Power', 'Action,Crime,Sci-Fi', 2020, 'Henry Joost', 'When a pill that gives its users unpredictable superpowers for five minutes hits the streets of New Orleans, a teenage dealer and a local cop must team with an ex-soldier to take down the group responsible for its creation.', 'https://m.media-amazon.com/images/M/MV5BM2QxNjM4YTAtMjY1Yi00YjMwLTlkOWUtZmIzYmZmNzUwNDU1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jamie Foxx, Joseph Gordon-Levitt, Dominique Fishback, Rodrigo Santoro, Courtney B. Vance, Amy Landecker', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (221576, 'Enola Holmes', 'Drama,Mystery', NULL, 'Harry Bradbeer', 'When Enola Holmes, Sherlock\'s sister, discovers her mother is missing, she endeavors to find her, becoming a super-sleuth in her own right as she outwits her famous brother and unravels a dangerous conspiracy.', 'https://m.media-amazon.com/images/M/MV5BMTRlYmI1NTMtYTVkYi00MjJkLWE3ZGItOThkYTdhNzBhMThhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Millie Bobby Brown, Henry Cavill, Sam Claflin, Helena Bonham Carter, Louis Partridge, Burn Gorman', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (222011, 'Greenland', 'Action,Sci-Fi,Thriller', 2020, 'Ric Roman Waugh', 'To save his family from a catastrophic end of times, John embarks on a risky quest to locate the last hope for salvation and witness the worst of mankind in the battle for survival.', 'https://m.media-amazon.com/images/M/MV5BZWZjZGMwNmUtYmRiMS00ODEwLTgyYjQtOGUzMDNhOGU3OGQ0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gerard Butler, Morena Baccarin, Roger Dale Floyd, Scott Glenn, Randal Gonzalez, Rick Pasqualone', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (222477, 'Wonder Woman 1984', 'Action,Adventure,Fantasy', 2020, 'Patty Jenkins', 'Wonder Woman finds herself battling two opponents, Maxwell Lord, a shrewd entrepreneur, and Barbara Minerva, a friend-turned-foe. Meanwhile, she also ends up crossing paths with her love interest.', 'https://m.media-amazon.com/images/M/MV5BYTdkYjI0M2ItMmUxZi00YjU1LTgwM2ItODgxNDY0ODZhZDQzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gal Gadot, Chris Pine, Kristen Wiig, Pedro Pascal, Robin Wright, Connie Nielsen', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (223204, 'The French Dispatch', 'Comedy,Drama,Romance', 2020, 'Wes Anderson', 'A collection of stories published in \"The French Dispatch Magazine\" comes to life in a fictional twentieth century French city.', 'https://m.media-amazon.com/images/M/MV5BMTU1YmNkZWYtYmExNC00YWE1LTk2NWEtMTQ2ODhmYTA5MmZiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Benicio Del Toro, Adrien Brody, Tilda Swinton, Léa Seydoux, Frances McDormand, Timothée Chalamet', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (223876, 'My Octopus Teacher', 'Documentary', 2020, 'Pippa Ehrlich', 'A filmmaker forges an unusual friendship with an octopus living in a South African kelp forest, learning as the animal shares the mysteries of her world.', 'https://m.media-amazon.com/images/M/MV5BYWU5OGMxYjktMWY5Ny00NDJhLTgwMDktNjVmMTExZGIyODljXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Craig Foster, Tom Braden Foster', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (224052, 'Wolfwalkers', 'Adventure,Animation,Drama', 2020, 'Tomm Moore', 'A young apprentice hunter and her father journey to Ireland to help wipe out the last wolf pack. But everything changes when she befriends a free-spirited girl from a mysterious tribe rumored to transform into wolves by night.', 'https://m.media-amazon.com/images/M/MV5BYzg3MjBkYmYtZjZkZS00YWVkLTk3YjMtNDBlMTVmNDZkZDJhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Honor Kneafsey, Eva Whittaker, Sean Bean, Simon McBurney, Tommy Tiernan, Maria Doyle Kennedy', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (224220, 'Freaky', 'Comedy,Horror,Thriller', 2020, 'Christopher Landon', 'After swapping bodies with a deranged serial killer, a high-school senior discovers that she has fewer than 24 hours before the change becomes permanent.', 'https://m.media-amazon.com/images/M/MV5BODZmNzJjNjAtOGFhNi00ZjhjLTg5MzgtYjRjNGE0YWE3NDUzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Vince Vaughn, Kathryn Newton, Celeste O\'Connor, Misha Osherovich, Emily Holder, Nicholas Stargel', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (224262, 'Love and Monsters', 'Adventure', 2020, 'Michael Matthews', 'Seven years after he survived the monster apocalypse, lovably hapless Joel leaves his cozy underground bunker behind on a quest to reunite with his high school sweetheart.', 'https://m.media-amazon.com/images/M/MV5BN2I1MGNiOWMtYmFlNC00MDYxLTkzODEtZDhiMTg5MjYzNTQxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dylan O\'Brien, Jessica Henwick, Michael Rooker, Dan Ewing, Ariana Greenblatt, Ellen Hollman', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (224266, 'Hubie Halloween', 'Comedy', 2020, 'Steven Brill', 'Despite his devotion to his hometown of Salem (and its Halloween celebration), Hubie Dubois is a figure of mockery for kids and adults alike. But this year, something is going bump in the night, and it\'s up to Hubie to save Halloween.', 'https://m.media-amazon.com/images/M/MV5BZTlkMDdiNmUtOTQwYS00ZTE5LWJlMWEtNzMyN2M2MWIzZTMzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Adam Sandler, Kevin James, Julie Bowen, Ray Liotta, Steve Buscemi, Rob Schneider', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (224943, 'I Care a Lot', 'Drama,Thriller', 2020, 'J Blakeson', 'A crooked legal guardian who drains the savings of her elderly wards meets her match when a woman she tries to swindle turns out to be more than she first appears.', 'https://m.media-amazon.com/images/M/MV5BNTg5M2NlZDItMmI5Yi00N2VmLTgyYmMtNDgzMzQ2ZjlmNzg5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Rosamund Pike, Peter Dinklage, Eiza González, Dianne Wiest, Chris Messina, Isiah Whitlock Jr.', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (225173, 'Soul', 'Adventure,Animation,Children,Comedy,Fantasy', 2020, 'Pete Docter', 'Joe is a middle-school band teacher whose life hasn\'t quite gone the way he expected. His true passion is jazz. But when he travels to another realm to help someone find their passion, he soon discovers what it means to have soul.', 'https://m.media-amazon.com/images/M/MV5BZTZkYjA5MDEtMjY1ZC00ODk5LThjOTUtZDYxODEzYWNjMTU2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jamie Foxx, Tina Fey, Graham Norton, Rachel House, Alice Braga, Richard Ayoade', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (225625, 'Borat Subsequent Moviefilm', 'Comedy', 2020, 'Jason Woliner', 'Borat returns to America from Kazakhstan to America, this time to reveal more about the American culture, the COVID-19 pandemic, and the political elections.', 'https://m.media-amazon.com/images/M/MV5BOWJmNDcyOTItYTE0ZS00NzAwLThjNGUtYTdhMjBjMTAwNDc4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sacha Baron Cohen, Maria Bakalova, Tom Hanks, Dani Popescu, Manuel Vieru, Miroslav Tolj', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (225984, 'Another Round', 'Drama', 2020, 'Thomas Vinterberg', 'Four high-school teachers consume alcohol on a daily basis to see how it affects their social and professional lives.', 'https://m.media-amazon.com/images/M/MV5BNjYxN2EwYjUtNzdiOS00NTgwLTgwNzMtZmE1NGMzYTYxNzBjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Mads Mikkelsen, Thomas Bo Larsen, Magnus Millang, Lars Ranthe, Maria Bonnevie, Helene Reingaard Neumann', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (226202, 'Free Guy', 'Action,Adventure,Comedy,Sci-Fi', 2020, 'Shawn Levy', 'When Guy, a bank teller, learns that he is a non-player character in a bloodthirsty, open-world video game, he goes on to become the hero of the story and takes the responsibility of saving the world.', 'https://m.media-amazon.com/images/M/MV5BN2I0MGMxYjUtZTZiMS00MzMxLTkzNWYtMDUyZmUwY2ViYTljXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ryan Reynolds, Jodie Comer, Lil Rel Howery, Joe Keery, Utkarsh Ambudkar, Taika Waititi', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (226270, 'The Trial of the Chicago 7', 'Drama,Thriller', 2020, 'Aaron Sorkin', 'The story of 7 people on trial stemming from various charges surrounding the uprising at the 1968 Democratic National Convention in Chicago, Illinois.', 'https://m.media-amazon.com/images/M/MV5BZjY2ZGFlOTgtOGQ1MS00YWJhLWIyZjQtNWNmNTQ0YTk0MTZjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Eddie Redmayne, Alex Sharp, Sacha Baron Cohen, Jeremy Strong, John Carroll Lynch, Yahya Abdul-Mateen II', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (227258, 'The Midnight Sky', 'Drama,Fantasy,Sci-Fi', 2020, 'George Clooney', 'This post-apocalyptic tale follows Augustine, a lonely scientist in the Arctic, as he races to stop Sully and her fellow astronauts from returning home to a mysterious global catastrophe.', 'https://m.media-amazon.com/images/M/MV5BMTE2NzJiM2UtZGRiMy00M2Q2LWFmZTAtYmI0MzVmZThkYTFhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'George Clooney, Felicity Jones, David Oyelowo, Caoilinn Springall, Kyle Chandler, Demián Bichir', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (235509, 'Outside the Wire', 'Action,Sci-Fi,Thriller', 2021, 'Mikael Håfström', 'In the near future, a drone pilot sent into a war zone finds himself paired with a top-secret android officer on a mission to stop a nuclear attack.', 'https://m.media-amazon.com/images/M/MV5BZTM2ZTFjMTctNmJjNS00OTkwLWIxOWEtY2NjMDI3NTJmNmMxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Anthony Mackie, Damson Idris, Enzo Cilenti, Emily Beecham, Michael Kelly, Kristina Tonteri-Young', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (237227, 'Raya and the Last Dragon', 'Action,Adventure,Animation,Children,Fantasy', 2021, 'Paul Briggs', 'In a realm known as Kumandra, a re-imagined Earth inhabited by an ancient civilization, a warrior named Raya is determined to find the last dragon.', 'https://m.media-amazon.com/images/M/MV5BN2QzZTQ3MzktN2JiYS00MDEzLTgxMWQtZWFmMDI3NWFkZTY0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kelly Marie Tran, Awkwafina, Izaac Wang, Gemma Chan, Daniel Dae Kim, Benedict Wong', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (237372, 'Coming 2 America', 'Children,Comedy', 2021, 'Craig Brewer', 'The African monarch Akeem learns he has a long-lost son in the United States and must return to America to meet this unexpected heir and build a relationship with his son.', 'https://m.media-amazon.com/images/M/MV5BN2NhODZjMTktOGNmOC00OTllLTk3NWItYzNiNmRlNTYwMTcxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Eddie Murphy, Arsenio Hall, Jermaine Fowler, Leslie Jones, Tracy Morgan, KiKi Layne', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (240270, 'Willy\'s Wonderland', 'Action,Comedy,Horror,Thriller', 2021, 'Kevin Lewis', 'A quiet drifter is tricked into a janitorial job at the now condemned Willy\'s Wonderland. The mundane tasks suddenly become an all-out fight for survival against wave after wave of demonic animatronics. Fists fly, kicks land, titans clash -- and only one side will make it out ali...Read all', 'https://m.media-amazon.com/images/M/MV5BOGUxOTQ4ZjItOTExNi00MzIzLTkzMTUtMjkxNDFiNTUzM2U0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nicolas Cage, Emily Tosta, Beth Grant, Ric Reitz, Chris Warner, Catherine Caylee Cowan', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (240452, 'Mortal Kombat', 'Action,Adventure,Fantasy', 2021, 'Simon McQuoid', 'MMA fighter Cole Young seeks out Earth\'s greatest champions in order to stand against the enemies of Outworld in a high stakes battle for the universe.', 'https://m.media-amazon.com/images/M/MV5BNmRmN2I5M2EtNDA1Ny00N2ZmLWE3YWYtMjQ1NTFjY2Q4NWM5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Lewis Tan, Jessica McNamee, Josh Lawson, Joe Taslim, Mehcad Brooks, Matilda Kimber', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (241272, 'Nobody', 'Action,Crime,Thriller', 2021, 'Ilya Naishuller', 'A docile family man slowly reveals his true character after his house gets burgled by two petty thieves, which, coincidentally, leads him into a bloody war with a Russian crime boss.', 'https://m.media-amazon.com/images/M/MV5BYmIzOWViNDEtOWRiZS00ZWM4LWFiMmEtNGJjMmQ3NTIxN2U0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Bob Odenkirk, Aleksey Serebryakov, Connie Nielsen, Christopher Lloyd, Michael Ironside, Colin Salmon', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (241960, 'Moxie', 'Comedy,Drama', 2021, 'Amy Poehler', 'Inspired by her mom\'s rebellious past and a confident new friend, a shy 16-year-old publishes an anonymous zine calling out sexism at her school.', 'https://m.media-amazon.com/images/M/MV5BZTQ0NzIzYmEtZWQyYS00NGQ3LTlkNTctNWIxODIwZTkyOTI0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Hadley Robinson, Lauren Tsai, Alycia Pascual-Pena, Nico Hiraga, Sabrina Haskett, Patrick Schwarzenegger', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (242774, 'Black Widow', 'Action,Adventure,Drama,Thriller', 2021, 'Cate Shortland', 'Natasha Romanoff confronts the darker parts of her ledger when a dangerous conspiracy with ties to her past arises.', 'https://m.media-amazon.com/images/M/MV5BZTMyZTA0ZTItYjY3Yi00ODNjLWExYTgtYzgxZTk0NTg0Y2FlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Scarlett Johansson, Florence Pugh, Rachel Weisz, David Harbour, Ray Winstone, Ever Anderson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (243208, 'Yes Day', 'Children,Comedy', 2021, 'Miguel Arteta', 'A mom and dad who usually say no decide to say yes to their kids\' wildest requests with a few ground rules on a whirlwind day of fun and adventure.', 'https://m.media-amazon.com/images/M/MV5BNjNmYThjN2UtODc3YS00ZDMxLTk1OGItZmM2OTFiMzJiNDg2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jennifer Garner, Edgar Ramírez, Jenna Ortega, Julian Lerner, Everly Carganilla, Tracie Thoms', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (244178, 'The Northman', 'Adventure,Drama,Thriller', NULL, 'Robert Eggers', 'A young Viking prince is on a quest to avenge his father\'s murder.', 'https://m.media-amazon.com/images/M/MV5BYzgwM2JiY2MtNWQ5OC00NDc1LWExMjYtYmY2YjViZmViYWM5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Alexander Skarsgård, Nicole Kidman, Claes Bang, Ethan Hawke, Anya Taylor-Joy, Gustav Lindh', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (251086, 'The Suicide Squad', 'Action,Adventure,Crime,Fantasy', 2021, 'James Gunn', 'Supervillains Harley Quinn, Bloodsport, Peacemaker, and a collection of nutty cons at Belle Reve prison join the super-secret, super-shady Task Force X as they are dropped off at the remote, enemy-infused island of Corto Maltese.', 'https://m.media-amazon.com/images/M/MV5BMWU3Y2NlZmEtMjJjNS00ZWMxLWE1MzctYWYyMjMzMDdkNTE4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Rooker, Viola Davis, John Ostrander, Joel Kinnaman, Nathan Fillion, Jai Courtney', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (251234, 'The Conjuring: The Devil Made Me Do It', 'Horror,Mystery,Thriller', 2021, 'Michael Chaves', 'Arne Cheyenne Johnson stabs and murders his landlord, claiming to be under demonic possession while Ed and Lorraine Warren investigate the case and try to prove his innocence.', 'https://m.media-amazon.com/images/M/MV5BNThkYWE3OGItNzAyNC00N2U4LThjY2QtMGQwYjZhYTI1MzMwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Patrick Wilson, Vera Farmiga, Ruairi O\'Connor, Sarah Catherine Hook, Julian Hilliard, John Noble', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (251388, 'Smiling Friends', 'Animation,Comedy', 2020, 'Zach Hadel', 'In a colorful yet bizarre world, the employees at a small firm dedicated to making its customers smile discover that their jobs are rarely as simple as they seem.', 'https://m.media-amazon.com/images/M/MV5BMjkxOWUzNmEtZTMyMC00Y2Y2LTk2OGUtZjQzNTc0NDg2NGQ5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michael Cusack, Zach Hadel, Marc M., Joshua Tomar, Erica Lindbeck, David Dore', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (252930, 'Old', 'Mystery,Thriller', 2021, 'M. Night Shyamalan', 'A vacationing family discovers that the secluded beach where they\'re relaxing for a few hours is somehow causing them to age rapidly, reducing their entire lives into a single day.', 'https://m.media-amazon.com/images/M/MV5BM2JkZjI5MjktNmQwZC00ZmYxLTg0OTYtYmVhNGFkMGZlMGYyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Gael García Bernal, Vicky Krieps, Rufus Sewell, Alex Wolff, Thomasin McKenzie, Abbey Lee', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (253690, 'The Worst Person in the World', 'Comedy,Drama', 2021, 'Joachim Trier', 'The chronicles of four years in the life of Julie, a young woman who navigates the troubled waters of her love life and struggles to find her career path, leading her to take a realistic look at who she really is.', 'https://m.media-amazon.com/images/M/MV5BZGEyYzBiYmItZDM4OC00NTdmLWJlYzctODdiM2E2MjZmYTU2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Renate Reinsve, Anders Danielsen Lie, Herbert Nordrum, Hans Olav Brenner, Helene Bjørneby, Vidar Sandem', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (254478, 'Kaamelott - The First Chapter', 'Adventure,Comedy', 2021, 'Alexandre Astier', 'The sequel on the big screen to the cult series of Alexandre Astier, an offbeat version of the legend of the Knights of the Round Table. Hidden in Rome, King Arthur plans his comeback to oppose the army of his former friend Lancelot.', 'https://m.media-amazon.com/images/M/MV5BYmEwZmYxYjYtNDVlOC00MTA0LWFmZDktMjZkZThmYTY1ZGViXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Dimitrios Lagopoulos, Sakir Uyar, Guillaume Gallienne, Reggy Vermeulen, Tigran Mekhitarian, Christian Clavier', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (254726, 'Dune', 'Action,Adventure,Drama,Sci-Fi', 2021, 'Denis Villeneuve', 'Paul Atreides arrives on Arrakis after his father accepts the stewardship of the dangerous planet. However, chaos ensues after a betrayal as forces clash to control melange, a precious resource.', 'https://m.media-amazon.com/images/M/MV5BNWIyNmU5MGYtZDZmNi00ZjAwLWJlYjgtZTc0ZGIxMDE4ZGYwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Timothée Chalamet, Rebecca Ferguson, Oscar Isaac, Jason Momoa, Stellan Skarsgård, Stephen McKinley Henderson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (255337, 'Venom: Let There Be Carnage', 'Action,Sci-Fi', 2021, 'Andy Serkis', 'Eddie Brock attempts to reignite his career by interviewing serial killer Cletus Kasady, who becomes the host of the symbiote Carnage and escapes prison after a failed execution.', 'https://m.media-amazon.com/images/M/MV5BZGIxMTU1MjItM2FmMi00YmFiLTgwNDMtMTczYmVjYTBhNGZhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Hardy, Woody Harrelson, Michelle Williams, Naomie Harris, Reid Scott, Stephen Graham', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (257037, 'Drive My Car', 'Drama', 2021, 'Ryûsuke Hamaguchi', 'A renowned stage actor and director learns to cope with a big personal loss when he receives an offer to direct a production of Uncle Vanya in Hiroshima.', 'https://m.media-amazon.com/images/M/MV5BOGE5ZWRhYjYtNzVkMS00ZGU3LTg2MTMtODYyMmJlMDMyZjU0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Hidetoshi Nishijima, Tôko Miura, Reika Kirishima, Masaki Okada, Park Yu-rim, Jin Dae-yeon', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (258637, 'The Voyeurs', 'Thriller', 2021, 'Michael Mohan', 'Pippa and Thomas move into their dream apartment, but notice that their windows look directly into the apartment opposite. This will set in motion a chain of events that will lead to disaster.', 'https://m.media-amazon.com/images/M/MV5BOTQ5NDVjZjAtZDM4NC00NmQzLTkwZmYtYjQ1YjQ5NDJjZjFlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Sydney Sweeney, Justice Smith, Ben Hardy, Natasha Liu Bordizzo, Katharine King So, Cameo Adele', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (261271, 'The Harder They Fall', 'Western', 2021, 'Jeymes Samuel', 'When an outlaw discovers his enemy is being released from prison, he reunites his gang to seek revenge.', 'https://m.media-amazon.com/images/M/MV5BNDBjOTQyZTEtZTdhYS00ZTNlLWE3NTgtZGY3YmZlZTdhYjUxXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chase Dillon, DeWanda Wise, Julio Cesar Cedillo, Jonathan Majors, Manny Rubio, Edi Gathegi', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (262521, 'Porcupine', '(no genres listed)', 2021, 'M. Cahill', 'An adult woman puts herself up for adoption and forms a bond with the misanthropic patriarch of her adoptive family. Based on a true story.', 'https://m.media-amazon.com/images/M/MV5BN2E4YzhjOWUtMThjMi00Njc2LWE3ZmUtODc1MzFiMGRjOTg0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jena Malone, Robert Hunger-Bühler, Emily Kuroda, Will Rogers, Brooke Bloom, Jillian Lindig', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (263007, 'Spider-Man: No Way Home', 'Action,Adventure,Fantasy,Sci-Fi', 2021, 'Jon Watts', 'With Spider-Man\'s identity now revealed, Peter asks Doctor Strange for help. When a spell goes wrong, dangerous foes from other worlds start to appear.', 'https://m.media-amazon.com/images/M/MV5BMmFiZGZjMmEtMTA0Ni00MzA2LTljMTYtZGI2MGJmZWYzZTQ2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Holland, Zendaya, Benedict Cumberbatch, Jacob Batalon, Jon Favreau, Jamie Foxx', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (263407, 'Don\'t Look Up', 'Comedy,Drama,Sci-Fi', 2021, 'Adam McKay', 'Two low-level astronomers must go on a giant media tour to warn humankind of an approaching comet that will destroy planet Earth.', 'https://m.media-amazon.com/images/M/MV5BMjhhNWFjNzctYTJjOS00MDc0LThiNjItZmM0ZDVmMWViY2UzXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Leonardo DiCaprio, Jennifer Lawrence, Meryl Streep, Cate Blanchett, Rob Morgan, Jonah Hill', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (268642, 'The Batman', 'Action,Crime,Drama', 2022, 'Matt Reeves', 'When a sadistic serial killer begins murdering key political figures in Gotham, the Batman is forced to investigate the city\'s hidden corruption and question his family\'s involvement.', 'https://m.media-amazon.com/images/M/MV5BMmU5NGJlMzAtMGNmOC00YjJjLTgyMzUtNjAyYmE4Njg5YWMyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Robert Pattinson, Zoë Kravitz, Jeffrey Wright, Colin Farrell, Paul Dano, John Turturro', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (270346, 'Kimi', 'Thriller', 2022, 'Steven Soderbergh', 'An agoraphobic Seattle tech worker uncovers evidence of a crime.', 'https://m.media-amazon.com/images/M/MV5BYjhkNzI4NWItOTFjNi00Y2VjLTkwZTktMjdlNWU0NWViMWI5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'India de Beaufort, Derek DelGaudio, Sarai Koo, Jaime Camil, Koya Harada, Zoë Kravitz', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (270698, 'Everything Everywhere All at Once', 'Action,Comedy,Sci-Fi', 2022, 'Daniel Kwan', 'A middle-aged Chinese immigrant is swept up into an insane adventure in which she alone can save existence by exploring other universes and connecting with the lives she could have led.', 'https://m.media-amazon.com/images/M/MV5BOWNmMzAzZmQtNDQ1NC00Nzk5LTkyMmUtNGI2N2NkOWM4MzEyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Michelle Yeoh, Stephanie Hsu, Ke Huy Quan, James Hong, Jamie Lee Curtis, Tallie Medel', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (271134, 'Cha Cha Real Smooth', 'Comedy,Drama,Romance', 2022, 'Cooper Raiff', 'A young man who works as a Bar Mitzvah party host strikes up a friendship with a mother and her autistic daughter.', 'https://m.media-amazon.com/images/M/MV5BNWVjOWQ1YzEtMDVhNS00MTk1LTg1MGQtMzgyYzE5Mzc5ZWVlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cooper Raiff, Dakota Johnson, Evan Assante, Vanessa Burghardt, Leslie Mann, Brad Garrett', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (272417, 'RRR', 'Action,Drama,War', 2022, 'S.S. Rajamouli', 'A fearless warrior on a perilous mission comes face to face with a steely cop serving British forces in this epic saga set in pre-independent India.', 'https://m.media-amazon.com/images/M/MV5BNWMwODYyMjQtMTczMi00NTQ1LWFkYjItMGJhMWRkY2E3NDAyXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'N.T. Rama Rao Jr., Ram Charan, Ajay Devgn, Alia Bhatt, Olivia Morris, Shriya Saran', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (272547, 'Moonshot', 'Comedy,Romance,Sci-Fi', 2022, 'Christopher Winterbauer', 'This romantic comedy with a twist follows two college students as they join forces in order to be reunited with their significant others, embarking on a lively journey that takes them wildly off course.', 'https://m.media-amazon.com/images/M/MV5BMTIyMjc0MzQtMTdiZi00YzE4LWJhNGMtMWIwYjM5Yzc1ZGM3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cole Sprouse, Zach Braff, Peter Woodward, Henson Milam, Lukas Gage, Sarah Stipe', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (273891, 'Bullet Train', 'Action,Mystery,Thriller', 2022, 'David Leitch', 'Five assassins aboard a swiftly-moving bullet train find out that their missions have something in common.', 'https://m.media-amazon.com/images/M/MV5BODUyZjkxZDMtZGI3ZC00ZmEwLTgwMTUtYTU4OTQ5YjU4ZjRlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Brad Pitt, Joey King, Aaron Taylor-Johnson, Brian Tyree Henry, Andrew Koji, Hiroyuki Sanada', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (274053, 'Top Gun: Maverick', 'Action,Drama', 2022, 'Joseph Kosinski', 'The story involves Maverick confronting his past while training a group of younger Top Gun graduates, including the son of his deceased best friend, for a dangerous mission.', 'https://m.media-amazon.com/images/M/MV5BMDBkZDNjMWEtOTdmMi00NmExLTg5MmMtNTFlYTJlNWY5YTdmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tom Cruise, Val Kilmer, Miles Teller, Jennifer Connelly, Bashir Salahuddin, Jon Hamm', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (274343, 'Contra', 'Comedy', 2020, 'Sönke Wortmann', 'A university professor\'s ignorance is exposed when he must prepare a student for a debate.', 'https://m.media-amazon.com/images/M/MV5BMDk0Mjc2NDYtM2E2Ny00ZjNiLTgyOWQtNjRhZmU1N2U0YjdiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nilam Farooq, Christoph Maria Herbst, Hassan Akkouch, Ernst Stötzner, Meriam Abbas, Mohamed Issa', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (275245, 'Nope', 'Horror,Mystery,Sci-Fi,Thriller', 2022, 'Jordan Peele', 'The residents of a lonely gulch in inland California bear witness to an uncanny and chilling phenomenon.', 'https://m.media-amazon.com/images/M/MV5BODRlNWRhZWUtMzdlZC00ZDIyLWFhZjMtYTcxNjI1ZDIwODhjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Daniel Kaluuya, Keke Palmer, Brandon Perea, Michael Wincott, Steven Yeun, Wrenn Schmidt', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (275827, 'Elizabeth: A Portrait in Part(s)', 'Documentary', 2022, 'Roger Michell', 'A documentary on the life of Queen Elizabeth II, the longest-lived, longest reigning British monarch and longest serving female head of state in history.', 'https://m.media-amazon.com/images/M/MV5BYjJjMzA3NjktMzMyZC00YzM2LTlmNTctZDVkM2JmYzdjYzM4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'King Charles III, Paul McCartney, Queen Elizabeth II', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (276087, 'Vengeance', 'Comedy,Drama,Thriller', 2022, 'B.J. Novak', 'A writer from New York City attempts to solve the murder of a girl he hooked up with and travels down south to investigate the circumstances of her death and discover what happened to her.', 'https://m.media-amazon.com/images/M/MV5BYmI2MmZlNTctYjIyMy00N2MxLTllZWQtNmEyOGZhMGQ3NThiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'B.J. Novak, Boyd Holbrook, Lio Tipton, Ashton Kutcher, Isabella Amara, Dove Cameron', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (276387, 'A Quién Cierra Los Ojos', '(no genres listed)', NULL, 'Ana Díez', NULL, 'https://m.media-amazon.com/images/M/MV5BNWI0NTU2ZWQtYjI3Ni00YWU0LTk1MmEtNjE0N2Y3NzM1MWQ1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Patricia Reyes Spíndola, Juan Pablo de Santiago, Valentina Martínez, Miguel Pizarro, Amanda Farah, Axel Shuarma', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (277256, 'Into the Deep', 'Thriller', 2022, 'Kate Cox', 'A young woman desperate for an escape, meets a mysterious and attractive stranger who promises a romantic trip. What follows is deceit, mistrust, and violence.', 'https://m.media-amazon.com/images/M/MV5BNmNjNWVjNTgtZjNiYS00Njg0LWEyYWQtNWJiOTUwMzE4MTE4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ella-Rae Smith, Jessica Alexander, Matthew Daddario, Nikkita Chadha, Jack Morris, Andrew Steele', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (277868, 'The Stranger in Our Bed', 'Mystery,Thriller', 2022, 'Giles Alderson', 'An unhappily married woman leaves her husband for a lover who mysteriously disappears.', 'https://m.media-amazon.com/images/M/MV5BMDU4YjU4NmMtMTFiZi00M2FjLWFjMTYtOGNmNzU0ZGZmMWU5XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Emily Berrington, Ben Lloyd-Hughes, Samantha Bond, Nina Wadia, Joseph Marcell, Terri Dwyer', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (277978, 'The Invitation', 'Horror,Thriller', 2022, 'Jessica M. Thompson', 'A woman learns the shocking and bloody truth about her family history while staying at an estate.', 'https://m.media-amazon.com/images/M/MV5BODJiMTNiN2MtZDAzYy00MjEwLWJhZjYtN2NiYWQyY2IwNjdjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nathalie Emmanuel, Thomas Doherty, Sean Pertwee, Hugh Skinner, Carol Ann Crawford, Alana Boden', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (278008, 'Liger', 'Action,Romance', 2022, 'Puri Jagannadh', 'A story about martial arts, dreams and star crossed lovers. Liger is an MMA fighter who trains hard and rises up the ranks with one goal in mind, to fight like his idol, world renowned MMA fighter Mark Anderson and get noticed by him.', 'https://m.media-amazon.com/images/M/MV5BNjBmM2NlMzItZTY1Ny00ZjcxLThmMDAtMmZjNjIzZDIzOWRiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Vijay Deverakonda, Ananya Panday, Ramya Krishnan, Mike Tyson, Ronit Roy, Vish', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (278050, 'Explorer', 'Documentary', 2022, 'Matthew Dyas', 'A portrait of the \"world\'s greatest living explorer\" Sir Ranulph Fiennes, a film that goes beyond the record breaking achievements to explore the man behind the myth.', 'https://m.media-amazon.com/images/M/MV5BODcwYjQwOGMtOWU3YS00YWE4LWIxYWUtZTI3Mjk4ZmI5OGNiXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ranulph Fiennes, Anton Bowring, Ginny Fiennes, King Charles III', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (278052, 'McEnroe', 'Documentary', 2022, 'Barney Douglas', 'It follows John McEnroe as he finally tells his side of his storied career and performances on the court.', 'https://m.media-amazon.com/images/M/MV5BMzkwZGQ0NGMtODVkMy00N2FmLThhNWQtMWU3ZDZjYWQ3Zjk3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Björn Borg, Peter Fleming, Chrissie Hynde, Billie Jean King, Phil Knight, James Malhane', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (278054, 'The Figo Affair: The Transfer that Changed Football', 'Documentary', 2022, 'Ben Nicholas', 'This documentary spotlights one of the most contentious deals in football history and the extraordinary player at the center of the storm: Luís Figo.', 'https://m.media-amazon.com/images/M/MV5BMDMxNDY1MDMtZTYyMC00ZmViLTllYjktYzZlOWZmYTZkYjA0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Roberto Carlos, José Ramón de la Morena, José Félix Díaz, Luis Figo, Toni Frieros, Paulo Futre', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (278056, 'Love at Twenty', 'Drama,Romance', 1962, 'Shintarô Ishihara', '\"Love at Twenty\" unites five directors from around the world to present their different perspectives on what love really is at the age of 20. The episodes are united with the score of Georges Delerue and still photos of Henri Cartier-Bresson. The directors create their peculiar s...Read all', 'https://m.media-amazon.com/images/M/MV5BODM4NWIwY2UtYWQ5MS00NjUwLTliYTktNzViZTdiYTM2MDA0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jean-Pierre Léaud, Marie-France Pisier, Eleonora Rossi Drago, Cristina Gaioni, Geronimo Meynier, Nami Tamura', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (278058, 'The Yellow Ticket', 'Drama', 1918, 'Eugen Illés', 'A story of a Jewish girl forced to hide her identity in order to attend medical school in St. Petersburg, the movie is a melodrama of multiple oppression.', 'https://m.media-amazon.com/images/M/MV5BZjhhMmU4ZjMtNWQzYS00M2U3LWIxNDctNDgwMmVjOTRkMmM0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Pola Negri, Harry Liedtke, Victor Janson, Adolf E. Licho, Werner Bernhardt, Guido Herzfeld', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (278446, 'The Banshees of Inisherin', 'Comedy,Drama', 2022, 'Martin McDonagh', 'Two lifelong friends find themselves at an impasse when one abruptly ends their relationship, with alarming consequences for both of them.', 'https://m.media-amazon.com/images/M/MV5BOTkzMWI4OTEtMTk0MS00MTUxLWI4NTYtYmRiNWM4Zjc1MGRhXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Colin Farrell, Brendan Gleeson, Kerry Condon, Pat Shortt, Gary Lydon, Jon Kenny', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (278578, 'All Quiet on the Western Front', 'Action,Drama,War', 2022, 'Edward Berger', 'A young German soldier\'s eagerness to serve his country quickly fades when he witnesses the horrors of combat on the Western Front during World War I.', 'https://m.media-amazon.com/images/M/MV5BOWJiYWMyYTktZThhOS00ZjgxLWE0YTQtZDMyNTQxMjMyYjI2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Felix Kammerer, Albrecht Schuch, Aaron Hilmer, Moritz Klaus, Adrian Grünewald, Edin Hasanovic', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (278702, 'Glass Onion: A Knives Out Mystery', 'Comedy,Crime,Mystery', 2022, 'Rian Johnson', 'Tech billionaire Miles Bron invites his friends for a getaway on his private Greek island. When someone turns up dead, Detective Benoit Blanc is put on the case.', 'https://m.media-amazon.com/images/M/MV5BMzI2ZDYxZTEtMzVlOC00OTUyLTgyNTAtYWFhNmRhZjAzZWE1XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Daniel Craig, Edward Norton, Janelle Monáe, Kathryn Hahn, Leslie Odom Jr., Kate Hudson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (278800, 'Confess, Fletch', 'Comedy,Crime', 2022, 'Greg Mottola', 'After becoming the prime suspect in a murder, Fletch strives to prove his innocence while simultaneously searching for his girlfriend\'s stolen art collection.', 'https://m.media-amazon.com/images/M/MV5BMTUzNDU5YTgtZjNjNS00MjZjLTllZjYtY2RjMDNlZDc4NmM2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jon Hamm, Caitlin Zerra Rose, Roy Wood Jr., Ayden Mayeri, Lorenza Izzo, Erion Metani', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (279756, 'How to Blow Up a Pipeline', 'Crime,Drama,Thriller', 2022, 'Daniel Goldhaber', 'A crew of environmental activists plot a daring plan to disrupt an oil pipeline.', 'https://m.media-amazon.com/images/M/MV5BZmE2OGJiZjAtZWY4OS00YjdmLTk5NGMtNjYzNWVlZGI5MWZkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Ariela Barer, Kristine Froseth, Lukas Gage, Forrest Goodluck, Sasha Lane, Jayme Lawson', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (280866, 'She Said', 'Drama', 2022, 'Maria Schrader', 'Jodi Kantor and Megan Twohey\'s quest to break the Harvey Weinstein scandal.', 'https://m.media-amazon.com/images/M/MV5BNjVmNTk1NzktMjk3OC00NDYwLWIzMzMtY2EzZWU0YjZlMmRkXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Lola Petticrew, Katherine Laheen, Zoe Kazan, Carey Mulligan, Emma Clare O\'Connor, Tom Pelphrey', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (281188, 'Suzume', 'Adventure,Animation,Drama,Fantasy', 2022, 'Makoto Shinkai', 'A modern action adventure road story where a 17-year-old girl named Suzume helps a mysterious young man close doors from the other side that are releasing disasters all over in Japan.', 'https://m.media-amazon.com/images/M/MV5BODhkNDhmNzktODFmMC00NDZiLWEzN2UtY2YwYzgzYTVlMWZmXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Nanoka Hara, Hokuto Matsumura, Eri Fukatsu, Shôta Sometani, Sairi Itô, Kotone Hanase', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (285301, 'Dungeons & Dragons: Honor Among Thieves', 'Action,Adventure,Fantasy', 2023, 'John Francis Daley', 'A charming thief and a band of unlikely adventurers embark on an epic quest to retrieve a lost relic, but things go dangerously awry when they run afoul of the wrong people.', 'https://m.media-amazon.com/images/M/MV5BOGRjMjQ0ZDAtODc0OS00MGY1LTkxMTMtODhhNjY5NTM4N2IwXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Chris Pine, Michelle Rodriguez, Regé-Jean Page, Justice Smith, Sophia Lillis, Hugh Grant', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (285851, 'Air: Courting a Legend', 'Drama', 2023, 'Ben Affleck', 'The history of the game-changing partnership between a then undiscovered Michael Jordan and Nike\'s fledgling basketball division which revolutionized the world of sports and culture with the Air Jordan brand.', 'https://m.media-amazon.com/images/M/MV5BNjdjYzJkZmUtZDNiMC00MzQ0LWE2MGEtYTk4ZGM4NzFkMzM3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Matt Damon, Jason Bateman, Ben Affleck, Chris Messina, Viola Davis, Julius Tennon', '2025-11-24 12:30:38');
INSERT INTO `movies` VALUES (286881, 'The Artifice Girl', 'Drama,Sci-Fi,Thriller', 2023, 'Franklin Ritch', 'A team of special agents discovers a revolutionary new computer program to bait and trap online predators. After teaming up with the program\'s troubled developer, they soon find that the AI is rapidly advancing beyond its original purpose.', 'https://m.media-amazon.com/images/M/MV5BZDQwNTVjZGMtM2NhNC00Njg4LWE3ZjUtZTFiOGUyYWUyNDY4XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Tatum Matthews, Lance Henriksen, Sinda Nichols, David Girard, Franklin Ritch, Ivana Barnes', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (287699, 'Oppenheimer', 'Drama', 2023, 'Christopher Nolan', 'A dramatization of the life story of J. Robert Oppenheimer, the physicist who had a large hand in the development of the atomic bombs that brought an end to World War II.', 'https://m.media-amazon.com/images/M/MV5BM2RmYmVmMzctMzc5Ny00MmNiLTgxMGUtYjk1ZDRhYjA2YTU0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Cillian Murphy, Emily Blunt, Robert Downey Jr., Alden Ehrenreich, Scott Grimes, Jason Clarke', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (288269, 'No Hard Feelings', 'Comedy,Romance', 2023, 'Gene Stupnitsky', 'On the brink of losing her home, Maddie finds an intriguing job listing: helicopter parents looking for someone to bring their introverted 19-year-old son out of his shell before college. She has one summer to make him a man or die trying.', 'https://m.media-amazon.com/images/M/MV5BZjk1NmZiNzYtZGUyYi00YzEwLTgwNWQtM2VmOWFmMGIwZDM2XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Jennifer Lawrence, Andrew Barth Feldman, Laura Benanti, Matthew Broderick, Natalie Morales, Scott MacArthur', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (288513, 'Barbie', 'Comedy', 2023, 'Greta Gerwig', 'Barbie and Ken are having the time of their lives in the seemingly perfect world of Barbie Land. However, when they get a chance to go to the outside world, they soon discover the joys and perils of living among regular humans.', 'https://m.media-amazon.com/images/M/MV5BYjI3NDU0ZGYtYjA2YS00Y2RlLTgwZDAtYTE2YTM5ZjE1M2JlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Margot Robbie, Issa Rae, Kate McKinnon, Alexandra Shipp, Emma Mackey, Hari Nef', '2025-11-24 12:30:37');
INSERT INTO `movies` VALUES (291695, 'Fair Play', 'Drama,Thriller', 2023, 'Chloe Domont', 'An unexpected promotion at a cutthroat hedge fund pushes a young couple\'s relationship to the brink, threatening to unravel far more than their recent engagement.', 'https://m.media-amazon.com/images/M/MV5BNjkxYjNkMGMtOTkyNC00YTRhLWIyZDctNmFmZjYxNjEwMDdjXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Phoebe Dynevor, Alden Ehrenreich, Eddie Marsan, Rich Sommer, Sebastian De Souza, Sia Alipour', '2025-11-24 16:51:27');
INSERT INTO `movies` VALUES (291717, 'The Mountain', 'Drama,Fantasy', 2023, 'Thomas Salvador', 'Pierre, a Parisian engineer, goes up in the Alps for his work. Irresistibly attracted by what surrounds him, he camps out alone high in the mountains and leaves behind his everyday life.', 'https://m.media-amazon.com/images/M/MV5BODdmM2E5NDktMDkwMi00MDBiLTkyM2MtNzRmZWVkNTlmYjg0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Thomas Salvador, Louise Bourgoin, Martine Chevallier, Laurent Poitrenaux, Andranic Manet, Adam Pouilhe', '2025-11-24 16:52:22');
INSERT INTO `movies` VALUES (291729, 'Looking for Venera', 'Drama', 2022, 'Norika Sefa', 'The quiet, taciturn teenager Venera lives in a small town in Kosovo. At home, where three generations are crawling together in a small house, she has hardly any privacy.', 'https://m.media-amazon.com/images/M/MV5BYTJmNjM4YjItOGRmYi00NWUzLTgyNTctYTIyZWRmYmVmMjI0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg', 'Kosovare Krasniqi, Rozafa Celaj, Erjona Kakeli, Basri Lushtaku, Bleon Monolli, Fatushe Nushi', '2025-11-24 16:52:54');
