-- ----------------------------
-- View structure for popular_movies
-- ----------------------------
DROP VIEW IF EXISTS `popular_movies`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `popular_movies` AS select `m`.`id` AS `id`,`m`.`title` AS `title`,`m`.`genres` AS `genres`,`m`.`release_year` AS `release_year`,`m`.`director` AS `director`,`m`.`description` AS `description`,`m`.`poster_url` AS `poster_url`,`m`.`actors` AS `actors`,`m`.`created_at` AS `created_at`,count(`ur`.`id`) AS `rating_count`,avg(`ur`.`rating`) AS `avg_rating` from (`movies` `m` left join `user_ratings` `ur` on((`m`.`id` = `ur`.`movie_id`))) group by `m`.`id` order by `rating_count` desc,`avg_rating` desc;

SET FOREIGN_KEY_CHECKS = 1;
